// MARK: - Reporting Mode Logging (privacy-safe)

enum ReportingLogSeverity: String, Codable {
    case debug = "DEBUG"
    case info = "INFO"
    case warn = "WARN"
    case error = "ERROR"
}

enum ReportingLogCategory: String, Codable {
    case uiEvents = "UI_EVENTS"
    case stateTransitions = "STATE_TRANSITIONS"
    case annotationOps = "ANNOTATION_OPS"
    case documentIO = "DOCUMENT_IO"
    case errors = "ERRORS"
    case performance = "PERFORMANCE"
}

struct ReportingLogContext: Encodable {
    var view: String?
    var documentID: String?
    var annotationID: String?
    var details: [String: String]

    enum CodingKeys: String, CodingKey {
        case view
        case documentID
        case annotationID
        case details
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        if let view {
            try container.encode(view, forKey: .view)
        } else {
            try container.encodeNil(forKey: .view)
        }
        if let documentID {
            try container.encode(documentID, forKey: .documentID)
        } else {
            try container.encodeNil(forKey: .documentID)
        }
        if let annotationID {
            try container.encode(annotationID, forKey: .annotationID)
        } else {
            try container.encodeNil(forKey: .annotationID)
        }
        try container.encode(details, forKey: .details)
    }
}

/*
 Example log entry (schema):
 {
   "timestamp": "2026-01-31T22:05:14.123Z",
   "severity": "INFO",
   "category": "UI_EVENTS",
   "event": "button_press",
   "context": {
     "view": "pdf",
     "documentID": "hash:3c2a1d9f5b7e8a12",
     "annotationID": null,
     "details": {
       "button": "share",
       "source": "toolbar"
     }
   }
 }
*/
struct ReportingLogEntry: Encodable {
    let timestamp: String
    let severity: ReportingLogSeverity
    let category: ReportingLogCategory
    let event: String
    let context: ReportingLogContext
    let sortTime: TimeInterval

    enum CodingKeys: String, CodingKey {
        case timestamp
        case severity
        case category
        case event
        case context
    }
}

enum ReportingLogConfig {
    static let hardEntryLimit: Int = 2000
    static let maxReportEntries: Int = 300
    static let slowOperationThresholdMs: Int = 800
    static let defaultRecipient: String = "juliomorales1823@gmail.com"
}

enum ReportingLogRedactor {
    private static let emailRegex = try? NSRegularExpression(pattern: #"[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}"#, options: [.caseInsensitive])
    private static let userPathRegex = try? NSRegularExpression(pattern: #"/Users/[^/]+/"#, options: [])
    private static let homePathRegex = try? NSRegularExpression(pattern: #"/home/[^/]+/"#, options: [])
    private static let winUserPathRegex = try? NSRegularExpression(pattern: #"(?i)\\Users\\[^\\]+\\?"#, options: [])
    private static let jwtRegex = try? NSRegularExpression(pattern: #"\b[A-Za-z0-9\-_]+\.[A-Za-z0-9\-_]+\.[A-Za-z0-9\-_]+\b"#, options: [])
    private static let uuidRegex = try? NSRegularExpression(pattern: #"\b[0-9a-fA-F]{8}\-[0-9a-fA-F]{4}\-[0-9a-fA-F]{4}\-[0-9a-fA-F]{4}\-[0-9a-fA-F]{12}\b"#, options: [])
    private static let longHexRegex = try? NSRegularExpression(pattern: #"\b[0-9a-fA-F]{32,}\b"#, options: [])
    private static let base64Regex = try? NSRegularExpression(pattern: #"\b[A-Za-z0-9+/=]{32,}\b"#, options: [])

    private static func shouldRedactKey(_ key: String) -> Bool {
        let lower = key.lowercased()
        return lower.contains("token")
            || lower.contains("secret")
            || lower.contains("apikey")
            || lower.contains("api_key")
            || lower.contains("password")
            || lower.contains("session")
            || lower.contains("auth")
            || lower.contains("device")
            || lower.contains("system")
            || lower.contains("identifier")
    }

    private static func redactEmailAddresses(in value: String) -> String {
        guard let emailRegex else { return value }
        let ns = value as NSString
        let matches = emailRegex.matches(in: value, range: NSRange(location: 0, length: ns.length))
        guard !matches.isEmpty else { return value }
        var redacted = value
        for match in matches.reversed() {
            let email = ns.substring(with: match.range)
            if email.lowercased() == ReportingLogConfig.defaultRecipient.lowercased() {
                continue
            }
            let range = Range(match.range, in: redacted)
            if let range {
                redacted.replaceSubrange(range, with: "<redacted-email>")
            }
        }
        return redacted
    }

    private static func redactPaths(in value: String) -> String {
        var redacted = value
        if let userPathRegex {
            redacted = userPathRegex.stringByReplacingMatches(in: redacted,
                                                             options: [],
                                                             range: NSRange(location: 0, length: redacted.utf16.count),
                                                             withTemplate: "/Users/<redacted>/")
        }
        if let homePathRegex {
            redacted = homePathRegex.stringByReplacingMatches(in: redacted,
                                                             options: [],
                                                             range: NSRange(location: 0, length: redacted.utf16.count),
                                                             withTemplate: "/home/<redacted>/")
        }
        if let winUserPathRegex {
            redacted = winUserPathRegex.stringByReplacingMatches(in: redacted,
                                                                options: [],
                                                                range: NSRange(location: 0, length: redacted.utf16.count),
                                                                withTemplate: "\\Users\\<redacted>\\")
        }
        return redacted
    }

    private static func redactTokenLike(in value: String) -> String {
        if value.hasPrefix("hash:") || value.hasPrefix("id:") {
            return value
        }
        var redacted = value
        if let jwtRegex, jwtRegex.firstMatch(in: redacted, range: NSRange(location: 0, length: redacted.utf16.count)) != nil {
            return "<redacted-token>"
        }
        if let uuidRegex, uuidRegex.firstMatch(in: redacted, range: NSRange(location: 0, length: redacted.utf16.count)) != nil {
            redacted = uuidRegex.stringByReplacingMatches(in: redacted,
                                                         options: [],
                                                         range: NSRange(location: 0, length: redacted.utf16.count),
                                                         withTemplate: "<redacted-id>")
        }
        if let longHexRegex, longHexRegex.firstMatch(in: redacted, range: NSRange(location: 0, length: redacted.utf16.count)) != nil {
            redacted = longHexRegex.stringByReplacingMatches(in: redacted,
                                                            options: [],
                                                            range: NSRange(location: 0, length: redacted.utf16.count),
                                                            withTemplate: "<redacted-token>")
        }
        if let base64Regex, base64Regex.firstMatch(in: redacted, range: NSRange(location: 0, length: redacted.utf16.count)) != nil {
            redacted = base64Regex.stringByReplacingMatches(in: redacted,
                                                           options: [],
                                                           range: NSRange(location: 0, length: redacted.utf16.count),
                                                           withTemplate: "<redacted-token>")
        }
        return redacted
    }

    static func redact(details: [String: String]) -> [String: String] {
        var out: [String: String] = [:]
        out.reserveCapacity(details.count)
        for (key, value) in details {
            if shouldRedactKey(key) {
                out[key] = "<redacted>"
                continue
            }
            var redacted = value
            redacted = redactPaths(in: redacted)
            redacted = redactEmailAddresses(in: redacted)
            redacted = redactTokenLike(in: redacted)
            out[key] = redacted
        }
        return out
    }
}

final class ReportingLogger {
    static let shared = ReportingLogger()

    private let lock = NSLock()
    private var entries: [ReportingLogEntry] = []
    private var active: Bool = false
    private var bugID: Int?
    private var sessionStart = Date()

    private static let isoFormatter: ISO8601DateFormatter = {
        let formatter = ISO8601DateFormatter()
        formatter.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        return formatter
    }()

    var isActive: Bool {
        lock.lock()
        defer { lock.unlock() }
        return active
    }

    func beginSession(bugID: Int) {
        lock.lock()
        active = true
        entries.removeAll(keepingCapacity: true)
        self.bugID = bugID
        sessionStart = Date()
        lock.unlock()
    }

    func log(severity: ReportingLogSeverity,
             category: ReportingLogCategory,
             event: String,
             context: ReportingLogContext) {
        lock.lock()
        guard active else {
            lock.unlock()
            return
        }
        lock.unlock()

        let now = Date()
        let timestamp = ReportingLogger.isoFormatter.string(from: now)
        let redactedContext = ReportingLogContext(
            view: context.view,
            documentID: context.documentID,
            annotationID: context.annotationID,
            details: ReportingLogRedactor.redact(details: context.details)
        )
        let entry = ReportingLogEntry(
            timestamp: timestamp,
            severity: severity,
            category: category,
            event: event,
            context: redactedContext,
            sortTime: now.timeIntervalSince1970
        )

        lock.lock()
        guard active else {
            lock.unlock()
            return
        }
        entries.append(entry)
        if entries.count > ReportingLogConfig.hardEntryLimit {
            pruneToHardLimitLocked()
        }
        lock.unlock()
    }

    func endSession(discard: Bool) -> ReportingLogReport? {
        lock.lock()
        guard active else {
            lock.unlock()
            return nil
        }
        active = false
        let snapshot = entries
        let bug = bugID
        entries = []
        bugID = nil
        let startedAt = sessionStart
        lock.unlock()

        guard let bug, discard == false else { return nil }
        return ReportingLogReport(bugID: bug,
                                  sessionStart: startedAt,
                                  entries: snapshot)
    }

    private func pruneToHardLimitLocked() {
        guard entries.count > ReportingLogConfig.hardEntryLimit else { return }
        var overflow = entries.count - ReportingLogConfig.hardEntryLimit
        if overflow <= 0 { return }

        let severityOrder: [ReportingLogSeverity] = [.debug, .info, .warn, .error]
        for severity in severityOrder {
            if overflow <= 0 { break }
            var indices: [Int] = []
            indices.reserveCapacity(entries.count)
            for (idx, entry) in entries.enumerated() where entry.severity == severity {
                indices.append(idx)
            }
            if indices.isEmpty { continue }
            let removeCount = min(overflow, indices.count)
            for idx in indices.prefix(removeCount).reversed() {
                entries.remove(at: idx)
            }
            overflow -= removeCount
        }
        if overflow > 0 {
            entries.removeFirst(min(overflow, entries.count))
        }
    }
}

struct ReportingLogReport {
    let bugID: Int
    let sessionStart: Date
    let entries: [ReportingLogEntry]

    private func collapseRepetitive(_ entries: [ReportingLogEntry]) -> [ReportingLogEntry] {
        guard !entries.isEmpty else { return entries }
        var output: [ReportingLogEntry] = []
        output.reserveCapacity(entries.count)

        var last = entries[0]
        var repeatCount = 1
        var firstTimestamp = last.timestamp
        output.append(last)

        func collapseKey(_ entry: ReportingLogEntry) -> String {
            let detailsKey = entry.context.details.sorted { $0.key < $1.key }
                .map { "\($0.key)=\($0.value)" }
                .joined(separator: "&")
            return [
                entry.severity.rawValue,
                entry.category.rawValue,
                entry.event,
                entry.context.view ?? "",
                entry.context.documentID ?? "",
                entry.context.annotationID ?? "",
                detailsKey
            ].joined(separator: "|")
        }

        var lastKey = collapseKey(last)
        for entry in entries.dropFirst() {
            let key = collapseKey(entry)
            if key == lastKey {
                repeatCount += 1
                var details = last.context.details
                details["repeatCount"] = String(repeatCount)
                details["firstTimestamp"] = firstTimestamp
                details["lastTimestamp"] = entry.timestamp
                last = ReportingLogEntry(timestamp: entry.timestamp,
                                         severity: last.severity,
                                         category: last.category,
                                         event: last.event,
                                         context: ReportingLogContext(view: last.context.view,
                                                                      documentID: last.context.documentID,
                                                                      annotationID: last.context.annotationID,
                                                                      details: details),
                                         sortTime: entry.sortTime)
                output[output.count - 1] = last
            } else {
                repeatCount = 1
                firstTimestamp = entry.timestamp
                last = entry
                lastKey = key
                output.append(entry)
            }
        }
        return output
    }

    private func trimEntries(_ entries: [ReportingLogEntry]) -> [ReportingLogEntry] {
        guard entries.count > ReportingLogConfig.maxReportEntries else { return entries }
        let sorted = entries.sorted { $0.sortTime < $1.sortTime }
        let errors = sorted.filter { $0.severity == .error }
        let warns = sorted.filter { $0.severity == .warn }
        let infos = sorted.filter { $0.severity == .info }
        let debugs = sorted.filter { $0.severity == .debug }

        var kept: [ReportingLogEntry] = []
        let errorWarnCount = errors.count + warns.count
        if errorWarnCount >= ReportingLogConfig.maxReportEntries {
            let combined = (errors + warns).sorted { $0.sortTime < $1.sortTime }
            kept = Array(combined.suffix(ReportingLogConfig.maxReportEntries))
            return kept
        }

        kept.append(contentsOf: errors)
        kept.append(contentsOf: warns)
        var remaining = ReportingLogConfig.maxReportEntries - kept.count
        if remaining > 0 {
            let keepInfo = min(remaining, infos.count)
            if keepInfo > 0 {
                kept.append(contentsOf: infos.suffix(keepInfo))
                remaining -= keepInfo
            }
        }
        if remaining > 0 {
            let keepDebug = min(remaining, debugs.count)
            if keepDebug > 0 {
                kept.append(contentsOf: debugs.suffix(keepDebug))
            }
        }

        return kept.sorted { $0.sortTime < $1.sortTime }
    }

    private func normalizedEntries() -> [ReportingLogEntry] {
        let collapsed = collapseRepetitive(entries)
        return trimEntries(collapsed)
    }

    var infoWarnErrorEntries: [ReportingLogEntry] {
        normalizedEntries().filter { $0.severity != .debug }
    }

    var debugEntries: [ReportingLogEntry] {
        normalizedEntries().filter { $0.severity == .debug }
    }

    func jsonString(for entries: [ReportingLogEntry]) -> String {
        guard !entries.isEmpty else { return "[]" }
        let encoder = JSONEncoder()
        encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
        if let data = try? encoder.encode(entries),
           let string = String(data: data, encoding: .utf8) {
            return string
        }
        return "[]"
    }
}

final class ShortcutRunner: ShortcutRunning {
    typealias OpenURLHandler = ShortcutOpenURLHooks.OpenURLHandler

    struct Configuration: Equatable {
        var useXCallback: Bool = false
        var xSuccess: URL = URL(string: "shortcuts://")!
        var xError: URL = URL(string: "shortcuts://")!
        var xCancel: URL = URL(string: "shortcuts://")!
    }

    private let config: Configuration
    private let openURL: OpenURLHandler

    init(config: Configuration = Configuration(), openURL: @escaping OpenURLHandler = ShortcutOpenURLHooks.openURL) {
        self.config = config
        self.openURL = openURL
    }

    func makeRunURL(name: String, inputText: String? = nil) throws -> URL {
        let trimmed = name.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { throw ShortcutRunnerError.invalidName }

        var components = URLComponents()
        components.scheme = "shortcuts"
        components.host = "run-shortcut"

        var items: [URLQueryItem] = [URLQueryItem(name: "name", value: trimmed)]
        if let inputText {
            items.append(URLQueryItem(name: "input", value: "text"))
            items.append(URLQueryItem(name: "text", value: inputText))
        }
        components.queryItems = items

        guard let url = components.url else { throw ShortcutRunnerError.couldNotBuildURL }
        return url
    }

    func makeXCallbackURL(
        name: String,
        xSuccess: URL,
        xError: URL,
        xCancel: URL,
        inputText: String? = nil
    ) throws -> URL {
        let trimmed = name.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { throw ShortcutRunnerError.invalidName }

        var components = URLComponents()
        components.scheme = "shortcuts"
        components.host = "x-callback-url"
        components.path = "/run-shortcut"

        var items: [URLQueryItem] = [
            URLQueryItem(name: "name", value: trimmed),
            URLQueryItem(name: "x-success", value: xSuccess.absoluteString),
            URLQueryItem(name: "x-error", value: xError.absoluteString),
            URLQueryItem(name: "x-cancel", value: xCancel.absoluteString),
        ]

        if let inputText {
            items.append(URLQueryItem(name: "input", value: "text"))
            items.append(URLQueryItem(name: "text", value: inputText))
        }

        components.queryItems = items

        guard let url = components.url else { throw ShortcutRunnerError.couldNotBuildURL }
        return url
    }

    func runShortcut(name: String, payload: ShortcutPayload?) throws {
        let inputText = payload?.inputText
        let url: URL
        if config.useXCallback {
            url = try makeXCallbackURL(name: name, xSuccess: config.xSuccess, xError: config.xError, xCancel: config.xCancel, inputText: inputText)
        } else {
            url = try makeRunURL(name: name, inputText: inputText)
        }

        ShortcutRunnerLog.info("open url=\(url.absoluteString)")
        let ok = openURL(url)
        if !ok {
            ShortcutRunnerLog.error("open_failed url=\(url.absoluteString)")
            throw ShortcutRunnerError.openFailed
        }
    }
}

// Preferred Apple-supported bridge: `/usr/bin/shortcuts run <name-or-id>`.
// Used for the pill toolbar control so execution never blocks UI animations.
final class ShortcutCLIRunner {
    static let shared = ShortcutCLIRunner()

    struct Result {
        let name: String
        let status: Int32
        let output: String
        let error: String
        var isSuccess: Bool { status == 0 }
    }

    private let queue = DispatchQueue(label: "arxiv.shortcuts.cli", qos: .utility)
    private let cleanupQueue = DispatchQueue(label: "arxiv.shortcuts.cleanup", qos: .utility)

    private init() {}

    private func inputFileIsReadable(_ url: URL) -> Bool {
        guard url.isFileURL else { return false }
        var isDir: ObjCBool = false
        let exists = FileManager.default.fileExists(atPath: url.path, isDirectory: &isDir)
        guard exists, !isDir.boolValue else { return false }
        return FileManager.default.isReadableFile(atPath: url.path)
    }

    func runShortcut(nameOrIdentifier: String,
                     inputText: String? = nil,
                     inputFileURL: URL? = nil,
                     cleanupInputFile: Bool = false,
                     resultHandler: ((Result) -> Void)? = nil) {
        let trimmed = nameOrIdentifier.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            ShortcutRunnerLog.error("cli_invalid_name")
            if let handler = resultHandler {
                let result = Result(name: nameOrIdentifier, status: -1, output: "", error: "Shortcut name is empty.")
                DispatchQueue.main.async { handler(result) }
            }
            return
        }

        queue.async {
            let attemptID = UUID().uuidString.prefix(8)
            ShortcutRunnerLog.info("cli_attempt id=\(attemptID) name=\(trimmed) hasInput=\(inputText != nil || inputFileURL != nil)")

            // `shortcuts run` only supports input via file paths.
            // We write small text payloads to a temp file off the main thread.
            var inputURLs: [URL] = []
            var cleanupURLs: [URL] = []
            if let inputFileURL {
                // Validate upfront so we never launch Shortcuts with a missing/unreadable PDF.
                guard self.inputFileIsReadable(inputFileURL) else {
                    ShortcutRunnerLog.error("cli_input_invalid id=\(attemptID) path=\(inputFileURL.path)")
                    let result = Result(name: trimmed, status: -1, output: "", error: "Shortcut input file is missing or unreadable.")
                    if let handler = resultHandler {
                        DispatchQueue.main.async { handler(result) }
                    }
                    return
                }
                inputURLs.append(inputFileURL)
                if cleanupInputFile {
                    cleanupURLs.append(inputFileURL)
                }
            }
            if let inputText {
                let dir = FileManager.default.temporaryDirectory
                let url = dir.appendingPathComponent("arxiv.shortcut.input.\(UUID().uuidString).txt")
                do {
                    try inputText.write(to: url, atomically: true, encoding: .utf8)
                    inputURLs.append(url)
                    cleanupURLs.append(url)
                } catch {
                    ShortcutRunnerLog.error("cli_input_write_failed id=\(attemptID) error=\(String(describing: error))")
                }
            }

            let process = Process()
            process.executableURL = URL(fileURLWithPath: "/usr/bin/shortcuts")
            var args: [String] = ["run", trimmed]
            for inputURL in inputURLs {
                args.append(contentsOf: ["--input-path", inputURL.path])
            }
            process.arguments = args

            let stdoutPipe = Pipe()
            let stderrPipe = Pipe()
            process.standardOutput = stdoutPipe
            process.standardError = stderrPipe

            func cleanupDelaySeconds(for url: URL) -> TimeInterval {
                // PDFs can be consumed asynchronously by Shortcuts after the CLI exits.
                // Delay deletion to avoid race conditions where the input disappears mid-run.
                if url.pathExtension.lowercased() == "pdf" { return 90.0 }
                return 10.0
            }

            func scheduleCleanup() {
                guard !cleanupURLs.isEmpty else { return }
                for url in cleanupURLs {
                    let delay = cleanupDelaySeconds(for: url)
                    ShortcutRunnerLog.info("cli_cleanup_scheduled path=\(url.path) delay=\(String(format: "%.1f", delay))")
                    self.cleanupQueue.asyncAfter(deadline: .now() + delay) {
                        try? FileManager.default.removeItem(at: url)
                        ShortcutRunnerLog.info("cli_cleanup_done path=\(url.path)")
                    }
                }
            }

            process.terminationHandler = { _ in
                // Never touch AppKit here; log and clean up on the runner queue.
                ShortcutCLIRunner.shared.queue.async {
                    let status = process.terminationStatus
                    let ok = (status == 0)

                    let outData = (try? stdoutPipe.fileHandleForReading.readToEnd()) ?? Data()
                    let errData = (try? stderrPipe.fileHandleForReading.readToEnd()) ?? Data()
                    let out = String(data: outData, encoding: .utf8)?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                    let err = String(data: errData, encoding: .utf8)?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""

                    if ok {
                        ShortcutRunnerLog.info("cli_success id=\(attemptID) status=\(status) out=\(out.prefix(400))")
                    } else {
                        // Most common failure: missing/renamed shortcut identifier.
                        ShortcutRunnerLog.error("cli_failed id=\(attemptID) status=\(status) err=\(err.prefix(600))")
                    }
                    let result = Result(name: trimmed, status: status, output: out, error: err)
                    if let handler = resultHandler {
                        DispatchQueue.main.async {
                            handler(result)
                        }
                    }
                    scheduleCleanup()
                }
            }

            do {
                try process.run()
            } catch {
                ShortcutRunnerLog.error("cli_spawn_failed id=\(attemptID) error=\(String(describing: error))")
                scheduleCleanup()
                let result = Result(name: trimmed, status: -1, output: "", error: "Shortcuts CLI failed to launch.")
                if let handler = resultHandler {
                    DispatchQueue.main.async {
                        handler(result)
                    }
                }
            }
        }
    }
}

