    case color
}

let annotationChangeKindKey = "arxiv.annotation.change.kind"
let annotationChangeGroupIDKey = "arxiv.annotation.change.group_id"
let annotationChangePageIndexKey = "arxiv.annotation.change.page_index"
let annotationChangeCommentKey = "arxiv.annotation.change.comment"
let annotationChangeCommentPayloadKey = "arxiv.annotation.change.comment_payload"
let annotationChangeColorKey = "arxiv.annotation.change.color"
let annotationChangePageLabelKey = "arxiv.annotation.change.page_label"

final class AppearanceManager {
    static let shared = AppearanceManager()

    private let lock = NSLock()
    private let log = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "appearance")
    private let signpostLog = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "appearance.signpost")

    private var started = false
    private var scheduled = false
    private var pendingReason: String = "startup"

    private var budgets = AppearanceBudgets()
    private var metrics = Metrics()
    private var currentSnapshot = AppearanceSnapshot(
        mode: .light,
        nsAppearanceName: .aqua,
        revision: 0,
        monotonicTimestampNs: DispatchTime.now().uptimeNanoseconds
    )


    private var observers: [Any] = []
    private var distributedObservers: [Any] = []

    private init() {}

    func startIfNeeded() {
        lock.lock()
        let needsStart = !started
        if needsStart { started = true }
        lock.unlock()
        guard needsStart else { return }

        // Initialize snapshot from system once.
        refreshFromSystem(reason: "startup", forceNotify: true)

        // Observe system appearance changes directly (authoritative).
        // NOTE: On newer SDKs the typed Swift constant is not available; use the Objective-C
        // notification name string to remain source-compatible.
        observers.append(NotificationCenter.default.addObserver(
            forName: Notification.Name("NSApplicationDidChangeEffectiveAppearanceNotification"),
            object: nil,
            queue: .main
        ) { [weak self] _ in
            self?.scheduleRefresh(reason: "system_appearance")
        })

        // Observe accent/tint changes.
        observers.append(NotificationCenter.default.addObserver(
            forName: NSColor.systemColorsDidChangeNotification,
            object: nil,
            queue: .main
        ) { [weak self] _ in
            self?.scheduleRefresh(reason: "system_colors")
        })

        // Extra robustness: distributed theme-changed notification.
        distributedObservers.append(DistributedNotificationCenter.default().addObserver(
            forName: Notification.Name("AppleInterfaceThemeChangedNotification"),
            object: nil,
            queue: .main
        ) { [weak self] _ in
            self?.scheduleRefresh(reason: "distributed_theme")
        })
    }

    func snapshot() -> AppearanceSnapshot {
        lock.lock(); defer { lock.unlock() }
        return currentSnapshot
    }

    func isDark() -> Bool {
        snapshot().isDark
    }

    func resolvedSystemColor(_ color: NSColor) -> NSColor {
        let appearanceName = snapshot().nsAppearanceName
        let appearance = NSAppearance(named: appearanceName)
            ?? currentDrawingAppearanceFallback()
            ?? NSAppearance(named: .aqua)
            ?? NSAppearance(named: .darkAqua)

        // If this is ever nil, something is seriously wrong with AppKit; fail loudly in debug.
        assert(appearance != nil)

        guard let appearance else { return color }
        var resolved = color
        appearance.performAsCurrentDrawingAppearance {
            resolved = color.usingColorSpace(.deviceRGB) ?? color
        }
        return resolved
    }

    func metricsSnapshot() -> Metrics {
        lock.lock(); defer { lock.unlock() }
        return metrics
    }

    private func scheduleRefresh(reason: String) {
        lock.lock()
        pendingReason = reason
        let shouldSchedule = !scheduled
        if shouldSchedule { scheduled = true }
        lock.unlock()

        guard shouldSchedule else { return }

        // Coalesce to next runloop tick; guarantees atomic propagation even under rapid toggling.
        DispatchQueue.main.async { [weak self] in
            self?.applyPendingRefresh()
        }
    }

    private func applyPendingRefresh() {
        let reason: String
        lock.lock()
        reason = pendingReason
        scheduled = false
        lock.unlock()
        refreshFromSystem(reason: reason, forceNotify: false)
    }

    private func refreshFromSystem(reason: String, forceNotify: Bool) {
        // NOTE: This is the *only* place where we query system appearance.
        let sys = NSApplication.shared.effectiveAppearance
        let best = sys.bestMatch(from: [.darkAqua, .aqua]) ?? .aqua
        let mode: SystemAppearanceMode = (best == .darkAqua) ? .dark : .light

        let startNs = DispatchTime.now().uptimeNanoseconds
        let signpostID = OSSignpostID(log: signpostLog)
        os_signpost(.begin, log: signpostLog, name: "AppearanceSwitch", signpostID: signpostID,
                    "reason=%{public}@", reason)

        // Main-thread blocking timer measures only the synchronous work here.
        let blockingStart = DispatchTime.now().uptimeNanoseconds

        var newSnapshot: AppearanceSnapshot?
        var oldSnapshot: AppearanceSnapshot?

        lock.lock()
        oldSnapshot = currentSnapshot
        let nextRevision = currentSnapshot.revision &+ 1
        let shouldNotify = forceNotify || currentSnapshot.mode != mode || currentSnapshot.nsAppearanceName != best
        if shouldNotify {
            currentSnapshot = AppearanceSnapshot(mode: mode,
                                                nsAppearanceName: best,
                                                revision: nextRevision,
                                                monotonicTimestampNs: startNs)
            newSnapshot = currentSnapshot
        }
        lock.unlock()

        guard let snapshot = newSnapshot else {
            os_signpost(.end, log: signpostLog, name: "AppearanceSwitch", signpostID: signpostID,
                        "noop=1")
            return
        }

        // Atomic propagation: capture windows list once for consistent invalidation.
        let windows = NSApp.windows

        // Notify subscribers once, with a single snapshot.
        NotificationCenter.default.post(name: .arxivAppearanceDidChange, object: self, userInfo: ["snapshot": snapshot, "reason": reason])

        // One root invalidation per window (budgeted).
        var rootInvalidations = 0
        for w in windows {
            if let root = w.contentView {
                root.needsDisplay = true
                rootInvalidations += 1
            }
        }

        let blockingEnd = DispatchTime.now().uptimeNanoseconds
        let blockingMs = Double(blockingEnd - blockingStart) / 1_000_000.0

        CATransaction.begin()
        CATransaction.setCompletionBlock { [weak self] in
            guard let self else { return }
            let endNs = DispatchTime.now().uptimeNanoseconds
            let latencyMs = Double(endNs - startNs) / 1_000_000.0
            os_signpost(.end, log: self.signpostLog, name: "AppearanceSwitch", signpostID: signpostID,
                        "latency_ms=%.3f", latencyMs)

            self.lock.lock()
            self.metrics.lastSwitchLatencyMs = latencyMs
            self.metrics.lastMainThreadBlockingMs = blockingMs
            self.metrics.lastRootViewInvalidations = rootInvalidations
            self.metrics.switchCount += 1
            self.lock.unlock()

            self.enforceBudgets(snapshot: snapshot)
        }
        CATransaction.commit()
    }

    private func enforceBudgets(snapshot: AppearanceSnapshot) {
        let m = metricsSnapshot()
        func assertBudget(_ condition: @autoclosure () -> Bool) {
            if appearanceBudgetAssertsEnabled {
                assert(condition())
            }
        }

        // Hard failure thresholds are enforced via asserts in debug; also logged for Instruments.
        if m.lastSwitchLatencyMs > budgets.appearanceSwitchLatencyMs {
            os_log("[APPEARANCE_BUDGET] latency_ms=%.3f exceeded (rev=%llu)", log: log, type: .fault, m.lastSwitchLatencyMs, snapshot.revision)
            assertBudget(m.lastSwitchLatencyMs <= budgets.appearanceSwitchLatencyMs)
        }
        if m.lastMainThreadBlockingMs > budgets.mainThreadBlockingMs {
            os_log("[APPEARANCE_BUDGET] main_block_ms=%.3f exceeded (rev=%llu)", log: log, type: .fault, m.lastMainThreadBlockingMs, snapshot.revision)
            assertBudget(m.lastMainThreadBlockingMs <= budgets.mainThreadBlockingMs)
        }
        if m.lastRootViewInvalidations > budgets.viewInvalidationsPerSwitch * max(1, NSApp.windows.count) {
            os_log("[APPEARANCE_BUDGET] root_invalidations=%d exceeded (rev=%llu)", log: log, type: .fault, m.lastRootViewInvalidations, snapshot.revision)
            assertBudget(m.lastRootViewInvalidations <= budgets.viewInvalidationsPerSwitch * max(1, NSApp.windows.count))
        }
        if m.lastLayoutPasses > budgets.redundantLayoutPasses {
            os_log("[APPEARANCE_BUDGET] layout_passes=%d exceeded (rev=%llu)", log: log, type: .fault, m.lastLayoutPasses, snapshot.revision)
            assertBudget(m.lastLayoutPasses <= budgets.redundantLayoutPasses)
        }
        if m.lastDroppedFrames > budgets.droppedFramesDuringSwitch {
            os_log("[APPEARANCE_BUDGET] dropped_frames=%d exceeded (rev=%llu)", log: log, type: .fault, m.lastDroppedFrames, snapshot.revision)
            assertBudget(m.lastDroppedFrames <= budgets.droppedFramesDuringSwitch)
        }
    }
}

func currentDrawingAppearanceFallback() -> NSAppearance? {
    if let appAppearance = NSApp?.effectiveAppearance {
        return appAppearance
    }
    if #available(macOS 11.0, *) {
        return NSAppearance.currentDrawing()
    }
    return nil
}

func activeAppearance() -> NSAppearance {
    let name = AppearanceManager.shared.snapshot().nsAppearanceName
    return NSAppearance(named: name)
        ?? currentDrawingAppearanceFallback()
        ?? NSAppearance(named: .aqua)
        ?? NSAppearance(named: .darkAqua)
        ?? NSAppearance()
}

func glassAlpha(_ alpha: CGFloat) -> CGFloat {
    let strength = glassTintStrengthSetting()
    let scaled = alpha * GLASS_TRANSPARENCY_MULTIPLIER * strength
    return max(0.0, min(1.0, scaled))
}

func windowBackgroundAlpha(_ alpha: CGFloat) -> CGFloat {
    let strength = windowBackgroundTintStrengthSetting()
    let scaled = alpha * GLASS_TRANSPARENCY_MULTIPLIER * strength
    return max(0.0, min(1.0, scaled))
}

func applyGlassTransparency(_ color: NSColor) -> NSColor {
    color.withAlphaComponent(glassAlpha(color.alphaComponent))
}

func tablePanelAutomaticTintColor(baseTint: NSColor, isDark: Bool) -> NSColor {
    let baseAlpha: CGFloat = isDark ? 0.55 : 0.30
    let alpha = windowBackgroundAlpha(baseAlpha)
    let rgb = baseTint.usingColorSpace(.deviceRGB) ?? baseTint
    return NSColor(srgbRed: rgb.redComponent, green: rgb.greenComponent, blue: rgb.blueComponent, alpha: alpha)
}

func tablePanelAutomaticTintPreviewColor() -> NSColor {
    tablePanelAutomaticTintColor(baseTint: resolvedAppAccentDisplayColor(),
                                 isDark: glassAppearanceIsDark())
}

func resolvedSystemColor(_ color: NSColor) -> NSColor {
    AppearanceManager.shared.resolvedSystemColor(color)
}

func tintDebugEnabled() -> Bool {
    DEBUG_TINT || ProcessInfo.processInfo.environment["ARXIV_DEBUG_TINT"] == "1"
}

func debugTint(_ message: String) {
    guard tintDebugEnabled() else { return }
    NSLog("[Tint] \(message)")
}

func systemHighlightTintColorFromDefaults() -> NSColor? {
    let domains = ["NSGlobalDomain", ".GlobalPreferences"]
    guard let raw = readUserDefault("AppleHighlightColor", domains: domains) else { return nil }
    if let color = raw as? NSColor {
        return color.usingColorSpace(.deviceRGB) ?? color
    }
    if let data = raw as? Data,
       let color = try? NSKeyedUnarchiver.unarchivedObject(ofClass: NSColor.self, from: data) {
        return color.usingColorSpace(.deviceRGB) ?? color
    }
    if let str = raw as? String {
        return colorFromComponentString(str)
    }
    if let array = raw as? [Any] {
        let comps = array.compactMap { ($0 as? NSNumber)?.doubleValue }
        return colorFromComponentList(comps)
    }
    if let dict = raw as? [String: Any],
       let components = dict["components"] as? [Any] {
        let comps = components.compactMap { ($0 as? NSNumber)?.doubleValue }
        return colorFromComponentList(comps)
    }
    return nil
}

func systemAccentColorFromDefaults() -> NSColor? {
    let domains = ["NSGlobalDomain", ".GlobalPreferences"]
    guard let raw = readUserDefault("AppleAccentColor", domains: domains) else { return nil }
    let code: Int? = {
        if let num = raw as? NSNumber { return num.intValue }
        if let val = raw as? Int { return val }
        if let str = raw as? String { return Int(str.trimmingCharacters(in: .whitespacesAndNewlines)) }
        return nil
    }()
    guard let code else { return nil }
    switch code {
    case -1:
        // "Multicolor" accent; let controlAccentColor resolve dynamically.
        return nil
    case 0: return NSColor.systemRed
    case 1: return NSColor.systemOrange
    case 2: return NSColor.systemYellow
    case 3: return NSColor.systemGreen
    case 4: return NSColor.systemBlue
    case 5: return NSColor.systemPurple
    case 6: return NSColor.systemPink
    case 7: return NSColor.systemGray
    default: return nil
    }
}

func resolvedSystemAccentColor() -> NSColor {
    if let accent = systemAccentColorFromDefaults() {
        let resolved = accent.usingColorSpace(.deviceRGB) ?? accent
        debugTint("system_accent=accent_code \(cssRGBA(resolved))")
        return resolved
    }
    let accent = resolvedSystemColor(.controlAccentColor)
    let resolved = accent.usingColorSpace(.deviceRGB) ?? accent
    debugTint("system_accent=control_accent \(cssRGBA(resolved))")
    return resolved
}

func resolvedSystemSelectionTintColor() -> NSColor {
    if let highlight = systemHighlightTintColorFromDefaults() {
        return highlight.usingColorSpace(.deviceRGB) ?? highlight
    }
    return resolvedSystemColor(.selectedContentBackgroundColor)
}

func resolvedSystemAccentDisplayColor() -> NSColor {
    let accent = resolvedSystemAccentColor()
    return accent.usingColorSpace(.deviceRGB) ?? accent
}

func resolvedAppAccentColor() -> NSColor {
    let settings = AppSettingsStore.shared.current.appearance
    switch settings.accentMode {
    case .system:
        let accent = resolvedSystemAccentColor()
        debugTint("app_accent=system_accent \(cssRGBA(accent))")
        return accent
    case .custom:
        if let color = colorFromHex(settings.customAccentHex) {
            let resolved = color.usingColorSpace(.deviceRGB) ?? color
            debugTint("app_accent=custom \(cssRGBA(resolved))")
            return resolved
        }
        let resolved = resolvedSystemAccentColor()
        debugTint("app_accent=custom_fallback \(cssRGBA(resolved))")
        return resolved
    }
}

func resolvedAppAccentDisplayColor() -> NSColor {
    let settings = AppSettingsStore.shared.current.appearance
    switch settings.accentMode {
    case .system:
        let display = resolvedSystemAccentDisplayColor()
        debugTint("app_accent_display=system_accent \(cssRGBA(display))")
        return display
    case .custom:
        return resolvedAppAccentColor()
    }
}

func glassTintStrengthSetting() -> CGFloat {
    let settings = AppSettingsStore.shared.current.appearance
    guard settings.glassTintSourceEnabled else { return 0.0 }
    if settings.glassTintSource == .none { return 0.0 }
    return 1.0
}

func windowBackgroundTintStrengthSetting() -> CGFloat {
    let settings = AppSettingsStore.shared.current.appearance
    let raw = CGFloat(settings.liquidGlassTintStrength)
    let strength = max(0.0, min(2.0, raw.isFinite ? raw : 1.0))
    guard settings.liquidGlassEnabled else { return 0.0 }
    guard settings.windowTintEnabled else { return 0.0 }
    guard settings.glassTintSourceEnabled else { return 0.0 }
    if settings.glassTintSource == .none { return 0.0 }
    return strength
}

func resolvedGlassAppearanceIsDark() -> Bool {
    let settings = AppSettingsStore.shared.current.appearance
    let style = settings.glassStyleEnabled ? settings.glassStyle : .followApp
    switch style {
    case .light:
        return false
    case .dark:
        return true
    case .followApp:
        return AppearanceManager.shared.isDark()
    }
}

func resolvedUIFontFromSettings(defaultSize: CGFloat, weight: NSFont.Weight = .regular) -> NSFont {
    let fonts = AppSettingsStore.shared.current.appearance.fonts
    let size = fonts.uiFontSize > 0 ? CGFloat(fonts.uiFontSize) : defaultSize
    if !fonts.uiFontName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
       let custom = NSFont(name: fonts.uiFontName, size: size) {
        return custom
    }
    return NSFont.systemFont(ofSize: size, weight: weight)
}

func fontByApplyingTrait(_ font: NSFont, trait: NSFontTraitMask) -> NSFont {
    NSFontManager.shared.convert(font, toHaveTrait: trait)
}

func resolvedHTMLFontOverride() -> (font: NSFont, familyName: String)? {
    let fonts = AppSettingsStore.shared.current.appearance.fonts
    let trimmed = fonts.htmlFontName.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !trimmed.isEmpty else { return nil }
    let size = fonts.htmlFontSize > 0 ? CGFloat(fonts.htmlFontSize) : 14
    guard let font = NSFont(name: trimmed, size: size) else { return nil }
    let family = font.familyName ?? font.fontName
    return (font, family)
}

func inkyBlackColor() -> NSColor {
    if let color = colorFromHex(PDF_FIND_TEXT_COLOR_HEX) {
        return color.usingColorSpace(.deviceRGB) ?? color
    }
    return NSColor(srgbRed: 0.05, green: 0.05, blue: 0.06, alpha: 1.0)
}

func tintedImage(_ image: NSImage, color: NSColor) -> NSImage {
    let size = image.size
    let out = NSImage(size: size)
    out.lockFocus()
    let rect = NSRect(origin: .zero, size: size)
    image.draw(in: rect, from: .zero, operation: .sourceOver, fraction: 1.0)
    color.set()
    rect.fill(using: .sourceAtop)
    out.unlockFocus()
    out.isTemplate = false
    return out
}

func horizontallyMirroredImage(_ image: NSImage) -> NSImage {
    let size = image.size
    let out = NSImage(size: size)
    out.lockFocus()
    defer { out.unlockFocus() }

    let transform = NSAffineTransform()
    transform.translateX(by: size.width, yBy: 0)
    transform.scaleX(by: -1, yBy: 1)
    transform.concat()

    image.draw(in: NSRect(origin: .zero, size: size), from: .zero, operation: .sourceOver, fraction: 1.0)
    out.isTemplate = image.isTemplate
    return out
}

func isAppLightAppearance() -> Bool {
    !AppearanceManager.shared.isDark()
}

func windowBackgroundSolidColor() -> NSColor {
    isAppLightAppearance() ? WINDOW_BACKGROUND_SOLID_COLOR_LIGHT : WINDOW_BACKGROUND_SOLID_COLOR
}

func applyStandardHoverTooltipStyle(to bubble: NSView, label: NSTextField, base: NSColor) {
    let baseRGB = (base.usingColorSpace(.deviceRGB) ?? base).withAlphaComponent(1.0)
    let shade = resolvedSystemColor(.labelColor)
    let backgroundColor = blend(baseRGB, shade, t: 0.25)
    let textColor = resolvedSystemColor(.alternateSelectedControlTextColor)
    label.textColor = textColor
    bubble.wantsLayer = true
    bubble.layer?.backgroundColor = backgroundColor.cgColor
    bubble.layer?.cornerRadius = 8
    bubble.layer?.masksToBounds = true
    bubble.layer?.shadowOpacity = 0
    bubble.layer?.shadowRadius = 0
    bubble.layer?.shadowOffset = .zero
    bubble.alphaValue = 1.0
}

func readableTextColor(on background: NSColor,
                               target: CGFloat = 4.5,
                               lightAlpha: CGFloat = 0.96,
                               darkAlpha: CGFloat = 0.92) -> NSColor {
    let bg = (background.usingColorSpace(.deviceRGB) ?? background).withAlphaComponent(1.0)
    let isLight = relativeLuminance(bg) > 0.55
    let seed = isLight
        ? NSColor(white: 0.12, alpha: darkAlpha)
        : NSColor(white: 0.98, alpha: lightAlpha)
    return adjustedForContrast(seed, background: bg, target: target)
}

func readableSecondaryTextColor(on background: NSColor,
                                        target: CGFloat = 3.0,
                                        lightAlpha: CGFloat = 0.82,
                                        darkAlpha: CGFloat = 0.78) -> NSColor {
    let bg = (background.usingColorSpace(.deviceRGB) ?? background).withAlphaComponent(1.0)
    let isLight = relativeLuminance(bg) > 0.55
    let seed = isLight
        ? NSColor(white: 0.18, alpha: darkAlpha)
        : NSColor(white: 0.92, alpha: lightAlpha)
    return adjustedForContrast(seed, background: bg, target: target)
}

enum ForegroundRole {
    case primaryText
    case secondaryText
    case tertiaryText
    case icon
    case disabledIcon
}

func foregroundTarget(for role: ForegroundRole, minContrast: CGFloat?) -> CGFloat {
    switch role {
    case .primaryText:
        return minContrast ?? 4.5
    case .secondaryText:
        return minContrast ?? 3.0
    case .tertiaryText:
        return minContrast ?? 2.3
    case .icon:
        return max(minContrast ?? ThemeContrast.iconMinimumContrast, ThemeContrast.iconMinimumContrast)
    case .disabledIcon:
        return max(minContrast ?? ThemeContrast.iconMinimumContrast, ThemeContrast.iconMinimumContrast)
    }
}

func glassBackgroundPair(base: NSColor,
                                 tint: NSColor?,
                                 intensity: CGFloat = 1.0) -> (primary: NSColor, alt: NSColor?) {
    let primary = effectiveBackgroundColor(base: base, tint: tint, intensity: intensity)
    guard !glassAppearanceIsDark(), let tint else { return (primary, nil) }

    let lum = relativeLuminance(primary)
    if lum < 0.42 { return (primary, nil) }

    let tintRGB = (tint.usingColorSpace(.deviceRGB) ?? tint)
    let alpha = max(0.0, min(1.0, tintRGB.alphaComponent * max(0.0, min(1.0, intensity))))
    let tintLum = relativeLuminance(tintRGB.withAlphaComponent(1.0))
    var lift: CGFloat = 0.06 + (0.10 * (1.0 - alpha))
    if lum < 0.50 {
        lift *= 0.7
    } else if lum < 0.58 {
        lift *= 0.85
    }
    var maxLift: CGFloat = 0.28
    if tintLum < 0.35 && alpha > 0.5 {
        maxLift = 0.10
    }
    if lum < 0.58 {
        let targetLum: CGFloat = 0.62
        if lum < targetLum {
            let needed = (targetLum - lum) / max(0.0001, (1.0 - lum))
            lift = max(lift, min(maxLift, needed))
        }
    }
    lift = min(maxLift, max(0.0, lift))
    if lift < 0.02 { return (primary, nil) }
    let alt = blend(primary, NSColor.white, t: lift)
    return (primary, alt)
}

func resolvedForegroundColor(background: NSColor,
                                     altBackground: NSColor?,
                                     role: ForegroundRole,
                                     minContrast: CGFloat? = nil) -> NSColor {
    let primary = resolvedForegroundColor(background: background, role: role, minContrast: minContrast)
    guard let alt = altBackground else { return primary }
    let alternate = resolvedForegroundColor(background: alt, role: role, minContrast: minContrast)

    let primaryWorst = min(contrastRatio(primary, background), contrastRatio(primary, alt))
    let alternateWorst = min(contrastRatio(alternate, background), contrastRatio(alternate, alt))
    let target = foregroundTarget(for: role, minContrast: minContrast)

    var chosen = primaryWorst >= alternateWorst ? primary : alternate
    let worstBackground = contrastRatio(chosen, background) <= contrastRatio(chosen, alt) ? background : alt
    if contrastRatio(chosen, worstBackground) < target {
        chosen = adjustedForContrast(chosen, background: worstBackground, target: target)
    }
    if role == .icon || role == .disabledIcon {
        chosen = ThemeContrast.ensureContrast(chosen, on: worstBackground, minimumContrast: target, context: "icon")
    }
    return chosen
}

func effectiveBackgroundColor(base: NSColor,
                                      tint: NSColor?,
                                      intensity: CGFloat = 1.0) -> NSColor {
    let baseRGB = (base.usingColorSpace(.deviceRGB) ?? base).withAlphaComponent(1.0)
    guard let tint else { return baseRGB }
    let tintRGB = (tint.usingColorSpace(.deviceRGB) ?? tint)
    let alpha = max(0.0, min(1.0, tintRGB.alphaComponent * max(0.0, min(1.0, intensity))))
    guard alpha > 0.0001 else { return baseRGB }

    let baseLin = (srgbToLinear(baseRGB.redComponent),
                   srgbToLinear(baseRGB.greenComponent),
                   srgbToLinear(baseRGB.blueComponent))
    let tintLin = (srgbToLinear(tintRGB.redComponent),
                   srgbToLinear(tintRGB.greenComponent),
                   srgbToLinear(tintRGB.blueComponent))
    let outLin = compositeRGBLinear(sourceRGB: tintLin, sourceAlpha: alpha, destRGB: baseLin)
    return NSColor(srgbRed: linearToSrgb(outLin.0),
                   green: linearToSrgb(outLin.1),
                   blue: linearToSrgb(outLin.2),
                   alpha: 1.0)
}

func resolvedForegroundColor(background: NSColor,
                                     role: ForegroundRole,
                                     minContrast: CGFloat? = nil) -> NSColor {
    let bg = (background.usingColorSpace(.deviceRGB) ?? background).withAlphaComponent(1.0)
    let isLight = relativeLuminance(bg) > 0.55

    let target: CGFloat
    let base: CGFloat
    let alpha: CGFloat
    switch role {
    case .primaryText:
        target = foregroundTarget(for: role, minContrast: minContrast)
        base = isLight ? 0.10 : 0.98
        alpha = isLight ? 0.92 : 0.96
    case .secondaryText:
        target = foregroundTarget(for: role, minContrast: minContrast)
        base = isLight ? 0.18 : 0.92
        alpha = isLight ? 0.78 : 0.82
    case .tertiaryText:
        target = foregroundTarget(for: role, minContrast: minContrast)
        base = isLight ? 0.26 : 0.86
        alpha = isLight ? 0.64 : 0.70
    case .icon:
        target = foregroundTarget(for: role, minContrast: minContrast)
        base = isLight ? 0.10 : 0.98
        alpha = isLight ? 0.92 : 0.96
    case .disabledIcon:
        target = foregroundTarget(for: role, minContrast: minContrast)
        base = isLight ? 0.22 : 0.84
        alpha = isLight ? 0.50 : 0.55
    }

    let seed = NSColor(white: base, alpha: alpha)
    let adjusted = adjustedForContrast(seed, background: bg, target: target)
    if role == .icon || role == .disabledIcon {
        return ThemeContrast.ensureContrast(adjusted, on: bg, minimumContrast: target, context: "icon")
    }
    return adjusted
}

enum ForegroundResolver {
    static func color(background: NSColor,
                      role: ForegroundRole,
                      minContrast: CGFloat? = nil,
                      context: String? = nil) -> NSColor {
        var resolved = resolvedForegroundColor(background: background, role: role, minContrast: minContrast)
        if ContrastDebug.enabled, let context {
            ContrastDebug.logResolved(context: context,
                                      role: role,
                                      background: background,
                                      foreground: resolved)
            if role == .icon || role == .primaryText {
                let ok = ContrastDebug.assertForegroundMatchesSearch(foreground: resolved,
                                                                     background: background,
                                                                     role: role,
                                                                     context: context)
                if !ok {
                    resolved = ThemeContrast.bestContrastingMonochrome(on: background,
                                                                       minimumContrast: ThemeContrast.iconMinimumContrast)
                }
            }
        }
        return resolved
    }

    static func color(background: NSColor,
                      altBackground: NSColor?,
                      role: ForegroundRole,
                      minContrast: CGFloat? = nil,
                      context: String? = nil) -> NSColor {
        var resolved = resolvedForegroundColor(background: background,
                                               altBackground: altBackground,
                                               role: role,
                                               minContrast: minContrast)
        let effectiveBackground = background
        if ContrastDebug.enabled, let context {
            let note = (altBackground == nil) ? "" : "alt_bg"
            ContrastDebug.logResolved(context: context,
                                      role: role,
                                      background: effectiveBackground,
                                      foreground: resolved,
                                      note: note)
            if role == .icon || role == .primaryText {
                let ok = ContrastDebug.assertForegroundMatchesSearch(foreground: resolved,
                                                                     background: effectiveBackground,
                                                                     role: role,
                                                                     context: context)
                if !ok {
                    resolved = ThemeContrast.bestContrastingMonochrome(on: effectiveBackground,
                                                                       minimumContrast: ThemeContrast.iconMinimumContrast)
                }
            }
        }
        return resolved
    }

    static func color(base: NSColor,
                      tint: NSColor?,
                      intensity: CGFloat = 1.0,
                      role: ForegroundRole,
                      minContrast: CGFloat? = nil,
                      context: String? = nil) -> NSColor {
        let pair = glassBackgroundPair(base: base, tint: tint, intensity: intensity)
        var resolved = resolvedForegroundColor(background: pair.primary,
                                               altBackground: pair.alt,
                                               role: role,
                                               minContrast: minContrast)
        let effectiveBackground = pair.primary
        if ContrastDebug.enabled, let context {
            let note = (pair.alt == nil) ? "" : "alt_bg"
            ContrastDebug.logResolved(context: context,
                                      role: role,
                                      background: effectiveBackground,
                                      foreground: resolved,
                                      note: note)
            if role == .icon || role == .primaryText {
                let ok = ContrastDebug.assertForegroundMatchesSearch(foreground: resolved,
                                                                     background: effectiveBackground,
                                                                     role: role,
                                                                     context: context)
                if !ok {
                    resolved = ThemeContrast.bestContrastingMonochrome(on: effectiveBackground,
                                                                       minimumContrast: ThemeContrast.iconMinimumContrast)
                }
            }
        }
        return resolved
    }
}

// Single source of truth for toolbar foreground colors (derived from the search bar pipeline).
struct ToolbarForegroundPalette {
    var primary: NSColor
    var secondary: NSColor
    var disabled: NSColor
    var background: NSColor
}

final class ToolbarForegroundTheme {
    static let shared = ToolbarForegroundTheme()
    private(set) var palette: ToolbarForegroundPalette

    private init() {
        let fallbackBackground = NSColor.windowBackgroundColor
        palette = ToolbarForegroundPalette(primary: NSColor.labelColor,
                                           secondary: NSColor.secondaryLabelColor,
                                           disabled: NSColor.disabledControlTextColor,
                                           background: fallbackBackground)
    }

    func update(_ palette: ToolbarForegroundPalette) {
        self.palette = palette
    }

    func color(for role: ForegroundRole) -> NSColor {
        switch role {
        case .primaryText, .icon:
            return palette.primary
        case .secondaryText, .tertiaryText:
            return palette.secondary
        case .disabledIcon:
            return palette.disabled
        }
    }
}

func toolbarForegroundColor() -> NSColor {
    ToolbarForegroundTheme.shared.palette.primary
}

func annotationDefaultForegroundColor() -> NSColor {
    toolbarForegroundColor()
}

func resolvedForegroundColor(base: NSColor,
                                     tint: NSColor?,
                                     intensity: CGFloat = 1.0,
                                     role: ForegroundRole,
                                     minContrast: CGFloat? = nil) -> NSColor {
    let pair = glassBackgroundPair(base: base, tint: tint, intensity: intensity)
    return resolvedForegroundColor(background: pair.primary,
                                   altBackground: pair.alt,
                                   role: role,
                                   minContrast: minContrast)
}

func glassAppearanceIsDark() -> Bool {
    let settings = AppSettingsStore.shared.current.appearance
    let style = settings.glassStyleEnabled ? settings.glassStyle : .followApp
    switch style {
    case .light:
        return false
    case .dark:
        return true
    case .followApp:
        let appearance = NSApplication.shared.effectiveAppearance
        return (appearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua)
    }
}

func resolvedRightAuxGlassTintColor() -> NSColor {
    let settings = AppSettingsStore.shared.current.appearance
    guard settings.rightAuxGlassEnabled else {
        return windowBackgroundSolidColor().withAlphaComponent(1.0)
    }
    let trimmed = settings.rightAuxTintHex.trimmingCharacters(in: .whitespacesAndNewlines)
    let base: NSColor
    if !trimmed.isEmpty, let color = colorFromHex(trimmed) {
        base = color.usingColorSpace(.deviceRGB) ?? color
    } else {
        let white = glassAppearanceIsDark() ? RIGHT_AUX_GLASS_TINT_WHITE : RIGHT_AUX_GLASS_TINT_WHITE_LIGHT
        base = NSColor(white: max(0.0, min(1.0, white)), alpha: 1.0)
    }
    let rawAlpha = CGFloat(settings.rightAuxTintAlpha)
    let defaultAlpha = CGFloat(RIGHT_AUX_GLASS_TINT_ALPHA)
    let isDefault = trimmed.isEmpty && abs(rawAlpha - defaultAlpha) < 0.0001
    let alphaBase = glassAppearanceIsDark() ? RIGHT_AUX_GLASS_TINT_ALPHA : RIGHT_AUX_GLASS_TINT_ALPHA_LIGHT
    let alpha = max(0.0, min(1.0, isDefault ? alphaBase : rawAlpha))
    return base.withAlphaComponent(alpha)
}

func rightAuxEffectiveBackgroundColor() -> NSColor {
    let base = windowBackgroundSolidColor()
    let tint = resolvedRightAuxGlassTintColor()
    let pair = glassBackgroundPair(base: base, tint: tint, intensity: 1.0)
    return pair.alt ?? pair.primary
}

func spotlightSearchTintColor() -> NSColor {
    let base = resolvedAppAccentDisplayColor().usingColorSpace(.deviceRGB)
        ?? resolvedAppAccentDisplayColor()
    let alphaBase = glassAppearanceIsDark() ? WINDOW_GLASS_TINT_ALPHA : WINDOW_GLASS_TINT_ALPHA_LIGHT
    let boosted = min(1.0, alphaBase * SPOTLIGHT_SEARCH_GLASS_ALPHA_MULTIPLIER)
    let alpha = glassAlpha(max(0.0, min(1.0, boosted)))
    let raw = NSColor(srgbRed: base.redComponent,
                      green: base.greenComponent,
                      blue: base.blueComponent,
                      alpha: alpha)
    let target: CGFloat = glassAppearanceIsDark() ? 1.22 : 1.35
    let maxAlpha: CGFloat = glassAppearanceIsDark() ? 0.6 : 0.7
    return adjustedTintForBackgroundContrast(base: windowBackgroundSolidColor(),
                                             tint: raw,
                                             target: target,
                                             maxAlpha: maxAlpha)
}

func mainSearchForegroundColor() -> NSColor {
    return ToolbarForegroundTheme.shared.palette.primary
}

func mainSearchLabelColor() -> NSColor {
    return ToolbarForegroundTheme.shared.palette.primary
}

// Pass-through view so background layers never intercept events.
final class PassthroughView: NSView {
    override func hitTest(_ point: NSPoint) -> NSView? { nil }
}

final class PassthroughImageView: NSImageView {
    override func hitTest(_ point: NSPoint) -> NSView? { nil }
}

final class PassthroughVisualEffectView: NSVisualEffectView {
    override func hitTest(_ point: NSPoint) -> NSView? { nil }
}

final class MenuDismissView: NSView {
    var onDismiss: (() -> Void)?
    override func hitTest(_ point: NSPoint) -> NSView? {
        guard !isHidden,
              alphaValue > 0.01,
              window != nil,
              bounds.contains(point) else { return nil }
        return self
    }
    override func mouseDown(with event: NSEvent) {
        guard !isHidden else { return }
        onDismiss?()
    }
}

/// Allows clicks that land on empty header chrome to fall through to views below.
final class HeaderHitTestContainer: NSView {
    override func hitTest(_ point: NSPoint) -> NSView? {
        guard let hit = super.hitTest(point) else { return nil }
        return hit === self ? nil : hit
    }
}

final class SearchFocusContainer: NSView {
    weak var focusTarget: NSView?
    var onAppearanceChanged: (() -> Void)?

    private var appearanceObserver: Any?

    override init(frame frameRect: NSRect) {
        super.init(frame: frameRect)
        appearanceObserver = NotificationCenter.default.addObserver(
            forName: .arxivAppearanceDidChange,
            object: AppearanceManager.shared,
            queue: .main
        ) { [weak self] _ in
            self?.onAppearanceChanged?()
        }
    }

    required init?(coder: NSCoder) {
        super.init(coder: coder)
        appearanceObserver = NotificationCenter.default.addObserver(
            forName: .arxivAppearanceDidChange,
            object: AppearanceManager.shared,
            queue: .main
        ) { [weak self] _ in
            self?.onAppearanceChanged?()
        }
    }

    deinit {
        if let appearanceObserver {
            NotificationCenter.default.removeObserver(appearanceObserver)
        }
    }

    override func mouseDown(with event: NSEvent) {
        if let target = focusTarget {
            window?.makeFirstResponder(target)
            target.mouseDown(with: event)
            return
        }
        super.mouseDown(with: event)
    }
}

