let chatLatencyDebugEnabled = ProcessInfo.processInfo.environment["ARXIV_CHAT_LATENCY"] == "1" || perfDebugEnabled
let searchLatencyDebugEnabled = ProcessInfo.processInfo.environment["ARXIV_SEARCH_LATENCY"] == "1" || perfDebugEnabled

func monotonicNowNs() -> UInt64 {
    DispatchTime.now().uptimeNanoseconds
}

func displayRefreshRateHz(for window: NSWindow?) -> Double {
    if #available(macOS 10.15, *) {
        if let screen = window?.screen ?? NSScreen.main {
            let hz = Double(screen.maximumFramesPerSecond)
            if hz > 0 { return hz }
        }
    }
    return 60.0
}

func displayRefreshInterval(for window: NSWindow?) -> TimeInterval {
    let hz = displayRefreshRateHz(for: window)
    return 1.0 / max(1.0, hz)
}

enum SearchPerfLog {
    private static let log = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "search.perf")
    static var isEnabled: Bool { searchLatencyDebugEnabled || perfDebugEnabled }

    @inline(__always)
    static func measure<T>(_ name: String,
                           thresholdMS: Double = 3.0,
                           _ block: () throws -> T) rethrows -> T {
        guard isEnabled else { return try block() }
        let start = monotonicNowNs()
        let result = try block()
        let elapsedMs = Double(monotonicNowNs() &- start) / 1_000_000.0
        let startMs = Double(start) / 1_000_000.0
        if elapsedMs >= thresholdMS {
            os_log("[SearchPerf] %{public}@ t_ms=%.3f dt_ms=%.3f (slow)", log: log, type: .info, name, startMs, elapsedMs)
        } else {
            os_log("[SearchPerf] %{public}@ t_ms=%.3f dt_ms=%.3f", log: log, type: .debug, name, startMs, elapsedMs)
        }
        return result
    }

    static func logDuration(_ name: String, durationNs: UInt64, thresholdMS: Double = 3.0) {
        guard isEnabled else { return }
        let elapsedMs = Double(durationNs) / 1_000_000.0
        if elapsedMs >= thresholdMS {
            os_log("[SearchPerf] %{public}@ %.3fms (slow)", log: log, type: .info, name, elapsedMs)
        } else {
            os_log("[SearchPerf] %{public}@ %.3fms", log: log, type: .debug, name, elapsedMs)
        }
    }
}

#if DEBUG
enum PerfLogger {
    private static let log = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "perf")
    private static let defaultWarnThresholdMS: Double = 4.5
    private static let lock = NSLock()
    private static var starts: [String: UInt64] = [:]
    private static var lastDurationsMS: [String: Double] = [:]

    static var isEnabled: Bool {
        ProcessInfo.processInfo.environment["ARXIV_PERF_LOG"] == "1" || perfDebugEnabled
    }

    @inline(__always)
    static func begin(_ name: String,
                      file: StaticString = #fileID,
                      line: UInt = #line,
                      function: StaticString = #function) {
        guard isEnabled else { return }
        let now = monotonicNowNs()
        lock.lock()
        starts[name] = now
        lock.unlock()
        os_log("perf_begin %{public}@ %{public}@:%{public}u %{public}@",
               log: log,
               type: .debug,
               name,
               String(describing: file),
               line,
               String(describing: function))
    }

    @discardableResult
    @inline(__always)
    static func end(_ name: String,
                    file: StaticString = #fileID,
                    line: UInt = #line,
                    function: StaticString = #function) -> Double? {
        guard isEnabled else { return nil }
        let now = monotonicNowNs()
        let start: UInt64?
        lock.lock()
        start = starts.removeValue(forKey: name)
        lock.unlock()
        guard let start else { return nil }
        let ms = Double(now &- start) / 1_000_000.0
        lock.lock()
        lastDurationsMS[name] = ms
        lock.unlock()
        os_log("perf_end %{public}@ duration_ms=%.3f %{public}@:%{public}u %{public}@",
               log: log,
               type: .debug,
               name,
               ms,
               String(describing: file),
               line,
               String(describing: function))
        if ms > defaultWarnThresholdMS {
            os_log("perf_warn %{public}@ duration_ms=%.3f threshold_ms=%.3f %{public}@:%{public}u %{public}@",
                   log: log,
                   type: .info,
                   name,
                   ms,
                   defaultWarnThresholdMS,
                   String(describing: file),
                   line,
                   String(describing: function))
        }
        return ms
    }

    @discardableResult
    @inline(__always)
    static func measure<T>(_ name: String,
                           _ block: () throws -> T,
                           file: StaticString = #fileID,
                           line: UInt = #line,
                           function: StaticString = #function) rethrows -> T {
        guard isEnabled else { return try block() }
        let start = monotonicNowNs()
        os_log("perf_begin %{public}@ %{public}@:%{public}u %{public}@",
               log: log,
               type: .debug,
               name,
               String(describing: file),
               line,
               String(describing: function))
        defer {
            let ms = Double(monotonicNowNs() &- start) / 1_000_000.0
            lock.lock()
            lastDurationsMS[name] = ms
            lock.unlock()
            os_log("perf_end %{public}@ duration_ms=%.3f %{public}@:%{public}u %{public}@",
                   log: log,
                   type: .debug,
                   name,
                   ms,
                   String(describing: file),
                   line,
                   String(describing: function))
            if ms > defaultWarnThresholdMS {
                os_log("perf_warn %{public}@ duration_ms=%.3f threshold_ms=%.3f %{public}@:%{public}u %{public}@",
                       log: log,
                       type: .info,
                       name,
                       ms,
                       defaultWarnThresholdMS,
                       String(describing: file),
                       line,
                       String(describing: function))
            }
        }
        return try block()
    }

    @inline(__always)
    static func warnIfExceeds(_ name: String,
                              thresholdMS: Double = defaultWarnThresholdMS,
                              file: StaticString = #fileID,
                              line: UInt = #line,
                              function: StaticString = #function) {
        guard isEnabled else { return }
        let ms: Double?
        lock.lock()
        ms = lastDurationsMS[name]
        lock.unlock()
        guard let ms else { return }
        guard ms > thresholdMS else { return }
        os_log("perf_warn %{public}@ duration_ms=%.3f threshold_ms=%.3f %{public}@:%{public}u %{public}@",
               log: log,
               type: .info,
               name,
               ms,
               thresholdMS,
               String(describing: file),
               line,
               String(describing: function))
    }
}
#else
enum PerfLogger {
    @inline(__always)
    static func begin(_ name: String,
                      file: StaticString = #fileID,
                      line: UInt = #line,
                      function: StaticString = #function) {}

    @inline(__always)
    @discardableResult
    static func end(_ name: String,
                    file: StaticString = #fileID,
                    line: UInt = #line,
                    function: StaticString = #function) -> Double? { nil }

    @discardableResult
    @inline(__always)
    static func measure<T>(_ name: String,
                           _ block: () throws -> T,
                           file: StaticString = #fileID,
                           line: UInt = #line,
                           function: StaticString = #function) rethrows -> T {
        try block()
    }

    @inline(__always)
    static func warnIfExceeds(_ name: String,
                              thresholdMS: Double = 0,
                              file: StaticString = #fileID,
                              line: UInt = #line,
                              function: StaticString = #function) {}
}
#endif

final class ChatLatencyProbe {
    static let shared = ChatLatencyProbe()

    private let log = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "chat.latency")
    private let signpostLog = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "chat.latency.signpost")
    private let lock = NSLock()

    private var token: UInt64 = 0
    private var actionNs: UInt64 = 0
    private var animationCommitNs: UInt64 = 0
    private var firstVsyncNs: UInt64 = 0
    private var opening: Bool = false
    private var signpostID: OSSignpostID = .invalid

    private var displayLink: AnyObject?
    private var displayLinkActive = false
    private var displayLinkFallbackTimer: Timer?

    private var dragFrameCount: Int = 0
    private var dragFrameOver1x: Int = 0
    private var dragFrameOver2x: Int = 0
    private var dragMaxFrameNs: UInt64 = 0
    private var dragLastVsyncNs: UInt64 = 0

    private init() {}

    private func stdoutLog(_ message: String) {
        // `os_log`/signposts are visible in Console/Instruments but not reliably in stdout.
        // For latency proof in terminal, mirror the key events to NSLog when enabled.
        NSLog("[CHAT_LATENCY] \(message)")
    }

    func markButtonAction(opening: Bool) {
        guard chatLatencyDebugEnabled else { return }
        lock.lock()
        token &+= 1
        self.opening = opening
        actionNs = monotonicNowNs()
        animationCommitNs = 0
        firstVsyncNs = 0
        signpostID = OSSignpostID(log: signpostLog)
        let currentToken = token
        lock.unlock()

        os_signpost(.begin, log: signpostLog, name: "right_aux_toggle", signpostID: signpostID, "%{public}@ token=%llu", opening ? "open" : "close", currentToken)
        os_log("button_action %{public}@ token=%llu", log: log, type: .info, opening ? "open" : "close", currentToken)
        stdoutLog("button_action \(opening ? "open" : "close") token=\(currentToken)")
        startDisplayLinkIfNeeded()
    }

    func markAnimationCommitted() {
        guard chatLatencyDebugEnabled else { return }
        let now = monotonicNowNs()
        lock.lock()
        if animationCommitNs == 0 {
            animationCommitNs = now
        }
        let currentToken = token
        let opening = self.opening
        let deltaMs = Double(now &- actionNs) / 1_000_000.0
        lock.unlock()

        os_signpost(.event, log: signpostLog, name: "anim_commit", signpostID: signpostID, "dt_ms=%.3f token=%llu", deltaMs, currentToken)
        os_log("anim_commit %{public}@ dt_ms=%.3f token=%llu", log: log, type: .info, opening ? "open" : "close", deltaMs, currentToken)
        stdoutLog(String(format: "anim_commit %@ dt_ms=%.3f token=%llu", opening ? "open" : "close", deltaMs, currentToken))
    }

    private func markFirstVsyncCallback(vsyncNs: UInt64) {
        guard chatLatencyDebugEnabled else { return }
        lock.lock()
        guard firstVsyncNs == 0 else { lock.unlock(); return }
        firstVsyncNs = vsyncNs
        let currentToken = token
        let opening = self.opening
        let actionDeltaMs = Double(vsyncNs &- actionNs) / 1_000_000.0
        let commitDeltaMs: Double
        if animationCommitNs > 0, vsyncNs >= animationCommitNs {
            commitDeltaMs = Double(vsyncNs &- animationCommitNs) / 1_000_000.0
        } else {
            commitDeltaMs = -1
        }
        lock.unlock()

        os_signpost(.event, log: signpostLog, name: "first_vsync", signpostID: signpostID, "action_ms=%.3f commit_ms=%.3f token=%llu", actionDeltaMs, commitDeltaMs, currentToken)
        os_log("first_vsync %{public}@ action_ms=%.3f commit_ms=%.3f token=%llu", log: log, type: .info, opening ? "open" : "close", actionDeltaMs, commitDeltaMs, currentToken)
        stdoutLog(String(format: "first_vsync %@ action_ms=%.3f commit_ms=%.3f token=%llu", opening ? "open" : "close", actionDeltaMs, commitDeltaMs, currentToken))
        os_signpost(.end, log: signpostLog, name: "right_aux_toggle", signpostID: signpostID, "token=%llu", currentToken)
        stopDisplayLinkIfNeeded()
    }

    @available(macOS 14.0, *)
    @objc private func handleDisplayLinkTick(_ link: CADisplayLink) {
        let vsyncNs = monotonicNowNs()
        markFirstVsyncCallback(vsyncNs: vsyncNs)
    }

    @available(macOS 14.0, *)
    private func makeDisplayLink() -> CADisplayLink? {
        if let window = NSApp.keyWindow ?? NSApp.mainWindow {
            return window.displayLink(target: self, selector: #selector(handleDisplayLinkTick(_:)))
        }
        if let screen = NSScreen.main {
            return screen.displayLink(target: self, selector: #selector(handleDisplayLinkTick(_:)))
        }
        return nil
    }

    private func startDisplayLinkIfNeeded() {
        guard chatLatencyDebugEnabled else { return }
        lock.lock()
        let needsStart = !displayLinkActive
        lock.unlock()
        guard needsStart else { return }

        if #available(macOS 14.0, *), let link = makeDisplayLink() {
            link.add(to: .main, forMode: .common)
            link.isPaused = false
            lock.lock()
            displayLink = link
            displayLinkActive = true
            lock.unlock()
            return
        }

        let timer = Timer.scheduledTimer(withTimeInterval: 1.0 / 60.0, repeats: false) { [weak self] _ in
            self?.markFirstVsyncCallback(vsyncNs: monotonicNowNs())
        }
        lock.lock()
        displayLinkFallbackTimer = timer
        displayLinkActive = true
        lock.unlock()
    }

    private func stopDisplayLinkIfNeeded() {
        lock.lock()
        guard displayLinkActive else { lock.unlock(); return }
        let linkObject = displayLink
        let timer = displayLinkFallbackTimer
        displayLinkActive = false
        displayLink = nil
        displayLinkFallbackTimer = nil
        lock.unlock()
        if #available(macOS 14.0, *), let link = linkObject as? CADisplayLink {
            link.invalidate()
        }
        timer?.invalidate()
    }
}

final class SearchLatencyProbe {
    static let shared = SearchLatencyProbe()

    private let log = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "search.latency")
    private let signpostLog = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "search.latency.signpost")
    private let lock = NSLock()

    private var token: UInt64 = 0
    private var keypressNs: UInt64 = 0
    private var firstVsyncNs: UInt64 = 0
    private var sourceLabel: String = ""
    private var signpostID: OSSignpostID = .invalid

    private var displayLink: AnyObject?
    private var displayLinkActive = false
    private var displayLinkFallbackTimer: Timer?

    private init() {}

    private func stdoutLog(_ message: String) {
        NSLog("[SEARCH_LATENCY] \(message)")
    }

    func markKeypress(source: String, query: String?, window: NSWindow?) {
        guard searchLatencyDebugEnabled else { return }
        lock.lock()
        token &+= 1
        keypressNs = monotonicNowNs()
        firstVsyncNs = 0
        sourceLabel = source
        signpostID = OSSignpostID(log: signpostLog)
        let currentToken = token
        lock.unlock()

        let qLen = query?.count ?? 0
        os_signpost(.begin, log: signpostLog, name: "search_keypress", signpostID: signpostID,
                    "source=%{public}@ token=%llu q_len=%d", source, currentToken, qLen)
        os_log("search_keypress source=%{public}@ token=%llu q_len=%d",
               log: log, type: .info, source, currentToken, qLen)
        stdoutLog("keypress source=\(source) token=\(currentToken) q_len=\(qLen)")
        startDisplayLinkIfNeeded(window: window)
    }

    private func markFirstVsyncCallback(vsyncNs: UInt64) {
        guard searchLatencyDebugEnabled else { return }
        lock.lock()
        guard firstVsyncNs == 0 else { lock.unlock(); return }
        firstVsyncNs = vsyncNs
        let currentToken = token
        let startNs = keypressNs
        let source = sourceLabel
        lock.unlock()

        let deltaMs = startNs > 0 ? Double(vsyncNs &- startNs) / 1_000_000.0 : -1
        os_signpost(.event, log: signpostLog, name: "first_vsync", signpostID: signpostID,
                    "dt_ms=%.3f token=%llu", deltaMs, currentToken)
        os_log("first_vsync source=%{public}@ dt_ms=%.3f token=%llu",
               log: log, type: .info, source, deltaMs, currentToken)
        stdoutLog(String(format: "first_vsync source=%@ dt_ms=%.3f token=%llu", source, deltaMs, currentToken))
        os_signpost(.end, log: signpostLog, name: "search_keypress", signpostID: signpostID,
                    "token=%llu", currentToken)
        stopDisplayLinkIfNeeded()
    }

    @available(macOS 14.0, *)
    @objc private func handleDisplayLinkTick(_ link: CADisplayLink) {
        markFirstVsyncCallback(vsyncNs: monotonicNowNs())
    }

    @available(macOS 14.0, *)
    private func makeDisplayLink(window: NSWindow?) -> CADisplayLink? {
        if let host = window ?? NSApp.keyWindow ?? NSApp.mainWindow {
            return host.displayLink(target: self, selector: #selector(handleDisplayLinkTick(_:)))
        }
        if let screen = NSScreen.main {
            return screen.displayLink(target: self, selector: #selector(handleDisplayLinkTick(_:)))
        }
        return nil
    }

    private func startDisplayLinkIfNeeded(window: NSWindow?) {
        guard searchLatencyDebugEnabled else { return }
        lock.lock()
        let needsStart = !displayLinkActive
        lock.unlock()
        guard needsStart else { return }

        if #available(macOS 14.0, *), let link = makeDisplayLink(window: window) {
            link.add(to: .main, forMode: .common)
            link.isPaused = false
            lock.lock()
            displayLink = link
            displayLinkActive = true
            lock.unlock()
            return
        }

        let interval = displayRefreshInterval(for: window)
        let timer = Timer.scheduledTimer(withTimeInterval: interval, repeats: false) { [weak self] _ in
            self?.markFirstVsyncCallback(vsyncNs: monotonicNowNs())
        }
        lock.lock()
        displayLinkFallbackTimer = timer
        displayLinkActive = true
        lock.unlock()
    }

    private func stopDisplayLinkIfNeeded() {
        lock.lock()
        guard displayLinkActive else { lock.unlock(); return }
        let linkObject = displayLink
        let timer = displayLinkFallbackTimer
        displayLinkActive = false
        displayLink = nil
        displayLinkFallbackTimer = nil
        lock.unlock()
        if #available(macOS 14.0, *), let link = linkObject as? CADisplayLink {
            link.invalidate()
        }
        timer?.invalidate()
    }
}

struct AnimationGuardMeasurement {
    #if DEBUG
    let label: String
    let startNs: UInt64
    let preAnimation: Bool
    let token: UInt64
    let enabled: Bool
    #endif
}

enum AnimationGuard {
    private static let lock = NSLock()
    private static var currentToken: UInt64 = 0
    private static var currentLabel: String = ""
    private static var actionStartNs: UInt64 = 0
    private static var animationStartNs: UInt64 = 0
    private static var preAnimationActive = false
    #if DEBUG
    private static let log = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "animation.guard")
    private static let warnThresholdMs: Double = 2.5
    #endif

    static var isEnabled: Bool {
        #if DEBUG
        return perfDebugEnabled || ProcessInfo.processInfo.environment["ARXIV_ANIMATION_GUARD"] == "1"
        #else
        return false
        #endif
    }

    static var shouldDeferHeavyWork: Bool {
        return isPreAnimationActive()
    }

    static func performAnimated(_ label: String,
                                action: () -> Void,
                                deferredWork: (() -> Void)? = nil) {
        let token = beginState(label)
        #if DEBUG
        let actionStart = monotonicNowNs()
        #endif
        action()
        #if DEBUG
        let actionEnd = monotonicNowNs()
        #endif
        clearPreAnimationIfNeeded(token: token, label: label)
        #if DEBUG
        if isEnabled {
            let actionMs = Double(actionEnd &- actionStart) / 1_000_000.0
            if actionMs > warnThresholdMs {
                os_log("action_block label=%{public}@ duration_ms=%.3f token=%llu",
                       log: log, type: .info, label, actionMs, token)
                NSLog("[ANIM_GUARD] action_block label=%@ duration_ms=%.3f token=%llu", label, actionMs, token)
            } else {
                os_log("action_done label=%{public}@ duration_ms=%.3f token=%llu",
                       log: log, type: .debug, label, actionMs, token)
            }
            if !hasAnimationStarted(token: token) {
                os_log("anim_missing label=%{public}@ token=%llu", log: log, type: .error, label, token)
                NSLog("[ANIM_GUARD] anim_missing label=%@ token=%llu", label, token)
            }
        }
        #endif
        if let deferredWork {
            deferWork(label: "\(label).deferred", deferredWork)
        }
    }

    static func markAnimationStart(_ label: String? = nil) {
        let now = monotonicNowNs()
        var shouldLog = false
        var token: UInt64 = 0
        var startNs: UInt64 = 0
        var name = label ?? ""
        lock.lock()
        if animationStartNs == 0 {
            animationStartNs = now
            preAnimationActive = false
            shouldLog = true
        }
        token = currentToken
        startNs = actionStartNs
        if name.isEmpty { name = currentLabel }
        lock.unlock()
        #if DEBUG
        guard isEnabled else { return }
        guard shouldLog, startNs > 0 else { return }
        let deltaMs = Double(now &- startNs) / 1_000_000.0
        let nowMs = Double(now) / 1_000_000.0
        os_log("anim_start label=%{public}@ t_ms=%.3f dt_ms=%.3f token=%llu",
               log: log, type: .info, name, nowMs, deltaMs, token)
        NSLog("[ANIM_GUARD] anim_start label=%@ t_ms=%.3f dt_ms=%.3f token=%llu", name, nowMs, deltaMs, token)
        if deltaMs > warnThresholdMs {
            os_log("anim_start_slow label=%{public}@ t_ms=%.3f dt_ms=%.3f token=%llu",
                   log: log, type: .info, name, nowMs, deltaMs, token)
            NSLog("[ANIM_GUARD] anim_start_slow label=%@ t_ms=%.3f dt_ms=%.3f token=%llu", name, nowMs, deltaMs, token)
        }
        #endif
    }

    static func recordKickstart(_ label: String) {
        #if DEBUG
        guard isEnabled else { return }
        let now = monotonicNowNs()
        lock.lock()
        let token = currentToken
        let startNs = actionStartNs
        lock.unlock()
        let deltaMs: Double = startNs > 0 ? Double(now &- startNs) / 1_000_000.0 : -1
        let nowMs = Double(now) / 1_000_000.0
        os_log("kickstart label=%{public}@ t_ms=%.3f dt_ms=%.3f token=%llu",
               log: log, type: .info, label, nowMs, deltaMs, token)
        NSLog("[ANIM_GUARD] kickstart label=%@ t_ms=%.3f dt_ms=%.3f token=%llu", label, nowMs, deltaMs, token)
        #endif
    }

    static func trace(_ label: String, details: String? = nil) {
        #if DEBUG
        guard isEnabled else { return }
        let now = monotonicNowNs()
        let nowMs = Double(now) / 1_000_000.0
        let pre = isPreAnimationActive()
        let token = currentToken
        let info = details ?? ""
        os_log("trace label=%{public}@ t_ms=%.3f pre_anim=%{public}@ token=%llu %{public}@",
               log: log, type: .debug, label, nowMs, pre ? "true" : "false", token, info)
        #endif
    }

    static func beginMeasurement(_ label: String) -> AnimationGuardMeasurement {
        #if DEBUG
        guard isEnabled else {
            return AnimationGuardMeasurement(label: label, startNs: 0, preAnimation: false, token: 0, enabled: false)
        }
        let now = monotonicNowNs()
        let pre = isPreAnimationActive()
        let token = currentToken
        return AnimationGuardMeasurement(label: label, startNs: now, preAnimation: pre, token: token, enabled: true)
        #else
        return AnimationGuardMeasurement()
        #endif
    }

    static func endMeasurement(_ measurement: AnimationGuardMeasurement, details: String? = nil) {
        #if DEBUG
        guard measurement.enabled else { return }
        let now = monotonicNowNs()
        let nowMs = Double(now) / 1_000_000.0
        let ms = Double(now &- measurement.startNs) / 1_000_000.0
        let info = details ?? ""
        if measurement.preAnimation {
            if ms > warnThresholdMs {
                os_log("pre_anim_block label=%{public}@ t_ms=%.3f duration_ms=%.3f token=%llu %{public}@",
                       log: log, type: .info, measurement.label, nowMs, ms, measurement.token, info)
                NSLog("[ANIM_GUARD] pre_anim_block label=%@ t_ms=%.3f duration_ms=%.3f token=%llu %@", measurement.label, nowMs, ms, measurement.token, info)
            } else {
                os_log("pre_anim_work label=%{public}@ t_ms=%.3f duration_ms=%.3f token=%llu %{public}@",
                       log: log, type: .debug, measurement.label, nowMs, ms, measurement.token, info)
            }
        } else {
            os_log("post_anim_work label=%{public}@ t_ms=%.3f duration_ms=%.3f token=%llu %{public}@",
                   log: log, type: .debug, measurement.label, nowMs, ms, measurement.token, info)
        }
        #endif
    }

    static func measure<T>(_ label: String, _ block: () throws -> T) rethrows -> T {
        #if DEBUG
        let measurement = beginMeasurement(label)
        defer { endMeasurement(measurement) }
        return try block()
        #else
        return try block()
        #endif
    }

    static func deferWork(label: String, _ work: @escaping () -> Void) {
        #if DEBUG
        if isEnabled {
            os_log("defer label=%{public}@", log: log, type: .debug, label)
        }
        #endif
        DispatchQueue.main.async(execute: work)
    }

    private static func beginState(_ label: String) -> UInt64 {
        let now = monotonicNowNs()
        lock.lock()
        currentToken &+= 1
        let token = currentToken
        currentLabel = label
        actionStartNs = now
        animationStartNs = 0
        preAnimationActive = true
        lock.unlock()
        #if DEBUG
        if isEnabled {
            os_log("begin label=%{public}@ token=%llu", log: log, type: .info, label, token)
            NSLog("[ANIM_GUARD] begin label=%@ token=%llu", label, token)
        }
        #endif
        return token
    }

    private static func isPreAnimationActive() -> Bool {
        lock.lock()
        let value = preAnimationActive
        lock.unlock()
        return value
    }

    private static func clearPreAnimationIfNeeded(token: UInt64, label: String) {
        lock.lock()
        let shouldClear = (token == currentToken) && animationStartNs == 0
        if shouldClear {
            preAnimationActive = false
        }
        lock.unlock()
        #if DEBUG
        if shouldClear && isEnabled {
            os_log("pre_anim_reset label=%{public}@ token=%llu", log: log, type: .info, label, token)
            NSLog("[ANIM_GUARD] pre_anim_reset label=%@ token=%llu", label, token)
        }
        #endif
    }

    #if DEBUG
    private static func hasAnimationStarted(token: UInt64) -> Bool {
        lock.lock()
        let started = (token == currentToken) && animationStartNs > 0
        lock.unlock()
        return started
    }
    #endif
}

final class ResizeLatencyProbe {
    static let shared = ResizeLatencyProbe()

    private let log = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "ui.resize")
    private let signpostLog = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "ui.resize.signpost")
    private let lock = NSLock()

    private var token: UInt64 = 0
    private var signpostID: OSSignpostID = .invalid
    private var dragActive = false
    private var lastDragEventNs: UInt64 = 0
    private var pendingVsync = false
    private var windowResizeActive = false
    private var windowResizeToken: UInt64 = 0
    private var windowResizeSignpostID: OSSignpostID = .invalid
    private var windowResizeStartNs: UInt64 = 0
    private var windowResizeLastEventNs: UInt64 = 0
    private var windowResizePendingVsync = false
    private var windowResizeDroppedFrames: Int = 0
    private var windowResizeLastVsyncNs: UInt64 = 0
    private var dragFrameCount: Int = 0
    private var dragFrameOver1x: Int = 0
    private var dragFrameOver2x: Int = 0
    private var dragMaxFrameNs: UInt64 = 0
    private var dragLastVsyncNs: UInt64 = 0

    private var displayLink: AnyObject?
    private var displayLinkActive = false
    private var displayLinkFallbackTimer: Timer?

    private init() {}

    private func stdoutLog(_ message: String) {
        NSLog("[UI_RESIZE] \(message)")
    }

    func beginDrag(reason: String) {
        guard perfDebugEnabled else { return }
        lock.lock()
        token &+= 1
        dragActive = true
        lastDragEventNs = 0
        pendingVsync = false
        dragFrameCount = 0
        dragFrameOver1x = 0
        dragFrameOver2x = 0
        dragMaxFrameNs = 0
        dragLastVsyncNs = 0
        signpostID = OSSignpostID(log: signpostLog)
        let currentToken = token
        lock.unlock()

        os_signpost(.begin, log: signpostLog, name: "divider_drag", signpostID: signpostID,
                    "reason=%{public}@ token=%llu", reason, currentToken)
        os_log("drag_begin reason=%{public}@ token=%llu", log: log, type: .info, reason, currentToken)
        stdoutLog("drag_begin reason=\(reason) token=\(currentToken)")
    }

    func endDrag(reason: String) {
        guard perfDebugEnabled else { return }
        lock.lock()
        guard dragActive else { lock.unlock(); return }
        dragActive = false
        pendingVsync = false
        let currentToken = token
        lock.unlock()

        os_signpost(.end, log: signpostLog, name: "divider_drag", signpostID: signpostID,
                    "reason=%{public}@ token=%llu", reason, currentToken)
        os_log("drag_end reason=%{public}@ token=%llu", log: log, type: .info, reason, currentToken)
        stdoutLog("drag_end reason=\(reason) token=\(currentToken)")
        logDragFrameSummary(reason: reason, token: currentToken)
        stopDisplayLinkIfNeeded()
    }

    func markDragUpdate(width: CGFloat, source: String) {
        guard perfDebugEnabled else { return }
        let now = monotonicNowNs()
        lock.lock()
        guard dragActive else { lock.unlock(); return }
        lastDragEventNs = now
        pendingVsync = true
        let currentToken = token
        lock.unlock()

        os_signpost(.event, log: signpostLog, name: "drag_update", signpostID: signpostID,
                    "width=%.2f source=%{public}@ token=%llu", width, source, currentToken)
        os_log("drag_update source=%{public}@ width=%.2f token=%llu", log: log, type: .info, source, width, currentToken)
        startDisplayLinkIfNeeded()
    }

    func markLayoutPass(name: String, durationNs: UInt64) {
        guard perfDebugEnabled else { return }
        let now = monotonicNowNs()
        lock.lock()
        let dragNs = lastDragEventNs
        let currentToken = token
        lock.unlock()

        let durationMs = Double(durationNs) / 1_000_000.0
        let dragToLayoutMs: Double = (dragNs > 0 && now >= dragNs)
            ? Double(now &- dragNs) / 1_000_000.0
            : -1
        os_signpost(.event, log: signpostLog, name: "layout_pass", signpostID: signpostID,
                    "name=%{public}@ duration_ms=%.3f drag_to_layout_ms=%.3f token=%llu",
                    name, durationMs, dragToLayoutMs, currentToken)
        os_log("layout_pass name=%{public}@ duration_ms=%.3f drag_to_layout_ms=%.3f token=%llu",
               log: log, type: .info, name, durationMs, dragToLayoutMs, currentToken)
    }

    @available(macOS 14.0, *)
    @objc private func handleDisplayLinkTick(_ link: CADisplayLink) {
        let now = monotonicNowNs()
        markFirstVsyncCallback(vsyncNs: now)
        markDragFramePacing(vsyncNs: now)
        markWindowResizeVsync(vsyncNs: now)
    }

    private func markFirstVsyncCallback(vsyncNs: UInt64) {
        guard perfDebugEnabled else { return }
        lock.lock()
        guard pendingVsync, lastDragEventNs > 0 else { lock.unlock(); return }
        pendingVsync = false
        let dragNs = lastDragEventNs
        let currentToken = token
        lock.unlock()

        let deltaMs = Double(vsyncNs &- dragNs) / 1_000_000.0
        os_signpost(.event, log: signpostLog, name: "drag_vsync", signpostID: signpostID,
                    "drag_to_vsync_ms=%.3f token=%llu", deltaMs, currentToken)
        os_log("drag_vsync dt_ms=%.3f token=%llu", log: log, type: .info, deltaMs, currentToken)
        stdoutLog(String(format: "drag_vsync dt_ms=%.3f token=%llu", deltaMs, currentToken))
        ResizePerfTrace.shared.recordDragToVsync(deltaMs: deltaMs)
    }

    private func markDragFramePacing(vsyncNs: UInt64) {
        guard perfDebugEnabled else { return }
        let interval = displayRefreshInterval(for: NSApp.keyWindow ?? NSApp.mainWindow)
        let intervalNs = UInt64(max(1.0 / 240.0, interval) * 1_000_000_000.0)

        lock.lock()
        guard dragActive else {
            dragLastVsyncNs = 0
            lock.unlock()
            return
        }
        let lastVsync = dragLastVsyncNs
        dragLastVsyncNs = vsyncNs
        lock.unlock()

        guard lastVsync > 0, intervalNs > 0 else { return }
        let deltaNs = vsyncNs &- lastVsync

        lock.lock()
        dragFrameCount += 1
        if deltaNs > dragMaxFrameNs { dragMaxFrameNs = deltaNs }
        if deltaNs > intervalNs { dragFrameOver1x += 1 }
        if deltaNs > intervalNs * 2 { dragFrameOver2x += 1 }
        lock.unlock()
    }

    private func logDragFrameSummary(reason: String, token: UInt64) {
        guard perfDebugEnabled else { return }
        lock.lock()
        let frameCount = dragFrameCount
        let over1x = dragFrameOver1x
        let over2x = dragFrameOver2x
        let maxFrameNs = dragMaxFrameNs
        lock.unlock()

        guard frameCount > 0 else { return }
        let maxFrameMs = Double(maxFrameNs) / 1_000_000.0
        let intervalMs = displayRefreshInterval(for: NSApp.keyWindow ?? NSApp.mainWindow) * 1000.0
        os_log("drag_frames reason=%{public}@ frames=%{public}d over1x=%{public}d over2x=%{public}d max_ms=%.3f interval_ms=%.3f token=%llu",
               log: log,
               type: .info,
               reason,
               frameCount,
               over1x,
               over2x,
               maxFrameMs,
               intervalMs,
               token)
        stdoutLog(String(format: "drag_frames reason=%@ frames=%d over1x=%d over2x=%d max_ms=%.3f interval_ms=%.3f token=%llu",
                         reason, frameCount, over1x, over2x, maxFrameMs, intervalMs, token))
    }

    private func markWindowResizeVsync(vsyncNs: UInt64) {
        guard perfDebugEnabled else { return }
        let interval = displayRefreshInterval(for: NSApp.keyWindow ?? NSApp.mainWindow)
        let intervalNs = UInt64(max(1.0 / 240.0, interval) * 1_000_000_000.0)

        lock.lock()
        guard windowResizeActive else { lock.unlock(); return }
        let pending = windowResizePendingVsync
        if pending { windowResizePendingVsync = false }
        let eventNs = windowResizeLastEventNs
        let startNs = windowResizeStartNs
        let token = windowResizeToken
        let lastVsync = windowResizeLastVsyncNs
        windowResizeLastVsyncNs = vsyncNs
        lock.unlock()

        if pending && eventNs > 0 {
            let deltaMs = Double(vsyncNs &- eventNs) / 1_000_000.0
            let startDeltaMs = startNs > 0 ? Double(vsyncNs &- startNs) / 1_000_000.0 : -1
            os_signpost(.event, log: signpostLog, name: "window_resize_vsync", signpostID: windowResizeSignpostID,
                        "dt_ms=%.3f start_ms=%.3f token=%llu", deltaMs, startDeltaMs, token)
            os_log("window_resize_vsync dt_ms=%.3f start_ms=%.3f token=%llu", log: log, type: .info, deltaMs, startDeltaMs, token)
            stdoutLog(String(format: "window_resize_vsync dt_ms=%.3f start_ms=%.3f token=%llu", deltaMs, startDeltaMs, token))
        }

        guard lastVsync > 0, intervalNs > 0 else { return }
        let deltaNs = vsyncNs &- lastVsync
        if deltaNs > (intervalNs * 3 / 2) {
            let dropped = max(0, Int(Double(deltaNs) / Double(intervalNs)) - 1)
            guard dropped > 0 else { return }
            lock.lock()
            windowResizeDroppedFrames += dropped
            lock.unlock()
            os_log("window_resize_frame_drop dropped=%{public}d token=%llu", log: log, type: .info, dropped, token)
        }
    }

    @available(macOS 14.0, *)
    private func makeDisplayLink() -> CADisplayLink? {
        if let window = NSApp.keyWindow ?? NSApp.mainWindow {
            return window.displayLink(target: self, selector: #selector(handleDisplayLinkTick(_:)))
        }
        if let screen = NSScreen.main {
            return screen.displayLink(target: self, selector: #selector(handleDisplayLinkTick(_:)))
        }
        return nil
    }

    private func startDisplayLinkIfNeeded() {
        guard perfDebugEnabled else { return }
        lock.lock()
        let needsStart = !displayLinkActive
        if needsStart { displayLinkActive = true }
        lock.unlock()
        guard needsStart else { return }

        if #available(macOS 14.0, *), let link = makeDisplayLink() {
            link.add(to: .main, forMode: .common)
            link.isPaused = false
            lock.lock()
            displayLink = link
            lock.unlock()
            return
        }

        let interval = displayRefreshInterval(for: NSApp.keyWindow ?? NSApp.mainWindow)
        let timer = Timer.scheduledTimer(withTimeInterval: interval, repeats: true) { [weak self] _ in
            let now = monotonicNowNs()
            self?.markFirstVsyncCallback(vsyncNs: now)
            self?.markDragFramePacing(vsyncNs: now)
        }
        timer.tolerance = interval * 0.2
        lock.lock()
        displayLinkFallbackTimer = timer
        lock.unlock()
    }

    private func stopDisplayLinkIfNeeded() {
        lock.lock()
        let shouldStop = displayLinkActive && !dragActive && !windowResizeActive
        if !shouldStop {
            lock.unlock()
            return
        }
        displayLinkActive = false
        let link = displayLink
        displayLink = nil
        let timer = displayLinkFallbackTimer
        displayLinkFallbackTimer = nil
        lock.unlock()

        if #available(macOS 14.0, *), let link = link as? CADisplayLink {
            link.invalidate()
        }
        timer?.invalidate()
    }

    func beginWindowResize(reason: String) {
        guard perfDebugEnabled else { return }
        lock.lock()
        windowResizeToken &+= 1
        windowResizeActive = true
        windowResizeStartNs = monotonicNowNs()
        windowResizeLastEventNs = 0
        windowResizePendingVsync = false
        windowResizeDroppedFrames = 0
        windowResizeLastVsyncNs = 0
        windowResizeSignpostID = OSSignpostID(log: signpostLog)
        let currentToken = windowResizeToken
        lock.unlock()

        os_signpost(.begin, log: signpostLog, name: "window_resize", signpostID: windowResizeSignpostID,
                    "reason=%{public}@ token=%llu", reason, currentToken)
        os_log("window_resize_begin reason=%{public}@ token=%llu", log: log, type: .info, reason, currentToken)
        stdoutLog("window_resize_begin reason=\(reason) token=\(currentToken)")
        startDisplayLinkIfNeeded()
    }

    func endWindowResize(reason: String) {
        guard perfDebugEnabled else { return }
        lock.lock()
        guard windowResizeActive else { lock.unlock(); return }
        windowResizeActive = false
        windowResizePendingVsync = false
        let currentToken = windowResizeToken
        let dropped = windowResizeDroppedFrames
        let startNs = windowResizeStartNs
        lock.unlock()

        let durationMs = startNs > 0 ? Double(monotonicNowNs() &- startNs) / 1_000_000.0 : -1
        os_signpost(.end, log: signpostLog, name: "window_resize", signpostID: windowResizeSignpostID,
                    "reason=%{public}@ duration_ms=%.3f dropped=%d token=%llu", reason, durationMs, dropped, currentToken)
        os_log("window_resize_end reason=%{public}@ duration_ms=%.3f dropped=%d token=%llu",
               log: log, type: .info, reason, durationMs, dropped, currentToken)
        stdoutLog(String(format: "window_resize_end reason=%@ duration_ms=%.3f dropped=%d token=%llu",
                         reason, durationMs, dropped, currentToken))
        stopDisplayLinkIfNeeded()
    }

    func markWindowResizeEvent(width: CGFloat, source: String) {
        guard perfDebugEnabled else { return }
        let now = monotonicNowNs()
        lock.lock()
        guard windowResizeActive else { lock.unlock(); return }
        windowResizeLastEventNs = now
        windowResizePendingVsync = true
        let currentToken = windowResizeToken
        lock.unlock()

        os_signpost(.event, log: signpostLog, name: "window_resize_update", signpostID: windowResizeSignpostID,
                    "width=%.2f source=%{public}@ token=%llu", width, source, currentToken)
        os_log("window_resize_update source=%{public}@ width=%.2f token=%llu", log: log, type: .info, source, width, currentToken)
        startDisplayLinkIfNeeded()
    }
}

final class ResizePerfTrace {
    static let shared = ResizePerfTrace()

    private struct Stat {
        var count: Int = 0
        var totalNs: UInt64 = 0
        var maxNs: UInt64 = 0
    }

    private let log = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "ui.resize.perf")
    private let lock = NSLock()

    private var active = false
    private var startNs: UInt64 = 0
    private var lastDragEventNs: UInt64 = 0
    private var counts: [String: Int] = [:]
    private var stats: [String: Stat] = [:]
    private var dragToLayoutCount: Int = 0
    private var dragToLayoutTotalMs: Double = 0
    private var dragToLayoutMaxMs: Double = 0
    private var dragToVsyncCount: Int = 0
    private var dragToVsyncTotalMs: Double = 0
    private var dragToVsyncMaxMs: Double = 0

    private init() {}

    var isActive: Bool {
        guard resizePerfEnabled else { return false }
        lock.lock()
        let value = active
        lock.unlock()
        return value
    }

    func beginSession(reason: String) {
        guard resizePerfEnabled else { return }
        lock.lock()
        active = true
        startNs = monotonicNowNs()
        lastDragEventNs = 0
        counts.removeAll(keepingCapacity: true)
        stats.removeAll(keepingCapacity: true)
        dragToLayoutCount = 0
        dragToLayoutTotalMs = 0
        dragToLayoutMaxMs = 0
        dragToVsyncCount = 0
        dragToVsyncTotalMs = 0
        dragToVsyncMaxMs = 0
        lock.unlock()
        os_log("resize_perf_begin reason=%{public}@", log: log, type: .info, reason)
    }

    func endSession(reason: String) {
        guard resizePerfEnabled else { return }
        let now = monotonicNowNs()
        lock.lock()
        guard active else { lock.unlock(); return }
        active = false
        let durationNs = now &- startNs
        let countsSnapshot = counts
        let statsSnapshot = stats
        let dragToLayoutCount = dragToLayoutCount
        let dragToLayoutTotalMs = dragToLayoutTotalMs
        let dragToLayoutMaxMs = dragToLayoutMaxMs
        let dragToVsyncCount = dragToVsyncCount
        let dragToVsyncTotalMs = dragToVsyncTotalMs
        let dragToVsyncMaxMs = dragToVsyncMaxMs
        lock.unlock()

        let durationSec = max(0.001, Double(durationNs) / 1_000_000_000.0)
        func sumCounts(prefix: String) -> Int {
            countsSnapshot
                .filter { $0.key.hasPrefix(prefix) }
                .reduce(0) { $0 + $1.value }
        }

        let layoutCount = sumCounts(prefix: "layout.")
        let autoLayoutCount = sumCounts(prefix: "autolayout.")
        let constraintCount = sumCounts(prefix: "constraint.")
        let invalidateCount = sumCounts(prefix: "invalidate.")

        let layoutHz = Double(layoutCount) / durationSec
        let autoLayoutHz = Double(autoLayoutCount) / durationSec
        let constraintHz = Double(constraintCount) / durationSec
        let invalidateHz = Double(invalidateCount) / durationSec

        let dragToLayoutAvg = dragToLayoutCount > 0 ? (dragToLayoutTotalMs / Double(dragToLayoutCount)) : -1
        let dragToVsyncAvg = dragToVsyncCount > 0 ? (dragToVsyncTotalMs / Double(dragToVsyncCount)) : -1

        os_log("resize_perf_end reason=%{public}@ duration_ms=%.1f layout_hz=%.1f autolayout_hz=%.1f constraint_hz=%.1f invalidate_hz=%.1f drag_to_layout_max=%.2f drag_to_layout_avg=%.2f drag_to_vsync_max=%.2f drag_to_vsync_avg=%.2f",
               log: log,
               type: .info,
               reason,
               durationSec * 1000.0,
               layoutHz,
               autoLayoutHz,
               constraintHz,
               invalidateHz,
               dragToLayoutMaxMs,
               dragToLayoutAvg,
               dragToVsyncMaxMs,
               dragToVsyncAvg)

        let topWork = statsSnapshot
            .sorted { $0.value.maxNs > $1.value.maxNs }
            .prefix(3)
        for (name, stat) in topWork {
            let maxMs = Double(stat.maxNs) / 1_000_000.0
            let avgMs = stat.count > 0 ? (Double(stat.totalNs) / Double(stat.count)) / 1_000_000.0 : 0
            let totalMs = Double(stat.totalNs) / 1_000_000.0
            os_log("resize_perf_heavy name=%{public}@ count=%{public}d max_ms=%.3f avg_ms=%.3f total_ms=%.1f",
                   log: log,
                   type: .info,
                   name,
                   stat.count,
                   maxMs,
                   avgMs,
                   totalMs)
        }

        let topCounts = countsSnapshot
            .sorted { $0.value > $1.value }
            .prefix(5)
        for (name, count) in topCounts {
            os_log("resize_perf_count name=%{public}@ count=%{public}d hz=%.1f",
                   log: log,
                   type: .info,
                   name,
                   count,
                   Double(count) / durationSec)
        }
    }

    func noteDragEvent() {
        guard resizePerfEnabled else { return }
        lock.lock()
        guard active else { lock.unlock(); return }
        lastDragEventNs = monotonicNowNs()
        lock.unlock()
    }

    func noteLayoutPass(name: String, durationNs: UInt64) {
        guard resizePerfEnabled else { return }
        lock.lock()
        guard active else { lock.unlock(); return }
        recordCountLocked("layout.\(name)")
        recordStatLocked("layout.\(name)", durationNs: durationNs)
        if lastDragEventNs > 0 {
            let deltaMs = Double(monotonicNowNs() &- lastDragEventNs) / 1_000_000.0
            dragToLayoutCount += 1
            dragToLayoutTotalMs += deltaMs
            if deltaMs > dragToLayoutMaxMs { dragToLayoutMaxMs = deltaMs }
        }
        lock.unlock()
    }

    func noteAutoLayout(name: String, durationNs: UInt64) {
        guard resizePerfEnabled else { return }
        lock.lock()
        guard active else { lock.unlock(); return }
        recordCountLocked("autolayout.\(name)")
        recordStatLocked("autolayout.\(name)", durationNs: durationNs)
        lock.unlock()
    }

    func noteConstraintAdjust(name: String) {
        guard resizePerfEnabled else { return }
        lock.lock()
        guard active else { lock.unlock(); return }
        recordCountLocked("constraint.\(name)")
        lock.unlock()
    }

    func noteInvalidation(name: String) {
        guard resizePerfEnabled else { return }
        lock.lock()
        guard active else { lock.unlock(); return }
        recordCountLocked("invalidate.\(name)")
        lock.unlock()
    }

    func recordWork(name: String, durationNs: UInt64) {
        guard resizePerfEnabled else { return }
        lock.lock()
        guard active else { lock.unlock(); return }
        recordStatLocked(name, durationNs: durationNs)
        lock.unlock()
    }

    func recordDragToVsync(deltaMs: Double) {
        guard resizePerfEnabled else { return }
        lock.lock()
        guard active else { lock.unlock(); return }
        dragToVsyncCount += 1
        dragToVsyncTotalMs += deltaMs
        if deltaMs > dragToVsyncMaxMs { dragToVsyncMaxMs = deltaMs }
        lock.unlock()
    }

    @inline(__always)
    private func recordCountLocked(_ key: String) {
        counts[key, default: 0] += 1
    }

    @inline(__always)
    private func recordStatLocked(_ key: String, durationNs: UInt64) {
        var stat = stats[key, default: Stat()]
        stat.count += 1
        stat.totalNs &+= durationNs
        if durationNs > stat.maxNs { stat.maxNs = durationNs }
        stats[key] = stat
    }
}

final class SidebarLatencyProbe {
    static let shared = SidebarLatencyProbe()

    private let log = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "sidebar.latency")
    private let signpostLog = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "sidebar.latency.signpost")
    private let lock = NSLock()

    private var token: UInt64 = 0
    private var actionNs: UInt64 = 0
    private var animationCommitNs: UInt64 = 0
    private var opening: Bool = false
    private var signpostID: OSSignpostID = .invalid

    private var displayLink: AnyObject?
    private var displayLinkActive = false
    private var displayLinkFallbackTimer: Timer?

    private init() {}

    private func stdoutLog(_ message: String) {
        NSLog("[SIDEBAR_LATENCY] \(message)")
    }

    func markButtonAction(opening: Bool) {
        guard perfDebugEnabled else { return }
        lock.lock()
        token &+= 1
        self.opening = opening
        actionNs = monotonicNowNs()
        animationCommitNs = 0
        signpostID = OSSignpostID(log: signpostLog)
        let currentToken = token
        lock.unlock()

        os_signpost(.begin, log: signpostLog, name: "sidebar_toggle", signpostID: signpostID,
                    "%{public}@ token=%llu", opening ? "open" : "close", currentToken)
        os_log("button_action %{public}@ token=%llu", log: log, type: .info, opening ? "open" : "close", currentToken)
        stdoutLog("button_action \(opening ? "open" : "close") token=\(currentToken)")
        startDisplayLinkIfNeeded()
    }

    func markAnimationCommitted() {
        guard perfDebugEnabled else { return }
        let now = monotonicNowNs()
        lock.lock()
        guard actionNs > 0 else { lock.unlock(); return }
        if animationCommitNs == 0 {
            animationCommitNs = now
        }
        let currentToken = token
        let opening = self.opening
        let deltaMs = Double(now &- actionNs) / 1_000_000.0
        lock.unlock()

        os_signpost(.event, log: signpostLog, name: "anim_commit", signpostID: signpostID,
                    "dt_ms=%.3f token=%llu", deltaMs, currentToken)
        os_log("anim_commit %{public}@ dt_ms=%.3f token=%llu", log: log, type: .info,
               opening ? "open" : "close", deltaMs, currentToken)
        stdoutLog(String(format: "anim_commit %@ dt_ms=%.3f token=%llu", opening ? "open" : "close", deltaMs, currentToken))
    }

    private func markFirstVsyncCallback(vsyncNs: UInt64) {
        guard perfDebugEnabled else { return }
        lock.lock()
        guard actionNs > 0 else { lock.unlock(); return }
        let currentToken = token
        let opening = self.opening
        let actionDeltaMs = Double(vsyncNs &- actionNs) / 1_000_000.0
        let commitDeltaMs: Double
        if animationCommitNs > 0, vsyncNs >= animationCommitNs {
            commitDeltaMs = Double(vsyncNs &- animationCommitNs) / 1_000_000.0
        } else {
            commitDeltaMs = -1
        }
        lock.unlock()

        os_signpost(.event, log: signpostLog, name: "first_vsync", signpostID: signpostID,
                    "action_ms=%.3f commit_ms=%.3f token=%llu", actionDeltaMs, commitDeltaMs, currentToken)
        os_log("first_vsync %{public}@ action_ms=%.3f commit_ms=%.3f token=%llu", log: log, type: .info,
               opening ? "open" : "close", actionDeltaMs, commitDeltaMs, currentToken)
        stdoutLog(String(format: "first_vsync %@ action_ms=%.3f commit_ms=%.3f token=%llu",
                         opening ? "open" : "close", actionDeltaMs, commitDeltaMs, currentToken))
        os_signpost(.end, log: signpostLog, name: "sidebar_toggle", signpostID: signpostID, "token=%llu", currentToken)
        stopDisplayLinkIfNeeded()
    }

    @available(macOS 14.0, *)
    @objc private func handleDisplayLinkTick(_ link: CADisplayLink) {
        markFirstVsyncCallback(vsyncNs: monotonicNowNs())
    }

    @available(macOS 14.0, *)
    private func makeDisplayLink() -> CADisplayLink? {
        if let window = NSApp.keyWindow ?? NSApp.mainWindow {
            return window.displayLink(target: self, selector: #selector(handleDisplayLinkTick(_:)))
        }
        if let screen = NSScreen.main {
            return screen.displayLink(target: self, selector: #selector(handleDisplayLinkTick(_:)))
        }
        return nil
    }

    private func startDisplayLinkIfNeeded() {
        guard perfDebugEnabled else { return }
        lock.lock()
        let needsStart = !displayLinkActive
        if needsStart { displayLinkActive = true }
        lock.unlock()
        guard needsStart else { return }

        if #available(macOS 14.0, *), let link = makeDisplayLink() {
            link.add(to: .main, forMode: .common)
            link.isPaused = false
            lock.lock()
            displayLink = link
            lock.unlock()
            return
        }

        let interval = displayRefreshInterval(for: NSApp.keyWindow ?? NSApp.mainWindow)
        let timer = Timer.scheduledTimer(withTimeInterval: interval, repeats: true) { [weak self] _ in
            self?.markFirstVsyncCallback(vsyncNs: monotonicNowNs())
        }
        timer.tolerance = interval * 0.2
        lock.lock()
        displayLinkFallbackTimer = timer
        lock.unlock()
    }

    private func stopDisplayLinkIfNeeded() {
        lock.lock()
        let shouldStop = displayLinkActive
        displayLinkActive = false
        let link = displayLink
        displayLink = nil
        let timer = displayLinkFallbackTimer
        displayLinkFallbackTimer = nil
        lock.unlock()

        guard shouldStop else { return }
        if #available(macOS 14.0, *), let link = link as? CADisplayLink {
            link.invalidate()
        }
        timer?.invalidate()
    }
}

func launchLog(_ message: String) {
    guard launchDebugEnabled else { return }
    NSLog("[LAUNCH] \(message)")
    print("[LAUNCH] \(message)")
}

func applyAppDisplayNameIfNeeded() {
    ProcessInfo.processInfo.processName = APP_EFFECTIVE_NAME
    // Avoid mutating Bundle.main via KVC; scripted bundles are not KVC-compliant for CFBundleName.
    if let app = NSApp {
        app.dockTile.display()
    }
}

func logLaunchFlagsIfNeeded() {
    let env = ProcessInfo.processInfo.environment
    let flags = [
        "ARXIV_LAUNCH_CHECK",
        "ARXIV_RUN_PILL_ANIMATION_TESTS",
        "ARXIV_RUN_TOOLBAR_GAP_TESTS",
        "ARXIV_RUN_SETTINGS_TESTS",
        "ARXIV_SHARE_SELF_TEST"
    ]
    let active = flags.filter { env[$0] == "1" }
    if !active.isEmpty {
        NSLog("[LAUNCH] active_flags=\(active.joined(separator: ","))")
    }
}

func launchExit(_ code: Int32, reason: String) -> Never {
    let message = "[LAUNCH_EXIT] reason=\(reason) code=\(code)"
    NSLog("%@", message)
    print(message)
    Darwin.exit(code)
}

func readUserDefault(_ key: String, domains: [String]) -> Any? {
    for domain in domains {
        if domain == "NSGlobalDomain" || domain == ".GlobalPreferences" {
            if let value = CFPreferencesCopyValue(
                key as CFString,
                kCFPreferencesAnyApplication,
                kCFPreferencesCurrentUser,
                kCFPreferencesAnyHost
            ) {
                return value
            }
        }
        if let dict = UserDefaults.standard.persistentDomain(forName: domain),
           let value = dict[key] {
            return value
        }
        if domain != "NSGlobalDomain" && domain != ".GlobalPreferences",
           let suite = UserDefaults(suiteName: domain),
           let value = suite.object(forKey: key) {
            return value
        }
    }
    return UserDefaults.standard.object(forKey: key)
}

func colorFromComponentList(_ values: [Double]) -> NSColor? {
    guard values.count >= 3 else { return nil }
    var r = values[0]
    var g = values[1]
    var b = values[2]
    var a = values.count >= 4 ? values[3] : 1.0
    let maxVal = max(r, g, b, a)
    if maxVal > 1.0 {
        r /= 255.0
        g /= 255.0
        b /= 255.0
        if a > 1.0 { a /= 255.0 }
    }
    func clamp(_ v: Double) -> CGFloat {
        CGFloat(max(0.0, min(1.0, v)))
    }
    return NSColor(srgbRed: clamp(r), green: clamp(g), blue: clamp(b), alpha: clamp(a))
}

func colorFromComponentString(_ raw: String) -> NSColor? {
    let parts = raw.split(whereSeparator: { $0 == " " || $0 == "\t" || $0 == "," })
    let values = parts.prefix(4).compactMap { Double($0) }
    return colorFromComponentList(values)
}

func layoutLog(_ message: String) {
    guard debugLayoutEnabled else { return }
    NSLog("[LayoutDebug] \(message)")
}

final class GapSplitView: NSSplitView {
    var gap: CGFloat = PANEL_INTER_CARD_GAP
    override var dividerThickness: CGFloat { max(1, gap) }

    override func drawDivider(in rect: NSRect) {
        // Intentionally no-op: keep the divider hit area without drawing the line.
    }

    override func resetCursorRects() {
        super.resetCursorRects()
        guard subviews.count >= 2 else { return }
        for i in 0..<(subviews.count - 1) {
            let rect = dividerRect(at: i)
            guard rect.width > 0, rect.height > 0 else { continue }
            addCursorRect(rect, cursor: .resizeLeftRight)
        }
    }

    func dividerRect(at index: Int) -> NSRect {
        // Important: do NOT derive the divider hitbox width from the transient gap between subviews.
        // During AppKit layout churn that gap can become very large, which makes hit-testing/drags
        // feel “stuck” or trigger in the wrong place. Always return a deterministic divider rect.
        guard index >= 0, index < (subviews.count - 1) else { return .zero }
        let first = subviews[index].frame
        let thickness = dividerThickness
        if isVertical {
            return NSRect(x: first.maxX, y: 0, width: thickness, height: bounds.height)
        } else {
            return NSRect(x: 0, y: first.maxY, width: bounds.width, height: thickness)
        }
    }
}

final class SplitDividerHandleView: NSView {
    private let lineLayer = CALayer()
    private var trackingArea: NSTrackingArea?
    private var dragStartX: CGFloat = 0
    private var dragStartPosition: CGFloat = 0
    private var isHovering = false
    private var isDragging = false
    private var didBeginDragCallback = false
    private let lineWidth: CGFloat = max(1, PANEL_BORDER_WIDTH)
    private var lastDragLogTime: TimeInterval = 0

    var paletteProvider: (() -> (fill: NSColor, glow: NSColor, glowOpacity: Float))?
    var positionProvider: (() -> CGFloat)?
    var clampPosition: ((CGFloat) -> CGFloat)?
    var applyPosition: ((CGFloat) -> Void)?
    var onDragBegin: (() -> Void)?
    var onDragEnd: (() -> Void)?
    var debugName: String = "divider_handle"

    private var appearanceObserver: Any?

    override init(frame frameRect: NSRect) {
        super.init(frame: frameRect)
        wantsLayer = true
        layer?.backgroundColor = NSColor.clear.cgColor
        lineLayer.backgroundColor = NSColor.clear.cgColor
        lineLayer.shadowOpacity = 0
        lineLayer.shadowRadius = 0
        lineLayer.shadowOffset = .zero
        lineLayer.masksToBounds = false
        lineLayer.contentsScale = NSScreen.main?.backingScaleFactor ?? 2.0
        // Hide the divider indicator while keeping the handle for dragging.
        lineLayer.isHidden = true
        layer?.addSublayer(lineLayer)
        updateLineStyle()

        appearanceObserver = NotificationCenter.default.addObserver(
            forName: .arxivAppearanceDidChange,
            object: AppearanceManager.shared,
            queue: .main
        ) { [weak self] _ in
            self?.updateLineStyle()
        }
    }

    required init?(coder: NSCoder) { fatalError() }

    deinit {
        if let appearanceObserver {
            NotificationCenter.default.removeObserver(appearanceObserver)
        }
    }

    override var isOpaque: Bool { false }

    override func layout() {
        PerfLogger.begin("layout.split_divider_handle")
        defer { PerfLogger.end("layout.split_divider_handle") }
        super.layout()
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        let verticalInset = max(4, min(12, PANEL_CORNER_RADIUS * 0.4))
        let height = max(0, bounds.height - (2 * verticalInset))
        let x = (bounds.width - lineWidth) / 2
        lineLayer.frame = NSRect(x: x, y: verticalInset, width: lineWidth, height: height)
        lineLayer.cornerRadius = lineWidth / 2
        lineLayer.shadowPath = CGPath(roundedRect: lineLayer.bounds,
                                      cornerWidth: lineLayer.cornerRadius,
                                      cornerHeight: lineLayer.cornerRadius,
                                      transform: nil)
        CATransaction.commit()
    }

    override func viewDidChangeBackingProperties() {
        super.viewDidChangeBackingProperties()
        lineLayer.contentsScale = window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0
    }

    override func updateTrackingAreas() {
        if let trackingArea {
            removeTrackingArea(trackingArea)
        }
        let area = NSTrackingArea(rect: bounds,
                                  options: [.mouseEnteredAndExited, .activeInKeyWindow, .inVisibleRect],
                                  owner: self,
                                  userInfo: nil)
        addTrackingArea(area)
        trackingArea = area
        super.updateTrackingAreas()
    }

    override func mouseEntered(with event: NSEvent) {
        isHovering = true
        updateLineStyle()
        super.mouseEntered(with: event)
    }

    override func mouseExited(with event: NSEvent) {
        isHovering = false
        updateLineStyle()
        super.mouseExited(with: event)
    }

    override func resetCursorRects() {
        super.resetCursorRects()
        addCursorRect(bounds, cursor: .resizeLeftRight)
    }

    override func mouseDown(with event: NSEvent) {
        dragStartX = event.locationInWindow.x
        dragStartPosition = positionProvider?() ?? 0
        isDragging = true
        didBeginDragCallback = false
        updateLineStyle()
        layoutLog("\(debugName) mouse_down x=\(String(format: "%.1f", event.locationInWindow.x)) start=\(Int(dragStartPosition)) frame=\(Int(frame.origin.x)),\(Int(frame.origin.y)) \(Int(frame.width))x\(Int(frame.height))")
    }

    override func mouseDragged(with event: NSEvent) {
        guard isDragging else { return }
        let delta = event.locationInWindow.x - dragStartX
        // Prevent immediate state flips on a mere click; only treat as a drag
        // once the pointer has moved a couple of pixels.
        if !didBeginDragCallback, abs(delta) >= 2 {
            didBeginDragCallback = true
            onDragBegin?()
            if debugLayoutEnabled {
                layoutLog("\(debugName) drag_begin_threshold delta=\(Int(delta))")
            }
        }
        guard didBeginDragCallback else { return }
        let proposed = dragStartPosition + delta
        let clamped = clampPosition?(proposed) ?? proposed
        if debugLayoutEnabled {
            let t = event.timestamp
            if t - lastDragLogTime > 0.05 {
                lastDragLogTime = t
                layoutLog("\(debugName) mouse_drag delta=\(Int(delta)) proposed=\(Int(proposed)) clamped=\(Int(clamped))")
            }
        }
        applyPosition?(clamped)
    }

    override func mouseUp(with event: NSEvent) {
        guard isDragging else { return }
        isDragging = false
        updateLineStyle()
        layoutLog("\(debugName) mouse_up x=\(String(format: "%.1f", event.locationInWindow.x))")
        if didBeginDragCallback {
            onDragEnd?()
        } else if debugLayoutEnabled {
            layoutLog("\(debugName) click_without_drag")
        }
        didBeginDragCallback = false
    }

    func refreshStyle() {
        updateLineStyle()
    }

    private func updateLineStyle() {
        let palette = paletteProvider?() ?? (
            fill: resolvedSystemColor(.separatorColor).withAlphaComponent(0.2),
            glow: NSColor.white.withAlphaComponent(0.2),
            glowOpacity: 0.2
        )
        let boost: CGFloat = (isHovering || isDragging) ? 0.12 : 0.0
        let fill = boostedAlpha(palette.fill, by: boost)
        let glow = boostedAlpha(palette.glow, by: boost * 0.6)
        let glowOpacity = min(1.0, palette.glowOpacity + Float(boost * 1.2))

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        lineLayer.backgroundColor = fill.cgColor
        lineLayer.shadowColor = glow.cgColor
        lineLayer.shadowOpacity = glowOpacity
        lineLayer.shadowRadius = (isHovering || isDragging) ? 6 : 3
        lineLayer.shadowOffset = .zero
        CATransaction.commit()
    }

    private func boostedAlpha(_ color: NSColor, by boost: CGFloat) -> NSColor {
        let c = color.usingColorSpace(.deviceRGB) ?? color
        return c.withAlphaComponent(min(1, c.alphaComponent + boost))
    }
}

final class DebugHitTestOverlayView: NSView {
    private let outlineLayer = CAShapeLayer()

    override init(frame frameRect: NSRect) {
        super.init(frame: frameRect)
        wantsLayer = true
        layer?.backgroundColor = NSColor.clear.cgColor
        outlineLayer.fillColor = NSColor.clear.cgColor
        outlineLayer.strokeColor = NSColor.systemRed.cgColor
        outlineLayer.lineWidth = 1.5
        outlineLayer.lineDashPattern = [6, 4]
        outlineLayer.isHidden = true
        if let layer = layer {
            layer.addSublayer(outlineLayer)
        }
    }

    required init?(coder: NSCoder) { fatalError() }

    override var isOpaque: Bool { false }

    override func hitTest(_ point: NSPoint) -> NSView? { nil }

    func update(rect: NSRect) {
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        outlineLayer.frame = bounds
        outlineLayer.path = CGPath(rect: rect, transform: nil)
        outlineLayer.isHidden = false
        CATransaction.commit()
    }

    func hide() {
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        outlineLayer.isHidden = true
        CATransaction.commit()
    }
}

final class DebugLayoutOverlayView: NSView {
    struct Item {
        let name: String
        let rect: NSRect
        let color: NSColor
        let label: String
    }

    private var itemLayers: [String: (shape: CAShapeLayer, text: CATextLayer)] = [:]

    override init(frame frameRect: NSRect) {
        super.init(frame: frameRect)
        wantsLayer = true
        layer?.backgroundColor = NSColor.clear.cgColor
    }

    required init?(coder: NSCoder) { fatalError() }

    override var isOpaque: Bool { false }

    override func hitTest(_ point: NSPoint) -> NSView? { nil }

    func update(items: [Item]) {
        guard let rootLayer = layer else { return }
        let scale = window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0

        CATransaction.begin()
        CATransaction.setDisableActions(true)

        var seen = Set<String>()
        for item in items {
            seen.insert(item.name)
            let pair: (CAShapeLayer, CATextLayer)
            if let existing = itemLayers[item.name] {
                pair = existing
            } else {
                let shape = CAShapeLayer()
                shape.fillColor = NSColor.clear.cgColor
                shape.lineWidth = 2
                shape.lineDashPattern = [5, 3]

                let text = CATextLayer()
                text.contentsScale = scale
                text.alignmentMode = .left
                text.font = NSFont.monospacedSystemFont(ofSize: 11, weight: .regular)
                text.fontSize = 11

                rootLayer.addSublayer(shape)
                rootLayer.addSublayer(text)
                itemLayers[item.name] = (shape, text)
                pair = (shape, text)
            }

            pair.0.strokeColor = item.color.cgColor
            pair.0.path = CGPath(rect: item.rect, transform: nil)
            pair.0.isHidden = item.rect.width <= 0 || item.rect.height <= 0

            pair.1.foregroundColor = item.color.cgColor
            pair.1.string = item.label
            let labelX = max(0, item.rect.minX + 4)
            let labelY = min(bounds.height - 16, max(0, item.rect.maxY - 16))
            pair.1.frame = NSRect(x: labelX, y: labelY, width: min(bounds.width - labelX, 520), height: 14)
            pair.1.isHidden = pair.0.isHidden
        }

        for (name, pair) in itemLayers where !seen.contains(name) {
            pair.shape.isHidden = true
            pair.text.isHidden = true
        }

        CATransaction.commit()
    }
}

// Apple Music–grade liquid glass renderer (Core Image + Metal when available).
final class LiquidGlassRenderer {
    struct Parameters: Equatable {
        // Diffusion model (points; multiplied by backing scale for pixels).
        // CALIBRATION (clarity leap): aggressively reduce diffusion, increase refraction + rim energy.
        //
        // Numerical diff (frost → clear pass):
        // - diffusionBlurRadius: 0.65 → 0.25
        // - centerBlurMix: 0.10 → 0.04
        // - edgeBlurMix: 0.40 → 0.18
        // - refractionScale: 22.0 → 30.0
        // - refractionAmplitude: 0.28 → 0.34
        // - centerRefractionMix: 0.08 → 0.13
        // - rimMaskWidth: 15.0 → 12.0
        // - rimMaskSoftness: 7.0 → 5.0
        // - tintAlpha: [0.0006, 0.014] → [0.0002, 0.006]
        // - fresnel: intensity 0.30 → 0.38, exponent 2.35 → 2.80
        // The pipeline now uses a single diffusion blur pass; softness comes from refraction.
        var diffusionBlurRadius: CGFloat = 0.25
        // How much of the blurred sample to mix into transmission (0 = fully clear, 1 = fully blurred).
        // Kept very low so the material reads as clear liquid acrylic rather than etched glass.
        var centerBlurMix: CGFloat = 0.04
        var edgeBlurMix: CGFloat = 0.18
        // Refraction.
        var refractionScale: CGFloat = 30.0
        var refractionAmplitude: CGFloat = 0.34
        // Apply a small amount of refraction across the whole surface so the center reads “liquid”
        // (still weaker than the rim, which is mask-boosted).
        var centerRefractionMix: CGFloat = 0.13
        // Rim/edge falloff controls (points).
        var rimMaskWidth: CGFloat = 12.0
        var rimMaskSoftness: CGFloat = 5.0
        // Fresnel (edge reflectance): increases reflectivity at edges without reducing center transmission.
        var fresnelIntensity: CGFloat = 0.38
        var fresnelExponent: CGFloat = 2.80
        var fresnelCornerBoost: CGFloat = 0.25
        // Color behavior.
        var saturation: CGFloat = 1.05
        var contrast: CGFloat = 1.06
        // Milkiness overlay bounds (auto-tuned via background luminance).
        var tintAlphaMin: CGFloat = 0.0002
        var tintAlphaMax: CGFloat = 0.006
        // Ambient occlusion base strength (light mode); dark mode scales this up.
        var aoStrength: CGFloat = 0.03
        struct TintOverride: Equatable {
            var r: CGFloat
            var g: CGFloat
            var b: CGFloat
        }
        var tintOverride: TintOverride? = nil
        // Micro noise: disabled by default (noise should modulate refraction, not act like opacity).
        var noiseOpacity: CGFloat = 0.0

        var enableRefraction: Bool = true
        var enableNoise: Bool = true

        func scaled(by s: CGFloat) -> Parameters {
            var p = self
            p.diffusionBlurRadius *= s
            p.refractionScale *= s
            p.rimMaskWidth *= s
            p.rimMaskSoftness *= s
            return p
        }
    }

    enum DebugView: String {
        case none
        case rimMask
        case aoMask
        case refractionField
        case baseBlur
        case edgeBlur
        case final
    }

    static let shared = LiquidGlassRenderer()

    private let context: CIContext
    private let queue = DispatchQueue(label: "LiquidGlassRenderer.queue", qos: .userInitiated)
    private let deviceRGB = CGColorSpaceCreateDeviceRGB()

    private init() {
        if let device = MTLCreateSystemDefaultDevice() {
            context = CIContext(mtlDevice: device, options: [
                CIContextOption.workingColorSpace: deviceRGB,
                CIContextOption.outputColorSpace: deviceRGB
            ])
        } else {
            context = CIContext(options: [
                CIContextOption.workingColorSpace: deviceRGB,
                CIContextOption.outputColorSpace: deviceRGB
            ])
        }
    }

    func renderAsync(background: CGImage,
                     sizePx: CGSize,
                     cornerRadiusPx: CGFloat,
                     isDark: Bool,
                     parameters: Parameters,
                     debug: DebugView,
                     completion: @escaping (CGImage?) -> Void) {
        queue.async { [weak self] in
	            guard let self else { return }
            let out = self.render(background: background,
                                  sizePx: sizePx,
                                  cornerRadiusPx: cornerRadiusPx,
                                  isDark: isDark,
                                  parameters: parameters,
                                  debug: debug)
            DispatchQueue.main.async { completion(out) }
        }
    }

    func renderSync(background: CGImage,
                    sizePx: CGSize,
                    cornerRadiusPx: CGFloat,
                    isDark: Bool,
                    parameters: Parameters,
                    debug: DebugView = .none) -> CGImage? {
        render(background: background,
               sizePx: sizePx,
               cornerRadiusPx: cornerRadiusPx,
               isDark: isDark,
               parameters: parameters,
               debug: debug)
    }

    private func render(background: CGImage,
                        sizePx: CGSize,
                        cornerRadiusPx: CGFloat,
                        isDark: Bool,
                        parameters: Parameters,
                        debug: DebugView) -> CGImage? {
        let extent = CGRect(origin: .zero, size: sizePx.integralSize)
        guard extent.width >= 2, extent.height >= 2 else { return nil }

        var input = CIImage(cgImage: background)
        // Ensure the sampled background matches the requested render size (avoid 1px seams from rounding differences).
        if abs(input.extent.width - extent.width) > 0.5 || abs(input.extent.height - extent.height) > 0.5 {
            let sx = extent.width / max(1.0, input.extent.width)
            let sy = extent.height / max(1.0, input.extent.height)
            input = input.transformed(by: CGAffineTransform(scaleX: sx, y: sy))
        }
        input = input.cropped(to: extent)
        let clamped = input.clampedToExtent()

        let rimMask = makeRimMask(extent: extent,
                                  cornerRadius: cornerRadiusPx,
                                  width: parameters.rimMaskWidth,
                                  softness: parameters.rimMaskSoftness)
        let aoMask = makeAOMask(from: rimMask, extent: extent)

        // Transmission: single-pass diffusion blur (center clearer, rim slightly more diffused).
        // Key point: blend blurred transmission over the *original* sample so we keep fine background detail.
        let diffusionBlur = gaussianBlur(clamped, radius: parameters.diffusionBlurRadius).cropped(to: extent)

        if debug == .rimMask {
            return context.createCGImage(rimMask, from: extent)
        }
        if debug == .aoMask {
            return context.createCGImage(aoMask, from: extent)
        }

        if debug == .baseBlur || debug == .edgeBlur {
            return context.createCGImage(diffusionBlur, from: extent)
        }

        let diffusionMask = mixMask(rimMask,
                                    base: parameters.centerBlurMix,
                                    edge: parameters.edgeBlurMix,
                                    extent: extent)
        var glass = blendWithMask(foreground: diffusionBlur, background: clamped, mask: diffusionMask) ?? clamped

        // Refraction: apply distortion to the *less blurred* background so we bend light instead of erasing detail.
        if parameters.enableRefraction,
           let refractedRaw = glassDistortion(image: clamped,
                                              extent: extent,
                                              isDark: isDark,
                                              scale: parameters.refractionScale,
                                              amplitude: parameters.refractionAmplitude) {
            if debug == .refractionField {
                return context.createCGImage(refractionTexture(extent: extent,
                                                               isDark: isDark,
                                                               amplitude: parameters.refractionAmplitude),
                                             from: extent)
            }
            // Keep refraction *sharp*: minimal blur to suppress aliasing only.
            let refr = gaussianBlur(refractedRaw.clampedToExtent(),
                                    radius: max(0.12, parameters.diffusionBlurRadius * 0.18)).cropped(to: extent)

            // Keep center highly transmissive: refraction is strongest near the rim (mask-weighted).
            var refrMask = powMask(rimMask, exponent: 2.10, extent: extent)
            let baseMix = max(0.0, min(0.25, parameters.centerRefractionMix))
            if baseMix > 0.0001 {
                refrMask = mixMask(refrMask, base: baseMix, edge: 1.0, extent: extent)
            }
            glass = blendWithMask(foreground: refr, background: glass, mask: refrMask) ?? glass
        }

        // Tint / internal light pooling:
        // Use *screen* blending of a very low-alpha, background-tinted swatch so we lift perceived brightness
        // without adding a milky source-over veil (better match to Apple’s “clear wet glass” samples).
        let avg = areaAverageRGB(input: input, extent: extent)
        let luma = (0.2126 * avg.r + 0.7152 * avg.g + 0.0722 * avg.b)
        let t = max(0.0, min(1.0, (luma - 0.15) / 0.70))
        let tintAlpha = lerp(parameters.tintAlphaMin, parameters.tintAlphaMax, t: t) * (isDark ? 1.05 : 0.90)
        let tintMix: CGFloat = isDark ? 0.66 : 0.70
        let tintBase: (r: CGFloat, g: CGFloat, b: CGFloat)
        if let override = parameters.tintOverride {
            tintBase = (override.r, override.g, override.b)
        } else {
            tintBase = (avg.r, avg.g, avg.b)
        }
        let tintR = lerp(tintBase.r, 1.0, t: tintMix)
        let tintG = lerp(tintBase.g, 1.0, t: tintMix)
        let tintB = lerp(tintBase.b, 1.0, t: tintMix)
        let tint = CIImage(color: CIColor(red: tintR, green: tintG, blue: tintB, alpha: tintAlpha)).cropped(to: extent)
        glass = screenBlend(foreground: tint, background: glass) ?? tint.composited(over: glass)

        // Subtle contrast/saturation lift to keep micro-contrast (avoid “chalky” blur).
        glass = colorControls(input: glass,
                              saturation: parameters.saturation,
                              contrast: parameters.contrast,
                              brightness: isDark ? 0.003 : 0.0) ?? glass

        // Ambient occlusion: faint darkening near the contact edge (inside the glass), masked to the rim zone.
        let aoStrength = parameters.aoStrength * (isDark ? 1.4 : 1.0)
        if aoStrength > 0.0001 {
            let aoTint = CIImage(color: CIColor(red: 0, green: 0, blue: 0, alpha: aoStrength)).cropped(to: extent)
            if let aoApplied = blendWithMask(foreground: aoTint, background: glass, mask: aoMask) {
                glass = aoApplied
            }
        }

        // Fresnel edge reflectance (dedicated term): brighter/wetter rim while the center stays highly transmissive.
        if parameters.fresnelIntensity > 0.0001 {
            let fresnelMask = makeFresnelMask(rimMask: rimMask,
                                              extent: extent,
                                              exponent: parameters.fresnelExponent,
                                              cornerBoost: parameters.fresnelCornerBoost)
            let fresnelWhite = CIImage(color: CIColor(red: 1, green: 1, blue: 1, alpha: parameters.fresnelIntensity)).cropped(to: extent)
            if let fresnelApplied = blendWithMask(foreground: fresnelWhite, background: glass, mask: fresnelMask) {
                glass = fresnelApplied
            }
        }

        if parameters.enableNoise, parameters.noiseOpacity > 0.0001 {
            glass = addMicroNoise(to: glass, extent: extent, opacity: parameters.noiseOpacity) ?? glass
        }

        return context.createCGImage(glass.cropped(to: extent), from: extent)
    }

    private func gaussianBlur(_ image: CIImage, radius: CGFloat) -> CIImage {
        guard radius > 0.001 else { return image }
        let f = CIFilter.gaussianBlur()
        f.inputImage = image
        f.radius = Float(radius)
        return f.outputImage ?? image
    }

    private func colorControls(input: CIImage, saturation: CGFloat, contrast: CGFloat, brightness: CGFloat) -> CIImage? {
        let f = CIFilter.colorControls()
        f.inputImage = input
        f.saturation = Float(saturation)
        f.contrast = Float(contrast)
        f.brightness = Float(brightness)
        return f.outputImage
    }

    private func blendWithMask(foreground: CIImage, background: CIImage, mask: CIImage) -> CIImage? {
        let f = CIFilter.blendWithMask()
        f.inputImage = foreground
        f.backgroundImage = background
        f.maskImage = mask
        return f.outputImage
    }

    private func screenBlend(foreground: CIImage, background: CIImage) -> CIImage? {
        let f = CIFilter.screenBlendMode()
        f.inputImage = foreground
        f.backgroundImage = background
        return f.outputImage
    }

    private func mixMask(_ mask: CIImage, base: CGFloat, edge: CGFloat, extent: CGRect) -> CIImage {
        let b = max(0.0, min(1.0, base))
        let e = max(0.0, min(1.0, edge))
        let scale = max(0.0, e - b)
        let scaled = mask.applyingFilter("CIColorMatrix", parameters: [
            "inputRVector": CIVector(x: scale, y: 0, z: 0, w: 0),
            "inputGVector": CIVector(x: scale, y: 0, z: 0, w: 0),
            "inputBVector": CIVector(x: scale, y: 0, z: 0, w: 0),
            "inputBiasVector": CIVector(x: b, y: b, z: b, w: 0)
        ]).cropped(to: extent)
        let clamp = CIFilter.colorClamp()
        clamp.inputImage = scaled
        clamp.minComponents = CIVector(x: 0, y: 0, z: 0, w: 0)
        clamp.maxComponents = CIVector(x: 1, y: 1, z: 1, w: 1)
        return (clamp.outputImage ?? scaled).cropped(to: extent)
    }

    private func powMask(_ mask: CIImage, exponent: CGFloat, extent: CGRect) -> CIImage {
        let p = max(0.25, min(4.0, exponent))
        let g = CIFilter.gammaAdjust()
        g.inputImage = mask
        g.power = Float(p)
        return (g.outputImage ?? mask).cropped(to: extent)
    }

    private func makeFresnelMask(rimMask: CIImage,
                                 extent: CGRect,
                                 exponent: CGFloat,
                                 cornerBoost: CGFloat) -> CIImage {
        // Fresnel response ramps smoothly with the rim mask and gets a small extra lift at corners (higher curvature).
        var mask = powMask(rimMask, exponent: exponent, extent: extent)

        let cb = max(0.0, min(0.4, cornerBoost))
        if cb > 0.0001, let corners = makeCornerBoostMask(extent: extent) {
            let scaled = corners.applyingFilter("CIColorMatrix", parameters: [
                "inputRVector": CIVector(x: cb, y: 0, z: 0, w: 0),
                "inputGVector": CIVector(x: cb, y: 0, z: 0, w: 0),
                "inputBVector": CIVector(x: cb, y: 0, z: 0, w: 0),
                "inputBiasVector": CIVector(x: 0, y: 0, z: 0, w: 0)
            ]).cropped(to: extent)
            let add = CIFilter.additionCompositing()
            add.inputImage = scaled
            add.backgroundImage = mask
            mask = (add.outputImage ?? mask).cropped(to: extent)
        }

        // Clamp to [0,1] to avoid hard clipping artifacts.
        let clamp = CIFilter.colorClamp()
        clamp.inputImage = mask
        clamp.minComponents = CIVector(x: 0, y: 0, z: 0, w: 0)
        clamp.maxComponents = CIVector(x: 1, y: 1, z: 1, w: 1)
        return (clamp.outputImage ?? mask).cropped(to: extent)
    }

    private func makeCornerBoostMask(extent: CGRect) -> CIImage? {
        // Corner-only mask (1 at corners, 0 on flats): sum of four radial gradients, clamped.
        let r = max(24.0, min(extent.width, extent.height) * 0.35)
        func radial(at p: CGPoint) -> CIImage? {
            guard let f = CIFilter(name: "CIRadialGradient") else { return nil }
            f.setValue(CIVector(x: p.x, y: p.y), forKey: "inputCenter")
            f.setValue(0.0, forKey: "inputRadius0")
            f.setValue(r, forKey: "inputRadius1")
            f.setValue(CIColor(red: 1, green: 1, blue: 1, alpha: 1), forKey: "inputColor0")
            f.setValue(CIColor(red: 0, green: 0, blue: 0, alpha: 1), forKey: "inputColor1")
            return (f.outputImage?.cropped(to: extent))
        }

        guard let tl = radial(at: CGPoint(x: extent.minX, y: extent.maxY)),
              let tr = radial(at: CGPoint(x: extent.maxX, y: extent.maxY)),
              let bl = radial(at: CGPoint(x: extent.minX, y: extent.minY)),
              let br = radial(at: CGPoint(x: extent.maxX, y: extent.minY)) else { return nil }

        let add1 = CIFilter.additionCompositing()
        add1.inputImage = tl
        add1.backgroundImage = tr
        let sum1 = (add1.outputImage ?? tl).cropped(to: extent)

        let add2 = CIFilter.additionCompositing()
        add2.inputImage = bl
        add2.backgroundImage = br
        let sum2 = (add2.outputImage ?? bl).cropped(to: extent)

        let add3 = CIFilter.additionCompositing()
        add3.inputImage = sum1
        add3.backgroundImage = sum2
        let sum = (add3.outputImage ?? sum1).cropped(to: extent)

        let clamp = CIFilter.colorClamp()
        clamp.inputImage = sum
        clamp.minComponents = CIVector(x: 0, y: 0, z: 0, w: 0)
        clamp.maxComponents = CIVector(x: 1, y: 1, z: 1, w: 1)
        return (clamp.outputImage ?? sum).cropped(to: extent)
    }

    private func makeRimMask(extent: CGRect, cornerRadius: CGFloat, width: CGFloat, softness: CGFloat) -> CIImage {
        // 0 in the center, 1 near the rim (rounded-rect stroke blurred outward).
        let size = extent.size.integralSize
        let w = max(2, Int(size.width))
        let h = max(2, Int(size.height))
        let cs = CGColorSpaceCreateDeviceGray()
        guard let ctx = CGContext(data: nil,
                                  width: w,
                                  height: h,
                                  bitsPerComponent: 8,
                                  bytesPerRow: w,
                                  space: cs,
                                  bitmapInfo: CGImageAlphaInfo.none.rawValue) else {
            return CIImage(color: CIColor(red: 0, green: 0, blue: 0, alpha: 1)).cropped(to: extent)
        }
        ctx.setFillColor(gray: 0.0, alpha: 1.0)
        ctx.fill(CGRect(x: 0, y: 0, width: w, height: h))

        let stroke = max(1.0, width)
        ctx.setStrokeColor(gray: 1.0, alpha: 1.0)
        ctx.setLineWidth(stroke)
        ctx.setLineJoin(.round)

        let inset = stroke / 2
        let rect = CGRect(x: inset, y: inset, width: CGFloat(w) - stroke, height: CGFloat(h) - stroke)
        let r = max(0, cornerRadius)
        ctx.addPath(CGPath(roundedRect: rect, cornerWidth: r, cornerHeight: r, transform: nil))
        ctx.strokePath()

        guard let cg = ctx.makeImage() else {
            return CIImage(color: CIColor(red: 0, green: 0, blue: 0, alpha: 1)).cropped(to: extent)
        }
        var mask = CIImage(cgImage: cg).cropped(to: extent)
        if softness > 0.5 {
            let blurred = gaussianBlur(mask.clampedToExtent(), radius: softness).cropped(to: extent)
            mask = blurred
        }
        // Clamp to [0,1] and keep as grayscale mask.
        let normalize = CIFilter.colorControls()
        normalize.inputImage = mask
        normalize.saturation = 0
        normalize.contrast = 1.2
        normalize.brightness = 0
        return (normalize.outputImage ?? mask).cropped(to: extent)
    }

    private func makeAOMask(from rimMask: CIImage, extent: CGRect) -> CIImage {
        // Slightly wider and softer than rimMask so AO sits under the highlight instead of looking like a hard outline.
        let blur = max(6.0, min(18.0, min(extent.width, extent.height) * 0.020))
        let widened = gaussianBlur(rimMask.clampedToExtent(), radius: blur).cropped(to: extent)
        let f = CIFilter.colorControls()
        f.inputImage = widened
        f.saturation = 0
        f.contrast = 1.0
        f.brightness = -0.02
        return (f.outputImage ?? widened).cropped(to: extent)
    }

    private func refractionTexture(extent: CGRect, isDark: Bool, amplitude: CGFloat) -> CIImage {
        // Refraction field (centered around 0.5 so distortion bends light instead of drifting/erasing it).
        // Replace “frost” with refraction by using a smooth, liquid normal-field:
        // - low-frequency component for broad lensing
        // - small high-frequency component for subtle waviness (NOT opacity grain)
        let blurLow = max(8.0, min(18.0, min(extent.width, extent.height) * 0.020))
        let blurHigh = max(2.2, min(5.0, blurLow * 0.24))

        guard let noise = CIFilter.randomGenerator().outputImage?
            .cropped(to: extent)
            .applyingFilter("CIColorControls", parameters: [kCIInputSaturationKey: 0.0, kCIInputContrastKey: 0.9])
            .cropped(to: extent) else {
            return CIImage(color: CIColor(red: 0.5, green: 0.5, blue: 0.5, alpha: 1)).cropped(to: extent)
        }

        let low = gaussianBlur(noise.clampedToExtent(), radius: blurLow).cropped(to: extent)
        let high = gaussianBlur(noise.clampedToExtent(), radius: blurHigh).cropped(to: extent)

        // Weighted sum: 0.90*low + 0.10*high.
        let lowScaled = low.applyingFilter("CIColorMatrix", parameters: [
            "inputRVector": CIVector(x: 0.90, y: 0, z: 0, w: 0),
            "inputGVector": CIVector(x: 0.90, y: 0, z: 0, w: 0),
            "inputBVector": CIVector(x: 0.90, y: 0, z: 0, w: 0),
            "inputBiasVector": CIVector(x: 0, y: 0, z: 0, w: 0)
        ]).cropped(to: extent)
        let highScaled = high.applyingFilter("CIColorMatrix", parameters: [
            "inputRVector": CIVector(x: 0.10, y: 0, z: 0, w: 0),
            "inputGVector": CIVector(x: 0.10, y: 0, z: 0, w: 0),
            "inputBVector": CIVector(x: 0.10, y: 0, z: 0, w: 0),
            "inputBiasVector": CIVector(x: 0, y: 0, z: 0, w: 0)
        ]).cropped(to: extent)

        let add = CIFilter.additionCompositing()
        add.inputImage = highScaled
        add.backgroundImage = lowScaled
        let raw = (add.outputImage ?? lowScaled).cropped(to: extent)

        // Center around 0.5 with small amplitude.
        let a = max(0.12, min(0.45, amplitude))
        let amp: CGFloat = isDark ? a * 0.90 : a
        let bias: CGFloat = 0.5 * (1.0 - amp)
        let centered = raw.applyingFilter("CIColorMatrix", parameters: [
            "inputRVector": CIVector(x: amp, y: 0, z: 0, w: 0),
            "inputGVector": CIVector(x: amp, y: 0, z: 0, w: 0),
            "inputBVector": CIVector(x: amp, y: 0, z: 0, w: 0),
            "inputBiasVector": CIVector(x: bias, y: bias, z: bias, w: 0)
        ]).cropped(to: extent)
        return centered
    }

    private func glassDistortion(image: CIImage,
                                 extent: CGRect,
                                 isDark: Bool,
                                 scale: CGFloat,
                                 amplitude: CGFloat) -> CIImage? {
        guard scale > 0.001 else { return nil }
        guard let f = CIFilter(name: "CIGlassDistortion") else { return nil }
        f.setValue(image, forKey: kCIInputImageKey)
        // Core Image uses the key name "inputTexture" for CIGlassDistortion's texture map on older SDKs.
        f.setValue(refractionTexture(extent: extent, isDark: isDark, amplitude: amplitude), forKey: "inputTexture")
        f.setValue(scale, forKey: kCIInputScaleKey)
        return (f.outputImage?.cropped(to: extent))
    }

    private func addMicroNoise(to image: CIImage, extent: CGRect, opacity: CGFloat) -> CIImage? {
        guard let noise = CIFilter.randomGenerator().outputImage?.cropped(to: extent) else { return nil }
        // Convert to subtle monochrome noise centered near 0.5, then source-over at very low alpha.
        let n = noise
            .applyingFilter("CIColorControls", parameters: [kCIInputSaturationKey: 0.0, kCIInputContrastKey: 0.6])
            .cropped(to: extent)

        let noiseAlpha = max(0.0, min(0.08, opacity))
        let tint = CIImage(color: CIColor(red: 1, green: 1, blue: 1, alpha: noiseAlpha)).cropped(to: extent)
        let clear = CIImage(color: CIColor(red: 0, green: 0, blue: 0, alpha: 0)).cropped(to: extent)
        let n2 = blendWithMask(foreground: tint, background: clear, mask: n) ?? tint
        return n2.composited(over: image)
    }

    private func areaAverageRGB(input: CIImage, extent: CGRect) -> (r: CGFloat, g: CGFloat, b: CGFloat) {
        let f = CIFilter.areaAverage()
        f.inputImage = input
        f.extent = extent
        guard let out = f.outputImage else { return (0, 0, 0) }
        var px = [UInt8](repeating: 0, count: 4)
        context.render(out,
                       toBitmap: &px,
                       rowBytes: 4,
                       bounds: CGRect(x: 0, y: 0, width: 1, height: 1),
                       format: .RGBA8,
                       colorSpace: deviceRGB)
        return (CGFloat(px[0]) / 255.0, CGFloat(px[1]) / 255.0, CGFloat(px[2]) / 255.0)
    }

    private func lerp(_ a: CGFloat, _ b: CGFloat, t: CGFloat) -> CGFloat {
        a + (b - a) * max(0.0, min(1.0, t))
    }
}

extension CGSize {
    var integralSize: CGSize { CGSize(width: ceil(width), height: ceil(height)) }
}

// Glass card material kit: condensed config + factory for reusable liquid-glass cards.
enum GlassCardKit {
    enum State: String {
        case normal
        case hover
        case pressed
        case selected
        case disabled
    }

    struct ShadowStyle: Equatable {
        var rimOpacity: Float
        var rimRadius: CGFloat
        var rimOffset: CGSize
        var bottomAlpha: CGFloat

        static let subtle = ShadowStyle(rimOpacity: 0.30,
                                        rimRadius: 7.5,
                                        rimOffset: CGSize(width: 0, height: -0.9),
                                        bottomAlpha: 0.10)
    }

    struct BorderStyle: Equatable {
        var rimWidth: CGFloat
        var outerWidth: CGFloat
        var innerWidth: CGFloat
        var rimLightAlpha: CGFloat
        var rimDarkAlpha: CGFloat
        var outerAlpha: CGFloat
        var innerAlpha: CGFloat
        var dispersionAlpha: CGFloat

        static let clearRim = BorderStyle(rimWidth: 2.1,
                          outerWidth: 1.1,
                          innerWidth: 0.9,
                          rimLightAlpha: 0.04,   // 80% more transparent
                          rimDarkAlpha: 0.036,  // 80% more transparent
                          outerAlpha: 0.028,    // 80% more transparent
                          innerAlpha: 0.020,    // 80% more transparent
                          dispersionAlpha: 0.0056) // 80% more transparent
    }

    struct GlassCardConfig: Equatable {
        var cornerRadius: CGFloat = PANEL_CORNER_RADIUS
        var thickness: CGFloat = 1.0
        var transmission: CGFloat = 0.93
        var refractionStrength: CGFloat = 1.90
        var refractionScale: CGFloat = 30.0
        var fresnelStrength: CGFloat = 0.38
        var specularIntensity: CGFloat = 1.0
        var tint: NSColor? = nil
        var tintBoost: CGFloat = 1.0
        var fillBoost: CGFloat = 1.0
        var flatFill: Bool = false
        var diffusionAmount: CGFloat = 1.0
        var shadowStyle: ShadowStyle = .subtle
        var borderStyle: BorderStyle = .clearRim
        var state: State = .normal
        // Refraction-only glass (no fill, rims, or tint overlays).
        var forceTransparent: Bool = false

        static func == (lhs: GlassCardConfig, rhs: GlassCardConfig) -> Bool {
            return lhs.cornerRadius == rhs.cornerRadius &&
                lhs.thickness == rhs.thickness &&
                lhs.transmission == rhs.transmission &&
                lhs.refractionStrength == rhs.refractionStrength &&
                lhs.refractionScale == rhs.refractionScale &&
                lhs.fresnelStrength == rhs.fresnelStrength &&
                lhs.specularIntensity == rhs.specularIntensity &&
                lhs.diffusionAmount == rhs.diffusionAmount &&
                lhs.tintBoost == rhs.tintBoost &&
                lhs.fillBoost == rhs.fillBoost &&
                lhs.flatFill == rhs.flatFill &&
                lhs.shadowStyle == rhs.shadowStyle &&
                lhs.borderStyle == rhs.borderStyle &&
                lhs.state == rhs.state &&
                lhs.forceTransparent == rhs.forceTransparent &&
                tintSignature(lhs.tint) == tintSignature(rhs.tint)
        }

        private static func tintSignature(_ color: NSColor?) -> (Int, Int, Int, Int) {
            guard let color else { return (-1, -1, -1, -1) }
            let c = color.usingColorSpace(.deviceRGB) ?? color
            return (
                Int(max(0, min(255, round(c.redComponent * 255)))),
                Int(max(0, min(255, round(c.greenComponent * 255)))),
                Int(max(0, min(255, round(c.blueComponent * 255)))),
                Int(max(0, min(255, round(c.alphaComponent * 255))))
            )
        }
    }

    static func makeGlassCard(config: GlassCardConfig,
                              backgroundProvider: ((CGRect, CGFloat) -> CGImage?)? = nil) -> GlassCardView {
        let card = GlassCardView(frame: .zero, config: config)
        card.backgroundProvider = backgroundProvider
        return card
    }
}

// Glass card view: renders refraction + diffusion into a cached bitmap, then layers Apple-like rims on top.
final class GlassCardView: NSView {
    private let backgroundImageLayer = CALayer()
    private let fillLayer = CALayer()
    private let highlightLayer = CAGradientLayer()
    private let shadowLayer = CAGradientLayer()
    // "Bubbly" rim: layered strokes + soft glow/shadow for a rounded glass edge.
    private let rimLightLayer = CAShapeLayer()
    private let rimDarkLayer = CAShapeLayer()
    private let strokeLayer = CAShapeLayer()
    private let innerStrokeLayer = CAShapeLayer()
    private let dispersionLayer = CAGradientLayer()
    private let dispersionMask = CAShapeLayer()
    private let symmetryGuideLayer = CAShapeLayer()

    var config: GlassCardKit.GlassCardConfig {
        didSet { applyConfig(from: oldValue) }
    }

    // Background sampling provider (rect in window coordinates, scale) -> CGImage.
    var backgroundProvider: ((CGRect, CGFloat) -> CGImage?)?

    private var renderWorkItem: DispatchWorkItem?
    private var lastRenderKey: String = ""
    private var frozenBackground: CGImage?
    private static var didLogLiquidGlassParams: Bool = false
    private var glassEnabled: Bool = true {
        didSet {
            guard glassEnabled != oldValue else { return }
            updateStyle()
            invalidateGlass(reason: "enabled")
        }
    }
    private var glassFallbackTint: NSColor?

    private var glassParams: LiquidGlassRenderer.Parameters {
        var p = makeRendererParameters()
        if ProcessInfo.processInfo.environment["ARXIV_GLASS_DISABLE_REFRACTION"] == "1" { p.enableRefraction = false }
        if ProcessInfo.processInfo.environment["ARXIV_GLASS_DISABLE_NOISE"] == "1" { p.enableNoise = false }
        return p
    }

    private var glassDebugView: LiquidGlassRenderer.DebugView {
        let raw = (ProcessInfo.processInfo.environment["ARXIV_GLASS_DEBUG"] ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        return LiquidGlassRenderer.DebugView(rawValue: raw) ?? .none
    }

    private var freezeBackgroundSampling: Bool {
        ProcessInfo.processInfo.environment["ARXIV_GLASS_FREEZE_BG"] == "1"
    }

    private var isLiquidGlassEnabled: Bool {
        glassEnabled
    }

    func setGlassEnabled(_ enabled: Bool, fallbackColor: NSColor? = nil) {
        glassFallbackTint = fallbackColor
        glassEnabled = enabled
    }

    var cornerRadius: CGFloat {
        get { config.cornerRadius }
        set {
            var next = config
            next.cornerRadius = newValue
            config = next
        }
    }

    init(frame frameRect: NSRect, config: GlassCardKit.GlassCardConfig) {
        self.config = config
        super.init(frame: frameRect)
        commonInit()
    }

    override init(frame frameRect: NSRect) {
        self.config = GlassCardKit.GlassCardConfig()
        super.init(frame: frameRect)
        commonInit()
    }

    required init?(coder: NSCoder) { fatalError() }

    private func commonInit() {
        wantsLayer = true
        layer?.masksToBounds = true
        if #available(macOS 10.13, *) { layer?.cornerCurve = .continuous }

        backgroundImageLayer.contentsGravity = .resize
        backgroundImageLayer.masksToBounds = true
        layer?.addSublayer(backgroundImageLayer)

        fillLayer.backgroundColor = NSColor.clear.cgColor
        layer?.addSublayer(fillLayer)

        highlightLayer.startPoint = CGPoint(x: 0.5, y: 1.0)
        highlightLayer.endPoint = CGPoint(x: 0.5, y: 0.0)
        layer?.addSublayer(highlightLayer)

        shadowLayer.startPoint = CGPoint(x: 0.5, y: 1.0)
        shadowLayer.endPoint = CGPoint(x: 0.5, y: 0.0)
        layer?.addSublayer(shadowLayer)

        rimDarkLayer.fillColor = NSColor.clear.cgColor
        rimDarkLayer.lineJoin = .round
        rimDarkLayer.lineCap = .round
        layer?.addSublayer(rimDarkLayer)

        rimLightLayer.fillColor = NSColor.clear.cgColor
        rimLightLayer.lineJoin = .round
        rimLightLayer.lineCap = .round
        layer?.addSublayer(rimLightLayer)

        // Rim-only chroma split (tasteful dispersion) - masked to the rim path.
        dispersionLayer.startPoint = CGPoint(x: 0.0, y: 0.5)
        dispersionLayer.endPoint = CGPoint(x: 1.0, y: 0.5)
        dispersionLayer.mask = dispersionMask
        layer?.addSublayer(dispersionLayer)

        strokeLayer.fillColor = NSColor.clear.cgColor
        strokeLayer.lineJoin = .round
        strokeLayer.lineCap = .round
        layer?.addSublayer(strokeLayer)

        innerStrokeLayer.fillColor = NSColor.clear.cgColor
        innerStrokeLayer.lineJoin = .round
        innerStrokeLayer.lineCap = .round
        layer?.addSublayer(innerStrokeLayer)
    }

    func updateConfig(_ newConfig: GlassCardKit.GlassCardConfig) {
        config = newConfig
    }

    func updateState(_ newState: GlassCardKit.State) {
        guard config.state != newState else { return }
        var next = config
        next.state = newState
        config = next
    }

    private func applyConfig(from oldValue: GlassCardKit.GlassCardConfig) {
        if oldValue.cornerRadius != config.cornerRadius {
            needsLayout = true
        }
        updateStyle()
        if needsRenderUpdate(from: oldValue, to: config) {
            invalidateGlass(reason: "config")
        }
    }

    private func needsRenderUpdate(from oldValue: GlassCardKit.GlassCardConfig,
                                   to newValue: GlassCardKit.GlassCardConfig) -> Bool {
        if oldValue.cornerRadius != newValue.cornerRadius { return true }
        if oldValue.transmission != newValue.transmission { return true }
        if oldValue.refractionStrength != newValue.refractionStrength { return true }
        if oldValue.refractionScale != newValue.refractionScale { return true }
        if oldValue.fresnelStrength != newValue.fresnelStrength { return true }
        if oldValue.diffusionAmount != newValue.diffusionAmount { return true }
        if oldValue.thickness != newValue.thickness { return true }
        if oldValue.tintBoost != newValue.tintBoost { return true }
        if oldValue.fillBoost != newValue.fillBoost { return true }
        if oldValue.forceTransparent != newValue.forceTransparent { return true }
        if tintSignature(oldValue.tint) != tintSignature(newValue.tint) { return true }
        return false
    }

    private func tintSignature(_ color: NSColor?) -> (Int, Int, Int, Int) {
        guard let color else { return (-1, -1, -1, -1) }
        let c = color.usingColorSpace(.deviceRGB) ?? color
        return (
            Int(max(0, min(255, round(c.redComponent * 255)))),
            Int(max(0, min(255, round(c.greenComponent * 255)))),
            Int(max(0, min(255, round(c.blueComponent * 255)))),
            Int(max(0, min(255, round(c.alphaComponent * 255))))
        )
    }

    private func clampUnit(_ value: CGFloat) -> CGFloat {
        max(0.0, min(1.0, value))
    }

    private func stateMultipliers(for state: GlassCardKit.State) -> (specular: CGFloat, fill: CGFloat, shadow: CGFloat) {
        switch state {
        case .normal:
            return (1.0, 1.0, 1.0)
        case .hover:
            return (1.06, 1.05, 1.05)
        case .pressed:
            return (0.92, 1.08, 0.90)
        case .selected:
            return (1.10, 1.06, 1.10)
        case .disabled:
            return (0.75, 0.85, 0.60)
        }
    }

    private func makeRendererParameters() -> LiquidGlassRenderer.Parameters {
        var p = LiquidGlassRenderer.Parameters()
        let transmission = clampUnit(config.transmission)
        let diffusion = clampUnit(config.diffusionAmount)
        let refractionStrength = clampUnit(config.refractionStrength)
        let thickness = max(0.6, config.thickness)

        p.diffusionBlurRadius = 0.18 + diffusion * 0.75
        p.centerBlurMix = (1.0 - transmission) * 0.55
        let rimBoost = 0.03 + diffusion * 0.95
        p.edgeBlurMix = min(0.32, max(p.centerBlurMix, p.centerBlurMix + rimBoost))

        p.refractionScale = max(2.0, config.refractionScale)
        p.refractionAmplitude = 0.22 + 0.14 * refractionStrength
        p.centerRefractionMix = 0.04 + 0.11 * refractionStrength

        p.rimMaskWidth = 12.0 * thickness
        p.rimMaskSoftness = 5.0 * thickness

        p.fresnelIntensity = clampUnit(config.fresnelStrength)
        p.fresnelExponent = 2.80
        p.fresnelCornerBoost = min(0.35, 0.22 + 0.05 * thickness)

        if let tint = config.tint {
            let c = tint.usingColorSpace(.deviceRGB) ?? tint
            p.tintOverride = .init(r: c.redComponent, g: c.greenComponent, b: c.blueComponent)
            let a = clampUnit(c.alphaComponent)
            p.tintAlphaMin *= a
            p.tintAlphaMax *= a
        }
        let tintBoost = max(0.0, min(12.0, config.tintBoost))
        if tintBoost != 1.0 {
            p.tintAlphaMin *= tintBoost
            p.tintAlphaMax *= tintBoost
        }

        if config.forceTransparent {
            p.diffusionBlurRadius = 0
            p.centerBlurMix = 0
            p.edgeBlurMix = 0
            p.tintAlphaMin = 0
            p.tintAlphaMax = 0
            p.fresnelIntensity = 0
            p.fresnelCornerBoost = 0
            p.saturation = 1.0
            p.contrast = 1.0
            p.aoStrength = 0
            p.refractionAmplitude = max(p.refractionAmplitude, 0.55)
            p.centerRefractionMix = max(p.centerRefractionMix, 0.28)
            p.refractionScale = max(12.0, p.refractionScale * 0.75)
        }

        return p
    }

    private var appearanceObserver: Any?

    private func installAppearanceObserverIfNeeded() {
        guard appearanceObserver == nil else { return }
        appearanceObserver = NotificationCenter.default.addObserver(
            forName: .arxivAppearanceDidChange,
            object: AppearanceManager.shared,
            queue: .main
        ) { [weak self] _ in
            guard let self else { return }
            self.updateStyle()
            self.scheduleRender(reason: "appearance")
        }
    }

    deinit {
        if let appearanceObserver {
            NotificationCenter.default.removeObserver(appearanceObserver)
        }
    }

    override func layout() {
        PerfLogger.begin("layout.glass_card")
        defer { PerfLogger.end("layout.glass_card") }
        super.layout()
        installAppearanceObserverIfNeeded()
        layer?.cornerRadius = cornerRadius
        if #available(macOS 10.13, *) { layer?.cornerCurve = .continuous }

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        backgroundImageLayer.frame = bounds
        backgroundImageLayer.cornerRadius = cornerRadius
        if #available(macOS 10.13, *) { backgroundImageLayer.cornerCurve = .continuous }
        fillLayer.frame = bounds
        highlightLayer.frame = bounds
        shadowLayer.frame = bounds

        let outerInset = max(0.5, strokeLayer.lineWidth / 2)
        let innerInset = max(0.5, innerStrokeLayer.lineWidth / 2) + 1.0
        let outerRect = bounds.insetBy(dx: outerInset, dy: outerInset)
        let innerRect = bounds.insetBy(dx: innerInset, dy: innerInset)
        let outerPath = CGPath(roundedRect: outerRect,
                               cornerWidth: cornerRadius,
                               cornerHeight: cornerRadius,
                               transform: nil)
        let innerPath = CGPath(roundedRect: innerRect,
                               cornerWidth: max(0, cornerRadius - 1.0),
                               cornerHeight: max(0, cornerRadius - 1.0),
                               transform: nil)
        rimDarkLayer.frame = bounds
        rimDarkLayer.path = outerPath
        rimDarkLayer.shadowPath = outerPath
        rimLightLayer.frame = bounds
        rimLightLayer.path = outerPath
        rimLightLayer.shadowPath = outerPath
        dispersionLayer.frame = bounds
        dispersionMask.frame = bounds
        dispersionMask.path = outerPath
        strokeLayer.frame = bounds
        strokeLayer.path = outerPath
        innerStrokeLayer.frame = bounds
        innerStrokeLayer.path = innerPath
        CATransaction.commit()

        updateStyle()
        scheduleRender(reason: "layout")
    }

    private func updateStyle() {
        if !isLiquidGlassEnabled {
            let fallback = glassFallbackTint ?? resolvedSystemColor(.windowBackgroundColor)
            let base = fallback.usingColorSpace(.deviceRGB) ?? fallback
            let tint = (config.tint?.usingColorSpace(.deviceRGB) ?? config.tint) ?? base
            let blended = blend(base, tint.withAlphaComponent(1.0), t: 0.12)
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            backgroundImageLayer.opacity = 0
            backgroundImageLayer.contents = nil
            fillLayer.backgroundColor = blended.withAlphaComponent(1.0).cgColor
            highlightLayer.colors = [NSColor.clear.cgColor, NSColor.clear.cgColor, NSColor.clear.cgColor]
            shadowLayer.colors = [NSColor.clear.cgColor, NSColor.clear.cgColor]
            rimDarkLayer.lineWidth = 0
            rimDarkLayer.strokeColor = NSColor.clear.cgColor
            rimDarkLayer.shadowOpacity = 0
            rimDarkLayer.shadowRadius = 0
            rimLightLayer.lineWidth = 0
            rimLightLayer.strokeColor = NSColor.clear.cgColor
            rimLightLayer.shadowOpacity = 0
            rimLightLayer.shadowRadius = 0
            dispersionLayer.colors = [NSColor.clear.cgColor, NSColor.clear.cgColor, NSColor.clear.cgColor]
            strokeLayer.lineWidth = 0
            strokeLayer.strokeColor = NSColor.clear.cgColor
            innerStrokeLayer.lineWidth = 0
            innerStrokeLayer.strokeColor = NSColor.clear.cgColor
            CATransaction.commit()
            return
        }
        if config.forceTransparent {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            backgroundImageLayer.opacity = 1
            fillLayer.backgroundColor = NSColor.clear.cgColor
            highlightLayer.colors = [NSColor.clear.cgColor, NSColor.clear.cgColor, NSColor.clear.cgColor]
            shadowLayer.colors = [NSColor.clear.cgColor, NSColor.clear.cgColor]
            rimDarkLayer.lineWidth = 0
            rimDarkLayer.strokeColor = NSColor.clear.cgColor
            rimDarkLayer.shadowOpacity = 0
            rimDarkLayer.shadowRadius = 0
            rimLightLayer.lineWidth = 0
            rimLightLayer.strokeColor = NSColor.clear.cgColor
            rimLightLayer.shadowOpacity = 0
            rimLightLayer.shadowRadius = 0
            dispersionLayer.colors = [NSColor.clear.cgColor, NSColor.clear.cgColor, NSColor.clear.cgColor]
            strokeLayer.lineWidth = 0
            strokeLayer.strokeColor = NSColor.clear.cgColor
            innerStrokeLayer.lineWidth = 0
            innerStrokeLayer.strokeColor = NSColor.clear.cgColor
            CATransaction.commit()
            return
        }
        backgroundImageLayer.opacity = 1

        let dark = resolvedGlassAppearanceIsDark()
        let stateScale = stateMultipliers(for: config.state)
        let thickness = max(0.7, config.thickness)
        let specular = max(0.2, min(1.6, config.specularIntensity)) * stateScale.specular
        let border = config.borderStyle
        let shadowStyle = config.shadowStyle

        // Clarity leap: keep the fill nearly invisible; let refraction + rims define the glass.
        // Optional debug instrumentation: colorize layers to isolate what is darkening the card.
        let fillBase: CGFloat = dark ? 0.010 : 0.014
        let clarity = clampUnit(config.transmission)
        let fillAlpha = max(0.0, fillBase * (1.05 - (0.80 * clarity)) * stateScale.fill)
        let fillColor = (config.tint ?? NSColor.white).usingColorSpace(.deviceRGB) ?? (config.tint ?? NSColor.white)
        let fillBoost = max(0.0, min(12.0, config.fillBoost))
        let fillAlphaAdjusted = min(1.0, fillAlpha * clampUnit(fillColor.alphaComponent) * fillBoost)

        let highlightTop: CGFloat = (dark ? 0.32 : 0.24) * specular
        let highlightMid: CGFloat = (dark ? 0.12 : 0.08) * specular
        let shadowBottom: CGFloat = (dark ? shadowStyle.bottomAlpha * 1.25 : shadowStyle.bottomAlpha) * stateScale.shadow

        CATransaction.begin()
        CATransaction.setDisableActions(true)

        let layerDebug = ProcessInfo.processInfo.environment["ARXIV_GLASS_LAYER_DEBUG"] == "1"
        if layerDebug {
            // Layer stack visualization:
            // - fillLayer: red
            // - highlightLayer: green
            // - shadowLayer: blue
            fillLayer.backgroundColor = NSColor.systemRed.withAlphaComponent(max(0.02, fillAlphaAdjusted * 20)).cgColor
        } else {
            fillLayer.backgroundColor = fillColor.withAlphaComponent(fillAlphaAdjusted).cgColor
        }

        if layerDebug {
            highlightLayer.colors = [
                NSColor.systemGreen.withAlphaComponent(0.50).cgColor,
                NSColor.systemGreen.withAlphaComponent(0.22).cgColor,
                NSColor.clear.cgColor
            ]
        } else if config.flatFill {
            highlightLayer.colors = [
                NSColor.clear.cgColor,
                NSColor.clear.cgColor,
                NSColor.clear.cgColor
            ]
        } else {
            highlightLayer.colors = [
                NSColor.white.withAlphaComponent(highlightTop).cgColor,
                NSColor.white.withAlphaComponent(highlightMid).cgColor,
                NSColor.clear.cgColor
            ]
        }
        highlightLayer.locations = [0.0, 0.15, 1.0]

        if layerDebug {
            shadowLayer.colors = [
                NSColor.clear.cgColor,
                NSColor.systemBlue.withAlphaComponent(0.55).cgColor
            ]
        } else if config.flatFill {
            shadowLayer.colors = [
                NSColor.clear.cgColor,
                NSColor.clear.cgColor
            ]
        } else {
            shadowLayer.colors = [
                NSColor.clear.cgColor,
                NSColor.black.withAlphaComponent(shadowBottom).cgColor
            ]
        }
        shadowLayer.locations = [0.80, 1.0]

        // Crisp rim shadows (rounded bubble edge).
        let rimWidth = border.rimWidth * thickness
        let rimDarkAlpha = border.rimDarkAlpha * (dark ? 1.20 : 1.45) * specular
        let rimLightAlpha = border.rimLightAlpha * (dark ? 1.15 : 0.85) * specular

        rimDarkLayer.lineWidth = rimWidth
        rimDarkLayer.strokeColor = NSColor.black.withAlphaComponent(rimDarkAlpha).cgColor
        rimDarkLayer.shadowColor = NSColor.black.cgColor
        rimDarkLayer.shadowOpacity = shadowStyle.rimOpacity * (dark ? 1.35 : 1.0) * Float(stateScale.shadow)
        rimDarkLayer.shadowRadius = shadowStyle.rimRadius * thickness
        rimDarkLayer.shadowOffset = CGSize(width: shadowStyle.rimOffset.width,
                                           height: -abs(shadowStyle.rimOffset.height))

        rimLightLayer.lineWidth = rimWidth + (0.2 * thickness)
        rimLightLayer.strokeColor = NSColor.white.withAlphaComponent(rimLightAlpha).cgColor
        rimLightLayer.shadowColor = NSColor.white.cgColor
        rimLightLayer.shadowOpacity = shadowStyle.rimOpacity * (dark ? 1.15 : 0.95) * Float(stateScale.shadow)
        rimLightLayer.shadowRadius = shadowStyle.rimRadius * 0.85 * thickness
        rimLightLayer.shadowOffset = CGSize(width: shadowStyle.rimOffset.width,
                                            height: abs(shadowStyle.rimOffset.height))

        // Rim dispersion (warm/cool split) - subtle and rim-only.
        let dispersionAlpha = border.dispersionAlpha * (dark ? 1.20 : 0.85) * specular
        let warm = NSColor(calibratedRed: 1.0, green: 0.86, blue: 0.72, alpha: dispersionAlpha * 1.10)
        let cool = NSColor(calibratedRed: 0.72, green: 0.88, blue: 1.0, alpha: dispersionAlpha)
        dispersionLayer.colors = [warm.cgColor, NSColor.clear.cgColor, cool.cgColor]
        dispersionLayer.locations = [0.0, 0.5, 1.0]

        // Crisp outer + inner strokes to define the edge without a hard border.
        let strokeBase = dark ? NSColor.white : NSColor.black
        strokeLayer.lineWidth = border.outerWidth * thickness
        strokeLayer.strokeColor = strokeBase.withAlphaComponent(border.outerAlpha * (dark ? 1.10 : 2.40)).cgColor
        innerStrokeLayer.lineWidth = border.innerWidth * thickness
        innerStrokeLayer.strokeColor = strokeBase.withAlphaComponent(border.innerAlpha * (dark ? 1.05 : 2.20)).cgColor

        CATransaction.commit()
    }

    func invalidateGlass(reason: String = "invalidate") {
        _ = reason
        lastRenderKey = ""
        scheduleRender(reason: reason)
    }

    func renderImmediately(reason: String = "manual") {
        _ = reason
        renderWorkItem?.cancel()
        lastRenderKey = ""
        renderGlassIfPossible()
    }

    private func scheduleRender(reason: String) {
        _ = reason
        renderWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            self?.renderGlassIfPossible()
        }
        renderWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.06, execute: work)
    }

    private func renderGlassIfPossible() {
        guard isLiquidGlassEnabled else {
            backgroundImageLayer.contents = nil
            return
        }
        guard bounds.width >= 8, bounds.height >= 8 else { return }
        guard let window else { return }
        // Avoid doing any work before the window is visible (AppKit can crash when caching display too early).
        guard window.isVisible else { return }

        let scale = max(1.0, window.backingScaleFactor)
        let sizePx = CGSize(width: bounds.width * scale, height: bounds.height * scale)
        let cornerRadiusPx = cornerRadius * scale
        let dark = effectiveAppearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua

        let rectInWindow = convert(bounds, to: nil)
        // Include position so moving glass re-samples its live background instead of dragging a stale snapshot.
        let originX = Int(round(rectInWindow.minX * scale))
        let originY = Int(round(rectInWindow.minY * scale))
        let key = "\(Int(sizePx.width))x\(Int(sizePx.height))@\(Int(scale * 100))_x=\(originX)_y=\(originY)_dark=\(dark)_dbg=\(glassDebugView.rawValue)"
        if key == lastRenderKey, backgroundImageLayer.contents != nil { return }
        lastRenderKey = key

        let paramsPx = glassParams.scaled(by: scale)
        maybeLogLiquidGlassParamsOnce(paramsPx: paramsPx, dark: dark, scale: scale)

        let bg: CGImage
        if freezeBackgroundSampling, let frozen = frozenBackground {
            bg = frozen
        } else if let image = backgroundProvider?(rectInWindow, scale) {
            bg = image
            frozenBackground = image
        } else if let cached = frozenBackground {
            // Keep the last successful sample to avoid a black flash during move/resize.
            bg = cached
        } else if config.forceTransparent {
            if backgroundImageLayer.contents != nil {
                CATransaction.begin()
                CATransaction.setDisableActions(true)
                backgroundImageLayer.contents = nil
                CATransaction.commit()
            }
            return
        } else {
            // If we cannot sample a background, keep the glass transparent instead of flashing black.
            if backgroundImageLayer.contents != nil {
                CATransaction.begin()
                CATransaction.setDisableActions(true)
                backgroundImageLayer.contents = nil
                CATransaction.commit()
            }
            return
        }

        LiquidGlassRenderer.shared.renderAsync(
            background: bg,
            sizePx: sizePx,
            cornerRadiusPx: cornerRadiusPx,
            isDark: dark,
            parameters: paramsPx,
            debug: glassDebugView
        ) { [weak self] cg in
            guard let self else { return }
            guard let cg else { return }
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            self.backgroundImageLayer.contents = cg
            self.backgroundImageLayer.contentsScale = scale
            CATransaction.commit()
        }
    }

    private func solidFallbackBackground(sizePx: CGSize, dark: Bool) -> CGImage {
        let w = max(2, Int(sizePx.width.rounded()))
        let h = max(2, Int(sizePx.height.rounded()))
        let cs = CGColorSpaceCreateDeviceRGB()
        let bitmapInfo = CGImageAlphaInfo.premultipliedLast.rawValue
        let base = dark ? NSColor.black : NSColor.white
        let c = base.usingColorSpace(.deviceRGB) ?? base
        guard let ctx = CGContext(data: nil,
                                  width: w,
                                  height: h,
                                  bitsPerComponent: 8,
                                  bytesPerRow: w * 4,
                                  space: cs,
                                  bitmapInfo: bitmapInfo) else {
            // As a last resort, return a 2x2 black image.
            return CGImage(width: 2, height: 2, bitsPerComponent: 8, bitsPerPixel: 32, bytesPerRow: 8, space: cs, bitmapInfo: CGBitmapInfo(rawValue: bitmapInfo), provider: CGDataProvider(data: Data(repeating: 0, count: 16) as CFData)!, decode: nil, shouldInterpolate: false, intent: .defaultIntent)!
        }
        ctx.setFillColor(red: c.redComponent, green: c.greenComponent, blue: c.blueComponent, alpha: 1.0)
        ctx.fill(CGRect(x: 0, y: 0, width: w, height: h))
        return ctx.makeImage()!
    }

    private func maybeLogLiquidGlassParamsOnce(paramsPx: LiquidGlassRenderer.Parameters, dark: Bool, scale: CGFloat) {
        guard ProcessInfo.processInfo.environment["ARXIV_GLASS_LOG_PARAMS"] == "1" else { return }
        guard !Self.didLogLiquidGlassParams else { return }
        Self.didLogLiquidGlassParams = true
        NSLog("[LiquidGlass] scale=%.2f dark=%@ diffuse(blur=%.2fpx mix(center=%.2f edge=%.2f)) refr(scale=%.2fpx amp=%.2f baseMix=%.2f enabled=%@) tint=[%.4f,%.4f] fresnel(int=%.3f exp=%.2f corner=%.2f) ao=%.4f sat=%.2f con=%.2f noise(op=%.4f enabled=%@)",
              scale,
              dark ? "true" : "false",
              paramsPx.diffusionBlurRadius,
              paramsPx.centerBlurMix,
              paramsPx.edgeBlurMix,
              paramsPx.refractionScale,
              paramsPx.refractionAmplitude,
              paramsPx.centerRefractionMix,
              paramsPx.enableRefraction ? "true" : "false",
              paramsPx.tintAlphaMin,
              paramsPx.tintAlphaMax,
              paramsPx.fresnelIntensity,
              paramsPx.fresnelExponent,
              paramsPx.fresnelCornerBoost,
              paramsPx.aoStrength,
              paramsPx.saturation,
              paramsPx.contrast,
              paramsPx.noiseOpacity,
              paramsPx.enableNoise ? "true" : "false")
    }
}

class NoScrollTableView: NSTableView {
    override func scrollWheel(with event: NSEvent) {
        // Disable gesture-driven scrolling/panning for the publications list.
    }
}

final class AnnotationListTableView: NSTableView {
    override var acceptsFirstResponder: Bool { true }
    var onDeletePressed: (() -> Void)?
    var onUserScroll: (() -> Void)?
    private var userInitiatedSelection = false
    private var selectionWasKeyboard = false

    func consumeUserInitiatedSelectionContext() -> (userInitiated: Bool, keyboard: Bool) {
        let wasUserInitiated = userInitiatedSelection
        let wasKeyboard = selectionWasKeyboard
        userInitiatedSelection = false
        selectionWasKeyboard = false
        return (wasUserInitiated, wasKeyboard)
    }

    override func mouseDown(with event: NSEvent) {
        userInitiatedSelection = true
        selectionWasKeyboard = false
        window?.makeFirstResponder(self)
        super.mouseDown(with: event)
    }

    override func scrollWheel(with event: NSEvent) {
        onUserScroll?()
        AnnotationScrollDebugState.shared.noteWheel(event, source: "annotations.tableView")
        super.scrollWheel(with: event)
    }

    override func noteHeightOfRows(withIndexesChanged indexSet: IndexSet) {
        AnnotationScrollDebugState.shared.noteRowsInvalidated(count: indexSet.count, source: "annotations.tableView")
        super.noteHeightOfRows(withIndexesChanged: indexSet)
    }

    override func layout() {
        PerfLogger.begin("layout.annotations.tableView")
        defer { PerfLogger.end("layout.annotations.tableView") }
        super.layout()
        AnnotationScrollDebugState.shared.noteLayout(bounds: bounds, source: "annotations.tableView")
    }

    override func keyDown(with event: NSEvent) {
        let disallowedMods: NSEvent.ModifierFlags = [.command, .option, .control]
        let hasDisallowedMods = !event.modifierFlags.intersection(disallowedMods).isEmpty
        if !hasDisallowedMods {
            switch event.keyCode {
            case 126: // up
                userInitiatedSelection = true
                selectionWasKeyboard = true
                moveSelection(delta: -1)
                return
            case 125: // down
                userInitiatedSelection = true
                selectionWasKeyboard = true
                moveSelection(delta: 1)
                return
            case 51, 117: // Delete / Forward Delete
                onDeletePressed?()
                return
            default:
                break
            }
        }
        super.keyDown(with: event)
    }

    private func moveSelection(delta: Int) {
        let rows = numberOfRows
        guard rows > 0 else { return }
        var next = selectedRow
        if next < 0 {
            next = delta >= 0 ? 0 : rows - 1
        } else {
            next += delta
        }
        next = max(0, min(rows - 1, next))
        if next == selectedRow { return }
        selectRowIndexes(IndexSet(integer: next), byExtendingSelection: false)
        scrollRowToVisible(next)
    }
}

final class HorizontalScrollableTableView: NSTableView {
    override func scrollWheel(with event: NSEvent) {
        // Allow horizontal panning for the main publications table only.
        // Keep vertical gesture scrolling disabled (selection/navigation is handled elsewhere).
        let dx = event.scrollingDeltaX
        guard abs(dx) > 0.01 else { return }
        if let sv = enclosingScrollView {
            sv.scrollWheel(with: event)
        } else {
            super.scrollWheel(with: event)
        }
    }
}

final class MenuTableView: NoScrollTableView {
    override func mouseDown(with event: NSEvent) {
        super.mouseDown(with: event)
        guard event.type == .leftMouseDown,
              event.clickCount == 1,
              clickedRow >= 0,
              let action = action else {
            return
        }
        NSApp.sendAction(action, to: target, from: self)
    }
}

final class NoScrollScrollView: NSScrollView {
    override func scrollWheel(with event: NSEvent) {
        // Swallow scroll-wheel events so trackpad gestures cannot pan this scroll view.
    }
}

final class HorizontalOnlyScrollView: NSScrollView {
    private var isClampingScroll: Bool = false

    private func clampHorizontalOffset() {
        guard !isClampingScroll else { return }
        guard let doc = documentView else { return }
        let clip = contentView

        let contentW = max(doc.bounds.width, doc.frame.width)
        let viewportW = max(1, clip.bounds.width)
        let maxX = max(0, contentW - viewportW)

        var origin = clip.bounds.origin
        let clampedX = max(0, min(maxX, origin.x))
        guard abs(origin.x - clampedX) > 0.01 else { return }
        origin.x = clampedX

        isClampingScroll = true
        clip.setBoundsOrigin(origin)
        super.reflectScrolledClipView(clip)
        isClampingScroll = false
    }

    override func scrollWheel(with event: NSEvent) {
        // Only allow horizontal scrolling; swallow vertical wheel/trackpad gestures.
        let dx = event.scrollingDeltaX
        guard abs(dx) > 0.01 else { return }
        super.scrollWheel(with: event)
        clampHorizontalOffset()
    }

    override func reflectScrolledClipView(_ cView: NSClipView) {
        super.reflectScrolledClipView(cView)
        clampHorizontalOffset()
    }

    override func layout() {
        super.layout()
        clampHorizontalOffset()
    }
}

protocol HitTestControlling: AnyObject {
    var allowsHitTesting: Bool { get set }
}

struct HighlightHitRegion {
    let annotation: PDFAnnotation
    let frame: CGRect
    let pageIndex: Int

    var area: CGFloat { frame.width * frame.height }
}

final class HorizontalLockedWKWebView: WKWebView, HitTestControlling {
    var allowsHitTesting: Bool = true

    override func hitTest(_ point: NSPoint) -> NSView? {
        guard allowsHitTesting, !isHidden else { return nil }
        return super.hitTest(point)
    }

    var lockedX: CGFloat = 0

    override func scrollWheel(with event: NSEvent) {
        super.scrollWheel(with: event)
        clampHorizontalOffset()
    }

    override func layout() {
        super.layout()
        clampHorizontalOffset()
    }

    private func clampHorizontalOffset() {
        guard let scrollView = firstDescendantScrollView() else { return }
        let clip = scrollView.contentView
        var origin = clip.bounds.origin
        guard abs(origin.x - lockedX) > 0.01 else { return }
        origin.x = lockedX
        clip.setBoundsOrigin(origin)
        scrollView.reflectScrolledClipView(clip)
    }

    private func firstDescendantScrollView() -> NSScrollView? {
        func walk(_ view: NSView) -> NSScrollView? {
            if let sv = view as? NSScrollView { return sv }
            for sub in view.subviews {
                if let found = walk(sub) { return found }
            }
            return nil
        }
        return walk(self)
    }
}

