    var onZoomOut: (() -> Void)?
    var onZoomReset: (() -> Void)?
    var onZoomAuto: (() -> Void)?
    var onZoomPageWidth: (() -> Void)?
    var onZoomPageHeight: (() -> Void)?
    var zoomMenuStateProvider: (() -> PDFZoomMenuState)?
    var highlightHitRegions: [HighlightHitRegion] = [] {
        didSet { window?.invalidateCursorRects(for: self) }
    }
#if DEBUG
    private static var debugIDCounter: Int = 0
    private let debugID: Int
    var flickerGuardActiveProvider: (() -> Bool)?
    var flickerGuardContextProvider: (() -> String)?
    private var layerObserver: LayerObserver?
#endif

    private lazy var annotateMenuIcon: NSImage? = {
        let pointSize = NSFont.menuFont(ofSize: 0).pointSize
        let config = NSImage.SymbolConfiguration(pointSize: pointSize, weight: .regular)
        let names = ["note.text", "square.and.pencil", "pencil.and.scribble", "pencil"]
        for name in names {
            if let base = NSImage(systemSymbolName: name, accessibilityDescription: nil) {
                let image = base.withSymbolConfiguration(config) ?? base
                image.isTemplate = true
                return image
            }
        }
        return nil
    }()

    private lazy var googleMenuIcon: NSImage? = {
        let pointSize = NSFont.menuFont(ofSize: 0).pointSize
        let size = NSSize(width: pointSize, height: pointSize)
        let image = NSImage(size: size, flipped: false) { rect in
            guard let ctx = NSGraphicsContext.current?.cgContext else { return false }
            let lineWidth = max(1.5, rect.width * 0.18)
            ctx.setLineWidth(lineWidth)
            ctx.setLineCap(.round)
            let center = CGPoint(x: rect.midX, y: rect.midY)
            let radius = (min(rect.width, rect.height) - lineWidth) / 2

            func strokeArc(start: CGFloat, end: CGFloat) {
                let degToRad = CGFloat.pi / 180.0
                ctx.setStrokeColor(NSColor.white.cgColor)
                ctx.addArc(center: center,
                           radius: radius,
                           startAngle: start * degToRad,
                           endAngle: end * degToRad,
                           clockwise: false)
                ctx.strokePath()
            }

            strokeArc(start: -40, end: 300)

            let barHeight = lineWidth
            let barWidth = radius * 0.85
            let barRect = CGRect(x: center.x, y: center.y - barHeight / 2, width: barWidth, height: barHeight)
            ctx.setFillColor(NSColor.white.cgColor)
            ctx.fill(barRect)

            return true
        }
        image.isTemplate = true
        return image
    }()

    private let highlightClickDragThreshold: CGFloat = 3
    private var highlightClickCandidate: PDFAnnotation?
    private var highlightClickStart: NSPoint?
    private var highlightClickDidDrag = false
    private var noteClickCandidate: PDFAnnotation?
    private var noteClickStart: NSPoint?
    private var noteClickDidDrag = false

