    private weak var lastContextMenuPage: PDFPage?

#if DEBUG
    private final class LayerObserver: NSObject {
        weak var owner: ZoomablePDFView?
        private weak var observedLayer: CALayer?
        private static var context = 0
        private let keys = ["opacity", "hidden", "opaque", "sublayers"]

        func attach(to layer: CALayer) {
            detach()
            observedLayer = layer
            for key in keys {
                layer.addObserver(self, forKeyPath: key, options: [.new, .old], context: &LayerObserver.context)
            }
        }

        func detach() {
            guard let layer = observedLayer else { return }
            for key in keys {
                layer.removeObserver(self, forKeyPath: key, context: &LayerObserver.context)
            }
            observedLayer = nil
        }

        deinit {
            detach()
        }

        override func observeValue(forKeyPath keyPath: String?,
                                   of object: Any?,
                                   change: [NSKeyValueChangeKey : Any]?,
                                   context: UnsafeMutableRawPointer?) {
            guard context == &LayerObserver.context else {
                super.observeValue(forKeyPath: keyPath, of: object, change: change, context: context)
                return
            }
            owner?.handleLayerObservation(keyPath: keyPath, change: change)
        }
    }

    private static func nextDebugID() -> Int {
        debugIDCounter += 1
        return debugIDCounter
    }

    private func flickerGuardActive() -> Bool {
        flickerGuardActiveProvider?() ?? false
    }

    private func flickerGuardContext() -> String {
        flickerGuardContextProvider?() ?? "unknown"
    }

    private func flickerDebugLog(_ message: String, force: Bool = false) {
        guard force || pdfFlickerDebugEnabled || flickerGuardActive() else { return }
        NSLog("[PDF_FLICKER] view=\(debugID) \(message) ctx=\(flickerGuardContext())")
    }

    private func flickerAssertIfActive(_ violation: Bool, _ message: String) {
        guard flickerGuardActive(), violation else { return }
        let stack = Thread.callStackSymbols.joined(separator: "\n")
        flickerDebugLog("ASSERT \(message)\n\(stack)", force: true)
        assertionFailure(message)
    }

    private func attachLayerObserverIfNeeded() {
        if layerObserver == nil {
            let observer = LayerObserver()
            observer.owner = self
            layerObserver = observer
        }
        if let layer = layer {
            layerObserver?.attach(to: layer)
        } else {
            layerObserver?.detach()
        }
    }

    private func handleLayerObservation(keyPath: String?, change: [NSKeyValueChangeKey : Any]?) {
        guard let keyPath else { return }
        let oldValue = change?[.oldKey]
        let newValue = change?[.newKey]
        flickerDebugLog("layer_change key=\(keyPath) old=\(String(describing: oldValue)) new=\(String(describing: newValue))")

        if keyPath == "opacity" || keyPath == "hidden" {
            flickerAssertIfActive(true, "layer.\(keyPath) changed")
        }
    }

    private func checkFrameForFlicker(_ frame: NSRect, reason: String) {
        let w = frame.width
        let h = frame.height
        if !w.isFinite || !h.isFinite {
            flickerDebugLog("frame_invalid reason=\(reason) frame=\(NSStringFromRect(frame))", force: true)
            return
        }
        if w <= 1 || h <= 1 {
            flickerDebugLog("frame_too_small reason=\(reason) frame=\(NSStringFromRect(frame))", force: true)
            flickerAssertIfActive(true, "pdfView frame <= 1 (\(String(format: "%.2f", w))x\(String(format: "%.2f", h)))")
        }
        if let superview {
            let b = superview.bounds
            let offscreen = frame.maxX < -1 || frame.maxY < -1 || frame.minX > b.width + 1 || frame.minY > b.height + 1
            if offscreen {
                flickerDebugLog("frame_offscreen reason=\(reason) frame=\(NSStringFromRect(frame)) super=\(NSStringFromRect(b))")
            }
        }
    }
#endif

    private enum ZoomMenuTag {
        static let base = 9100
        static let annotate = 9101
        static let zoomIn = 9102
        static let zoomOut = 9103
        static let zoomReset = 9104
        static let zoomAuto = 9105
        static let zoomPageWidth = 9106
        static let zoomPageHeight = 9107
        static let separator1 = 9108
        static let separator2 = 9109
    }

    override var acceptsFirstResponder: Bool { true }

#if DEBUG
    override init(frame frameRect: NSRect) {
        self.debugID = ZoomablePDFView.nextDebugID()
        super.init(frame: frameRect)
        flickerDebugLog("init frame=\(NSStringFromRect(frameRect))", force: true)
        attachLayerObserverIfNeeded()
        flickerAssertIfActive(true, "pdfView init during panel/resize transaction")
    }

    required init?(coder: NSCoder) {
        self.debugID = ZoomablePDFView.nextDebugID()
        super.init(coder: coder)
        flickerDebugLog("init coder", force: true)
        attachLayerObserverIfNeeded()
        flickerAssertIfActive(true, "pdfView init during panel/resize transaction")
    }

    deinit {
        flickerDebugLog("deinit", force: true)
        flickerAssertIfActive(true, "pdfView deinit during panel/resize transaction")
        layerObserver?.detach()
    }

    override var isHidden: Bool {
        didSet {
            guard oldValue != isHidden else { return }
            flickerDebugLog("isHidden=\(isHidden)")
            flickerAssertIfActive(true, "pdfView.isHidden changed")
        }
    }

    override var alphaValue: CGFloat {
        didSet {
            guard abs(oldValue - alphaValue) > 0.0001 else { return }
            flickerDebugLog("alphaValue=\(String(format: "%.3f", alphaValue))")
            flickerAssertIfActive(true, "pdfView.alphaValue changed")
        }
    }

    override var wantsLayer: Bool {
        didSet {
            guard oldValue != wantsLayer else { return }
            flickerDebugLog("wantsLayer=\(wantsLayer)")
            attachLayerObserverIfNeeded()
        }
    }

    override var layer: CALayer? {
        didSet {
            let oldID = oldValue.map { ObjectIdentifier($0) }
            let newID = layer.map { ObjectIdentifier($0) }
            if oldID != newID {
                flickerDebugLog("layer_set old=\(String(describing: oldID)) new=\(String(describing: newID))")
            }
            attachLayerObserverIfNeeded()
        }
    }

    override var document: PDFDocument? {
        didSet {
            let changed = (oldValue !== document)
            guard changed else { return }
            let oldPtr = oldValue.map { ObjectIdentifier($0) }
            let newPtr = document.map { ObjectIdentifier($0) }
            flickerDebugLog("document_set old=\(String(describing: oldPtr)) new=\(String(describing: newPtr))")
            flickerAssertIfActive(true, "pdfView.document reassigned")
        }
    }

    override func viewWillMove(toSuperview newSuperview: NSView?) {
        let phase = (newSuperview == nil) ? "willDisappear" : "willAppear"
        flickerDebugLog("viewWillMoveToSuperview phase=\(phase) new=\(String(describing: newSuperview))")
        if newSuperview == nil {
            flickerAssertIfActive(true, "pdfView removed from superview (willMove)")
        }
        super.viewWillMove(toSuperview: newSuperview)
    }

    override func viewDidMoveToSuperview() {
        let phase = (superview == nil) ? "didDisappear" : "didAppear"
        flickerDebugLog("viewDidMoveToSuperview phase=\(phase) super=\(String(describing: superview))")
        if superview == nil {
            flickerAssertIfActive(true, "pdfView removed from superview (didMove)")
        }
        super.viewDidMoveToSuperview()
    }

    override func viewWillMove(toWindow newWindow: NSWindow?) {
        flickerDebugLog("viewWillMoveToWindow new=\(String(describing: newWindow))")
        super.viewWillMove(toWindow: newWindow)
    }

    override func viewDidMoveToWindow() {
        flickerDebugLog("viewDidMoveToWindow window=\(String(describing: window))")
        super.viewDidMoveToWindow()
    }

    override func setFrameSize(_ newSize: NSSize) {
        super.setFrameSize(newSize)
        checkFrameForFlicker(frame, reason: "setFrameSize")
    }

    override func setFrameOrigin(_ newOrigin: NSPoint) {
        super.setFrameOrigin(newOrigin)
        checkFrameForFlicker(frame, reason: "setFrameOrigin")
    }

    override func layout() {
        super.layout()
        checkFrameForFlicker(frame, reason: "layout")
    }
#endif

    func primaryScrollView() -> NSScrollView? {
        var found: [NSScrollView] = []
        func walk(_ v: NSView) {
            if let sv = v as? NSScrollView { found.append(sv) }
            for sub in v.subviews { walk(sub) }
        }
        walk(self)
        return found.first(where: { $0.documentView != nil }) ?? found.first
    }

    private func scrollPrimary(by deltaY: CGFloat) -> Bool {
        guard let scrollView = primaryScrollView() else { return false }
        let clip = scrollView.contentView
        var origin = clip.bounds.origin
        origin.y += deltaY
        origin = clip.constrainBoundsRect(NSRect(origin: origin, size: clip.bounds.size)).origin
        clip.setBoundsOrigin(origin)
        scrollView.reflectScrolledClipView(clip)
        return true
    }

    private func scrollPrimaryToEdge(top: Bool) -> Bool {
        guard let scrollView = primaryScrollView(),
              let doc = scrollView.documentView else { return false }
        let clip = scrollView.contentView
        var origin = clip.bounds.origin
        if top {
            origin.y = doc.bounds.minY
        } else {
            origin.y = doc.bounds.maxY - clip.bounds.height
        }
        origin = clip.constrainBoundsRect(NSRect(origin: origin, size: clip.bounds.size)).origin
        clip.setBoundsOrigin(origin)
        scrollView.reflectScrolledClipView(clip)
        return true
    }

    override func hitTest(_ point: NSPoint) -> NSView? {
        guard allowsHitTesting, !isHidden else { return nil }
        return super.hitTest(point)
    }

    override func resetCursorRects() {
        super.resetCursorRects()
        for region in highlightHitRegions {
            addCursorRect(region.frame, cursor: .pointingHand)
        }
    }

    private func highlightHitTest(at point: NSPoint) -> PDFAnnotation? {
        let hits = highlightHitRegions.filter { $0.frame.contains(point) }
        guard let best = hits.min(by: { $0.area < $1.area }) else { return nil }
        return best.annotation
    }

    private func noteHitTest(at point: NSPoint) -> PDFAnnotation? {
        guard let page = page(for: point, nearest: true) else { return nil }
        let pagePoint = convert(point, to: page)
        if let ann = page.annotation(at: pagePoint), annotationIsTextNote(ann) {
            return ann
        }
        let padding: CGFloat = 6
        for ann in page.annotations where annotationIsTextNote(ann) {
            if ann.bounds.insetBy(dx: -padding, dy: -padding).contains(pagePoint) {
                return ann
            }
        }
        return nil
    }

    private func removeZoomMenuItems(from menu: NSMenu) {
        for item in menu.items.reversed() {
            if item.tag >= ZoomMenuTag.base && item.tag <= ZoomMenuTag.separator2 {
                menu.removeItem(item)
            }
        }
    }

    private static let strippedContextMenuTitles: Set<String> = [
        "Zoom In",
        "Zoom Out",
        "Zoom Reset (Page Width)",
        "Zoom Auto",
        "Zoom Page Width",
        "Zoom Page Height",
        "Actual Size",
        "Next Page",
        "Previous Page",
        "Automatically Resize"
    ]

    private func removeUnwantedContextMenuItems(from menu: NSMenu) {
        let items = menu.items
        for item in items.reversed() {
            if Self.strippedContextMenuTitles.contains(item.title) {
                menu.removeItem(item)
                continue
            }
            if let submenu = item.submenu {
                removeUnwantedContextMenuItems(from: submenu)
                if submenu.items.isEmpty, item.title != "Services" {
                    menu.removeItem(item)
                }
            }
        }
    }

    private func reorderContextMenuItems(_ menu: NSMenu) {
        var items = menu.items
        items.removeAll { $0.isSeparatorItem }

        func takeFirst(where predicate: (NSMenuItem) -> Bool) -> NSMenuItem? {
            guard let index = items.firstIndex(where: predicate) else { return nil }
            return items.remove(at: index)
        }

        func takeTitle(_ title: String) -> NSMenuItem? {
            takeFirst { $0.title == title }
        }

        func takePrefix(_ prefix: String) -> NSMenuItem? {
            takeFirst { $0.title.hasPrefix(prefix) }
        }

        let annotate = takeFirst { $0.tag == ZoomMenuTag.annotate } ?? takeTitle("Annotate…")
        let lookUp = takePrefix("Look Up")
        let search = takePrefix("Search with Google")
        if let search { search.image = googleMenuIcon }
        let translate = takePrefix("Translate")
        let copy = takeTitle("Copy")
        let summarize = takeTitle("Summarize")
        let writingTools = takeTitle("Show Writing Tools")

        let singlePage = takeTitle("Single Page")
        let singlePageContinuous = takeTitle("Single Page Continuous")
        let twoPages = takeTitle("Two Pages")
        let twoPagesContinuous = takeTitle("Two Pages Continuous")
        let services = takeTitle("Services")

        var ordered: [NSMenuItem] = []

        func append(_ item: NSMenuItem?) {
            if let item { ordered.append(item) }
        }

        func appendSeparatorIfNeeded() {
            guard let last = ordered.last, !last.isSeparatorItem else { return }
            ordered.append(.separator())
        }

        append(annotate)
        append(lookUp)
        append(search)
        append(translate)
        append(copy)
        append(summarize)
        append(writingTools)

        let singleGroup = [singlePage, singlePageContinuous].compactMap { $0 }
        if !singleGroup.isEmpty {
            appendSeparatorIfNeeded()
            ordered.append(contentsOf: singleGroup)
        }

        let doubleGroup = [twoPages, twoPagesContinuous].compactMap { $0 }
        if !doubleGroup.isEmpty {
            appendSeparatorIfNeeded()
            ordered.append(contentsOf: doubleGroup)
        }

        if !items.isEmpty {
            appendSeparatorIfNeeded()
            ordered.append(contentsOf: items)
        }

        if let services {
            appendSeparatorIfNeeded()
            ordered.append(services)
        }

        menu.removeAllItems()
        ordered.forEach { menu.addItem($0) }
    }

    private func pruneMenuSeparators(in menu: NSMenu) {
        let items = menu.items
        for item in items {
            if let submenu = item.submenu {
                pruneMenuSeparators(in: submenu)
                if submenu.items.isEmpty, item.title != "Services" {
                    menu.removeItem(item)
                }
            }
        }

        var lastWasSeparator = false
        for item in menu.items.reversed() {
            if item.isSeparatorItem {
                if lastWasSeparator {
                    menu.removeItem(item)
                }
                lastWasSeparator = true
            } else {
                lastWasSeparator = false
            }
        }

        while menu.items.first?.isSeparatorItem == true {
            menu.removeItem(at: 0)
        }
        while menu.items.last?.isSeparatorItem == true {
            menu.removeItem(at: menu.items.count - 1)
        }
    }

    private func makeZoomMenuItems(state: PDFZoomMenuState) -> [NSMenuItem] {
        let zoomIn = NSMenuItem(title: "Zoom In", action: #selector(handleZoomInMenuItem(_:)), keyEquivalent: "=")
        zoomIn.keyEquivalentModifierMask = [.command]
        zoomIn.isEnabled = state.canZoomIn
        zoomIn.tag = ZoomMenuTag.zoomIn

        let zoomOut = NSMenuItem(title: "Zoom Out", action: #selector(handleZoomOutMenuItem(_:)), keyEquivalent: "-")
        zoomOut.keyEquivalentModifierMask = [.command]
        zoomOut.isEnabled = state.canZoomOut
        zoomOut.tag = ZoomMenuTag.zoomOut

        let zoomReset = NSMenuItem(title: "Zoom Reset (Page Width)", action: #selector(handleZoomResetMenuItem(_:)), keyEquivalent: "0")
        zoomReset.keyEquivalentModifierMask = [.command]
        zoomReset.isEnabled = state.canZoomReset
        zoomReset.tag = ZoomMenuTag.zoomReset

        let presetSeparator = NSMenuItem.separator()
        presetSeparator.tag = ZoomMenuTag.separator2

        let zoomAuto = NSMenuItem(title: "Zoom Auto", action: #selector(handleZoomAutoMenuItem(_:)), keyEquivalent: "")
        zoomAuto.state = state.zoomAutoEnabled ? .on : .off
        zoomAuto.isEnabled = true
        zoomAuto.tag = ZoomMenuTag.zoomAuto

        let zoomPageWidth = NSMenuItem(title: "Zoom Page Width", action: #selector(handleZoomPageWidthMenuItem(_:)), keyEquivalent: "")
        zoomPageWidth.state = state.zoomPageWidthEnabled ? .on : .off
        zoomPageWidth.isEnabled = true
        zoomPageWidth.tag = ZoomMenuTag.zoomPageWidth

        let zoomPageHeight = NSMenuItem(title: "Zoom Page Height", action: #selector(handleZoomPageHeightMenuItem(_:)), keyEquivalent: "")
        zoomPageHeight.state = state.zoomPageHeightEnabled ? .on : .off
        zoomPageHeight.isEnabled = true
        zoomPageHeight.tag = ZoomMenuTag.zoomPageHeight

        return [zoomIn, zoomOut, zoomReset, presetSeparator, zoomAuto, zoomPageWidth, zoomPageHeight]
    }

    @objc private func handleZoomInMenuItem(_ sender: NSMenuItem) {
        onZoomIn?()
    }

    @objc private func handleZoomOutMenuItem(_ sender: NSMenuItem) {
        onZoomOut?()
    }

    @objc private func handleZoomResetMenuItem(_ sender: NSMenuItem) {
        onZoomReset?()
    }

    @objc private func handleZoomAutoMenuItem(_ sender: NSMenuItem) {
        onZoomAuto?()
    }

    @objc private func handleZoomPageWidthMenuItem(_ sender: NSMenuItem) {
        onZoomPageWidth?()
    }

    @objc private func handleZoomPageHeightMenuItem(_ sender: NSMenuItem) {
        onZoomPageHeight?()
    }

    override func menu(for event: NSEvent) -> NSMenu? {
        let locationInView = convert(event.locationInWindow, from: nil)
        guard let page = page(for: locationInView, nearest: true) else {
            return super.menu(for: event)
        }

        let pagePoint = convert(locationInView, to: page)
        let bounds = page.bounds(for: displayBox)
        guard bounds.contains(pagePoint) else {
            return super.menu(for: event)
        }

        lastContextMenuLocationInView = locationInView
        lastContextMenuPage = page

        let menu = super.menu(for: event) ?? NSMenu()
        removeZoomMenuItems(from: menu)
        removeUnwantedContextMenuItems(from: menu)

        let annotate = NSMenuItem(title: "Annotate…", action: #selector(handleAnnotateMenuItem(_:)), keyEquivalent: "")
        annotate.target = self
        annotate.tag = ZoomMenuTag.annotate
        annotate.image = annotateMenuIcon
        menu.insertItem(annotate, at: 0)
        reorderContextMenuItems(menu)
        pruneMenuSeparators(in: menu)
        return menu
    }

    // `validateMenuItem` historically came from NSResponder; on some SDKs
    // `PDFView` does not expose it as an overridable member. Define a
    // non-overriding implementation that matches the intent without
    // requiring an override, to maximize compatibility across toolchains.
    func validateMenuItem(_ menuItem: NSMenuItem) -> Bool {
        if menuItem.tag >= ZoomMenuTag.base && menuItem.tag <= ZoomMenuTag.separator2 {
            return menuItem.isEnabled
        }
        // Fall back to allowing the menu item in ambiguous cases.
        return true
    }

    override func mouseDown(with event: NSEvent) {
        // Ensure key events (e.g. Shift+Arrow selection extension) reach PDFKit.
        window?.makeFirstResponder(self)
        let location = convert(event.locationInWindow, from: nil)
        if onNoteTap != nil,
           let note = noteHitTest(at: location) {
            noteClickCandidate = note
            noteClickStart = location
            noteClickDidDrag = false
            highlightClickCandidate = nil
            highlightClickStart = nil
            highlightClickDidDrag = false
            return
        }
        highlightClickCandidate = highlightHitTest(at: location)
        highlightClickStart = location
        highlightClickDidDrag = false
        super.mouseDown(with: event)
    }

    override func mouseDragged(with event: NSEvent) {
        if let start = noteClickStart {
            let current = convert(event.locationInWindow, from: nil)
            if abs(current.x - start.x) > highlightClickDragThreshold ||
               abs(current.y - start.y) > highlightClickDragThreshold {
                noteClickDidDrag = true
            }
        }
        if noteClickCandidate != nil {
            return
        }
        if let start = highlightClickStart {
            let current = convert(event.locationInWindow, from: nil)
            if abs(current.x - start.x) > highlightClickDragThreshold ||
               abs(current.y - start.y) > highlightClickDragThreshold {
                highlightClickDidDrag = true
            }
        }
        super.mouseDragged(with: event)
    }

    override func mouseUp(with event: NSEvent) {
        if let note = noteClickCandidate {
            defer {
                noteClickCandidate = nil
                noteClickStart = nil
                noteClickDidDrag = false
            }
            if !noteClickDidDrag && event.clickCount == 1 {
                onNoteTap?(note)
            }
            return
        }
        super.mouseUp(with: event)
        defer {
            highlightClickCandidate = nil
            highlightClickStart = nil
            highlightClickDidDrag = false
        }

        guard let candidate = highlightClickCandidate else { return }
        guard !highlightClickDidDrag else { return }
        guard event.clickCount == 1 else { return }
        let mods = event.modifierFlags.intersection([.shift, .option, .command, .control])
        guard mods.isEmpty else { return }
        onHighlightTap?(candidate)
    }

    @objc private func handleAnnotateMenuItem(_ sender: NSMenuItem) {
        guard let location = lastContextMenuLocationInView, let page = lastContextMenuPage else { return }
        onAnnotateRequest?(location, page)
        lastContextMenuLocationInView = nil
        lastContextMenuPage = nil
    }

    override func scrollWheel(with event: NSEvent) {
        // If PDFKit's internal scroll view didn't win hit-testing for some reason, forward wheel
        // events so the document remains scrollable.
        if let sv = primaryScrollView() {
            sv.scrollWheel(with: event)
            return
        }
        super.scrollWheel(with: event)
    }

    override func magnify(with _: NSEvent) {
        // Disable pinch zoom; zoom is controlled via explicit presets/commands.
    }

    override func keyDown(with event: NSEvent) {
        // Provide deterministic keyboard scrolling (arrow keys / page up/down / space).
        // This avoids relying on PDFKit's responder chain, which can be inconsistent across macOS.
        // But PDFKit uses Shift+Arrow for text selection extension; let it handle that.
        if event.modifierFlags.contains(.shift) {
            switch event.keyCode {
            case 123, 124, 125, 126: // left, right, down, up
                super.keyDown(with: event)
                return
            default:
                break
            }
        }
        guard let scrollView = primaryScrollView() else {
            super.keyDown(with: event)
            return
        }

        let shift = event.modifierFlags.contains(.shift)
        let line = max(8, scrollView.verticalLineScroll)
        let page = max(40, scrollView.verticalPageScroll)

        switch event.keyCode {
        case 126: // up
            if scrollPrimary(by: line) { return }
        case 125: // down
            if scrollPrimary(by: -line) { return }
        case 116: // page up
            if scrollPrimary(by: page) { return }
        case 121: // page down
            if scrollPrimary(by: -page) { return }
        case 49: // space
            if scrollPrimary(by: (shift ? page : -page)) { return }
        case 115: // home
            if scrollPrimaryToEdge(top: true) { return }
        case 119: // end
            if scrollPrimaryToEdge(top: false) { return }
        default:
            break
        }

        super.keyDown(with: event)
    }

    func routeScrollWheel(_ event: NSEvent) -> Bool {
        if let sv = primaryScrollView() {
            sv.scrollWheel(with: event)
            return true
        }
        return false
    }
}

protocol HorizontalLockingClipView: AnyObject {
    var lockedX: CGFloat { get set }
    var locksHorizontal: Bool { get set }
    var clampsVertical: Bool { get set }
}

final class HorizontalLockClipView: NSClipView, HorizontalLockingClipView {
    var lockedX: CGFloat = 0
    var locksHorizontal: Bool = true
    var clampsVertical: Bool = false
    private let preservesFlipped: Bool

    init(frame frameRect: NSRect, flipped: Bool) {
        self.preservesFlipped = flipped
        super.init(frame: frameRect)
    }

    required init?(coder: NSCoder) { fatalError() }

    override var isFlipped: Bool { preservesFlipped }

    private func constrainedOrigin(_ proposedOrigin: NSPoint, boundsHeight: CGFloat) -> NSPoint {
        var origin = proposedOrigin
        if locksHorizontal {
            origin.x = lockedX
        }
        if clampsVertical, let doc = documentView {
            let docFrame = doc.frame
            let minY = docFrame.minY
            let maxY = max(minY, docFrame.maxY - boundsHeight)
            origin.y = max(minY, min(maxY, origin.y))
        }
        return origin
    }

    override func setBoundsOrigin(_ newOrigin: NSPoint) {
        let constrained = constrainedOrigin(newOrigin, boundsHeight: bounds.height)
        if documentView is AnnotationListTableView,
           (abs(constrained.x - newOrigin.x) > 0.01 || abs(constrained.y - newOrigin.y) > 0.01) {
            AnnotationScrollDebugState.shared.noteClamp(origin: newOrigin,
                                                       target: constrained,
                                                       source: "annotations.clipView.setBoundsOrigin")
        }
        super.setBoundsOrigin(constrained)
    }

    override func constrainBoundsRect(_ proposedBounds: NSRect) -> NSRect {
        var rect = super.constrainBoundsRect(proposedBounds)
        rect.origin = constrainedOrigin(rect.origin, boundsHeight: rect.height)
        return rect
    }

    override func scroll(to newOrigin: NSPoint) {
        let constrained = constrainedOrigin(newOrigin, boundsHeight: bounds.height)
        super.scroll(to: constrained)
    }
}

final class FlippedView: NSView {
    override var isFlipped: Bool { true }
}

