func customAnnotationPaletteDefaultLabels() -> [String] {
    (1...6).map { "Color \($0)" }
}

func normalizedPaletteHexColors(_ raw: [String], fallback: [String]) -> [String] {
    var cleaned = raw.map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
        .filter { !$0.isEmpty }
    var result: [String] = []
    for idx in 0..<6 {
        let candidate = idx < cleaned.count ? cleaned[idx] : (idx < fallback.count ? fallback[idx] : "")
        if let color = colorFromHex(candidate) {
            let hex = hexFromColor(color, includeAlpha: true)
            result.append(hex)
        } else if idx < fallback.count {
            let fallbackHex = fallback[idx]
            if let color = colorFromHex(fallbackHex) {
                result.append(hexFromColor(color, includeAlpha: true))
            } else {
                result.append("#000000")
            }
        } else {
            result.append("#000000")
        }
    }
    return Array(result.prefix(6))
}

func normalizedPaletteLabels(_ raw: [String], fallback: [String]) -> [String] {
    var cleaned = raw.map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
    var result: [String] = []
    for idx in 0..<6 {
        let candidate = idx < cleaned.count ? cleaned[idx] : ""
        if candidate.isEmpty {
            result.append(idx < fallback.count ? fallback[idx] : "Color \(idx + 1)")
        } else {
            result.append(candidate)
        }
    }
    return Array(result.prefix(6))
}

func customAnnotationPaletteIndex(for id: String, in settings: AppSettings.DocumentsPDF) -> Int? {
    settings.customPalettes.firstIndex { $0.id == id }
}

func paletteColor(_ hex: String) -> NSColor {
    colorFromHex(hex) ?? NSColor.black
}

func accentStyleTint(from accent: NSColor, isDark: Bool) -> NSColor {
    let color = (accent.usingColorSpace(.deviceRGB) ?? accent)
    var h: CGFloat = 0
    var s: CGFloat = 0
    var v: CGFloat = 0
    var a: CGFloat = 0
    color.getHue(&h, saturation: &s, brightness: &v, alpha: &a)

    let satBoost: CGFloat = isDark ? 1.28 : 1.18
    let briMul: CGFloat = isDark ? 0.70 : 0.78
    let briBias: CGFloat = isDark ? 0.02 : 0.00
    let gamma: CGFloat = isDark ? 1.06 : 1.04

    let sat = min(1.0, max(0.0, s * satBoost))
    var bri = min(1.0, max(0.0, v * briMul + briBias))
    bri = CGFloat(pow(Double(bri), Double(gamma)))

    let out = NSColor(calibratedHue: h, saturation: sat, brightness: bri, alpha: 1.0)
    return out.usingColorSpace(.deviceRGB) ?? out
}

func accentDepthTones(from base: NSColor, isDark: Bool) -> (NSColor, NSColor) {
    let c = base.usingColorSpace(.deviceRGB) ?? base
    var h: CGFloat = 0
    var s: CGFloat = 0
    var v: CGFloat = 0
    var a: CGFloat = 0
    c.getHue(&h, saturation: &s, brightness: &v, alpha: &a)

    let hiV = min(1.0, v + (isDark ? 0.08 : 0.06))
    let loV = max(0.0, v - (isDark ? 0.10 : 0.08))
    let hiS = max(0.0, min(1.0, s * (isDark ? 0.96 : 0.94)))
    let loS = max(0.0, min(1.0, s * (isDark ? 1.02 : 1.00)))

    let hi = NSColor(calibratedHue: h, saturation: hiS, brightness: hiV, alpha: 1.0)
    let lo = NSColor(calibratedHue: h, saturation: loS, brightness: loV, alpha: 1.0)
    return (hi.usingColorSpace(.deviceRGB) ?? hi, lo.usingColorSpace(.deviceRGB) ?? lo)
}

func systemTintAnnotationPaletteColors() -> [NSColor] {
    let isDark = AppearanceManager.shared.isDark()
    let base = accentStyleTint(from: resolvedAppAccentColor(), isDark: isDark)
    let (hi, lo) = accentDepthTones(from: base, isDark: isDark)
    let soft = blend(base, NSColor.white, t: isDark ? 0.18 : 0.32)
    let deep = blend(base, NSColor.black, t: isDark ? 0.28 : 0.22)
    let muted = blend(base, resolvedSystemColor(.systemGray), t: 0.35)
    return [soft, hi, base, lo, deep, muted]
}

