            kind: .preset,
            colorNames: ["Coffee", "Teal", "Forest", "Plum", "Rose", "Steel"],
            colorsProvider: {
                [
                    paletteColor("#8A5A44"),
                    paletteColor("#4C6E78"),
                    paletteColor("#556B5E"),
                    paletteColor("#6B4B7A"),
                    paletteColor("#7A5C6E"),
                    paletteColor("#5A667A")
                ]
            }
        ),
        AnnotationPaletteDefinition(
            id: "muted-academic",
            name: "Muted Academic",
            kind: .preset,
            colorNames: ["Sage", "Sand", "Clay", "Rust", "Charcoal", "Slate"],
            colorsProvider: {
                [
                    paletteColor("#9AA58C"),
                    paletteColor("#D7C6AE"),
                    paletteColor("#C7B39A"),
                    paletteColor("#B55236"),
                    paletteColor("#5A554E"),
                    paletteColor("#8C8F93")
                ]
            }
