        AnnotationPaletteDefinition(
            id: "vibrant",
            name: "Vibrant",
            kind: .preset,
            colorNames: ["Coral", "Sun", "Green", "Sky", "Indigo", "Magenta"],
            colorsProvider: {
                [
                    paletteColor("#FF6B6B"),
                    paletteColor("#FFB84C"),
                    paletteColor("#4CD964"),
                    paletteColor("#5AC8FA"),
                    paletteColor("#5856D6"),
                    paletteColor("#FF2D55")
                ]
            }
        ),
        AnnotationPaletteDefinition(
            id: "grayscale",
            name: "Grayscale",
            kind: .preset,
            colorNames: ["Snow", "Mist", "Gray", "Stone", "Graphite", "Ink"],
            colorsProvider: {
                [
                    paletteColor("#F2F2F2"),
                    paletteColor("#D9D9D9"),
                    paletteColor("#BFBFBF"),
                    paletteColor("#8F8F8F"),
                    paletteColor("#5F5F5F"),
                    paletteColor("#2F2F2F")
                ]
            }
        )
