    let system = AnnotationPaletteDefinition(
        id: "system-tint",
        name: "System Tint",
        kind: .system,
        colorNames: ["Tint 1", "Tint 2", "Tint 3", "Tint 4", "Tint 5", "Tint 6"],
        colorsProvider: { systemTintAnnotationPaletteColors() }
    )

    let customPalettes: [AnnotationPaletteDefinition] = settings.customPalettes.enumerated().map { index, palette in
        let rawID = palette.id.trimmingCharacters(in: .whitespacesAndNewlines)
        let paletteID = rawID.isEmpty ? customAnnotationPaletteID(index) : rawID
        let colorsHex = normalizedPaletteHexColors(palette.colors, fallback: customAnnotationPaletteDefaultHex)
        let colors = colorsHex.compactMap { colorFromHex($0) }
        let labels = normalizedPaletteLabels(palette.colorLabels, fallback: customAnnotationPaletteDefaultLabels())
        return AnnotationPaletteDefinition(
