            colorNames: labels,
            colorsProvider: { colors.isEmpty ? customAnnotationPaletteDefaultHex.compactMap { colorFromHex($0) } : colors }
        )
    }

    return presets + [system] + customPalettes
}

func annotationPaletteDefinitions() -> [AnnotationPaletteDefinition] {
    annotationPaletteDefinitions(using: AppSettingsStore.shared.current.documentsPDF)
}

func annotationPaletteDefinition(for id: String?, using settings: AppSettings.DocumentsPDF) -> AnnotationPaletteDefinition {
    let palettes = annotationPaletteDefinitions(using: settings)
    let target = (id ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
    if let match = palettes.first(where: { $0.id == target }) {
        return match
    }
    if let fallback = palettes.first(where: { $0.id == annotationPaletteDefaultID }) {
        return fallback
    }
    return palettes.first ?? AnnotationPaletteDefinition(
        id: annotationPaletteDefaultID,
        name: "System Tint",
        kind: .system,
        colorNames: ["Tint 1", "Tint 2", "Tint 3", "Tint 4", "Tint 5", "Tint 6"],
        colorsProvider: { systemTintAnnotationPaletteColors() }
    )
}

func annotationPaletteDefinition(for id: String?) -> AnnotationPaletteDefinition {
    annotationPaletteDefinition(for: id, using: AppSettingsStore.shared.current.documentsPDF)
}

func annotationPaletteColorNames(_ names: [String], count: Int) -> [String] {
    guard count > 0 else { return [] }
    if names.count >= count {
        return Array(names.prefix(count))
    }
    var out = names
    for idx in names.count..<count {
        out.append("Color \(idx + 1)")
    }
    return out
}

func annotationPaletteDisplayName(for def: AnnotationPaletteDefinition, settings: AppSettings.DocumentsPDF) -> String {
    switch def.kind {
    case .custom:
        if let palette = settings.customPalettes.first(where: { $0.id == def.id }) {
            let trimmed = palette.name.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty {
                return trimmed
            }
        }
        if let index = customAnnotationPaletteIndex(for: def.id, in: settings) {
            return customAnnotationPaletteDefaultName(index)
        }
        return def.name
    case .preset, .system:
        let override = settings.annotationPaletteLabels[def.id]?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return override.isEmpty ? def.name : override
    }
}

func paletteColorsMatch(_ a: NSColor, _ b: NSColor) -> Bool {
    guard let ca = a.usingColorSpace(.deviceRGB),
          let cb = b.usingColorSpace(.deviceRGB) else { return false }
    return abs(ca.redComponent - cb.redComponent) < 0.001 &&
           abs(ca.greenComponent - cb.greenComponent) < 0.001 &&
           abs(ca.blueComponent - cb.blueComponent) < 0.001 &&
           abs(ca.alphaComponent - cb.alphaComponent) < 0.001
}

func resolvedAnnotationPaletteColors(id: String,
                                             settings: AppSettings.DocumentsPDF,
                                             overrides: [String: [String]],
                                             allowOverrides: Bool) -> [NSColor] {
    let def = annotationPaletteDefinition(for: id, using: settings)
    var colors = def.colors()
    if colors.count > 6 {
        colors = Array(colors.prefix(6))
    } else if colors.count < 6, let last = colors.last {
        colors.append(contentsOf: Array(repeating: last, count: 6 - colors.count))
    }
    guard allowOverrides, let raw = overrides[def.id], !raw.isEmpty else { return colors }
    let overrideColors = raw.compactMap { colorFromHex($0) }
    for (idx, color) in overrideColors.prefix(6).enumerated() {
        if idx < colors.count {
            colors[idx] = color
        } else {
            colors.append(color)
        }
    }
    if colors.count > 6 {
        colors = Array(colors.prefix(6))
    }
    return colors
}

func resolvedAnnotationPaletteColors(id: String,
                                             overrides: [String: [String]],
                                             allowOverrides: Bool) -> [NSColor] {
    resolvedAnnotationPaletteColors(id: id,
                                    settings: AppSettingsStore.shared.current.documentsPDF,
                                    overrides: overrides,
                                    allowOverrides: allowOverrides)
}
func resolvedAnnotationPalette(using settings: AppSettings.DocumentsPDF) -> (definition: AnnotationPaletteDefinition, colors: [NSColor], colorNames: [String]) {
    let def = annotationPaletteDefinition(for: settings.annotationPaletteID, using: settings)
    let allowOverrides = (def.kind == AnnotationPaletteKind.preset)
    let colors = resolvedAnnotationPaletteColors(id: def.id,
                                                 settings: settings,
                                                 overrides: settings.annotationPaletteOverrides,
                                                 allowOverrides: allowOverrides)
    let names = annotationPaletteColorNames(def.colorNames, count: colors.count)
    return (def, colors, names)
}

func annotationPaletteColors() -> [NSColor] {
    let settings = AppSettingsStore.shared.current.documentsPDF
    return resolvedAnnotationPalette(using: settings).colors
}

func annotationPaletteEntries() -> [AnnotationPaletteEntry] {
    let settings = AppSettingsStore.shared.current.documentsPDF
    let resolved = resolvedAnnotationPalette(using: settings)
    let count = min(resolved.colorNames.count, resolved.colors.count, 6)
    if count == 0 { return [] }
    var entries: [AnnotationPaletteEntry] = []
    for idx in 0..<count {
        entries.append(AnnotationPaletteEntry(name: resolved.colorNames[idx], color: resolved.colors[idx]))
    }
    return entries
}

enum InlineMathSegment {
    case text(String)
    case math(String, display: Bool, centerable: Bool, displayUsesDollar: Bool)
}

struct InlineMathDelimiter {
    let open: String
    let close: String
    let display: Bool
    let centerable: Bool
}

let inlineMathDelimiters: [InlineMathDelimiter] = [
    InlineMathDelimiter(open: "$$", close: "$$", display: true, centerable: true),
    InlineMathDelimiter(open: "\\[", close: "\\]", display: true, centerable: false),
    InlineMathDelimiter(open: "\\(", close: "\\)", display: false, centerable: false),
    InlineMathDelimiter(open: "$", close: "$", display: false, centerable: false)
]

func inlineMathIsEscaped(_ ns: NSString, at location: Int) -> Bool {
    guard location > 0 else { return false }
    var idx = location - 1
    var slashCount = 0
    while idx >= 0, ns.character(at: idx) == 92 { // backslash
        slashCount += 1
        idx -= 1
    }
    return (slashCount % 2) == 1
}

func inlineMathIsStandaloneLine(_ ns: NSString, openRange: NSRange, closeRange: NSRange) -> Bool {
    let beforeRange = NSRange(location: 0, length: openRange.location)
    let lastNewline = ns.range(of: "\n", options: [.backwards], range: beforeRange)
    let lineStart = (lastNewline.location == NSNotFound) ? 0 : (lastNewline.location + 1)
    let prefixRange = NSRange(location: lineStart, length: max(0, openRange.location - lineStart))
    let prefix = ns.substring(with: prefixRange).trimmingCharacters(in: .whitespacesAndNewlines)
    if !prefix.isEmpty { return false }

    let afterStart = closeRange.location + closeRange.length
    if afterStart >= ns.length { return true }
    let afterRange = NSRange(location: afterStart, length: ns.length - afterStart)
    let nextNewline = ns.range(of: "\n", options: [], range: afterRange)
    let lineEnd = (nextNewline.location == NSNotFound) ? ns.length : nextNewline.location
    let suffixRange = NSRange(location: afterStart, length: max(0, lineEnd - afterStart))
    let suffix = ns.substring(with: suffixRange).trimmingCharacters(in: .whitespacesAndNewlines)
    return suffix.isEmpty
}

func parseInlineMathSegments(_ text: String) -> [InlineMathSegment] {
    let ns = text as NSString
    var segments: [InlineMathSegment] = []
    var idx = 0

    func appendText(range: NSRange) {
        guard range.length > 0 else { return }
        let part = ns.substring(with: range)
        segments.append(.text(part))
    }

    func findNextDelimiter(from start: Int) -> (InlineMathDelimiter, NSRange)? {
        var best: (InlineMathDelimiter, NSRange)? = nil
        let searchRange = NSRange(location: start, length: ns.length - start)
        for delim in inlineMathDelimiters {
            var range = ns.range(of: delim.open, options: [], range: searchRange)
            while range.location != NSNotFound {
                if delim.open.hasPrefix("$") && inlineMathIsEscaped(ns, at: range.location) {
                    let nextStart = range.location + range.length
                    if nextStart >= ns.length { break }
                    range = ns.range(of: delim.open, options: [], range: NSRange(location: nextStart, length: ns.length - nextStart))
                    continue
                }
                if let current = best {
                    if range.location < current.1.location ||
                        (range.location == current.1.location && range.length > current.1.length) {
                        best = (delim, range)
                    }
                } else {
                    best = (delim, range)
                }
                break
            }
        }
        return best
    }

    while idx < ns.length {
        guard let (delim, openRange) = findNextDelimiter(from: idx) else {
            appendText(range: NSRange(location: idx, length: ns.length - idx))
            break
        }
        if openRange.location > idx {
            appendText(range: NSRange(location: idx, length: openRange.location - idx))
        }
        let contentStart = openRange.location + openRange.length
        if contentStart >= ns.length {
            appendText(range: NSRange(location: openRange.location, length: ns.length - openRange.location))
            break
        }
        var searchRange = NSRange(location: contentStart, length: ns.length - contentStart)
        var closeRange = ns.range(of: delim.close, options: [], range: searchRange)
        while closeRange.location != NSNotFound {
            if delim.close.hasPrefix("$") && inlineMathIsEscaped(ns, at: closeRange.location) {
                let nextStart = closeRange.location + closeRange.length
                if nextStart >= ns.length { break }
                searchRange = NSRange(location: nextStart, length: ns.length - nextStart)
                closeRange = ns.range(of: delim.close, options: [], range: searchRange)
                continue
            }
            break
        }
        guard closeRange.location != NSNotFound else {
            appendText(range: NSRange(location: openRange.location, length: ns.length - openRange.location))
            break
        }
        let contentRange = NSRange(location: contentStart, length: closeRange.location - contentStart)
        let mathSource = ns.substring(with: contentRange)
        let centerable = delim.centerable && inlineMathIsStandaloneLine(ns, openRange: openRange, closeRange: closeRange)
        let displayUsesDollar = delim.display && delim.open == "$$"
        segments.append(.math(mathSource,
                              display: delim.display,
                              centerable: centerable,
                              displayUsesDollar: displayUsesDollar))
        idx = closeRange.location + closeRange.length
    }
    return segments
}

struct InlineMathParsedSegment {
    let range: NSRange
    let kind: InlineMathSegment
}

func parseInlineMathSegmentsWithRanges(_ text: String) -> [InlineMathParsedSegment] {
    let ns = text as NSString
    var segments: [InlineMathParsedSegment] = []
    var idx = 0

    func appendText(range: NSRange) {
        guard range.length > 0 else { return }
        let part = ns.substring(with: range)
        segments.append(InlineMathParsedSegment(range: range, kind: .text(part)))
    }

    func findNextDelimiter(from start: Int) -> (InlineMathDelimiter, NSRange)? {
        var best: (InlineMathDelimiter, NSRange)? = nil
        let searchRange = NSRange(location: start, length: ns.length - start)
        for delim in inlineMathDelimiters {
            var range = ns.range(of: delim.open, options: [], range: searchRange)
            while range.location != NSNotFound {
                if delim.open.hasPrefix("$") && inlineMathIsEscaped(ns, at: range.location) {
                    let nextStart = range.location + range.length
                    if nextStart >= ns.length { break }
                    range = ns.range(of: delim.open, options: [], range: NSRange(location: nextStart, length: ns.length - nextStart))
                    continue
                }
                if let current = best {
                    if range.location < current.1.location ||
                        (range.location == current.1.location && range.length > current.1.length) {
                        best = (delim, range)
                    }
                } else {
                    best = (delim, range)
                }
                break
            }
        }
        return best
    }

    while idx < ns.length {
        guard let (delim, openRange) = findNextDelimiter(from: idx) else {
            appendText(range: NSRange(location: idx, length: ns.length - idx))
            break
        }
        if openRange.location > idx {
            appendText(range: NSRange(location: idx, length: openRange.location - idx))
        }
        let contentStart = openRange.location + openRange.length
        if contentStart >= ns.length {
            appendText(range: NSRange(location: openRange.location, length: ns.length - openRange.location))
            break
        }
        var searchRange = NSRange(location: contentStart, length: ns.length - contentStart)
        var closeRange = ns.range(of: delim.close, options: [], range: searchRange)
        while closeRange.location != NSNotFound {
            if delim.close.hasPrefix("$") && inlineMathIsEscaped(ns, at: closeRange.location) {
                let nextStart = closeRange.location + closeRange.length
                if nextStart >= ns.length { break }
                searchRange = NSRange(location: nextStart, length: ns.length - nextStart)
                closeRange = ns.range(of: delim.close, options: [], range: searchRange)
                continue
            }
            break
        }
        guard closeRange.location != NSNotFound else {
            appendText(range: NSRange(location: openRange.location, length: ns.length - openRange.location))
            break
        }
        let contentRange = NSRange(location: contentStart, length: closeRange.location - contentStart)
        let mathSource = ns.substring(with: contentRange)
        let centerable = delim.centerable && inlineMathIsStandaloneLine(ns, openRange: openRange, closeRange: closeRange)
        let displayUsesDollar = delim.display && delim.open == "$$"
        let mathRange = NSRange(location: openRange.location,
                                length: closeRange.location + closeRange.length - openRange.location)
        let segment = InlineMathParsedSegment(range: mathRange,
                                              kind: .math(mathSource,
                                                          display: delim.display,
                                                          centerable: centerable,
                                                          displayUsesDollar: displayUsesDollar))
        segments.append(segment)
        idx = closeRange.location + closeRange.length
    }
    return segments
}

let inlineMathBareCommands: Set<String> = [
    "alpha","beta","gamma","delta","epsilon","varepsilon","zeta","eta","theta","vartheta",
    "iota","kappa","lambda","mu","nu","xi","pi","varpi","rho","varrho","sigma","varsigma","tau",
    "upsilon","phi","varphi","chi","psi","omega","ell",
    "Gamma","Delta","Theta","Lambda","Xi","Pi","Sigma","Upsilon","Phi","Psi","Omega","Re","Im",
    "approx","sim","simeq","equiv","neq","ne","leq","geq","le","ge","leqslant","geqslant","propto",
    "subset","subseteq","supset","supseteq","in","notin","ni","forall","exists","neg",
    "land","lor","wedge","vee","perp","parallel","cdot","cdots","ldots","vdots","ddots",
    "times","pm","mp","div","otimes","oplus","ominus","cap","cup","star","ast","circ","bullet",
    "to","rightarrow","Rightarrow","leftarrow","Leftarrow","leftrightarrow","Leftrightarrow","mapsto",
    "frac","dfrac","tfrac","sqrt","root","sum","prod","int","iint","iiint","oint","lim","log","ln","exp","hbar","imath","jmath",
    "sin","cos","tan","cot","sec","csc","sinh","cosh","tanh",
    "overline","underline","bar","hat","tilde","vec","dot","ddot","prime","quad","qquad","cdotp",
    "mathbb","mathbf","mathrm","mathcal","mathscr","mathsf","mathtt","text",
    "begin","end","left","right","over","under","overbrace","underbrace","stackrel","binom","choose","genfrac",
    "langle","rangle","lceil","rceil","lfloor","rfloor","lbrace","rbrace","vert","Vert",
    "infty","partial","nabla"
]

func inlineMathIsAsciiLetter(_ ch: unichar) -> Bool {
    (ch >= 65 && ch <= 90) || (ch >= 97 && ch <= 122)
}

func inlineMathIsAsciiDigit(_ ch: unichar) -> Bool {
    ch >= 48 && ch <= 57
}

func inlineMathIsBareWhitespace(_ ch: unichar) -> Bool {
    ch == 32 || ch == 9
}

func inlineMathIsMathPunct(_ ch: unichar) -> Bool {
    switch ch {
    case 43, 45, 42, 47, 61, 60, 62, 40, 41, 91, 93, 123, 125, 44, 46, 58, 59, 124:
        return true
    default:
        return false
    }
}

let inlineMathFunctionWords: Set<String> = [
    "sin","cos","tan","cot","sec","csc","sinh","cosh","tanh",
    "log","ln","exp","det","dim","mod","gcd","lcm","max","min",
    "sup","inf","arg","ker","deg","lim","limsup","liminf","sgn"
]

let inlineMathStopWords: Set<String> = [
    "a","an","and","are","as","at","be","by","do","for","if","in","is","it",
    "no","not","of","on","or","so","the","to","us","we","you","your","our"
]

func inlineMathIsMathWord(_ word: String) -> Bool {
    guard !word.isEmpty else { return false }
    let lower = word.lowercased()
    if inlineMathStopWords.contains(lower) { return false }
    if inlineMathFunctionWords.contains(lower) { return true }
    if lower == "re" || lower == "im" { return true }
    if word.rangeOfCharacter(from: CharacterSet.decimalDigits) != nil { return true }
    if word.count == 1 { return true }
    if word.count == 2 {
        if word == word.uppercased() { return true }
        return false
    }
    if word.count == 3 {
        if inlineMathFunctionWords.contains(lower) { return true }
        if word == word.uppercased() { return true }
        return false
    }
    if word.count <= 5 && inlineMathFunctionWords.contains(lower) { return true }
    return false
}

func inlineMathIsMathSymbol(_ ch: unichar) -> Bool {
    switch ch {
    case 0x00B1, // plus-minus
         0x00B7, // middle dot
         0x00D7, // times
         0x2190, // left arrow
         0x2192, // right arrow
         0x2194, // left-right arrow
         0x21D0, // left double arrow
         0x21D2, // right double arrow
         0x21D4, // left-right double arrow
         0x2200, // for all
         0x2202, // partial
         0x2203, // exists
         0x2205, // empty set
         0x2207, // nabla
         0x2208, // element of
         0x2209, // not element of
         0x2211, // summation
         0x221A, // square root
         0x221D, // proportional to
         0x221E, // infinity
         0x222B, // integral
         0x223C, // tilde
         0x2248, // approximately equal
         0x2260, // not equal
         0x2264, // less than or equal
         0x2265, // greater than or equal
         0x22C5: // dot operator
        return true
    default:
        if ch >= 0x0370 && ch <= 0x03FF { return true } // Greek and Coptic
        return false
    }
}

func inlineMathBareCommandMatch(in ns: NSString,
                                        at index: Int,
                                        limit: Int,
                                        allowUnknown: Bool) -> (end: Int, command: String, isKnown: Bool)? {
    let start = index + 1
    guard start < limit else { return nil }
    var cursor = start
    while cursor < limit, inlineMathIsAsciiLetter(ns.character(at: cursor)) {
        cursor += 1
    }
    guard cursor > start else { return nil }
    let cmd = ns.substring(with: NSRange(location: start, length: cursor - start))
    if inlineMathBareCommands.contains(cmd) {
        return (cursor, cmd, true)
    }
    guard allowUnknown else { return nil }
    if cmd.count < 2 { return nil }
    let lower = cmd.lowercased()
    if inlineMathStopWords.contains(lower) { return nil }
    if cursor < limit, ns.character(at: cursor) == 92 { return nil }
    return (cursor, cmd, false)
}

func inlineMathBareStartAllowed(_ ns: NSString, index: Int, range: NSRange) -> Bool {
    guard index > range.location else { return true }
    let prev = ns.character(at: index - 1)
    if prev == 58, index >= 2, inlineMathIsAsciiLetter(ns.character(at: index - 2)) { // "C:\"
        return false
    }
    if inlineMathIsAsciiLetter(prev) || inlineMathIsAsciiDigit(prev) {
        return false
    }
    return true
}

func inlineMathTrimWhitespaceRange(in ns: NSString, range: NSRange) -> NSRange {
    var start = range.location
    var end = range.location + range.length
    while start < end, inlineMathIsBareWhitespace(ns.character(at: start)) {
        start += 1
    }
    while end > start, inlineMathIsBareWhitespace(ns.character(at: end - 1)) {
        end -= 1
    }
    return NSRange(location: start, length: max(0, end - start))
}

func inlineMathTrimMathRange(in ns: NSString, range: NSRange) -> NSRange {
    var trimmed = inlineMathTrimWhitespaceRange(in: ns, range: range)
    var start = trimmed.location
    var end = trimmed.location + trimmed.length
    let leadingTrim: Set<unichar> = [58, 59, 44] // : ; ,
    let trailingTrim: Set<unichar> = [46, 44, 59, 58] // . , ; :

    while start < end, leadingTrim.contains(ns.character(at: start)) {
        start += 1
    }

    func countBalance(open: unichar, close: unichar, in range: NSRange) -> (opens: Int, closes: Int) {
        var opens = 0
        var closes = 0
        var idx = range.location
        let limit = range.location + range.length
        while idx < limit {
            let ch = ns.character(at: idx)
            if ch == open { opens += 1 }
            else if ch == close { closes += 1 }
            idx += 1
        }
        return (opens, closes)
    }

    var trimmedRange = NSRange(location: start, length: max(0, end - start))
    var balance = countBalance(open: 40, close: 41, in: trimmedRange) // ()
    while balance.closes > balance.opens, trimmedRange.length > 0 {
        let last = trimmedRange.location + trimmedRange.length - 1
        if ns.character(at: last) == 41 { // )
            trimmedRange.length -= 1
            balance.closes -= 1
        } else {
            break
        }
    }

    balance = countBalance(open: 91, close: 93, in: trimmedRange) // []
    while balance.closes > balance.opens, trimmedRange.length > 0 {
        let last = trimmedRange.location + trimmedRange.length - 1
        if ns.character(at: last) == 93 { // ]
            trimmedRange.length -= 1
            balance.closes -= 1
        } else {
            break
        }
    }

    while trimmedRange.length > 0 {
        let last = trimmedRange.location + trimmedRange.length - 1
        if trailingTrim.contains(ns.character(at: last)) {
            trimmedRange.length -= 1
        } else {
            break
        }
    }

    return inlineMathTrimWhitespaceRange(in: ns, range: trimmedRange)
}

func inlineMathWordRange(in ns: NSString, at index: Int, limit: NSRange) -> NSRange {
    let limitEnd = limit.location + limit.length
    var start = index
    while start > limit.location {
        let ch = ns.character(at: start - 1)
        if inlineMathIsAsciiLetter(ch) || inlineMathIsAsciiDigit(ch) {
            start -= 1
        } else {
            break
        }
    }
    var end = index
    while end < limitEnd {
        let ch = ns.character(at: end)
        if inlineMathIsAsciiLetter(ch) || inlineMathIsAsciiDigit(ch) {
            end += 1
        } else {
            break
        }
    }
    return NSRange(location: start, length: max(0, end - start))
}

func inlineMathSpanScore(in ns: NSString, range: NSRange) -> (math: Int, text: Int) {
    var mathScore = 0
    var textScore = 0
    var idx = range.location
    let limit = range.location + range.length
    while idx < limit {
        let ch = ns.character(at: idx)
        if ch == 92, !inlineMathIsEscaped(ns, at: idx) { // backslash
            if (idx + 1) < limit, ns.character(at: idx + 1) == 92 {
                mathScore += 2
                idx += 2
                continue
            }
            if let match = inlineMathBareCommandMatch(in: ns, at: idx, limit: limit, allowUnknown: true) {
                mathScore += match.isKnown ? 3 : 2
                idx = match.end
                continue
            }
        }
        if ch == 95 || ch == 94 { // _ ^
            mathScore += 2
            idx += 1
            continue
        }
        if inlineMathIsMathSymbol(ch) {
            mathScore += 2
            idx += 1
            continue
        }
        if inlineMathIsMathPunct(ch) {
            mathScore += 1
            idx += 1
            continue
        }
        if inlineMathIsAsciiDigit(ch) {
            mathScore += 1
            idx += 1
            continue
        }
        if inlineMathIsAsciiLetter(ch) {
            let wordRange = inlineMathWordRange(in: ns, at: idx, limit: range)
            let word = ns.substring(with: wordRange)
            if inlineMathIsMathWord(word) {
                mathScore += 1
            } else {
                textScore += 2
            }
            idx = wordRange.location + wordRange.length
            continue
        }
        idx += 1
    }
    return (mathScore, textScore)
}

func inlineMathIsStandaloneLineRange(_ ns: NSString, range: NSRange) -> Bool {
    let lineRange = ns.lineRange(for: range)
    let prefixRange = NSRange(location: lineRange.location, length: max(0, range.location - lineRange.location))
    let suffixStart = range.location + range.length
    let suffixRange = NSRange(location: suffixStart,
                              length: max(0, (lineRange.location + lineRange.length) - suffixStart))
    let prefix = ns.substring(with: prefixRange).trimmingCharacters(in: .whitespacesAndNewlines)
    if !prefix.isEmpty { return false }
    let suffix = ns.substring(with: suffixRange).trimmingCharacters(in: .whitespacesAndNewlines)
    return suffix.isEmpty
}

func inlineMathLineRange(in ns: NSString, index: Int, limit: NSRange) -> NSRange {
    let line = ns.lineRange(for: NSRange(location: index, length: 0))
    return NSIntersectionRange(line, limit)
}

func inlineMathIsMathNeighbor(_ ch: unichar) -> Bool {
    if inlineMathIsAsciiLetter(ch) || inlineMathIsAsciiDigit(ch) { return true }
    if inlineMathIsMathSymbol(ch) { return true }
    if inlineMathIsMathPunct(ch) { return true }
    if ch == 95 || ch == 94 { return true } // _ ^
    return false
}

func inlineMathScanLeft(in ns: NSString, from index: Int, limit: NSRange) -> Int {
    var i = index
    while i > limit.location {
        let ch = ns.character(at: i - 1)
        if ch == 10 { break } // newline
        if inlineMathIsBareWhitespace(ch) {
            i -= 1
            continue
        }
        if ch == 92 {
            if i - 2 >= limit.location, ns.character(at: i - 2) == 92 {
                i -= 2
                continue
            }
            if inlineMathIsEscaped(ns, at: i - 1) { break }
            if !inlineMathBareStartAllowed(ns, index: i - 1, range: limit) { break }
            if let _ = inlineMathBareCommandMatch(in: ns, at: i - 1, limit: limit.location + limit.length, allowUnknown: true) {
                i -= 1
                continue
            }
            break
        }
        if ch == 95 || ch == 94 || inlineMathIsMathPunct(ch) || inlineMathIsMathSymbol(ch) || inlineMathIsAsciiDigit(ch) {
            i -= 1
            continue
        }
        if inlineMathIsAsciiLetter(ch) {
            let wordRange = inlineMathWordRange(in: ns, at: i - 1, limit: limit)
            let word = ns.substring(with: wordRange)
            if inlineMathIsMathWord(word) {
                i = wordRange.location
                continue
            }
        }
        break
    }
    return i
}

func inlineMathScanRight(in ns: NSString, from index: Int, limit: NSRange) -> Int {
    var i = index
    let end = limit.location + limit.length
    while i < end {
        let ch = ns.character(at: i)
        if ch == 10 { break } // newline
        if inlineMathIsBareWhitespace(ch) {
            i += 1
            continue
        }
        if ch == 92 {
            if (i + 1) < end, ns.character(at: i + 1) == 92 {
                i += 2
                continue
            }
            if inlineMathIsEscaped(ns, at: i) { break }
            if let match = inlineMathBareCommandMatch(in: ns, at: i, limit: end, allowUnknown: true) {
                i = match.end
                continue
            }
            break
        }
        if ch == 95 || ch == 94 || inlineMathIsMathPunct(ch) || inlineMathIsMathSymbol(ch) || inlineMathIsAsciiDigit(ch) {
            i += 1
            continue
        }
        if inlineMathIsAsciiLetter(ch) {
            let wordRange = inlineMathWordRange(in: ns, at: i, limit: limit)
            let word = ns.substring(with: wordRange)
            if inlineMathIsMathWord(word) {
                i = wordRange.location + wordRange.length
                continue
            }
        }
        break
    }
    return i
}

func inlineMathBareRange(in ns: NSString, search: NSRange) -> NSRange? {
    let limit = search.location + search.length
    var cursor = search.location

    while cursor < limit {
        let ch = ns.character(at: cursor)

        if ch == 92 { // backslash command
            if inlineMathIsEscaped(ns, at: cursor) {
                cursor += 1
                continue
            }
            guard inlineMathBareStartAllowed(ns, index: cursor, range: search) else {
                cursor += 1
                continue
            }
            if let match = inlineMathBareCommandMatch(in: ns, at: cursor, limit: limit, allowUnknown: true) {
                let lineRange = inlineMathLineRange(in: ns, index: cursor, limit: search)
                let start = inlineMathScanLeft(in: ns, from: cursor, limit: lineRange)
                let end = inlineMathScanRight(in: ns, from: match.end, limit: lineRange)
                let rawRange = NSRange(location: start, length: max(0, end - start))
                let trimmed = inlineMathTrimMathRange(in: ns, range: rawRange)
                if trimmed.length > 0 {
                    let score = inlineMathSpanScore(in: ns, range: trimmed)
                    if score.math >= 3 && score.math >= score.text && inlineMathIsValid(ns.substring(with: trimmed)) {
                        return rawRange
                    }
                }
                cursor = max(cursor + 1, match.end)
                continue
            }
        }

        if ch == 95 || ch == 94 || inlineMathIsMathSymbol(ch) { // _ ^ or unicode math symbol
            let lineRange = inlineMathLineRange(in: ns, index: cursor, limit: search)
            let start = inlineMathScanLeft(in: ns, from: cursor, limit: lineRange)
            let end = inlineMathScanRight(in: ns, from: cursor + 1, limit: lineRange)
            let rawRange = NSRange(location: start, length: max(0, end - start))
            let trimmed = inlineMathTrimMathRange(in: ns, range: rawRange)
            if trimmed.length > 0 {
                let score = inlineMathSpanScore(in: ns, range: trimmed)
                if score.math >= 3 && score.math >= score.text && inlineMathIsValid(ns.substring(with: trimmed)) {
                    return rawRange
                }
            }
            cursor += 1
            continue
        }

        if ch == 61 || ch == 60 || ch == 62 || ch == 43 || ch == 45 || ch == 42 || ch == 47 { // = < > + - * /
            let left = cursor > search.location ? ns.character(at: cursor - 1) : 0
            let right = (cursor + 1) < limit ? ns.character(at: cursor + 1) : 0
            let leftOk = cursor > search.location && inlineMathIsMathNeighbor(left)
            let rightOk = (cursor + 1) < limit && inlineMathIsMathNeighbor(right)
            if leftOk || rightOk {
                let lineRange = inlineMathLineRange(in: ns, index: cursor, limit: search)
                let start = inlineMathScanLeft(in: ns, from: cursor, limit: lineRange)
                let end = inlineMathScanRight(in: ns, from: cursor + 1, limit: lineRange)
                let rawRange = NSRange(location: start, length: max(0, end - start))
                let trimmed = inlineMathTrimMathRange(in: ns, range: rawRange)
                if trimmed.length > 0 {
                    let score = inlineMathSpanScore(in: ns, range: trimmed)
                    if score.math >= 3 && score.math >= score.text && inlineMathIsValid(ns.substring(with: trimmed)) {
                        return rawRange
                    }
                }
            }
        }

        cursor += 1
    }

    return nil
}

func inlineMathBareSegments(in ns: NSString, range: NSRange) -> [InlineMathParsedSegment]? {
    var segments: [InlineMathParsedSegment] = []
    var cursor = range.location
    let end = range.location + range.length
    var found = false

    while cursor < end {
        let searchRange = NSRange(location: cursor, length: end - cursor)
        guard let match = inlineMathBareRange(in: ns, search: searchRange) else { break }

        if match.location > cursor {
            let textRange = NSRange(location: cursor, length: match.location - cursor)
            let text = ns.substring(with: textRange)
            segments.append(InlineMathParsedSegment(range: textRange, kind: .text(text)))
        }

        let trimmed = inlineMathTrimMathRange(in: ns, range: match)
        if trimmed.length == 0 {
            let text = ns.substring(with: match)
            segments.append(InlineMathParsedSegment(range: match, kind: .text(text)))
            cursor = match.location + match.length
            continue
        }

        if trimmed.length > 0 {
            if trimmed.location > match.location {
                let leadingRange = NSRange(location: match.location, length: trimmed.location - match.location)
                let text = ns.substring(with: leadingRange)
                segments.append(InlineMathParsedSegment(range: leadingRange, kind: .text(text)))
            }
            let source = ns.substring(with: trimmed)
            let score = inlineMathSpanScore(in: ns, range: trimmed)
            let standalone = inlineMathIsStandaloneLineRange(ns, range: trimmed)
            let hasDisplayHints = source.contains("\\begin") || source.contains("\\end") || source.contains("\\\\")
            let display = (standalone && score.math >= 3 && score.math >= score.text) || (hasDisplayHints && score.math >= 4)
            let centerable = display && standalone
            segments.append(InlineMathParsedSegment(range: trimmed,
                                                    kind: .math(source,
                                                                display: display,
                                                                centerable: centerable,
                                                                displayUsesDollar: false)))
            found = true
        }

        let trimmedEnd = trimmed.location + trimmed.length
        let matchEnd = match.location + match.length
        if trimmedEnd < matchEnd {
            let tailRange = NSRange(location: trimmedEnd, length: matchEnd - trimmedEnd)
            let text = ns.substring(with: tailRange)
            segments.append(InlineMathParsedSegment(range: tailRange, kind: .text(text)))
        }

        cursor = match.location + match.length
    }

    if cursor < end {
        let textRange = NSRange(location: cursor, length: end - cursor)
        let text = ns.substring(with: textRange)
        segments.append(InlineMathParsedSegment(range: textRange, kind: .text(text)))
    }

    return found ? segments : nil
}

func inlineMathCanonicalWrapped(_ source: String,
                                        display: Bool,
                                        displayUsesDollar: Bool) -> String {
    if display {
        return displayUsesDollar ? "$$\(source)$$" : "\\[\(source)\\]"
    }
    return "\\(\(source)\\)"
}

func inlineMathNormalizeSource(_ source: String) -> String {
    let normalized = source
        .replacingOccurrences(of: "\r\n", with: "\n")
        .replacingOccurrences(of: "\r", with: "\n")
    let trimmed = normalized.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !trimmed.isEmpty else { return "" }

    let delimiterPairs: [(open: String, close: String)] = [
        ("$$", "$$"),
        ("\\[", "\\]"),
        ("\\(", "\\)"),
        ("$", "$")
    ]

    let ns = trimmed as NSString
    for pair in delimiterPairs {
        guard trimmed.hasPrefix(pair.open), trimmed.hasSuffix(pair.close) else { continue }
        let closeLocation = max(0, ns.length - pair.close.count)
        if pair.close.hasPrefix("$"), inlineMathIsEscaped(ns, at: closeLocation) {
            continue
        }
        let innerStart = trimmed.index(trimmed.startIndex, offsetBy: pair.open.count)
        let innerEnd = trimmed.index(trimmed.endIndex, offsetBy: -pair.close.count)
        let inner = trimmed[innerStart..<innerEnd].trimmingCharacters(in: .whitespacesAndNewlines)
        return String(inner)
    }

    return trimmed
}

func inlineMathIsValid(_ source: String) -> Bool {
    let trimmed = inlineMathNormalizeSource(source)
    guard !trimmed.isEmpty else { return false }
    let ns = trimmed as NSString
    var depth = 0
    for idx in 0..<ns.length {
        let ch = ns.character(at: idx)
        if ch == 123 { // "{"
            if inlineMathIsEscaped(ns, at: idx) { continue }
            depth += 1
        } else if ch == 125 { // "}"
            if inlineMathIsEscaped(ns, at: idx) { continue }
            if depth == 0 { return false }
            depth -= 1
        }
    }
    return depth == 0
}

struct InlineMathStyle {
    let font: NSFont
    let textColor: NSColor
    let backgroundColor: NSColor
    let errorBackgroundColor: NSColor
    let errorBorderColor: NSColor
    let cornerRadius: CGFloat
    let padding: NSEdgeInsets
    let baselineFromBottom: CGFloat
    let drawsBackground: Bool
}

let inlineMathDebugEnabled = ProcessInfo.processInfo.environment["ARXIV_INLINE_MATH_DEBUG"] == "1"
let inlineMathBaselineGuideEnabled = ProcessInfo.processInfo.environment["ARXIV_INLINE_MATH_BASELINE"] == "1"
let inlineMathTortureEnabled = ProcessInfo.processInfo.environment["ARXIV_INLINE_MATH_TORTURE"] == "1"
let inlineMathCenterAttribute = NSAttributedString.Key("InlineMathCenter")

func inlineMathLog(_ msg: String) {
    if inlineMathDebugEnabled { print("[INLINE_MATH] \(msg)") }
}

func inlineMathCSSColor(_ color: NSColor) -> String {
    let rgb = color.usingColorSpace(.deviceRGB) ?? color
    let r = Int(round(rgb.redComponent * 255))
    let g = Int(round(rgb.greenComponent * 255))
    let b = Int(round(rgb.blueComponent * 255))
    let a = rgb.alphaComponent
    if a >= 0.995 {
        return String(format: "#%02X%02X%02X", r, g, b)
    }
    return String(format: "rgba(%d,%d,%d,%.3f)", r, g, b, a)
}

func inlineMathCSSFontFamily(_ font: NSFont) -> String {
    let fallback = "-apple-system, BlinkMacSystemFont, \"SF Pro Text\", \"Helvetica Neue\", Helvetica, Arial, sans-serif"
    let family = (font.familyName?.trimmingCharacters(in: .whitespacesAndNewlines))
        ?? font.fontName.trimmingCharacters(in: .whitespacesAndNewlines)
    if family.isEmpty || family.hasPrefix(".") || family.lowercased().contains("system") {
        return fallback
    }
    let sanitized = family.replacingOccurrences(of: "'", with: "\\'")
    return "'\(sanitized)', \(fallback)"
}

private let katexAssetDirectoryLock = NSLock()
private var katexAssetDirectoryCache: URL?
private var katexAssetDirectoryResolved = false

func katexAssetDirectoryURL() -> URL? {
    katexAssetDirectoryLock.lock()
    if katexAssetDirectoryResolved {
        let cached = katexAssetDirectoryCache
        katexAssetDirectoryLock.unlock()
        return cached
    }
    katexAssetDirectoryLock.unlock()

    let env = ProcessInfo.processInfo.environment["ARXIV_KATEX_DIR"] ?? ""
    let root = (ProcessInfo.processInfo.environment["ARXIV_ROOT"] ?? "")
        .trimmingCharacters(in: .whitespacesAndNewlines)
    let fm = FileManager.default
    let cwd = fm.currentDirectoryPath
    var candidates: [URL] = []

    if !env.isEmpty {
        candidates.append(URL(fileURLWithPath: env, isDirectory: false))
    }
    if let bundleURL = Bundle.main.resourceURL {
        candidates.append(bundleURL.appendingPathComponent("katex", isDirectory: true))
    }

    if !root.isEmpty {
        let base = (root as NSString).expandingTildeInPath
        candidates.append(URL(fileURLWithPath: base, isDirectory: true).appendingPathComponent("katex", isDirectory: true))
        candidates.append(URL(fileURLWithPath: base, isDirectory: true).appendingPathComponent("React-Notion-X-API-master/node_modules/katex", isDirectory: true))
        candidates.append(URL(fileURLWithPath: base, isDirectory: true).appendingPathComponent("React-Notion-X-API-master/node_modules/katex/dist", isDirectory: true))
        candidates.append(URL(fileURLWithPath: base, isDirectory: true).appendingPathComponent("React-Notion-X-API-master/packages/react-notion-x/node_modules/katex", isDirectory: true))
        candidates.append(URL(fileURLWithPath: base, isDirectory: true).appendingPathComponent("React-Notion-X-API-master/packages/react-notion-x/node_modules/katex/dist", isDirectory: true))
    }

    candidates.append(URL(fileURLWithPath: "\(cwd)/katex", isDirectory: true))
    candidates.append(URL(fileURLWithPath: "\(cwd)/React-Notion-X-API-master/node_modules/katex", isDirectory: true))
    candidates.append(URL(fileURLWithPath: "\(cwd)/React-Notion-X-API-master/node_modules/katex/dist", isDirectory: true))
    candidates.append(URL(fileURLWithPath: "\(cwd)/React-Notion-X-API-master/packages/react-notion-x/node_modules/katex", isDirectory: true))
    candidates.append(URL(fileURLWithPath: "\(cwd)/React-Notion-X-API-master/packages/react-notion-x/node_modules/katex/dist", isDirectory: true))

    for candidate in candidates {
        var isDir: ObjCBool = false
        if !fm.fileExists(atPath: candidate.path, isDirectory: &isDir) { continue }
        let base = isDir.boolValue ? candidate : candidate.deletingLastPathComponent()
        if let resolved = katexResolveAssetDirectory(base, fm: fm) {
            katexAssetDirectoryLock.lock()
            katexAssetDirectoryCache = resolved
            katexAssetDirectoryResolved = true
            katexAssetDirectoryLock.unlock()
            return resolved
        }
    }
    katexAssetDirectoryLock.lock()
    katexAssetDirectoryCache = nil
    katexAssetDirectoryResolved = true
    katexAssetDirectoryLock.unlock()
    return nil
}

func katexResolveAssetDirectory(_ base: URL, fm: FileManager) -> URL? {
    if katexDirectoryHasAssets(base, fm: fm) { return base }
    let dist = base.appendingPathComponent("dist", isDirectory: true)
    if katexDirectoryHasAssets(dist, fm: fm) { return dist }
    return nil
}

func katexDirectoryHasAssets(_ base: URL, fm: FileManager) -> Bool {
    let js = base.appendingPathComponent("katex.min.js").path
    let css = base.appendingPathComponent("katex.min.css").path
    guard fm.fileExists(atPath: js), fm.fileExists(atPath: css) else { return false }
    if !katexDirectoryHasFonts(base, fm: fm) {
        inlineMathLog("KaTeX fonts not found in \(base.path); symbols may render as boxes.")
    }
    return true
}

func katexDirectoryHasFonts(_ base: URL, fm: FileManager) -> Bool {
    let fonts = base.appendingPathComponent("fonts", isDirectory: true)
    var isDir: ObjCBool = false
    guard fm.fileExists(atPath: fonts.path, isDirectory: &isDir), isDir.boolValue else { return false }
    if let enumerator = fm.enumerator(at: fonts, includingPropertiesForKeys: [.isRegularFileKey], options: [.skipsHiddenFiles]) {
        for case let url as URL in enumerator {
            let ext = url.pathExtension.lowercased()
            if ext == "woff2" || ext == "woff" || ext == "ttf" || ext == "otf" {
                return true
            }
        }
    }
    return false
}

struct KaTeXAssetConfig {
    let baseURL: URL?
    let cssHref: String
    let jsSrc: String
    let isRemote: Bool
}

func katexAssetConfig() -> KaTeXAssetConfig? {
    let env = ProcessInfo.processInfo.environment
    if let cssURL = env["ARXIV_KATEX_CSS_URL"],
       let jsURL = env["ARXIV_KATEX_JS_URL"],
       !cssURL.isEmpty, !jsURL.isEmpty {
        return KaTeXAssetConfig(baseURL: nil, cssHref: cssURL, jsSrc: jsURL, isRemote: true)
    }
    if let cdnBase = env["ARXIV_KATEX_CDN"], !cdnBase.isEmpty {
        let base = cdnBase.hasSuffix("/") ? String(cdnBase.dropLast()) : cdnBase
        return KaTeXAssetConfig(baseURL: nil,
                                cssHref: "\(base)/katex.min.css",
                                jsSrc: "\(base)/katex.min.js",
                                isRemote: true)
    }
    if let local = katexAssetDirectoryURL() {
        return KaTeXAssetConfig(baseURL: local,
                                cssHref: "katex.min.css",
                                jsSrc: "katex.min.js",
                                isRemote: false)
    }
    if env["ARXIV_KATEX_DISABLE_REMOTE"] != "1" {
        let base = "https://cdn.jsdelivr.net/npm/katex@0.16.9/dist"
        return KaTeXAssetConfig(baseURL: nil,
                                cssHref: "\(base)/katex.min.css",
                                jsSrc: "\(base)/katex.min.js",
                                isRemote: true)
    }
    return nil
}

final class KaTeXRenderer: NSObject, WKNavigationDelegate {
    struct RenderResult {
        let image: NSImage?
        let size: CGSize
        let baselineFromBottom: CGFloat
        let visualCenterFromBaseline: CGFloat?
        let isError: Bool
        let errorMessage: String?
    }

    struct RenderRequest {
        let source: String
        let display: Bool
        let fontSize: CGFloat
        let textColor: NSColor
        let fontFamily: String
        let retryCount: Int
        let completion: (RenderResult) -> Void
    }

    private static var sharedInstance: KaTeXRenderer?

    static var shared: KaTeXRenderer {
        if Thread.isMainThread {
            if let existing = sharedInstance { return existing }
            let instance = KaTeXRenderer()
            sharedInstance = instance
            return instance
        }
        var instance: KaTeXRenderer?
        DispatchQueue.main.sync {
            if let existing = sharedInstance {
                instance = existing
            } else {
                let created = KaTeXRenderer()
                sharedInstance = created
                instance = created
            }
        }
        return instance!
    }

    private let webView: WKWebView
    private let assetConfig: KaTeXAssetConfig?
    private var isReady = false
    private var isLoading = false
    private var queue: [RenderRequest] = []
    private var activeRequest: RenderRequest?
    private var didWarm = false
    private var isWarmQueued = false
    private var warmCallbacks: [() -> Void] = []
    private let maxRetryCount = 1
    private let retryDelay: TimeInterval = 0.05

    var isAvailable: Bool { assetConfig != nil }
    var isWarm: Bool { didWarm }

    private func runOnMain(_ block: @escaping () -> Void) {
        if Thread.isMainThread {
            block()
        } else {
            DispatchQueue.main.async(execute: block)
        }
    }

    private static func buildWebView() -> WKWebView {
        let config = WKWebViewConfiguration()
        config.websiteDataStore = .nonPersistent()
        config.setValue(true, forKey: "allowUniversalAccessFromFileURLs")
        let view = WKWebView(frame: NSRect(x: 0, y: 0, width: 1, height: 1), configuration: config)
        view.setValue(false, forKey: "drawsBackground")
        return view
    }

    private static func makeWebView() -> WKWebView {
        if Thread.isMainThread {
            return buildWebView()
        }
        var view: WKWebView!
        DispatchQueue.main.sync {
            view = buildWebView()
        }
        return view
    }

    override init() {
        assetConfig = katexAssetConfig()
        self.webView = Self.makeWebView()
        super.init()
        runOnMain { [weak self] in
            guard let self else { return }
            self.webView.navigationDelegate = self
            self.loadIfPossible()
        }
        if assetConfig == nil {
            inlineMathLog("KaTeX assets not found; falling back to readable renderer.")
        } else if inlineMathDebugEnabled {
            if let base = assetConfig?.baseURL {
                inlineMathLog("KaTeX assets loaded from \(base.path)")
            } else if assetConfig?.isRemote == true {
                inlineMathLog("KaTeX assets loaded from remote URLs.")
            }
        }
        // loadIfPossible scheduled on main in init.
    }

    private func loadIfPossible() {
        if !Thread.isMainThread {
            runOnMain { [weak self] in
                self?.loadIfPossible()
            }
            return
        }
        guard !isLoading, let assetConfig else { return }
        isLoading = true
        let debugFlag = inlineMathDebugEnabled ? "true" : "false"
        let html = """
        <!doctype html>
        <html>
        <head>
          <meta charset="utf-8" />
          <link rel="stylesheet" href="\(assetConfig.cssHref)" />
          <style>
            html, body { margin:0; padding:0; background: transparent; }
            #math { display:inline-block; }
            #baseline-probe { display:inline-block; width:0; height:0; padding:0; margin:0; overflow:hidden; vertical-align: baseline; }
            .katex-mathml { display:none !important; }
          </style>
        </head>
        <body>
          <span id="math"><span id="katex-wrap"></span><span id="baseline-probe"></span></span>
          <script src="\(assetConfig.jsSrc)"></script>
          <script>
            window.__katexDebug = \(debugFlag);
            window.__renderMath = function(src, displayMode, color, fontSize, fontFamily) {
              var el = document.getElementById('math');
              var wrap = document.getElementById('katex-wrap');
              var probe = document.getElementById('baseline-probe');
              el.style.color = color;
              el.style.fontSize = fontSize + 'px';
              if (fontFamily) {
                el.style.fontFamily = fontFamily;
              }
              el.style.lineHeight = '1';
              el.style.whiteSpace = 'nowrap';
              el.style.display = 'inline-block';
              el.style.padding = '0px';
              el.style.margin = '0px';
              el.style.transform = 'none';
              el.style.boxSizing = 'content-box';
              if (wrap) {
                wrap.style.lineHeight = '1';
              }
              if (wrap) { wrap.innerHTML = ''; }
              var error = false;
              var errorMessage = '';
              var katexVersion = '';
              if (window.katex && window.katex.version) {
                katexVersion = window.katex.version;
              }
              try {
                if (!window.katex) {
                  error = true;
                  errorMessage = 'KaTeX not loaded';
                  if (wrap) {
                    wrap.textContent = src;
                  } else {
                    el.textContent = src;
                  }
                } else {
                  katex.render(src, wrap || el, {
                    displayMode: displayMode,
                    throwOnError: false,
                    strict: false,
                    trust: true
                  });
                  if (displayMode) {
                    var displayNode = el.querySelector('.katex-display');
                    if (displayNode) {
                      displayNode.style.display = 'inline-block';
                      displayNode.style.margin = '0';
                      displayNode.style.padding = '0';
                      displayNode.style.width = 'auto';
                      displayNode.style.whiteSpace = 'nowrap';
                    }
                  }
                  var errorNode = el.querySelector('.katex-error');
                  if (errorNode) {
                    error = true;
                    errorMessage = errorNode.textContent || 'KaTeX error';
                  }
                }
              } catch (e) {
                error = true;
                errorMessage = (e && e.message) ? e.message : String(e);
                if (wrap) {
                  wrap.textContent = src;
                } else {
                  el.textContent = src;
                }
              }
              if (probe) {
                probe.style.fontSize = fontSize + 'px';
                probe.style.lineHeight = '1';
                if (fontFamily) {
                  probe.style.fontFamily = fontFamily;
                }
                probe.style.color = 'transparent';
                probe.textContent = '\\u200b';
              }
              function getFontString(style) {
                if (style && style.font && style.font.length > 0) { return style.font; }
                if (!style) { return fontSize + 'px sans-serif'; }
                var parts = [];
                if (style.fontStyle && style.fontStyle !== 'normal') { parts.push(style.fontStyle); }
                if (style.fontVariant && style.fontVariant !== 'normal') { parts.push(style.fontVariant); }
                if (style.fontWeight && style.fontWeight !== 'normal') { parts.push(style.fontWeight); }
                parts.push(style.fontSize || (fontSize + 'px'));
                parts.push(style.fontFamily || 'sans-serif');
                return parts.join(' ');
              }
              function measureFontMetrics(fontString) {
                if (!window.__katexCanvas) {
                  window.__katexCanvas = document.createElement('canvas');
                }
                var ctx = window.__katexCanvas.getContext('2d');
                ctx.font = fontString;
                var metrics = ctx.measureText('Hg');
                return {
                  ascent: metrics.actualBoundingBoxAscent || 0,
                  descent: metrics.actualBoundingBoxDescent || 0
                };
              }
              var visualRoot = el.querySelector('.katex-html') || el;
              var rect = visualRoot.getBoundingClientRect();
              var minTop = rect.top;
              var maxBottom = rect.bottom;
              var minLeft = rect.left;
              var maxRight = rect.right;
              var nodes = visualRoot.querySelectorAll('*');
              for (var i = 0; i < nodes.length; i++) {
                var node = nodes[i];
                if (node.classList && node.classList.contains('katex-mathml')) { continue; }
                var style = window.getComputedStyle(node);
                if (style.display === 'none' || style.visibility === 'hidden' || style.opacity === '0') { continue; }
                var r = node.getBoundingClientRect();
                if (r.top < minTop) { minTop = r.top; }
                if (r.bottom > maxBottom) { maxBottom = r.bottom; }
                if (r.left < minLeft) { minLeft = r.left; }
                if (r.right > maxRight) { maxRight = r.right; }
              }
              var padTop = Math.max(0, rect.top - minTop);
              var padLeft = Math.max(0, rect.left - minLeft);
              var padBottom = Math.max(0, maxBottom - rect.bottom);
              var padRight = Math.max(0, maxRight - rect.right);
              var visualTop = minTop - rect.top;
              var visualBottom = maxBottom - rect.top;
              if (padTop || padLeft || padBottom || padRight) {
                el.style.paddingTop = padTop + 'px';
                el.style.paddingLeft = padLeft + 'px';
                el.style.paddingBottom = padBottom + 'px';
                el.style.paddingRight = padRight + 'px';
                rect = el.getBoundingClientRect();
              }
              visualTop = visualTop + padTop;
              visualBottom = visualBottom + padTop;
              var width = rect.width;
              var height = rect.height;
              if (!isFinite(width) || width <= 0) { width = 1; }
              if (!isFinite(height) || height <= 0) { height = 1; }
              width = Math.ceil(width);
              height = Math.ceil(height);
              var baseline = height;
              if (probe) {
                var probeRect = probe.getBoundingClientRect();
                if (probeRect && isFinite(probeRect.bottom)) {
                  var probeStyle = window.getComputedStyle(probe);
                  var fontString = getFontString(probeStyle);
                  var metrics = measureFontMetrics(fontString);
                  var descent = metrics.descent || 0;
                  var ascent = metrics.ascent || 0;
                  var lineHeightPx = parseFloat(probeStyle.lineHeight);
                  if (!isFinite(lineHeightPx) || lineHeightPx <= 0) {
                    lineHeightPx = fontSize;
                  }
                  var extra = Math.max(0, lineHeightPx - (ascent + descent));
                  var candidate = probeRect.bottom - descent - (extra * 0.5) - rect.top;
                  if (isFinite(candidate)) {
                    baseline = candidate;
                  } else {
                    baseline = probeRect.bottom - rect.top;
                  }
                }
              }
              if (!isFinite(baseline) || baseline <= 0 || baseline > height) {
                var katexRoot = el.querySelector('.katex') || el;
                if (katexRoot) {
                  var rootRect = katexRoot.getBoundingClientRect();
                  var rootStyle = window.getComputedStyle(katexRoot);
                  var valign = rootStyle.verticalAlign || '0px';
                  var rootFontSize = parseFloat(rootStyle.fontSize) || fontSize;
                  var lineHeightPx = parseFloat(rootStyle.lineHeight);
                  if (!isFinite(lineHeightPx) || lineHeightPx <= 0) {
                    lineHeightPx = rootFontSize * 1.2;
                  }
                  var valignPx = 0;
                  if (valign.endsWith('px')) {
                    valignPx = parseFloat(valign) || 0;
                  } else if (valign.endsWith('em')) {
                    valignPx = (parseFloat(valign) || 0) * rootFontSize;
                  } else if (valign.endsWith('%')) {
                    valignPx = (parseFloat(valign) || 0) * 0.01 * lineHeightPx;
                  } else if (valign === 'middle' || valign === 'baseline') {
                    valignPx = 0;
                  }
                  baseline = (rootRect.bottom - rect.top) + valignPx;
                } else {
                  var base = el.querySelector('.katex-html .base');
                  if (base) {
                    var baseRect = base.getBoundingClientRect();
                    baseline = baseRect.bottom - rect.top;
                  }
                }
              }
              if (!isFinite(baseline)) { baseline = height; }
              if (baseline < 0) { baseline = 0; }
              if (baseline > height) { baseline = height; }
              var needsRetry = false;
              if (!window.katex) { needsRetry = true; }
              if (document.fonts && document.fonts.status && document.fonts.status !== 'loaded') {
                needsRetry = true;
              }
              var visualCenterFromBaseline = null;
              if (isFinite(visualTop) && isFinite(visualBottom) && isFinite(baseline)) {
                visualCenterFromBaseline = ((visualTop + visualBottom) * 0.5) - baseline;
              }
              var debug = null;
              if (window.__katexDebug) {
                var snap = function(node) {
                  if (!node) { return null; }
                  var s = window.getComputedStyle(node);
                  return {
                    display: s.display,
                    fontSize: s.fontSize,
                    lineHeight: s.lineHeight,
                    verticalAlign: s.verticalAlign,
                    position: s.position,
                    transform: s.transform,
                    whiteSpace: s.whiteSpace
                  };
                };
                debug = {
                  html: el.outerHTML,
                  el: snap(el),
                  wrap: snap(wrap),
                  katex: snap(el.querySelector('.katex')),
                  katexHtml: snap(el.querySelector('.katex-html')),
                  base: snap(el.querySelector('.katex-html .base')),
                  probe: snap(probe),
                  probeFont: probe ? getFontString(window.getComputedStyle(probe)) : null,
                  probeMetrics: probe ? measureFontMetrics(getFontString(window.getComputedStyle(probe))) : null,
                  probeLineHeight: probe ? window.getComputedStyle(probe).lineHeight : null,
                  visualTop: visualTop,
                  visualBottom: visualBottom,
                  visualCenterFromBaseline: visualCenterFromBaseline,
                  rect: { top: rect.top, bottom: rect.bottom, height: rect.height },
                  probeBottom: probe ? probe.getBoundingClientRect().bottom : null
                };
              }
              return { width: width, height: height, baseline: baseline, visualCenterFromBaseline: visualCenterFromBaseline, error: error, errorMessage: errorMessage, katexVersion: katexVersion, needsRetry: needsRetry, debug: debug };
            };
          </script>
        </body>
        </html>
        """
        webView.loadHTMLString(html, baseURL: assetConfig.baseURL)
    }

    func render(source: String,
                display: Bool,
                fontSize: CGFloat,
                textColor: NSColor,
                fontFamily: String,
                completion: @escaping (RenderResult) -> Void) {
        guard isAvailable else {
            completion(RenderResult(image: nil, size: .zero, baselineFromBottom: 0, visualCenterFromBaseline: nil, isError: false, errorMessage: nil))
            return
        }
        let request = RenderRequest(source: source,
                                    display: display,
                                    fontSize: fontSize,
                                    textColor: textColor,
                                    fontFamily: fontFamily,
                                    retryCount: 0,
                                    completion: completion)
        if Thread.isMainThread {
            enqueue(request)
        } else {
            DispatchQueue.main.async { [weak self] in
                self?.enqueue(request)
            }
        }
    }

    func prewarm(fontSize: CGFloat, textColor: NSColor, fontFamily: String, completion: (() -> Void)? = nil) {
        if !Thread.isMainThread {
            runOnMain { [weak self] in
                self?.prewarm(fontSize: fontSize, textColor: textColor, fontFamily: fontFamily, completion: completion)
            }
            return
        }
        guard isAvailable else {
            completion?()
            return
        }
        if didWarm {
            completion?()
            return
        }
        if let completion {
            warmCallbacks.append(completion)
        }
        guard !isWarmQueued else { return }
        isWarmQueued = true
        let request = RenderRequest(source: "x",
                                    display: false,
                                    fontSize: max(1, fontSize),
                                    textColor: textColor,
                                    fontFamily: fontFamily,
                                    retryCount: 0) { [weak self] _ in
            self?.isWarmQueued = false
        }
        queue.insert(request, at: 0)
        processNext()
    }

    private func enqueue(_ request: RenderRequest) {
        queue.append(request)
        processNext()
    }

    private func processNext() {
        if !Thread.isMainThread {
            runOnMain { [weak self] in
                self?.processNext()
            }
            return
        }
        guard isAvailable else { return }
        guard isReady else { loadIfPossible(); return }
        guard activeRequest == nil, !queue.isEmpty else { return }
        let request = queue.removeFirst()
        activeRequest = request

        let color = inlineMathCSSColor(request.textColor)
        let fontSize = max(1, request.fontSize)
        let jsSource = inlineMathJSONStringLiteral(request.source)
        let displayFlag = request.display ? "true" : "false"
        let sizeLiteral = String(format: "%.3f", fontSize)
        let fontFamilyLiteral = inlineMathJSONStringLiteral(request.fontFamily)
        let probeWidth = max(512, fontSize * 120)
        let probeHeight = max(256, fontSize * 40)
        self.webView.setFrameSize(NSSize(width: probeWidth, height: probeHeight))
        let js = "window.__renderMath(\(jsSource), \(displayFlag), '\(color)', \(sizeLiteral), \(fontFamilyLiteral))"

        webView.evaluateJavaScript(js) { [weak self] result, error in
            guard let self else { return }
            self.runOnMain { [weak self] in
                guard let self, let active = self.activeRequest else { return }
            guard error == nil, let dict = result as? [String: Any] else {
                if inlineMathDebugEnabled, let error {
                    inlineMathLog("KaTeX JS evaluation error: \(error.localizedDescription)")
                }
                self.finish(active, result: RenderResult(image: nil, size: .zero, baselineFromBottom: 0, visualCenterFromBaseline: nil, isError: true, errorMessage: error?.localizedDescription))
                return
            }
            var width = CGFloat(dict["width"] as? Double ?? 0)
            if !width.isFinite || width <= 0 { width = 1 }
            var height = CGFloat(dict["height"] as? Double ?? 0)
            if !height.isFinite || height <= 0 { height = 1 }
            var baselineTop = CGFloat(dict["baseline"] as? Double ?? Double(height))
            if !baselineTop.isFinite { baselineTop = height }
            baselineTop = min(max(0, baselineTop), height)
            let baselineFromBottom = max(0, height - baselineTop)
            let visualCenterFromBaseline = (dict["visualCenterFromBaseline"] as? Double).flatMap { value in
                value.isFinite ? CGFloat(value) : nil
            }
            let isError = (dict["error"] as? Bool) ?? false
            let errorMessage = dict["errorMessage"] as? String
            let needsRetry = (dict["needsRetry"] as? Bool) ?? false
            let tinyRender = width <= 2 || height <= 2
            let shouldRetry = (needsRetry || tinyRender) && request.retryCount < self.maxRetryCount
            if !needsRetry {
                self.markWarm()
            }
            if inlineMathDebugEnabled {
                let katexVersion = dict["katexVersion"] as? String ?? ""
                if isError {
                    inlineMathLog("KaTeX render error: \(errorMessage ?? "unknown")")
                } else if !katexVersion.isEmpty {
                    inlineMathLog("KaTeX version: \(katexVersion)")
                }
                if let debug = dict["debug"] as? [String: Any] {
                    if let html = debug["html"] as? String {
                        let snippet = html.count > 800 ? String(html.prefix(800)) + "…" : html
                        inlineMathLog("KaTeX DOM: \(snippet)")
                    }
                    if let el = debug["el"] as? [String: Any],
                       let display = el["display"] as? String,
                       let fontSize = el["fontSize"] as? String,
                       let lineHeight = el["lineHeight"] as? String {
                        inlineMathLog("KaTeX el display=\(display) fontSize=\(fontSize) lineHeight=\(lineHeight)")
                    }
                    if let katex = debug["katex"] as? [String: Any],
                       let va = katex["verticalAlign"] as? String,
                       let fs = katex["fontSize"] as? String {
                        inlineMathLog("KaTeX .katex fontSize=\(fs) verticalAlign=\(va)")
                    }
                    if let probeBottom = debug["probeBottom"] {
                        inlineMathLog("KaTeX baseline probe bottom=\(probeBottom)")
                    }
                    if let probeFont = debug["probeFont"] {
                        inlineMathLog("KaTeX probe font=\(probeFont)")
                    }
                    if let metrics = debug["probeMetrics"] as? [String: Any] {
                        let asc = metrics["ascent"] ?? "?"
                        let desc = metrics["descent"] ?? "?"
                        inlineMathLog("KaTeX probe metrics ascent=\(asc) descent=\(desc)")
                    }
                    if let probeLineHeight = debug["probeLineHeight"] {
                        inlineMathLog("KaTeX probe lineHeight=\(probeLineHeight)")
                    }
                    if let visualCenter = debug["visualCenterFromBaseline"] {
                        inlineMathLog("KaTeX visual center from baseline=\(visualCenter)")
                    }
                }
            }

            if shouldRetry {
                let retryRequest = RenderRequest(source: request.source,
                                                 display: request.display,
                                                 fontSize: request.fontSize,
                                                 textColor: request.textColor,
                                                 fontFamily: request.fontFamily,
                                                 retryCount: request.retryCount + 1,
                                                 completion: request.completion)
                DispatchQueue.main.asyncAfter(deadline: .now() + self.retryDelay) { [weak self] in
                    self?.queue.insert(retryRequest, at: 0)
                    self?.processNext()
                }
                let res = RenderResult(image: nil,
                                       size: .zero,
                                       baselineFromBottom: 0,
                                       visualCenterFromBaseline: nil,
                                       isError: isError,
                                       errorMessage: errorMessage)
                self.finish(active, result: res)
                return
            }

            self.webView.setFrameSize(NSSize(width: width, height: height))
            let config = WKSnapshotConfiguration()
            config.rect = CGRect(x: 0, y: 0, width: width, height: height)
            self.webView.takeSnapshot(with: config) { image, _ in
                self.runOnMain { [weak self] in
                    guard let self else { return }
                    let res = RenderResult(image: image,
                                           size: NSSize(width: width, height: height),
                                           baselineFromBottom: baselineFromBottom,
                                           visualCenterFromBaseline: visualCenterFromBaseline,
                                           isError: isError,
                                           errorMessage: errorMessage)
                    self.finish(active, result: res)
                }
            }
        }
        }
    }

    private func markWarm() {
        guard !didWarm else { return }
        didWarm = true
        let callbacks = warmCallbacks
        warmCallbacks.removeAll()
        callbacks.forEach { $0() }
    }

    private func finish(_ request: RenderRequest, result: RenderResult) {
        runOnMain { [weak self] in
            guard let self else { return }
            request.completion(result)
            self.activeRequest = nil
            self.processNext()
        }
    }

    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        isReady = true
        isLoading = false
        processNext()
    }

    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        isLoading = false
        isReady = false
    }

    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        isLoading = false
        isReady = false
    }
}

func inlineMathJSONStringLiteral(_ string: String) -> String {
    let data = try? JSONSerialization.data(withJSONObject: [string], options: [])
    let json = data.flatMap { String(data: $0, encoding: .utf8) } ?? "[\"\"]"
    let start = json.index(after: json.startIndex)
    let end = json.index(before: json.endIndex)
    return String(json[start..<end])
}

func inlineMathResolvedFont(baseFont: NSFont, display: Bool) -> NSFont {
    // Use the surrounding text font directly to avoid CoreText private .SFNS lookups
    // that can fall back to Times, which causes size/baseline drift.
    let size = baseFont.pointSize * (display ? 1.02 : 1.0)
    return baseFont.withSize(size)
}

func inlineMathBaselineShift(display: Bool,
                                     font: NSFont,
                                     imageHeight: CGFloat,
                                     imageBaselineFromBottom: CGFloat,
                                     imageCenterFromBaseline: CGFloat?) -> CGFloat {
    guard !display else { return 0 }
    guard imageHeight > 1, imageBaselineFromBottom.isFinite else { return 0 }
    // Align the visual centroid of the math with a more optical text center (favor x-height).
    let xHeight = font.xHeight
    let capHeight = font.capHeight > 0 ? font.capHeight : font.ascender
    let textCenter: CGFloat
    if xHeight > 0 {
        let weight: CGFloat = 0.7
        textCenter = (xHeight * weight + capHeight * (1 - weight)) * 0.5
    } else {
        textCenter = (font.ascender + font.descender) * 0.5
    }
    let mathCenter = imageCenterFromBaseline ?? ((imageHeight * 0.5) - imageBaselineFromBottom)
    var shift = textCenter - mathCenter
    if !shift.isFinite { return 0 }
    let limit = max(1.0, min(4.0, font.pointSize * 0.3))
    return min(limit, max(-limit, shift))
}

func inlineMathStyle(baseFont: NSFont, display: Bool, textColor: NSColor) -> InlineMathStyle {
    let mathFont = inlineMathResolvedFont(baseFont: baseFont, display: display)
    let padding = display
        ? NSEdgeInsets(top: 2, left: 6, bottom: 2, right: 6)
        : NSEdgeInsets(top: 0, left: 4, bottom: 0, right: 4)
    // Baseline position inside the attachment (distance from bottom to baseline).
    let baselineFromBottom = max(0, -mathFont.descender + padding.bottom)
    let bg = textColor.withAlphaComponent(0.06)
    return InlineMathStyle(
        font: mathFont,
        textColor: textColor,
        backgroundColor: bg,
        errorBackgroundColor: NSColor.systemRed.withAlphaComponent(0.12),
        errorBorderColor: NSColor.systemRed.withAlphaComponent(0.75),
        cornerRadius: display ? 5 : 4,
        padding: padding,
        baselineFromBottom: baselineFromBottom,
        drawsBackground: false
    )
}

final class InlineMathAttachmentCell: NSTextAttachmentCell {
    private var rendered: String = ""
    private var isError: Bool = false
    private var style: InlineMathStyle
    private let displayMode: Bool
    private let renderTextColor: NSColor
    private let referenceFont: NSFont
    private var renderedImage: NSImage?
    private var renderedImageSize: NSSize = .zero
    private var renderedImageBaselineFromBottom: CGFloat = 0
    private var renderedImageCenterFromBaseline: CGFloat?
    private var pendingRenderWork: DispatchWorkItem?
    private var renderToken: Int = 0
    private var renderScale: CGFloat = 1
    var onRenderUpdate: (() -> Void)?
    private let renderStabilizeThreshold: CGFloat = 0.5

    private func safeCellSize(width: CGFloat, height: CGFloat) -> NSSize {
        let safeWidth = (width.isFinite && width > 0) ? width : 4
        let safeHeight = (height.isFinite && height > 0) ? height : 4
        return NSSize(width: max(4, safeWidth), height: max(4, safeHeight))
    }

    private func safeBaseline(_ value: CGFloat) -> CGFloat {
        guard value.isFinite else { return 0 }
        return max(0, value)
    }

    init(source: String, style: InlineMathStyle, display: Bool, textColor: NSColor, referenceFont: NSFont) {
        self.style = style
        self.displayMode = display
        self.renderTextColor = textColor
        self.referenceFont = referenceFont
        super.init(textCell: "")
        update(source: source)
    }

    required init(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

    func updateRenderScale(maxWidth: CGFloat, allowScale: Bool) {
        guard allowScale, maxWidth > 1 else {
            renderScale = 1
            return
        }
        let available = max(4, maxWidth - style.padding.left - style.padding.right)
        guard available > 1 else {
            renderScale = 1
            return
        }

        let baseWidth: CGFloat
        if renderedImageSize.width > 0 {
            baseWidth = renderedImageSize.width
        } else {
            let font = style.font
            let attrs: [NSAttributedString.Key: Any] = [.font: font]
            let maxSize = NSSize(width: CGFloat.greatestFiniteMagnitude, height: CGFloat.greatestFiniteMagnitude)
            let rect = (rendered as NSString).boundingRect(with: maxSize,
                                                           options: [.usesLineFragmentOrigin, .usesFontLeading],
                                                           attributes: attrs)
            baseWidth = rect.size.width
        }

        guard baseWidth.isFinite, baseWidth > 0 else {
            renderScale = 1
            return
        }
        if baseWidth > available {
            let ratio = available / baseWidth
            let safeRatio = ratio.isFinite ? ratio : 1
            renderScale = max(0.1, min(1, safeRatio))
        } else {
            renderScale = 1
        }
    }

    private func effectiveFont() -> NSFont {
        if renderScale < 0.999 {
            return style.font.withSize(max(1, style.font.pointSize * renderScale))
        }
        return style.font
    }

    private func effectiveBaselineFromBottom() -> CGFloat {
        let font = effectiveFont()
        return max(0, -font.descender + style.padding.bottom)
    }

    private func referenceAlignmentShift(imageHeight: CGFloat,
                                         imageBaselineFromBottom: CGFloat,
                                         imageCenterFromBaseline: CGFloat?) -> CGFloat {
        inlineMathBaselineShift(display: displayMode,
                                font: referenceFont,
                                imageHeight: imageHeight,
                                imageBaselineFromBottom: imageBaselineFromBottom,
                                imageCenterFromBaseline: imageCenterFromBaseline)
    }

    private func textMetrics() -> (size: NSSize, baselineFromBottom: CGFloat) {
        let font = effectiveFont()
        let attrs: [NSAttributedString.Key: Any] = [.font: font]
        let maxSize = NSSize(width: CGFloat.greatestFiniteMagnitude, height: CGFloat.greatestFiniteMagnitude)
        let rect = (rendered as NSString).boundingRect(with: maxSize,
                                                       options: [.usesLineFragmentOrigin, .usesFontLeading],
                                                       attributes: attrs)
        let size = rect.size
        let baseline = max(0, -font.descender)
        return (size: size, baselineFromBottom: baseline)
    }

    private func baselineShiftForImage() -> CGFloat {
        guard renderedImageSize.height > 0 else { return 0 }
        let scaledHeight = renderedImageSize.height * renderScale
        let scaledBaseline = renderedImageBaselineFromBottom * renderScale
        let scaledCenter = renderedImageCenterFromBaseline.map { $0 * renderScale }
        let shift = referenceAlignmentShift(imageHeight: scaledHeight,
                                            imageBaselineFromBottom: scaledBaseline,
                                            imageCenterFromBaseline: scaledCenter)
        if inlineMathDebugEnabled {
            let fontBaseline = max(0, -referenceFont.descender)
            if let scaledCenter {
                inlineMathLog("inline shift=\(shift) display=\(displayMode) imgH=\(scaledHeight) imgBase=\(scaledBaseline) imgCenter=\(scaledCenter) refAsc=\(referenceFont.ascender) refDesc=\(referenceFont.descender) fontBase=\(fontBaseline)")
            } else {
                inlineMathLog("inline shift=\(shift) display=\(displayMode) imgH=\(scaledHeight) imgBase=\(scaledBaseline) refAsc=\(referenceFont.ascender) refDesc=\(referenceFont.descender) fontBase=\(fontBaseline)")
            }
        }
        return shift
    }

    private func baselineShiftForText() -> CGFloat {
        let metrics = textMetrics()
        let shift = referenceAlignmentShift(imageHeight: metrics.size.height,
                                            imageBaselineFromBottom: metrics.baselineFromBottom,
                                            imageCenterFromBaseline: nil)
        if inlineMathDebugEnabled {
            let fontBaseline = max(0, -referenceFont.descender)
            inlineMathLog("inline shift=\(shift) display=\(displayMode) txtH=\(metrics.size.height) txtBase=\(metrics.baselineFromBottom) refAsc=\(referenceFont.ascender) refDesc=\(referenceFont.descender) fontBase=\(fontBaseline)")
        }
        return shift
    }

    func update(source: String) {
        // Fallback renderer: lightweight LaTeX → readable Unicode (swap to KaTeX when bundled).
        let normalized = inlineMathNormalizeSource(source)
        let cleaned = renderLatexReadable(normalized)
        rendered = cleaned.isEmpty ? normalized : cleaned
        pendingRenderWork?.cancel()
        pendingRenderWork = nil
        renderedImage = nil
        renderedImageSize = .zero
        renderedImageBaselineFromBottom = 0
        renderedImageCenterFromBaseline = nil
        if inlineMathDebugEnabled {
            inlineMathLog("math raw=\(source) normalized=\(normalized)")
        }

        let token = renderToken &+ 1
        renderToken = token

        let trimmed = normalized.trimmingCharacters(in: .whitespacesAndNewlines)
        guard KaTeXRenderer.shared.isAvailable, !trimmed.isEmpty else {
            renderedImage = nil
            renderedImageSize = .zero
            renderedImageBaselineFromBottom = 0
            renderedImageCenterFromBaseline = nil
            isError = !inlineMathIsValid(normalized)
            return
        }
        isError = false

        let scheduleRender: () -> Void = { [weak self] in
            guard let self, self.renderToken == token else { return }
            let work = DispatchWorkItem { [weak self] in
                guard let self, self.renderToken == token else { return }
                KaTeXRenderer.shared.render(source: normalized,
                                            display: displayMode,
                                            fontSize: style.font.pointSize,
                                            textColor: renderTextColor,
                                            fontFamily: inlineMathCSSFontFamily(referenceFont)) { [weak self] result in
                    guard let self, self.renderToken == token else { return }
                    self.renderedImage = result.image
                    let safeWidth = (result.size.width.isFinite && result.size.width > 0) ? result.size.width : 0
                    let safeHeight = (result.size.height.isFinite && result.size.height > 0) ? result.size.height : 0
                    let safeSize = NSSize(width: safeWidth, height: safeHeight)
                    let safeBaseline = (result.baselineFromBottom.isFinite && result.baselineFromBottom >= 0) ? result.baselineFromBottom : 0
                    let safeCenter = result.visualCenterFromBaseline.flatMap { $0.isFinite ? $0 : nil }
                    let sizeDeltaW = abs(safeSize.width - self.renderedImageSize.width)
                    let sizeDeltaH = abs(safeSize.height - self.renderedImageSize.height)
                    let baselineDelta = abs(safeBaseline - self.renderedImageBaselineFromBottom)
                    let shouldUpdateMetrics = self.renderedImageSize.width <= 0
                        || self.renderedImageSize.height <= 0
                        || sizeDeltaW > self.renderStabilizeThreshold
                        || sizeDeltaH > self.renderStabilizeThreshold
                        || baselineDelta > self.renderStabilizeThreshold
                    if shouldUpdateMetrics {
                        self.renderedImageSize = safeSize
                        self.renderedImageBaselineFromBottom = safeBaseline
                        self.renderedImageCenterFromBaseline = safeCenter
                    }
                    self.isError = result.isError
                    if inlineMathDebugEnabled, result.isError, let message = result.errorMessage, !message.isEmpty {
                        inlineMathLog("KaTeX error: \(message)")
                    }
                    DispatchQueue.main.async {
                        self.onRenderUpdate?()
                    }
                }
            }
            self.pendingRenderWork = work
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.03, execute: work)
        }

        // Ensure the KaTeX runtime/font stack is warmed before rendering; early renders could
        // return empty/tiny snapshots and leave list previews stuck on fallback text.
        if KaTeXRenderer.shared.isWarm {
            scheduleRender()
        } else {
            KaTeXRenderer.shared.prewarm(fontSize: style.font.pointSize,
                                         textColor: renderTextColor,
                                         fontFamily: inlineMathCSSFontFamily(referenceFont)) { [weak self] in
                guard let self, self.renderToken == token else { return }
                scheduleRender()
            }
        }
    }

    func updateStyle(_ style: InlineMathStyle) {
        self.style = style
    }

    override func cellSize() -> NSSize {
        if renderedImageSize.width > 0, renderedImageSize.height > 0 {
            let scaledWidth = renderedImageSize.width * renderScale
            let scaledHeight = renderedImageSize.height * renderScale
            let baselineOffset = baselineShiftForImage()
            let width = ceil(scaledWidth) + style.padding.left + style.padding.right
            let height = ceil(scaledHeight) + style.padding.top + style.padding.bottom + abs(baselineOffset)
            return safeCellSize(width: width, height: height)
        } else {
            let font = effectiveFont()
            let attrs: [NSAttributedString.Key: Any] = [.font: font]
            let maxSize = NSSize(width: CGFloat.greatestFiniteMagnitude, height: CGFloat.greatestFiniteMagnitude)
            let rect = (rendered as NSString).boundingRect(with: maxSize,
                                                           options: [.usesLineFragmentOrigin, .usesFontLeading],
                                                           attributes: attrs)
            let size = rect.size
            let width = ceil(size.width) + style.padding.left + style.padding.right
            let height = ceil(size.height) + style.padding.top + style.padding.bottom + abs(baselineShiftForText())
            return safeCellSize(width: width, height: height)
        }
    }

    override func draw(withFrame cellFrame: NSRect, in controlView: NSView?) {
        let frame = cellFrame.integral
        if style.drawsBackground || isError {
            let path = NSBezierPath(roundedRect: frame, xRadius: style.cornerRadius, yRadius: style.cornerRadius)
            let fill = isError ? style.errorBackgroundColor : style.backgroundColor
            fill.setFill()
            path.fill()
            if isError {
                style.errorBorderColor.setStroke()
                path.lineWidth = 1
                path.stroke()
            }
        }
        if let image = renderedImage, renderedImageSize.width > 0, renderedImageSize.height > 0 {
            let scaledBaseline = renderedImageBaselineFromBottom * renderScale
            let baselineOffset = baselineShiftForImage()
            let baselineFromBottom = max(0, scaledBaseline + style.padding.bottom + max(0, -baselineOffset))
            let baselineY = frame.minY + baselineFromBottom
            let imageBaseline = scaledBaseline
            let drawY = baselineY - imageBaseline + baselineOffset
            let drawRect = NSRect(x: frame.minX + style.padding.left,
                                  y: drawY,
                                  width: renderedImageSize.width * renderScale,
                                  height: renderedImageSize.height * renderScale)
            image.draw(in: drawRect)
        } else {
            let baselineOffset = baselineShiftForText()
            let baselineY = frame.minY + effectiveBaselineFromBottom() + max(0, -baselineOffset)
            let drawPoint = NSPoint(x: frame.minX + style.padding.left, y: baselineY + baselineOffset)
            let attrs: [NSAttributedString.Key: Any] = [
                .font: effectiveFont(),
                .foregroundColor: style.textColor
            ]
            (rendered as NSString).draw(at: drawPoint, withAttributes: attrs)
        }
    }

    func baselineFromBottom() -> CGFloat {
        if renderedImageSize.height > 0 {
            let scaledBaseline = renderedImageBaselineFromBottom * renderScale
            let baselineOffset = baselineShiftForImage()
            let value = scaledBaseline + style.padding.bottom + max(0, -baselineOffset)
            return safeBaseline(value)
        }
        let baselineOffset = baselineShiftForText()
        let value = effectiveBaselineFromBottom() + max(0, -baselineOffset)
        return safeBaseline(value)
    }
}

final class InlineMathAttachment: NSTextAttachment {
    let display: Bool
    let displayUsesDollar: Bool
    private(set) var source: String
    private let baseFont: NSFont
    private let textColor: NSColor
    private let style: InlineMathStyle
    private let cellRef: InlineMathAttachmentCell
    private weak var hostTextView: NSTextView?
    private var lastBounds: CGRect = .zero
    private var boundsDidChange = true
    private let boundsStabilizeThreshold: CGFloat = 0.5

    init(source: String,
         display: Bool,
         displayUsesDollar: Bool,
         baseFont: NSFont,
         textColor: NSColor) {
        self.display = display
        self.displayUsesDollar = displayUsesDollar
        let normalized = inlineMathNormalizeSource(source)
        self.source = normalized
        self.baseFont = baseFont
        self.textColor = textColor
        let style = inlineMathStyle(baseFont: baseFont, display: display, textColor: textColor)
        self.style = style
        let cell = InlineMathAttachmentCell(source: normalized,
                                            style: style,
                                            display: display,
                                            textColor: textColor,
                                            referenceFont: baseFont)
        self.cellRef = cell
        super.init(data: nil, ofType: nil)
        attachmentCell = cell
        cell.onRenderUpdate = { [weak self] in
            self?.updateBounds()
            self?.notifyRenderUpdate()
        }
        updateBounds()
    }

    required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

    func updateSource(_ source: String) {
        let normalized = inlineMathNormalizeSource(source)
        self.source = normalized
        cellRef.update(source: normalized)
        updateBounds()
    }

    private func updateBounds() {
        let size = cellRef.cellSize()
        let safeWidth = (size.width.isFinite && size.width > 0) ? size.width : 4
        let safeHeight = (size.height.isFinite && size.height > 0) ? size.height : 4
        let baseline = cellRef.baselineFromBottom()
        let safeBaseline = baseline.isFinite ? baseline : 0
        let newBounds = CGRect(x: 0, y: -safeBaseline, width: safeWidth, height: safeHeight)
        if lastBounds != .zero {
            let dx = abs(newBounds.origin.x - lastBounds.origin.x)
            let dy = abs(newBounds.origin.y - lastBounds.origin.y)
            let dw = abs(newBounds.size.width - lastBounds.size.width)
            let dh = abs(newBounds.size.height - lastBounds.size.height)
            let delta = max(max(dx, dy), max(dw, dh))
            boundsDidChange = delta > boundsStabilizeThreshold
        } else {
            boundsDidChange = true
        }
        if boundsDidChange {
            bounds = newBounds
            lastBounds = newBounds
        }
        if inlineMathDebugEnabled {
            inlineMathLog("size=\(NSStringFromSize(NSSize(width: safeWidth, height: safeHeight))) baseFont=\(baseFont.fontName) \(baseFont.pointSize) asc=\(baseFont.ascender) desc=\(baseFont.descender) xH=\(baseFont.xHeight) mathFont=\(style.font.fontName) \(style.font.pointSize) asc=\(style.font.ascender) desc=\(style.font.descender) xH=\(style.font.xHeight) baseline=\(safeBaseline) boundsY=\(bounds.origin.y)")
        }
    }

    override func attachmentBounds(for textContainer: NSTextContainer?,
                                   proposedLineFragment lineFrag: CGRect,
                                   glyphPosition position: CGPoint,
                                   characterIndex charIndex: Int) -> CGRect {
        var maxWidth = lineFrag.width
        if !maxWidth.isFinite || maxWidth <= 1, let container = textContainer {
            maxWidth = container.containerSize.width
        }
        if !maxWidth.isFinite || maxWidth <= 1 {
            maxWidth = 1
        }
        cellRef.updateRenderScale(maxWidth: maxWidth, allowScale: true)
        let size = cellRef.cellSize()
        let safeWidth = (size.width.isFinite && size.width > 0) ? size.width : 4
        let safeHeight = (size.height.isFinite && size.height > 0) ? size.height : 4
        let baseline = cellRef.baselineFromBottom()
        let safeBaseline = baseline.isFinite ? baseline : 0
        let originY = -safeBaseline
        return CGRect(x: 0, y: originY, width: safeWidth, height: safeHeight)
    }

    func makeVariant(display: Bool, displayUsesDollar: Bool) -> InlineMathAttachment {
        InlineMathAttachment(source: source,
                             display: display,
                             displayUsesDollar: displayUsesDollar,
                             baseFont: baseFont,
                             textColor: textColor)
    }

    func setHost(_ host: NSTextView?) {
        hostTextView = host
    }

    private func notifyRenderUpdate() {
        guard let textView = hostTextView,
              let storage = textView.textStorage else { return }
        guard rectIsFinite(bounds) else { return }
        let full = NSRange(location: 0, length: storage.length)
        storage.enumerateAttribute(.attachment, in: full, options: []) { value, range, stop in
            if let att = value as? InlineMathAttachment, att === self {
                storage.edited(.editedAttributes, range: range, changeInLength: 0)
                if boundsDidChange {
                    textView.layoutManager?.invalidateLayout(forCharacterRange: range, actualCharacterRange: nil)
                }
                textView.layoutManager?.invalidateDisplay(forCharacterRange: range)
                stop.pointee = true
            }
        }
        textView.didChangeText()
    }
}

func inlineMathBaseAttributes(font: NSFont, color: NSColor) -> [NSAttributedString.Key: Any] {
    let style = NSMutableParagraphStyle()
    style.lineBreakMode = .byWordWrapping
    return [
        .font: font,
        .foregroundColor: color,
        .paragraphStyle: style
    ]
}

func applyCenteredMathParagraphs(_ storage: NSMutableAttributedString) {
    let ns = storage.string as NSString
    var idx = 0
    while idx < storage.length {
        let paraRange = ns.paragraphRange(for: NSRange(location: idx, length: 0))
        var hasCenterable = false
        var attachmentCount = 0
        var hasNonWhitespaceText = false

        storage.enumerateAttributes(in: paraRange, options: []) { attrs, range, _ in
            if let _ = attrs[.attachment] as? InlineMathAttachment {
                attachmentCount += 1
                if (attrs[inlineMathCenterAttribute] as? Bool) == true {
                    hasCenterable = true
                }
            } else {
                let chunk = ns.substring(with: range)
                if !chunk.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                    hasNonWhitespaceText = true
                }
            }
        }

        let shouldCenter = !hasNonWhitespaceText && attachmentCount == 1 && hasCenterable
        let currentStyle = (storage.attribute(.paragraphStyle, at: paraRange.location, effectiveRange: nil) as? NSParagraphStyle)
            ?? NSParagraphStyle()
        let style = (currentStyle.mutableCopy() as? NSMutableParagraphStyle) ?? NSMutableParagraphStyle()
        style.lineBreakMode = .byWordWrapping
        if shouldCenter && currentStyle.alignment == .natural {
            style.alignment = .center
        }
        storage.addAttribute(.paragraphStyle, value: style, range: paraRange)

        idx = paraRange.location + paraRange.length
    }
}

func inlineMathAttributedString(from raw: String,
                                        baseFont: NSFont,
                                        textColor: NSColor) -> NSAttributedString {
    let output = NSMutableAttributedString()
    let attrs = inlineMathBaseAttributes(font: baseFont, color: textColor)
    for segment in parseInlineMathSegments(raw) {
        switch segment {
        case .text(let text):
            output.append(NSAttributedString(string: text, attributes: attrs))
        case .math(let source, let display, let centerable, let displayUsesDollar):
            let attachment = InlineMathAttachment(source: source,
                                                  display: display,
                                                  displayUsesDollar: displayUsesDollar,
                                                  baseFont: baseFont,
                                                  textColor: textColor)
            let run = NSMutableAttributedString(attachment: attachment)
            if centerable {
                run.addAttribute(inlineMathCenterAttribute, value: true, range: NSRange(location: 0, length: run.length))
            }
            output.append(run)
        }
    }
    applyCenteredMathParagraphs(output)
    return output
}

func inlineMathAttributedString(from attributed: NSAttributedString,
                                        baseFont: NSFont,
                                        textColor: NSColor,
                                        allowBare: Bool = false) -> NSAttributedString {
    let normalized = normalizedRichText(attributed,
                                        defaultFont: baseFont,
                                        defaultColor: textColor,
                                        storedBase: nil)
    let segments = parseInlineMathSegmentsWithRanges(normalized.string)
    let hasDelimited = segments.contains(where: { if case .math = $0.kind { return true }; return false })
    guard hasDelimited || allowBare else {
        return normalized
    }

    let output = NSMutableAttributedString()
    let ns = normalized.string as NSString
    for segment in segments {
        switch segment.kind {
        case .text:
            if allowBare, let bareSegments = inlineMathBareSegments(in: ns, range: segment.range) {
                for bare in bareSegments {
                    switch bare.kind {
                    case .text:
                        output.append(normalized.attributedSubstring(from: bare.range))
                    case .math(let source, let display, let centerable, let displayUsesDollar):
                        let attrs = normalized.attributes(at: bare.range.location, effectiveRange: nil)
                        let font = (attrs[.font] as? NSFont) ?? baseFont
                        let color = (attrs[.foregroundColor] as? NSColor) ?? textColor
                        let attachment = InlineMathAttachment(source: source,
                                                              display: display,
                                                              displayUsesDollar: displayUsesDollar,
                                                              baseFont: font,
                                                              textColor: color)
                        let run = NSMutableAttributedString(attachment: attachment)
                        if let paragraph = attrs[.paragraphStyle] as? NSParagraphStyle {
                            run.addAttribute(.paragraphStyle, value: paragraph, range: NSRange(location: 0, length: run.length))
                        }
                        if centerable {
                            run.addAttribute(inlineMathCenterAttribute, value: true, range: NSRange(location: 0, length: run.length))
                        }
                        output.append(run)
                    }
                }
            } else {
                output.append(normalized.attributedSubstring(from: segment.range))
            }
        case .math(let source, let display, let centerable, let displayUsesDollar):
            let attrs = normalized.attributes(at: segment.range.location, effectiveRange: nil)
            let font = (attrs[.font] as? NSFont) ?? baseFont
            let color = (attrs[.foregroundColor] as? NSColor) ?? textColor
            let attachment = InlineMathAttachment(source: source,
                                                  display: display,
                                                  displayUsesDollar: displayUsesDollar,
                                                  baseFont: font,
                                                  textColor: color)
            let run = NSMutableAttributedString(attachment: attachment)
            if let paragraph = attrs[.paragraphStyle] as? NSParagraphStyle {
                run.addAttribute(.paragraphStyle, value: paragraph, range: NSRange(location: 0, length: run.length))
            }
            if centerable {
                run.addAttribute(inlineMathCenterAttribute, value: true, range: NSRange(location: 0, length: run.length))
            }
            output.append(run)
        }
    }
    applyCenteredMathParagraphs(output)
    return output
}

func inlineMathRawString(from attributed: NSAttributedString) -> String {
    let fullRange = NSRange(location: 0, length: attributed.length)
    var out = ""
    attributed.enumerateAttributes(in: fullRange, options: []) { attrs, range, _ in
        if let attachment = attrs[.attachment] as? InlineMathAttachment {
            let normalized = inlineMathNormalizeSource(attachment.source)
            out += inlineMathCanonicalWrapped(normalized,
                                             display: attachment.display,
                                             displayUsesDollar: attachment.displayUsesDollar)
        } else {
            out += attributed.attributedSubstring(from: range).string
        }
    }
    return out
}

struct AnnotationCommentContent {
    let plainText: String
    let richTextPayload: String?

    var trimmedPlainText: String {
        plainText.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    var isEmpty: Bool {
        let hasPayload = !(richTextPayload?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true)
        return trimmedPlainText.isEmpty && !hasPayload
    }

    func normalizedForStorage() -> AnnotationCommentContent {
        let trimmedPayload = richTextPayload?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let hasPayload = !trimmedPayload.isEmpty
        if trimmedPlainText.isEmpty && !hasPayload {
            return AnnotationCommentContent(plainText: "", richTextPayload: nil)
        }
        return self
    }
}

struct AnnotationRichTextPayload: Codable {
    let v: Int
    let rtf: String
    let baseFontName: String?
    let baseFontSize: Double?
    let baseColorHex: String?
}

struct AnnotationRichTextDecoded {
    let attributed: NSAttributedString
    let baseFontName: String?
    let baseFontSize: Double?
    let baseColorHex: String?
}

// NOTE: Some variable fonts keep the same PostScript name across weights/styles.
// Comparing only name/size treated bold/italic as "base", causing rich-text payloads
// to be dropped on save (e.g., after Add to Note) and losing formatting. Compare traits too.
func fontMatchesBase(_ font: NSFont, baseFont: NSFont) -> Bool {
    guard abs(font.pointSize - baseFont.pointSize) < 0.1 else { return false }
    guard font.fontName == baseFont.fontName else { return false }
    let fontTraits = font.fontDescriptor.symbolicTraits
    let baseTraits = baseFont.fontDescriptor.symbolicTraits
    if fontTraits != baseTraits {
        return false
    }
    let fontTraitsDict = font.fontDescriptor.object(forKey: .traits) as? [NSFontDescriptor.TraitKey: Any]
    let baseTraitsDict = baseFont.fontDescriptor.object(forKey: .traits) as? [NSFontDescriptor.TraitKey: Any]
    func traitDiff(_ key: NSFontDescriptor.TraitKey, epsilon: Double = 0.01) -> Bool {
        guard let lhs = fontTraitsDict?[key] as? NSNumber,
              let rhs = baseTraitsDict?[key] as? NSNumber else { return false }
        return abs(lhs.doubleValue - rhs.doubleValue) > epsilon
    }
    if traitDiff(.weight) || traitDiff(.slant) || traitDiff(.width) {
        return false
    }
    return true
}

func fontMatchesBase(_ font: NSFont, name: String, size: Double) -> Bool {
    guard let base = NSFont(name: name, size: CGFloat(size)) else {
        return abs(font.pointSize - CGFloat(size)) < 0.1 && font.fontName == name
    }
    return fontMatchesBase(font, baseFont: base)
}

func colorsMatch(_ a: NSColor, _ b: NSColor) -> Bool {
    guard let ca = a.usingColorSpace(.deviceRGB),
          let cb = b.usingColorSpace(.deviceRGB) else { return false }
    return abs(ca.redComponent - cb.redComponent) < 0.001
        && abs(ca.greenComponent - cb.greenComponent) < 0.001
        && abs(ca.blueComponent - cb.blueComponent) < 0.001
        && abs(ca.alphaComponent - cb.alphaComponent) < 0.001
}

func colorsClose(_ a: NSColor, _ b: NSColor, epsilon: CGFloat = 0.004) -> Bool {
    guard let ca = a.usingColorSpace(.deviceRGB),
          let cb = b.usingColorSpace(.deviceRGB) else { return false }
    return abs(ca.redComponent - cb.redComponent) < epsilon
        && abs(ca.greenComponent - cb.greenComponent) < epsilon
        && abs(ca.blueComponent - cb.blueComponent) < epsilon
        && abs(ca.alphaComponent - cb.alphaComponent) < epsilon
}

func decodeAnnotationRichTextPayload(_ payload: String) -> AnnotationRichTextDecoded? {
    let trimmed = payload.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !trimmed.isEmpty,
          let data = trimmed.data(using: .utf8),
          let decoded = try? JSONDecoder().decode(AnnotationRichTextPayload.self, from: data),
          decoded.v == 1,
          let rtfData = Data(base64Encoded: decoded.rtf),
          let attributed = try? NSAttributedString(data: rtfData,
                                                   options: [.documentType: NSAttributedString.DocumentType.rtf],
                                                   documentAttributes: nil) else {
        return nil
    }
    return AnnotationRichTextDecoded(attributed: attributed,
                                     baseFontName: decoded.baseFontName,
                                     baseFontSize: decoded.baseFontSize,
                                     baseColorHex: decoded.baseColorHex)
}

func serializedAnnotationAttributedString(from attributed: NSAttributedString) -> NSAttributedString {
    let output = NSMutableAttributedString()
    let full = NSRange(location: 0, length: attributed.length)
    attributed.enumerateAttributes(in: full, options: []) { attrs, range, _ in
        if let attachment = attrs[.attachment] as? InlineMathAttachment {
            let normalized = inlineMathNormalizeSource(attachment.source)
            let raw = inlineMathCanonicalWrapped(normalized,
                                                 display: attachment.display,
                                                 displayUsesDollar: attachment.displayUsesDollar)
            var cleaned = attrs
            cleaned.removeValue(forKey: .attachment)
            cleaned.removeValue(forKey: inlineMathCenterAttribute)
            output.append(NSAttributedString(string: raw, attributes: cleaned))
            return
        }
        let piece = NSMutableAttributedString(attributedString: attributed.attributedSubstring(from: range))
        piece.removeAttribute(inlineMathCenterAttribute, range: NSRange(location: 0, length: piece.length))
        output.append(piece)
    }
    return output
}

func annotationRichTextPayload(from attributed: NSAttributedString,
                                       baseFont: NSFont,
                                       baseColor: NSColor) -> String? {
    let serialized = serializedAnnotationAttributedString(from: attributed)
    guard serialized.length > 0 else { return nil }
    let defaultColor = annotationDefaultForegroundColor()
    let usesDefaultToken = colorsMatch(baseColor, defaultColor)
    let normalizedForStorage: NSAttributedString = {
        guard usesDefaultToken else { return serialized }
        let output = NSMutableAttributedString(attributedString: serialized)
        let full = NSRange(location: 0, length: output.length)
        var didChange = false
        output.enumerateAttribute(.foregroundColor, in: full, options: []) { value, range, _ in
            if let color = value as? NSColor, colorsMatch(color, baseColor) {
                output.removeAttribute(.foregroundColor, range: range)
                didChange = true
            }
        }
        return didChange ? output : serialized
    }()
    let full = NSRange(location: 0, length: normalizedForStorage.length)
    guard let data = try? normalizedForStorage.data(from: full,
                                                    documentAttributes: [.documentType: NSAttributedString.DocumentType.rtf]) else {
        return nil
    }
    let payload = AnnotationRichTextPayload(v: 1,
                                           rtf: data.base64EncodedString(),
                                           baseFontName: baseFont.fontName,
                                           baseFontSize: Double(baseFont.pointSize),
                                           baseColorHex: usesDefaultToken ? nil : hexFromColor(baseColor, includeAlpha: true))
    guard let encoded = try? JSONEncoder().encode(payload),
          let string = String(data: encoded, encoding: .utf8) else {
        return nil
    }
    return string
}

func attributedStringHasFormatting(_ attributed: NSAttributedString,
                                           baseFont: NSFont,
                                           baseColor: NSColor) -> Bool {
    guard attributed.length > 0 else { return false }
    let full = NSRange(location: 0, length: attributed.length)
    let baseStyle = inlineMathBaseAttributes(font: baseFont, color: baseColor)
    let baseParagraph = baseStyle[.paragraphStyle] as? NSParagraphStyle
    var hasFormatting = false
    attributed.enumerateAttributes(in: full, options: []) { attrs, _, stop in
        if attrs[.attachment] != nil {
            hasFormatting = true
            stop.pointee = true
            return
        }
        if let font = attrs[.font] as? NSFont,
           !fontMatchesBase(font, baseFont: baseFont) {
            hasFormatting = true
            stop.pointee = true
            return
        }
        if let color = attrs[.foregroundColor] as? NSColor, !colorsMatch(color, baseColor) {
            hasFormatting = true
            stop.pointee = true
            return
        }
        if let underline = attrs[.underlineStyle] as? NSNumber, underline.intValue != 0 {
            hasFormatting = true
            stop.pointee = true
            return
        }
        if let strike = attrs[.strikethroughStyle] as? NSNumber, strike.intValue != 0 {
            hasFormatting = true
            stop.pointee = true
            return
        }
        if let oblique = attrs[.obliqueness] as? NSNumber, abs(oblique.doubleValue) > 0.0001 {
            hasFormatting = true
            stop.pointee = true
            return
        }
        if let expansion = attrs[.expansion] as? NSNumber, abs(expansion.doubleValue) > 0.0001 {
            hasFormatting = true
            stop.pointee = true
            return
        }
        if attrs[.backgroundColor] != nil || attrs[.link] != nil || attrs[.baselineOffset] != nil || attrs[.superscript] != nil {
            hasFormatting = true
            stop.pointee = true
            return
        }
        if let style = attrs[.paragraphStyle] as? NSParagraphStyle, let baseParagraph {
            if !style.isEqual(baseParagraph) {
                hasFormatting = true
                stop.pointee = true
                return
            }
        }
    }
    return hasFormatting
}

func normalizedRichText(_ attributed: NSAttributedString,
                                defaultFont: NSFont,
                                defaultColor: NSColor,
                                storedBase: AnnotationRichTextDecoded?) -> NSAttributedString {
    let output = NSMutableAttributedString(attributedString: attributed)
    let storedBaseColor = storedBase?.baseColorHex.flatMap { colorFromHex($0) }
    let storedBaseFontName = storedBase?.baseFontName
    let storedBaseFontSize = storedBase?.baseFontSize
    let full = NSRange(location: 0, length: output.length)
    output.enumerateAttributes(in: full, options: []) { attrs, range, _ in
        var updated = attrs

        let currentFont = attrs[.font] as? NSFont
        if let currentFont {
            if let name = storedBaseFontName,
               let size = storedBaseFontSize,
               fontMatchesBase(currentFont, name: name, size: size) {
                updated[.font] = defaultFont
            }
        } else {
            updated[.font] = defaultFont
        }

        let currentColor = attrs[.foregroundColor] as? NSColor
        if let currentColor {
            if let storedBaseColor, colorsMatch(currentColor, storedBaseColor) {
                updated[.foregroundColor] = defaultColor
            }
        } else {
            updated[.foregroundColor] = defaultColor
        }

        if updated[.paragraphStyle] == nil {
            let style = NSMutableParagraphStyle()
            style.lineBreakMode = .byWordWrapping
            updated[.paragraphStyle] = style
        }

        let updatedDict = NSDictionary(dictionary: updated)
        if !updatedDict.isEqual(to: attrs) {
            output.setAttributes(updated, range: range)
        }
    }
    return output
}

func annotationRichTextAttributedString(from payload: String,
                                                baseFont: NSFont,
                                                textColor: NSColor) -> NSAttributedString? {
    guard let decoded = decodeAnnotationRichTextPayload(payload) else { return nil }
    let normalized = normalizedRichText(decoded.attributed,
                                        defaultFont: baseFont,
                                        defaultColor: textColor,
                                        storedBase: decoded)
    return inlineMathAttributedString(from: normalized, baseFont: baseFont, textColor: textColor)
}

func annotationCommentAttributedString(plainText: String,
                                               payload: String?,
                                               baseFont: NSFont,
                                               textColor: NSColor) -> NSAttributedString {
    if let payload,
       let attributed = annotationRichTextAttributedString(from: payload,
                                                           baseFont: baseFont,
                                                           textColor: textColor) {
        return attributed
    }
    return inlineMathAttributedString(from: plainText, baseFont: baseFont, textColor: textColor)
}

func measuredAttributedTextHeight(_ attributed: NSAttributedString,
                                          width: CGFloat,
                                          minLineHeight: CGFloat) -> CGFloat {
    guard width > 1 else { return minLineHeight }
    let storage = NSTextStorage(attributedString: attributed)
    let container = NSTextContainer(containerSize: NSSize(width: width, height: CGFloat.greatestFiniteMagnitude))
    container.lineFragmentPadding = 0
    let layout = NSLayoutManager()
    layout.addTextContainer(container)
    storage.addLayoutManager(layout)
    layout.glyphRange(for: container)
    let used = layout.usedRect(for: container)
    let usedHeight = used.height
    if !usedHeight.isFinite { return minLineHeight }
    let height = ceil(usedHeight + PDFAnnotationRowMetrics.textMeasureHeightFudge)
    if !height.isFinite { return minLineHeight }
    return max(height, minLineHeight)
}

final class AnnotationTextView: NSTextView {
    var onSubmit: (() -> Void)?
    var onCancel: (() -> Void)?
    var onTextDidChange: (() -> Void)?
    var onSelectionDidChange: (() -> Void)?
    var autoScrollCaret: Bool = false
    var submitOnReturn: Bool = true
    private var pendingFormattingSelection: NSRange?
    private var pendingFormattingDismissalRange: NSRange?
    private static weak var activeFormattingPanelOwner: AnnotationTextView?
    private static var formattingPanelKeyMonitor: Any?
    private var suppressNextAutoIndent: Bool = false
    private var isNormalizingNonListIndentation: Bool = false
    private var inlineMathEditor: InlineMathEditorController?
    private var suppressNextSubmitTimestamp: TimeInterval?
    private weak var pendingDisplayWrapAttachment: InlineMathAttachment?
    private var isDrawingTextView: Bool = false
    private var deferredFrameSize: NSSize?
    private var payloadBaseFont: NSFont?
    private var payloadBaseColor: NSColor?
    private lazy var fallbackUndoManager: UndoManager = UndoManager()

    var isInlineMathPopupVisible: Bool {
        inlineMathEditor?.isVisible ?? false
    }

    override var undoManager: UndoManager? {
        super.undoManager ?? fallbackUndoManager
    }

    deinit {
        detachFormattingPanelsIfNeeded()
    }

    private func registerFormattingPanelOwner() {
        AnnotationTextView.activeFormattingPanelOwner = self
        AnnotationTextView.installFormattingPanelKeyMonitorIfNeeded()
    }

    private func clearFormattingPanelOwnerIfNeeded() {
        if AnnotationTextView.activeFormattingPanelOwner === self {
            AnnotationTextView.activeFormattingPanelOwner = nil
        }
        AnnotationTextView.removeFormattingPanelKeyMonitorIfNeeded(force: false)
    }

    private static func installFormattingPanelKeyMonitorIfNeeded() {
        guard formattingPanelKeyMonitor == nil else { return }
        formattingPanelKeyMonitor = NSEvent.addLocalMonitorForEvents(matching: .keyDown) { event in
            guard let owner = AnnotationTextView.activeFormattingPanelOwner else { return event }
            if !(NSColorPanel.shared.isVisible || NSFontPanel.shared.isVisible) {
                AnnotationTextView.activeFormattingPanelOwner = nil
                AnnotationTextView.removeFormattingPanelKeyMonitorIfNeeded(force: true)
                return event
            }
            if event.keyCode == 36 || event.keyCode == 76 {
                if owner.handleReturnWhileFormattingPanelOpen() {
                    return nil
                }
            }
            return event
        }
    }

    private static func removeFormattingPanelKeyMonitorIfNeeded(force: Bool) {
        if !force && (NSColorPanel.shared.isVisible || NSFontPanel.shared.isVisible) {
            return
        }
        if let monitor = formattingPanelKeyMonitor {
            NSEvent.removeMonitor(monitor)
            formattingPanelKeyMonitor = nil
        }
    }

    private func markFormattingDismissalCandidate(_ range: NSRange) {
        guard range.length > 0 else {
            pendingFormattingDismissalRange = nil
            return
        }
        pendingFormattingDismissalRange = range
    }

    private func clearFormattingDismissalCandidateIfNeeded(for newRange: NSRange) {
        guard let pending = pendingFormattingDismissalRange else { return }
        guard !NSEqualRanges(pending, newRange) else { return }
        if !(NSColorPanel.shared.isVisible || NSFontPanel.shared.isVisible) {
            pendingFormattingDismissalRange = nil
        }
    }

    func setPayloadBase(font: NSFont, color: NSColor, forceFont: Bool = false) {
        if payloadBaseFont == nil || forceFont {
            payloadBaseFont = font
        }
        payloadBaseColor = color
    }

    private func resetUndoHistoryIfUsingFallback() {
        guard super.undoManager == nil else { return }
        fallbackUndoManager.removeAllActions()
    }

    override func viewWillMove(toWindow newWindow: NSWindow?) {
        if newWindow == nil {
            if isInlineMathPopupVisible {
                closeInlineMathPopup(commit: true)
            }
            cleanupFormattingPanels()
        }
        super.viewWillMove(toWindow: newWindow)
    }

    func isInlineMathEvent(_ event: NSEvent) -> Bool {
        inlineMathEditor?.isEventInPopoverWindow(event) ?? false
    }

    func closeInlineMathPopup(commit: Bool) {
        if commit {
            inlineMathEditor?.close(commit: true)
        } else {
            inlineMathEditor?.cancelEditing()
        }
    }

    func suppressNextSubmitOnce(timestamp: TimeInterval) {
        suppressNextSubmitTimestamp = timestamp
    }

    func consumeInlineMathSubmitSuppression(matching event: NSEvent) -> Bool {
        guard let stored = suppressNextSubmitTimestamp else { return false }
        suppressNextSubmitTimestamp = nil
        return abs(stored - event.timestamp) < 0.0001
    }

    override func insertText(_ insertString: Any, replacementRange: NSRange) {
        guard let str = insertString as? String else {
            super.insertText(insertString, replacementRange: replacementRange)
            return
        }
        pendingFormattingDismissalRange = nil
        if str == " " {
            let selection = (replacementRange.location == NSNotFound) ? selectedRange() : replacementRange
            if selection.length == 0, handleAutoListTrigger(at: selection.location) {
                return
            }
        }
        if str == "$" {
            let selection = (replacementRange.location == NSNotFound) ? selectedRange() : replacementRange
            if selection.length == 0,
               let storage = textStorage,
               selection.location > 0 {
                let prevIndex = selection.location - 1
                if storage.attribute(.attachment, at: prevIndex, effectiveRange: nil) == nil {
                    let prevChar = (storage.string as NSString).substring(with: NSRange(location: prevIndex, length: 1))
                    if prevChar == "$" {
                        if handleDoubleDollar(at: prevIndex) {
                            return
                        }
                    }
                }
            }
        }
        super.insertText(insertString, replacementRange: replacementRange)
    }

    func setRawText(_ text: String) {
        let baseFont = payloadBaseFont ?? (font ?? PDFAnnotationRowMetrics.commentFont)
        let color = payloadBaseColor ?? (textColor ?? annotationDefaultForegroundColor())
        let attributed = inlineMathAttributedString(from: text, baseFont: baseFont, textColor: color)
        textStorage?.setAttributedString(attributed)
        normalizeNonListIndentationAcrossStorage()
        typingAttributes = inlineMathBaseAttributes(font: baseFont, color: color)
        assignInlineMathHosts()
        didChangeText()
        resetUndoHistoryIfUsingFallback()
    }

    func setRichText(_ attributed: NSAttributedString) {
        let baseFont = payloadBaseFont ?? (font ?? PDFAnnotationRowMetrics.commentFont)
        let color = payloadBaseColor ?? (textColor ?? annotationDefaultForegroundColor())
        let full = NSRange(location: 0, length: attributed.length)
        var hasAttachment = false
        attributed.enumerateAttribute(.attachment, in: full, options: []) { value, _, stop in
            if value is InlineMathAttachment {
                hasAttachment = true
                stop.pointee = true
            }
        }
        let processed = hasAttachment
            ? attributed
            : inlineMathAttributedString(from: attributed,
                                         baseFont: baseFont,
                                         textColor: color)
        textStorage?.setAttributedString(processed)
        normalizeNonListIndentationAcrossStorage()
        typingAttributes = inlineMathBaseAttributes(font: baseFont, color: color)
        assignInlineMathHosts()
        didChangeText()
        resetUndoHistoryIfUsingFallback()
    }

    func rawText() -> String {
        guard let storage = textStorage else { return string }
        return inlineMathRawString(from: storage)
    }

    func richTextPayload() -> String? {
        guard let storage = textStorage else { return nil }
        let baseFont = payloadBaseFont ?? (font ?? PDFAnnotationRowMetrics.commentFont)
        let baseColor = payloadBaseColor ?? (textColor ?? annotationDefaultForegroundColor())
        if !attributedStringHasFormatting(storage, baseFont: baseFont, baseColor: baseColor) {
            return nil
        }
        return annotationRichTextPayload(from: storage, baseFont: baseFont, baseColor: baseColor)
    }

    override func doCommand(by selector: Selector) {
        if selector == #selector(insertNewline(_:)) {
            if isInlineMathPopupVisible {
                closeInlineMathPopup(commit: true)
                return
            }
            if submitOnReturn {
                if NSEvent.modifierFlags.contains(.shift) {
                    super.doCommand(by: selector) // Insert newline for Shift+Return
                } else {
                    annotationLog("insertNewline command, calling onSubmit")
                    onSubmit?()
                }
            } else {
                if handleListNewline() {
                    return
                }
                let selection = selectedRange()
                let shouldAutoIndent = selection.length == 0 && !suppressNextAutoIndent
                var indentPrefix = ""
                if shouldAutoIndent, let storage = textStorage, storage.length > 0 {
                    let ns = storage.string as NSString
                    let safeLocation = min(max(0, selection.location), max(0, storage.length - 1))
                    let paragraph = ns.paragraphRange(for: NSRange(location: safeLocation, length: 0))
                    indentPrefix = leadingTabPrefix(in: paragraph, storage: storage)
                }
                suppressNextAutoIndent = false
                super.doCommand(by: selector)
                guard shouldAutoIndent, !indentPrefix.isEmpty, let storage = textStorage else { return }
                let insertLocation = min(max(0, selectedRange().location), storage.length)
                let insertRange = NSRange(location: insertLocation, length: 0)
                if shouldChangeText(in: insertRange, replacementString: indentPrefix) {
                    storage.beginEditing()
                    storage.replaceCharacters(in: insertRange, with: indentPrefix)
                    storage.endEditing()
                    setSelectedRange(NSRange(location: insertLocation + indentPrefix.count, length: 0))
                    didChangeText()
                }
            }
            return
        }
        super.doCommand(by: selector)
    }

    override func keyDown(with event: NSEvent) {
        if (event.keyCode == 36 || event.keyCode == 76) && handleReturnWhileFormattingPanelOpen() {
            return
        }
        let mods = event.modifierFlags.intersection([.command, .shift, .control, .option])
        if isEditable,
           mods.contains(.command),
           !mods.contains(.control),
           !mods.contains(.option),
           let key = event.charactersIgnoringModifiers?.lowercased(),
           key == "z" {
            if mods.contains(.shift) {
                undoManager?.redo()
            } else {
                undoManager?.undo()
            }
            return
        }
        if event.keyCode == 48,
           isEditable,
           !event.modifierFlags.contains(.command),
           !event.modifierFlags.contains(.control),
           !event.modifierFlags.contains(.option),
           !event.modifierFlags.contains(.shift) {
            if handleTabIndent() {
                return
            }
        }
        if isEditable,
           event.modifierFlags.contains([.command, .shift]),
           let key = event.charactersIgnoringModifiers?.lowercased(),
           key == "e" {
            triggerInlineMathEditor()
            return
        }
        if isEditable,
           event.modifierFlags.contains(.command),
           event.modifierFlags.contains(.shift) {
            if event.keyCode == 26 {
                applyListFormatting(marker: .decimal, removing: nil)
                return
            }
            if event.keyCode == 28 {
                applyListFormatting(marker: .disc, removing: nil)
                return
            }
        }
        if isEditable,
           event.modifierFlags.contains(.command),
           !event.modifierFlags.contains([.shift, .control, .option]),
           let key = event.charactersIgnoringModifiers?.lowercased() {
            switch key {
            case "b":
                toggleBoldAction(nil)
                return
            case "i":
                toggleItalicsAction(nil)
                return
            case "u":
                toggleUnderlineAction(nil)
                return
            default:
                break
            }
        }
        if (event.keyCode == 36 || event.keyCode == 76),
           isEditable,
           !isInlineMathPopupVisible,
           event.modifierFlags.contains(.shift),
           !event.modifierFlags.contains(.command) {
            if handleListShiftReturn() {
                return
            }
            suppressNextAutoIndent = true
            super.keyDown(with: event)
            return
        }
        if (event.keyCode == 36 || event.keyCode == 76), isInlineMathPopupVisible {
            closeInlineMathPopup(commit: true)
            return
        }
        if event.keyCode == 36 || event.keyCode == 76 { // Return / Enter
            if isInlineMathPopupVisible {
                closeInlineMathPopup(commit: true)
                return
            }
            if submitOnReturn {
                if event.modifierFlags.contains(.shift) {
                    super.keyDown(with: event) // Shift+Return inserts newline
                } else {
                    annotationLog("Return/Enter pressed in textView, calling onSubmit")
                    onSubmit?()
                }
                return
            }
            if event.modifierFlags.contains(.command) {
                annotationLog("Cmd+Return pressed in textView, calling onSubmit")
                onSubmit?()
                return
            }
        }
        if event.keyCode == 53 { // esc
            if isInlineMathPopupVisible {
                closeInlineMathPopup(commit: false)
                return
            }
            annotationLog("Escape pressed in textView, calling onCancel")
            onCancel?()
            return
        }
        super.keyDown(with: event)
    }

    func handleReturnWhileFormattingPanelOpen() -> Bool {
        let panelsVisible = NSColorPanel.shared.isVisible || NSFontPanel.shared.isVisible
        let targetRange = pendingFormattingDismissalRange
            ?? pendingFormattingSelection
            ?? (selectedRange().length > 0 ? selectedRange() : nil)
        guard panelsVisible || targetRange != nil else { return false }
        if let window = window {
            window.makeFirstResponder(self)
        }
        if panelsVisible {
            if NSColorPanel.shared.isVisible {
                NSColorPanel.shared.orderOut(nil)
            }
            if NSFontPanel.shared.isVisible {
                NSFontPanel.shared.orderOut(nil)
            }
            detachFormattingPanelsIfNeeded()
        }
        if let range = targetRange {
            let end = max(0, range.location + range.length)
            setSelectedRange(NSRange(location: min(end, textStorage?.length ?? end), length: 0))
        }
        pendingFormattingSelection = nil
        pendingFormattingDismissalRange = nil
        clearFormattingPanelOwnerIfNeeded()
        return true
    }

    override func menu(for event: NSEvent) -> NSMenu? {
        let menu = NSMenu()
        menu.autoenablesItems = false

        let hasSelection = selectedRange().length > 0
        let canEdit = isEditable && isSelectable
        let canPaste = isEditable && NSPasteboard.general.canReadObject(forClasses: [NSAttributedString.self, NSString.self],
                                                                        options: nil)
        if let undoManager = undoManager {
            let undoItem = menuItem(title: "Undo", action: #selector(menuUndo(_:)), enabled: undoManager.canUndo)
            let redoItem = menuItem(title: "Redo", action: #selector(menuRedo(_:)), enabled: undoManager.canRedo)
            menu.addItem(undoItem)
            menu.addItem(redoItem)
            menu.addItem(.separator())
        }

        menu.addItem(menuItem(title: "Cut", action: #selector(cut(_:)), enabled: canEdit && hasSelection))
        menu.addItem(menuItem(title: "Copy", action: #selector(copy(_:)), enabled: hasSelection))
        menu.addItem(menuItem(title: "Paste", action: #selector(paste(_:)), enabled: canPaste))
        menu.addItem(menuItem(title: "Select All", action: #selector(selectAll(_:)), enabled: true))

        guard canEdit else { return menu }

        menu.addItem(.separator())

        let boldItem = menuItem(title: "Bold", action: #selector(toggleBoldAction(_:)), enabled: true)
        boldItem.state = selectionIsBold() ? NSControl.StateValue.on : NSControl.StateValue.off
        let italicItem = menuItem(title: "Italic", action: #selector(toggleItalicsAction(_:)), enabled: true)
        italicItem.state = selectionIsItalic() ? NSControl.StateValue.on : NSControl.StateValue.off
        let underlineItem = menuItem(title: "Underline", action: #selector(toggleUnderlineAction(_:)), enabled: true)
        underlineItem.state = selectionIsUnderlined() ? NSControl.StateValue.on : NSControl.StateValue.off
        menu.addItem(boldItem)
        menu.addItem(italicItem)
        menu.addItem(underlineItem)

        let alignMenu = NSMenu(title: "Alignment")
        let alignLeftItem = menuItem(title: "Left", action: #selector(menuAlignLeft(_:)), enabled: true)
        let alignCenterItem = menuItem(title: "Center", action: #selector(menuAlignCenter(_:)), enabled: true)
        let alignRightItem = menuItem(title: "Right", action: #selector(menuAlignRight(_:)), enabled: true)
        switch currentAlignment() {
        case .left:
            alignLeftItem.state = .on
        case .center:
            alignCenterItem.state = .on
        case .right:
            alignRightItem.state = .on
        default:
            break
        }
        let alignRoot = NSMenuItem(title: "Alignment", action: nil, keyEquivalent: "")
        alignRoot.submenu = alignMenu
        menu.addItem(alignRoot)

        let listMenu = NSMenu(title: "List")
        let bulletItem = menuItem(title: "Bulleted List", action: #selector(applyBulletList(_:)), enabled: true)
        let numberItem = menuItem(title: "Numbered List", action: #selector(applyNumberedList(_:)), enabled: true)
        listMenu.addItem(bulletItem)
        listMenu.addItem(numberItem)
        if selectionHasList() {
            listMenu.addItem(.separator())
            listMenu.addItem(menuItem(title: "Remove List", action: #selector(removeTextList(_:)), enabled: true))
        }
        let listRoot = NSMenuItem(title: "List", action: nil, keyEquivalent: "")
        listRoot.submenu = listMenu
        menu.addItem(listRoot)

        let sizeMenu = NSMenu(title: "Font Size")
        sizeMenu.addItem(menuItem(title: "Increase", action: #selector(increaseFontSize(_:)), enabled: true))
        sizeMenu.addItem(menuItem(title: "Decrease", action: #selector(decreaseFontSize(_:)), enabled: true))
        let sizeRoot = NSMenuItem(title: "Font Size", action: nil, keyEquivalent: "")
        sizeRoot.submenu = sizeMenu
        menu.addItem(sizeRoot)

        menu.addItem(menuItem(title: "Text Color…", action: #selector(showColorPanel(_:)), enabled: true))
        menu.addItem(menuItem(title: "Font…", action: #selector(showFontPanel(_:)), enabled: true))

        return menu
    }

    @objc private func menuUndo(_ sender: Any?) {
        ensureFirstResponder()
        undoManager?.undo()
    }

    @objc private func menuRedo(_ sender: Any?) {
        ensureFirstResponder()
        undoManager?.redo()
    }

    @objc func toggleBoldAction(_ sender: Any?) {
        ensureFirstResponder()
        toggleFontTrait(.boldFontMask, isActive: selectionIsBold())
    }

    @objc func toggleItalicsAction(_ sender: Any?) {
        ensureFirstResponder()
        toggleFontTrait(.italicFontMask, isActive: selectionIsItalic())
    }

    @objc func toggleUnderlineAction(_ sender: Any?) {
        ensureFirstResponder()
        toggleUnderlineAttribute(isActive: selectionIsUnderlined())
    }

    @objc private func menuAlignLeft(_ sender: Any?) {
        ensureFirstResponder()
        applyParagraphAlignment(.left)
    }

    @objc private func menuAlignCenter(_ sender: Any?) {
        ensureFirstResponder()
        applyParagraphAlignment(.center)
    }

    @objc private func menuAlignRight(_ sender: Any?) {
        ensureFirstResponder()
        applyParagraphAlignment(.right)
    }

    @objc func alignLeftAction(_ sender: Any?) {
        ensureFirstResponder()
        applyParagraphAlignment(.left)
    }

    @objc func alignCenterAction(_ sender: Any?) {
        ensureFirstResponder()
        applyParagraphAlignment(.center)
    }

    @objc func alignRightAction(_ sender: Any?) {
        ensureFirstResponder()
        applyParagraphAlignment(.right)
    }

    @objc func showFontPanel(_ sender: Any?) {
        ensureFirstResponder()
        let sel = selectedRange()
        pendingFormattingSelection = sel.length > 0 ? sel : nil
        let manager = NSFontManager.shared
        manager.target = self
        manager.orderFrontFontPanel(sender)
        registerFormattingPanelOwner()
    }

    @objc func showColorPanel(_ sender: Any?) {
        ensureFirstResponder()
        let sel = selectedRange()
        pendingFormattingSelection = sel.length > 0 ? sel : nil
        let panel = NSColorPanel.shared
        panel.isContinuous = true
        panel.setTarget(self)
        panel.setAction(#selector(changeColor(_:)))
        panel.orderFront(sender)
        registerFormattingPanelOwner()
    }

    func cleanupFormattingPanels() {
        detachFormattingPanelsIfNeeded()
    }

    private func detachFormattingPanelsIfNeeded() {
        let colorPanel = NSColorPanel.shared
        colorPanel.setTarget(nil)
        colorPanel.setAction(nil)
        if colorPanel.isVisible {
            colorPanel.orderOut(nil)
        }
        let fontManager = NSFontManager.shared
        if fontManager.target === self {
            fontManager.target = nil
            if NSFontPanel.shared.isVisible {
                NSFontPanel.shared.orderOut(nil)
            }
        }
        clearFormattingPanelOwnerIfNeeded()
    }

    @objc private func increaseFontSize(_ sender: Any?) {
        adjustFontSize(by: 1)
    }

    @objc private func decreaseFontSize(_ sender: Any?) {
        adjustFontSize(by: -1)
    }

    @objc func applyBulletList(_ sender: Any?) {
        applyListFormatting(marker: .disc,
                            removing: nil,
                            moveCaretAfterMarker: shouldMoveCaretAfterToolbarListToggle())
    }

    @objc func applyNumberedList(_ sender: Any?) {
        applyListFormatting(marker: .decimal,
                            removing: nil,
                            moveCaretAfterMarker: shouldMoveCaretAfterToolbarListToggle())
    }

    private func shouldMoveCaretAfterToolbarListToggle() -> Bool {
        guard let storage = textStorage else { return true }
        let selection = selectedRange()
        guard selection.length == 0 else { return false }
        if storage.length == 0 { return true }
        let safeLocation = min(max(0, selection.location), max(0, storage.length - 1))
        let paragraph = (storage.string as NSString).paragraphRange(for: NSRange(location: safeLocation, length: 0))
        if selection.location == paragraph.location { return true }
        let content = (storage.string as NSString).substring(with: paragraph)
        return content.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    @objc private func removeTextList(_ sender: Any?) {
        removeTextLists()
    }

    override func changeFont(_ sender: Any?) {
        if let pending = pendingFormattingSelection, selectedRange().length == 0 {
            setSelectedRange(pending)
        }
        super.changeFont(sender)
        refreshInlineMathAttachmentStyles(in: selectedRange())
        didChangeText()
        markFormattingDismissalCandidate(selectedRange())
    }

    override func changeColor(_ sender: Any?) {
        if let pending = pendingFormattingSelection, selectedRange().length == 0 {
            setSelectedRange(pending)
        }
        super.changeColor(sender)
        refreshInlineMathAttachmentStyles(in: selectedRange())
        didChangeText()
        markFormattingDismissalCandidate(selectedRange())
    }

    override func mouseDown(with event: NSEvent) {
        super.mouseDown(with: event)
        guard isEditable else { return }
        let point = convert(event.locationInWindow, from: nil)
        if let attachment = inlineMathAttachment(at: point) {
            beginEditingInlineMath(attachment: attachment)
        }
    }

    override func didChangeText() {
        super.didChangeText()
        if autoScrollCaret {
            adjustScrollHeightIfNeeded()
            scrollRangeToVisible(selectedRange())
        }
        onTextDidChange?()
    }

    override func setSelectedRange(_ charRange: NSRange) {
        super.setSelectedRange(charRange)
        if charRange.length > 0 {
            pendingFormattingSelection = charRange
        } else if !(NSColorPanel.shared.isVisible || NSFontPanel.shared.isVisible) {
            pendingFormattingSelection = nil
        }
        clearFormattingDismissalCandidateIfNeeded(for: charRange)
        normalizeNonListIndentationIfNeeded(for: charRange)
        if autoScrollCaret {
            scrollRangeToVisible(selectedRange())
        }
        onSelectionDidChange?()
    }

    private func adjustScrollHeightIfNeeded() {
        guard isVerticallyResizable,
              let layout = layoutManager,
              let container = textContainer else { return }
        layout.ensureLayout(for: container)
        let used = layout.usedRect(for: container)
        let insetHeight = textContainerInset.height * 2
        let minHeight = enclosingScrollView?.contentView.bounds.height ?? 0
        let usedHeight = used.height
        guard usedHeight.isFinite else { return }
        let desiredHeight = max(usedHeight + insetHeight, minHeight)
        guard desiredHeight.isFinite else { return }
        if abs(frame.height - desiredHeight) > 0.5 {
            setFrameSize(NSSize(width: frame.width, height: desiredHeight))
        }
    }

    override func draw(_ dirtyRect: NSRect) {
        PerfLogger.begin("draw.annotation_text_view")
        defer { PerfLogger.end("draw.annotation_text_view") }
        guard rectIsFinite(dirtyRect) else { return }
        isDrawingTextView = true
        defer {
            isDrawingTextView = false
            scheduleDeferredFrameSizeIfNeeded()
        }
        super.draw(dirtyRect)
        guard inlineMathBaselineGuideEnabled,
              let layout = layoutManager,
              let container = textContainer else { return }
        let origin = textContainerOrigin
        let glyphRange = layout.glyphRange(forBoundingRect: dirtyRect, in: container)
        guard glyphRange.length > 0 else { return }
        let guideColor = NSColor.systemRed.withAlphaComponent(0.35)
        guideColor.setStroke()
        layout.enumerateLineFragments(forGlyphRange: glyphRange) { rect, usedRect, _, lineGlyphRange, _ in
            guard lineGlyphRange.length > 0 else { return }
            let glyphIndex = lineGlyphRange.location
            let loc = layout.location(forGlyphAt: glyphIndex)
            let baselineY = rect.minY + loc.y + origin.y
            let start = NSPoint(x: usedRect.minX + origin.x, y: baselineY + 0.5)
            let end = NSPoint(x: usedRect.maxX + origin.x, y: baselineY + 0.5)
            let path = NSBezierPath()
            path.move(to: start)
            path.line(to: end)
            path.lineWidth = 1
            path.stroke()
        }
    }

    override func setFrameSize(_ newSize: NSSize) {
        guard newSize.width.isFinite, newSize.height.isFinite else { return }
        if isDrawingTextView {
            deferredFrameSize = newSize
            scheduleDeferredFrameSizeIfNeeded()
            return
        }
        super.setFrameSize(newSize)
    }

    private func scheduleDeferredFrameSizeIfNeeded() {
        guard let deferred = deferredFrameSize else { return }
        deferredFrameSize = nil
        DispatchQueue.main.async { [weak self] in
            guard let self else { return }
            guard deferred.width.isFinite, deferred.height.isFinite else { return }
            if self.frame.size != deferred {
                self.setFrameSize(deferred)
            }
        }
    }

    private func inlineMathAttachment(at point: NSPoint) -> InlineMathAttachment? {
        guard let layout = layoutManager,
              let container = textContainer,
              let storage = textStorage else { return nil }
        let origin = textContainerOrigin
        let containerPoint = NSPoint(x: point.x - origin.x, y: point.y - origin.y)
        let idx = layout.glyphIndex(for: containerPoint, in: container)
        let charIndex = layout.characterIndexForGlyph(at: idx)
        guard charIndex < storage.length else { return nil }
        if let attachment = storage.attribute(.attachment, at: charIndex, effectiveRange: nil) as? InlineMathAttachment {
            return attachment
        }

        var lineGlyphRange = NSRange(location: NSNotFound, length: 0)
        _ = layout.lineFragmentRect(forGlyphAt: idx, effectiveRange: &lineGlyphRange)
        guard lineGlyphRange.location != NSNotFound, lineGlyphRange.length > 0 else { return nil }
        let lineCharRange = layout.characterRange(forGlyphRange: lineGlyphRange, actualGlyphRange: nil)
        var hit: InlineMathAttachment?
        storage.enumerateAttribute(.attachment, in: lineCharRange, options: []) { value, range, stop in
            guard let att = value as? InlineMathAttachment else { return }
            let glyphRange = layout.glyphRange(forCharacterRange: range, actualCharacterRange: nil)
            var rect = layout.boundingRect(forGlyphRange: glyphRange, in: container)
            rect.origin.x += origin.x
            rect.origin.y += origin.y
            if rect.insetBy(dx: -2, dy: -2).contains(point) {
                hit = att
                stop.pointee = true
            }
        }
        return hit
    }

    private func inlineMathAttachment(atSelection location: Int) -> InlineMathAttachment? {
        guard let storage = textStorage, storage.length > 0 else { return nil }
        let clamped = max(0, min(location, storage.length - 1))
        if let attachment = storage.attribute(.attachment, at: clamped, effectiveRange: nil) as? InlineMathAttachment {
            return attachment
        }
        if location > 0,
           let attachment = storage.attribute(.attachment, at: location - 1, effectiveRange: nil) as? InlineMathAttachment {
            return attachment
        }
        return nil
    }

    private func triggerInlineMathEditor() {
        guard isEditable else { return }
        let selection = selectedRange()
        if let attachment = inlineMathAttachment(atSelection: selection.location) {
            beginEditingInlineMath(attachment: attachment)
            return
        }
        insertInlineMathAttachment(at: selection)
    }

    private func insertInlineMathAttachment(at selection: NSRange) {
        guard let storage = textStorage else { return }
        let baseFont = font ?? PDFAnnotationRowMetrics.commentFont
        let color = textColor ?? annotationDefaultForegroundColor()
        let attachment = InlineMathAttachment(source: "",
                                              display: false,
                                              displayUsesDollar: false,
                                              baseFont: baseFont,
                                              textColor: color)
        attachment.setHost(self)
        if selection.length > 0 {
            storage.deleteCharacters(in: selection)
        }
        let insertLocation = min(selection.location, storage.length)
        storage.insert(NSAttributedString(attachment: attachment), at: insertLocation)
        let newRange = NSRange(location: insertLocation, length: 1)
        setSelectedRange(newRange)
        didChangeText()
        beginEditingInlineMath(attachment: attachment)
    }

    private func beginEditingInlineMath(attachment: InlineMathAttachment) {
        let editor = inlineMathEditor ?? InlineMathEditorController()
        inlineMathEditor = editor
        editor.present(for: attachment, in: self)
    }

    func refreshInlineMathAttachmentStyles(in range: NSRange? = nil) {
        guard let storage = textStorage else { return }
        let target = range ?? NSRange(location: 0, length: storage.length)
        guard target.length > 0 else { return }
        var replacements: [(range: NSRange, attrs: [NSAttributedString.Key: Any], attachment: InlineMathAttachment)] = []
        storage.enumerateAttributes(in: target, options: []) { attrs, range, _ in
            if let attachment = attrs[.attachment] as? InlineMathAttachment {
                replacements.append((range, attrs, attachment))
            }
        }
        guard !replacements.isEmpty else { return }

        storage.beginEditing()
        for item in replacements.reversed() {
            let attrs = item.attrs
            let font = (attrs[.font] as? NSFont) ?? (self.font ?? PDFAnnotationRowMetrics.commentFont)
            let color = (attrs[.foregroundColor] as? NSColor) ?? (self.textColor ?? annotationDefaultForegroundColor())
            let newAttachment = InlineMathAttachment(source: item.attachment.source,
                                                    display: item.attachment.display,
                                                    displayUsesDollar: item.attachment.displayUsesDollar,
                                                    baseFont: font,
                                                    textColor: color)
            newAttachment.setHost(self)
            let run = NSMutableAttributedString(attachment: newAttachment)
            if let paragraph = attrs[.paragraphStyle] as? NSParagraphStyle {
                run.addAttribute(.paragraphStyle, value: paragraph, range: NSRange(location: 0, length: run.length))
            }
            if (attrs[inlineMathCenterAttribute] as? Bool) == true {
                run.addAttribute(inlineMathCenterAttribute, value: true, range: NSRange(location: 0, length: run.length))
            }
            storage.replaceCharacters(in: item.range, with: run)
        }
        storage.endEditing()
    }

    private func handleDoubleDollar(at firstDollarLocation: Int) -> Bool {
        guard let storage = textStorage else { return false }
        let removeRange = NSRange(location: firstDollarLocation, length: 1)
        if removeRange.location + removeRange.length > storage.length { return false }

        storage.beginEditing()
        storage.deleteCharacters(in: removeRange)
        let insertionLocation = firstDollarLocation
        let attachmentRight = (insertionLocation < storage.length)
            ? storage.attribute(.attachment, at: insertionLocation, effectiveRange: nil) as? InlineMathAttachment
            : nil
        let attachmentLeft = (insertionLocation > 0)
            ? storage.attribute(.attachment, at: insertionLocation - 1, effectiveRange: nil) as? InlineMathAttachment
            : nil

        if let right = attachmentRight, pendingDisplayWrapAttachment == nil {
            pendingDisplayWrapAttachment = right
            storage.endEditing()
            setSelectedRange(NSRange(location: insertionLocation, length: 0))
            didChangeText()
            return true
        }

        if let left = attachmentLeft, let pending = pendingDisplayWrapAttachment, left === pending {
            pendingDisplayWrapAttachment = nil
            storage.endEditing()
            convertAttachmentToDisplay(left)
            return true
        }

        if pendingDisplayWrapAttachment != nil, attachmentLeft !== pendingDisplayWrapAttachment {
            pendingDisplayWrapAttachment = nil
        }

        storage.endEditing()
        insertDisplayMathAttachment(at: insertionLocation)
        return true
    }

    private func insertDisplayMathAttachment(at location: Int, source: String = "") {
        guard let storage = textStorage else { return }
        let baseFont = font ?? PDFAnnotationRowMetrics.commentFont
        let color = textColor ?? annotationDefaultForegroundColor()
        let attachment = InlineMathAttachment(source: source,
                                              display: true,
                                              displayUsesDollar: true,
                                              baseFont: baseFont,
                                              textColor: color)
        attachment.setHost(self)
        storage.beginEditing()
        let insertLocation = min(location, storage.length)
        storage.insert(NSAttributedString(attachment: attachment), at: insertLocation)
        let range = NSRange(location: insertLocation, length: 1)
        storage.addAttribute(inlineMathCenterAttribute, value: true, range: range)
        storage.endEditing()
        let finalRange = ensureAttachmentOnOwnLineIfNeeded(attachment, range: range)
        applyCenteredMathParagraphs(storage)
        setSelectedRange(finalRange)
        didChangeText()
        beginEditingInlineMath(attachment: attachment)
    }

    private func convertAttachmentToDisplay(_ attachment: InlineMathAttachment) {
        guard let storage = textStorage,
              let range = attachmentRange(attachment, in: storage) else { return }
        let displayAttachment = attachment.makeVariant(display: true, displayUsesDollar: true)
        displayAttachment.setHost(self)
        storage.beginEditing()
        storage.replaceCharacters(in: range, with: NSAttributedString(attachment: displayAttachment))
        let newRange = NSRange(location: range.location, length: 1)
        storage.addAttribute(inlineMathCenterAttribute, value: true, range: newRange)
        storage.endEditing()
        let finalRange = ensureAttachmentOnOwnLineIfNeeded(displayAttachment, range: newRange)
        applyCenteredMathParagraphs(storage)
        setSelectedRange(finalRange)
        didChangeText()
        beginEditingInlineMath(attachment: displayAttachment)
    }

    private func attachmentRange(_ attachment: InlineMathAttachment,
                                 in storage: NSTextStorage) -> NSRange? {
        let full = NSRange(location: 0, length: storage.length)
        var target: NSRange?
        storage.enumerateAttribute(.attachment, in: full, options: []) { value, range, stop in
            if let att = value as? InlineMathAttachment, att === attachment {
                target = range
                stop.pointee = true
            }
        }
        return target
    }

    private func ensureAttachmentOnOwnLineIfNeeded(_ attachment: InlineMathAttachment,
                                                   range: NSRange) -> NSRange {
        guard let storage = textStorage else { return range }
        let ns = storage.string as NSString
        let paragraphRange = ns.paragraphRange(for: NSRange(location: range.location, length: 0))
        var hasNonWhitespace = false
        var attachmentCount = 0
        var hasTarget = false

        storage.enumerateAttributes(in: paragraphRange, options: []) { attrs, subrange, _ in
            if let att = attrs[.attachment] as? InlineMathAttachment {
                attachmentCount += 1
                if att === attachment {
                    hasTarget = true
                } else {
                    hasNonWhitespace = true
                }
            } else {
                let chunk = ns.substring(with: subrange)
                if !chunk.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                    hasNonWhitespace = true
                }
            }
        }

        if hasTarget && attachmentCount == 1 && !hasNonWhitespace {
            return range
        }

        let originalRange = range
        storage.beginEditing()
        storage.deleteCharacters(in: originalRange)
        let updatedString = storage.string as NSString
        let updatedParagraph = updatedString.paragraphRange(for: NSRange(location: min(originalRange.location, storage.length), length: 0))
        var insertIndex = updatedParagraph.location + updatedParagraph.length
        if insertIndex > 0 {
            let prevChar = updatedString.character(at: insertIndex - 1)
            if prevChar != 10 {
                storage.insert(NSAttributedString(string: "\n"), at: insertIndex)
                insertIndex += 1
            }
        } else {
            storage.insert(NSAttributedString(string: "\n"), at: insertIndex)
            insertIndex += 1
        }

        let newRange = NSRange(location: insertIndex, length: 1)
        storage.insert(NSAttributedString(attachment: attachment), at: insertIndex)
        storage.addAttribute(inlineMathCenterAttribute, value: true, range: newRange)

        let afterIndex = insertIndex + 1
        let afterString = storage.string as NSString
        if afterIndex >= storage.length || afterString.character(at: afterIndex) != 10 {
            storage.insert(NSAttributedString(string: "\n"), at: afterIndex)
        }
        storage.endEditing()
        return newRange
    }

    private func assignInlineMathHosts() {
        guard let storage = textStorage else { return }
        let full = NSRange(location: 0, length: storage.length)
        storage.enumerateAttribute(.attachment, in: full, options: []) { value, _, _ in
            if let attachment = value as? InlineMathAttachment {
                attachment.setHost(self)
            }
        }
    }

    func refreshInlineMathHosts() {
        assignInlineMathHosts()
    }

    func updateTypingAttributes(font: NSFont, color: NSColor) {
        var attrs = typingAttributes
        attrs[.font] = font
        attrs[.foregroundColor] = color
        if attrs[.paragraphStyle] == nil {
            attrs[.paragraphStyle] = inlineMathBaseAttributes(font: font, color: color)[.paragraphStyle]
        }
        typingAttributes = attrs
    }

    private func menuItem(title: String, action: Selector?, enabled: Bool) -> NSMenuItem {
        let item = NSMenuItem(title: title, action: action, keyEquivalent: "")
        item.target = self
        item.isEnabled = enabled
        return item
    }

    private func selectionFont() -> NSFont? {
        guard let storage = textStorage, storage.length > 0 else { return font }
        let sel = selectedRange()
        let index = max(0, min(sel.location, storage.length - 1))
        return storage.attribute(.font, at: index, effectiveRange: nil) as? NSFont ?? font
    }

    private func selectionIsBold() -> Bool {
        guard let font = selectionFont() else { return false }
        return NSFontManager.shared.traits(of: font).contains(.boldFontMask)
    }

    private func selectionIsItalic() -> Bool {
        guard let font = selectionFont() else { return false }
        return NSFontManager.shared.traits(of: font).contains(.italicFontMask)
    }

    private func selectionIsUnderlined() -> Bool {
        guard let storage = textStorage, storage.length > 0 else { return false }
        let sel = selectedRange()
        let index = max(0, min(sel.location, storage.length - 1))
        let style = storage.attribute(.underlineStyle, at: index, effectiveRange: nil) as? Int ?? 0
        return style != 0
    }

    private func currentParagraphStyle() -> NSParagraphStyle? {
        guard let storage = textStorage, storage.length > 0 else { return nil }
        let sel = selectedRange()
        let index = max(0, min(sel.location, storage.length - 1))
        return storage.attribute(.paragraphStyle, at: index, effectiveRange: nil) as? NSParagraphStyle
    }

    private func currentAlignment() -> NSTextAlignment {
        currentParagraphStyle()?.alignment ?? .natural
    }

    private func selectionHasList() -> Bool {
        guard let storage = textStorage, storage.length > 0 else { return false }
        let paragraph = selectionParagraphRange()
        return listMarkerInfo(in: paragraph, storage: storage) != nil
            || !(currentParagraphStyle()?.textLists.isEmpty ?? true)
    }

    func toolbarIsBold() -> Bool { selectionIsBold() }
    func toolbarIsItalic() -> Bool { selectionIsItalic() }
    func toolbarIsUnderlined() -> Bool { selectionIsUnderlined() }

    func toolbarAlignment() -> NSTextAlignment { currentAlignment() }

    func toolbarListMarker() -> NSTextList.MarkerFormat? {
        guard let storage = textStorage, storage.length > 0 else {
            return currentParagraphStyle()?.textLists.first?.markerFormat
        }
        let paragraph = selectionParagraphRange()
        if let info = listMarkerInfo(in: paragraph, storage: storage) {
            return info.marker
        }
        return currentParagraphStyle()?.textLists.first?.markerFormat
    }

    func toolbarTextColor() -> NSColor {
        guard let storage = textStorage, storage.length > 0 else {
            return textColor ?? annotationDefaultForegroundColor()
        }
        let sel = selectedRange()
        var index = sel.location
        if index >= storage.length && storage.length > 0 {
            index = storage.length - 1
        }
        if index < 0 { index = 0 }
        if let color = storage.attribute(.foregroundColor, at: index, effectiveRange: nil) as? NSColor {
            return color
        }
        return textColor ?? annotationDefaultForegroundColor()
    }

    func toolbarFontDisplayName() -> String {
        if let storage = textStorage, storage.length > 0 {
            let sel = selectedRange()
            let index = max(0, min(sel.location, storage.length - 1))
            if let font = storage.attribute(.font, at: index, effectiveRange: nil) as? NSFont {
                return font.displayName ?? font.fontName
            }
        }
        if let font = typingAttributes[.font] as? NSFont ?? font {
            return font.displayName ?? font.fontName
        }
        return "Font"
    }

    private func normalizedSelectionRange() -> NSRange {
        guard let storage = textStorage else { return selectedRange() }
        var sel = selectedRange()
        if sel.location == NSNotFound {
            let loc = max(0, storage.length)
            sel = NSRange(location: loc, length: 0)
            setSelectedRange(sel)
            return sel
        }
        if sel.location > storage.length {
            sel = NSRange(location: storage.length, length: 0)
            setSelectedRange(sel)
        }
        if sel.location + sel.length > storage.length {
            sel.length = max(0, storage.length - sel.location)
            setSelectedRange(sel)
        }
        return sel
    }

    private func selectionParagraphRange() -> NSRange {
        guard let storage = textStorage else { return selectedRange() }
        let ns = storage.string as NSString
        let sel = normalizedSelectionRange()
        if storage.length == 0 { return sel }
        if sel.location >= storage.length {
            let lastIndex = max(0, storage.length - 1)
            if storage.length == 0 {
                return NSRange(location: 0, length: 0)
            }
            let lastChar = ns.substring(with: NSRange(location: lastIndex, length: 1))
            if lastChar == "\n" || lastChar == "\r" {
                return NSRange(location: storage.length, length: 0)
            }
            return ns.paragraphRange(for: NSRange(location: lastIndex, length: 0))
        }
        let safeRange = NSRange(location: max(0, sel.location), length: sel.length)
        return ns.paragraphRange(for: safeRange)
    }

    private func ensureFirstResponder() {
        if window?.firstResponder !== self {
            window?.makeFirstResponder(self)
        }
    }

    private func toggleFontTrait(_ trait: NSFontTraitMask, isActive: Bool) {
        guard let storage = textStorage else { return }
        let selection = selectedRange()
        let fontManager = NSFontManager.shared
        let shouldEnable = !isActive
        if selection.length == 0 {
            let current = (typingAttributes[.font] as? NSFont) ?? font ?? PDFAnnotationRowMetrics.commentFont
            let next = shouldEnable
                ? fontManager.convert(current, toHaveTrait: trait)
                : fontManager.convert(current, toNotHaveTrait: trait)
            var attrs = typingAttributes
            attrs[.font] = next
            typingAttributes = attrs
            return
        }
        storage.beginEditing()
        storage.enumerateAttribute(.font, in: selection, options: []) { value, range, _ in
            let current = (value as? NSFont) ?? self.font ?? PDFAnnotationRowMetrics.commentFont
            let next = shouldEnable
                ? fontManager.convert(current, toHaveTrait: trait)
                : fontManager.convert(current, toNotHaveTrait: trait)
            storage.addAttribute(.font, value: next, range: range)
        }
        storage.endEditing()
        refreshInlineMathAttachmentStyles(in: selection)
        if storage.length > 0 {
            let index = max(0, min(selection.location, storage.length - 1))
            if let font = storage.attribute(.font, at: index, effectiveRange: nil) as? NSFont {
                var attrs = typingAttributes
                attrs[.font] = font
                typingAttributes = attrs
            }
        }
        didChangeText()
        markFormattingDismissalCandidate(selection)
    }

    private func toggleUnderlineAttribute(isActive: Bool) {
        guard let storage = textStorage else { return }
        let selection = selectedRange()
        let shouldUnderline = !isActive
        let value = shouldUnderline ? NSUnderlineStyle.single.rawValue : 0
        if selection.length == 0 {
            var attrs = typingAttributes
            attrs[.underlineStyle] = value
            typingAttributes = attrs
            return
        }
        storage.beginEditing()
        storage.addAttribute(.underlineStyle, value: value, range: selection)
        storage.endEditing()
        if storage.length > 0 {
            var attrs = typingAttributes
            attrs[.underlineStyle] = value
            typingAttributes = attrs
        }
        didChangeText()
        markFormattingDismissalCandidate(selection)
    }

    private func applyParagraphAlignment(_ alignment: NSTextAlignment) {
        guard let storage = textStorage else { return }
        let selection = selectionParagraphRange()
        if storage.length == 0 {
            let style = (typingAttributes[.paragraphStyle] as? NSParagraphStyle)?.mutableCopy() as? NSMutableParagraphStyle
                ?? NSMutableParagraphStyle()
            style.lineBreakMode = .byWordWrapping
            style.alignment = alignment
            var attrs = typingAttributes
            attrs[.paragraphStyle] = style
            typingAttributes = attrs
            didChangeText()
            return
        }
        storage.beginEditing()
        storage.enumerateAttribute(.paragraphStyle, in: selection, options: []) { value, range, _ in
            let style = (value as? NSParagraphStyle)?.mutableCopy() as? NSMutableParagraphStyle ?? NSMutableParagraphStyle()
            style.lineBreakMode = .byWordWrapping
            style.alignment = alignment
            storage.addAttribute(.paragraphStyle, value: style, range: range)
        }
        storage.endEditing()
        if storage.length > 0 {
            let index = max(0, min(selection.location, storage.length - 1))
            if let style = storage.attribute(.paragraphStyle, at: index, effectiveRange: nil) as? NSParagraphStyle {
                var attrs = typingAttributes
                attrs[.paragraphStyle] = style
                typingAttributes = attrs
            }
        }
        didChangeText()
    }

    private func paragraphRanges(in selection: NSRange, storage: NSTextStorage) -> [NSRange] {
        let ns = storage.string as NSString
        if storage.length == 0 {
            return [NSRange(location: 0, length: 0)]
        }
        if selection.location >= storage.length {
            let lastIndex = max(0, storage.length - 1)
            if storage.length > 0 {
                let lastChar = ns.substring(with: NSRange(location: lastIndex, length: 1))
                if lastChar == "\n" || lastChar == "\r" {
                    return [NSRange(location: storage.length, length: 0)]
                }
            }
            let fallback = ns.paragraphRange(for: NSRange(location: lastIndex, length: 0))
            return [fallback]
        }
        let safeLocation = max(0, min(selection.location, max(0, storage.length - 1)))
        let end = min(storage.length, safeLocation + max(0, selection.length))
        var ranges: [NSRange] = []
        var idx = safeLocation
        while idx <= end {
            let para = ns.paragraphRange(for: NSRange(location: idx, length: 0))
            if ranges.last?.location == para.location { break }
            ranges.append(para)
            idx = para.location + para.length
            if idx >= end { break }
        }
        if ranges.isEmpty {
            ranges.append(ns.paragraphRange(for: NSRange(location: safeLocation, length: 0)))
        }
        return ranges
    }

    private func leadingTabPrefix(in paragraphRange: NSRange, storage: NSTextStorage) -> String {
        guard paragraphRange.length > 0 else { return "" }
        let ns = storage.string as NSString
        let para = ns.substring(with: paragraphRange)
        var prefix = ""
        for scalar in para.unicodeScalars {
            if scalar.value == 9 { // tab
                prefix.append("\t")
            } else {
                break
            }
        }
        return prefix
    }

    private func normalizeNonListIndentationAcrossStorage() {
        guard let storage = textStorage, storage.length > 0 else { return }
        guard !isNormalizingNonListIndentation else { return }
        isNormalizingNonListIndentation = true
        let ns = storage.string as NSString
        storage.beginEditing()
        var idx = 0
        while idx < storage.length {
            let para = ns.paragraphRange(for: NSRange(location: idx, length: 0))
            _ = normalizeNonListIndentation(in: storage, paragraphRange: para, updateTypingAttributes: false)
            idx = para.location + para.length
        }
        storage.endEditing()
        isNormalizingNonListIndentation = false
    }

    private func normalizeNonListIndentationIfNeeded(for selection: NSRange) {
        guard !isNormalizingNonListIndentation else { return }
        guard let storage = textStorage else { return }
        guard selection.length == 0 else { return }
        if storage.length == 0 {
            normalizeTypingAttributesForNonListParagraph()
            return
        }
        let paragraph: NSRange = {
            let ns = storage.string as NSString
            if selection.location >= storage.length {
                let lastIndex = max(0, storage.length - 1)
                if storage.length > 0 {
                    let lastChar = ns.substring(with: NSRange(location: lastIndex, length: 1))
                    if lastChar == "\n" || lastChar == "\r" {
                        return NSRange(location: storage.length, length: 0)
                    }
                }
                return ns.paragraphRange(for: NSRange(location: lastIndex, length: 0))
            }
            let safeLocation = max(0, min(selection.location, max(0, storage.length - 1)))
            return ns.paragraphRange(for: NSRange(location: safeLocation, length: 0))
        }()
        _ = normalizeNonListIndentation(in: storage, paragraphRange: paragraph, updateTypingAttributes: true)
    }

    private func normalizeTypingAttributesForNonListParagraph() {
        let style = (typingAttributes[.paragraphStyle] as? NSParagraphStyle) ?? NSMutableParagraphStyle()
        guard needsNonListIndentReset(style) else { return }
        let updated = nonListParagraphStyle(from: style)
        var attrs = typingAttributes
        attrs[.paragraphStyle] = updated
        typingAttributes = attrs
    }

    @discardableResult
    private func normalizeNonListIndentation(in storage: NSTextStorage,
                                             paragraphRange: NSRange,
                                             updateTypingAttributes: Bool) -> Bool {
        if storage.length == 0 {
            if updateTypingAttributes {
                normalizeTypingAttributesForNonListParagraph()
            }
            return false
        }
        if paragraphRange.length > 0,
           listMarkerInfo(in: paragraphRange, storage: storage) != nil {
            return false
        }
        let styleIndex = max(0, min(paragraphRange.location, storage.length - 1))
        guard let style = storage.attribute(.paragraphStyle, at: styleIndex, effectiveRange: nil) as? NSParagraphStyle else {
            return false
        }
        guard needsNonListIndentReset(style) else { return false }
        let updated = nonListParagraphStyle(from: style)
        if paragraphRange.length > 0 {
            storage.addAttribute(.paragraphStyle, value: updated, range: paragraphRange)
        }
        if updateTypingAttributes {
            var attrs = typingAttributes
            attrs[.paragraphStyle] = updated
            typingAttributes = attrs
        }
        return true
    }

    private func needsNonListIndentReset(_ style: NSParagraphStyle) -> Bool {
        return style.headIndent > 0
            || style.firstLineHeadIndent > 0
            || !(style.textLists.isEmpty)
            || !style.tabStops.isEmpty
            || style.defaultTabInterval > 0
    }

    private func nonListParagraphStyle(from style: NSParagraphStyle) -> NSMutableParagraphStyle {
        let updated = (style.mutableCopy() as? NSMutableParagraphStyle) ?? NSMutableParagraphStyle()
        updated.headIndent = 0
        updated.firstLineHeadIndent = 0
        updated.textLists = []
        updated.tabStops = []
        updated.defaultTabInterval = 0
        return updated
    }

    private func handleTabIndent() -> Bool {
        guard isEditable, let storage = textStorage else { return false }
        let selection = selectedRange()
        let paragraphs = paragraphRanges(in: selection, storage: storage)
        guard !paragraphs.isEmpty else { return false }

        let selectionStart = selection.location
        let selectionEnd = selection.location + selection.length
        var beforeCount = 0
        var withinCount = 0
        let insertionLocations = paragraphs.map { $0.location }
        for loc in insertionLocations {
            if loc <= selectionStart {
                beforeCount += 1
            } else if loc < selectionEnd {
                withinCount += 1
            }
        }

        storage.beginEditing()
        var offset = 0
        for loc in insertionLocations {
            let insertLoc = loc + offset
            let insertRange = NSRange(location: insertLoc, length: 0)
            if shouldChangeText(in: insertRange, replacementString: "\t") {
                storage.replaceCharacters(in: insertRange, with: "\t")
                offset += 1
            }
        }
        storage.endEditing()

        let newLocation = selectionStart + beforeCount
        let newLength = selection.length + withinCount
        setSelectedRange(NSRange(location: newLocation, length: newLength))
        didChangeText()
        return true
    }

    private func listMarkerInfo(in paragraphRange: NSRange,
                                storage: NSTextStorage) -> (marker: NSTextList.MarkerFormat, range: NSRange)? {
        guard storage.length > 0 else { return nil }
        let ns = storage.string as NSString
        let para = ns.substring(with: paragraphRange)
        var idx = 0
        while idx < para.count {
            let ch = (para as NSString).character(at: idx)
            if ch == 9 || ch == 32 { // tab or space
                idx += 1
                continue
            }
            break
        }
        guard idx < para.count else { return nil }
        let start = idx
        let remaining = (para as NSString).substring(from: start)
        if remaining.hasPrefix("•") {
            let markerLen = 1
            var totalLen = markerLen
            if remaining.count > markerLen {
                let nextChar = (remaining as NSString).character(at: markerLen)
                if nextChar == 9 || nextChar == 32 {
                    totalLen += 1
                }
            }
            return (.disc, NSRange(location: paragraphRange.location + start, length: totalLen))
        }
        let numberPattern = "^[0-9]+\\."
        if let match = remaining.range(of: numberPattern, options: .regularExpression) {
            let markerString = String(remaining[match])
            var totalLen = markerString.count
            if remaining.count > totalLen {
                let nextChar = (remaining as NSString).character(at: totalLen)
                if nextChar == 9 || nextChar == 32 {
                    totalLen += 1
                }
            }
            return (.decimal, NSRange(location: paragraphRange.location + start, length: totalLen))
        }
        return nil
    }

    private func listMarkerString(for marker: NSTextList.MarkerFormat, itemNumber: Int) -> String {
        switch marker {
        case .decimal:
            return "\(itemNumber)."
        default:
            return "•"
        }
    }

    private func listMarkerNumber(from markerRange: NSRange, storage: NSTextStorage) -> Int? {
        guard storage.length > 0,
              markerRange.location + markerRange.length <= storage.length else { return nil }
        let fragment = (storage.string as NSString).substring(with: markerRange)
        let digits = fragment.filter { $0.isNumber }
        return Int(digits)
    }

    private func clearListFormatting(in paragraphRange: NSRange, storage: NSTextStorage) {
        guard storage.length > 0 else { return }
        let safeIndex = min(max(0, paragraphRange.location), max(0, storage.length - 1))
        let style = (storage.attribute(.paragraphStyle, at: safeIndex, effectiveRange: nil) as? NSParagraphStyle)?.mutableCopy()
            as? NSMutableParagraphStyle ?? NSMutableParagraphStyle()
        style.headIndent = 0
        style.firstLineHeadIndent = 0
        style.defaultTabInterval = 0
        style.tabStops = []
        style.textLists = []
        let applyLength = min(paragraphRange.length, storage.length - paragraphRange.location)
        if applyLength > 0 {
            storage.addAttribute(.paragraphStyle, value: style,
                                 range: NSRange(location: paragraphRange.location, length: applyLength))
        }
    }

    private func applyListMarker(marker: NSTextList.MarkerFormat,
                                 itemNumber: Int,
                                 paragraphRange: NSRange,
                                 storage: NSTextStorage,
                                 baseIndent: CGFloat) -> Int {
        var range = paragraphRange
        guard range.location <= storage.length else { return 0 }
        if range.location + range.length > storage.length {
            range.length = max(0, storage.length - range.location)
        }

        var removedLength = 0
        if let existing = listMarkerInfo(in: range, storage: storage) {
            storage.deleteCharacters(in: existing.range)
            removedLength = existing.range.length
            range.length = max(0, range.length - removedLength)
        }

        let markerString = listMarkerString(for: marker, itemNumber: itemNumber)
        let prefix = markerString + "\t"
        let attrs: [NSAttributedString.Key: Any] = {
            if storage.length > 0, range.location < storage.length {
                var result = storage.attributes(at: range.location, effectiveRange: nil)
                if result[.font] == nil { result[.font] = self.font ?? PDFAnnotationRowMetrics.commentFont }
                if result[.foregroundColor] == nil { result[.foregroundColor] = self.textColor ?? annotationDefaultForegroundColor() }
                if result[.paragraphStyle] == nil {
                    result[.paragraphStyle] = inlineMathBaseAttributes(font: self.font ?? PDFAnnotationRowMetrics.commentFont,
                                                                       color: self.textColor ?? annotationDefaultForegroundColor())[.paragraphStyle]
                }
                return result
            }
            return typingAttributes
        }()
        storage.insert(NSAttributedString(string: prefix, attributes: attrs), at: range.location)
        range.length += prefix.count

        let styleIndex = min(max(0, range.location), max(0, storage.length - 1))
        let style = (storage.attribute(.paragraphStyle, at: styleIndex, effectiveRange: nil) as? NSParagraphStyle)?.mutableCopy()
            as? NSMutableParagraphStyle ?? NSMutableParagraphStyle()
        style.lineBreakMode = .byWordWrapping
        style.headIndent = max(style.headIndent, baseIndent)
        style.firstLineHeadIndent = 0
        style.defaultTabInterval = baseIndent
        style.tabStops = [NSTextTab(textAlignment: .left, location: baseIndent, options: [:])]
        style.textLists = []

        let applyLength = min(range.length, storage.length - range.location)
        if applyLength > 0 {
            storage.addAttribute(.paragraphStyle, value: style,
                                 range: NSRange(location: range.location, length: applyLength))
        }
        return prefix.count - removedLength
    }

    private func handleListNewline() -> Bool {
        guard let storage = textStorage else { return false }
        let selection = selectedRange()
        guard selection.length == 0 else { return false }
        let ns = storage.string as NSString
        let safeLocation = min(max(0, selection.location), max(0, storage.length))
        let lookupLocation = min(safeLocation, max(0, storage.length - 1))
        let paragraph = ns.paragraphRange(for: NSRange(location: lookupLocation, length: 0))
        guard let info = listMarkerInfo(in: paragraph, storage: storage) else { return false }

        let markerEnd = info.range.location + info.range.length
        let paraEnd = paragraph.location + paragraph.length
        if markerEnd > paraEnd { return false }
        let contentRange = NSRange(location: markerEnd, length: max(0, paraEnd - markerEnd))
        let content = ns.substring(with: contentRange)
        let trimmed = content.trimmingCharacters(in: .whitespacesAndNewlines)

        if trimmed.isEmpty {
            storage.beginEditing()
            storage.deleteCharacters(in: info.range)
            storage.endEditing()
            let updatedParagraph = (storage.string as NSString).paragraphRange(
                for: NSRange(location: min(info.range.location, max(0, storage.length)), length: 0)
            )
            storage.beginEditing()
            clearListFormatting(in: updatedParagraph, storage: storage)
            storage.endEditing()
            if storage.length > 0 {
                let styleIndex = min(info.range.location, storage.length - 1)
                if let style = storage.attribute(.paragraphStyle, at: styleIndex, effectiveRange: nil) as? NSParagraphStyle {
                    var attrs = typingAttributes
                    attrs[.paragraphStyle] = style
                    typingAttributes = attrs
                }
            }
            if storage.length == 0 {
                let style = NSMutableParagraphStyle()
                style.lineBreakMode = .byWordWrapping
                var attrs = typingAttributes
                attrs[.paragraphStyle] = style
                typingAttributes = attrs
            }
            setSelectedRange(NSRange(location: min(info.range.location, storage.length), length: 0))
            super.doCommand(by: #selector(insertNewline(_:)))
            return true
        }

        let marker = info.marker
        var nextNumber = 1
        if marker == .decimal, let current = listMarkerNumber(from: info.range, storage: storage) {
            nextNumber = current + 1
        }
        super.doCommand(by: #selector(insertNewline(_:)))
        let newSelection = selectedRange()
        let newParagraph = selectionParagraphRange()
        let baseIndent = max(14, (self.font ?? PDFAnnotationRowMetrics.commentFont).pointSize * 1.6)
        storage.beginEditing()
        _ = applyListMarker(marker: marker,
                            itemNumber: nextNumber,
                            paragraphRange: newParagraph,
                            storage: storage,
                            baseIndent: baseIndent)
        storage.endEditing()
        if let markerInfo = listMarkerInfo(in: newParagraph, storage: storage) {
            setSelectedRange(NSRange(location: markerInfo.range.location + markerInfo.range.length, length: 0))
        }
        if storage.length > 0 {
            let index = max(0, min(newSelection.location, storage.length - 1))
            if let style = storage.attribute(.paragraphStyle, at: index, effectiveRange: nil) as? NSParagraphStyle {
                var attrs = typingAttributes
                attrs[.paragraphStyle] = style
                typingAttributes = attrs
            }
        }
        didChangeText()
        return true
    }

    private func handleListShiftReturn() -> Bool {
        guard let storage = textStorage else { return false }
        let selection = selectedRange()
        guard selection.length == 0 else { return false }
        let ns = storage.string as NSString
        let safeLocation = min(max(0, selection.location), max(0, storage.length))
        let lookupLocation = min(safeLocation, max(0, storage.length - 1))
        let paragraph = ns.paragraphRange(for: NSRange(location: lookupLocation, length: 0))
        guard let info = listMarkerInfo(in: paragraph, storage: storage) else { return false }

        let markerEnd = info.range.location + info.range.length
        let paraEnd = paragraph.location + paragraph.length
        if markerEnd > paraEnd { return false }
        let contentRange = NSRange(location: markerEnd, length: max(0, paraEnd - markerEnd))
        let content = ns.substring(with: contentRange)
        let trimmed = content.trimmingCharacters(in: .whitespacesAndNewlines)

        if trimmed.isEmpty {
            storage.beginEditing()
            storage.deleteCharacters(in: info.range)
            storage.endEditing()
            let updatedParagraph = (storage.string as NSString).paragraphRange(
                for: NSRange(location: min(info.range.location, max(0, storage.length)), length: 0)
            )
            storage.beginEditing()
            clearListFormatting(in: updatedParagraph, storage: storage)
            storage.endEditing()
            let cursorLocation = min(info.range.location, storage.length)
            setSelectedRange(NSRange(location: cursorLocation, length: 0))
            if storage.length > 0 {
                let styleIndex = min(cursorLocation, storage.length - 1)
                if let style = storage.attribute(.paragraphStyle, at: styleIndex, effectiveRange: nil) as? NSParagraphStyle {
                    var attrs = typingAttributes
                    attrs[.paragraphStyle] = style
                    typingAttributes = attrs
                }
            }
            if storage.length == 0 {
                let style = NSMutableParagraphStyle()
                style.lineBreakMode = .byWordWrapping
                var attrs = typingAttributes
                attrs[.paragraphStyle] = style
                typingAttributes = attrs
            }
            didChangeText()
            return true
        }

        let marker = info.marker
        var nextNumber = 1
        if marker == .decimal, let current = listMarkerNumber(from: info.range, storage: storage) {
            nextNumber = current + 1
        }
        super.doCommand(by: #selector(insertNewline(_:)))
        let newSelection = selectedRange()
        let newParagraph = selectionParagraphRange()
        let baseIndent = max(14, (self.font ?? PDFAnnotationRowMetrics.commentFont).pointSize * 1.6)
        storage.beginEditing()
        _ = applyListMarker(marker: marker,
                            itemNumber: nextNumber,
                            paragraphRange: newParagraph,
                            storage: storage,
                            baseIndent: baseIndent)
        storage.endEditing()
        if let markerInfo = listMarkerInfo(in: newParagraph, storage: storage) {
            setSelectedRange(NSRange(location: markerInfo.range.location + markerInfo.range.length, length: 0))
        }
        if storage.length > 0 {
            let index = max(0, min(newSelection.location, storage.length - 1))
            if let style = storage.attribute(.paragraphStyle, at: index, effectiveRange: nil) as? NSParagraphStyle {
                var attrs = typingAttributes
                attrs[.paragraphStyle] = style
                typingAttributes = attrs
            }
        }
        didChangeText()
        return true
    }

    private func applyListFormatting(marker: NSTextList.MarkerFormat,
                                     removing range: NSRange?,
                                     moveCaretAfterMarker: Bool = false) {
        guard let storage = textStorage else { return }
        if let range, range.length > 0, range.location <= storage.length {
            let clampedLength = min(range.length, storage.length - range.location)
            let deleteRange = NSRange(location: range.location, length: clampedLength)
            storage.beginEditing()
            storage.deleteCharacters(in: deleteRange)
            storage.endEditing()
            setSelectedRange(NSRange(location: deleteRange.location, length: 0))
        }
        applyTextList(marker: marker)
        guard moveCaretAfterMarker else { return }
        guard storage.length > 0 else { return }
        let sel = selectedRange()
        let safeLocation = min(max(0, sel.location), max(0, storage.length - 1))
        let paragraph = (storage.string as NSString).paragraphRange(for: NSRange(location: safeLocation, length: 0))
        if let info = listMarkerInfo(in: paragraph, storage: storage) {
            setSelectedRange(NSRange(location: info.range.location + info.range.length, length: 0))
        }
    }

    private func handleAutoListTrigger(at insertionLocation: Int) -> Bool {
        guard let storage = textStorage else { return false }
        let ns = storage.string as NSString
        let clampedLocation = max(0, min(insertionLocation, storage.length))
        let paraRange: NSRange
        if clampedLocation >= storage.length, storage.length > 0 {
            let lastIndex = max(0, storage.length - 1)
            let lastChar = ns.substring(with: NSRange(location: lastIndex, length: 1))
            if lastChar == "\n" || lastChar == "\r" {
                paraRange = NSRange(location: storage.length, length: 0)
            } else {
                paraRange = ns.paragraphRange(for: NSRange(location: lastIndex, length: 0))
            }
        } else {
            paraRange = ns.paragraphRange(for: NSRange(location: clampedLocation, length: 0))
        }
        let prefixLength = max(0, clampedLocation - paraRange.location)
        guard prefixLength > 0 else { return false }
        let prefixRange = NSRange(location: paraRange.location, length: prefixLength)
        let prefix = ns.substring(with: prefixRange)
        let trimmed = prefix.trimmingCharacters(in: .whitespaces)
        guard trimmed == prefix else { return false }
        if trimmed == "*" {
            applyListFormatting(marker: .disc, removing: prefixRange, moveCaretAfterMarker: true)
            return true
        }
        let numberPattern = "^[0-9]+\\.$"
        if trimmed.range(of: numberPattern, options: .regularExpression) != nil {
            applyListFormatting(marker: .decimal, removing: prefixRange, moveCaretAfterMarker: true)
            return true
        }
        return false
    }

    private func adjustFontSize(by delta: CGFloat) {
        guard let storage = textStorage else { return }
        let selection = selectedRange()
        if selection.length == 0 {
            let current = (typingAttributes[.font] as? NSFont) ?? font ?? PDFAnnotationRowMetrics.commentFont
            let nextSize = max(6, current.pointSize + delta)
            let nextFont = NSFont(descriptor: current.fontDescriptor, size: nextSize) ?? current.withSize(nextSize)
            typingAttributes[.font] = nextFont
            return
        }
        storage.beginEditing()
        storage.enumerateAttribute(.font, in: selection, options: []) { value, range, _ in
            let current = (value as? NSFont) ?? self.font ?? PDFAnnotationRowMetrics.commentFont
            let nextSize = max(6, current.pointSize + delta)
            let nextFont = NSFont(descriptor: current.fontDescriptor, size: nextSize) ?? current.withSize(nextSize)
            storage.addAttribute(.font, value: nextFont, range: range)
        }
        storage.endEditing()
        refreshInlineMathAttachmentStyles(in: selection)
        didChangeText()
    }

    private func applyTextList(marker: NSTextList.MarkerFormat) {
        ensureFirstResponder()
        guard let storage = textStorage else { return }
        let selection = selectionParagraphRange()
        let paragraphs = paragraphRanges(in: selection, storage: storage)
        let baseIndent = max(14, (self.font ?? PDFAnnotationRowMetrics.commentFont).pointSize * 1.6)
        var offset = 0
        storage.beginEditing()
        var itemNumber = 1
        for para in paragraphs {
            var range = NSRange(location: para.location + offset, length: para.length)
            guard range.location <= storage.length else { continue }
            if range.location + range.length > storage.length {
                range.length = max(0, storage.length - range.location)
            }
            let delta = applyListMarker(marker: marker,
                                        itemNumber: itemNumber,
                                        paragraphRange: range,
                                        storage: storage,
                                        baseIndent: baseIndent)
            offset += delta
            itemNumber += 1
        }
        storage.endEditing()
        if storage.length > 0 {
            let index = max(0, min(selection.location, storage.length - 1))
            if let style = storage.attribute(.paragraphStyle, at: index, effectiveRange: nil) as? NSParagraphStyle {
                var attrs = typingAttributes
                attrs[.paragraphStyle] = style
                typingAttributes = attrs
            }
        }
        didChangeText()
    }

    private func removeTextLists() {
        ensureFirstResponder()
        guard let storage = textStorage else { return }
        let selection = selectionParagraphRange()
        if storage.length == 0 {
            let style = (typingAttributes[.paragraphStyle] as? NSParagraphStyle)?.mutableCopy() as? NSMutableParagraphStyle
                ?? NSMutableParagraphStyle()
            style.textLists = []
            style.headIndent = 0
            style.firstLineHeadIndent = 0
            style.defaultTabInterval = 0
            style.tabStops = []
            var attrs = typingAttributes
            attrs[.paragraphStyle] = style
            typingAttributes = attrs
            didChangeText()
            return
        }
        let paragraphs = paragraphRanges(in: selection, storage: storage)
        storage.beginEditing()
        var offset = 0
        for para in paragraphs {
            var range = NSRange(location: para.location + offset, length: para.length)
            if range.location + range.length > storage.length {
                range.length = max(0, storage.length - range.location)
            }
            if let existing = listMarkerInfo(in: range, storage: storage) {
                storage.deleteCharacters(in: existing.range)
                offset -= existing.range.length
                range.length = max(0, range.length - existing.range.length)
            }
            clearListFormatting(in: range, storage: storage)
        }
        storage.endEditing()
        if storage.length > 0 {
            let index = max(0, min(selection.location, storage.length - 1))
            if let style = storage.attribute(.paragraphStyle, at: index, effectiveRange: nil) as? NSParagraphStyle {
                var attrs = typingAttributes
                attrs[.paragraphStyle] = style
                typingAttributes = attrs
            }
        }
        didChangeText()
    }
}

final class InlineMathEditorTextView: NSTextView {
    private var isDrawingTextView: Bool = false
    private var deferredFrameSize: NSSize?

    override func draw(_ dirtyRect: NSRect) {
        PerfLogger.begin("draw.inline_math_editor")
        defer { PerfLogger.end("draw.inline_math_editor") }
        guard rectIsFinite(dirtyRect) else { return }
        isDrawingTextView = true
        defer {
            isDrawingTextView = false
            scheduleDeferredFrameSizeIfNeeded()
        }
        super.draw(dirtyRect)
    }

    override func setFrameSize(_ newSize: NSSize) {
        guard newSize.width.isFinite, newSize.height.isFinite else { return }
        if isDrawingTextView {
            deferredFrameSize = newSize
            scheduleDeferredFrameSizeIfNeeded()
            return
        }
        super.setFrameSize(newSize)
    }

    private func scheduleDeferredFrameSizeIfNeeded() {
        guard let deferred = deferredFrameSize else { return }
        deferredFrameSize = nil
        DispatchQueue.main.async { [weak self] in
            guard let self else { return }
            guard deferred.width.isFinite, deferred.height.isFinite else { return }
            if self.frame.size != deferred {
                self.setFrameSize(deferred)
            }
        }
    }
}

final class InlineMathEditorController: NSObject, NSTextViewDelegate, NSPopoverDelegate {
    private weak var hostTextView: AnnotationTextView?
    private weak var editingAttachment: InlineMathAttachment?
    private var originalSource: String = ""
    private var popover: NSPopover?
    private var textView: NSTextView?
    private weak var scrollView: NSScrollView?
    private var widthConstraint: NSLayoutConstraint?
    private var heightConstraint: NSLayoutConstraint?
    private var baseSize: CGSize = .zero
    private var maxWidth: CGFloat = 0
    private var maxHeight: CGFloat = 0
    private var cancelled = false
    private var clickMonitor: Any?
    private var keyMonitor: Any?
    private var hostTextChangeObserver: Any?
    private var sizeUpdateWork: DispatchWorkItem?
    private var repositionWork: DispatchWorkItem?
    private var layoutRefreshWork: DispatchWorkItem?
    private var suppressHostSync = false
    private let popoverGap: CGFloat = 10
    private let popoverDefaultHeight: CGFloat = 120
    private let previewClearance: CGFloat = 6
    private var lastPreviewRect: NSRect = .zero
    private var isClosing = false
    private let popoverUpdateDelay: TimeInterval = 0.06
    private let previewMoveThreshold: CGFloat = 2
    private let popoverMoveThreshold: CGFloat = 1

    var isVisible: Bool {
        popover?.isShown ?? false
    }

    func isEventInPopoverWindow(_ event: NSEvent) -> Bool {
        guard let window = popover?.contentViewController?.view.window else { return false }
        return event.window === window
    }

    func present(for attachment: InlineMathAttachment, in textView: AnnotationTextView) {
        hostTextView = textView
        editingAttachment = attachment
        originalSource = attachment.source
        cancelled = false
        isClosing = false
        suppressHostSync = true

        let warmFont = textView.font ?? PDFAnnotationRowMetrics.commentFont
        let warmColor = textView.textColor ?? annotationDefaultForegroundColor()
        KaTeXRenderer.shared.prewarm(fontSize: warmFont.pointSize,
                                     textColor: warmColor,
                                     fontFamily: inlineMathCSSFontFamily(warmFont))

        let pop = popover ?? makePopover()
        popover = pop

        if let editor = self.textView {
            editor.string = attachment.source
            editor.delegate = self
            editor.setSelectedRange(NSRange(location: 0, length: editor.string.count))
        }

        if let container = textView.textContainer {
            textView.layoutManager?.ensureLayout(for: container)
        }
        let rawAnchor = anchorRect(for: attachment, in: textView) ?? caretRect(in: textView)
        let fallbackAnchor: NSRect? = {
            let rect = textView.visibleRect
            if rectIsFinite(rect), rect.width > 1, rect.height > 1 {
                return NSRect(x: rect.midX - 1, y: rect.midY - 1, width: 2, height: 2)
            }
            let bounds = textView.bounds
            guard rectIsFinite(bounds), bounds.width > 1, bounds.height > 1 else { return nil }
            return NSRect(x: bounds.midX - 1, y: bounds.midY - 1, width: 2, height: 2)
        }()
        guard let initialAnchor = rawAnchor, rectIsFinite(initialAnchor) else {
            guard let safe = fallbackAnchor else { return }
            if pop.isShown { pop.close() }
            let placement = popoverPlacement(preview: safe, in: textView)
            maxHeight = placement.maxHeight
            configureBaseSize()
            pop.show(relativeTo: placement.anchor, of: textView, preferredEdge: placement.edge)
            lastPreviewRect = safe
            installClickMonitor()
            installKeyMonitor()
            installHostTextObserver()
            updatePopoverSize()
            return
        }
        if pop.isShown {
            pop.close()
        }
        ensurePreviewVisible(initialAnchor, in: textView)
        let previewRect = anchorRect(for: attachment, in: textView) ?? initialAnchor
        let placement = popoverPlacement(preview: previewRect, in: textView)
        maxHeight = placement.maxHeight
        configureBaseSize()
        pop.show(relativeTo: placement.anchor, of: textView, preferredEdge: placement.edge)
        lastPreviewRect = previewRect
        adjustPopoverToAvoidPreview(previewRect, in: textView)
        pop.contentViewController?.view.window?.makeKeyAndOrderFront(nil)
        pop.contentViewController?.view.window?.makeFirstResponder(self.textView)
        installClickMonitor()
        installKeyMonitor()
        installHostTextObserver()
        updatePopoverSize()
    }

    private func makePopover() -> NSPopover {
        let pop = NSPopover()
        pop.behavior = .transient
        pop.animates = false
        pop.delegate = self

        let vc = NSViewController()
        let effect = NSVisualEffectView()
        effect.translatesAutoresizingMaskIntoConstraints = false
        effect.material = .popover
        effect.appearance = NSAppearance(named: .darkAqua)
        effect.blendingMode = .withinWindow
        effect.state = .active
        effect.wantsLayer = true
        effect.layer?.cornerRadius = 8
        effect.layer?.masksToBounds = true

        let scroll = NSScrollView()
        scroll.translatesAutoresizingMaskIntoConstraints = false
        scroll.borderType = .noBorder
        scroll.drawsBackground = false
        scroll.hasVerticalScroller = false
        scroll.hasHorizontalScroller = false
        scroll.autohidesScrollers = true

        let editor = InlineMathEditorTextView()
        editor.translatesAutoresizingMaskIntoConstraints = true
        editor.isEditable = true
        editor.isSelectable = true
        editor.isRichText = false
        editor.allowsUndo = true
        editor.font = NSFont.monospacedSystemFont(ofSize: 12.5, weight: .regular)
        editor.textColor = .white
        editor.backgroundColor = .clear
        editor.drawsBackground = false
        editor.insertionPointColor = .systemRed
        editor.focusRingType = .none
        editor.isVerticallyResizable = true
        editor.isHorizontallyResizable = false
        editor.minSize = NSSize(width: 0, height: 0)
        editor.maxSize = NSSize(width: CGFloat.greatestFiniteMagnitude, height: CGFloat.greatestFiniteMagnitude)
        editor.textContainerInset = NSSize(width: 6, height: 4)
        editor.textContainer?.lineFragmentPadding = 0
        editor.textContainer?.widthTracksTextView = true
        editor.textContainer?.heightTracksTextView = false
        editor.delegate = self

        scroll.documentView = editor
        effect.addSubview(scroll)
        NSLayoutConstraint.activate([
            scroll.leadingAnchor.constraint(equalTo: effect.leadingAnchor),
            scroll.trailingAnchor.constraint(equalTo: effect.trailingAnchor),
            scroll.topAnchor.constraint(equalTo: effect.topAnchor),
            scroll.bottomAnchor.constraint(equalTo: effect.bottomAnchor)
        ])

        let container = NSView()
        container.translatesAutoresizingMaskIntoConstraints = false
        container.addSubview(effect)
        NSLayoutConstraint.activate([
            effect.leadingAnchor.constraint(equalTo: container.leadingAnchor),
            effect.trailingAnchor.constraint(equalTo: container.trailingAnchor),
            effect.topAnchor.constraint(equalTo: container.topAnchor),
            effect.bottomAnchor.constraint(equalTo: container.bottomAnchor)
        ])

        let widthConstraint = effect.widthAnchor.constraint(equalToConstant: 180)
        let heightConstraint = effect.heightAnchor.constraint(equalToConstant: 30)
        widthConstraint.isActive = true
        heightConstraint.isActive = true

        vc.view = container
        pop.contentViewController = vc
        self.textView = editor
        self.scrollView = scroll
        self.widthConstraint = widthConstraint
        self.heightConstraint = heightConstraint
        return pop
    }

    private func resolvedPanelSize() -> CGSize {
        guard let host = hostTextView else { return CGSize(width: 320, height: 160) }
        var view: NSView? = host
        while let current = view {
            if current is GlassCardView {
                let size = current.bounds.size
                if size.width > 1, size.height > 1 { return size }
            }
            view = current.superview
        }
        if let content = host.window?.contentView {
            let size = content.bounds.size
            if size.width > 1, size.height > 1 { return size }
        }
        if let window = host.window,
           window.styleMask.contains(.borderless),
           let content = window.contentView {
            let size = content.bounds.size
            if size.width > 1, size.height > 1 { return size }
        }
        let fallback = host.bounds.size
        return (fallback.width > 1 && fallback.height > 1) ? fallback : CGSize(width: 320, height: 160)
    }

    private func configureBaseSize() {
        guard let widthConstraint, let heightConstraint, let popover else { return }
        let panelSize = resolvedPanelSize()
        let baseWidth = panelSize.width > 1 ? panelSize.width : 180
        let heightCap = maxHeight > 1 ? maxHeight : (panelSize.height > 1 ? panelSize.height : 120)
        let minHeight: CGFloat = 32
        var baseHeight = max(minHeight, min(popoverDefaultHeight, heightCap))
        if heightCap < minHeight {
            baseHeight = heightCap
        }
        baseSize = CGSize(width: baseWidth, height: baseHeight)
        maxWidth = baseWidth
        widthConstraint.constant = baseWidth
        heightConstraint.constant = baseHeight
        popover.contentSize = baseSize
    }

    private func anchorRect(for attachment: InlineMathAttachment, in textView: AnnotationTextView) -> NSRect? {
        guard let storage = textView.textStorage,
              let layout = textView.layoutManager,
              let container = textView.textContainer else { return nil }
        layout.ensureLayout(for: container)
        let full = NSRange(location: 0, length: storage.length)
        var target: NSRange?
        storage.enumerateAttribute(.attachment, in: full, options: []) { value, range, stop in
            if let att = value as? InlineMathAttachment, att === attachment {
                target = range
                stop.pointee = true
            }
        }
        guard let range = target else { return nil }
        let glyphRange = layout.glyphRange(forCharacterRange: range, actualCharacterRange: nil)
        var rect = layout.boundingRect(forGlyphRange: glyphRange, in: container)
        let origin = textView.textContainerOrigin
        rect.origin.x += origin.x
        rect.origin.y += origin.y
        rect = rect.insetBy(dx: -4, dy: -2)
        guard rectIsFinite(rect), rect.width > 0, rect.height > 0 else { return nil }
        return rect
    }

    private func ensurePreviewVisible(_ rect: NSRect, in textView: AnnotationTextView) {
        guard rectIsFinite(rect) else { return }
        let margin: CGFloat = 14
        var target = rect.insetBy(dx: -margin, dy: -(margin + previewClearance))
        if target.size.width < 1 { target.size.width = 1 }
        if target.size.height < 1 { target.size.height = 1 }
        guard rectIsFinite(target) else { return }
        textView.scrollToVisible(target)
    }

    private func popoverPlacement(preview: NSRect, in textView: AnnotationTextView) -> (anchor: NSRect, edge: NSRectEdge, maxHeight: CGFloat) {
        let previewRect: NSRect = {
            if rectIsFinite(preview), preview.width > 0, preview.height > 0 {
                return preview
            }
            let rect = textView.visibleRect
            if rectIsFinite(rect), rect.width > 1, rect.height > 1 {
                return NSRect(x: rect.midX - 1, y: rect.midY - 1, width: 2, height: 2)
            }
            let bounds = textView.bounds
            if rectIsFinite(bounds), bounds.width > 1, bounds.height > 1 {
                return NSRect(x: bounds.midX - 1, y: bounds.midY - 1, width: 2, height: 2)
            }
            return NSRect(x: 0, y: 0, width: 2, height: 2)
        }()
        guard let window = textView.window else {
            return (previewRect, .maxY, 0)
        }
        let windowRect = textView.convert(previewRect, to: nil)
        guard rectIsFinite(windowRect) else {
            return (previewRect, .maxY, 0)
        }
        let screenRect = window.convertToScreen(windowRect)
        guard rectIsFinite(screenRect) else {
            return (previewRect, .maxY, 0)
        }
        let visibleFrame = window.screen?.visibleFrame ?? NSScreen.main?.visibleFrame ?? window.frame

        let anchorOffset = popoverGap + previewClearance
        let spaceBelow = max(0, screenRect.minY - visibleFrame.minY - anchorOffset)
        let spaceAbove = max(0, visibleFrame.maxY - screenRect.maxY - anchorOffset)

        let edge: NSRectEdge
        let maxHeight: CGFloat
        if spaceBelow >= spaceAbove {
            edge = .maxY
            maxHeight = spaceBelow
        } else {
            edge = .minY
            maxHeight = spaceAbove
        }

        let anchorWidth: CGFloat = 2
        let anchorHeight: CGFloat = 2
        let anchorX = previewRect.midX - (anchorWidth / 2)
        let anchorY: CGFloat
        if edge == .maxY {
            anchorY = previewRect.minY - anchorOffset
        } else {
            anchorY = previewRect.maxY + anchorOffset
        }

        var adjusted = NSRect(x: anchorX, y: anchorY, width: anchorWidth, height: anchorHeight)
        let bounds = textView.bounds.insetBy(dx: 2, dy: 2)
        if bounds.width > 4, bounds.height > 4 {
            if adjusted.minX < bounds.minX { adjusted.origin.x = bounds.minX }
            if adjusted.maxX > bounds.maxX { adjusted.origin.x = bounds.maxX - adjusted.width }
            if adjusted.minY < bounds.minY { adjusted.origin.y = bounds.minY }
            if adjusted.maxY > bounds.maxY { adjusted.origin.y = bounds.maxY - adjusted.height }
        }
        return (adjusted, edge, maxHeight)
    }

    private func caretRect(in textView: AnnotationTextView) -> NSRect? {
        let selected = textView.selectedRange()
        guard let window = textView.window else { return nil }
        let screenRect = textView.firstRect(forCharacterRange: selected, actualRange: nil)
        if screenRect.isEmpty || !rectIsFinite(screenRect) { return nil }
        let windowRect = window.convertFromScreen(screenRect)
        guard rectIsFinite(windowRect) else { return nil }
        let localRect = textView.convert(windowRect, from: nil)
        guard rectIsFinite(localRect) else { return nil }
        return localRect
    }

    func textDidChange(_ notification: Notification) {
        guard !isClosing else { return }
        guard let editor = textView, let attachment = editingAttachment else { return }
        attachment.updateSource(editor.string)
        scheduleAttachmentRefresh(attachment)
        schedulePopoverSizeUpdate()
        if let host = hostTextView,
           let previewRect = anchorRect(for: attachment, in: host),
           rectIsFinite(previewRect) {
            schedulePopoverRepositionIfNeeded(previewRect, in: host)
        }
    }

    func textView(_ textView: NSTextView, doCommandBy commandSelector: Selector) -> Bool {
        if commandSelector == #selector(NSResponder.insertNewline(_:)) {
            closePopover(commit: true)
            return true
        }
        if commandSelector == #selector(NSResponder.cancelOperation(_:)) {
            cancelEditing()
            return true
        }
        return false
    }

    func popoverDidClose(_ notification: Notification) {
        guard let attachment = editingAttachment else {
            cleanup()
            return
        }
        defer { cleanup() }
        if cancelled { return }
        let trimmed = attachment.source.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty {
            removeAttachment(attachment)
        } else {
            refreshAttachmentLayout(attachment)
            if !attachment.display {
                ensureTrailingSpace(after: attachment)
            }
        }
        removeClickMonitor()
    }

    private func closePopover(commit: Bool) {
        guard !isClosing else { return }
        isClosing = true
        cancelPendingWork()
        removeHostTextObserver()
        removeClickMonitor()
        removeKeyMonitor()
        popover?.performClose(nil)
        if commit {
            cancelled = false
        }
    }

    func close(commit: Bool) {
        if commit {
            cancelled = false
        }
        closePopover(commit: commit)
    }

    func cancelEditing() {
        cancelled = true
        if let attachment = editingAttachment {
            attachment.updateSource(originalSource)
            refreshAttachmentLayout(attachment)
        }
        closePopover(commit: false)
    }

    private func updatePopoverSize() {
        guard !isClosing else { return }
        guard let editor = textView,
              let popover,
              let host = hostTextView,
              let widthConstraint,
              let heightConstraint,
              let container = editor.textContainer,
              let layout = editor.layoutManager else { return }
        let fallbackWidth = max(120, host.bounds.width)
        let baseWidth = baseSize.width > 1 ? baseSize.width : fallbackWidth
        let baseHeight = baseSize.height > 1 ? baseSize.height : max(32, host.bounds.height)
        let heightCap = maxHeight > 1 ? maxHeight : CGFloat.greatestFiniteMagnitude
        let maxWidth = max(baseWidth, self.maxWidth > 1 ? self.maxWidth : baseWidth)
        let insets = editor.textContainerInset
        let availableMax = max(20, maxWidth - (insets.width * 2))

        container.containerSize = NSSize(width: availableMax, height: CGFloat.greatestFiniteMagnitude)
        layout.ensureLayout(for: container)
        let used = layout.usedRect(for: container)
        let usedWidth = used.width
        guard usedWidth.isFinite else { return }
        let requiredWidth = min(maxWidth, ceil(usedWidth + (insets.width * 2)))
        let targetWidth = max(baseWidth, requiredWidth)

        container.containerSize = NSSize(width: max(20, targetWidth - (insets.width * 2)),
                                         height: CGFloat.greatestFiniteMagnitude)
        layout.ensureLayout(for: container)
        let usedWrapped = layout.usedRect(for: container)
        let usedHeight = usedWrapped.height
        guard usedHeight.isFinite else { return }
        let requiredHeight = ceil(usedHeight + (insets.height * 2))
        let targetHeight = min(heightCap, max(baseHeight, requiredHeight))

        let targetSize = NSSize(width: targetWidth, height: targetHeight)
        if editor.frame.size != targetSize {
            editor.setFrameSize(targetSize)
        }

        var didUpdate = false
        if targetWidth > widthConstraint.constant + 1 {
            widthConstraint.constant = targetWidth
            didUpdate = true
        }
        if abs(targetHeight - heightConstraint.constant) > 1 {
            heightConstraint.constant = targetHeight
            didUpdate = true
        }
        if let scrollView = scrollView {
            let needsScroll = requiredHeight > targetHeight + 1
            scrollView.hasVerticalScroller = needsScroll
            scrollView.autohidesScrollers = true
        }
        guard didUpdate else { return }
        popover.contentSize = NSSize(width: widthConstraint.constant, height: heightConstraint.constant)
        popover.contentViewController?.view.needsLayout = true
        popover.contentViewController?.view.layoutSubtreeIfNeeded()
        if !lastPreviewRect.isEmpty, rectIsFinite(lastPreviewRect) {
            schedulePopoverRepositionIfNeeded(lastPreviewRect, in: host)
        }
    }

    private func adjustPopoverToAvoidPreview(_ preview: NSRect, in textView: AnnotationTextView) {
        guard !isClosing else { return }
        guard let popoverWindow = popover?.contentViewController?.view.window,
              let hostWindow = textView.window else { return }
        guard rectIsFinite(preview) else { return }
        let windowRect = textView.convert(preview, to: nil)
        guard rectIsFinite(windowRect) else { return }
        let screenRect = hostWindow.convertToScreen(windowRect)
        guard rectIsFinite(screenRect) else { return }
        let gap = popoverGap + previewClearance
        var avoidRect = screenRect.insetBy(dx: -previewClearance, dy: -previewClearance)
        avoidRect = avoidRect.insetBy(dx: -previewClearance, dy: -previewClearance)
        guard rectIsFinite(avoidRect) else { return }

        let originalFrame = popoverWindow.frame
        var popFrame = originalFrame
        var attempts = 0
        while popFrame.intersects(avoidRect), attempts < 4 {
            if popFrame.midY <= avoidRect.midY {
                let overlap = popFrame.maxY - avoidRect.minY
                popFrame.origin.y -= (overlap + gap)
            } else {
                let overlap = avoidRect.maxY - popFrame.minY
                popFrame.origin.y += (overlap + gap)
            }
            attempts += 1
        }

        let visible = hostWindow.screen?.visibleFrame ?? NSScreen.main?.visibleFrame ?? hostWindow.frame
        if popFrame.maxY > visible.maxY { popFrame.origin.y = visible.maxY - popFrame.height }
        if popFrame.minY < visible.minY { popFrame.origin.y = visible.minY }
        let dx = abs(popFrame.origin.x - originalFrame.origin.x)
        let dy = abs(popFrame.origin.y - originalFrame.origin.y)
        if max(dx, dy) < popoverMoveThreshold { return }
        popoverWindow.setFrame(popFrame, display: true, animate: false)
    }

    private func installClickMonitor() {
        guard clickMonitor == nil else { return }
        clickMonitor = NSEvent.addLocalMonitorForEvents(matching: [.leftMouseDown]) { [weak self] event in
            guard let self, let popover = self.popover, popover.isShown else { return event }
            guard let popoverWindow = popover.contentViewController?.view.window else { return event }
            if event.window === popoverWindow {
                if let editor = self.textView, popoverWindow.firstResponder !== editor {
                    popoverWindow.makeFirstResponder(editor)
                }
                return event
            }
            self.closePopover(commit: true)
            return nil
        }
    }

    private func installKeyMonitor() {
        guard keyMonitor == nil else { return }
        keyMonitor = NSEvent.addLocalMonitorForEvents(matching: [.keyDown]) { [weak self] event in
            guard let self, let popover = self.popover, popover.isShown else { return event }
            if event.keyCode == 53 { // esc
                self.cancelEditing()
                return nil
            }
            return event
        }
    }

    private func removeClickMonitor() {
        if let monitor = clickMonitor {
            NSEvent.removeMonitor(monitor)
            clickMonitor = nil
        }
    }

    private func removeKeyMonitor() {
        if let monitor = keyMonitor {
            NSEvent.removeMonitor(monitor)
            keyMonitor = nil
        }
    }

    private func installHostTextObserver() {
        guard hostTextChangeObserver == nil, let host = hostTextView else { return }
        hostTextChangeObserver = NotificationCenter.default.addObserver(forName: NSText.didChangeNotification,
                                                                        object: host,
                                                                        queue: .main) { [weak self] _ in
            guard let self, !self.suppressHostSync else { return }
            self.syncPopoverToPreview()
        }
    }

    private func removeHostTextObserver() {
        if let observer = hostTextChangeObserver {
            NotificationCenter.default.removeObserver(observer)
            hostTextChangeObserver = nil
        }
    }

    private func syncPopoverToPreview() {
        guard !isClosing else { return }
        guard let host = hostTextView,
              let attachment = editingAttachment,
              popover?.isShown == true else { return }
        guard let previewRect = anchorRect(for: attachment, in: host),
              rectIsFinite(previewRect) else { return }
        schedulePopoverRepositionIfNeeded(previewRect, in: host)
    }

    private func schedulePopoverSizeUpdate() {
        guard !isClosing else { return }
        sizeUpdateWork?.cancel()
        let work = DispatchWorkItem { [weak self] in
            self?.updatePopoverSize()
        }
        sizeUpdateWork = work
        DispatchQueue.main.asyncAfter(deadline: .now() + popoverUpdateDelay, execute: work)
    }

    private func schedulePopoverRepositionIfNeeded(_ previewRect: NSRect, in host: AnnotationTextView) {
        guard !isClosing else { return }
        guard rectIsFinite(previewRect) else { return }
        if !lastPreviewRect.isEmpty {
            let dx = abs(previewRect.midX - lastPreviewRect.midX)
            let dy = abs(previewRect.midY - lastPreviewRect.midY)
            if dx < previewMoveThreshold && dy < previewMoveThreshold {
                return
            }
        }
        lastPreviewRect = previewRect
        repositionWork?.cancel()
        let work = DispatchWorkItem { [weak self, weak host] in
            guard let self, let host else { return }
            self.adjustPopoverToAvoidPreview(self.lastPreviewRect, in: host)
        }
        repositionWork = work
        DispatchQueue.main.asyncAfter(deadline: .now() + popoverUpdateDelay, execute: work)
    }

    private func scheduleAttachmentRefresh(_ attachment: InlineMathAttachment) {
        layoutRefreshWork?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self,
                  let editing = self.editingAttachment,
                  editing === attachment else { return }
            self.refreshAttachmentLayout(attachment)
        }
        layoutRefreshWork = work
        DispatchQueue.main.asyncAfter(deadline: .now() + popoverUpdateDelay, execute: work)
    }

    private func cancelPendingWork() {
        sizeUpdateWork?.cancel()
        sizeUpdateWork = nil
        repositionWork?.cancel()
        repositionWork = nil
        layoutRefreshWork?.cancel()
        layoutRefreshWork = nil
    }

    private func refreshAttachmentLayout(_ attachment: InlineMathAttachment) {
        guard let textView = hostTextView,
              let storage = textView.textStorage else { return }
        let full = NSRange(location: 0, length: storage.length)
        storage.enumerateAttribute(.attachment, in: full, options: []) { value, range, stop in
            if let att = value as? InlineMathAttachment, att === attachment {
                storage.edited(.editedAttributes, range: range, changeInLength: 0)
                textView.layoutManager?.invalidateLayout(forCharacterRange: range, actualCharacterRange: nil)
                textView.layoutManager?.invalidateDisplay(forCharacterRange: range)
                stop.pointee = true
            }
        }
        textView.didChangeText()
    }

    private func ensureTrailingSpace(after attachment: InlineMathAttachment) {
        guard let textView = hostTextView,
              let storage = textView.textStorage else { return }
        let full = NSRange(location: 0, length: storage.length)
        var target: NSRange?
        storage.enumerateAttribute(.attachment, in: full, options: []) { value, range, stop in
            if let att = value as? InlineMathAttachment, att === attachment {
                target = range
                stop.pointee = true
            }
        }
        guard let range = target else { return }
        let insertLocation = min(storage.length, range.location + range.length)
        if insertLocation < storage.length {
            let next = (storage.string as NSString).substring(with: NSRange(location: insertLocation, length: 1))
            if next == " " {
                textView.setSelectedRange(NSRange(location: insertLocation + 1, length: 0))
                textView.didChangeText()
                return
            }
        }
        let font = textView.font ?? PDFAnnotationRowMetrics.commentFont
        let color = textView.textColor ?? annotationDefaultForegroundColor()
        let attrs = inlineMathBaseAttributes(font: font, color: color)
        storage.beginEditing()
        storage.insert(NSAttributedString(string: " ", attributes: attrs), at: insertLocation)
        storage.endEditing()
        textView.setSelectedRange(NSRange(location: insertLocation + 1, length: 0))
        textView.didChangeText()
    }

    private func removeAttachment(_ attachment: InlineMathAttachment) {
        guard let textView = hostTextView,
              let storage = textView.textStorage else { return }
        let full = NSRange(location: 0, length: storage.length)
        var target: NSRange?
        storage.enumerateAttribute(.attachment, in: full, options: []) { value, range, stop in
            if let att = value as? InlineMathAttachment, att === attachment {
                target = range
                stop.pointee = true
            }
        }
        if let range = target {
            storage.deleteCharacters(in: range)
            textView.setSelectedRange(NSRange(location: range.location, length: 0))
            textView.didChangeText()
        }
    }

    private func cleanup() {
        removeClickMonitor()
        removeKeyMonitor()
        removeHostTextObserver()
        cancelPendingWork()
        editingAttachment = nil
        originalSource = ""
        cancelled = false
        isClosing = false
        suppressHostSync = false
        lastPreviewRect = .zero
    }
}

final class AnnotationToolbarButtonCell: NSButtonCell {
    var iconBoxSize: CGFloat = 12

    override func imageRect(forBounds rect: NSRect) -> NSRect {
        let size = min(iconBoxSize, min(rect.width, rect.height))
        let origin = NSPoint(x: rect.midX - size / 2, y: rect.midY - size / 2)
        return NSRect(origin: origin, size: NSSize(width: size, height: size))
    }
}

final class AnnotationToolbarTextFieldCell: NSTextFieldCell {
    override func drawingRect(forBounds rect: NSRect) -> NSRect {
        centeredRect(forBounds: rect)
    }

    override func titleRect(forBounds rect: NSRect) -> NSRect {
        centeredRect(forBounds: rect)
    }

    private func centeredRect(forBounds rect: NSRect) -> NSRect {
        guard rect.height > 1 else { return rect }
        let fontToUse = font ?? NSFont.systemFont(ofSize: NSFont.systemFontSize)
        let textSize = (stringValue as NSString).size(withAttributes: [.font: fontToUse])
        let lineHeight = max(1, fontLineHeight(fontToUse))
        let targetHeight = min(rect.height, max(textSize.height, lineHeight))
        let offset = (rect.height - targetHeight) * 0.5
        return NSRect(x: rect.origin.x,
                      y: rect.origin.y + offset,
                      width: rect.width,
                      height: targetHeight)
    }
}

final class AnnotationToolbarTextField: NSTextField {
    override class var cellClass: AnyClass? {
        get { AnnotationToolbarTextFieldCell.self }
        set { }
    }
}

final class AnnotationToolbarIconButton: NSButton {
    override class var cellClass: AnyClass? {
        get { AnnotationToolbarButtonCell.self }
        set { }
    }

    var iconBoxSize: CGFloat = 12 {
        didSet {
            (cell as? AnnotationToolbarButtonCell)?.iconBoxSize = iconBoxSize
        }
    }
}

final class AnnotationComposerResizeHandleView: NSView {
    var strokeColor: NSColor = NSColor.white.withAlphaComponent(0.25) {
        didSet { needsDisplay = true }
    }
    var onDragStart: ((NSPoint) -> Void)?
    var onDrag: ((NSPoint) -> Void)?
    var onDragEnd: (() -> Void)?

    override var acceptsFirstResponder: Bool { false }

    override func resetCursorRects() {
        addCursorRect(bounds, cursor: .resizeLeftRight)
    }

    override func mouseDown(with event: NSEvent) {
        onDragStart?(event.locationInWindow)
    }

    override func mouseDragged(with event: NSEvent) {
        onDrag?(event.locationInWindow)
    }

    override func mouseUp(with event: NSEvent) {
        onDragEnd?()
    }

    override func draw(_ dirtyRect: NSRect) {
        PerfLogger.begin("draw.annotation_resize_handle")
        defer { PerfLogger.end("draw.annotation_resize_handle") }
        super.draw(dirtyRect)
        let inset: CGFloat = 2
        let lineLength: CGFloat = 8
        let lineSpacing: CGFloat = 3
        let base = NSPoint(x: bounds.maxX - inset, y: bounds.minY + inset)

        strokeColor.setStroke()
        for idx in 0..<2 {
            let offset = CGFloat(idx) * lineSpacing
            let start = NSPoint(x: base.x - offset, y: base.y + offset)
            let end = NSPoint(x: start.x - lineLength, y: start.y + lineLength)
            let path = NSBezierPath()
            path.lineWidth = 1
            path.move(to: start)
            path.line(to: end)
            path.stroke()
        }
    }
}

final class AnnotationComposerResizeOverlayView: NSView {
    enum Region {
        case left
        case right
        case bottom
        case bottomLeft
        case bottomRight
    }

    var edgeThickness: CGFloat = 6
    var cornerSize: CGFloat = 14
    var onDragStart: ((Region, NSPoint) -> Void)?
    var onDrag: ((NSPoint) -> Void)?
    var onDragEnd: (() -> Void)?

    private var activeRegion: Region?

    private static func diagonalCursor(symbolName: String) -> NSCursor? {
        let config = NSImage.SymbolConfiguration(pointSize: 12, weight: .regular)
        guard let image = NSImage(systemSymbolName: symbolName, accessibilityDescription: nil)?
            .withSymbolConfiguration(config) else { return nil }
        image.isTemplate = true
        let size = NSSize(width: 16, height: 16)
        image.size = size
        let hotSpot = NSPoint(x: size.width / 2, y: size.height / 2)
        return NSCursor(image: image, hotSpot: hotSpot)
    }

    private lazy var cursorDiagonalLeft: NSCursor = {
        AnnotationComposerResizeOverlayView.diagonalCursor(symbolName: "arrow.up.right.and.arrow.down.left")
            ?? NSCursor.resizeLeftRight
    }()

    private lazy var cursorDiagonalRight: NSCursor = {
        AnnotationComposerResizeOverlayView.diagonalCursor(symbolName: "arrow.up.left.and.arrow.down.right")
            ?? NSCursor.resizeLeftRight
    }()

    private func region(for point: NSPoint) -> Region? {
        let w = bounds.width
        let h = bounds.height
        guard w > 1, h > 1 else { return nil }
        let t = max(4, edgeThickness)
        let c = max(t + 2, cornerSize)

        let isLeft = point.x <= t
        let isRight = point.x >= (w - t)
        let isBottom = point.y <= t
        let isBottomLeft = point.x <= c && point.y <= c
        let isBottomRight = point.x >= (w - c) && point.y <= c

        if isBottomLeft { return .bottomLeft }
        if isBottomRight { return .bottomRight }
        if isLeft { return .left }
        if isRight { return .right }
        if isBottom { return .bottom }
        return nil
    }

    override func hitTest(_ point: NSPoint) -> NSView? {
        region(for: point) != nil ? self : nil
    }

    override func resetCursorRects() {
        let w = bounds.width
        let h = bounds.height
        guard w > 1, h > 1 else { return }
        let t = max(4, edgeThickness)
        let c = max(t + 2, cornerSize)

        let bottomLeftRect = NSRect(x: 0, y: 0, width: c, height: c)
        let bottomRightRect = NSRect(x: w - c, y: 0, width: c, height: c)
        addCursorRect(bottomLeftRect, cursor: cursorDiagonalLeft)
        addCursorRect(bottomRightRect, cursor: cursorDiagonalRight)

        let leftRect = NSRect(x: 0, y: c, width: t, height: h - c)
        let rightRect = NSRect(x: w - t, y: c, width: t, height: h - c)
        addCursorRect(leftRect, cursor: .resizeLeftRight)
        addCursorRect(rightRect, cursor: .resizeLeftRight)

        let bottomRect = NSRect(x: c, y: 0, width: w - (2 * c), height: t)
        addCursorRect(bottomRect, cursor: .resizeUpDown)
    }

    override func mouseDown(with event: NSEvent) {
        let point = convert(event.locationInWindow, from: nil)
        guard let region = region(for: point) else { return }
        activeRegion = region
        onDragStart?(region, event.locationInWindow)
    }

    override func mouseDragged(with event: NSEvent) {
        guard activeRegion != nil else { return }
        onDrag?(event.locationInWindow)
    }

    override func mouseUp(with event: NSEvent) {
        activeRegion = nil
        onDragEnd?()
    }
}

