    private var cachedIconColor: NSColor = annotationDefaultForegroundColor()
    private var cachedDeleteColor: NSColor = NSColor.systemRed
    private var cachedTagBackgroundColor: NSColor = NSColor.black.withAlphaComponent(0.12)
    private var contentInsetConstraints: (top: NSLayoutConstraint,
                                         bottom: NSLayoutConstraint,
                                         leading: NSLayoutConstraint,
                                         trailing: NSLayoutConstraint)?
    private var pageNumberValue: String?
    private var pageNumberEditable: Bool = true
    private var isEditingPageNumber: Bool = false
    private var suppressPageNumberCallbacks: Bool = false
    private var notePositionValue: (index: Int, total: Int) = (1, 1)
    private var resizeStartPoint: NSPoint = .zero
    private var resizeStartSize: NSSize = .zero
    private var resizeStartWindowFrame: NSRect = .zero
    private var resizeConstraintBounds: NSRect?
    private var resizeAnchorCenterX: CGFloat = 0
    private var resizeAnchorTopY: CGFloat = 0
    private var activeResizeRegion: AnnotationComposerResizeOverlayView.Region?
    private var isLiveResizing = false
    private var pendingResizeSize: NSSize = .zero
    private var lockedContentInsets: (top: CGFloat, bottom: CGFloat, leading: CGFloat, trailing: CGFloat)?
    private var creationTimestamp: Date?
    var onResizeRequested: ((NSSize) -> Void)?
    private var appearanceObservers: [Any] = []
    private var presentationID: Int = 0
    private var preparedPresentationID: Int = -1
