    var isInlineMathPopupVisible: Bool {
        textView.isInlineMathPopupVisible
    }

    func isInlineMathEvent(_ event: NSEvent) -> Bool {
        textView.isInlineMathEvent(event)
    }

    func closeInlineMathPopup(commit: Bool) {
        textView.closeInlineMathPopup(commit: commit)
    }

    func consumeInlineMathSubmitSuppression(matching event: NSEvent) -> Bool {
        textView.consumeInlineMathSubmitSuppression(matching: event)
    }

    private func composerTintColor() -> NSColor {
        let fallback = annotationComposerTintColorSetting()
        if let glass = view as? GlassCardView, let tint = glass.config.tint {
            return tint
        }
        if #available(macOS 26.0, *), let glass = view as? NSGlassEffectView, let tint = glass.tintColor {
            return tint
        }
        if let effect = view as? NSVisualEffectView,
           let cg = effect.layer?.backgroundColor,
           let tint = NSColor(cgColor: cg) {
            return tint
        }
        return fallback
    }

    private func composerEffectiveBackgroundColor() -> NSColor {
        let base = windowBackgroundSolidColor()
        let tint = composerTintColor()
        let tintRGB = (tint.usingColorSpace(.deviceRGB) ?? tint)
        let alpha = max(0.0, min(1.0, tintRGB.alphaComponent))
        let bias = max(0.3, min(0.85, alpha * 1.4))
        let biasedBase = blend(base, tintRGB.withAlphaComponent(1.0), t: bias)
        let pair = glassBackgroundPair(base: biasedBase, tint: tintRGB, intensity: 1.0)
        return pair.alt ?? pair.primary
    }

    private func applyButtonTitleColors() {
        updateUnderlineButtonLabel()
        if let delete = deleteButton {
            delete.foregroundColor = cachedDeleteColor
            delete.fillColor = cachedTagBackgroundColor
        }
    }

    private func makeToolbarButton(symbolName: String,
                                   tooltip: String,
                                   action: Selector,
                                   target: AnyObject? = nil,
                                   iconScale: CGFloat = 1.0) -> NSButton {
        let button = AnnotationToolbarIconButton()
        let iconBoxSize = max(1, toolbarIconBoxSize)
        let scaledIconSize = max(1, toolbarIconBoxSize * iconScale)
        button.iconBoxSize = iconBoxSize
        if let cell = button.cell as? AnnotationToolbarButtonCell {
            cell.iconBoxSize = iconBoxSize
        }
        button.translatesAutoresizingMaskIntoConstraints = false
        button.title = ""
        let config = NSImage.SymbolConfiguration(pointSize: toolbarIconPointSize * iconScale, weight: .semibold)
        let image = NSImage(systemSymbolName: symbolName, accessibilityDescription: tooltip)?
            .withSymbolConfiguration(config)
        if let image {
            image.size = NSSize(width: scaledIconSize, height: scaledIconSize)
        }
        button.image = image
        button.imagePosition = .imageOnly
        button.setButtonType(.momentaryChange)
        button.imageScaling = .scaleNone
        button.isBordered = false
        button.bezelStyle = .regularSquare
        button.focusRingType = .none
        button.refusesFirstResponder = true
        button.controlSize = .small
        button.setAccessibilityLabel(tooltip)
        button.toolTip = nil
        button.contentTintColor = cachedIconColor
        button.wantsLayer = true
        button.layer?.cornerRadius = 5
        button.layer?.backgroundColor = NSColor.clear.cgColor
        button.layer?.masksToBounds = true
        button.target = target ?? textView
        button.action = action
        let width = button.widthAnchor.constraint(equalToConstant: toolbarButtonSide)
        let height = button.heightAnchor.constraint(equalToConstant: toolbarButtonSide)
        width.isActive = true
        height.isActive = true
        toolbarButtonWidthConstraints.append(width)
        toolbarButtonHeightConstraints.append(height)
        toolbarButtons.append(button)
        return button
    }

    private func makeToolbarSeparator() -> NSView {
        let separator = NSView()
        separator.translatesAutoresizingMaskIntoConstraints = false
        separator.wantsLayer = true
        separator.layer?.cornerRadius = 0.5
        separator.layer?.backgroundColor = cachedForegroundColor.withAlphaComponent(0.12).cgColor
        separator.widthAnchor.constraint(equalToConstant: 1).isActive = true
        separator.heightAnchor.constraint(equalToConstant: 16).isActive = true
        toolbarSeparators.append(separator)
        return separator
    }

    private func normalizedPageNumber(_ value: String) -> String {
        value.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func updatePageNumberFieldIfNeeded(force: Bool) {
        guard let field = pageNumberField else { return }
        if isEditingPageNumber && !force {
            return
        }
        let display = normalizedPageNumber(pageNumberValue ?? "")
        if !force, field.stringValue == display {
            return
        }
        suppressPageNumberCallbacks = true
        field.stringValue = display
        updatePageNumberFieldWidth(for: display)
        field.isEditable = pageNumberEditable
        field.isSelectable = pageNumberEditable
        field.alphaValue = pageNumberEditable ? 1.0 : 0.6
        suppressPageNumberCallbacks = false
    }

    private func updatePageNumberFieldWidth(for value: String) {
        guard let field = pageNumberField else { return }
        let font = field.font ?? NSFont.systemFont(ofSize: 12, weight: .semibold)
        let measured = (value as NSString).size(withAttributes: [.font: font]).width
        let padding: CGFloat = 6
        let minWidth: CGFloat = 18
        pageFieldWidthConstraint?.constant = max(minWidth, ceil(measured + padding))
    }

    private func normalizedNotePosition(index: Int?, total: Int?) -> (index: Int, total: Int) {
        let baseTotal = total ?? notePositionValue.total
        let resolvedTotal = max(1, baseTotal)
        let baseIndex = index ?? notePositionValue.index
        let resolvedIndex = max(1, min(baseIndex, resolvedTotal))
        return (resolvedIndex, resolvedTotal)
    }

    private func updateNotePositionFieldIfNeeded(force: Bool) {
        guard let field = notePositionField else { return }
        let display = "Note \(notePositionValue.index)/\(notePositionValue.total)"
        if !force, field.stringValue == display {
            return
        }
        field.stringValue = display
    }

    func setNotePosition(index: Int?, total: Int?) {
        notePositionValue = normalizedNotePosition(index: index, total: total)
        updateNotePositionFieldIfNeeded(force: true)
    }

    func setCreationTimestamp(_ date: Date?) {
        creationTimestamp = date
        updateCreationTimestampLabels()
    }

    func setSelectedStyle(_ style: AnnotationMarkupStyle, color: NSColor? = nil) {
        selectedStyle = style
        if let color {
            selectedColor = color
            updateColorSelection()
        }
        updateUnderlineButtonLabel()
    }

    private func updateCreationTimestampLabels() {
        guard let dateLabel = creationDateLabel,
              let timeLabel = creationTimeLabel else { return }
        guard let timestamp = creationTimestamp else {
            dateLabel.stringValue = ""
            timeLabel.stringValue = ""
            dateLabel.isHidden = true
            timeLabel.isHidden = true
            return
        }
        dateLabel.stringValue = annotationCreationDateString(timestamp)
        timeLabel.stringValue = annotationCreationTimeString(timestamp)
        dateLabel.isHidden = false
        timeLabel.isHidden = false
    }

    func prepareForPresentation(presentationID: Int) {
        if !isViewLoaded { _ = view }
        self.presentationID = presentationID
        preparedPresentationID = presentationID
        selectedColor = initialColor
        selectedStyle = initialStyle
        prewarmInlineMathIfNeeded()
        if inlineMathTortureEnabled && initialText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            let torture = """
            Test 1 $7^{2/3}$ end
            Test 2 $x_i^2$ end
            Test 3 $\\frac{a}{b}$ end
            Test 4 $\\int_0^1 x^2\\,dx$ end
            Test 5 $\\sqrt{2}$ end
            """
            textView.setRawText(torture)
        } else {
            let baseFont = textView.font ?? PDFAnnotationRowMetrics.commentFont
            let baseColor = textView.textColor ?? annotationDefaultForegroundColor()
            if let payload = initialRichTextPayload,
               let attributed = annotationRichTextAttributedString(from: payload,
                                                                   baseFont: baseFont,
                                                                   textColor: baseColor) {
                textView.setRichText(attributed)
            } else {
                textView.setRawText(initialText)
            }
        }
        updateColorSelection()
        updateUnderlineButtonLabel()
        updateToolbarState()
        updatePageNumberFieldIfNeeded(force: true)
        updateCreationTimestampLabels()
        updateNotePositionFieldIfNeeded(force: true)
        scrollComposerToTop()
    }

    private func prepareForPresentationIfNeeded() {
        guard preparedPresentationID != presentationID else { return }
        prepareForPresentation(presentationID: presentationID)
    }

    func prewarmInlineMathIfNeeded() {
        let warmFont = textView.font ?? PDFAnnotationRowMetrics.commentFont
        let warmColor = textView.textColor ?? annotationDefaultForegroundColor()
        if !Self.inlineMathPrewarmed {
            KaTeXRenderer.shared.prewarm(fontSize: warmFont.pointSize,
                                         textColor: warmColor,
                                         fontFamily: inlineMathCSSFontFamily(warmFont))
            Self.inlineMathPrewarmed = true
        }
    }

    private func removeGlassCornerOutline(from view: NSView) {
        view.wantsLayer = true
        view.layer?.borderWidth = 0
        view.layer?.borderColor = NSColor.clear.cgColor
        if let glass = view as? GlassCardView {
            var next = glass.config
            var border = next.borderStyle
            border.rimWidth = 0
            border.outerWidth = 0
            border.innerWidth = 0
            border.rimLightAlpha = 0
            border.rimDarkAlpha = 0
            border.outerAlpha = 0
            border.innerAlpha = 0
            border.dispersionAlpha = 0
            next.borderStyle = border
            glass.config = next
        }
    }

    private func applyUniformToolbarButtonSizing() {
        guard !toolbarButtons.isEmpty else { return }
        let widths = toolbarButtons.map { max(1, $0.fittingSize.width) }
        let heights = toolbarButtons.map { max(1, $0.fittingSize.height) }
        let targetWidth = ceil(widths.max() ?? toolbarButtonSide)
        let targetHeight = ceil(heights.max() ?? toolbarButtonSide)
        for constraint in toolbarButtonWidthConstraints {
            constraint.constant = targetWidth
        }
        for constraint in toolbarButtonHeightConstraints {
            constraint.constant = targetHeight
        }
        toolbarRowHeightConstraint?.constant = targetHeight
        toolbarStackHeightConstraint?.constant = targetHeight
        pageRegionHeightConstraint?.constant = targetHeight
        noteRegionHeightConstraint?.constant = targetHeight
        view.needsLayout = true
    }

    private func resizeLimits() -> (min: NSSize, max: NSSize) {
        var minSize = NSSize(width: 500, height: 220)
        let screen = view.window?.screen ?? NSScreen.main
        let visible = screen?.visibleFrame ?? .zero
        var maxWidth = max(minSize.width, visible.width * 0.9)
        var maxHeight = max(minSize.height, visible.height * 0.85)

        if let bounds = currentResizeBounds(), bounds.width > 1, bounds.height > 1 {
            let anchorCenterX = resizeAnchorCenterX > 0 ? resizeAnchorCenterX : (view.window?.frame.midX ?? bounds.midX)
            let anchorTopY = resizeAnchorTopY > 0 ? resizeAnchorTopY : (view.window?.frame.maxY ?? bounds.maxY)
            let maxWidthFromBounds = 2 * min(anchorCenterX - bounds.minX, bounds.maxX - anchorCenterX)
            let maxHeightFromBounds = anchorTopY - bounds.minY
            if maxWidthFromBounds.isFinite, maxWidthFromBounds > 1 {
                maxWidth = min(maxWidth, maxWidthFromBounds)
            }
            if maxHeightFromBounds.isFinite, maxHeightFromBounds > 1 {
                maxHeight = min(maxHeight, maxHeightFromBounds)
            }
            minSize.width = min(minSize.width, maxWidth)
            minSize.height = min(minSize.height, maxHeight)
        }

        return (min: minSize, max: NSSize(width: maxWidth, height: maxHeight))
    }

    private func clampedSize(_ size: NSSize) -> NSSize {
        let limits = resizeLimits()
        let width = min(max(size.width, limits.min.width), limits.max.width)
        let height = min(max(size.height, limits.min.height), limits.max.height)
        return NSSize(width: width, height: height)
    }

    private func applyResize(_ size: NSSize, finalize: Bool) {
        let clamped = clampedSize(size)
        pendingResizeSize = clamped
        preferredContentSize = clamped
        if finalize || view.window == nil {
            onResizeRequested?(clamped)
        }
        if let window = view.window, resizeStartWindowFrame.width > 1 {
            let centerX = resizeAnchorCenterX > 0 ? resizeAnchorCenterX : resizeStartWindowFrame.midX
            let topY = resizeAnchorTopY > 0 ? resizeAnchorTopY : resizeStartWindowFrame.maxY
            var frame = window.frame
            frame.size = clamped
            frame.origin.x = centerX - (clamped.width * 0.5)
            frame.origin.y = topY - clamped.height
            window.setFrame(frame, display: true)
            enforcePopoverWindowShape()
        }
        view.needsLayout = true
    }

    private func beginResize(region: AnnotationComposerResizeOverlayView.Region, at windowPoint: NSPoint) {
        guard let window = view.window else { return }
        resizeStartPoint = window.convertPoint(toScreen: windowPoint)
        resizeStartSize = view.bounds.size
        resizeStartWindowFrame = window.frame
        resizeAnchorCenterX = resizeStartWindowFrame.midX
        resizeAnchorTopY = resizeStartWindowFrame.maxY
        resizeConstraintBounds = currentResizeBounds()
        activeResizeRegion = region
        isLiveResizing = true
        if let constraints = contentInsetConstraints {
            lockedContentInsets = (top: constraints.top.constant,
                                   bottom: constraints.bottom.constant,
                                   leading: constraints.leading.constant,
                                   trailing: constraints.trailing.constant)
        }
    }

    private func updateResize(at windowPoint: NSPoint) {
        guard let window = view.window else { return }
        guard let region = activeResizeRegion else { return }
        let current = window.convertPoint(toScreen: windowPoint)
        let dx = current.x - resizeStartPoint.x
        let dyDown = resizeStartPoint.y - current.y
        var nextWidth = resizeStartSize.width
        var nextHeight = resizeStartSize.height
        switch region {
        case .left:
            nextWidth = resizeStartSize.width - (dx * 2)
        case .right:
            nextWidth = resizeStartSize.width + (dx * 2)
        case .bottom:
            nextHeight = resizeStartSize.height + dyDown
        case .bottomLeft:
            nextWidth = resizeStartSize.width - (dx * 2)
            nextHeight = resizeStartSize.height + dyDown
        case .bottomRight:
            nextWidth = resizeStartSize.width + (dx * 2)
            nextHeight = resizeStartSize.height + dyDown
        }
        applyResize(NSSize(width: nextWidth, height: nextHeight), finalize: false)
    }

    private func endResize() {
        isLiveResizing = false
        activeResizeRegion = nil
        lockedContentInsets = nil
        resizeConstraintBounds = nil
        let target = pendingResizeSize == .zero ? view.bounds.size : pendingResizeSize
        applyResize(target, finalize: true)
        updateContentInsets()
    }

    private func currentResizeBounds() -> NSRect? {
        if let bounds = resizeConstraintBounds, bounds.width > 1, bounds.height > 1 {
            return bounds
        }
        return resizeBoundsProvider?()
    }

    private func updateNavigationButtonState() {
        toolbarBackButton?.isEnabled = (onNavigatePrevious != nil)
        toolbarForwardButton?.isEnabled = (onNavigateNext != nil)
    }

    func setPageNumberValue(_ value: String?, editable: Bool = true) {
        pageNumberValue = value
        pageNumberEditable = editable
        updatePageNumberFieldIfNeeded(force: true)
    }

    func updatePageNumberValue(_ value: String?) {
        pageNumberValue = value
        updatePageNumberFieldIfNeeded(force: false)
    }

    func isEditingPageNumberField(in window: NSWindow?) -> Bool {
        guard let field = pageNumberField, let window else { return false }
        if window.firstResponder === field { return true }
        if let editor = window.firstResponder as? NSTextView,
           editor.delegate === field {
            return true
        }
        return false
    }

    private func updateForegroundColors() {
        let background = composerEffectiveBackgroundColor()
        let primary = annotationDefaultForegroundColor()
        let secondary = primary
        let tertiary = primary
        let icon = primary
        let deleteColor = primary

        let previousForeground = cachedForegroundColor
        cachedForegroundColor = primary
        cachedIconColor = icon
        cachedDeleteColor = deleteColor
        let isLight = relativeLuminance(background) > 0.55
        let tagBase = isLight ? NSColor.black : NSColor.white
        let tagAlpha: CGFloat = isLight ? 0.08 : 0.12
        cachedTagBackgroundColor = tagBase.withAlphaComponent(tagAlpha)

        textView.textColor = primary
        textView.insertionPointColor = primary
        textView.setPayloadBase(font: textView.font ?? PDFAnnotationRowMetrics.commentFont,
                                color: primary)
        textView.updateTypingAttributes(font: textView.font ?? PDFAnnotationRowMetrics.commentFont,
                                        color: primary)
        for button in toolbarButtons {
            button.contentTintColor = icon
            button.layer?.backgroundColor = NSColor.clear.cgColor
        }
        for separator in toolbarSeparators {
            let alpha: CGFloat = isLight ? 0.16 : 0.12
            separator.layer?.backgroundColor = primary.withAlphaComponent(alpha).cgColor
        }
        applyButtonTitleColors()
        let metaColor = secondary
        if let field = pageNumberField {
            field.textColor = metaColor
            if let editor = field.currentEditor() as? NSTextView {
                editor.textColor = metaColor
                editor.insertionPointColor = metaColor
            }
        }
        if let label = pageLabelField {
            label.textColor = metaColor
        }
        if let separator = pageNoteSeparator {
            separator.layer?.backgroundColor = primary.withAlphaComponent(isLight ? 0.16 : 0.12).cgColor
        }
        if let noteField = notePositionField {
            noteField.textColor = metaColor
        }
        if let dateLabel = creationDateLabel {
            dateLabel.textColor = tertiary
        }
        if let timeLabel = creationTimeLabel {
            timeLabel.textColor = tertiary
        }
        if let handle = resizeHandle {
            handle.strokeColor = primary.withAlphaComponent(0.35)
        }

        if let storage = textView.textStorage,
           storage.length > 0,
           !colorsMatch(previousForeground, primary) {
            let full = NSRange(location: 0, length: storage.length)
            storage.beginEditing()
            storage.enumerateAttribute(.foregroundColor, in: full, options: []) { value, range, _ in
                if let color = value as? NSColor, colorsMatch(color, previousForeground) {
                    storage.addAttribute(.foregroundColor, value: primary, range: range)
                }
            }
            storage.endEditing()
            textView.refreshInlineMathAttachmentStyles(in: full)
        }
        updateToolbarState()
    }

    private func setToolbarButton(_ button: NSButton?, active: Bool) {
        guard let button else { return }
        let base = cachedIconColor
        button.layer?.backgroundColor = NSColor.clear.cgColor
        let candidate = base.withAlphaComponent(active ? 1.0 : 0.8)
        button.contentTintColor = candidate
        if ContrastDebug.enabled {
            ContrastDebug.logApplied(context: "annotation.toolbar.button",
                                     role: .icon,
                                     background: composerEffectiveBackgroundColor(),
                                     foreground: candidate,
                                     note: active ? "active" : "inactive")
        }
    }

    private func updateToolbarState() {
        guard isViewLoaded else { return }
        let boldActive = textView.toolbarIsBold()
        let italicActive = textView.toolbarIsItalic()
        let underlineActive = textView.toolbarIsUnderlined()
        let alignment = textView.toolbarAlignment()
        let listMarker = textView.toolbarListMarker()
        let numberActive = listMarker == .decimal
        let bulletActive: Bool = {
            guard let listMarker else { return false }
            return listMarker != .decimal
        }()

        let alignLeftActive = (alignment == .left || alignment == .natural)
        let alignCenterActive = alignment == .center
        let alignRightActive = alignment == .right

        setToolbarButton(toolbarBoldButton, active: boldActive)
        setToolbarButton(toolbarItalicButton, active: italicActive)
        setToolbarButton(toolbarUnderlineButton, active: underlineActive)
        setToolbarButton(toolbarBulletButton, active: bulletActive)
        setToolbarButton(toolbarNumberButton, active: numberActive)
        setToolbarButton(toolbarAlignLeftButton, active: alignLeftActive)
        setToolbarButton(toolbarAlignCenterButton, active: alignCenterActive)
        setToolbarButton(toolbarAlignRightButton, active: alignRightActive)

        if let paint = toolbarPaintButton {
            paint.layer?.backgroundColor = NSColor.clear.cgColor
            let paintColor = textView.toolbarTextColor()
            paint.contentTintColor = paintColor
            if ContrastDebug.enabled {
                ContrastDebug.logApplied(context: "annotation.toolbar.paint",
                                         role: .icon,
                                         background: composerEffectiveBackgroundColor(),
                                         foreground: paintColor,
                                         note: "paint")
            }
        }

        if let fontButton = toolbarFontButton {
            fontButton.layer?.backgroundColor = NSColor.clear.cgColor
            let display = textView.toolbarFontDisplayName().trimmingCharacters(in: .whitespacesAndNewlines)
            let tooltipText = display.isEmpty ? "Font" : display
            fontButton.setAccessibilityLabel(tooltipText)
            fontButton.toolTip = tooltipText
        }
    }

    func refreshForegroundColors() {
        updateForegroundColors()
    }

    func refreshGlassTint() {
        let tint = annotationComposerTintColorSetting()
        if let glass = view as? GlassCardView {
            var next = glass.config
            next.tint = tint
            glass.config = next
            return
        }
        if #available(macOS 26.0, *), let glass = view as? NSGlassEffectView {
            glass.tintColor = tint
            return
        }
        if let effect = view as? NSVisualEffectView {
            effect.layer?.backgroundColor = tint.cgColor
        }
    }

    private func updateContentInsets() {
        guard let constraints = contentInsetConstraints else { return }
        let resizing = isLiveResizing || (view.window?.inLiveResize == true)
        if resizing {
            if lockedContentInsets == nil {
                lockedContentInsets = (top: constraints.top.constant,
                                       bottom: constraints.bottom.constant,
                                       leading: constraints.leading.constant,
                                       trailing: constraints.trailing.constant)
            }
            if let locked = lockedContentInsets {
                constraints.leading.constant = locked.leading
                constraints.trailing.constant = locked.trailing
                constraints.top.constant = locked.top
                constraints.bottom.constant = locked.bottom
            }
            return
        }
        if lockedContentInsets != nil {
            lockedContentInsets = nil
        }
        let bounds = contentHostView?.bounds ?? view.bounds
        guard bounds.width > 1, bounds.height > 1 else { return }
        let insetX = max(0, bounds.width * 0.05)
        let insetY = max(0, bounds.height * 0.05)
        constraints.leading.constant = insetX
        constraints.trailing.constant = -insetX
        constraints.top.constant = insetY
        constraints.bottom.constant = -insetY
    }

    override func viewDidLayout() {
        super.viewDidLayout()
        updateContentInsets()
        enforcePopoverWindowShape()
        if tagDebugEnabled {
            let scrollFrame = composerScrollView?.frame ?? .zero
            let colorFrame = colorStackView?.frame ?? .zero
            let intersect = scrollFrame.intersects(colorFrame)
            annotationLog("Composer layout scroll=\(NSStringFromRect(scrollFrame)) colorStack=\(NSStringFromRect(colorFrame)) intersects=\(intersect)")
            if let content = contentView {
                let order = content.subviews.enumerated().map { idx, view in
                    "\(idx):\(type(of: view)) frame=\(NSStringFromRect(view.frame))"
                }.joined(separator: " | ")
                annotationLog("Composer subviews order: \(order)")
            }
            if let underline = underlineButton, let delete = deleteButton {
                annotationLog("Tag frames underline=\(NSStringFromRect(underline.frame)) delete=\(NSStringFromRect(delete.frame))")
            }
        }
    }

    override func viewWillLayout() {
        super.viewWillLayout()
        updateContentInsets()
    }

    override func loadView() {
        let glass = dropdownGlassFactory?() ?? AnnotationComposerViewController.makeFallbackDropdownGlass()
        glass.translatesAutoresizingMaskIntoConstraints = true
        glass.autoresizingMask = [.width, .height]
        glass.wantsLayer = true
        if #available(macOS 10.13, *) {
            glass.layer?.cornerCurve = .continuous
        }
        removeGlassCornerOutline(from: glass)

        let contentHost = NSView()
        contentHost.translatesAutoresizingMaskIntoConstraints = false
        let content = NSView()
        content.translatesAutoresizingMaskIntoConstraints = false
        contentView = content
        if #available(macOS 26.0, *), let glassView = glass as? NSGlassEffectView {
            glassView.contentView = contentHost
        } else if let effect = glass as? NSVisualEffectView {
            effect.addSubview(contentHost)
        } else {
            glass.addSubview(contentHost)
        }
        contentHost.addSubview(content)
        let resizeGrip = AnnotationComposerResizeHandleView()
        resizeGrip.translatesAutoresizingMaskIntoConstraints = false
        resizeGrip.strokeColor = cachedForegroundColor.withAlphaComponent(0.35)
        resizeGrip.isHidden = true
        resizeGrip.onDragStart = { [weak self] point in
            self?.beginResize(region: .bottomRight, at: point)
        }
