    static func makeFallbackDropdownGlass() -> NSView {
        var config = GlassCardKit.GlassCardConfig()
        config.transmission = DROPDOWN_GLASS_TRANSMISSION
        config.diffusionAmount = DROPDOWN_GLASS_DIFFUSION_AMOUNT
        config.cornerRadius = 12
        config.tint = annotationComposerTintColorSetting()
        let card = GlassCardKit.makeGlassCard(config: config) { _, _ in nil }
        card.translatesAutoresizingMaskIntoConstraints = true
        card.wantsLayer = true
        if #available(macOS 10.13, *) {
            card.layer?.cornerCurve = .continuous
        }
        return card
    }

    override func viewDidAppear() {
        super.viewDidAppear()
        debugLog("AnnotationComposerViewController viewDidAppear")
        installAppearanceObserversIfNeeded()
        updateContentInsets()
        updateForegroundColors()
        enforcePopoverWindowShape()
        installTagClickMonitor()
        prepareForPresentationIfNeeded()
        // Ensure the popover window is key and text view is first responder
        self.view.window?.makeKeyAndOrderFront(nil)
        self.view.window?.makeFirstResponder(textView)
        debugLog("Made popover window key and set first responder in viewDidAppear")
    }

    private func enforcePopoverWindowShape() {
        guard let window = view.window,
              let contentView = window.contentView,
              let frameView = contentView.superview else { return }
        frameView.wantsLayer = true
        if #available(macOS 10.13, *) {
            frameView.layer?.cornerCurve = .continuous
        }
        let setValueIfPossible: (NSObject, String, Any) -> Void = { object, key, value in
            guard let first = key.unicodeScalars.first else { return }
            let selector = NSSelectorFromString("set\(String(first).uppercased())\(String(key.dropFirst())):")
            guard object.responds(to: selector) else { return }
            object.setValue(value, forKey: key)
        }
        if let obj = frameView as? NSObject {
            setValueIfPossible(obj, "drawsArrow", false)
            setValueIfPossible(obj, "hasArrow", false)
            setValueIfPossible(obj, "arrowHeight", 0)
            setValueIfPossible(obj, "arrowWidth", 0)
            setValueIfPossible(obj, "arrowOffset", 0)
        }
        let bounds = frameView.bounds.integral
        guard bounds.width > 0, bounds.height > 0 else { return }
        let desiredRadius: CGFloat = {
            if let glass = view as? GlassCardView {
                return glass.config.cornerRadius
            }
            if let radius = view.layer?.cornerRadius, radius > 0 {
                return radius
            }
            return 12
        }()
        let maxRadius = max(0, min(desiredRadius, min(bounds.width, bounds.height) * 0.5))
        let maskLayer = (frameView.layer?.mask as? CAShapeLayer) ?? CAShapeLayer()
        maskLayer.frame = bounds
        maskLayer.path = CGPath(roundedRect: bounds,
                                cornerWidth: maxRadius,
                                cornerHeight: maxRadius,
                                transform: nil)
        frameView.layer?.mask = maskLayer
        frameView.layer?.masksToBounds = true

        contentView.translatesAutoresizingMaskIntoConstraints = true
        contentView.autoresizingMask = [.width, .height]
        if contentView.frame != frameView.bounds {
            contentView.frame = frameView.bounds
        }
    }

    private func installTagClickMonitor() {
        guard tagClickMonitor == nil else { return }
        tagClickMonitor = NSEvent.addLocalMonitorForEvents(matching: .leftMouseDown) { [weak self] event in
            guard let self else { return event }
            guard let window = self.view.window, event.window === window else { return event }
            guard let stack = self.colorStackView,
                  let underline = self.underlineButton,
                  let delete = self.deleteButton else { return event }
            let pointInStack = stack.convert(event.locationInWindow, from: nil)
            if underline.frame.contains(pointInStack) {
                if tagDebugEnabled { annotationLog("TagClickMonitor routed to tag_aa point=\(NSStringFromPoint(pointInStack))") }
                self.onUnderlineTapped(nil)
                return nil
            }
            if delete.frame.contains(pointInStack) {
                if tagDebugEnabled { annotationLog("TagClickMonitor routed to tag_trash point=\(NSStringFromPoint(pointInStack))") }
                self.onDeleteTapped(nil)
                return nil
            }
            return event
        }
    }

    private func removeTagClickMonitor() {
        if let monitor = tagClickMonitor {
            NSEvent.removeMonitor(monitor)
            tagClickMonitor = nil
        }
    }

    private func installAppearanceObserversIfNeeded() {
        guard appearanceObservers.isEmpty else { return }
        let center = NotificationCenter.default
        appearanceObservers.append(center.addObserver(
            forName: Notification.Name("NSApplicationDidChangeEffectiveAppearanceNotification"),
            object: nil,
            queue: .main
        ) { [weak self] _ in
            self?.refreshGlassTint()
            self?.updateForegroundColors()
        })
        appearanceObservers.append(center.addObserver(
            forName: NSColor.systemColorsDidChangeNotification,
            object: nil,
            queue: .main
        ) { [weak self] _ in
            self?.refreshGlassTint()
            self?.updateForegroundColors()
        })
    }

    private func removeAppearanceObservers() {
        guard !appearanceObservers.isEmpty else { return }
        let center = NotificationCenter.default
        for observer in appearanceObservers {
            center.removeObserver(observer)
        }
        appearanceObservers.removeAll()
    }

    override func viewWillDisappear() {
        super.viewWillDisappear()
        textView.cleanupFormattingPanels()
        removeTagClickMonitor()
        removeAppearanceObservers()
    }

    private func scrollComposerToTop() {
        guard let storage = textView.textStorage else { return }
        let start = NSRange(location: 0, length: 0)
        textView.setSelectedRange(start)
        textView.scrollRangeToVisible(start)
        if let container = textView.textContainer {
            textView.layoutManager?.ensureLayout(for: container)
        }
        if let scroll = composerScrollView {
            let clip = scroll.contentView
            var origin = clip.bounds.origin
            origin.y = 0
            clip.setBoundsOrigin(origin)
            scroll.reflectScrolledClipView(clip)
        }
    }

    private func onSelectColor(_ sender: ColorButtonView) {
        debugLog("Color button clicked: \(sender)")
        let palette = paletteColors()
        guard let idx = colorButtons.firstIndex(of: sender), idx < palette.count else { debugLog("Color button index not found"); return }
        selectedColor = palette[idx]
        updateColorSelection()
        updateUnderlineButtonLabel()
        onColorChanged?(selectedColor, selectedStyle)
        debugLog("Selected color: \(selectedColor), current selection: \(String(describing: view.window?.firstResponder))")
    }

    private func updateColorSelection() {
        let palette = paletteColors()
        for (idx, button) in colorButtons.enumerated() where idx < palette.count {
            let base = palette[idx].usingColorSpace(.deviceRGB)
            let target = selectedColor.usingColorSpace(.deviceRGB)
            let isSelected = {
                guard let base, let target else { return false }
                return abs(base.redComponent - target.redComponent) < 0.001 &&
                       abs(base.greenComponent - target.greenComponent) < 0.001 &&
                       abs(base.blueComponent - target.blueComponent) < 0.001 &&
                       abs(base.alphaComponent - target.alphaComponent) < 0.001
            }()
            button.isSelected = isSelected
        }
    }

    @objc private func onNavigatePreviousTapped(_ sender: NSButton) {
        onNavigatePrevious?()
    }

    @objc private func onNavigateNextTapped(_ sender: NSButton) {
        onNavigateNext?()
    }

    @objc private func onUnderlineTapped(_ sender: Any?) {
        let targetStyle: AnnotationMarkupStyle = (selectedStyle == .underline) ? .highlight : .underline
        if tagDebugEnabled {
            let mode = (onToggleStyleRequested == nil) ? "inline" : "command"
            #if DEBUG
            let targetID = debugTargetAnnotationID ?? "unknown"
            annotationLog("Underline tag tapped; mode=\(mode) target=\(targetID) currentStyle=\(selectedStyle.rawValue) targetStyle=\(targetStyle.rawValue) color=\(selectedColor)")
            #else
            annotationLog("Underline tag tapped; mode=\(mode) currentStyle=\(selectedStyle.rawValue) target=\(targetStyle.rawValue) color=\(selectedColor)")
            #endif
        }
        annotationActionLog("tag=aa_tapped currentStyle=\(selectedStyle.rawValue) target=\(targetStyle.rawValue)")
        if let onToggleStyleRequested {
            onToggleStyleRequested()
            return
        }
        selectedStyle = targetStyle
        updateUnderlineButtonLabel()
        onStyleChanged?(selectedStyle, selectedColor)
    }

    private func updateUnderlineButtonLabel() {
        guard let underline = underlineButton else { return }
        let targetStyle: AnnotationMarkupStyle = (selectedStyle == .underline) ? .highlight : .underline
        let rawColor = selectedColor.usingColorSpace(.deviceRGB) ?? selectedColor
        let baseColor = (rawColor.alphaComponent < 0.01) ? NSColor.systemYellow : rawColor
        let accentColor: NSColor
        switch targetStyle {
        case .highlight:
            let alpha: CGFloat = isAppLightAppearance() ? 0.65 : 0.55
            accentColor = baseColor.withAlphaComponent(alpha)
        case .underline:
            accentColor = baseColor.withAlphaComponent(1.0)
        }
        underline.setText("Aa")
        underline.isEmphasized = (targetStyle == .highlight)
        underline.isUnderlined = (targetStyle == .underline)
        underline.underlineColorOverride = (targetStyle == .underline) ? accentColor : nil
        underline.foregroundColor = cachedForegroundColor
        underline.fillColor = (targetStyle == .highlight) ? accentColor : cachedTagBackgroundColor
    }

    @objc private func onDeleteTapped(_ sender: Any?) {
        if tagDebugEnabled { annotationLog("Delete tag tapped") }
        annotationActionLog("tag=trash_tapped")
        onDelete?()
    }

    func controlTextDidBeginEditing(_ obj: Notification) {
        guard let field = obj.object as? NSTextField, field === pageNumberField else { return }
        isEditingPageNumber = true
        updatePageNumberFieldWidth(for: field.stringValue)
        if let editor = field.currentEditor() as? NSTextView {
            editor.textColor = cachedForegroundColor
            editor.insertionPointColor = cachedForegroundColor
            var attrs = editor.typingAttributes
            attrs[.foregroundColor] = cachedForegroundColor
            editor.typingAttributes = attrs
        }
    }

    func controlTextDidChange(_ obj: Notification) {
        guard let field = obj.object as? NSTextField, field === pageNumberField else { return }
        guard !suppressPageNumberCallbacks else { return }
        let value = normalizedPageNumber(field.stringValue)
        if value == pageNumberValue { return }
        pageNumberValue = value
        updatePageNumberFieldWidth(for: value)
        onPageNumberChanged?(value)
    }

    func controlTextDidEndEditing(_ obj: Notification) {
        guard let field = obj.object as? NSTextField, field === pageNumberField else { return }
        isEditingPageNumber = false
        let value = normalizedPageNumber(field.stringValue)
        if field.stringValue != value {
            suppressPageNumberCallbacks = true
            field.stringValue = value
            suppressPageNumberCallbacks = false
        }
        updatePageNumberFieldWidth(for: value)
        if value != pageNumberValue {
            pageNumberValue = value
            if !suppressPageNumberCallbacks {
                onPageNumberChanged?(value)
            }
        }
    }

    func submit() {
        textView.closeInlineMathPopup(commit: true)
        textView.cleanupFormattingPanels()
        let payload = textView.richTextPayload()
        let content = AnnotationCommentContent(plainText: textView.rawText(),
                                               richTextPayload: payload)
        // For existing annotations, avoid committing when nothing actually changed.
        if skipSubmitIfUnchanged && !isDirty(content: content, color: selectedColor, style: selectedStyle) {
            onCancel?()
            return
        }
        onSubmit?(content, selectedColor, selectedStyle)
    }

    func cancel() {
        textView.closeInlineMathPopup(commit: false)
        textView.cleanupFormattingPanels()
        onCancel?()
    }

    private func isDirty(content: AnnotationCommentContent, color: NSColor, style: AnnotationMarkupStyle) -> Bool {
        let initialTextNormalized = initialText.trimmingCharacters(in: .whitespacesAndNewlines)
        let currentTextNormalized = content.plainText.trimmingCharacters(in: .whitespacesAndNewlines)
        if initialTextNormalized != currentTextNormalized {
            return true
        }
        func normalizedPayload(_ payload: String?) -> String? {
            let trimmed = payload?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            return trimmed.isEmpty ? nil : trimmed
        }
        if normalizedPayload(initialRichTextPayload) != normalizedPayload(content.richTextPayload) {
            return true
        }
        if !colorsMatch(initialColor, color) {
            return true
        }
        if initialStyle != style {
            return true
        }
        return false
    }
}

// === AnnotationIconOverlayView (icons + highlight cursor regions; highlight clicks handled by PDFView) ===
final class AnnotationIconOverlayView: NSView {

    struct Icon {
        let annotation: PDFAnnotation
        let frame: CGRect
        let color: NSColor
    }

    struct HighlightRegion {
        let annotation: PDFAnnotation   // the PDF highlight annotation
        let frame: CGRect               // in overlay coordinates
        let pageIndex: Int              // stable page index captured at render time
    }

    var icons: [Icon] = [] {
        didSet { needsDisplay = true }
    }

    /// Regions corresponding to PDF highlight annotations (cursor + click hit-testing).
    var highlightRegions: [HighlightRegion] = [] {
        didSet {
            window?.invalidateCursorRects(for: self)
            needsDisplay = true
        }
    }

    var onIconTapped: ((PDFAnnotation) -> Void)?
    var onHighlightTapped: ((PDFAnnotation) -> Void)?
    weak var pdfView: ZoomablePDFView?

    private let highlightClickDragThreshold: CGFloat = 3
    private var highlightClickCandidate: PDFAnnotation?
    private var highlightClickStart: NSPoint?
    private var highlightClickDidDrag = false
    private var iconClickCandidate: Icon?
    private var cursorTrackingArea: NSTrackingArea?
    private let highlightHitDebugEnabled = ProcessInfo.processInfo.environment["ARXIV_HIGHLIGHT_HIT_DEBUG"] == "1"

    override var isOpaque: Bool { false }

    override init(frame frameRect: NSRect) {
        super.init(frame: frameRect)
        wantsLayer = true
        layer?.backgroundColor = NSColor.clear.cgColor
    }

    required init?(coder: NSCoder) { fatalError() }

    /// Icons and highlights are hit-testable; highlight events are forwarded to PDFView for selection.
    override func hitTest(_ point: NSPoint) -> NSView? {
        if iconHit(at: point) != nil {
            return self
        }
        if highlightAnnotation(at: point) != nil {
            return self
        }
        return nil
    }

    /// Cursor affordance over highlight regions (even though we click-through).
    override func resetCursorRects() {
        super.resetCursorRects()

        for region in highlightRegions {
            addCursorRect(region.frame, cursor: .pointingHand)
        }
    }

    override func mouseUp(with event: NSEvent) {
        let p = convert(event.locationInWindow, from: nil)
        if let icon = iconClickCandidate {
            iconClickCandidate = nil
            if icon.frame.contains(p) {
                onIconTapped?(icon.annotation)
            }
            return
        }

        pdfView?.mouseUp(with: event)
        defer {
            highlightClickCandidate = nil
            highlightClickStart = nil
            highlightClickDidDrag = false
        }

        guard let candidate = highlightClickCandidate else { return }
        guard !highlightClickDidDrag else { return }
        guard event.clickCount == 1 else { return }
        let mods = event.modifierFlags.intersection([.shift, .option, .command, .control])
        guard mods.isEmpty else { return }
        onHighlightTapped?(candidate)
    }

    override func mouseDown(with event: NSEvent) {
        let p = convert(event.locationInWindow, from: nil)
        if let icon = iconHit(at: p) {
            iconClickCandidate = icon
            highlightClickCandidate = nil
            highlightClickStart = nil
            highlightClickDidDrag = false
            return
        }

        iconClickCandidate = nil
        if let ann = highlightAnnotation(at: p) {
            highlightClickCandidate = ann
            highlightClickStart = p
            highlightClickDidDrag = false
            pdfView?.mouseDown(with: event)
            if highlightHitDebugEnabled {
                print("[HIGHLIGHT_HIT] mouseDown hit=\(ann.type ?? "-") point=\(NSStringFromPoint(p)) regions=\(highlightRegions.count)")
            }
        } else if highlightHitDebugEnabled {
            print("[HIGHLIGHT_HIT] mouseDown miss point=\(NSStringFromPoint(p)) regions=\(highlightRegions.count)")
        }
    }

    override func mouseDragged(with event: NSEvent) {
        if let start = highlightClickStart {
            let current = convert(event.locationInWindow, from: nil)
            if abs(current.x - start.x) > highlightClickDragThreshold ||
               abs(current.y - start.y) > highlightClickDragThreshold {
                highlightClickDidDrag = true
            }
        }
        pdfView?.mouseDragged(with: event)
    }

    override func rightMouseDown(with event: NSEvent) {
        pdfView?.rightMouseDown(with: event)
    }

    override func rightMouseUp(with event: NSEvent) {
        pdfView?.rightMouseUp(with: event)
    }

    override func otherMouseDown(with event: NSEvent) {
        pdfView?.otherMouseDown(with: event)
    }

    override func otherMouseUp(with event: NSEvent) {
        pdfView?.otherMouseUp(with: event)
    }

    override func scrollWheel(with event: NSEvent) {
        pdfView?.scrollWheel(with: event)
    }

    override func updateTrackingAreas() {
        super.updateTrackingAreas()
        if let area = cursorTrackingArea {
            removeTrackingArea(area)
        }
        let options: NSTrackingArea.Options = [
            .activeInKeyWindow,
            .cursorUpdate,
            .mouseMoved,
            .inVisibleRect
        ]
        let area = NSTrackingArea(rect: bounds, options: options, owner: self, userInfo: nil)
        addTrackingArea(area)
        cursorTrackingArea = area
    }

    override func cursorUpdate(with event: NSEvent) {
        let p = convert(event.locationInWindow, from: nil)
        if highlightAnnotation(at: p) != nil {
            NSCursor.pointingHand.set()
            return
        }
        pdfView?.cursorUpdate(with: event)
    }

    override func mouseMoved(with event: NSEvent) {
        cursorUpdate(with: event)
    }

    override func viewDidMoveToWindow() {
        super.viewDidMoveToWindow()
        window?.acceptsMouseMovedEvents = true
        window?.invalidateCursorRects(for: self)
    }

    private func iconHit(at point: NSPoint) -> Icon? {
        icons.first(where: { $0.frame.contains(point) })
    }

    private func highlightHit(at point: NSPoint) -> HighlightRegion? {
        let hits = highlightRegions.filter { $0.frame.contains(point) }
        return hits.min(by: { ($0.frame.width * $0.frame.height) < ($1.frame.width * $1.frame.height) })
    }

    private func highlightAnnotation(at point: NSPoint) -> PDFAnnotation? {
        if let region = highlightHit(at: point) {
            return region.annotation
        }
        return highlightAnnotationFromPDFView(at: point)
    }

    private func highlightAnnotationFromPDFView(at point: NSPoint) -> PDFAnnotation? {
        guard let pdfView else { return nil }
        let pointInView = pdfView.convert(point, from: self)
        guard let page = pdfView.page(for: pointInView, nearest: true) else { return nil }
        let pagePoint = pdfView.convert(pointInView, to: page)
        if let ann = page.annotation(at: pagePoint),
           annotationIsHighlightLike(ann) {
            return ann
        }
        for ann in page.annotations where annotationIsHighlightLike(ann) {
            if ann.bounds.contains(pagePoint) { return ann }
            if quadRects(for: ann).contains(where: { $0.contains(pagePoint) }) { return ann }
        }
        return nil
    }

    private func quadRects(for annotation: PDFAnnotation) -> [CGRect] {
        annotationQuadRects(for: annotation)
    }

    override func draw(_ dirtyRect: NSRect) {
        PerfLogger.begin("draw.annotation_overlay")
        defer { PerfLogger.end("draw.annotation_overlay") }
        super.draw(dirtyRect)
        guard let ctx = NSGraphicsContext.current?.cgContext else { return }

        // Draw sticky-note icons
        for icon in icons {
            let rect = icon.frame
            let path = NSBezierPath(ovalIn: rect)
            icon.color.setFill()
            path.fill()

            ctx.setLineWidth(1)
            NSColor.black.withAlphaComponent(0.25).setStroke()
            path.stroke()
        }

        // Draw underline marks only when PDFKit underlines are suppressed.
        for region in highlightRegions {
            let annotation = region.annotation
            guard annotationMarkupStyle(for: annotation) == .underline else { continue }
            let typeName = annotationTypeName(annotation)
            let alpha = annotation.color.alphaComponent
            let ca = (annotation.value(forAnnotationKey: PDFAnnotationKey(rawValue: "CA")) as? NSNumber)?.doubleValue ?? 1.0
            let needsOverlayUnderline = (typeName != "underline") || alpha <= 0.01 || ca <= 0.01
            guard needsOverlayUnderline else { continue }
            let rect = region.frame
            let baseColor = annotationDisplayBaseColor(for: annotation).usingColorSpace(.deviceRGB)
                ?? annotationDisplayBaseColor(for: annotation)
            let color = baseColor.withAlphaComponent(1.0)
            let lineWidth = max(1.0, annotation.border?.lineWidth ?? 1.4)
            ctx.setStrokeColor(color.cgColor)
            ctx.setLineWidth(lineWidth)
            let y = rect.minY + (lineWidth / 2)
            ctx.move(to: CGPoint(x: rect.minX, y: y))
            ctx.addLine(to: CGPoint(x: rect.maxX, y: y))
            ctx.strokePath()
        }

        // Draw highlight fills when PDFKit rendering is suppressed (overlay-only highlights).
        for region in highlightRegions {
            let annotation = region.annotation
            guard annotationMarkupStyle(for: annotation) == .highlight else { continue }
            let overlay = annotation.value(forAnnotationKey: annotationOverlayHighlightKey) as? Bool ?? false
            guard overlay else { continue }
            let rect = region.frame
            let baseColor = annotationDisplayBaseColor(for: annotation).usingColorSpace(.deviceRGB)
                ?? annotationDisplayBaseColor(for: annotation)
            let alpha: CGFloat = isAppLightAppearance() ? 0.70 : 0.60
            let fill = baseColor.withAlphaComponent(alpha)
            ctx.setFillColor(fill.cgColor)
            ctx.fill(rect)
        }
    }
}

let annotationNoteGroupKey = PDFAnnotationKey(rawValue: "NoteGroupID")
let annotationPageLabelOverrideKey = PDFAnnotationKey(rawValue: "PageLabelOverride")
let annotationStoredQuadPointsKey = PDFAnnotationKey(rawValue: "ArxivQuadPoints")
let annotationPreviewFlagKey = PDFAnnotationKey(rawValue: "ArxivPreview")
let annotationRichTextKey = PDFAnnotationKey(rawValue: "ArxivRichText")
let annotationMarkupStyleKey = PDFAnnotationKey(rawValue: "ArxivMarkupStyle")
let annotationMarkupColorKey = PDFAnnotationKey(rawValue: "ArxivMarkupColor")
let annotationOverlayHighlightKey = PDFAnnotationKey(rawValue: "ArxivOverlayHighlight")
let annotationGroupQuadPointsKey = PDFAnnotationKey(rawValue: "ArxivGroupQuadPoints")
let annotationSubtypeKey = PDFAnnotationKey(rawValue: "Subtype")

final class PDFAnnotationCoordinator: NSObject, NSPopoverDelegate {
    private weak var pdfView: ZoomablePDFView?
    private weak var hostView: NSView?
    private let overlay = AnnotationIconOverlayView(frame: .zero)
    private var overlayConstraints: [NSLayoutConstraint] = []
    private var composerPopover: NSPopover?
    private var composerViewController: AnnotationComposerViewController?
    private var composerPrewarmed = false
    private var composerPresentationID: Int = 0
    private var composerKeyBuffer: [NSEvent] = []
    private var composerKeyBufferMonitor: Any?
    private var composerKeyBuffering = false
    private weak var composerKeyBufferWindow: NSWindow?
    private var readOnlyPopover: NSPopover?
    private var readOnlyPopoverAnnotation: PDFAnnotation?
    private var observers: [NSObjectProtocol] = []
    private var scrollObserver: NSObjectProtocol?
    private var currentContext: AnnotationContext?
    private var previewHighlight: PDFAnnotation?
    private var previewSelection: PDFSelection?
    private var annotationSelectionOverlayIDs: Set<ObjectIdentifier> = []
    private let annotationSelectionOverlayEnabled = ProcessInfo.processInfo.environment["ARXIV_ANNOTATION_SELECTION_OVERLAY"] == "1"
    private let persistQueue = DispatchQueue(label: "arxiv.annotation.persist", qos: .utility)
    private var pendingPersistWorkItem: DispatchWorkItem?
    private var persistToken: Int = 0
    private var keyMonitor: Any?
    private var clickMonitor: Any?
    private var highlightMonitor: Any?
    private var highlightMonitorCandidate: PDFAnnotation?
    private var highlightMonitorStart: NSPoint?
    private var highlightMonitorDidDrag = false
    private let highlightMonitorDragThreshold: CGFloat = 3
    private var lastHighlightOpenTimestamp: TimeInterval = 0
    private let highlightHitDebugEnabled = ProcessInfo.processInfo.environment["ARXIV_HIGHLIGHT_HIT_DEBUG"] == "1"
    private var groupQuadPointsCache: [String: [NSValue]] = [:]
    var overlayRefreshSuppressedProvider: (() -> Bool)?
    private var overlayRefreshPending = false
    var onNavigatePrevious: (() -> Void)?
    var onNavigateNext: (() -> Void)?
    var listItemsProvider: (() -> [PDFAnnotationListItem])?
    private var currentListItemID: String?
    private var currentListItem: PDFAnnotationListItem?
    private var pendingPageLabelOverride: String?
    private var pendingCreationDateOverride: Date?
#if DEBUG
    private var aaToggleDebugActive = false
    private var aaToggleDebugTargetID: String?
    private var aaToggleDebugGroupID: String?
    private var aaToggleDebugPageIndex: Int?
    private var aaToggleDebugAffectedIDs: [String] = []
    private var aaToggleDebugPreCount: Int = 0
    private var aaToggleDebugPostCount: Int = 0
    private var aaToggleDebugPreInventory: [String] = []
    private var aaToggleDebugPostInventory: [String] = []
    private var aaToggleDebugAllowsRemoval = false
    private var aaReproDidRun = false
#endif

    var isComposerVisible: Bool {
        composerPopover?.isShown == true
    }

    private func composerController() -> AnnotationComposerViewController {
        if let vc = composerViewController {
            vc.dropdownGlassFactory = dropdownGlassFactory
            return vc
        }
        let vc = AnnotationComposerViewController()
        vc.dropdownGlassFactory = dropdownGlassFactory
        composerViewController = vc
        return vc
    }

    private func prewarmComposerIfNeeded() {
        guard !composerPrewarmed else { return }
        composerPrewarmed = true
        DispatchQueue.main.async { [weak self] in
            guard let self else { return }
            let vc = self.composerController()
            _ = vc.view
            vc.prewarmInlineMathIfNeeded()
        }
    }

    private func beginComposerKeyBuffering() {
        composerKeyBuffer.removeAll()
        composerKeyBuffering = true
        composerKeyBufferWindow = pdfView?.window
        guard composerKeyBufferMonitor == nil else { return }
        composerKeyBufferMonitor = NSEvent.addLocalMonitorForEvents(matching: [.keyDown]) { [weak self] event in
            guard let self else { return event }
            guard self.composerKeyBuffering else { return event }
            guard let window = self.composerKeyBufferWindow else { return event }
            if event.window !== window { return event }
            if event.modifierFlags.contains(.command) || event.modifierFlags.contains(.control) {
                return event
            }
            self.composerKeyBuffer.append(event)
            return nil
        }
    }

    private func flushComposerKeyBuffer(into textView: AnnotationTextView?) {
        guard composerKeyBuffering else { return }
        composerKeyBuffering = false
        if let monitor = composerKeyBufferMonitor {
            NSEvent.removeMonitor(monitor)
            composerKeyBufferMonitor = nil
        }
        guard let textView, !composerKeyBuffer.isEmpty else {
            composerKeyBuffer.removeAll()
            return
        }
        let events = composerKeyBuffer
        composerKeyBuffer.removeAll()
        textView.interpretKeyEvents(events)
    }

    private func cancelComposerKeyBuffering() {
        composerKeyBuffering = false
        composerKeyBuffer.removeAll()
        if let monitor = composerKeyBufferMonitor {
            NSEvent.removeMonitor(monitor)
            composerKeyBufferMonitor = nil
        }
    }

    func refreshComposerForegroundColors() {
        if let vc = composerPopover?.contentViewController as? AnnotationComposerViewController {
            vc.refreshForegroundColors()
        }
    }

    func refreshComposerAppearance() {
        if let vc = composerPopover?.contentViewController as? AnnotationComposerViewController {
            vc.refreshGlassTint()
            vc.refreshForegroundColors()
        }
    }

    func syncCurrentListItem(with items: [PDFAnnotationListItem]) {
        if let id = currentListItemID, let updated = items.first(where: { $0.stableID == id }) {
            currentListItem = updated
            let value = normalizedPageLabelValue(from: updated.pageLabel)
            if let vc = composerPopover?.contentViewController as? AnnotationComposerViewController {
                vc.updatePageNumberValue(value)
                let style = annotationStyle(for: updated)
                vc.setSelectedStyle(style, color: updated.color)
            }
        }
        if let vc = composerPopover?.contentViewController as? AnnotationComposerViewController {
            let position = notePositionData(from: items)
            vc.setNotePosition(index: position.index, total: position.total)
        }
    }

    private func activeComposerGroupID() -> String? {
        if let id = currentListItemID { return id }
        if let existing = currentContext?.existingAnnotation, let gid = noteGroupID(for: existing) {
            return gid
        }
        return nil
    }

    private func syncComposerStyleIfNeeded(groupID: String, style: AnnotationMarkupStyle, color: NSColor?) {
        guard let activeID = activeComposerGroupID(), activeID == groupID else { return }
        guard let vc = composerPopover?.contentViewController as? AnnotationComposerViewController else { return }
        vc.setSelectedStyle(style, color: color)
    }

    private func normalizedPageLabelValue(from label: String) -> String {
        let prefix = "Page "
        if label.hasPrefix(prefix) {
            return String(label.dropFirst(prefix.count))
        }
        return label
    }

    private func notePositionData(from items: [PDFAnnotationListItem]) -> (index: Int?, total: Int) {
        let total = items.count
        guard total > 0 else { return (nil, 0) }
        if let current = currentListItem, let idx = items.firstIndex(of: current) {
            return (idx + 1, total)
        }
        if let id = currentListItemID, let idx = items.firstIndex(where: { $0.stableID == id }) {
            currentListItem = items[idx]
            return (idx + 1, total)
        }
        return (nil, total)
    }

    private func canNavigateAnnotations(delta: Int) -> Bool {
        guard delta != 0, let items = listItemsProvider?(), !items.isEmpty else { return false }
        if let current = currentListItem, let idx = items.firstIndex(of: current) {
            let target = idx + delta
            return target >= 0 && target < items.count
        }
        if let id = currentListItemID, let idx = items.firstIndex(where: { $0.stableID == id }) {
            currentListItem = items[idx]
            let target = idx + delta
            return target >= 0 && target < items.count
        }
        return false
    }

    private func defaultPageLabelValue(for page: PDFPage, override: String?) -> String {
        let trimmed = override?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !trimmed.isEmpty {
            return trimmed
        }
        if let label = page.label?.trimmingCharacters(in: .whitespacesAndNewlines), !label.isEmpty {
            return label
        }
        if let doc = page.document {
            return String(doc.index(for: page) + 1)
        }
        return ""
    }

    private func resolveListItem(for context: AnnotationContext) -> PDFAnnotationListItem? {
        guard let existing = context.existingAnnotation,
              let items = listItemsProvider?() else {
            return nil
        }
        if let groupID = noteGroupID(for: existing),
           let direct = items.first(where: { $0.stableID == groupID }) {
            return direct
        }
        if let objectMatch = items.first(where: { item in
            item.highlightAnnotations.contains(where: { $0 === existing })
                || item.noteAnnotations.contains(where: { $0 === existing })
        }) {
            return objectMatch
        }
        let pageIndex = max(0, context.page.document?.index(for: context.page) ?? 0)
        let stableKey = annotationStableKey(existing, pageIndex: pageIndex)
        return items.first(where: { item in
            let idx = item.pageIndex
            let highlightMatch = item.highlightAnnotations.contains {
                annotationStableKey($0, pageIndex: idx) == stableKey
            }
            let noteMatch = item.noteAnnotations.contains {
                annotationStableKey($0, pageIndex: idx) == stableKey
            }
            return highlightMatch || noteMatch
        })
    }

    private func listItemMatchesContext(_ item: PDFAnnotationListItem, context: AnnotationContext) -> Bool {
        guard let existing = context.existingAnnotation else { return false }
        if let gid = noteGroupID(for: existing), gid == item.stableID {
            return true
        }
        if item.highlightAnnotations.contains(where: { $0 === existing }) ||
            item.noteAnnotations.contains(where: { $0 === existing }) {
            return true
        }
        let pageIndex = max(0, context.page.document?.index(for: context.page) ?? item.pageIndex)
        let stableKey = annotationStableKey(existing, pageIndex: pageIndex)
        if stableKeysForSyntheticGroupID(item.stableID).contains(stableKey) {
            return true
        }
        let itemKeys = (item.highlightAnnotations + item.noteAnnotations)
            .map { annotationStableKey($0, pageIndex: item.pageIndex) }
        return itemKeys.contains(stableKey)
    }

    private func applyingColorOverride(_ item: PDFAnnotationListItem, color: NSColor?) -> PDFAnnotationListItem {
        guard let color else { return item }
        return PDFAnnotationListItem(
            stableID: item.stableID,
            pageIndex: item.pageIndex,
            pageLabel: item.pageLabel,
            sortTopOffset: item.sortTopOffset,
            sortTimestamp: item.sortTimestamp,
            createdAt: item.createdAt,
            color: color,
            highlightText: item.highlightText,
            commentText: item.commentText,
            commentRichTextPayload: item.commentRichTextPayload,
            page: item.page,
            anchorBounds: item.anchorBounds,
            highlightAnnotations: item.highlightAnnotations,
            noteAnnotations: item.noteAnnotations
        )
    }

    private func actionListItem(for context: AnnotationContext, colorOverride: NSColor? = nil) -> PDFAnnotationListItem? {
        if let current = currentListItem {
            if context.existingAnnotation != nil, !listItemMatchesContext(current, context: context) {
                if annotationActionDebugEnabled {
                    annotationActionLog("action_item=drop_current id=\(current.stableID) reason=context_mismatch")
                }
                currentListItem = nil
            } else {
            if annotationActionDebugEnabled {
                annotationActionLog("action_item=hit_current id=\(current.stableID)")
            }
            return applyingColorOverride(current, color: colorOverride)
            }
        }
        if let id = currentListItemID, let items = listItemsProvider?(),
           let resolved = items.first(where: { $0.stableID == id }) {
            if context.existingAnnotation != nil, !listItemMatchesContext(resolved, context: context) {
                if annotationActionDebugEnabled {
                    annotationActionLog("action_item=drop_current_id id=\(resolved.stableID) reason=context_mismatch")
                }
            } else {
                currentListItem = resolved
                if annotationActionDebugEnabled {
                    annotationActionLog("action_item=hit_current_id id=\(resolved.stableID)")
                }
                return applyingColorOverride(resolved, color: colorOverride)
            }
        }
        if let resolved = resolveListItem(for: context) {
            currentListItem = resolved
            currentListItemID = resolved.stableID
            if annotationActionDebugEnabled {
                annotationActionLog("action_item=resolved_from_context id=\(resolved.stableID)")
            }
            return applyingColorOverride(resolved, color: colorOverride)
        }
        guard let existing = context.existingAnnotation else { return nil }
        let page = existing.page ?? context.page
        let pageIndex = page.document?.index(for: page) ?? 0
        let safePageIndex = max(0, pageIndex)
        let groupID: String
        if let gid = noteGroupID(for: existing), !gid.isEmpty {
            groupID = gid
        } else {
            let stableKey = annotationStableKey(existing, pageIndex: safePageIndex)
            if annotationIsHighlightLike(existing) {
                groupID = "synthetic-h|\(stableKey)"
            } else if annotationIsTextNote(existing) {
                groupID = "synthetic-n|\(stableKey)"
            } else {
                groupID = stableKey
            }
        }
        let label = page.label?.trimmingCharacters(in: .whitespacesAndNewlines)
        let pageLabelValue = (label?.isEmpty == false) ? label! : String(safePageIndex + 1)
        let pageLabel = "Page \(pageLabelValue)"
        let color = colorOverride ?? existing.color
        let displayBox = pdfView?.displayBox ?? .cropBox
        let sortTopOffset = annotationTopOffset(for: existing, page: page, displayBox: displayBox)
        let sortTimestamp = annotationSortTimestamp(existing)
        let anchorBounds = annotationAnchorRect(for: existing)
        let highlightAnnotations = annotationIsHighlightLike(existing) ? [existing] : []
        let noteAnnotations = annotationIsTextNote(existing) ? [existing] : []
        let synthesized = PDFAnnotationListItem(
            stableID: groupID,
            pageIndex: safePageIndex,
            pageLabel: pageLabel,
            sortTopOffset: sortTopOffset,
            sortTimestamp: sortTimestamp,
            createdAt: annotationCreationDateValue(for: existing),
            color: color,
            highlightText: "",
            commentText: "",
            commentRichTextPayload: nil,
            page: page,
            anchorBounds: anchorBounds,
            highlightAnnotations: highlightAnnotations,
            noteAnnotations: noteAnnotations
        )
        if annotationActionDebugEnabled {
            annotationActionLog("action_item=synthesized id=\(synthesized.stableID) page=\(synthesized.pageIndex)")
        }
        return synthesized
    }

    private func handlePageNumberChange(_ value: String) {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        if currentListItem == nil, let id = currentListItemID, let items = listItemsProvider?() {
            currentListItem = items.first(where: { $0.stableID == id })
        }
        if let item = currentListItem {
            updateAnnotationGroupPageLabel(for: item, label: trimmed)
            pendingPageLabelOverride = nil
        } else {
            pendingPageLabelOverride = trimmed
        }
    }

    // Manage PDFView.highlightedSelections safely so multiple selections can be
    // preserved simultaneously. Compare selections by page and bounds/string.
    private func selectionEquals(_ a: PDFSelection, _ b: PDFSelection) -> Bool {
        guard let aPage = a.pages.first as? PDFPage, let bPage = b.pages.first as? PDFPage else { return false }
        if aPage.document?.index(for: aPage) != bPage.document?.index(for: bPage) { return false }
        let aBounds = a.bounds(for: aPage)
        let bBounds = b.bounds(for: bPage)
        if !aBounds.equalTo(bBounds) { return false }
        return (a.string ?? "") == (b.string ?? "")
    }

    private func annotationDebugID(_ annotation: PDFAnnotation) -> String {
        let ptr = Unmanaged.passUnretained(annotation).toOpaque()
        return String(format: "0x%016llx", UInt64(UInt(bitPattern: ptr)))
    }

    private func selectionDebugID(_ selection: PDFSelection) -> String {
        let ptr = Unmanaged.passUnretained(selection).toOpaque()
        return String(format: "0x%016llx", UInt64(UInt(bitPattern: ptr)))
    }

    private func debugTrimmedText(_ text: String?, limit: Int = 80) -> String {
        let raw = text?.replacingOccurrences(of: "\n", with: " ").trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard raw.count > limit else { return raw }
        let idx = raw.index(raw.startIndex, offsetBy: limit)
        return String(raw[..<idx]) + "..."
    }

    private func debugRectsText(_ rects: [CGRect]) -> String {
        guard !rects.isEmpty else { return "[]" }
        let parts = rects.map { NSStringFromRect($0) }
        return "[" + parts.joined(separator: ", ") + "]"
    }

    private func timingStart() -> CFTimeInterval {
        CACurrentMediaTime()
    }

    private func timingEnd(_ label: String, _ start: CFTimeInterval) {
        let ms = (CACurrentMediaTime() - start) * 1000.0
        annotationTimingLog("\(label) ms=\(String(format: "%.2f", ms))")
    }

    private func debugSelectionSummary(_ selection: PDFSelection) -> String {
        let pages = (selection.pages as? [PDFPage]) ?? []
        let pageIndices = pages.compactMap { $0.document?.index(for: $0) }
        let pageText = pageIndices.isEmpty ? "-" : pageIndices.map(String.init).joined(separator: ",")
        let rectsText: String = {
            guard let firstPage = pages.first else { return "[]" }
            return debugRectsText(selectionLineRects(selection, on: firstPage))
        }()
        let text = debugTrimmedText(selection.string)
        return "sel=\(selectionDebugID(selection)) pages=\(pageText) rects=\(rectsText) text=\"\(text)\""
    }

    private func debugAnnotationTextRange(_ annotation: PDFAnnotation, page: PDFPage?) -> String {
        guard let page else { return "-" }
        let text = debugTrimmedText(annotationPreviewText(for: annotation, page: page))
        return "text=\"\(text)\""
    }

    private func debugAnnotationRenderState(_ annotation: PDFAnnotation, page: PDFPage? = nil) -> String {
        let resolvedPage = page ?? annotation.page
        let pageIndex = resolvedPage?.document?.index(for: resolvedPage!) ?? -1
        let type = annotationTypeName(annotation)
        let style = annotationMarkupStyle(for: annotation).rawValue
        let overlay = (annotation.value(forAnnotationKey: annotationOverlayHighlightKey) as? Bool) == true
        let base = annotationStoredBaseColor(for: annotation) ?? annotationDisplayBaseColor(for: annotation)
        let color = annotation.color
        let ca = (annotation.value(forAnnotationKey: PDFAnnotationKey(rawValue: "CA")) as? NSNumber)?.doubleValue ?? 1.0
        let storedCount = storedQuadPointsFromValue(annotation.value(forAnnotationKey: annotationStoredQuadPointsKey))?.count ?? 0
        let pageCount = annotationQuadPoints(for: annotation).count
        let localCount = annotation.quadrilateralPoints?.count ?? 0
        return "id=\(annotationDebugID(annotation)) page=\(pageIndex) type=\(type) style=\(style) overlay=\(overlay) base=\(hexFromColor(base, includeAlpha: true)) color=\(hexFromColor(color, includeAlpha: true)) ca=\(String(format: "%.2f", ca)) quads(page=\(pageCount) local=\(localCount) stored=\(storedCount)) bounds=\(NSStringFromRect(annotation.bounds))"
    }

    private func annotationIsPreview(_ annotation: PDFAnnotation) -> Bool {
        if let flag = annotation.value(forAnnotationKey: annotationPreviewFlagKey) as? Bool {
            return flag
        }
        let contents = annotation.contents?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return contents == "preview"
    }

    private func annotationViewRect(_ rect: CGRect, page: PDFPage) -> CGRect? {
        guard let pdfView else { return nil }
        return pdfView.convert(rect, from: page)
    }

    private func logAnnotationEvent(_ action: String,
                                    annotation: PDFAnnotation,
                                    page: PDFPage? = nil,
                                    context: String? = nil) {
        guard annotationDebugEnabled else { return }
        let resolvedPage = page ?? annotation.page
        let pageIndex = resolvedPage?.document?.index(for: resolvedPage!) ?? -1
        let type = annotationTypeName(annotation)
        let gid = noteGroupID(for: annotation) ?? "-"
        let preview = annotationIsPreview(annotation)
        let bounds = annotation.bounds
        let anchor = annotationAnchorRect(for: annotation)
        let quadCount = annotation.quadrilateralPoints?.count
            ?? storedQuadPointsFromValue(annotation.value(forAnnotationKey: annotationStoredQuadPointsKey))?.count
            ?? 0
        let boundsView = resolvedPage.flatMap { annotationViewRect(bounds, page: $0) }
        let anchorView = resolvedPage.flatMap { annotationViewRect(anchor, page: $0) }
        let boundsViewText = boundsView.map { NSStringFromRect($0) } ?? "-"
        let anchorViewText = anchorView.map { NSStringFromRect($0) } ?? "-"
        let ctx = context ?? "-"
        annotationLog("[ANN_EVT] action=\(action) id=\(annotationDebugID(annotation)) type=\(type) preview=\(preview) gid=\(gid) quad=\(quadCount) page=\(pageIndex) bounds=\(NSStringFromRect(bounds)) anchor=\(NSStringFromRect(anchor)) viewBounds=\(boundsViewText) viewAnchor=\(anchorViewText) ctx=\(ctx)")
    }

    private func reportingAnnotationID(_ annotation: PDFAnnotation, pageIndex: Int?) -> String {
        let safePage = max(0, pageIndex ?? annotation.page.flatMap { $0.document?.index(for: $0) } ?? 0)
        return reportingHash(annotationStableKey(annotation, pageIndex: safePage))
    }

    private func reportAnnotationOp(_ event: String,
                                    annotation: PDFAnnotation,
                                    pageIndex: Int?,
                                    details: [String: String] = [:]) {
        guard ReportingLogger.shared.isActive else { return }
        let annotationID = reportingAnnotationID(annotation, pageIndex: pageIndex)
        let context = ReportingLogContext(
            view: "pdf",
            documentID: pdfView?.document.flatMap { reportingDocumentID(for: $0) },
            annotationID: annotationID,
            details: details
        )
        ReportingLogger.shared.log(severity: .info,
                                   category: .annotationOps,
                                   event: event,
                                   context: context)
    }

    private func reportDocumentIO(_ event: String,
                                  documentID: String?,
                                  severity: ReportingLogSeverity = .info,
                                  details: [String: String] = [:]) {
        guard ReportingLogger.shared.isActive else { return }
        let context = ReportingLogContext(
            view: "pdf",
            documentID: documentID,
            annotationID: nil,
            details: details
        )
        ReportingLogger.shared.log(severity: severity,
                                   category: .documentIO,
                                   event: event,
                                   context: context)
    }

#if DEBUG
    private func debugAnnotationSummary(_ annotation: PDFAnnotation, page: PDFPage? = nil) -> String {
        let resolvedPage = page ?? annotation.page
        let pageIndex = resolvedPage?.document?.index(for: resolvedPage!) ?? -1
        let gid = noteGroupID(for: annotation) ?? "-"
        let type = annotationTypeName(annotation)
        let style = annotationMarkupStyle(for: annotation).rawValue
        let anchor = annotationAnchorRect(for: annotation)
        let anchorText = NSStringFromRect(anchor)
        let stableKey = annotationStableKey(annotation, pageIndex: max(0, pageIndex))
        return "id=\(annotationDebugID(annotation)) gid=\(gid) page=\(pageIndex) type=\(type) style=\(style) anchor=\(anchorText) key=\(stableKey)"
    }

    private func debugAnnotationInventory(document: PDFDocument) -> [String] {
        var out: [String] = []
        for pageIndex in 0..<document.pageCount {
            guard let page = document.page(at: pageIndex) else { continue }
            for ann in page.annotations where (annotationIsHighlightLike(ann) || annotationIsTextNote(ann)) {
                out.append(debugAnnotationSummary(ann, page: page))
            }
        }
        return out
    }

    private func debugAnnotationCount(document: PDFDocument) -> Int {
        var count = 0
        for pageIndex in 0..<document.pageCount {
            guard let page = document.page(at: pageIndex) else { continue }
            count += page.annotations.filter { annotationIsHighlightLike($0) || annotationIsTextNote($0) }.count
        }
        return count
    }

    private func startAAToggleDebug(target: PDFAnnotation, page: PDFPage, source: String) {
        aaToggleDebugActive = true
        aaToggleDebugTargetID = annotationDebugID(target)
        aaToggleDebugGroupID = noteGroupID(for: target)
        aaToggleDebugPageIndex = page.document?.index(for: page) ?? -1
        aaToggleDebugAffectedIDs = []
        aaToggleDebugAllowsRemoval = false
        if let doc = page.document {
            aaToggleDebugPreCount = debugAnnotationCount(document: doc)
            aaToggleDebugPreInventory = debugAnnotationInventory(document: doc)
        } else {
            aaToggleDebugPreCount = 0
            aaToggleDebugPreInventory = []
        }
        annotationLog("[AA_DEBUG] start source=\(source) target=\(debugAnnotationSummary(target, page: page)) count=\(aaToggleDebugPreCount)")
    }

    private func recordAAToggleAffected(_ annotation: PDFAnnotation, reason: String) {
        let entry = debugAnnotationSummary(annotation)
        aaToggleDebugAffectedIDs.append(entry + " reason=\(reason)")
    }

    private func endAAToggleDebug(page: PDFPage, source: String) {
        if let doc = page.document {
            aaToggleDebugPostCount = debugAnnotationCount(document: doc)
            aaToggleDebugPostInventory = debugAnnotationInventory(document: doc)
        } else {
            aaToggleDebugPostCount = 0
            aaToggleDebugPostInventory = []
        }
        annotationLog("[AA_DEBUG] end source=\(source) target_id=\(aaToggleDebugTargetID ?? "-") count_before=\(aaToggleDebugPreCount) count_after=\(aaToggleDebugPostCount) affected=\(aaToggleDebugAffectedIDs.count)")
        aaToggleDebugAllowsRemoval = false
        aaToggleDebugActive = false
    }

    private func dumpAAToggleState(label: String, page: PDFPage) {
        annotationLog("[AA_DEBUG] \(label) target_id=\(aaToggleDebugTargetID ?? "-") group=\(aaToggleDebugGroupID ?? "-") page=\(aaToggleDebugPageIndex ?? -1)")
        annotationLog("[AA_DEBUG] affected:")
        for entry in aaToggleDebugAffectedIDs {
            annotationLog("  \(entry)")
        }
        if let doc = page.document {
            let inventory = debugAnnotationInventory(document: doc)
            annotationLog("[AA_DEBUG] store dump (\(inventory.count)):")
            for entry in inventory {
                annotationLog("  \(entry)")
            }
        }
        annotationLog("[AA_DEBUG] stack:\n\(Thread.callStackSymbols.joined(separator: "\n"))")
    }
#endif

    private func logDuplicateHighlights(on page: PDFPage, context: String) {
        guard annotationDebugEnabled else { return }
        let pageIndex = page.document?.index(for: page) ?? -1
        let highlights = page.annotations.filter { annotationIsHighlightLike($0) }
        guard highlights.count > 1 else { return }
        let pageBounds = page.bounds(for: pdfView?.displayBox ?? .cropBox)
        var groups: [String: [PDFAnnotation]] = [:]
        var rectGroups: [String: [PDFAnnotation]] = [:]
        for ann in highlights {
            let gid = noteGroupID(for: ann)
            let key = gid ?? "nogid|\(annotationStableKey(ann, pageIndex: pageIndex))"
            groups[key, default: []].append(ann)
            let anchor = annotationAnchorRect(for: ann)
            let type = annotationTypeName(ann)
            let rectKey = [
                type,
                String(Int(anchor.origin.x.rounded())),
                String(Int(anchor.origin.y.rounded())),
                String(Int(anchor.size.width.rounded())),
                String(Int(anchor.size.height.rounded()))
            ].joined(separator: "|")
            rectGroups[rectKey, default: []].append(ann)
            if !pageBounds.intersects(anchor) {
                annotationLog("[ANN_GHOST] page=\(pageIndex) id=\(annotationDebugID(ann)) gid=\(gid ?? "-") type=\(annotationTypeName(ann)) anchor=\(NSStringFromRect(anchor)) pageBounds=\(NSStringFromRect(pageBounds)) ctx=\(context)")
            }
        }
        for (key, group) in groups where group.count > 1 {
            let ids = group.map { annotationDebugID($0) }.joined(separator: ",")
            annotationLog("[ANN_DUP] page=\(pageIndex) key=\(key) count=\(group.count) ids=[\(ids)] ctx=\(context)")
        }
        for (key, group) in rectGroups where group.count > 1 {
            let ids = group.map { annotationDebugID($0) }.joined(separator: ",")
            annotationLog("[ANN_DUP_RECT] page=\(pageIndex) key=\(key) count=\(group.count) ids=[\(ids)] ctx=\(context)")
        }
    }

    private func addAnnotation(_ annotation: PDFAnnotation, to page: PDFPage, reason: String) {
        page.addAnnotation(annotation)
        logAnnotationEvent("add", annotation: annotation, page: page, context: reason)
        let pageIndex = page.document?.index(for: page) ?? -1
        reportAnnotationOp("annotation_add", annotation: annotation, pageIndex: pageIndex, details: ["reason": reason])
#if DEBUG
        if annotationDebugEnabled {
            let pageIndex = page.document?.index(for: page) ?? -1
            let rects = quadRects(for: annotation)
            let text = debugAnnotationTextRange(annotation, page: page)
            annotationLog("[ANN_ADD] id=\(annotationDebugID(annotation)) page=\(pageIndex) rects=\(debugRectsText(rects)) \(text) reason=\(reason)")
            annotationLog("[ANN_MUTATE] ADD \(debugAnnotationSummary(annotation, page: page)) reason=\(reason)")
        }
#endif
        logDuplicateHighlights(on: page, context: "after_add:\(reason)")
    }

    private func removeAnnotation(_ annotation: PDFAnnotation, from page: PDFPage, reason: String) {
        logAnnotationEvent("remove", annotation: annotation, page: page, context: reason)
        let pageIndex = page.document?.index(for: page) ?? -1
        reportAnnotationOp("annotation_remove", annotation: annotation, pageIndex: pageIndex, details: ["reason": reason])
#if DEBUG
        if annotationDebugEnabled {
            annotationLog("[ANN_MUTATE] REMOVE \(debugAnnotationSummary(annotation, page: page)) reason=\(reason)")
        }
        if aaToggleDebugActive {
            annotationLog("[AA_DEBUG] REMOVE during Aa toggle detected: \(debugAnnotationSummary(annotation, page: page)) reason=\(reason)")
            if aaToggleDebugAllowsRemoval || reason.hasPrefix("convert_") {
                annotationLog("[AA_DEBUG] remove allowed for Aa toggle reason=\(reason)")
            } else {
                dumpAAToggleState(label: "remove_during_aa", page: page)
                assertionFailure("AA toggle triggered an unexpected REMOVE mutation.")
            }
        }
#endif
        clearRenderArtifacts(for: annotation, reason: "remove:\(reason)")
        page.removeAnnotation(annotation)
        logDuplicateHighlights(on: page, context: "after_remove:\(reason)")
    }

    private func updateAnnotation(_ annotation: PDFAnnotation, reason: String) {
        logAnnotationEvent("update", annotation: annotation, page: annotation.page, context: reason)
        let pageIndex = annotation.page.flatMap { $0.document?.index(for: $0) } ?? -1
        reportAnnotationOp("annotation_update", annotation: annotation, pageIndex: pageIndex, details: ["reason": reason])
#if DEBUG
        if annotationDebugEnabled, let page = annotation.page {
            annotationLog("[ANN_MUTATE] UPDATE \(debugAnnotationSummary(annotation, page: page)) reason=\(reason)")
        }
#endif
    }

    private func rectsAreNeighbors(_ a: CGRect, _ b: CGRect, tolerance: CGFloat) -> Bool {
        if a.intersects(b) { return true }
        let expanded = a.insetBy(dx: -tolerance, dy: -tolerance)
        return expanded.intersects(b)
    }

    private func clusterHighlights(_ annotations: [PDFAnnotation], tolerance: CGFloat) -> [[PDFAnnotation]] {
        let rects = annotations.map { annotationAnchorRect(for: $0) }
        var visited = Array(repeating: false, count: annotations.count)
        var clusters: [[PDFAnnotation]] = []
        for i in 0..<annotations.count {
            if visited[i] { continue }
            visited[i] = true
            var queue = [i]
            var cluster: [PDFAnnotation] = []
            while let idx = queue.popLast() {
                cluster.append(annotations[idx])
                for j in 0..<annotations.count where !visited[j] {
                    if rectsAreNeighbors(rects[idx], rects[j], tolerance: tolerance) {
                        visited[j] = true
                        queue.append(j)
                    }
                }
            }
            clusters.append(cluster)
        }
        return clusters
    }

    private func clusterUnionRect(_ annotations: [PDFAnnotation]) -> CGRect {
        let rects = annotations.map { annotationAnchorRect(for: $0) }
        guard let first = rects.first else { return .zero }
        return rects.dropFirst().reduce(first) { $0.union($1) }
    }

    private func choosePrimaryCluster(_ clusters: [[PDFAnnotation]],
                                      note: PDFAnnotation?) -> [PDFAnnotation] {
        guard !clusters.isEmpty else { return [] }
        if clusters.count == 1 { return clusters[0] }
        var best = clusters[0]
        var bestArea = clusterUnionRect(best).width * clusterUnionRect(best).height
        var bestDistance = CGFloat.greatestFiniteMagnitude
        if let note {
            bestDistance = annotationRectDistance(clusterUnionRect(best), note.bounds)
        }
        for cluster in clusters.dropFirst() {
            let rect = clusterUnionRect(cluster)
            let area = rect.width * rect.height
            if area > bestArea + 0.5 {
                best = cluster
                bestArea = area
                if let note {
                    bestDistance = annotationRectDistance(rect, note.bounds)
                }
            } else if abs(area - bestArea) <= 0.5, let note {
                let dist = annotationRectDistance(rect, note.bounds)
                if dist < bestDistance {
                    best = cluster
                    bestArea = area
                    bestDistance = dist
                }
            }
        }
        return best
    }

    private func rectsNearlyEqual(_ a: CGRect, _ b: CGRect, tolerance: CGFloat) -> Bool {
        abs(a.origin.x - b.origin.x) <= tolerance &&
        abs(a.origin.y - b.origin.y) <= tolerance &&
        abs(a.size.width - b.size.width) <= tolerance &&
        abs(a.size.height - b.size.height) <= tolerance
    }

    private func dedupeAnnotations(_ annotations: [PDFAnnotation], tolerance: CGFloat) -> (kept: [PDFAnnotation], removed: [PDFAnnotation]) {
        var kept: [PDFAnnotation] = []
        var removed: [PDFAnnotation] = []
        for ann in annotations {
            let rect = annotationAnchorRect(for: ann)
            let type = annotationTypeName(ann)
            if kept.contains(where: { annotationTypeName($0) == type && rectsNearlyEqual(rect, annotationAnchorRect(for: $0), tolerance: tolerance) }) {
                removed.append(ann)
            } else {
                kept.append(ann)
            }
        }
        return (kept, removed)
    }

    private func purgePreviewAnnotations(on page: PDFPage, reason: String) {
        let previews = page.annotations.filter { annotationIsPreview($0) }
        guard !previews.isEmpty else { return }
        for ann in previews {
            if ann === previewHighlight {
                previewHighlight = nil
                previewSelection = nil
            }
            removeAnnotation(ann, from: page, reason: "purge_preview:\(reason)")
        }
        clearAnnotationSelectionOverlays(reason: "purge_preview")
    }

    private func sanitizeHighlightMatches(_ matches: [PDFAnnotation],
                                          groupID: String,
                                          page: PDFPage,
                                          fallbackNote: PDFAnnotation?) -> [PDFAnnotation] {
        var candidates = matches.filter { annotationIsHighlightLike($0) && !annotationIsPreview($0) && $0.page === page }
        guard !candidates.isEmpty else { return [] }
        let pageBounds = page.bounds(for: pdfView?.displayBox ?? .cropBox)
        var onPage: [PDFAnnotation] = []
        var offPage: [PDFAnnotation] = []
        for ann in candidates {
            let rect = annotationAnchorRect(for: ann)
            if rect.intersects(pageBounds) {
                onPage.append(ann)
            } else {
                offPage.append(ann)
            }
        }

        let tolerance = max(24, pageBounds.height * 0.02)
        let clusters = clusterHighlights(onPage, tolerance: tolerance)
        let primaryCluster = choosePrimaryCluster(clusters, note: fallbackNote)
        let primaryIDs = Set(primaryCluster.map { ObjectIdentifier($0) })
        var ghosts: [PDFAnnotation] = []
        for cluster in clusters {
            let ids = Set(cluster.map { ObjectIdentifier($0) })
            if ids.isDisjoint(with: primaryIDs) {
                ghosts.append(contentsOf: cluster)
            }
        }
        let dedupe = dedupeAnnotations(primaryCluster, tolerance: 1.0)
        ghosts.append(contentsOf: dedupe.removed)
        ghosts.append(contentsOf: offPage)

        // IMPORTANT: Never delete annotations during sanitization. Deletion is allowed
        // only via explicit Trash/Delete actions. Keep ghosts in place to avoid
        // "traveling" highlights when clicking between adjacent annotations.
        let allowRemoval = ProcessInfo.processInfo.environment["ARXIV_ALLOW_SANITIZE_REMOVAL"] == "1"
        if allowRemoval, !ghosts.isEmpty {
            removeHighlightedSelections(overlapping: ghosts.filter { annotationIsHighlightLike($0) })
            for ann in ghosts {
                removeAnnotation(ann, from: page, reason: "sanitize_ghost")
            }
        }

        let kept = allowRemoval ? dedupe.kept : candidates
        for ann in kept {
            assignGroupID(groupID, to: ann)
        }
#if DEBUG
        if annotationDebugEnabled {
            let keptIDs = kept.map { annotationDebugID($0) }.joined(separator: ",")
            let removedIDs = ghosts.map { annotationDebugID($0) }.joined(separator: ",")
            annotationLog("[ANN_COALESCE] group=\(groupID) kept=[\(keptIDs)] removed=[\(removedIDs)]")
        }
#endif
        if annotationDebugEnabled, !ghosts.isEmpty {
            annotationLog("[ANN_SAN] group=\(groupID) kept=\(kept.count) removed=\(ghosts.count)")
        }
        return kept
    }

    // === NEW: map a clicked highlight annotation to its note annotation and open composer/popover ===
    private func openNoteForHighlight(_ highlight: PDFAnnotation) {
        guard let page = highlight.page else { return }
        ensureMarkupState(for: page)

        // Preferred: direct group ID mapping
        let groupID = noteGroupID(for: highlight)

        if let gid = groupID, let note = noteForGroup(gid, on: page) {
            showAnnotationPopover(for: note)
            return
        }
        // If no note found, fall back to showing the composer for the highlight itself.
        // This avoids proximity-based note reuse, which can merge adjacent annotations.
        debugLog("openNoteForHighlight: no matching note found (gid=\(groupID ?? "nil"))")
        showAnnotationPopover(for: highlight)
    }

    private func addHighlightedSelection(_ sel: PDFSelection,
                                         color: NSColor? = nil,
                                         source: String = "unknown") {
        guard let pdfView = pdfView else { return }
        if annotationDebugEnabled {
            annotationLog("[ANN_SEL_ADD] source=\(source) enabled=\(annotationSelectionOverlayEnabled) \(debugSelectionSummary(sel)) color=\(String(describing: color))")
        }
        guard annotationSelectionOverlayEnabled else { return }
        var existing = pdfView.highlightedSelections ?? []
        let tint = color.map { highlightColor(for: $0).withAlphaComponent(0.25) }
        var found = false
        for existingSel in existing {
            if selectionEquals(existingSel, sel) {
                found = true
                if annotationSelectionOverlayIDs.contains(ObjectIdentifier(existingSel)),
                   let tint {
                    existingSel.color = tint
                }
                break
            }
        }
        if !found {
            if let tint { sel.color = tint }
            debugLog("addHighlightedSelection: before=\(existing.count) adding selection")
            existing.append(sel)
            annotationSelectionOverlayIDs.insert(ObjectIdentifier(sel))
        }
        if !existing.isEmpty {
            pdfView.highlightedSelections = existing
        }
    }

    private func removeHighlightedSelection(_ sel: PDFSelection,
                                            source: String = "unknown") {
        guard let pdfView = pdfView else { return }
        var existing = pdfView.highlightedSelections ?? []
        let before = existing.count
        var removedIDs: [ObjectIdentifier] = []
        existing.removeAll { existingSel in
            let id = ObjectIdentifier(existingSel)
            guard annotationSelectionOverlayIDs.contains(id) else { return false }
            if selectionEquals(existingSel, sel) {
                removedIDs.append(id)
                return true
            }
            return false
        }
        if !removedIDs.isEmpty {
            annotationSelectionOverlayIDs.subtract(removedIDs)
            if annotationDebugEnabled {
                annotationLog("[ANN_SEL_REMOVE] source=\(source) removed=\(removedIDs.count) before=\(before) after=\(existing.count)")
            }
            pdfView.highlightedSelections = existing.isEmpty ? nil : existing
        }
    }

    private func clearAnnotationSelectionOverlays(reason: String) {
        guard let pdfView = pdfView else { return }
        guard !annotationSelectionOverlayIDs.isEmpty else { return }
        var existing = pdfView.highlightedSelections ?? []
        let before = existing.count
        let idsToRemove = annotationSelectionOverlayIDs
        existing.removeAll { idsToRemove.contains(ObjectIdentifier($0)) }
        annotationSelectionOverlayIDs.removeAll()
        pdfView.highlightedSelections = existing.isEmpty ? nil : existing
        if annotationDebugEnabled {
            annotationLog("[ANN_SEL_CLEAR] reason=\(reason) removed=\(before - existing.count) before=\(before) after=\(existing.count)")
        }
    }

#if DEBUG
    private func assertNoAnnotationSelectionOverlays(reason: String) {
        guard annotationSelectionOverlayIDs.isEmpty else {
            annotationLog("[ANN_SEL_ASSERT] reason=\(reason) remaining=\(annotationSelectionOverlayIDs.count)")
            assertionFailure("Annotation selection overlays still present after \(reason).")
            return
        }
    }
#endif

    private func removeAnnotationSelectionOverlays(overlapping annotations: [PDFAnnotation], reason: String) {
        guard let pdfView, !annotations.isEmpty, !annotationSelectionOverlayIDs.isEmpty else { return }
        var existing = pdfView.highlightedSelections ?? []
        let before = existing.count
        var removedIDs: [ObjectIdentifier] = []
        existing.removeAll { sel in
            let id = ObjectIdentifier(sel)
            guard annotationSelectionOverlayIDs.contains(id) else { return false }
            if selectionOverlapsAnnotations(sel, annotations: annotations) {
                removedIDs.append(id)
                return true
            }
            return false
        }
        if !removedIDs.isEmpty {
            annotationSelectionOverlayIDs.subtract(removedIDs)
            pdfView.highlightedSelections = existing.isEmpty ? nil : existing
            if annotationDebugEnabled {
                annotationLog("[ANN_SEL_REMOVE] reason=\(reason) removed=\(removedIDs.count) before=\(before) after=\(existing.count)")
            }
        }
    }

    private func rectArea(_ rect: CGRect) -> CGFloat {
        max(0, rect.width) * max(0, rect.height)
    }

    private func selectionLineRects(_ selection: PDFSelection, on page: PDFPage) -> [CGRect] {
        let pieces = selection.selectionsByLine() ?? [selection]
        var rects: [CGRect] = []
        rects.reserveCapacity(pieces.count)
        for piece in pieces {
            guard (piece.pages ?? []).contains(page) else { continue }
            let bounds = piece.bounds(for: page)
            if bounds.width > 0, bounds.height > 0 {
                rects.append(bounds)
            }
        }
        if rects.isEmpty {
            let bounds = selection.bounds(for: page)
            if bounds.width > 0, bounds.height > 0 {
                rects = [bounds]
            }
        }
        return rects
    }

    private func clusterRects(_ rects: [CGRect], tolerance: CGFloat) -> [[CGRect]] {
        guard rects.count > 1 else { return rects.isEmpty ? [] : [rects] }
        var visited = Array(repeating: false, count: rects.count)
        var clusters: [[CGRect]] = []
        for i in 0..<rects.count {
            if visited[i] { continue }
            visited[i] = true
            var queue = [i]
            var cluster: [CGRect] = []
            while let idx = queue.popLast() {
                cluster.append(rects[idx])
                for j in 0..<rects.count where !visited[j] {
                    if rectsAreNeighbors(rects[idx], rects[j], tolerance: tolerance) {
                        visited[j] = true
                        queue.append(j)
                    }
                }
            }
            clusters.append(cluster)
        }
        return clusters
    }

    private func rectClusterUnion(_ rects: [CGRect]) -> CGRect {
        guard let first = rects.first else { return .zero }
        return rects.dropFirst().reduce(first) { $0.union($1) }
    }

    private func choosePrimaryRectCluster(_ clusters: [[CGRect]],
                                          anchor: CGPoint,
                                          fallbackRect: CGRect?) -> [CGRect] {
        guard !clusters.isEmpty else { return [] }
        if clusters.count == 1 { return clusters[0] }
        var best = clusters[0]
        var bestArea = rectArea(rectClusterUnion(best))
        var bestDistance = CGFloat.greatestFiniteMagnitude
        if let fallbackRect {
            bestDistance = annotationRectDistance(rectClusterUnion(best), fallbackRect)
        } else {
            bestDistance = annotationRectDistance(rectClusterUnion(best), CGRect(origin: anchor, size: .zero))
        }
        for cluster in clusters.dropFirst() {
            let union = rectClusterUnion(cluster)
            let area = rectArea(union)
            let dist = fallbackRect.map { annotationRectDistance(union, $0) }
                ?? annotationRectDistance(union, CGRect(origin: anchor, size: .zero))
            if area > bestArea + 0.5 || (abs(area - bestArea) <= 0.5 && dist < bestDistance) {
                best = cluster
                bestArea = area
                bestDistance = dist
            }
        }
        return best
    }

    private func selectionRectsForCommit(_ selection: PDFSelection,
                                         page: PDFPage,
                                         anchor: CGPoint) -> [CGRect] {
        let start = timingStart()
        var rects = selectionLineRects(selection, on: page).filter { rectIsFinite($0) }
        guard rects.count > 1 else {
            timingEnd("selection_rects", start)
            return rects
        }
        let selectionBounds = selection.bounds(for: page)
        if rectIsFinite(selectionBounds) {
            let heights = rects.map { $0.height }.filter { $0 > 0 }.sorted()
            if let medianHeight = heights.isEmpty ? nil : heights[heights.count / 2],
               medianHeight > 0,
               selectionBounds.height <= medianHeight * 1.6 {
                let targetY = selectionBounds.midY
                let filtered = rects.filter { abs($0.midY - targetY) <= medianHeight * 0.75 }
                if !filtered.isEmpty && filtered.count < rects.count {
                    if annotationDebugEnabled {
                        annotationLog("[ANN_SEL_LINE_FILTER] before=\(rects.count) after=\(filtered.count) sel_h=\(String(format: "%.2f", selectionBounds.height)) median_h=\(String(format: "%.2f", medianHeight))")
                    }
                    rects = filtered
                }
            }
        }
        let pageBounds = page.bounds(for: pdfView?.displayBox ?? .cropBox)
        let tolerance = max(10, pageBounds.height * 0.01)
        let clusters = clusterRects(rects, tolerance: tolerance)
        if clusters.count <= 1 {
            timingEnd("selection_rects", start)
            return rects
        }
        let fallback = selection.bounds(for: page)
        let primary = choosePrimaryRectCluster(clusters, anchor: anchor, fallbackRect: fallback)
        if annotationDebugEnabled {
            annotationLog("[ANN_SEL_CLUSTER] clusters=\(clusters.count) primary=\(primary.count) total=\(rects.count) anchor=\(NSStringFromPoint(anchor))")
            let dropped = clusters.flatMap { $0 }.filter { r in !primary.contains(where: { rectsNearlyEqual(r, $0, tolerance: 0.5) }) }
            if !dropped.isEmpty {
                annotationLog("[ANN_SEL_DROP] dropped=\(dropped.count) rects=\(debugRectsText(dropped))")
            }
        }
        rects = primary
        timingEnd("selection_rects", start)
        return rects
    }

    private func selectionIntersectsAnnotation(_ selection: PDFSelection,
                                               annotation: PDFAnnotation,
                                               on page: PDFPage,
                                               minOverlapRatio: CGFloat) -> Bool {
        let lineRects = selectionLineRects(selection, on: page)
        guard !lineRects.isEmpty else { return false }
        let annRects = quadRects(for: annotation)
        guard !annRects.isEmpty else { return false }
        for line in lineRects {
            let lineArea = rectArea(line)
            guard lineArea > 0 else { continue }
            for rect in annRects {
                let inter = line.intersection(rect)
                let interArea = rectArea(inter)
                if interArea <= 0 { continue }
                let denom = min(lineArea, rectArea(rect))
                if denom > 0 && (interArea / denom) >= minOverlapRatio {
                    return true
                }
            }
        }
        return false
    }

    private func selectionOverlapsAnnotations(_ selection: PDFSelection, annotations: [PDFAnnotation]) -> Bool {
        let pages = selection.pages
        guard !pages.isEmpty else { return false }
        for page in pages {
            for annotation in annotations {
                guard annotation.page === page else { continue }
                if selectionIntersectsAnnotation(selection,
                                                 annotation: annotation,
                                                 on: page,
                                                 minOverlapRatio: 0.2) {
                    return true
                }
            }
        }
        return false
    }

    private func removeHighlightedSelections(overlapping annotations: [PDFAnnotation]) {
        removeAnnotationSelectionOverlays(overlapping: annotations, reason: "overlap_remove")
    }

    private func updateHighlightedSelectionsColor(overlapping annotations: [PDFAnnotation],
                                                  color: NSColor,
                                                  style: AnnotationMarkupStyle? = nil) {
        guard !annotations.isEmpty else { return }
        removeAnnotationSelectionOverlays(overlapping: annotations, reason: "style_update")
        guard annotationSelectionOverlayEnabled else { return }
        let resolvedStyle = style ?? annotations.first.map(annotationMarkupStyle) ?? .highlight
        if resolvedStyle == .underline {
            removeHighlightedSelections(overlapping: annotations)
            return
        }
        // Clear any stale selection overlays and rebuild them with the new color.
        removeHighlightedSelections(overlapping: annotations)
        ensureHighlightedSelections(for: annotations, color: color, style: resolvedStyle)
    }

    private func selectionFromAnnotation(_ annotation: PDFAnnotation) -> PDFSelection? {
        guard let page = annotation.page else { return nil }
        let rects = quadRects(for: annotation)
        var selections: [PDFSelection] = []
        for rect in rects {
            if let sel = page.selection(for: rect) {
                selections.append(sel)
            }
        }
        guard let first = selections.first else { return nil }
        let combined = first
        for sel in selections.dropFirst() {
            combined.add(sel)
        }
        return combined
    }

    private func ensureHighlightedSelections(for annotations: [PDFAnnotation],
                                             color: NSColor,
                                             style: AnnotationMarkupStyle) {
        guard annotationSelectionOverlayEnabled else { return }
        guard style == .highlight, let pdfView else { return }
        let existing = pdfView.highlightedSelections ?? []
        for ann in annotations {
            guard ann.page != nil else { continue }
            if existing.contains(where: { selectionOverlapsAnnotations($0, annotations: [ann]) }) {
                continue
            }
            if let selection = selectionFromAnnotation(ann) {
                addHighlightedSelection(selection, color: color, source: "ensure_for_annotation")
            }
        }
    }

    private func highlightMatchesListItemText(_ annotation: PDFAnnotation, item: PDFAnnotationListItem, page: PDFPage) -> Bool {
        let itemText = normalizedAnnotationText(item.highlightText).lowercased()
        guard !itemText.isEmpty else { return false }
        let previewPage = annotation.page ?? page
        let annText = normalizedAnnotationText(annotationPreviewText(for: annotation, page: previewPage)).lowercased()
        guard !annText.isEmpty else { return false }
        if annText.hasPrefix(itemText) || itemText.hasPrefix(annText) {
            return true
        }
        return annText.contains(itemText) || itemText.contains(annText)
    }

    private func fallbackHighlights(for item: PDFAnnotationListItem, page: PDFPage) -> [PDFAnnotation] {
        guard let pdfView else { return [] }
        let highlights = page.annotations.filter { annotationIsHighlightLike($0) }
        let textMatches = highlights.filter { highlightMatchesListItemText($0, item: item, page: page) }
        if !textMatches.isEmpty {
            return textMatches
        }
        let anchor = item.anchorBounds
        guard rectIsUsable(anchor) else { return [] }
        let baseThreshold = annotationMatchThreshold(for: page, displayBox: pdfView.displayBox)
        let threshold = max(160, baseThreshold * 3)
        return highlights.filter { ann in
            annotationRectDistance(annotationAnchorRect(for: ann), anchor) <= threshold
        }
    }

    private let dropdownGlassFactory: () -> NSView

    private let defaultAnnotationColorHexDefaultsKey = "arxivPicker.annotation.defaultColorHex"

    private let noteBaseSize = CGSize(width: 24, height: 24)
    private let noteIconScale: CGFloat = 0.6 // 60% of default note icon size.
    private var noteIconSize: CGSize {
        CGSize(width: noteBaseSize.width * noteIconScale, height: noteBaseSize.height * noteIconScale)
    }

    init(pdfView: ZoomablePDFView, hostView: NSView, dropdownGlassFactory: @escaping () -> NSView) {
        self.pdfView = pdfView
        self.hostView = hostView
        self.dropdownGlassFactory = dropdownGlassFactory
        super.init()
        attachOverlay()
        installObservers()
        pdfView.onNoteTap = { [weak self] annotation in
            self?.presentComposer(for: annotation)
        }
        refreshIcons()

        // If requested via environment, capture an in-process snapshot shortly after
        // initialization so automated runs can inspect the host rendering without
        // requiring system screen-record permission.
        if ProcessInfo.processInfo.environment["ARXIV_CAPTURE_HOST_SNAPSHOT"] == "1" {
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) { [weak self] in
                guard let self else { return }
                let path = "/tmp/arxiv_snapshot_init_\(Int(Date().timeIntervalSince1970)).png"
                self.debugSaveHostSnapshot(to: path)
            }
        }

        // Prewarm the annotation composer view so it opens without first-use latency.
        prewarmComposerIfNeeded()

        // NOTE: removed automatic debug-trigger here. The annotation composer
        // must only appear in response to explicit user actions (Annotate).
    }

    deinit {
        removeObservers()
    }

    func beginAnnotation(at viewPoint: NSPoint, page: PDFPage) {
        guard let pdfView, let host = hostView else { return }
        let pagePoint = pdfView.convert(viewPoint, to: page)
        let crop = page.bounds(for: pdfView.displayBox)
        guard crop.contains(pagePoint) else { return }

        // Always prefer the user's current selection, even if the click is slightly outside.
        let selection = selectionForAnnotation(in: pdfView, page: page, pagePoint: pagePoint)
        let context = AnnotationContext(
            viewPointInView: viewPoint,
            viewPointInHost: pdfView.convert(viewPoint, to: host),
            page: page,
            pagePoint: pagePoint,
            selection: selection,
            existingAnnotation: nil
        )
        currentListItem = nil
        currentListItemID = nil
        pendingPageLabelOverride = nil
        pendingCreationDateOverride = nil
        currentContext = context
        presentComposer(context: context)
    }

    private func resizedNoteBounds(_ bounds: CGRect, targetSize: CGSize) -> CGRect {
        CGRect(
            x: bounds.midX - targetSize.width / 2,
            y: bounds.midY - targetSize.height / 2,
            width: targetSize.width,
            height: targetSize.height
        )
    }

    private func requestOverlayRefresh(reason: String) {
        _ = reason
        if overlayRefreshSuppressedProvider?() == true {
            overlayRefreshPending = true
            return
        }
        refreshIcons()
    }

    func flushPendingOverlayRefresh(reason: String) {
        _ = reason
        guard overlayRefreshPending else { return }
        overlayRefreshPending = false
        refreshIcons()
    }

    func setOverlayHidden(_ hidden: Bool) {
        overlay.isHidden = hidden
    }

    func refreshIcons() {
        let t0 = timingStart()
        guard let pdfView, let host = hostView else { return }
        pdfView.layoutSubtreeIfNeeded()
        host.layoutSubtreeIfNeeded()
        guard let doc = pdfView.document else {
            overlay.icons = []
            overlay.highlightRegions = []
            pdfView.highlightHitRegions = []
            timingEnd("refresh_icons_empty", t0)
            return
        }

        let targetNoteSize = noteIconSize
        var icons: [AnnotationIconOverlayView.Icon] = []
        for pageIndex in 0..<doc.pageCount {
            guard let page = doc.page(at: pageIndex) else { continue }
            ensureMarkupState(for: page)
            for ann in page.annotations where annotationIsTextNote(ann) {
                suppressNotePopupUI(for: ann)
                let safeBounds = sanitizedAnchorRect(ann.bounds, page: page, displayBox: .cropBox, minSize: targetNoteSize)
                if safeBounds != ann.bounds {
                    ann.bounds = safeBounds
                }
                if abs(ann.bounds.width - targetNoteSize.width) > 0.1 ||
                   abs(ann.bounds.height - targetNoteSize.height) > 0.1 {
                    let resized = resizedNoteBounds(ann.bounds, targetSize: targetNoteSize)
                    ann.bounds = clampedRect(resized, within: safePageBounds(page, displayBox: .cropBox), minSize: targetNoteSize)
                }
            }
        }
        overlay.icons = icons
        // ID-driven render: rebuild highlight regions from model state each refresh,
        // ensuring any prior rendered artifacts are cleared before drawing.
        // === Compute highlight regions for cursor + hit-testing ===
        var highlightHitRegions: [HighlightHitRegion] = []
        var highlightOverlayRegions: [AnnotationIconOverlayView.HighlightRegion] = []
#if DEBUG
        var renderPassIDs: Set<ObjectIdentifier> = []
#endif
        for pageIndex in 0..<doc.pageCount {
            guard let page = doc.page(at: pageIndex) else { continue }
            let pageBounds = page.bounds(for: pdfView.displayBox)

            for ann in page.annotations where annotationIsHighlightLike(ann) {
                let annID = ObjectIdentifier(ann)
#if DEBUG
                if renderPassIDs.contains(annID) {
                    annotationLog("[ANN_RENDER_DUP] id=\(annotationDebugID(ann)) page=\(pageIndex)")
                    assertionFailure("Duplicate render pass for annotation ID.")
                } else {
                    renderPassIDs.insert(annID)
                }
                if ann.page !== page {
                    annotationLog("[ANN_RENDER_PAGE_MISMATCH] id=\(annotationDebugID(ann)) iter_page=\(pageIndex)")
                    assertionFailure("Annotation page mismatch during render pass.")
                }
#endif
                let quadRects = quadRects(for: ann)
                if annotationDebugEnabled {
                    annotationLog("[ANN_RENDER_PASS] id=\(annotationDebugID(ann)) page=\(pageIndex) rects=\(debugRectsText(quadRects)) \(debugAnnotationTextRange(ann, page: page)) ctx=full_refresh")
                }
                for rect in quadRects where rect.width > 0 && rect.height > 0 {
#if DEBUG
                    if !rect.intersects(pageBounds) {
                        annotationLog("[ANN_RENDER_OOB] id=\(annotationDebugID(ann)) page=\(pageIndex) rect=\(NSStringFromRect(rect)) pageBounds=\(NSStringFromRect(pageBounds))")
                        assertionFailure("Rendered rect outside page bounds.")
                    }
#endif
                    if annotationDebugEnabled {
                        let style = annotationMarkupStyle(for: ann).rawValue
                        annotationLog("[ANN_RENDER] id=\(annotationDebugID(ann)) page=\(pageIndex) style=\(style) rect=\(NSStringFromRect(rect)) ctx=full_refresh")
                    }
                    let rectInView = pdfView.convert(rect, from: page)
                    highlightHitRegions.append(.init(annotation: ann, frame: rectInView, pageIndex: pageIndex))
                    let rectInOverlay = overlay.convert(rectInView, from: pdfView)
                    highlightOverlayRegions.append(.init(annotation: ann, frame: rectInOverlay, pageIndex: pageIndex))
                }
            }
        }
        pdfView.highlightHitRegions = highlightHitRegions
        overlay.highlightRegions = highlightOverlayRegions

        // Debug: when requested, briefly hide PDF highlight annotations so we can
        // determine whether the visible bars come from PDFKit (set env
        // ARXIV_DEBUG_HIDE_PDF_ANNOTATIONS=1). This is intentionally aggressive
        // and only intended for ephemeral debug runs.
        if ProcessInfo.processInfo.environment["ARXIV_DEBUG_HIDE_PDF_ANNOTATIONS"] == "1" {
            for pageIndex in 0..<doc.pageCount {
                guard let page = doc.page(at: pageIndex) else { continue }
                for ann in page.annotations where annotationIsHighlightLike(ann) {
                    ann.color = .clear
                    print("[DBG_HIDE_ANN] hid ann gid=\(noteGroupID(for: ann) ?? "-") page=\(pageIndex) bounds=\(NSStringFromRect(ann.bounds))")
                }
            }
        }

        // Debug: when requested, indicate overlays are disabled (for historical
        // runs where overlays were separate). Set ARXIV_DISABLE_CUSTOM_HIGHLIGHT_OVERLAY=1
        // to enable; this is a no-op for the current icon-only overlay.
        if ProcessInfo.processInfo.environment["ARXIV_DISABLE_CUSTOM_HIGHLIGHT_OVERLAY"] == "1" {
            print("[DBG_RENDER_SWITCH] Custom highlight overlays disabled; skipping overlay work")
        }
#if DEBUG
        assertRenderArtifactsValid(reason: "full_refresh")
#endif
        timingEnd("refresh_icons_full", t0)
    }

    private func annotationPageIndex(_ annotation: PDFAnnotation) -> Int {
        guard let page = annotation.page else { return -1 }
        return page.document?.index(for: page) ?? -1
    }

    private func buildHighlightRegions(for pages: [PDFPage], reason: String) -> (hit: [HighlightHitRegion], overlay: [AnnotationIconOverlayView.HighlightRegion]) {
        guard let pdfView else { return ([], []) }
        var highlightHitRegions: [HighlightHitRegion] = []
        var highlightOverlayRegions: [AnnotationIconOverlayView.HighlightRegion] = []
#if DEBUG
        var renderPassIDs: Set<ObjectIdentifier> = []
#endif
        for page in pages {
            ensureMarkupState(for: page)
            let pageIndex = page.document?.index(for: page) ?? -1
            let pageBounds = page.bounds(for: pdfView.displayBox)
            for ann in page.annotations where annotationIsHighlightLike(ann) {
#if DEBUG
                let annID = ObjectIdentifier(ann)
                if renderPassIDs.contains(annID) {
                    annotationLog("[ANN_RENDER_DUP] id=\(annotationDebugID(ann)) page=\(pageIndex) ctx=partial")
                    assertionFailure("Duplicate render pass for annotation ID.")
                } else {
                    renderPassIDs.insert(annID)
                }
                if ann.page !== page {
                    annotationLog("[ANN_RENDER_PAGE_MISMATCH] id=\(annotationDebugID(ann)) iter_page=\(pageIndex) ctx=partial")
                    assertionFailure("Annotation page mismatch during partial render pass.")
                }
#endif
                let quadRects = quadRects(for: ann)
                if annotationDebugEnabled {
                    annotationLog("[ANN_RENDER_PASS] id=\(annotationDebugID(ann)) page=\(pageIndex) rects=\(debugRectsText(quadRects)) \(debugAnnotationTextRange(ann, page: page)) ctx=partial:\(reason)")
                }
                for rect in quadRects where rect.width > 0 && rect.height > 0 {
#if DEBUG
                    if !rect.intersects(pageBounds) {
                        annotationLog("[ANN_RENDER_OOB] id=\(annotationDebugID(ann)) page=\(pageIndex) rect=\(NSStringFromRect(rect)) pageBounds=\(NSStringFromRect(pageBounds))")
                        assertionFailure("Rendered rect outside page bounds.")
                    }
#endif
                    if annotationDebugEnabled {
                        let style = annotationMarkupStyle(for: ann).rawValue
                        annotationLog("[ANN_RENDER] id=\(annotationDebugID(ann)) page=\(pageIndex) style=\(style) rect=\(NSStringFromRect(rect)) ctx=partial:\(reason)")
                    }
                    let rectInView = pdfView.convert(rect, from: page)
                    highlightHitRegions.append(.init(annotation: ann, frame: rectInView, pageIndex: pageIndex))
                    let rectInOverlay = overlay.convert(rectInView, from: pdfView)
                    highlightOverlayRegions.append(.init(annotation: ann, frame: rectInOverlay, pageIndex: pageIndex))
                }
            }
        }
        return (highlightHitRegions, highlightOverlayRegions)
    }

    private func refreshHighlightRegions(for pages: [PDFPage], reason: String) {
        guard let pdfView else { return }
        let t0 = timingStart()
        let pageIndices = Set(pages.compactMap { $0.document?.index(for: $0) })
        var existingHit = pdfView.highlightHitRegions
        var existingOverlay = overlay.highlightRegions
        if !pageIndices.isEmpty {
            existingHit.removeAll { region in
                if pageIndices.contains(region.pageIndex) { return true }
                return region.annotation.page == nil
            }
            existingOverlay.removeAll { region in
                if pageIndices.contains(region.pageIndex) { return true }
                return region.annotation.page == nil
            }
        } else {
            existingHit.removeAll { $0.annotation.page == nil }
            existingOverlay.removeAll { $0.annotation.page == nil }
        }
        let built = buildHighlightRegions(for: pages, reason: reason)
        existingHit.append(contentsOf: built.hit)
        existingOverlay.append(contentsOf: built.overlay)
        pdfView.highlightHitRegions = existingHit
        overlay.highlightRegions = existingOverlay
#if DEBUG
        assertRenderArtifactsValid(reason: "refresh:\(reason)")
#endif
        annotationTimingLog("refresh_icons_partial reason=\(reason) pages=\(pageIndices.count)")
        timingEnd("refresh_icons_partial", t0)
    }

    private func clearRenderArtifacts(for annotation: PDFAnnotation, reason: String) {
        guard let pdfView else { return }
        let beforeHit = pdfView.highlightHitRegions.count
        let beforeOverlay = overlay.highlightRegions.count
        if beforeHit > 0 {
            pdfView.highlightHitRegions.removeAll { $0.annotation === annotation }
        }
        if beforeOverlay > 0 {
            overlay.highlightRegions.removeAll { $0.annotation === annotation }
        }
        if annotationDebugEnabled {
            let hitDelta = beforeHit - pdfView.highlightHitRegions.count
            let overlayDelta = beforeOverlay - overlay.highlightRegions.count
            if hitDelta > 0 || overlayDelta > 0 {
                let pageIndex = annotation.page.flatMap { $0.document?.index(for: $0) } ?? -1
                let rects = quadRects(for: annotation)
                let style = annotationMarkupStyle(for: annotation).rawValue
                annotationLog("[ANN_RENDER_CLEAR] id=\(annotationDebugID(annotation)) page=\(pageIndex) style=\(style) rects=\(debugRectsText(rects)) hit_removed=\(hitDelta) overlay_removed=\(overlayDelta) reason=\(reason)")
            }
        }
    }

#if DEBUG
    private func assertRenderArtifactsValid(reason: String) {
        guard annotationDebugEnabled,
              let pdfView,
              let doc = pdfView.document else { return }

        func validate(regionPageIndex: Int, annotation: PDFAnnotation, source: String) {
            guard let page = annotation.page else {
                annotationLog("[ANN_RENDER_ASSERT] source=\(source) reason=\(reason) id=\(annotationDebugID(annotation)) error=missing_page")
                assertionFailure("Render artifact without page.")
                return
            }
            let actualIndex = doc.index(for: page)
            if actualIndex != regionPageIndex {
                annotationLog("[ANN_RENDER_ASSERT] source=\(source) reason=\(reason) id=\(annotationDebugID(annotation)) region_page=\(regionPageIndex) ann_page=\(actualIndex)")
                assertionFailure("Render artifact page mismatch.")
            }
            if !page.annotations.contains(where: { $0 === annotation }) {
                annotationLog("[ANN_RENDER_ASSERT] source=\(source) reason=\(reason) id=\(annotationDebugID(annotation)) error=annotation_not_in_page")
                assertionFailure("Render artifact without model annotation.")
            }
        }

        for region in pdfView.highlightHitRegions {
            validate(regionPageIndex: region.pageIndex, annotation: region.annotation, source: "hit")
        }
        for region in overlay.highlightRegions {
            validate(regionPageIndex: region.pageIndex, annotation: region.annotation, source: "overlay")
        }
    }
#endif

    private func ensureMarkupState(for page: PDFPage) {
        for ann in page.annotations where annotationIsHighlightLike(ann) && !annotationIsPreview(ann) {
            let hasStyleKey = ann.value(forAnnotationKey: annotationMarkupStyleKey) != nil
            let style = annotationMarkupStyle(for: ann)
            if !hasStyleKey {
                ann.setValue(style.rawValue, forAnnotationKey: annotationMarkupStyleKey)
                if annotationDebugEnabled {
                    let pageIndex = page.document?.index(for: page) ?? -1
                    annotationLog("[ANN_NORMALIZE] id=\(annotationDebugID(ann)) page=\(pageIndex) set_style=\(style.rawValue)")
                }
            }
            if ann.value(forAnnotationKey: annotationMarkupColorKey) == nil {
                let base = annotationDisplayBaseColor(for: ann).usingColorSpace(.deviceRGB)
                    ?? annotationDisplayBaseColor(for: ann)
                ann.setValue(base.withAlphaComponent(1.0), forAnnotationKey: annotationMarkupColorKey)
                if annotationDebugEnabled {
                    let pageIndex = page.document?.index(for: page) ?? -1
                    annotationLog("[ANN_NORMALIZE] id=\(annotationDebugID(ann)) page=\(pageIndex) set_color=\(hexFromColor(base, includeAlpha: false))")
                }
            }

            if let storedValue = ann.value(forAnnotationKey: annotationStoredQuadPointsKey),
               (storedValue as? [NSNumber]) == nil,
               let stored = storedQuadPointsFromValue(storedValue),
               !stored.isEmpty {
                storeQuadPoints(stored, on: ann)
            } else if ann.value(forAnnotationKey: annotationStoredQuadPointsKey) == nil,
                      let quadPoints = ann.quadrilateralPoints,
                      !quadPoints.isEmpty {
                storeQuadPoints(quadPoints, on: ann)
            }

            if style == .highlight {
                let alpha = ann.color.alphaComponent
                let ca = (ann.value(forAnnotationKey: PDFAnnotationKey(rawValue: "CA")) as? NSNumber)?.doubleValue ?? 1.0
                if alpha <= 0.01 || ca <= 0.01 {
                    applyMarkupStyleInPlace(ann, baseColor: annotationDisplayBaseColor(for: ann), style: .highlight)
                }
            }

            // Seed group quad-point metadata on the note for selection-independent updates.
            if let gid = noteGroupID(for: ann),
               let note = noteForGroup(gid, on: page),
               note.value(forAnnotationKey: annotationGroupQuadPointsKey) == nil {
                let quadPoints = annotationQuadPoints(for: ann)
                if let valid = validateQuadPoints(quadPoints, on: page) {
                    storeGroupQuadPoints(valid, on: note)
                    if annotationDebugEnabled {
                        annotationLog("[ANN_NORMALIZE] id=\(annotationDebugID(ann)) page=\(page.document?.index(for: page) ?? -1) seed_group_quads=\(valid.count)")
                    }
                }
            }
        }
    }

    /// Debug helper: save a snapshot of the host view (if present) to `path` as PNG.
    /// Does not require system screen-recording permission because the app renders
    /// its own view to an image and writes it to disk. Use env `ARXIV_CAPTURE_HOST_SNAPSHOT=1`.
    func debugSaveHostSnapshot(to path: String) {
        guard let host = hostView else { NSLog("[DBG_SNAP] no host view to snapshot"); return }
        let bounds = host.bounds
        guard let rep = host.bitmapImageRepForCachingDisplay(in: bounds) else { NSLog("[DBG_SNAP] bitmapImageRepForCachingDisplay failed"); return }
        host.cacheDisplay(in: bounds, to: rep)
        guard let data = rep.representation(using: .png, properties: [:]) else { NSLog("[DBG_SNAP] failed to encode PNG"); return }
        do {
            try data.write(to: URL(fileURLWithPath: path))
            NSLog("[DBG_SNAP] wrote snapshot to \(path)")
            print("[DBG_SNAP] wrote snapshot to \(path)")
        } catch {
            NSLog("[DBG_SNAP] write failed: \(error)")
            print("[DBG_SNAP] write failed: \(error)")
        }
    }

    private func attachOverlay() {
        guard let pdfView, let host = hostView else { return }
        overlay.translatesAutoresizingMaskIntoConstraints = false
        overlay.onIconTapped = { [weak self] ann in
            self?.presentComposer(for: ann)
        }
        overlay.onHighlightTapped = { [weak self] ann in
            guard let self else { return }
            // Avoid conflicting interactions while the composer is open.
            if self.isComposerVisible { return }
            self.lastHighlightOpenTimestamp = CACurrentMediaTime()
            self.openNoteForHighlight(ann)
        }
        overlay.pdfView = pdfView
        host.addSubview(overlay)
        overlayConstraints = [
            overlay.leadingAnchor.constraint(equalTo: pdfView.leadingAnchor),
            overlay.trailingAnchor.constraint(equalTo: pdfView.trailingAnchor),
            overlay.topAnchor.constraint(equalTo: pdfView.topAnchor),
            overlay.bottomAnchor.constraint(equalTo: pdfView.bottomAnchor)
        ]
        NSLayoutConstraint.activate(overlayConstraints)
        installHighlightMonitor()
    }

    private func installObservers() {
        guard let pdfView else { return }
        let center = NotificationCenter.default
        observers.append(center.addObserver(forName: .PDFViewScaleChanged, object: pdfView, queue: .main) { [weak self] _ in
            self?.requestOverlayRefresh(reason: "pdf_scale")
        })
        observers.append(center.addObserver(forName: .PDFViewPageChanged, object: pdfView, queue: .main) { [weak self] _ in
            self?.requestOverlayRefresh(reason: "pdf_page")
        })
        observers.append(center.addObserver(forName: .PDFViewDocumentChanged, object: pdfView, queue: .main) { [weak self] _ in
            self?.requestOverlayRefresh(reason: "pdf_document")
        })

        if let scrollView = primaryScrollView(in: pdfView) {
            scrollView.contentView.postsBoundsChangedNotifications = true
            scrollObserver = center.addObserver(forName: NSView.boundsDidChangeNotification,
                                                object: scrollView.contentView,
                                                queue: .main) { [weak self] _ in
                self?.requestOverlayRefresh(reason: "pdf_scroll")
            }
        }
    }

    private func installHighlightMonitor() {
        guard highlightMonitor == nil else { return }
        highlightMonitor = NSEvent.addLocalMonitorForEvents(matching: [.leftMouseDown, .leftMouseDragged, .leftMouseUp]) { [weak self] event in
            guard let self, let pdfView = self.pdfView else { return event }
            guard event.window === pdfView.window else { return event }
            guard !pdfView.isHidden else { return event }
            if self.isComposerVisible { return event }

            let pointInView = pdfView.convert(event.locationInWindow, from: nil)
            guard pdfView.bounds.contains(pointInView) else {
                if event.type == .leftMouseDown {
                    self.resetHighlightMonitor()
                }
                return event
            }

            switch event.type {
            case .leftMouseDown:
                self.highlightMonitorCandidate = self.highlightAnnotation(at: pointInView)
                self.highlightMonitorStart = pointInView
                self.highlightMonitorDidDrag = false
                if self.highlightHitDebugEnabled {
                    let hit = self.highlightMonitorCandidate != nil ? "hit" : "miss"
                    print("[HIGHLIGHT_MON] down \(hit) point=\(NSStringFromPoint(pointInView))")
                }
            case .leftMouseDragged:
                if let start = self.highlightMonitorStart {
                    let cur = pointInView
                    if abs(cur.x - start.x) > self.highlightMonitorDragThreshold ||
                        abs(cur.y - start.y) > self.highlightMonitorDragThreshold {
                        self.highlightMonitorDidDrag = true
                    }
                }
            case .leftMouseUp:
                defer { self.resetHighlightMonitor() }
                guard let candidate = self.highlightMonitorCandidate else { return event }
                guard !self.highlightMonitorDidDrag else { return event }
                guard event.clickCount == 1 else { return event }
                let mods = event.modifierFlags.intersection([.shift, .option, .command, .control])
                guard mods.isEmpty else { return event }
                if CACurrentMediaTime() - self.lastHighlightOpenTimestamp < 0.12 {
                    return event
                }
                self.lastHighlightOpenTimestamp = CACurrentMediaTime()
                if self.highlightHitDebugEnabled {
                    print("[HIGHLIGHT_MON] open point=\(NSStringFromPoint(pointInView))")
                }
                self.openNoteForHighlight(candidate)
            default:
                break
            }

            return event
        }
    }

    private func resetHighlightMonitor() {
        highlightMonitorCandidate = nil
        highlightMonitorStart = nil
        highlightMonitorDidDrag = false
    }

    private func removeObservers() {
        let center = NotificationCenter.default
        for obs in observers { center.removeObserver(obs) }
        if let scrollObserver { center.removeObserver(scrollObserver) }
        observers.removeAll()
        scrollObserver = nil
        if let monitor = highlightMonitor {
            NSEvent.removeMonitor(monitor)
            highlightMonitor = nil
        }
    }

    private func noteGroupID(for annotation: PDFAnnotation) -> String? {
        annotation.value(forAnnotationKey: annotationNoteGroupKey) as? String
    }

    private func assignGroupID(_ id: String, to annotation: PDFAnnotation) {
        annotation.setValue(id, forAnnotationKey: annotationNoteGroupKey)
    }

    private func resolvedPage(for item: PDFAnnotationListItem, document: PDFDocument) -> PDFPage {
        if let page = document.page(at: item.pageIndex) {
            return page
        }
        return item.page
    }

    private func annotationsForListItem(_ item: PDFAnnotationListItem, page: PDFPage) -> [PDFAnnotation] {
        let direct = (item.highlightAnnotations + item.noteAnnotations).filter { $0.page === page }
        if !direct.isEmpty { return direct }
        let groupID = item.stableID
        let grouped = page.annotations.filter { noteGroupID(for: $0) == groupID }
        if !grouped.isEmpty { return grouped }

        let stableKeys = stableKeysForSyntheticGroupID(groupID)
        guard !stableKeys.isEmpty else { return [] }
        let pageIndex = item.pageIndex
        return page.annotations.filter { ann in
            let key = annotationStableKey(ann, pageIndex: pageIndex)
            return stableKeys.contains(key)
        }
    }

    private func primaryAnnotation(for item: PDFAnnotationListItem, page: PDFPage) -> PDFAnnotation? {
        if let direct = (item.highlightAnnotations + item.noteAnnotations).first(where: { $0.page === page }) {
            return direct
        }
        let groupID = item.stableID
        return page.annotations.first(where: { noteGroupID(for: $0) == groupID })
    }

    func primaryAnnotation(for item: PDFAnnotationListItem) -> PDFAnnotation? {
        guard let pdfView, let doc = pdfView.document else { return nil }
        let page = resolvedPage(for: item, document: doc)
        return primaryAnnotation(for: item, page: page)
    }

    private func stableKeysForSyntheticGroupID(_ groupID: String) -> [String] {
        let syntheticHighlightPrefix = "synthetic-h|"
        let syntheticNotePrefix = "synthetic-n|"
        let pairedPrefix = "paired|"
        if groupID.hasPrefix(syntheticHighlightPrefix) {
            return [String(groupID.dropFirst(syntheticHighlightPrefix.count))]
        }
        if groupID.hasPrefix(syntheticNotePrefix) {
            return [String(groupID.dropFirst(syntheticNotePrefix.count))]
        }
        if groupID.hasPrefix(pairedPrefix) {
            let remainder = String(groupID.dropFirst(pairedPrefix.count))
            let parts = remainder.split(separator: "|", omittingEmptySubsequences: false)
            let keyPartsCount = 6
            guard parts.count >= keyPartsCount * 2 else { return [] }
            let first = parts.prefix(keyPartsCount).joined(separator: "|")
            let second = parts.dropFirst(keyPartsCount).prefix(keyPartsCount).joined(separator: "|")
            return [first, second]
        }
        return []
    }

    private func highlightColor(for tagColor: NSColor, style: AnnotationMarkupStyle = .highlight) -> NSColor {
        // Slightly higher alpha so highlights remain visible after submitting the composer.
        // Increase alpha to make persisted highlights more noticeable and persistent-looking.
        let base = tagColor.usingColorSpace(.deviceRGB) ?? tagColor
        switch style {
        case .underline:
            return base.withAlphaComponent(1.0)
        case .highlight:
            let alpha: CGFloat = isAppLightAppearance() ? 0.70 : 0.60
            return base.withAlphaComponent(alpha)
        }
    }

    private func applyMarkupBorder(_ annotation: PDFAnnotation, style: AnnotationMarkupStyle) {
        switch style {
        case .underline:
            if annotation.border != nil {
                annotation.border = nil
            }
            annotation.removeValue(forAnnotationKey: .border)
            annotation.removeValue(forAnnotationKey: PDFAnnotationKey(rawValue: "LineWidth"))
        case .highlight:
            if annotation.border != nil {
                annotation.border = nil
            }
            annotation.removeValue(forAnnotationKey: .border)
            annotation.removeValue(forAnnotationKey: PDFAnnotationKey(rawValue: "LineWidth"))
        }
    }

    private func applyHighlightColor(_ annotation: PDFAnnotation,
                                     baseColor: NSColor,
                                     style: AnnotationMarkupStyle? = nil) {
        let resolvedStyle = style ?? annotationMarkupStyle(for: annotation)
        annotation.setValue(resolvedStyle.rawValue, forAnnotationKey: annotationMarkupStyleKey)
        let tint = highlightColor(for: baseColor, style: resolvedStyle)
        annotation.color = tint
        annotation.setValue(tint, forAnnotationKey: .color)
        annotation.setValue((baseColor.usingColorSpace(.deviceRGB) ?? baseColor).withAlphaComponent(1.0),
                            forAnnotationKey: annotationMarkupColorKey)
        let opacity: CGFloat = (resolvedStyle == .highlight)
            ? (isAppLightAppearance() ? 0.45 : 0.35)
            : 1.0
        annotation.setValue(opacity, forAnnotationKey: PDFAnnotationKey(rawValue: "CA"))
        if resolvedStyle == .highlight {
            annotation.setValue(tint, forAnnotationKey: .interiorColor)
        } else {
            annotation.removeValue(forAnnotationKey: .interiorColor)
        }
        applyMarkupBorder(annotation, style: resolvedStyle)
        invalidateAnnotationAppearance(annotation)
        updateAnnotation(annotation, reason: "apply_color")
    }

    // Root cause (Color bug): color changes flowed through style mutations that could clear or
    // mis-apply geometry, and in some cases depended on transient selection state. Zotero treats
    // color changes as pure model updates (position stays fixed; only color changes). We follow
    // that pattern here: mutate color fields in-place and reapply stored quad points/bounds so
    // rendering never depends on current selection.
    private func applyMarkupColorOnly(_ annotation: PDFAnnotation,
                                      baseColor: NSColor,
                                      style: AnnotationMarkupStyle,
                                      source: String) {
        let base = baseColor.usingColorSpace(.deviceRGB) ?? baseColor
        let typeName = annotationTypeName(annotation)
        let typeBefore = typeName
        // Color-only updates must not flip overlay modes; preserve any existing overlay flag.
        let overlayFlag = (annotation.value(forAnnotationKey: annotationOverlayHighlightKey) as? Bool) == true
        let currentStyle = annotationMarkupStyle(for: annotation)
        let effectiveStyle = (currentStyle == style) ? style : currentStyle
        if currentStyle != style, annotationDebugEnabled {
            annotationLog("[ANN_COLOR_MISMATCH] source=\(source) id=\(annotationDebugID(annotation)) ui_style=\(style.rawValue) ann_style=\(currentStyle.rawValue)")
        }
        let needsOverlayUnderline = (effectiveStyle == .underline && typeName != "underline")
        let usesOverlayHighlight = overlayFlag

        if annotationDebugEnabled {
            annotationLog("[ANN_COLOR] start source=\(source) mode=mutate_in_place \(debugAnnotationRenderState(annotation))")
        }

        annotation.setValue(effectiveStyle.rawValue, forAnnotationKey: annotationMarkupStyleKey)
        annotation.setValue(base.withAlphaComponent(1.0), forAnnotationKey: annotationMarkupColorKey)
        if overlayFlag {
            annotation.setValue(true, forAnnotationKey: annotationOverlayHighlightKey)
        } else {
            annotation.removeValue(forAnnotationKey: annotationOverlayHighlightKey)
        }

        if usesOverlayHighlight || needsOverlayUnderline {
            let clear = base.withAlphaComponent(0.0)
            annotation.color = clear
            annotation.setValue(clear, forAnnotationKey: .color)
            annotation.setValue(0.0, forAnnotationKey: PDFAnnotationKey(rawValue: "CA"))
            annotation.removeValue(forAnnotationKey: .interiorColor)
            applyMarkupBorder(annotation, style: effectiveStyle)
            invalidateAnnotationAppearance(annotation)
            updateAnnotation(annotation, reason: "apply_color_overlay")
        } else {
            // Applies highlight/underline color without changing subtype.
            applyHighlightColor(annotation, baseColor: base, style: effectiveStyle)
        }

        ensureMarkupAnnotationVisible(annotation)

        if annotationDebugEnabled {
            annotationLog("[ANN_COLOR] end source=\(source) mode=mutate_in_place \(debugAnnotationRenderState(annotation))")
        }
#if DEBUG
        if annotationDebugEnabled {
            let quadRects = annotationQuadRects(for: annotation)
            if quadRects.isEmpty {
                annotationLog("[ANN_COLOR_ASSERT] source=\(source) id=\(annotationDebugID(annotation)) error=missing_rects")
                assertionFailure("Color update removed annotation geometry.")
            }
            let typeAfter = annotationTypeName(annotation)
            if typeAfter != typeBefore {
                annotationLog("[ANN_COLOR_ASSERT] source=\(source) id=\(annotationDebugID(annotation)) error=subtype_changed before=\(typeBefore) after=\(typeAfter)")
                assertionFailure("Color update must not change annotation subtype.")
            }
        }
#endif
    }

    private func ensureGeometryForColorUpdate(_ annotation: PDFAnnotation,
                                              groupID: String,
                                              page: PDFPage,
                                              fallbackNote: PDFAnnotation?,
                                              source: String) {
        var pageQuadPoints = annotationQuadPoints(for: annotation)
        var sourceTag = "stored"
        if let valid = validateQuadPoints(pageQuadPoints, on: page) {
            pageQuadPoints = valid
        } else {
            pageQuadPoints = []
        }
        if pageQuadPoints.isEmpty,
           let cached = cachedGroupQuadPoints(for: groupID, page: page, fallbackNote: fallbackNote),
           let valid = validateQuadPoints(cached, on: page) {
            pageQuadPoints = valid
            sourceTag = "cached"
        }
        if pageQuadPoints.isEmpty, rectIsUsable(annotation.bounds) {
            let fallback = quadrilateralPoints(for: annotation.bounds)
            if let valid = validateQuadPoints(fallback, on: page) {
                pageQuadPoints = valid
                sourceTag = "bounds"
            }
        }
        guard !pageQuadPoints.isEmpty else {
            if annotationDebugEnabled {
                annotationLog("[ANN_COLOR_GEOM] source=\(source) id=\(annotationDebugID(annotation)) error=missing_quads")
            }
            return
        }
        let rects = quadRects(from: pageQuadPoints)
        if let first = rects.first {
            let union = rects.dropFirst().reduce(first) { $0.union($1) }
            if rectIsUsable(union) {
                annotation.bounds = union
            }
        }
        storeQuadPoints(pageQuadPoints, on: annotation)
        if annotationDebugEnabled {
            annotationLog("[ANN_COLOR_GEOM] source=\(source) id=\(annotationDebugID(annotation)) restored=\(sourceTag) rects=\(debugRectsText(rects))")
        }
    }

    private func annotationHasValidQuadPoints(_ annotation: PDFAnnotation, page: PDFPage) -> Bool {
        let pageQuads = annotationQuadPoints(for: annotation)
        return validateQuadPoints(pageQuads, on: page) != nil
    }

    private func setAnnotationSubtypeInPlace(_ annotation: PDFAnnotation,
                                             style: AnnotationMarkupStyle) -> Bool {
        let targets = style == .underline
            ? ["Underline", "/Underline", "underline", "/underline"]
            : ["Highlight", "/Highlight", "highlight", "/highlight"]
        let expected = style == .underline ? "underline" : "highlight"
        for value in targets {
            annotation.setValue(value, forAnnotationKey: annotationSubtypeKey)
            if annotationTypeName(annotation) == expected {
                return true
            }
        }
        return annotationTypeName(annotation) == expected
    }

    private func applyMarkupStyleInPlace(_ annotation: PDFAnnotation,
                                         baseColor: NSColor,
                                         style: AnnotationMarkupStyle) {
        let previousStyle = annotationMarkupStyle(for: annotation)
        if annotationDebugEnabled {
            let page = annotation.page
            let pageIndex = page.flatMap { $0.document?.index(for: $0) } ?? -1
            let rects = quadRects(for: annotation)
            let text = debugAnnotationTextRange(annotation, page: page)
            annotationLog("[ANN_STYLE] id=\(annotationDebugID(annotation)) page=\(pageIndex) from=\(previousStyle.rawValue) to=\(style.rawValue) rects=\(debugRectsText(rects)) \(text)")
        }
        // Preserve identity + metadata so subtype flips don't drop group IDs/quad points.
        // Root cause (Bug B): PDFKit subtype changes can clear custom keys, which makes list grouping
        // fall back to proximity and merge adjacent annotations. Restoring keys keeps identity stable.
        let preservedGroupID = noteGroupID(for: annotation)
        let preservedBounds = annotation.bounds
        let preservedPageQuadPoints = annotationQuadPoints(for: annotation)
        let fallbackQuads: [NSValue]? = rectIsUsable(preservedBounds) ? quadrilateralPoints(for: preservedBounds) : nil
        let preservedQuadPoints: Any? = annotation.value(forAnnotationKey: annotationStoredQuadPointsKey)
            ?? annotation.quadrilateralPoints
            ?? fallbackQuads
        let preservedAnchorRect: CGRect = {
            if !preservedPageQuadPoints.isEmpty {
                let rects = quadRects(from: preservedPageQuadPoints)
                if let first = rects.first {
                    let union = rects.dropFirst().reduce(first) { $0.union($1) }
                    if rectIsUsable(union) { return union }
                }
            }
            return rectIsUsable(preservedBounds) ? preservedBounds : annotation.bounds
        }()
        let preservedPageLabel = annotation.value(forAnnotationKey: annotationPageLabelOverrideKey)
        let preservedRichText = annotation.value(forAnnotationKey: annotationRichTextKey)
        let preservedCreationDate = annotation.value(forAnnotationKey: annotationCreationDateKey)

        let base = baseColor.usingColorSpace(.deviceRGB) ?? baseColor
        annotation.setValue(style.rawValue, forAnnotationKey: annotationMarkupStyleKey)
        annotation.setValue(base.withAlphaComponent(1.0), forAnnotationKey: annotationMarkupColorKey)
        let subtypeChanged = setAnnotationSubtypeInPlace(annotation, style: style)
        let typeName = annotationTypeName(annotation)

        let needsOverlayUnderline = (style == .underline && typeName == "highlight")
        let needsOverlayHighlight = (style == .highlight && typeName == "underline" && !subtypeChanged)

        func reapplyAnnotationGeometry(pagePoints: [NSValue], fallbackBounds: CGRect) -> Bool {
            var points = pagePoints
            if points.isEmpty, rectIsUsable(fallbackBounds) {
                points = quadrilateralPoints(for: fallbackBounds)
            }
            if !points.isEmpty {
                let rects = quadRects(from: points)
                if let first = rects.first {
                    let union = rects.dropFirst().reduce(first) { $0.union($1) }
                    if rectIsUsable(union) {
                        annotation.bounds = union
                    }
                }
                storeQuadPoints(points, on: annotation)
                return true
            }
            if rectIsUsable(fallbackBounds) {
                annotation.bounds = fallbackBounds
            }
            return false
        }

        if needsOverlayUnderline || needsOverlayHighlight {
            let clear = base.withAlphaComponent(0.0)
            annotation.color = clear
            annotation.setValue(clear, forAnnotationKey: .color)
            annotation.setValue(0.0, forAnnotationKey: PDFAnnotationKey(rawValue: "CA"))
            annotation.removeValue(forAnnotationKey: .interiorColor)
            applyMarkupBorder(annotation, style: style)
            if needsOverlayHighlight {
                annotation.setValue(true, forAnnotationKey: annotationOverlayHighlightKey)
            } else {
                annotation.removeValue(forAnnotationKey: annotationOverlayHighlightKey)
            }
            invalidateAnnotationAppearance(annotation)
            updateAnnotation(annotation, reason: "apply_style_overlay")
            if let gid = preservedGroupID { assignGroupID(gid, to: annotation) }
            restoreStoredQuadPoints(preservedQuadPoints, on: annotation)
            _ = reapplyAnnotationGeometry(pagePoints: preservedPageQuadPoints, fallbackBounds: preservedAnchorRect)
            ensureMarkupAnnotationVisible(annotation)
            if let label = preservedPageLabel { annotation.setValue(label, forAnnotationKey: annotationPageLabelOverrideKey) }
            if let rich = preservedRichText { annotation.setValue(rich, forAnnotationKey: annotationRichTextKey) }
            if let created = preservedCreationDate { annotation.setValue(created, forAnnotationKey: annotationCreationDateKey) }
            return
        }

        annotation.removeValue(forAnnotationKey: annotationOverlayHighlightKey)
        if let gid = preservedGroupID { assignGroupID(gid, to: annotation) }
        restoreStoredQuadPoints(preservedQuadPoints, on: annotation)
        applyHighlightColor(annotation, baseColor: base, style: style)
        let geometryUpdated = reapplyAnnotationGeometry(pagePoints: preservedPageQuadPoints, fallbackBounds: preservedAnchorRect)
        if geometryUpdated {
            invalidateAnnotationAppearance(annotation)
        }
        ensureMarkupAnnotationVisible(annotation)
        if let label = preservedPageLabel { annotation.setValue(label, forAnnotationKey: annotationPageLabelOverrideKey) }
        if let rich = preservedRichText { annotation.setValue(rich, forAnnotationKey: annotationRichTextKey) }
        if let created = preservedCreationDate { annotation.setValue(created, forAnnotationKey: annotationCreationDateKey) }
    }

    private func mutateHighlightAnnotationsInPlace(_ annotations: [PDFAnnotation],
                                                   groupID: String?,
                                                   baseColor: NSColor,
                                                   styleOverride: AnnotationMarkupStyle? = nil) -> [PDFAnnotation] {
        var updated: [PDFAnnotation] = []
        for ann in annotations {
            guard annotationIsHighlightLike(ann),
                  !annotationIsPreview(ann),
                  ann.page != nil else { continue }
            if let groupID {
                assignGroupID(groupID, to: ann)
            }
            let targetStyle = styleOverride ?? annotationMarkupStyle(for: ann)
            applyMarkupStyleInPlace(ann, baseColor: baseColor, style: targetStyle)
            updated.append(ann)
        }
        return updated
    }

    private func normalizeMarkupAnnotationsForExport(document: PDFDocument, sourceDocument: PDFDocument) {
        let pageCount = min(document.pageCount, sourceDocument.pageCount)
        guard pageCount > 0 else { return }

        for index in 0..<pageCount {
            guard let exportPage = document.page(at: index),
                  let sourcePage = sourceDocument.page(at: index) else { continue }

            // Remove all markup/text annotations in the export doc so we only emit one per group.
            let existing = exportPage.annotations.filter { annotationIsHighlightLike($0) || annotationIsTextNote($0) }
            for ann in existing {
                exportPage.removeAnnotation(ann)
            }

            // Map note text by group ID so we can attach it to the unified markup annotation.
            var noteTextByGroupID: [String: String] = [:]
            for note in sourcePage.annotations where annotationIsTextNote(note) && !annotationIsPreview(note) {
                guard let gid = noteGroupID(for: note) else { continue }
                let text = note.contents?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                if !text.isEmpty {
                    noteTextByGroupID[gid] = text
                }
            }

            struct ExportGroup {
                var rects: [CGRect] = []
                var color: NSColor = .systemYellow
                var style: AnnotationMarkupStyle = .highlight
                var contents: String = ""
                var userName: String?
                var created: Any?
                var modified: Date?
                var pageLabelOverride: Any?
                var groupID: String?
            }

            var groups: [String: ExportGroup] = [:]

            let sourceHighlights = sourcePage.annotations.filter { annotationIsHighlightLike($0) && !annotationIsPreview($0) }
            for annotation in sourceHighlights {
                let gid = noteGroupID(for: annotation) ?? annotationDebugID(annotation)
                var group = groups[gid] ?? ExportGroup()
                group.groupID = noteGroupID(for: annotation) ?? group.groupID
                group.style = (group.style == .underline || annotationMarkupStyle(for: annotation) == .underline) ? .underline : .highlight
                group.color = annotationStoredBaseColor(for: annotation) ?? annotation.color ?? group.color
                group.rects.append(contentsOf: quadRects(for: annotation))
                if group.contents.isEmpty {
                    let noteText = noteGroupID(for: annotation).flatMap { noteTextByGroupID[$0] } ?? ""
                    let fallback = annotation.contents ?? ""
                    group.contents = (noteText.isEmpty ? fallback : noteText)
                }
                if group.userName == nil { group.userName = annotation.userName }
                if group.created == nil { group.created = annotation.value(forAnnotationKey: annotationCreationDateKey) }
                if group.modified == nil { group.modified = annotation.modificationDate }
                if group.pageLabelOverride == nil {
                    group.pageLabelOverride = annotation.value(forAnnotationKey: annotationPageLabelOverrideKey)
                }
                groups[gid] = group
            }

            for (_, group) in groups {
                let rects = group.rects.filter { $0.width > 0 && $0.height > 0 }
                guard !rects.isEmpty else { continue }
                let normalizedPoints = rects.flatMap { quadrilateralPoints(for: $0) }
                guard !normalizedPoints.isEmpty else { continue }
                let union = rects.dropFirst().reduce(rects[0]) { $0.union($1) }

                let exported = PDFAnnotation(bounds: union,
                                             forType: annotationSubtype(for: group.style),
                                             withProperties: nil)
                exported.quadrilateralPoints = normalizedPoints
                exported.setValue(normalizedPoints, forAnnotationKey: PDFAnnotationKey(rawValue: "QuadPoints"))
                storeQuadPoints(normalizedPoints, on: exported)

                let trimmed = group.contents.trimmingCharacters(in: .whitespacesAndNewlines)
                if !trimmed.isEmpty {
                    exported.contents = trimmed
                }
                if let userName = group.userName {
                    exported.userName = userName
                }
                if let overrideLabel = group.pageLabelOverride {
                    exported.setValue(overrideLabel, forAnnotationKey: annotationPageLabelOverrideKey)
                }
                if let created = group.created {
                    exported.setValue(created, forAnnotationKey: annotationCreationDateKey)
                }
                if let modified = group.modified {
                    exported.modificationDate = modified
                }
                if let gid = group.groupID {
                    assignGroupID(gid, to: exported)
                }

                if !trimmed.isEmpty {
                    let popupRect = noteRect(for: exportPage,
                                             anchor: NSPoint(x: union.minX, y: union.midY),
                                             selectionBounds: union)
                    let popupSubtype = PDFAnnotationSubtype(rawValue: "Popup")
                    let popup = PDFAnnotation(bounds: popupRect, forType: popupSubtype, withProperties: nil)
                    popup.contents = trimmed
                    popup.isOpen = false
                    exported.popup = popup
                }

                applyHighlightColor(exported, baseColor: group.color, style: group.style)
                ensureMarkupAnnotationVisible(exported)
                exportPage.addAnnotation(exported)
            }
        }
    }

    private func invalidateAnnotationAppearance(_ annotation: PDFAnnotation) {
        // PDFKit can cache highlight appearance streams; clearing forces a redraw with the new color.
        let removeAllSelector = NSSelectorFromString("removeAllAppearanceStreams")
        if annotation.responds(to: removeAllSelector) {
            annotation.perform(removeAllSelector)
        }
        annotation.removeValue(forAnnotationKey: PDFAnnotationKey(rawValue: "AP"))
        annotation.removeValue(forAnnotationKey: PDFAnnotationKey(rawValue: "AS"))
        invalidateAnnotationDisplay(annotation)
    }

    private func invalidateAnnotationDisplay(_ annotation: PDFAnnotation) {
        guard let pdfView, let page = annotation.page else { return }
        let rects = quadRects(for: annotation)
        for rect in rects {
            let viewRect = pdfView.convert(rect, from: page).insetBy(dx: -2, dy: -2)
            pdfView.setNeedsDisplay(viewRect)
            if let docView = pdfView.documentView {
                let docRect = pdfView.convert(viewRect, to: docView)
                docView.setNeedsDisplay(docRect)
            }
        }
        pdfView.setNeedsDisplay(pdfView.bounds)
    }

    private func ensureMarkupAnnotationVisible(_ annotation: PDFAnnotation) {
        if !annotation.shouldDisplay {
            annotation.shouldDisplay = true
        }
        if !annotation.shouldPrint {
            annotation.shouldPrint = true
        }
    }

    private func highlightSubtype(for annotation: PDFAnnotation) -> PDFAnnotationSubtype {
        switch annotationTypeName(annotation) {
        case "underline":
            return .underline
        case "strikeout":
            return .strikeOut
        default:
            return .highlight
        }
    }

    private func rebuildHighlightAnnotation(_ annotation: PDFAnnotation,
                                            baseColor: NSColor,
                                            groupIDOverride: String? = nil,
                                            subtypeOverride: PDFAnnotationSubtype? = nil) -> PDFAnnotation? {
        guard annotation.page != nil else { return nil }
        let subtype = subtypeOverride ?? highlightSubtype(for: annotation)
        let storedQuadPoints = storedQuadPointsFromValue(annotation.value(forAnnotationKey: annotationStoredQuadPointsKey))
        let sourceQuadPoints: [NSValue]? = {
            if let quadPoints = annotation.quadrilateralPoints, !quadPoints.isEmpty {
                return normalizeQuadPoints(quadPoints, for: annotation)
            }
            if let storedQuadPoints, !storedQuadPoints.isEmpty {
                return normalizeQuadPoints(storedQuadPoints, for: annotation)
            }
            return nil
        }()
        var targetBounds = annotation.bounds
        if let quadPoints = sourceQuadPoints, !quadPoints.isEmpty {
            let rects = quadRects(from: quadPoints)
            if let first = rects.first {
                targetBounds = rects.dropFirst().reduce(first) { $0.union($1) }
            }
        }
        annotation.bounds = targetBounds
        if let quadPoints = sourceQuadPoints, !quadPoints.isEmpty {
            if quadPoints.count % 4 == 0 {
                // Preserve existing quad ordering; some PDFKit renders are sensitive to point order.
                annotation.quadrilateralPoints = quadPoints
            } else {
                let rects = quadRects(for: annotation)
                let normalized = rects.flatMap { quadrilateralPoints(for: $0) }
                annotation.quadrilateralPoints = normalized.isEmpty ? quadPoints : normalized
            }
        } else {
            annotation.quadrilateralPoints = quadrilateralPoints(for: targetBounds)
        }
        if let quads = annotation.quadrilateralPoints, !quads.isEmpty {
            storeQuadPoints(quads, on: annotation)
        }
        // Persist custom quad points in a PDF-safe format so we can restore after subtype changes.
        let groupID = groupIDOverride ?? noteGroupID(for: annotation)
        if let groupID {
            assignGroupID(groupID, to: annotation)
        }
        ensureMarkupAnnotationVisible(annotation)
        let style: AnnotationMarkupStyle = (subtype == .underline) ? .underline : .highlight
        applyMarkupStyleInPlace(annotation, baseColor: baseColor, style: style)
        return annotation
    }

    private func loadDefaultAnnotationColor() -> NSColor {
        guard let raw = UserDefaults.standard.string(forKey: defaultAnnotationColorHexDefaultsKey),
              let color = colorFromHex(raw) else {
            return .systemYellow
        }
        return color
    }

    private func persistDefaultAnnotationColor(_ color: NSColor) {
        UserDefaults.standard.set(hexFromColor(color, includeAlpha: true), forKey: defaultAnnotationColorHexDefaultsKey)
    }

    private func quadRects(for annotation: PDFAnnotation) -> [CGRect] {
        annotationQuadRects(for: annotation)
    }

    private func quadRects(from quadPoints: [NSValue]) -> [CGRect] {
        guard quadPoints.count >= 4 else { return [] }
        var rects: [CGRect] = []
        var idx = 0
        while idx + 3 < quadPoints.count {
            let points = [
                quadPoints[idx].pointValue,
                quadPoints[idx + 1].pointValue,
                quadPoints[idx + 2].pointValue,
                quadPoints[idx + 3].pointValue
            ]
            let xs = points.map { $0.x }
            let ys = points.map { $0.y }
            let minX = xs.min() ?? 0
            let maxX = xs.max() ?? 0
            let minY = ys.min() ?? 0
            let maxY = ys.max() ?? 0
            let rect = CGRect(x: minX, y: minY, width: max(0, maxX - minX), height: max(0, maxY - minY))
            if rect.width > 0 && rect.height > 0 {
                rects.append(rect)
            }
            idx += 4
        }
        return rects
    }

    private func quadrilateralPoints(for rect: CGRect) -> [NSValue] {
        // PDF highlight quad points are in page coordinates.
        // Order: top-left, top-right, bottom-left, bottom-right.
        let tl = NSPoint(x: rect.minX, y: rect.maxY)
        let tr = NSPoint(x: rect.maxX, y: rect.maxY)
        let bl = NSPoint(x: rect.minX, y: rect.minY)
        let br = NSPoint(x: rect.maxX, y: rect.minY)
        return [NSValue(point: tl), NSValue(point: tr), NSValue(point: bl), NSValue(point: br)]
    }

    private func highlightAnnotation(at pointInView: NSPoint) -> PDFAnnotation? {
        guard let pdfView,
              let page = pdfView.page(for: pointInView, nearest: true) else { return nil }
        let pagePoint = pdfView.convert(pointInView, to: page)
        if let ann = page.annotation(at: pagePoint),
           annotationIsHighlightLike(ann) {
            return ann
        }
        for ann in page.annotations where annotationIsHighlightLike(ann) {
            if ann.bounds.contains(pagePoint) { return ann }
            if quadRects(for: ann).contains(where: { $0.contains(pagePoint) }) { return ann }
        }
        return nil
    }

    private func logHighlightSummary(_ label: String, page: PDFPage, groupID: String?) {
        guard PDFAnnotationLog.isEnabled else { return }
        let highlights = page.annotations.filter { annotationIsHighlightLike($0) }
        let notes = page.annotations.filter { annotationIsTextNote($0) }
        PDFAnnotationLog.info("[ANNOT] \(label) pageIndex=\(page.pageRef?.pageNumber ?? -1) highlights=\(highlights.count) notes=\(notes.count) groupID=\(groupID ?? "-")")

        // Log a few highlights to confirm quad points are present.
        for (idx, h) in highlights.prefix(6).enumerated() {
            let quadCount = h.quadrilateralPoints?.count ?? annotationQuadPoints(for: h).count
            let gid = noteGroupID(for: h) ?? "-"
            PDFAnnotationLog.info("[ANNOT]   hi#\(idx) gid=\(gid) bounds=\(NSStringFromRect(h.bounds)) quadPoints=\(quadCount) color=\(hexFromColor(h.color, includeAlpha: true))")
        }
    }

    private func existingGroupID(for selection: PDFSelection, on page: PDFPage) -> String? {
        let selText = selectionTextForMatch(selection)
        let shouldMatchText = !selText.isEmpty

        // Prefer highlights that already overlap the selection and carry a group id.
        for ann in page.annotations where annotationIsHighlightLike(ann) {
            guard selectionIntersectsAnnotation(selection,
                                                 annotation: ann,
                                                 on: page,
                                                 minOverlapRatio: 0.2) else { continue }
            if shouldMatchText,
               !selectionMatchesAnnotationText(selText, annotation: ann, page: page) {
                continue
            }
            if let gid = noteGroupID(for: ann) { return gid }
        }

        return nil
    }

    private func noteForGroup(_ groupID: String, on page: PDFPage) -> PDFAnnotation? {
        for ann in page.annotations where annotationIsTextNote(ann) {
            if noteGroupID(for: ann) == groupID { return ann }
        }
        return nil
    }

    private func noteNearSelection(_ selection: PDFSelection, on page: PDFPage) -> PDFAnnotation? {
        let selBounds = selection.bounds(for: page)
        let expanded = selBounds.insetBy(dx: -80, dy: -32)
        for ann in page.annotations where annotationIsTextNote(ann) {
            if expanded.intersects(ann.bounds) { return ann }
        }
        return nil
    }

    private func noteNearBounds(_ bounds: CGRect, on page: PDFPage) -> PDFAnnotation? {
        let expanded = bounds.insetBy(dx: -80, dy: -32)
        var best: PDFAnnotation?
        var bestDistance = CGFloat.greatestFiniteMagnitude
        for ann in page.annotations where annotationIsTextNote(ann) {
            if expanded.intersects(ann.bounds) { return ann }
            let dx = ann.bounds.midX - bounds.midX
            let dy = ann.bounds.midY - bounds.midY
            let dist = sqrt(dx * dx + dy * dy)
            if dist < bestDistance {
                bestDistance = dist
                best = ann
            }
        }
        if bestDistance <= 160 {
            return best
        }
        return nil
    }

    private func highlightsMatching(selection: PDFSelection?, page: PDFPage, groupID: String?) -> [PDFAnnotation] {
        let selText = selection.map(selectionTextForMatch) ?? ""
        let shouldMatchText = !selText.isEmpty
        return page.annotations.compactMap { ann in
            guard annotationIsHighlightLike(ann) else { return nil }
            if let gid = groupID, let annGid = noteGroupID(for: ann), annGid == gid {
                return ann
            }
            if let selection {
                if selectionIntersectsAnnotation(selection,
                                                 annotation: ann,
                                                 on: page,
                                                 minOverlapRatio: 0.2) {
                    if shouldMatchText,
                       !selectionMatchesAnnotationText(selText, annotation: ann, page: page) {
                        return nil
                    }
                    return ann
                }
            }
            return nil
        }
    }

    private func highlightsNearNote(_ note: PDFAnnotation, on page: PDFPage) -> [PDFAnnotation] {
        guard let pdfView else { return [] }
        let baseThreshold = annotationMatchThreshold(for: page, displayBox: pdfView.displayBox)
        let threshold = max(160, baseThreshold * 3)
        let noteRect = note.bounds
        let highlights = page.annotations.filter { annotationIsHighlightLike($0) }
        return highlights.filter { annotationRectDistance(annotationAnchorRect(for: $0), noteRect) <= threshold }
    }

    private func quadPointsForAnnotation(_ annotation: PDFAnnotation) -> [NSValue] {
        annotationQuadPoints(for: annotation)
    }

    private func groupQuadPoints(from annotations: [PDFAnnotation]) -> [NSValue] {
        annotations.flatMap { quadPointsForAnnotation($0) }
    }

    private func validateQuadPoints(_ points: [NSValue], on page: PDFPage) -> [NSValue]? {
        guard !points.isEmpty else { return nil }
        let rects = quadRects(from: points)
        guard !rects.isEmpty else { return nil }
        let union = rects.dropFirst().reduce(rects[0]) { $0.union($1) }
        let pageBounds = page.bounds(for: pdfView?.displayBox ?? .cropBox)
        if union.width <= 0 || union.height <= 0 { return nil }
        if !union.intersects(pageBounds) { return nil }
        if union.width > pageBounds.width * 1.6 || union.height > pageBounds.height * 1.6 {
            return nil
        }
        return points
    }

    private func validatedGroupQuadPoints(from annotations: [PDFAnnotation], page: PDFPage) -> [NSValue] {
        var out: [NSValue] = []
        for ann in annotations {
            let raw = quadPointsForAnnotation(ann)
            if let valid = validateQuadPoints(raw, on: page) {
                out.append(contentsOf: valid)
            } else if annotationDebugEnabled {
                annotationLog("[ANN_QUAD_INVALID] id=\(annotationDebugID(ann)) gid=\(noteGroupID(for: ann) ?? "-") type=\(annotationTypeName(ann)) bounds=\(NSStringFromRect(ann.bounds))")
            }
        }
        return out
    }

    private func cachedGroupQuadPoints(for groupID: String, page: PDFPage, fallbackNote: PDFAnnotation?) -> [NSValue]? {
        if let cached = groupQuadPointsCache[groupID], !cached.isEmpty {
            if let valid = validateQuadPoints(cached, on: page) {
                return valid
            }
            if annotationDebugEnabled {
                annotationLog("[ANN_CACHE_INVALID] group=\(groupID) cached_points=\(cached.count)")
            }
        }
        let note = fallbackNote ?? noteForGroup(groupID, on: page)
        if let note,
           let storedValue = note.value(forAnnotationKey: annotationGroupQuadPointsKey),
           let stored = storedQuadPointsFromValue(storedValue),
           !stored.isEmpty {
            if let valid = validateQuadPoints(stored, on: page) {
                groupQuadPointsCache[groupID] = valid
                if annotationDebugEnabled {
                    annotationLog("[ANN_CACHE_NOTE_GROUP] group=\(groupID) points=\(valid.count)")
                }
                return valid
            }
        }
        if let note,
           let storedValue = note.value(forAnnotationKey: annotationStoredQuadPointsKey),
           let stored = storedQuadPointsFromValue(storedValue),
           !stored.isEmpty {
            let normalized = normalizeQuadPoints(stored, for: note)
            if let valid = validateQuadPoints(normalized, on: page) {
                groupQuadPointsCache[groupID] = valid
                return valid
            }
        }
        return nil
    }

    private func cacheGroupQuadPoints(_ points: [NSValue],
                                      groupID: String,
                                      page: PDFPage,
                                      fallbackNote: PDFAnnotation?) {
        guard !points.isEmpty else { return }
        guard let valid = validateQuadPoints(points, on: page) else {
            if annotationDebugEnabled {
                annotationLog("[ANN_CACHE_DROP] group=\(groupID) points=\(points.count)")
            }
            return
        }
        groupQuadPointsCache[groupID] = valid
        if let note = fallbackNote {
            storeGroupQuadPoints(valid, on: note)
        }
    }

    private func convertMarkupAnnotations(matches: [PDFAnnotation],
                                          groupID: String,
                                          page: PDFPage,
                                          color: NSColor,
                                          targetStyle: AnnotationMarkupStyle,
                                          fallbackNote: PDFAnnotation?) -> [PDFAnnotation] {
        ensureMarkupState(for: page)
        if annotationDebugEnabled {
            for ann in matches {
                logAnnotationEvent("convert_match", annotation: ann, page: page, context: "target=\(targetStyle.rawValue)")
            }
        }
        var quadPoints = validatedGroupQuadPoints(from: matches, page: page)
        if quadPoints.isEmpty,
           let cached = cachedGroupQuadPoints(for: groupID, page: page, fallbackNote: fallbackNote) {
            quadPoints = cached
        }
        var fallbackRects: [CGRect] = []
        if quadPoints.isEmpty {
            for ann in matches {
                let rect = ann.bounds
                guard rect.width > 0 && rect.height > 0 && rectIsFinite(rect) else { continue }
                fallbackRects.append(rect)
            }
            if fallbackRects.isEmpty {
                for ann in matches {
                    let rect = annotationAnchorRect(for: ann)
                    guard rect.width > 0 && rect.height > 0 else { continue }
                    fallbackRects.append(rect)
                }
            }
            if !fallbackRects.isEmpty {
                quadPoints = fallbackRects.flatMap { quadrilateralPoints(for: $0) }
            }
        }
        guard !quadPoints.isEmpty else {
            annotationLog("[CONVERT] group=\(groupID) target=\(targetStyle.rawValue) no quad points")
            return []
        }

        var rects = quadRects(from: quadPoints)
        if rects.isEmpty {
            rects = fallbackRects
        }
        guard let first = rects.first else {
            annotationLog("[CONVERT] group=\(groupID) target=\(targetStyle.rawValue) no rects")
            return []
        }
        let bounds = rects.dropFirst().reduce(first) { $0.union($1) }
        guard bounds.width > 0, bounds.height > 0 else {
            annotationLog("[CONVERT] group=\(groupID) target=\(targetStyle.rawValue) invalid bounds=\(NSStringFromRect(bounds))")
            return []
        }

        for ann in matches {
            removeAnnotation(ann, from: page, reason: "convert_remove")
        }

        let replacement = PDFAnnotation(bounds: bounds,
                                        forType: annotationSubtype(for: targetStyle),
                                        withProperties: nil)
        let resolvedQuadPoints: [NSValue]
        if quadPoints.count >= 4 {
            resolvedQuadPoints = quadPoints
        } else {
            resolvedQuadPoints = quadrilateralPoints(for: bounds)
        }
        replacement.quadrilateralPoints = resolvedQuadPoints
        storeQuadPoints(resolvedQuadPoints, on: replacement)
        assignGroupID(groupID, to: replacement)

        if let contents = matches.first?.contents, !contents.isEmpty {
            replacement.contents = contents
        }
        if let userName = matches.first?.userName {
            replacement.userName = userName
        }
        if let overrideLabel = matches.first?.value(forAnnotationKey: annotationPageLabelOverrideKey) {
            replacement.setValue(overrideLabel, forAnnotationKey: annotationPageLabelOverrideKey)
        }
        if let created = matches.first?.value(forAnnotationKey: annotationCreationDateKey) {
            replacement.setValue(created, forAnnotationKey: annotationCreationDateKey)
        }
        if let modified = matches.first?.modificationDate {
            replacement.modificationDate = modified
        }

        addAnnotation(replacement, to: page, reason: "convert_add")
        ensureMarkupAnnotationVisible(replacement)
        applyHighlightColor(replacement, baseColor: color, style: targetStyle)
        cacheGroupQuadPoints(resolvedQuadPoints, groupID: groupID, page: page, fallbackNote: fallbackNote)
        annotationLog("[CONVERT] group=\(groupID) target=\(targetStyle.rawValue) matches=\(matches.count) quadPoints=\(resolvedQuadPoints.count) bounds=\(NSStringFromRect(bounds))")
        return [replacement]
    }

    private func resolveGroupID(for note: PDFAnnotation, on page: PDFPage) -> String {
        return strictGroupID(for: note, on: page)
    }

    private func strictGroupID(for annotation: PDFAnnotation, on page: PDFPage) -> String {
        if let gid = noteGroupID(for: annotation) { return gid }
        let pageIndex = max(0, page.document?.index(for: page) ?? 0)
        let stableKey = annotationStableKey(annotation, pageIndex: pageIndex)
        let synthetic: String
        if annotationIsHighlightLike(annotation) {
            synthetic = "synthetic-h|\(stableKey)"
        } else if annotationIsTextNote(annotation) {
            synthetic = "synthetic-n|\(stableKey)"
        } else {
            synthetic = stableKey
        }
        assignGroupID(synthetic, to: annotation)
        return synthetic
    }

    private func highlightStyle(for note: PDFAnnotation, on page: PDFPage) -> AnnotationMarkupStyle {
        if let gid = noteGroupID(for: note) {
            let matches = page.annotations.filter {
                annotationIsHighlightLike($0) && noteGroupID(for: $0) == gid
            }
            if matches.contains(where: { annotationMarkupStyle(for: $0) == .underline }) {
                return .underline
            }
            if !matches.isEmpty {
                return .highlight
            }
        }
        // No proximity fallback here: avoid style leakage from adjacent annotations.
        return .highlight
    }

    private func highlightStyle(for selection: PDFSelection, on page: PDFPage) -> AnnotationMarkupStyle {
        let matches = highlightsMatching(selection: selection, page: page, groupID: nil)
        if matches.contains(where: { annotationMarkupStyle(for: $0) == .underline }) {
            return .underline
        }
        return .highlight
    }

    private func recolorHighlights(groupID: String,
                                   page: PDFPage,
                                   color: NSColor,
                                   selection: PDFSelection?,
                                   fallbackNote: PDFAnnotation? = nil,
                                   styleOverride: AnnotationMarkupStyle? = nil,
                                   mutationOnly: Bool = false) {
        let matches: [PDFAnnotation]
        if let selection {
            matches = highlightsMatching(selection: selection, page: page, groupID: groupID)
        } else if mutationOnly {
            matches = page.annotations.filter {
                annotationIsHighlightLike($0) && noteGroupID(for: $0) == groupID
            }
        } else {
            matches = highlightsForGroupWithoutSelection(groupID: groupID, page: page, fallbackNote: fallbackNote)
        }
        purgePreviewAnnotations(on: page, reason: "recolor")
        if mutationOnly {
            let candidates = matches.filter { annotationIsHighlightLike($0) && !annotationIsPreview($0) && $0.page === page }
            let targetStyle = styleOverride ?? candidates.first.map(annotationMarkupStyle) ?? .highlight
            if annotationDebugEnabled {
                let matchTypes = candidates.map { annotationTypeName($0) }.joined(separator: ",")
                annotationLog("[RECOLOR_MUTATE] group=\(groupID) target=\(targetStyle.rawValue) matches=\(candidates.count) types=\(matchTypes)")
            }
            guard !candidates.isEmpty else { return }
            let updated = mutateHighlightAnnotationsInPlace(candidates,
                                                           groupID: groupID,
                                                           baseColor: color,
                                                           styleOverride: styleOverride)
            let selectionTargets = updated.isEmpty ? candidates : updated
            updateHighlightedSelectionsColor(overlapping: selectionTargets, color: color, style: styleOverride)
            return
        }
        var sanitized = matches
        if !sanitized.isEmpty {
            sanitized = sanitizeHighlightMatches(sanitized, groupID: groupID, page: page, fallbackNote: fallbackNote)
        }
        let targetStyle = styleOverride ?? sanitized.first.map(annotationMarkupStyle) ?? .highlight
        if annotationDebugEnabled {
            let matchTypes = sanitized.map { annotationTypeName($0) }.joined(separator: ",")
            annotationLog("[RECOLOR] group=\(groupID) target=\(targetStyle.rawValue) matches=\(sanitized.count) types=\(matchTypes)")
        }
        guard !sanitized.isEmpty else { return }

        var updatedHighlights: [PDFAnnotation] = []
        let subtypeOverride = styleOverride.map { annotationSubtype(for: $0) }
        for highlight in sanitized {
            assignGroupID(groupID, to: highlight)
            if let rebuilt = rebuildHighlightAnnotation(
                highlight,
                baseColor: color,
                groupIDOverride: groupID,
                subtypeOverride: subtypeOverride
            ) {
                updatedHighlights.append(rebuilt)
            }
        }
        let latestQuadPoints = validatedGroupQuadPoints(from: updatedHighlights.isEmpty ? sanitized : updatedHighlights, page: page)
        if !latestQuadPoints.isEmpty {
            cacheGroupQuadPoints(latestQuadPoints, groupID: groupID, page: page, fallbackNote: fallbackNote)
        }
        let selectionTargets = updatedHighlights.isEmpty ? sanitized : updatedHighlights
        updateHighlightedSelectionsColor(overlapping: selectionTargets, color: color, style: styleOverride)
    }

    private func highlightsForGroupWithoutSelection(groupID: String,
                                                    page: PDFPage,
                                                    fallbackNote: PDFAnnotation?) -> [PDFAnnotation] {
        var matches = page.annotations.filter {
            annotationIsHighlightLike($0) && noteGroupID(for: $0) == groupID
        }
        if matches.isEmpty, let fallbackNote {
            matches = highlightsNearNote(fallbackNote, on: page)
        }
        if matches.isEmpty, let cached = groupQuadPointsCache[groupID], !cached.isEmpty,
           let valid = validateQuadPoints(cached, on: page) {
            let rects = quadRects(from: valid)
            if !rects.isEmpty {
                matches = page.annotations.filter { ann in
                    guard annotationIsHighlightLike(ann) else { return false }
                    let anchor = annotationAnchorRect(for: ann)
                    return rects.contains(where: { $0.intersects(anchor) })
                }
            }
        }
        return matches
    }

    private func resolveStyleTarget(from annotation: PDFAnnotation, on page: PDFPage) -> PDFAnnotation? {
        if annotationIsHighlightLike(annotation) {
            return annotation
        }
        if annotationIsTextNote(annotation), let gid = noteGroupID(for: annotation) {
            return page.annotations.first { annotationIsHighlightLike($0) && noteGroupID(for: $0) == gid }
        }
        return nil
    }

    private func applySingleAnnotationStyle(_ target: PDFAnnotation,
                                            on page: PDFPage,
                                            color: NSColor,
                                            style: AnnotationMarkupStyle,
                                            source: String) {
        guard let doc = page.document else { return }
        let baseColor = (color.usingColorSpace(.deviceRGB) ?? color).withAlphaComponent(1.0)
#if DEBUG
        let preCount = debugAnnotationCount(document: doc)
        annotationLog("[AA_DEBUG] applySingle start source=\(source) target=\(debugAnnotationSummary(target, page: page)) count=\(preCount)")
#endif
        let currentStyle = annotationMarkupStyle(for: target)
        if currentStyle != style {
            // Zotero-style conversion: delete + recreate to avoid stale render artifacts
            // and ensure a single highlight/underline render per annotation ID.
            let groupID = noteGroupID(for: target) ?? strictGroupID(for: target, on: page)
            let matches = page.annotations.filter {
                annotationIsHighlightLike($0) && noteGroupID(for: $0) == groupID
            }
            let fallbackNote = noteForGroup(groupID, on: page)
            let convertTargets = matches.isEmpty ? [target] : matches
            removeHighlightedSelections(overlapping: convertTargets)
            #if DEBUG
            if aaToggleDebugActive { aaToggleDebugAllowsRemoval = true }
            #endif
            let converted = convertMarkupAnnotations(matches: convertTargets,
                                                     groupID: groupID,
                                                     page: page,
                                                     color: baseColor,
                                                     targetStyle: style,
                                                     fallbackNote: fallbackNote)
            #if DEBUG
            if aaToggleDebugActive { aaToggleDebugAllowsRemoval = false }
            #endif
            let selectionTargets: [PDFAnnotation]
            if converted.isEmpty {
                let updated = mutateHighlightAnnotationsInPlace(convertTargets,
                                                                groupID: groupID,
                                                                baseColor: baseColor,
                                                                styleOverride: style)
                selectionTargets = updated.isEmpty ? convertTargets : updated
                updateHighlightedSelectionsColor(overlapping: selectionTargets, color: baseColor, style: style)
            } else {
                selectionTargets = converted
                updateHighlightedSelectionsColor(overlapping: selectionTargets, color: baseColor, style: style)
            }
            let latestQuadPoints = validatedGroupQuadPoints(from: selectionTargets, page: page)
            if !latestQuadPoints.isEmpty {
                cacheGroupQuadPoints(latestQuadPoints, groupID: groupID, page: page, fallbackNote: fallbackNote)
            }
#if DEBUG
            if aaToggleDebugActive {
                for ann in selectionTargets { recordAAToggleAffected(ann, reason: "convert_target") }
            }
#endif
            refreshHighlightRegions(for: [page], reason: "convert_style")
            persistAndReload(document: doc,
                             focusPage: page,
                             refresh: .none,
                             reason: "convert_style",
                             debounce: 0.0)
            NotificationCenter.default.post(name: .arxivPDFAnnotationsDidChange, object: doc)
#if DEBUG
            let postCount = debugAnnotationCount(document: doc)
            annotationLog("[AA_DEBUG] applySingle end source=\(source) target=\(debugAnnotationSummary(target, page: page)) count=\(postCount)")
#endif
            return
        }
        applyMarkupStyleInPlace(target, baseColor: baseColor, style: style)
        updateHighlightedSelectionsColor(overlapping: [target], color: baseColor, style: style)
#if DEBUG
        if aaToggleDebugActive {
            recordAAToggleAffected(target, reason: "single_target")
        }
#endif
        refreshHighlightRegions(for: [page], reason: "apply_style")
        persistAndReload(document: doc,
                         focusPage: page,
                         refresh: .none,
                         reason: "apply_style",
                         debounce: 0.0)
        let groupID = noteGroupID(for: target) ?? strictGroupID(for: target, on: page)
        let pageIndex = doc.index(for: page)
        let info: [AnyHashable: Any] = [
            annotationChangeKindKey: AnnotationChangeKind.color.rawValue,
            annotationChangeGroupIDKey: groupID,
            annotationChangePageIndexKey: pageIndex,
            annotationChangeColorKey: baseColor
        ]
        NotificationCenter.default.post(name: .arxivPDFAnnotationsDidChange, object: doc, userInfo: info)
#if DEBUG
        let postCount = debugAnnotationCount(document: doc)
        annotationLog("[AA_DEBUG] applySingle end source=\(source) target=\(debugAnnotationSummary(target, page: page)) count=\(postCount)")
#endif
    }

    private func applyMarkupStyle(for annotation: PDFAnnotation,
                                  on page: PDFPage,
                                  color: NSColor,
                                  style: AnnotationMarkupStyle) {
        guard let target = resolveStyleTarget(from: annotation, on: page) else {
            if annotationActionDebugEnabled {
                annotationActionLog("apply_style_skipped reason=no_target id=\(annotationDebugID(annotation))")
            }
            return
        }
        let currentStyle = annotationMarkupStyle(for: target)
        if currentStyle == style {
            if annotationDebugEnabled {
                annotationLog("[ANN_COLOR_ROUTE] id=\(annotationDebugID(target)) page=\(page.document?.index(for: page) ?? -1) style=\(style.rawValue) source=apply_style_color")
            }
            applyGroupColorUpdate(for: target, on: page, color: color, style: style, source: "apply_style_color")
            return
        }
        applySingleAnnotationStyle(target, on: page, color: color, style: style, source: "apply_style")
    }

    private func applyGroupColorUpdate(for target: PDFAnnotation,
                                       on page: PDFPage,
                                       color: NSColor,
                                       style: AnnotationMarkupStyle,
                                       source: String) {
        // Color updates are pure style changes: keep subtype + geometry stable and never depend
        // on current selection. This mirrors Zotero's approach of updating annotation.color while
        // preserving stored position rects.
        guard let doc = page.document else { return }
        ensureMarkupState(for: page)
        let baseColor = (color.usingColorSpace(.deviceRGB) ?? color).withAlphaComponent(1.0)
        let groupID = noteGroupID(for: target) ?? strictGroupID(for: target, on: page)
        let notes = page.annotations.filter {
            annotationIsTextNote($0) && noteGroupID(for: $0) == groupID
        }
        var highlights = page.annotations.filter {
            annotationIsHighlightLike($0) && noteGroupID(for: $0) == groupID
        }
        if highlights.isEmpty {
            let fallbackNote = notes.first ?? (annotationIsTextNote(target) ? target : nil)
            highlights = highlightsForGroupWithoutSelection(groupID: groupID,
                                                            page: page,
                                                            fallbackNote: fallbackNote)
        }
        if highlights.isEmpty, annotationIsHighlightLike(target) {
            highlights = [target]
        }
        if annotationDebugEnabled {
            annotationLog("[ANN_COLOR_GROUP] start source=\(source) group=\(groupID) page=\(doc.index(for: page)) style=\(style.rawValue) color=\(hexFromColor(baseColor, includeAlpha: true)) highlights=\(highlights.count) notes=\(notes.count)")
        }
        for note in notes {
            note.color = baseColor
            updateAnnotation(note, reason: "group_color_note")
        }
        var highlightStyleHighlights: [PDFAnnotation] = []
        var underlineStyleHighlights: [PDFAnnotation] = []
        for ann in highlights {
            assignGroupID(groupID, to: ann)
            if !annotationHasValidQuadPoints(ann, page: page) {
                ensureGeometryForColorUpdate(ann, groupID: groupID, page: page, fallbackNote: notes.first, source: source)
            } else if annotationDebugEnabled {
                annotationLog("[ANN_COLOR_GEOM] source=\(source) id=\(annotationDebugID(ann)) kept=stored")
            }
            let currentStyle = annotationMarkupStyle(for: ann)
            if currentStyle == .underline {
                underlineStyleHighlights.append(ann)
            } else {
                highlightStyleHighlights.append(ann)
            }
            applyMarkupColorOnly(ann, baseColor: baseColor, style: currentStyle, source: source)
        }
        let quadPoints = validatedGroupQuadPoints(from: highlights, page: page)
        if !quadPoints.isEmpty {
            cacheGroupQuadPoints(quadPoints, groupID: groupID, page: page, fallbackNote: notes.first)
        }
        if !highlightStyleHighlights.isEmpty {
            updateHighlightedSelectionsColor(overlapping: highlightStyleHighlights, color: baseColor, style: .highlight)
        }
        if !underlineStyleHighlights.isEmpty {
            updateHighlightedSelectionsColor(overlapping: underlineStyleHighlights, color: baseColor, style: .underline)
        }
        refreshHighlightRegions(for: [page], reason: "group_color_update")
        persistAndReload(document: doc,
                         focusPage: page,
                         refresh: .none,
                         reason: "group_color_update",
                         debounce: 0.0)
        let info: [AnyHashable: Any] = [
            annotationChangeKindKey: AnnotationChangeKind.color.rawValue,
            annotationChangeGroupIDKey: groupID,
            annotationChangePageIndexKey: doc.index(for: page),
            annotationChangeColorKey: baseColor
        ]
        NotificationCenter.default.post(name: .arxivPDFAnnotationsDidChange, object: doc, userInfo: info)
        if annotationDebugEnabled {
            let pageIndex = doc.index(for: page)
            for ann in highlights {
                let inPage = page.annotations.contains { $0 === ann }
                let rects = quadRects(for: ann)
                annotationLog("[ANN_COLOR_GROUP_STATE] source=\(source) id=\(annotationDebugID(ann)) page=\(pageIndex) in_page=\(inPage) rects=\(debugRectsText(rects)) \(debugAnnotationRenderState(ann, page: page))")
            }
            annotationLog("[ANN_COLOR_GROUP] end source=\(source) group=\(groupID) page=\(pageIndex) highlights=\(highlights.count)")
        }
    }

    // Root cause (Bug A): toggling from the note annotation reads a default "highlight" style,
    // so underline -> highlight never happens. Resolve the actual highlight annotation and toggle that.
    private func toggleEmphasisStyle(for annotation: PDFAnnotation,
                                     on page: PDFPage,
                                     source: String) -> (current: AnnotationMarkupStyle, target: AnnotationMarkupStyle, color: NSColor, targetID: String)? {
        guard let target = resolveStyleTarget(from: annotation, on: page) else {
            if annotationActionDebugEnabled {
                annotationActionLog("toggle_style_skipped reason=no_target id=\(annotationDebugID(annotation))")
            }
            return nil
        }
        let currentStyle = annotationMarkupStyle(for: target)
        let targetStyle: AnnotationMarkupStyle = (currentStyle == .underline) ? .highlight : .underline
        let baseColor = annotationDisplayBaseColor(for: target)
        let targetID = annotationDebugID(target)
#if DEBUG
        startAAToggleDebug(target: target, page: page, source: source)
#endif
        applySingleAnnotationStyle(target, on: page, color: baseColor, style: targetStyle, source: source)
#if DEBUG
        endAAToggleDebug(page: page, source: source)
#endif
        return (currentStyle, targetStyle, baseColor, targetID)
    }

    private func deleteAnnotationGroup(for note: PDFAnnotation, on page: PDFPage) {
        guard let doc = page.document else { return }
        let groupID = resolveGroupID(for: note, on: page)
        var annotationsToDelete: [PDFAnnotation] = []
        annotationsToDelete = page.annotations.filter { noteGroupID(for: $0) == groupID }
        if annotationsToDelete.isEmpty {
            annotationsToDelete = highlightsNearNote(note, on: page)
        }
        if !annotationsToDelete.contains(where: { $0 === note }) {
            annotationsToDelete.append(note)
        }
        let highlightAnnotations = annotationsToDelete.filter { annotationIsHighlightLike($0) }
        removeHighlightedSelections(overlapping: highlightAnnotations)
        for ann in annotationsToDelete {
            removeAnnotation(ann, from: page, reason: "delete_group")
        }
        groupQuadPointsCache.removeValue(forKey: groupID)
        if currentListItemID == groupID {
            currentListItemID = nil
            currentListItem = nil
        }
        refreshHighlightRegions(for: [page], reason: "delete_group")
        persistAndReload(document: doc,
                         focusPage: page,
                         refresh: .none,
                         reason: "delete_group",
                         debounce: 0.0)
        NotificationCenter.default.post(name: .arxivPDFAnnotationsDidChange, object: doc)
    }

    private func primaryScrollView(in view: NSView) -> NSScrollView? {
        var out: NSScrollView?
        func walk(_ v: NSView) {
            if let sv = v as? NSScrollView { out = sv; return }
            for sub in v.subviews where out == nil { walk(sub) }
        }
        walk(view)
        return out
    }

    private struct PDFScrollSnapshot {
        let documentID: ObjectIdentifier
        let clipOrigin: NSPoint
        let anchorPageIndex: Int?
        let anchorPointOnPage: NSPoint?
        let anchorOffsetInClip: NSPoint?
    }

    private func capturePDFScrollSnapshot(reason: String) -> PDFScrollSnapshot? {
        _ = reason
        guard let pdfView,
              let doc = pdfView.document,
              let scrollView = primaryScrollView(in: pdfView) else { return nil }
        let clip = scrollView.contentView
        let clipOrigin = clip.bounds.origin

        var anchorPageIndex: Int?
        var anchorPointOnPage: NSPoint?
        var anchorOffsetInClip: NSPoint?

        let visibleRect = pdfView.convert(clip.bounds, from: clip)
        let anchorInView = NSPoint(x: visibleRect.midX, y: visibleRect.midY)
        if let page = pdfView.page(for: anchorInView, nearest: true) {
            let pageIndex = doc.index(for: page)
            if pageIndex != NSNotFound {
                anchorPageIndex = pageIndex
                anchorPointOnPage = pdfView.convert(anchorInView, to: page)
                if let docView = scrollView.documentView {
                    let anchorInDoc = pdfView.convert(anchorInView, to: docView)
                    anchorOffsetInClip = NSPoint(x: anchorInDoc.x - clipOrigin.x,
                                                 y: anchorInDoc.y - clipOrigin.y)
                }
            }
        }

        return PDFScrollSnapshot(documentID: ObjectIdentifier(doc),
                                 clipOrigin: clipOrigin,
                                 anchorPageIndex: anchorPageIndex,
                                 anchorPointOnPage: anchorPointOnPage,
                                 anchorOffsetInClip: anchorOffsetInClip)
    }

    private func restorePDFScrollSnapshot(_ snapshot: PDFScrollSnapshot?, reason: String) {
        _ = reason
        guard let snapshot,
              let pdfView,
              let doc = pdfView.document,
              ObjectIdentifier(doc) == snapshot.documentID,
              let scrollView = primaryScrollView(in: pdfView) else { return }
        let clip = scrollView.contentView

        var targetOrigin: NSPoint?
        if let pageIndex = snapshot.anchorPageIndex,
           let anchorPointOnPage = snapshot.anchorPointOnPage,
           let offset = snapshot.anchorOffsetInClip,
           let page = doc.page(at: pageIndex),
           let docView = scrollView.documentView {
            let anchorInView = pdfView.convert(anchorPointOnPage, from: page)
            let anchorInDoc = pdfView.convert(anchorInView, to: docView)
            var origin = NSPoint(x: anchorInDoc.x - offset.x, y: anchorInDoc.y - offset.y)
            origin = clip.constrainBoundsRect(NSRect(origin: origin, size: clip.bounds.size)).origin
            targetOrigin = origin
        } else {
            var origin = snapshot.clipOrigin
            origin = clip.constrainBoundsRect(NSRect(origin: origin, size: clip.bounds.size)).origin
            targetOrigin = origin
        }

        guard let origin = targetOrigin else { return }
        if abs(origin.x - clip.bounds.origin.x) > 0.01 || abs(origin.y - clip.bounds.origin.y) > 0.01 {
            clip.setBoundsOrigin(origin)
            scrollView.reflectScrolledClipView(clip)
        }
    }

    private func createPreviewHighlight(for selection: PDFSelection,
                                        on page: PDFPage,
                                        color: NSColor,
                                        style: AnnotationMarkupStyle) {
        removePreviewHighlight()
        clearAnnotationSelectionOverlays(reason: "preview_create")
        guard pdfView != nil else { return }

        let selBounds = selection.bounds(for: page)
        let anchor = CGPoint(x: selBounds.midX, y: selBounds.midY)
        let rects = selectionRectsForCommit(selection, page: page, anchor: anchor)
        guard let bounds = rects.first else { return }

        let highlight = PDFAnnotation(bounds: bounds, forType: annotationSubtype(for: style), withProperties: nil)
        applyHighlightColor(highlight, baseColor: color, style: style)
        let quadPoints = quadrilateralPoints(for: bounds)
        highlight.quadrilateralPoints = quadPoints
        storeQuadPoints(quadPoints, on: highlight)
        highlight.setValue("preview", forAnnotationKey: .contents) // Mark as preview
        highlight.setValue(true, forAnnotationKey: annotationPreviewFlagKey)
        let pageIndex = page.document?.index(for: page) ?? -1
        print("[DBG_ANN_MUTATE] action=add type=preview page=\(pageIndex) bounds=\(NSStringFromRect(bounds)) scale=\(pdfView?.scaleFactor ?? 0)")
        if annotationDebugEnabled {
            let text = debugTrimmedText(page.selection(for: bounds)?.string)
            annotationLog("[ANN_PREVIEW_ADD] id=\(annotationDebugID(highlight)) page=\(pageIndex) style=\(style.rawValue) rects=\(debugRectsText([bounds])) text=\"\(text)\"")
        }
        addAnnotation(highlight, to: page, reason: "preview_add")
        previewHighlight = highlight
        // Track the selection used for preview so it can be removed on cancel.
        previewSelection = selection
    }

    private func updatePreviewHighlight(color: NSColor, style: AnnotationMarkupStyle) {
        guard let highlight = previewHighlight else { return }
        let currentStyle = annotationMarkupStyle(for: highlight)
        if currentStyle != style {
            if let rebuilt = rebuildHighlightAnnotation(
                highlight,
                baseColor: color,
                groupIDOverride: nil,
                subtypeOverride: annotationSubtype(for: style)
            ) {
                previewHighlight = rebuilt
            }
        } else {
            applyHighlightColor(highlight, baseColor: color, style: style)
        }
    }

    private func removePreviewHighlight() {
        guard let highlight = previewHighlight, let page = highlight.page else { return }
        let pageIndex = page.document?.index(for: page) ?? -1
        print("[DBG_ANN_MUTATE] action=remove type=preview page=\(pageIndex) bounds=\(NSStringFromRect(highlight.bounds)) scale=\(pdfView?.scaleFactor ?? 0)")
        if annotationDebugEnabled {
            annotationLog("[ANN_PREVIEW_REMOVE] id=\(annotationDebugID(highlight)) page=\(pageIndex) rect=\(NSStringFromRect(highlight.bounds))")
        }
        removeAnnotation(highlight, from: page, reason: "preview_remove")
        previewHighlight = nil
        // Remove the temporary selection highlight associated with the preview (if any).
        if let sel = previewSelection {
            removeHighlightedSelection(sel, source: "preview_remove")
            previewSelection = nil
        }
        clearAnnotationSelectionOverlays(reason: "preview_remove")
    }

    private func hideAnnotationMenu(reason: String) {
        annotationLog("hideAnnotationMenu called, reason: \(reason)")
        cancelComposerKeyBuffering()
        removePreviewHighlight()
        clearAnnotationSelectionOverlays(reason: "hide_menu")
        if let vc = composerPopover?.contentViewController as? AnnotationComposerViewController {
            vc.textView.closeInlineMathPopup(commit: true)
            vc.textView.cleanupFormattingPanels()
        }
        composerPopover?.close()
        currentContext = nil
        removeClickOutsideMonitor()
    }

    private func installClickOutsideMonitor() {
        guard clickMonitor == nil else { return }
        clickMonitor = NSEvent.addLocalMonitorForEvents(matching: [.leftMouseDown]) { [weak self] event in
            guard let self, let popover = self.composerPopover else { return event }
            guard let popoverWindow = popover.contentViewController?.view.window else { return event }
            if event.window === popoverWindow {
                return event
            }
            if NSColorPanel.shared.isVisible || NSFontPanel.shared.isVisible {
                return event
            }
            if let window = event.window {
                if window is NSColorPanel || window is NSFontPanel {
                    return event
                }
            }
            if let vc = popover.contentViewController as? AnnotationComposerViewController {
                if vc.isInlineMathEvent(event) {
                    return event
                }
                if vc.consumeInlineMathSubmitSuppression(matching: event) {
                    return event
                }
                if vc.isInlineMathPopupVisible {
                    vc.closeInlineMathPopup(commit: true)
                    return nil
                }
                vc.submit()
            } else {
                self.hideAnnotationMenu(reason: "outside_click")
            }
            return event
        }
    }

    private func removeClickOutsideMonitor() {
        if let monitor = clickMonitor {
            NSEvent.removeMonitor(monitor)
            clickMonitor = nil
        }
    }

    @discardableResult
    private func setupComposerWindowIfReady(for vc: AnnotationComposerViewController) -> Bool {
        guard let popover = composerPopover,
              popover.isShown,
              popover.contentViewController === vc,
              let window = popover.contentViewController?.view.window else { return false }

        if let hostingView = popover.contentViewController?.view {
            prepareComposerPopoverWindow(window: window, hostingView: hostingView)
        }
        window.makeKeyAndOrderFront(nil)
        window.makeFirstResponder(vc.textView)
        installComposerKeyMonitorIfNeeded(for: vc, window: window)
        flushComposerKeyBuffer(into: vc.textView)
        return true
    }

    private func installComposerKeyMonitorIfNeeded(for vc: AnnotationComposerViewController, window: NSWindow) {
        guard keyMonitor == nil else { return }
        let monitor = NSEvent.addLocalMonitorForEvents(matching: .keyDown) { event in
            if event.keyCode == 36 || event.keyCode == 76 { // Return / Enter
                if vc.textView.handleReturnWhileFormattingPanelOpen() {
                    return nil
                }
                if vc.isEditingPageNumberField(in: window) {
                    return event
                }
                if event.modifierFlags.contains(.shift) {
                    return event // let textView handle for newline
                } else {
                    if vc.isInlineMathPopupVisible {
                        vc.closeInlineMathPopup(commit: true)
                        return nil
                    }
                    annotationLog("Return/Enter pressed globally, calling submit")
                    vc.submit()
                    return nil
                }
            } else if event.keyCode == 53 { // Escape
                annotationLog("Escape pressed globally, calling cancel")
                vc.cancel()
                return nil
            }
            return event
        }
        keyMonitor = monitor
    }

    // removed triggerAutoAnnotation() (testing helper) to avoid optional unwrap regressions

    private func cancel() {
        hideAnnotationMenu(reason: "user_cancel")
    }

    private func presentComposer(context: AnnotationContext) {
        annotationLog("presentComposer called")
        let openStart = timingStart()
        if let monitor = keyMonitor {
            NSEvent.removeMonitor(monitor)
            keyMonitor = nil
        }
        if let popover = composerPopover {
            if let vc = popover.contentViewController as? AnnotationComposerViewController {
                vc.textView.closeInlineMathPopup(commit: true)
                vc.textView.cleanupFormattingPanels()
            }
            popover.close()
        }
        cancelComposerKeyBuffering()
        beginComposerKeyBuffering()
        NSApp.activate(ignoringOtherApps: true)
        currentContext = context
        let vc = composerController()
        vc.onSubmit = nil
        vc.onCancel = nil
        vc.onDelete = nil
        vc.onColorChanged = nil
        vc.onStyleChanged = nil
        vc.onToggleStyleRequested = nil
        vc.onNavigatePrevious = nil
        vc.onNavigateNext = nil
        vc.onPageNumberChanged = nil
        vc.onResizeRequested = nil
        vc.resizeBoundsProvider = nil
        if let existing = context.existingAnnotation {
            vc.initialText = annotationCommentText(for: existing)
            vc.initialRichTextPayload = annotationRichTextPayload(for: existing)
#if DEBUG
            vc.debugTargetAnnotationID = annotationDebugID(existing)
#endif
        } else {
            vc.initialText = ""
            vc.initialRichTextPayload = nil
        }
        let initialStyle: AnnotationMarkupStyle
        if let existing = context.existingAnnotation {
            initialStyle = highlightStyle(for: existing, on: context.page)
        } else if let selection = context.selection {
            initialStyle = highlightStyle(for: selection, on: context.page)
        } else {
            initialStyle = .highlight
        }
        if let existing = context.existingAnnotation {
            // Use the stored base color so we don't treat alpha-tinted highlight colors
            // as edits when the user simply clicks between annotations.
            vc.initialColor = annotationDisplayBaseColor(for: existing)
        } else {
            vc.initialColor = loadDefaultAnnotationColor()
        }
        vc.initialStyle = initialStyle
        vc.skipSubmitIfUnchanged = (context.existingAnnotation != nil && context.selection == nil)
        vc.resizeBoundsProvider = { [weak self] in
            guard let host = self?.hostView, let window = host.window else { return .zero }
            let rectInWindow = host.convert(host.bounds, to: nil)
            return window.convertToScreen(rectInWindow)
        }
        pendingPageLabelOverride = nil
        pendingCreationDateOverride = nil
        if let resolved = resolveListItem(for: context) {
            currentListItem = resolved
            currentListItemID = resolved.stableID
        } else if let existing = context.existingAnnotation, let groupID = noteGroupID(for: existing) {
            currentListItem = nil
            currentListItemID = groupID
        } else {
            currentListItem = nil
            currentListItemID = nil
        }
        if currentListItemID == nil, let current = currentListItem {
            currentListItemID = current.stableID
        }
        let overrideLabel = context.existingAnnotation?.value(forAnnotationKey: annotationPageLabelOverrideKey) as? String
        let pageNumberValue = currentListItem.map { normalizedPageLabelValue(from: $0.pageLabel) }
            ?? defaultPageLabelValue(for: context.page, override: overrideLabel)
        vc.setPageNumberValue(pageNumberValue, editable: true)
        let creationTimestamp: Date? = {
            if let createdAt = currentListItem?.createdAt {
                return createdAt
            }
            if let existing = context.existingAnnotation,
               let createdAt = annotationCreationDateValue(for: existing) {
                return createdAt
            }
            if pendingCreationDateOverride == nil {
                pendingCreationDateOverride = Date()
            }
            return pendingCreationDateOverride
        }()
        vc.setCreationTimestamp(creationTimestamp)
        if let items = listItemsProvider?() {
            let position = notePositionData(from: items)
            vc.setNotePosition(index: position.index, total: position.total)
        }
        if let host = hostView {
            let bounds = host.bounds
            if bounds.width > 1, bounds.height > 1 {
                let maxSide = max(1, min(bounds.width, bounds.height) * 0.9)
                let minSide = min(maxSide, 220)
                let preferred = vc.preferredContentSize
                let targetSide = max(minSide, min(maxSide, min(preferred.width, preferred.height)))
                vc.preferredContentSize = NSSize(width: targetSide, height: targetSide)
            }
        }
        vc.onPageNumberChanged = { [weak self] value in
            self?.handlePageNumberChange(value)
        }
        vc.onNavigatePrevious = { [weak self, weak vc] in
            guard let self, self.canNavigateAnnotations(delta: -1) else { return }
            vc?.submit()
            self.onNavigatePrevious?()
        }
        vc.onNavigateNext = { [weak self, weak vc] in
            guard let self, self.canNavigateAnnotations(delta: 1) else { return }
            vc?.submit()
            self.onNavigateNext?()
        }
        composerPresentationID &+= 1
        vc.prepareForPresentation(presentationID: composerPresentationID)

        let pop: NSPopover
        if let existing = composerPopover {
            pop = existing
        } else {
            let created = NSPopover()
            created.behavior = .applicationDefined
            created.animates = false
            created.delegate = self
            composerPopover = created
            pop = created
        }
        pop.contentViewController = vc
        vc.onResizeRequested = { [weak pop, weak vc, weak self] size in
            pop?.contentSize = size
            if let window = pop?.contentViewController?.view.window, let hostingView = vc?.view {
                self?.stripComposerPopoverOverlay(in: window, hostingView: hostingView)
            }
        }

        vc.onSubmit = { [weak self] content, color, style in
            guard let self = self else { return }
            debugLog("onSubmit called with text: '\(content.plainText)', color: \(color)")
            // Always persist through commitAnnotation to ensure both new and edited
            // annotations are saved to disk and UI updates occur consistently.
            self.hideAnnotationMenu(reason: "submit")
            self.commitAnnotation(content: content, color: color, style: style, context: context)
        }

        vc.onCancel = { [weak self] in
            self?.cancel()
        }

        vc.onDelete = { [weak self] in
            guard let self else { return }
            guard context.existingAnnotation != nil else {
                annotationActionLog("glass_delete_skipped reason=no_existing")
                self.cancel()
                return
            }
            guard let item = self.actionListItem(for: context) else {
                annotationActionLog("glass_delete_skipped reason=no_item")
                self.cancel()
                return
            }
            self.performAnnotationCommand(.delete, for: item, source: "glass_delete")
        }

        // Set up preview highlight for real-time color feedback (only for new annotations)
        if let selection = context.selection, context.existingAnnotation == nil {
            debugLog("Setting up preview highlight for selection")
            createPreviewHighlight(for: selection, on: context.page, color: vc.initialColor, style: vc.initialStyle)
            vc.onColorChanged = { [weak self] color, style in
                debugLog("Color changed to: \(color)")
                self?.updatePreviewHighlight(color: color, style: style)
            }
            vc.onStyleChanged = { [weak self] style, color in
                self?.updatePreviewHighlight(color: color, style: style)
            }
            vc.onToggleStyleRequested = nil
        } else {
            if let existing = context.existingAnnotation {
                vc.onColorChanged = { [weak self] color, _ in
                    guard let self else { return }
                    if let target = self.resolveStyleTarget(from: existing, on: context.page) {
                        let targetStyle = annotationMarkupStyle(for: target)
                        self.applyGroupColorUpdate(for: target,
                                                   on: context.page,
                                                   color: color,
                                                   style: targetStyle,
                                                   source: "glass_color")
                    } else {
                        let base = (color.usingColorSpace(.deviceRGB) ?? color).withAlphaComponent(1.0)
                        existing.color = base
                        self.updateAnnotation(existing, reason: "glass_color_note")
                    }
                }
                vc.onStyleChanged = nil
                vc.onToggleStyleRequested = { [weak self, weak vc] in
                    guard let self else { return }
                    if let item = self.actionListItem(for: context) {
                        let targetStyle = self.annotationToggleTargetStyle(for: item)
                        self.performAnnotationCommand(.convertStyle(targetStyle), for: item, source: "glass_toggle")
                        let baseColor = (item.color.usingColorSpace(.deviceRGB) ?? item.color).withAlphaComponent(1.0)
                        vc?.setSelectedStyle(targetStyle, color: baseColor)
                        return
                    }
                    guard let result = self.toggleEmphasisStyle(for: existing,
                                                               on: context.page,
                                                               source: "glass_toggle") else { return }
                    annotationActionLog("glass_toggle_target id=\(result.targetID) current=\(result.current.rawValue) target=\(result.target.rawValue)")
                    vc?.setSelectedStyle(result.target, color: result.color)
                }
            }
            debugLog("No selection for preview highlight, existing annotation: \(context.existingAnnotation != nil)")
        }

        if let host = hostView, let pdfView {
            func clamped(_ rect: NSRect, in bounds: NSRect, inset: CGFloat = 8) -> NSRect {
                let ib = bounds.insetBy(dx: inset, dy: inset)
                var r = rect
                r.origin.x = min(max(ib.minX, r.origin.x), ib.maxX - max(1, r.width))
                r.origin.y = min(max(ib.minY, r.origin.y), ib.maxY - max(1, r.height))
                return r
            }

            let anchorRect: NSRect
            if let selection = context.selection,
               let selectionBounds = selectionAnchorBounds(selection, on: context.page) {
                let target = anchorRectAtBottom(bounds: selectionBounds, page: context.page, pdfView: pdfView, host: host)
                anchorRect = clamped(target, in: host.bounds)
            } else if let existing = context.existingAnnotation,
                      let highlightBounds = highlightAnchorBounds(for: existing, on: context.page) {
                let target = anchorRectAtBottom(bounds: highlightBounds, page: context.page, pdfView: pdfView, host: host)
                anchorRect = clamped(target, in: host.bounds)
            } else {
                let pointRect = NSRect(origin: context.viewPointInHost, size: NSSize(width: 1, height: 1))
                anchorRect = clamped(pointRect, in: host.bounds)
            }

            let preferredEdge: NSRectEdge = host.isFlipped ? .maxY : .minY
            pop.show(relativeTo: anchorRect, of: host, preferredEdge: preferredEdge)
            installClickOutsideMonitor()
            annotationLog("Popover shown")
            maybeRunAnnotationHarness(for: context)
#if DEBUG
            maybeRunAAToggleRepro(for: context)
#endif
            if !self.setupComposerWindowIfReady(for: vc) {
                DispatchQueue.main.async { [weak self, weak vc] in
                    guard let self, let vc else { return }
                    if !self.setupComposerWindowIfReady(for: vc) {
                        DispatchQueue.main.asyncAfter(deadline: .now() + 0.02) { [weak self, weak vc] in
                            guard let self, let vc else { return }
                            if !self.setupComposerWindowIfReady(for: vc) {
                                annotationLog("No window found while configuring composer")
                            }
                        }
                    }
                }
            }
        }
        timingEnd("open_annotation", openStart)
    }

    private func stripComposerPopoverOverlay(in window: NSWindow, hostingView: NSView) {
        guard let contentView = window.contentView else { return }
        if let frameView = contentView.superview {
            stripPopoverBackground(on: frameView, keep: contentView)
        }
        if contentView !== hostingView {
            stripPopoverBackground(on: contentView, keep: hostingView)
        }
        enforcePopoverWindowShape(window: window, hostingView: hostingView)
    }

    private func prepareComposerPopoverWindow(window: NSWindow, hostingView: NSView) {
        window.isOpaque = false
        window.backgroundColor = .clear
        window.contentView?.wantsLayer = true
        window.contentView?.layer?.backgroundColor = NSColor.clear.cgColor
        stripComposerPopoverOverlay(in: window, hostingView: hostingView)
    }

    private func stripPopoverBackground(on view: NSView, keep protectedView: NSView?) {
        view.wantsLayer = true
        view.layer?.backgroundColor = NSColor.clear.cgColor
        view.layer?.borderWidth = 0
        view.layer?.shadowOpacity = 0
        if let effect = view as? NSVisualEffectView {
            effect.material = .appearanceBased
            effect.blendingMode = .withinWindow
            effect.state = .active
        }
        if #available(macOS 26.0, *), let glass = view as? NSGlassEffectView {
            glass.tintColor = .clear
        }
        if let obj = view as? NSObject {
            _ = setValueIfPossible(obj, key: "drawsBackground", value: false)
            _ = setValueIfPossible(obj, key: "backgroundColor", value: NSColor.clear)
            _ = setValueIfPossible(obj, key: "borderColor", value: NSColor.clear)
            _ = setValueIfPossible(obj, key: "fillColor", value: NSColor.clear)
            _ = setValueIfPossible(obj, key: "shadowColor", value: NSColor.clear)
            _ = setValueIfPossible(obj, key: "drawsArrow", value: false)
            _ = setValueIfPossible(obj, key: "hasArrow", value: false)
            _ = setValueIfPossible(obj, key: "arrowHeight", value: 0)
            _ = setValueIfPossible(obj, key: "arrowWidth", value: 0)
            _ = setValueIfPossible(obj, key: "arrowOffset", value: 0)
        }
        for subview in view.subviews where subview !== protectedView {
            stripPopoverBackground(on: subview, keep: nil)
            subview.isHidden = true
            subview.removeFromSuperview()
        }
    }

    @discardableResult
    private func setValueIfPossible(_ object: NSObject, key: String, value: Any) -> Bool {
        guard let first = key.unicodeScalars.first else { return false }
        let selector = NSSelectorFromString("set\(String(first).uppercased())\(String(key.dropFirst())):")
        guard object.responds(to: selector) else { return false }
        object.setValue(value, forKey: key)
        return true
    }

    private func enforcePopoverWindowShape(window: NSWindow, hostingView: NSView) {
        guard let contentView = window.contentView,
              let frameView = contentView.superview else { return }
        frameView.wantsLayer = true
        if #available(macOS 10.13, *) {
            frameView.layer?.cornerCurve = .continuous
        }
        if let obj = frameView as? NSObject {
            _ = setValueIfPossible(obj, key: "drawsArrow", value: false)
            _ = setValueIfPossible(obj, key: "hasArrow", value: false)
            _ = setValueIfPossible(obj, key: "arrowHeight", value: 0)
            _ = setValueIfPossible(obj, key: "arrowWidth", value: 0)
            _ = setValueIfPossible(obj, key: "arrowOffset", value: 0)
        }
        let bounds = frameView.bounds.integral
        guard bounds.width > 0, bounds.height > 0 else { return }
        let desiredRadius: CGFloat = {
            if let glass = hostingView as? GlassCardView {
                return glass.config.cornerRadius
            }
            if let radius = hostingView.layer?.cornerRadius, radius > 0 {
                return radius
            }
            return 12
        }()
        let maxRadius = max(0, min(desiredRadius, min(bounds.width, bounds.height) * 0.5))
        let maskLayer = (frameView.layer?.mask as? CAShapeLayer) ?? CAShapeLayer()
        maskLayer.frame = bounds
        maskLayer.path = CGPath(roundedRect: bounds,
                                cornerWidth: maxRadius,
                                cornerHeight: maxRadius,
                                transform: nil)
        frameView.layer?.mask = maskLayer
        frameView.layer?.masksToBounds = true

        contentView.translatesAutoresizingMaskIntoConstraints = true
        contentView.autoresizingMask = [.width, .height]
        if contentView.frame != frameView.bounds {
            contentView.frame = frameView.bounds
        }
    }

    func popoverDidClose(_ notification: Notification) {
        if let closed = notification.object as? NSPopover,
           let current = composerPopover,
           closed !== current {
            return
        }
        if let monitor = keyMonitor {
            NSEvent.removeMonitor(monitor)
            keyMonitor = nil
        }
        cancelComposerKeyBuffering()
        removeClickOutsideMonitor()
        currentListItem = nil
        currentListItemID = nil
        pendingPageLabelOverride = nil
        removePreviewHighlight()
        clearAnnotationSelectionOverlays(reason: "popover_close")
    }

    func popoverWillShow(_ notification: Notification) {
        guard let popover = notification.object as? NSPopover,
              popover === composerPopover,
              let vc = popover.contentViewController as? AnnotationComposerViewController,
              let window = popover.contentViewController?.view.window else { return }
        prepareComposerPopoverWindow(window: window, hostingView: vc.view)
    }

    private func selectionForAnnotation(in pdfView: PDFView, page: PDFPage, pagePoint: NSPoint) -> PDFSelection? {
        guard let sel = pdfView.currentSelection else { return nil }
        let trimmed = sel.string?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !trimmed.isEmpty else { return nil }
        let pages = sel.pages ?? []
        guard pages.contains(page) else { return nil }

        // If the click is near the selection, use it; otherwise still honor the current selection to avoid losing the highlight on submit.
        let bounds = sel.bounds(for: page)
        let padded = bounds.insetBy(dx: -12, dy: -12)
        if padded.contains(pagePoint) {
            return sel
        }

        return sel
    }

    private func selectionAnchorBounds(_ selection: PDFSelection, on page: PDFPage) -> CGRect? {
        let pieces = selection.selectionsByLine() ?? [selection]
        var union = CGRect.null
        for piece in pieces {
            guard (piece.pages ?? []).contains(page) else { continue }
            let rect = piece.bounds(for: page)
            guard rect.width > 0 && rect.height > 0 else { continue }
            union = union.isNull ? rect : union.union(rect)
        }
        if union.isNull {
            let rect = selection.bounds(for: page)
            if rect.width > 0 && rect.height > 0 { return rect }
            return nil
        }
        return union
    }

    private func highlightAnchorBounds(for annotation: PDFAnnotation, on page: PDFPage) -> CGRect? {
        if annotationIsHighlightLike(annotation) {
            let rect = annotationAnchorRect(for: annotation)
            return (rect.width > 0 && rect.height > 0) ? rect : nil
        }

        let groupID = noteGroupID(for: annotation)
        var matches: [PDFAnnotation] = []
        if let groupID {
            matches = page.annotations.filter {
                annotationIsHighlightLike($0) && noteGroupID(for: $0) == groupID
            }
        }
        if matches.isEmpty {
            matches = highlightsNearNote(annotation, on: page)
        }
        guard !matches.isEmpty else { return nil }

        var union = CGRect.null
        for highlight in matches {
            let rect = annotationAnchorRect(for: highlight)
            guard rect.width > 0 && rect.height > 0 else { continue }
            union = union.isNull ? rect : union.union(rect)
        }
        return union.isNull ? nil : union
    }

    private func anchorRectAtBottom(bounds: CGRect, page: PDFPage, pdfView: PDFView, host: NSView) -> NSRect {
        let rectInView = pdfView.convert(bounds, from: page)
        let anchorY = pdfView.isFlipped ? rectInView.maxY : rectInView.minY
        let anchorPointInView = NSPoint(x: rectInView.midX, y: anchorY)
        let anchorPointInHost = pdfView.convert(anchorPointInView, to: host)
        return NSRect(origin: anchorPointInHost, size: NSSize(width: 1, height: 1))
    }

    private func applyPendingPageLabelOverride(groupID: String, page: PDFPage) {
        guard let override = pendingPageLabelOverride else { return }
        let trimmed = override.trimmingCharacters(in: .whitespacesAndNewlines)
        let annotations = page.annotations.filter { noteGroupID(for: $0) == groupID }
        guard !annotations.isEmpty else {
            pendingPageLabelOverride = nil
            return
        }
        for ann in annotations {
            assignGroupID(groupID, to: ann)
            if trimmed.isEmpty {
                ann.setValue("", forAnnotationKey: annotationPageLabelOverrideKey)
            } else {
                ann.setValue(trimmed, forAnnotationKey: annotationPageLabelOverrideKey)
            }
            updateAnnotation(ann, reason: "group_page_label")
        }
        pendingPageLabelOverride = nil
    }

    private func ensureAnnotationCreationDate(_ annotation: PDFAnnotation, fallback: Date) {
        guard annotationCreationDateValue(for: annotation) == nil else { return }
        annotation.setValue(fallback, forAnnotationKey: annotationCreationDateKey)
    }

    private func commitAnnotation(content: AnnotationCommentContent,
                                  color: NSColor,
                                  style: AnnotationMarkupStyle,
                                  context: AnnotationContext) {
        debugLog("commitAnnotation called with selection: \(context.selection != nil ? "present" : "nil")")
        let saveStart = timingStart()
        guard let pdfView, let doc = pdfView.document else { return }

        // Persist the last-used color so it becomes the default for new highlights.
        persistDefaultAnnotationColor(color)

        let page = context.page
        var needsHighlightRefresh = false
        var pendingGroupID: String?
        var structuralChange = false
        purgePreviewAnnotations(on: page, reason: "commit")
        if let selection = context.selection {
            let detectedGroupID = existingGroupID(for: selection, on: page)
            let groupID = detectedGroupID
                ?? context.existingAnnotation.flatMap { noteGroupID(for: $0) }
                ?? UUID().uuidString
            pendingGroupID = groupID
            structuralChange = true
            let anchor = CGPoint(x: context.pagePoint.x, y: context.pagePoint.y)
            var rects = selectionRectsForCommit(selection, page: page, anchor: anchor)
            if rects.isEmpty {
                let fallback = selection.bounds(for: page)
                if fallback.width > 0 && fallback.height > 0 {
                    rects = [fallback]
                }
            }
            let existingHighlights = highlightsMatching(selection: selection, page: page, groupID: groupID)
            let creationFallback: Date = {
                if let existing = context.existingAnnotation,
                   let createdAt = annotationCreationDateValue(for: existing) {
                    return createdAt
                }
                if let existingNote = noteForGroup(groupID, on: page),
                   let createdAt = annotationCreationDateValue(for: existingNote) {
                    return createdAt
                }
                if let createdAt = existingHighlights.first.flatMap(annotationCreationDateValue) {
                    return createdAt
                }
                if let pending = pendingCreationDateOverride {
                    return pending
                }
                return Date()
            }()
            if existingHighlights.isEmpty {
                for bounds in rects {
                    guard bounds.width > 0, bounds.height > 0 else { continue }
                    let highlight = PDFAnnotation(bounds: bounds, forType: annotationSubtype(for: style), withProperties: nil)
                    applyHighlightColor(highlight, baseColor: color, style: style)
                    let quadPoints = quadrilateralPoints(for: bounds)
                    highlight.quadrilateralPoints = quadPoints
                    storeQuadPoints(quadPoints, on: highlight)
                    if let raw = page.selection(for: bounds)?.string?.trimmingCharacters(in: .whitespacesAndNewlines),
                       !raw.isEmpty {
                        highlight.contents = raw
                    }
                    ensureAnnotationCreationDate(highlight, fallback: creationFallback)
                    assignGroupID(groupID, to: highlight)
                    let pageIndex = doc.index(for: page)
                    print("[DBG_ANN_MUTATE] action=add type=highlight page=\(pageIndex) gid=\(groupID) bounds=\(NSStringFromRect(bounds)) scale=\(pdfView.scaleFactor)")
                    if annotationDebugEnabled {
                        let rects = quadRects(for: highlight)
                        let text = debugTrimmedText(page.selection(for: bounds)?.string)
                        annotationLog("[ANN_CREATE] id=\(annotationDebugID(highlight)) page=\(pageIndex) gid=\(groupID) style=\(style.rawValue) rects=\(debugRectsText(rects)) text=\"\(text)\"")
                    }
                    addAnnotation(highlight, to: page, reason: "commit_highlight_add")
                }
                needsHighlightRefresh = true
            } else {
                for highlight in existingHighlights {
                    assignGroupID(groupID, to: highlight)
                    _ = rebuildHighlightAnnotation(
                        highlight,
                        baseColor: color,
                        groupIDOverride: groupID,
                        subtypeOverride: annotationSubtype(for: style)
                    )
                }
                needsHighlightRefresh = true
            }

            let selBounds = selection.bounds(for: page)
            let note = noteForGroup(groupID, on: page)
                ?? {
                    let rect = noteRect(for: page, anchor: NSPoint(x: selBounds.minX, y: selBounds.midY), selectionBounds: selBounds)
                    let created = PDFAnnotation(bounds: rect, forType: .text, withProperties: nil)
                    ensureAnnotationCreationDate(created, fallback: creationFallback)
                    let pageIndex = doc.index(for: page)
                    print("[DBG_ANN_MUTATE] action=add type=note page=\(pageIndex) gid=\(groupID) bounds=\(NSStringFromRect(rect)) scale=\(pdfView.scaleFactor)")
                    addAnnotation(created, to: page, reason: "commit_note_add")
                    self.suppressNotePopupUI(for: created)
                    return created
                }()
            assignGroupID(groupID, to: note)
            suppressNotePopupUI(for: note)
            applyAnnotationContent(content, to: note)
            note.color = color
            note.userName = NSFullUserName()
            updateAnnotation(note, reason: "commit_note_update")

            var updatedHighlights = highlightsMatching(selection: selection, page: page, groupID: groupID)
            if !updatedHighlights.isEmpty {
                updatedHighlights = sanitizeHighlightMatches(updatedHighlights, groupID: groupID, page: page, fallbackNote: note)
            }
            let quadPoints = validatedGroupQuadPoints(from: updatedHighlights, page: page)
            if !quadPoints.isEmpty {
                cacheGroupQuadPoints(quadPoints, groupID: groupID, page: page, fallbackNote: note)
            }

            logHighlightSummary("before_persist", page: page, groupID: groupID)
        } else if let existing = context.existingAnnotation {
            let groupID = strictGroupID(for: existing, on: page)
            pendingGroupID = groupID
            assignGroupID(groupID, to: existing)
            suppressNotePopupUI(for: existing)
            applyAnnotationContent(content, to: existing)
            existing.color = color
            updateAnnotation(existing, reason: "commit_note_update")
            let normalizedBaseColor = (color.usingColorSpace(.deviceRGB) ?? color).withAlphaComponent(1.0)
            var highlightTargets = page.annotations.filter {
                annotationIsHighlightLike($0) && noteGroupID(for: $0) == groupID
            }
            if highlightTargets.isEmpty, annotationIsHighlightLike(existing) {
                highlightTargets = [existing]
            }
            if !highlightTargets.isEmpty {
                let currentStyle = highlightTargets.first.map(annotationMarkupStyle) ?? highlightStyle(for: existing, on: page)
                let currentColor = highlightTargets.first.map(annotationDisplayBaseColor) ?? normalizedBaseColor
                let styleChanged = currentStyle != style
                let colorChanged = !colorsMatch(currentColor.withAlphaComponent(1.0), normalizedBaseColor)
                if styleChanged {
                    let fallbackNote = annotationIsTextNote(existing) ? existing : noteForGroup(groupID, on: page)
                    removeHighlightedSelections(overlapping: highlightTargets)
                    let converted = convertMarkupAnnotations(matches: highlightTargets,
                                                             groupID: groupID,
                                                             page: page,
                                                             color: normalizedBaseColor,
                                                             targetStyle: style,
                                                             fallbackNote: fallbackNote)
                    let selectionTargets: [PDFAnnotation]
                    if converted.isEmpty {
                        let updated = mutateHighlightAnnotationsInPlace(highlightTargets,
                                                                        groupID: groupID,
                                                                        baseColor: normalizedBaseColor,
                                                                        styleOverride: style)
                        selectionTargets = updated.isEmpty ? highlightTargets : updated
                        updateHighlightedSelectionsColor(overlapping: selectionTargets, color: normalizedBaseColor, style: style)
                    } else {
                        selectionTargets = converted
                        updateHighlightedSelectionsColor(overlapping: selectionTargets, color: normalizedBaseColor, style: style)
                    }
                    let latestQuadPoints = validatedGroupQuadPoints(from: selectionTargets, page: page)
                    if !latestQuadPoints.isEmpty {
                        cacheGroupQuadPoints(latestQuadPoints, groupID: groupID, page: page, fallbackNote: existing)
                    }
                    needsHighlightRefresh = true
                    structuralChange = true
                } else if colorChanged {
                    let updatedHighlights = mutateHighlightAnnotationsInPlace(highlightTargets,
                                                                              groupID: groupID,
                                                                              baseColor: normalizedBaseColor,
                                                                              styleOverride: style)
                    let selectionTargets = updatedHighlights.isEmpty ? highlightTargets : updatedHighlights
                    let quadPoints = validatedGroupQuadPoints(from: selectionTargets, page: page)
                    if !quadPoints.isEmpty {
                        cacheGroupQuadPoints(quadPoints, groupID: groupID, page: page, fallbackNote: existing)
                    }
                    updateHighlightedSelectionsColor(overlapping: selectionTargets, color: normalizedBaseColor, style: style)
                    needsHighlightRefresh = true
                } else if annotationDebugEnabled {
                    annotationLog("[ANN_EDIT] skip highlight mutate (no style/color change) gid=\(groupID)")
                }
            }

            logHighlightSummary("before_persist", page: page, groupID: groupID)
            self.composerPopover?.close()
            self.composerPopover = nil
        } else {
            let groupID = UUID().uuidString
            pendingGroupID = groupID
            let noteRect = noteRect(for: page, anchor: context.pagePoint, selectionBounds: nil)
            let note = PDFAnnotation(bounds: noteRect, forType: .text, withProperties: nil)
            let creationFallback = pendingCreationDateOverride ?? Date()
            ensureAnnotationCreationDate(note, fallback: creationFallback)
            assignGroupID(groupID, to: note)
            applyAnnotationContent(content, to: note)
            note.color = color
            note.userName = NSFullUserName()
            updateAnnotation(note, reason: "commit_note_update")
            let pageIndex = doc.index(for: page)
            print("[DBG_ANN_MUTATE] action=add type=note page=\(pageIndex) gid=\(groupID) bounds=\(NSStringFromRect(noteRect)) scale=\(pdfView.scaleFactor)")
            addAnnotation(note, to: page, reason: "commit_note_add")
            suppressNotePopupUI(for: note)

            logHighlightSummary("before_persist", page: page, groupID: groupID)
            structuralChange = true
        }

        if let groupID = pendingGroupID {
            applyPendingPageLabelOverride(groupID: groupID, page: page)
        }
        pendingCreationDateOverride = nil
        if needsHighlightRefresh {
            refreshHighlightRegions(for: [page], reason: "commit")
        }
        // Ghost highlight root cause (Failure Mode 3): quad points coming back in annotation-local
        // coordinates were treated as page coords, so overlay/hit regions rendered on the wrong
        // line. Quad points are now normalized to page coordinates before any render/cache.
        clearAnnotationSelectionOverlays(reason: "commit")
        pdfView.clearSelection()
#if DEBUG
        assertNoAnnotationSelectionOverlays(reason: "commit")
#endif
        persistAndReload(document: doc,
                         focusPage: page,
                         refresh: .none,
                         reason: "commit",
                         debounce: 0.0)
        if !structuralChange, let groupID = pendingGroupID, context.selection == nil {
            let comment = content.plainText.trimmingCharacters(in: .whitespacesAndNewlines)
            let pageIndex = doc.index(for: page)
            let info: [AnyHashable: Any] = [
                annotationChangeKindKey: AnnotationChangeKind.comment.rawValue,
                annotationChangeGroupIDKey: groupID,
                annotationChangePageIndexKey: pageIndex,
                annotationChangeCommentKey: comment,
                annotationChangeCommentPayloadKey: content.richTextPayload as Any,
                annotationChangeColorKey: color
            ]
            NotificationCenter.default.post(name: .arxivPDFAnnotationsDidChange, object: doc, userInfo: info)
        } else {
            NotificationCenter.default.post(name: .arxivPDFAnnotationsDidChange, object: doc)
        }
        timingEnd("save_annotation", saveStart)
    }

    @discardableResult
    func addShortcutResultAnnotation(content: AnnotationCommentContent) -> PDFAnnotation? {
        guard let pdfView, let doc = pdfView.document else { return nil }
        guard !content.isEmpty else { return nil }
        guard var page = pdfView.currentPage ?? doc.page(at: 0) else { return nil }
        if doc.index(for: page) == NSNotFound, let fallback = doc.page(at: 0) {
            page = fallback
        }

        let noteRect = shortcutResultNoteRect(on: page)
        let safeRect = sanitizedAnchorRect(noteRect, page: page, displayBox: .cropBox, minSize: noteIconSize)
        let note = PDFAnnotation(bounds: safeRect, forType: .text, withProperties: nil)
        let groupID = UUID().uuidString
        ensureAnnotationCreationDate(note, fallback: Date())
        assignGroupID(groupID, to: note)
        applyAnnotationContent(content, to: note)
        note.color = loadDefaultAnnotationColor()
        note.userName = NSFullUserName()
        updateAnnotation(note, reason: "shortcut_result_add")
        addAnnotation(note, to: page, reason: "shortcut_result_add")
        suppressNotePopupUI(for: note)

        refreshHighlightRegions(for: [page], reason: "shortcut_add")
        persistAndReload(document: doc,
                         focusPage: page,
                         refresh: .none,
                         reason: "shortcut_add",
                         debounce: 0.0)
        NotificationCenter.default.post(name: .arxivPDFAnnotationsDidChange, object: doc)
        return note
    }

    func updateAnnotationGroupColor(for item: PDFAnnotationListItem, color: NSColor) {
        guard let pdfView, let doc = pdfView.document else { return }
        let groupID = item.stableID
        let page = resolvedPage(for: item, document: doc)
        ensureMarkupState(for: page)
        let baseColor = (color.usingColorSpace(.deviceRGB) ?? color).withAlphaComponent(1.0)
        var annotations = annotationsForListItem(item, page: page)
        guard !annotations.isEmpty else { return }
        if annotationDebugEnabled {
            annotationLog("[ANN_COLOR_GROUP] start source=list_menu group=\(groupID) page=\(doc.index(for: page)) color=\(hexFromColor(baseColor, includeAlpha: true)) count=\(annotations.count)")
        }
        for ann in annotations {
            assignGroupID(groupID, to: ann)
            if annotationIsHighlightLike(ann) {
                // Updated below in a single in-place pass.
            } else {
                ann.color = baseColor
                updateAnnotation(ann, reason: "group_color_note")
            }
        }

        var highlightAnnotations = annotations.filter { annotationIsHighlightLike($0) }
        if highlightAnnotations.isEmpty {
            let fallbackNote = annotations.first(where: { annotationIsTextNote($0) })
            highlightAnnotations = highlightsForGroupWithoutSelection(groupID: groupID,
                                                                      page: page,
                                                                      fallbackNote: fallbackNote)
        }
        var highlightStyleHighlights: [PDFAnnotation] = []
        var underlineStyleHighlights: [PDFAnnotation] = []
        for ann in highlightAnnotations {
            let currentStyle = annotationMarkupStyle(for: ann)
            if currentStyle == .underline {
                underlineStyleHighlights.append(ann)
            } else {
                highlightStyleHighlights.append(ann)
            }
            if !annotationHasValidQuadPoints(ann, page: page) {
                ensureGeometryForColorUpdate(ann, groupID: groupID, page: page, fallbackNote: nil, source: "group_color_menu")
            } else if annotationDebugEnabled {
                annotationLog("[ANN_COLOR_GEOM] source=group_color_menu id=\(annotationDebugID(ann)) kept=stored")
            }
            applyMarkupColorOnly(ann, baseColor: baseColor, style: currentStyle, source: "group_color_menu")
        }
        // Do not fallback to proximity-based matching here; strict group-only updates.
        let quadPoints = validatedGroupQuadPoints(from: highlightAnnotations, page: page)
        if !quadPoints.isEmpty {
            cacheGroupQuadPoints(quadPoints, groupID: groupID, page: page, fallbackNote: nil)
        }
        if !highlightStyleHighlights.isEmpty {
            updateHighlightedSelectionsColor(overlapping: highlightStyleHighlights, color: baseColor, style: .highlight)
        }
        if !underlineStyleHighlights.isEmpty {
            updateHighlightedSelectionsColor(overlapping: underlineStyleHighlights, color: baseColor, style: .underline)
        }
        refreshHighlightRegions(for: [page], reason: "group_color")
        persistAndReload(document: doc,
                         focusPage: page,
                         refresh: .none,
                         reason: "group_color",
                         debounce: 0.0)
        let pageIndex = doc.index(for: page)
        let info: [AnyHashable: Any] = [
            annotationChangeKindKey: AnnotationChangeKind.color.rawValue,
            annotationChangeGroupIDKey: groupID,
            annotationChangePageIndexKey: pageIndex,
            annotationChangeColorKey: baseColor
        ]
        NotificationCenter.default.post(name: .arxivPDFAnnotationsDidChange, object: doc, userInfo: info)
        if annotationDebugEnabled {
            annotationLog("[ANN_COLOR_GROUP] end source=list_menu group=\(groupID) page=\(pageIndex) color=\(hexFromColor(baseColor, includeAlpha: true)) highlights=\(highlightAnnotations.count)")
        }
    }

    private func annotationStyleSnapshot(for item: PDFAnnotationListItem) -> (style: AnnotationMarkupStyle, hasAnnotations: Bool) {
        guard let pdfView, let doc = pdfView.document else { return (.highlight, false) }
        let page = resolvedPage(for: item, document: doc)
        var annotations = annotationsForListItem(item, page: page)
        guard !annotations.isEmpty else { return (.highlight, false) }
        if let note = annotations.first(where: { annotationIsTextNote($0) }) {
            return (highlightStyle(for: note, on: page), true)
        }
        let highlights = annotations.filter { annotationIsHighlightLike($0) }
        if highlights.contains(where: { annotationMarkupStyle(for: $0) == .underline }) {
            return (.underline, true)
        }
        if !highlights.isEmpty {
            return (.highlight, true)
        }
        return (.highlight, true)
    }

    func annotationStyle(for item: PDFAnnotationListItem) -> AnnotationMarkupStyle {
        annotationStyleSnapshot(for: item).style
    }

    enum AnnotationCommand {
        case delete
        case convertStyle(AnnotationMarkupStyle)
    }

    func annotationToggleTargetStyle(for item: PDFAnnotationListItem) -> AnnotationMarkupStyle {
        let snapshot = annotationStyleSnapshot(for: item)
        var currentStyle = snapshot.style
        if !snapshot.hasAnnotations,
           let existing = currentContext?.existingAnnotation,
           annotationIsHighlightLike(existing) {
            currentStyle = annotationMarkupStyle(for: existing)
        }
        return (currentStyle == .underline) ? .highlight : .underline
    }

    func annotationToggleTitle(for item: PDFAnnotationListItem) -> String {
        let targetStyle = annotationToggleTargetStyle(for: item)
        return (targetStyle == .underline) ? "Convert to Underline" : "Convert to Highlight"
    }

    func annotationToggleCommand(for item: PDFAnnotationListItem) -> AnnotationCommand {
        .convertStyle(annotationToggleTargetStyle(for: item))
    }

    func performAnnotationCommand(_ command: AnnotationCommand,
                                              for item: PDFAnnotationListItem,
                                              source: String) {
        if !Thread.isMainThread {
            DispatchQueue.main.async { [weak self] in
                self?.performAnnotationCommand(command, for: item, source: source)
            }
            return
        }
        var resolvedItem = item
        if let items = listItemsProvider?(),
           let latest = items.first(where: { $0.stableID == item.stableID }) {
            resolvedItem = applyingColorOverride(latest, color: item.color)
        }
        let shouldLog = annotationActionDebugEnabled
        if shouldLog {
            let pre = debugAnnotationSnapshot(for: resolvedItem)
            annotationActionLog("command_start source=\(source) item=\(resolvedItem.stableID) page=\(resolvedItem.pageIndex) \(pre)")
        }
        switch command {
        case .delete:
            deleteAnnotationGroup(for: resolvedItem)
        case .convertStyle(let style):
            updateAnnotationGroupStyle(for: resolvedItem, style: style)
        }
        if shouldLog {
            let post = debugAnnotationSnapshot(for: resolvedItem)
            let listExists = listItemsProvider?().contains(where: { $0.stableID == resolvedItem.stableID }) ?? false
            annotationActionLog("command_end source=\(source) item=\(resolvedItem.stableID) listItem=\(listExists) \(post)")
        }
    }

    func updateAnnotationAppearance(for annotation: PDFAnnotation,
                                                color: NSColor,
                                                style: AnnotationMarkupStyle,
                                                source: String) {
        guard let page = annotation.page else { return }
        if annotationActionDebugEnabled {
            let gid = noteGroupID(for: annotation) ?? "-"
            annotationActionLog("command_start source=\(source) annotation=\(annotationDebugID(annotation)) gid=\(gid) style=\(style.rawValue)")
        }
        if annotationDebugEnabled {
            annotationLog("[ANN_COLOR_UI] before source=\(source) \(debugAnnotationRenderState(annotation, page: page))")
        }
        applyMarkupStyle(for: annotation, on: page, color: color, style: style)
        if annotationDebugEnabled {
            annotationLog("[ANN_COLOR_UI] after source=\(source) \(debugAnnotationRenderState(annotation, page: page))")
        }
        if annotationActionDebugEnabled {
            let gid = noteGroupID(for: annotation) ?? "-"
            annotationActionLog("command_end source=\(source) annotation=\(annotationDebugID(annotation)) gid=\(gid) style=\(style.rawValue)")
        }
    }

    private func maybeRunAnnotationHarness(for context: AnnotationContext) {
        guard annotationHarnessEnabled else { return }
        guard context.existingAnnotation != nil else { return }
        guard let item = actionListItem(for: context) else { return }
        let toggleCount = 12
        let delay: TimeInterval = 0.15
        annotationActionLog("harness_start item=\(item.stableID) toggles=\(toggleCount) delete=\(annotationHarnessDeleteEnabled)")
        for idx in 0..<toggleCount {
            let deadline = DispatchTime.now() + (delay * Double(idx))
            DispatchQueue.main.asyncAfter(deadline: deadline) { [weak self] in
                guard let self else { return }
                let command = self.annotationToggleCommand(for: item)
                self.performAnnotationCommand(command, for: item, source: "harness_toggle")
            }
        }
        if annotationHarnessDeleteEnabled {
            let deadline = DispatchTime.now() + (delay * Double(toggleCount)) + 0.3
            DispatchQueue.main.asyncAfter(deadline: deadline) { [weak self] in
                self?.performAnnotationCommand(.delete, for: item, source: "harness_delete")
            }
        }
    }

