    private func debugAnnotationSnapshot(for item: PDFAnnotationListItem) -> String {
        guard let pdfView, let doc = pdfView.document else { return "state=no_document" }
        let page = resolvedPage(for: item, document: doc)
        let annotations = annotationsForListItem(item, page: page)
        let highlightTypes = annotations
            .filter { annotationIsHighlightLike($0) }
            .map { annotationTypeName($0) }
        let noteCount = annotations.filter { annotationIsTextNote($0) }.count
        let snapshot = annotationStyleSnapshot(for: item)
        let style = snapshot.style
        let listItem = listItemsProvider?().first(where: { $0.stableID == item.stableID })
        let listStyle = listItem.map { annotationStyle(for: $0).rawValue } ?? "missing"
        let pdfTypes = highlightTypes.isEmpty ? "none" : highlightTypes.joined(separator: ",")
        let presence = snapshot.hasAnnotations ? "present" : "missing"
        return "state=style:\(style.rawValue) pdfTypes:\(pdfTypes) notes:\(noteCount) listStyle:\(listStyle) anns:\(presence)"
    }

    func updateAnnotationGroupStyle(for item: PDFAnnotationListItem, style: AnnotationMarkupStyle) {
        guard let doc = pdfView?.document else { return }
        let groupID = item.stableID
        let page = resolvedPage(for: item, document: doc)
        let baseColor = (item.color.usingColorSpace(.deviceRGB) ?? item.color).withAlphaComponent(1.0)
        var annotations = annotationsForListItem(item, page: page)
        guard !annotations.isEmpty else { return }
        var note: PDFAnnotation?
        for ann in annotations {
            assignGroupID(groupID, to: ann)
            if annotationIsTextNote(ann) {
                ann.color = baseColor
                updateAnnotation(ann, reason: "group_style_note")
                note = ann
            }
        }
        if note == nil {
            note = noteForGroup(groupID, on: page)
        }
        if let target = annotations.first(where: { annotationIsHighlightLike($0) }) {
            syncComposerStyleIfNeeded(groupID: groupID, style: style, color: baseColor)
            applySingleAnnotationStyle(target, on: page, color: baseColor, style: style, source: "group_style")
            return
        }
        persistAndReload(document: doc,
                         focusPage: page,
                         refresh: .none,
                         reason: "group_style_note_only",
                         debounce: 0.0)
        NotificationCenter.default.post(name: .arxivPDFAnnotationsDidChange, object: doc)
    }

    func openAnnotationGroup(for item: PDFAnnotationListItem) {
        guard let pdfView, let doc = pdfView.document else { return }
        currentListItem = item
        currentListItemID = item.stableID
        pendingPageLabelOverride = nil
        let page = resolvedPage(for: item, document: doc)
        let annotations = annotationsForListItem(item, page: page)
        if let note = annotations.first(where: { annotationIsTextNote($0) }) {
            presentComposer(for: note)
            return
        }
        if let highlight = annotations.first(where: { annotationIsHighlightLike($0) }) {
            presentComposer(for: highlight)
        }
    }

    func updateAnnotationGroupComment(for item: PDFAnnotationListItem, content: AnnotationCommentContent) {
        guard let pdfView, let doc = pdfView.document else { return }
        let saveStart = timingStart()
        let groupID = item.stableID
        let page = resolvedPage(for: item, document: doc)
        let comment = content.plainText.trimmingCharacters(in: .whitespacesAndNewlines)
        let baseColor = (item.color.usingColorSpace(.deviceRGB) ?? item.color).withAlphaComponent(1.0)

        let annotations = annotationsForListItem(item, page: page)
        guard !annotations.isEmpty else { return }
        for ann in annotations {
            assignGroupID(groupID, to: ann)
        }
        let notes = annotations.filter { annotationIsTextNote($0) }

        if let note = notes.first {
            applyAnnotationContent(content, to: note)
            note.color = baseColor
            suppressNotePopupUI(for: note)
            updateAnnotation(note, reason: "group_comment_update")
        } else if !comment.isEmpty {
            let bounds = item.anchorBounds
            let anchor = NSPoint(x: bounds.minX, y: bounds.midY)
            let selectionBounds = (bounds.width > 0 && bounds.height > 0) ? bounds : nil
            let rect = noteRect(for: page, anchor: anchor, selectionBounds: selectionBounds)
            let note = PDFAnnotation(bounds: rect, forType: .text, withProperties: nil)
            assignGroupID(groupID, to: note)
            applyAnnotationContent(content, to: note)
            note.color = baseColor
            note.userName = NSFullUserName()
            addAnnotation(note, to: page, reason: "commit_note_add")
            suppressNotePopupUI(for: note)
        }

        persistAndReload(document: doc,
                         focusPage: page,
                         refresh: .none,
                         reason: "group_comment",
                         debounce: 0.35)
        let pageIndex = doc.index(for: page)
        let info: [AnyHashable: Any] = [
            annotationChangeKindKey: AnnotationChangeKind.comment.rawValue,
            annotationChangeGroupIDKey: groupID,
            annotationChangePageIndexKey: pageIndex,
            annotationChangeCommentKey: comment,
            annotationChangeCommentPayloadKey: content.richTextPayload as Any,
            annotationChangeColorKey: baseColor
        ]
        NotificationCenter.default.post(name: .arxivPDFAnnotationsDidChange, object: doc, userInfo: info)
        timingEnd("save_comment", saveStart)
    }

    func updateAnnotationGroupPageLabel(for item: PDFAnnotationListItem, label: String?) {
        guard let pdfView, let doc = pdfView.document else { return }
        let groupID = item.stableID
        let page = resolvedPage(for: item, document: doc)
        let trimmed = label?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let prefix = "Page "
        let normalized = trimmed.hasPrefix(prefix) ? String(trimmed.dropFirst(prefix.count)) : trimmed

        let annotations = annotationsForListItem(item, page: page)
        guard !annotations.isEmpty else { return }
        for ann in annotations {
            assignGroupID(groupID, to: ann)
            if normalized.isEmpty {
                // PDFAnnotation.setValue expects a non-optional in newer SDKs; use empty string to clear.
                ann.setValue("", forAnnotationKey: annotationPageLabelOverrideKey)
            } else {
                ann.setValue(normalized, forAnnotationKey: annotationPageLabelOverrideKey)
            }
            updateAnnotation(ann, reason: "group_page_label")
        }

        persistAndReload(document: doc,
                         focusPage: page,
                         refresh: .none,
                         reason: "group_page_label",
                         debounce: 0.25)
        let pageIndex = doc.index(for: page)
        let resolvedLabel: String = {
            if !normalized.isEmpty { return normalized }
            if let label = page.label?.trimmingCharacters(in: .whitespacesAndNewlines), !label.isEmpty {
                return label
            }
            return String(pageIndex + 1)
        }()
        let info: [AnyHashable: Any] = [
            annotationChangeKindKey: AnnotationChangeKind.pageLabel.rawValue,
            annotationChangeGroupIDKey: groupID,
            annotationChangePageIndexKey: pageIndex,
            annotationChangePageLabelKey: "Page \(resolvedLabel)"
        ]
        NotificationCenter.default.post(name: .arxivPDFAnnotationsDidChange, object: doc, userInfo: info)
    }

    func deleteAnnotationGroup(for item: PDFAnnotationListItem) {
        guard let pdfView, let doc = pdfView.document else { return }
        if isComposerVisible {
            hideAnnotationMenu(reason: "delete_from_list")
        }
        let page = resolvedPage(for: item, document: doc)
        let annotations = annotationsForListItem(item, page: page)
        guard !annotations.isEmpty else { return }

        let highlightAnnotations = annotations.filter { annotationIsHighlightLike($0) }
        removeHighlightedSelections(overlapping: highlightAnnotations)
        for ann in annotations {
            removeAnnotation(ann, from: page, reason: "delete_item")
        }
        groupQuadPointsCache.removeValue(forKey: item.stableID)
        if currentListItemID == item.stableID {
            currentListItemID = nil
            currentListItem = nil
        }

        refreshHighlightRegions(for: [page], reason: "delete_item")
        persistAndReload(document: doc,
                         focusPage: page,
                         refresh: .none,
                         reason: "delete_item",
                         debounce: 0.0)
        NotificationCenter.default.post(name: .arxivPDFAnnotationsDidChange, object: doc)
    }

    private func noteRect(for page: PDFPage, anchor: NSPoint, selectionBounds: CGRect?) -> CGRect {
        let size = noteIconSize

        var origin = anchor
        if let selectionBounds {
            // Place to the left of the selection start, vertically centered on the selection.
            origin = NSPoint(x: selectionBounds.minX - size.width - 4, y: selectionBounds.midY - (size.height / 2))
        } else {
            origin.y -= size.height / 2
        }
        let rawRect = CGRect(origin: origin, size: size)
        return clampedRect(rawRect, within: safePageBounds(page, displayBox: .cropBox), minSize: size)
    }

    private func shortcutResultNoteRect(on page: PDFPage) -> CGRect {
        guard let bounds = safePageBounds(page, displayBox: .cropBox) else {
            return defaultAnchorRect(on: page, displayBox: .cropBox, size: noteIconSize)
        }
        let insetX = max(12, noteIconSize.width * 0.8)
        let insetY = max(12, noteIconSize.height * 0.8)
        let anchors: [CGPoint] = [
            CGPoint(x: bounds.minX + insetX, y: bounds.maxY - insetY),
            CGPoint(x: bounds.maxX - insetX, y: bounds.maxY - insetY),
            CGPoint(x: bounds.minX + insetX, y: bounds.midY),
            CGPoint(x: bounds.maxX - insetX, y: bounds.midY),
            CGPoint(x: bounds.midX, y: bounds.maxY - insetY),
            CGPoint(x: bounds.midX, y: bounds.midY),
            CGPoint(x: bounds.midX, y: bounds.minY + insetY),
            CGPoint(x: bounds.minX + insetX, y: bounds.minY + insetY),
            CGPoint(x: bounds.maxX - insetX, y: bounds.minY + insetY),
        ]
        for anchor in anchors {
            let rect = noteRect(for: page, anchor: anchor, selectionBounds: nil)
            if !shortcutResultRectIntersectsAnnotations(rect, on: page) {
                return rect
            }
        }
        let fallback = CGPoint(x: bounds.midX, y: bounds.midY)
        let rect = noteRect(for: page, anchor: fallback, selectionBounds: nil)
        return rectIsUsable(rect)
            ? rect
            : defaultAnchorRect(on: page, displayBox: .cropBox, size: noteIconSize)
    }

    private func shortcutResultRectIntersectsAnnotations(_ rect: CGRect, on page: PDFPage) -> Bool {
        for ann in page.annotations {
            if annotationIsHighlightLike(ann) {
                if annotationAnchorRect(for: ann).intersects(rect) {
                    return true
                }
            } else if annotationIsTextNote(ann) {
                if ann.bounds.intersects(rect) {
                    return true
                }
            }
        }
        return false
    }

    private func suppressNotePopupUI(for annotation: PDFAnnotation) {
        guard annotationIsTextNote(annotation) else { return }
        var didChange = false
        if let popup = annotation.popup {
            let popupContents = popup.contents?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            let noteContents = annotation.contents?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            if noteContents.isEmpty && !popupContents.isEmpty {
                annotation.contents = popupContents
                didChange = true
            }
            if popup.isOpen {
                popup.isOpen = false
            }
            if popup.shouldDisplay || popup.shouldPrint {
                popup.shouldDisplay = false
                popup.shouldPrint = false
                didChange = true
            }
            annotation.popup = nil
            didChange = true
        }
        if annotation.shouldDisplay || annotation.shouldPrint {
            annotation.shouldDisplay = false
            annotation.shouldPrint = false
            didChange = true
        }
        if didChange {
            invalidateAnnotationDisplay(annotation)
        }
    }

    private enum AnnotationRefreshMode {
        case none
        case page(PDFPage)
        case full
    }

    private func persistAndReload(document: PDFDocument,
                                  focusPage: PDFPage,
                                  refresh: AnnotationRefreshMode = .full,
                                  reason: String = "persist",
                                  debounce: TimeInterval = 0.0) {
        guard let pdfView else { return }
        let focusIndex = document.index(for: focusPage)
        let targetURL = writableURL(for: document)
        guard let targetURL else { return }
        persistToken += 1
        let token = persistToken
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            let start = self.timingStart()
            self.persistQueue.async {
                let tmp = targetURL.deletingLastPathComponent()
                    .appendingPathComponent(".tmp-\(UUID().uuidString)-\(targetURL.lastPathComponent)")
                var wrote = false
                if document.write(to: tmp) {
                    do {
                        if FileManager.default.fileExists(atPath: targetURL.path) {
                            _ = try FileManager.default.replaceItemAt(targetURL, withItemAt: tmp)
                        } else {
                            try FileManager.default.moveItem(at: tmp, to: targetURL)
                        }
                        wrote = true
                    } catch {
                        try? FileManager.default.removeItem(at: tmp)
                    }
                } else {
                    try? FileManager.default.removeItem(at: tmp)
                }
                DispatchQueue.main.async { [weak self] in
                    guard let self, token == self.persistToken else { return }
                    // Root cause: we previously called pdfView.go(to:) (and reset scale) after each
                    // annotation save. PDFKit treats go(to:) as navigation and snaps to page top,
                    // so debounced saves could trigger random scroll jumps during normal scrolling.
                    // Fix: never navigate here; preserve the current scroll anchor across refreshes.
                    let scrollSnapshot: PDFScrollSnapshot? = {
                        if case .none = refresh { return nil }
                        return self.capturePDFScrollSnapshot(reason: "persist_\(reason)")
                    }()
                    if focusIndex != NSNotFound, focusIndex >= 0,
                       let page = document.page(at: focusIndex) {
                        logHighlightSummary("after_persist", page: page, groupID: nil)
                    }
                    if annotationDebugEnabled {
                        annotationLog("[ANN_PERSIST] reason=\(reason) wrote=\(wrote) token=\(token)")
                    }
                    let docID = reportingDocumentID(for: document)
                    let severity: ReportingLogSeverity = wrote ? .info : .warn
                    self.reportDocumentIO("pdf_save",
                                          documentID: docID,
                                          severity: severity,
                                          details: ["reason": reason, "wrote": "\(wrote)"])
                    switch refresh {
                    case .none:
                        break
                    case .page(let page):
                        self.refreshHighlightRegions(for: [page], reason: reason)
                    case .full:
                        self.refreshIcons()
                    }
                    self.restorePDFScrollSnapshot(scrollSnapshot, reason: "persist_\(reason)")
                    self.timingEnd("persist", start)
                }
            }
        }
        pendingPersistWorkItem?.cancel()
        pendingPersistWorkItem = work
        if debounce > 0 {
            DispatchQueue.main.asyncAfter(deadline: .now() + debounce, execute: work)
        } else {
            DispatchQueue.main.async(execute: work)
        }
    }

    private func writableURL(for document: PDFDocument) -> URL? {
        if let url = document.documentURL, url.isFileURL, FileManager.default.isWritableFile(atPath: url.path) {
            return url
        }
        let caches = FileManager.default.urls(for: .cachesDirectory, in: .userDomainMask).first
        let targetName = document.documentURL?.lastPathComponent ?? "annotated.pdf"
        if let caches {
            try? FileManager.default.createDirectory(at: caches, withIntermediateDirectories: true)
            return caches.appendingPathComponent("annotated_" + targetName)
        }
        return nil
    }

    private func presentComposer(for annotation: PDFAnnotation) {
        guard let page = annotation.page, let pdfView, let host = hostView else { return }
        let anchorRect = annotationAnchorRect(for: annotation)
        let safeRect = sanitizedAnchorRect(anchorRect, page: page, displayBox: pdfView.displayBox, minSize: CGSize(width: 1, height: 1))
        let pointInView = pdfView.convert(safeRect.origin, from: page)
        let context = AnnotationContext(
            viewPointInView: pointInView,
            viewPointInHost: pdfView.convert(pointInView, to: host),
            page: page,
            pagePoint: safeRect.origin,
            selection: nil,
            existingAnnotation: annotation
        )
        presentComposer(context: context)
    }

    private func showAnnotationPopover(for annotation: PDFAnnotation) {
        presentComposer(for: annotation)
    }

    @objc private func handleEditButton(_ sender: NSButton) {
        guard let ann = readOnlyPopoverAnnotation,
              let page = ann.page,
              let pdfView,
              let host = hostView else { return }
        readOnlyPopover?.close()
        readOnlyPopover = nil
        readOnlyPopoverAnnotation = nil
        let pointInView = pdfView.convert(ann.bounds.origin, from: page)
        let context = AnnotationContext(
            viewPointInView: pointInView,
            viewPointInHost: pdfView.convert(pointInView, to: host),
            page: page,
            pagePoint: ann.bounds.origin,
            selection: nil,
            existingAnnotation: ann
        )
        presentComposer(context: context)
    }

    @objc private func handleDeleteButton(_ sender: NSButton) {
        guard let ann = readOnlyPopoverAnnotation,
              let page = ann.page,
              let doc = page.document else { return }
        readOnlyPopover?.close()
        readOnlyPopover = nil
        readOnlyPopoverAnnotation = nil
        removeAnnotation(ann, from: page, reason: "delete_button")
        refreshHighlightRegions(for: [page], reason: "delete_button")
        persistAndReload(document: doc,
                         focusPage: page,
                         refresh: .none,
                         reason: "delete_button",
                         debounce: 0.0)
        NotificationCenter.default.post(name: .arxivPDFAnnotationsDidChange, object: doc)
    }

    func exportAnnotatedPDF() -> URL? {
        guard let pdfView, let doc = pdfView.document else { return nil }
        let focusPage = pdfView.currentPage ?? doc.page(at: 0)
        if let focusPage {
            persistAndReload(document: doc, focusPage: focusPage)
        }
        guard let sourceURL = writableURL(for: doc) else { return nil }
        guard let exportDoc = PDFDocument(url: sourceURL) else { return sourceURL }
        normalizeMarkupAnnotationsForExport(document: exportDoc, sourceDocument: doc)
        let exportURL = sourceURL.deletingLastPathComponent()
            .appendingPathComponent("zotero-export-\(UUID().uuidString)-\(sourceURL.lastPathComponent)")
        let docID = reportingDocumentID(for: doc)
        if exportDoc.write(to: exportURL) {
            reportDocumentIO("pdf_export",
                             documentID: docID,
                             details: ["result": "success"])
            return exportURL
        }
        reportDocumentIO("pdf_export",
                         documentID: docID,
                         severity: .warn,
                         details: ["result": "failed"])
        return sourceURL
    }
}

struct PDFAnnotationListItem: Hashable {
    let stableID: String
    let pageIndex: Int
    let pageLabel: String
    let sortTopOffset: CGFloat
    let sortTimestamp: TimeInterval
    let createdAt: Date?
    let color: NSColor
    let highlightText: String
    let commentText: String
    let commentRichTextPayload: String?
    let page: PDFPage
    let anchorBounds: CGRect
    let highlightAnnotations: [PDFAnnotation]
    let noteAnnotations: [PDFAnnotation]

    func hash(into hasher: inout Hasher) {
        hasher.combine(stableID)
        hasher.combine(pageIndex)
    }

    static func == (lhs: PDFAnnotationListItem, rhs: PDFAnnotationListItem) -> Bool {
        lhs.stableID == rhs.stableID && lhs.pageIndex == rhs.pageIndex
    }
}

struct PDFAnnotationGroupKey: Hashable {
    let id: String
    let pageIndex: Int
}

struct PDFAnnotationGroup {
    let key: PDFAnnotationGroupKey
    let page: PDFPage
    var highlights: [PDFAnnotation] = []
    var notes: [PDFAnnotation] = []
}

let annotationPreviewMaxLength = 160
let annotationListSortStabilityEpsilon: CGFloat = 12.0
let annotationListAnchorStabilityEpsilon: CGFloat = 12.0
let annotationModificationDateKey = PDFAnnotationKey(rawValue: "ModDate")
let annotationCreationDateKey = PDFAnnotationKey(rawValue: "CreationDate")

func annotationGroupID(for annotation: PDFAnnotation) -> String? {
    if let gid = annotation.value(forAnnotationKey: annotationNoteGroupKey) as? String,
       !gid.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
        return gid
    }
    return nil
}

func annotationIsArxivOwned(_ annotation: PDFAnnotation) -> Bool {
    if annotationGroupID(for: annotation) != nil { return true }
    if annotation.value(forAnnotationKey: annotationStoredQuadPointsKey) != nil { return true }
    if annotation.value(forAnnotationKey: annotationRichTextKey) != nil { return true }
    if annotation.value(forAnnotationKey: annotationPageLabelOverrideKey) != nil { return true }
    return false
}

func safeRoundedInt(_ value: CGFloat) -> Int {
    guard value.isFinite else { return 0 }
    let rounded = value.rounded()
    if rounded > CGFloat(Int.max) { return Int.max }
    if rounded < CGFloat(Int.min) { return Int.min }
    return Int(rounded)
}

func annotationStableKey(_ annotation: PDFAnnotation, pageIndex: Int) -> String {
    let bounds = annotation.bounds
    let parts: [String] = [
        String(pageIndex),
        annotation.type ?? "unknown",
        String(safeRoundedInt(bounds.origin.x)),
        String(safeRoundedInt(bounds.origin.y)),
        String(safeRoundedInt(bounds.size.width)),
        String(safeRoundedInt(bounds.size.height))
    ]
    return parts.joined(separator: "|")
}

func parsePDFDateString(_ raw: String) -> Date? {
    let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !trimmed.isEmpty else { return nil }
    var source = trimmed
    if source.hasPrefix("D:") {
        source = String(source.dropFirst(2))
    }

    var index = source.startIndex
    func readDigits(_ count: Int, from idx: inout String.Index) -> Int? {
        var temp = idx
        var value = 0
        for _ in 0..<count {
            guard temp < source.endIndex else { return nil }
            let ch = source[temp]
            guard ch >= "0" && ch <= "9" else { return nil }
            value = value * 10 + Int(String(ch))!
            temp = source.index(after: temp)
        }
        idx = temp
        return value
    }

    guard let year = readDigits(4, from: &index) else { return nil }
    var month: Int? = readDigits(2, from: &index)
    var day: Int?
    var hour: Int?
    var minute: Int?
    var second: Int?
    if month != nil {
        day = readDigits(2, from: &index)
        if day != nil {
            hour = readDigits(2, from: &index)
            if hour != nil {
                minute = readDigits(2, from: &index)
                if minute != nil {
                    second = readDigits(2, from: &index)
                }
            }
        }
    }

    let resolvedMonth = max(1, min(12, month ?? 1))
    let resolvedDay = max(1, min(31, day ?? 1))
    let resolvedHour = max(0, min(23, hour ?? 0))
    let resolvedMinute = max(0, min(59, minute ?? 0))
    let resolvedSecond = max(0, min(59, second ?? 0))

    var tz: TimeZone? = nil
    var tzIndex = index
    while tzIndex < source.endIndex, source[tzIndex].isWhitespace {
        tzIndex = source.index(after: tzIndex)
    }
    if tzIndex < source.endIndex {
        let tzChar = source[tzIndex]
        if tzChar == "Z" {
            tz = TimeZone(secondsFromGMT: 0)
        } else if tzChar == "+" || tzChar == "-" {
            let sign = (tzChar == "-") ? -1 : 1
            tzIndex = source.index(after: tzIndex)
            if let tzHour = readDigits(2, from: &tzIndex) {
                if tzIndex < source.endIndex, source[tzIndex] == "'" {
                    tzIndex = source.index(after: tzIndex)
                }
                let tzMinute = readDigits(2, from: &tzIndex) ?? 0
                if tzIndex < source.endIndex, source[tzIndex] == "'" {
                    tzIndex = source.index(after: tzIndex)
                }
                let offset = sign * ((tzHour * 3600) + (tzMinute * 60))
                tz = TimeZone(secondsFromGMT: offset)
            }
        }
    }

    var components = DateComponents()
    components.calendar = Calendar(identifier: .gregorian)
    components.timeZone = tz ?? TimeZone.current
    components.year = year
    components.month = resolvedMonth
    components.day = resolvedDay
    components.hour = resolvedHour
    components.minute = resolvedMinute
    components.second = resolvedSecond
    return components.date
}

func annotationDateValue(for annotation: PDFAnnotation, key: PDFAnnotationKey) -> Date? {
    if let date = annotation.value(forAnnotationKey: key) as? Date {
        return date
    }
    if let raw = annotation.value(forAnnotationKey: key) as? String {
        return parsePDFDateString(raw)
    }
    return nil
}

func annotationCreationDateValue(for annotation: PDFAnnotation) -> Date? {
    if let existing = annotationDateValue(for: annotation, key: annotationCreationDateKey) {
        return existing
    }
    if let fallback = annotationModificationDateValue(for: annotation) ?? annotation.modificationDate {
        annotation.setValue(fallback, forAnnotationKey: annotationCreationDateKey)
        return fallback
    }
    let now = Date()
    annotation.setValue(now, forAnnotationKey: annotationCreationDateKey)
    return now
}

func annotationModificationDateValue(for annotation: PDFAnnotation) -> Date? {
    annotationDateValue(for: annotation, key: annotationModificationDateKey)
}

func annotationResolvedCreationDate(for annotation: PDFAnnotation) -> Date? {
    annotationCreationDateValue(for: annotation) ?? annotationModificationDateValue(for: annotation)
}

func annotationSortTimestamp(_ annotation: PDFAnnotation) -> TimeInterval {
    if let date = annotationModificationDateValue(for: annotation) {
        return date.timeIntervalSinceReferenceDate
    }
    if let date = annotationCreationDateValue(for: annotation) {
        return date.timeIntervalSinceReferenceDate
    }
    return 0
}

func annotationCreationDateString(_ date: Date) -> String {
    let calendar = Calendar.current
    let components = calendar.dateComponents([.month, .day, .year], from: date)
    let monthIndex = max(1, min(12, components.month ?? 1)) - 1
    let months = ["Jan.", "Feb.", "Mar.", "Apr.", "May", "Jun.", "Jul.", "Aug.", "Sep.", "Oct.", "Nov.", "Dec."]
    let month = months[monthIndex]
    let day = max(1, min(31, components.day ?? 1))
    let year = components.year ?? 0
    let suffix: String = {
        let mod100 = day % 100
        if mod100 >= 11 && mod100 <= 13 { return "th" }
        switch day % 10 {
        case 1: return "st"
        case 2: return "nd"
        case 3: return "rd"
        default: return "th"
        }
    }()
    return "\(month) \(day)\(suffix), \(year)"
}

let annotationTimeFormatter: DateFormatter = {
    let formatter = DateFormatter()
    formatter.locale = Locale(identifier: "en_US_POSIX")
    formatter.dateFormat = "h:mm a"
    formatter.amSymbol = "am"
    formatter.pmSymbol = "pm"
    return formatter
}()

func annotationCreationTimeString(_ date: Date) -> String {
    annotationTimeFormatter.string(from: date)
}

let pdfHighlightSubtypeNames: Set<String> = [
    "highlight",
    "underline",
    "strikeout",
    "squiggly"
]

func annotationTypeName(_ annotation: PDFAnnotation) -> String {
    let raw = annotation.type?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() ?? ""
    if raw.hasPrefix("/") {
        return String(raw.dropFirst())
    }
    return raw
}

func annotationMarkupStyle(for annotation: PDFAnnotation) -> AnnotationMarkupStyle {
    if let raw = annotation.value(forAnnotationKey: annotationMarkupStyleKey) as? String,
       let style = AnnotationMarkupStyle(rawValue: raw.lowercased()) {
        return style
    }
    let typeName = annotationTypeName(annotation)
    if (annotation.value(forAnnotationKey: annotationOverlayHighlightKey) as? Bool) == true {
        return .highlight
    }
    if typeName == "underline" {
        let alpha = annotation.color.alphaComponent
        let ca = (annotation.value(forAnnotationKey: PDFAnnotationKey(rawValue: "CA")) as? NSNumber)?.doubleValue ?? 1.0
        if alpha <= 0.01 && ca <= 0.01 {
            return .highlight
        }
        return .underline
    }
    if typeName == "highlight" {
        let alpha = annotation.color.alphaComponent
        let ca = (annotation.value(forAnnotationKey: PDFAnnotationKey(rawValue: "CA")) as? NSNumber)?.doubleValue ?? 1.0
        let interior = annotation.value(forAnnotationKey: .interiorColor) as? NSColor
        if alpha <= 0.01 && ca <= 0.01 && interior == nil {
            return .underline
        }
    }
    return .highlight
}

func annotationSubtype(for style: AnnotationMarkupStyle) -> PDFAnnotationSubtype {
    switch style {
    case .underline:
        return .underline
    case .highlight:
        return .highlight
    }
}

func annotationStoredBaseColor(for annotation: PDFAnnotation) -> NSColor? {
    annotation.value(forAnnotationKey: annotationMarkupColorKey) as? NSColor
}

func annotationDisplayBaseColor(for annotation: PDFAnnotation) -> NSColor {
    if let stored = annotationStoredBaseColor(for: annotation) {
        return stored
    }
    let color = annotation.color
    if color.alphaComponent > 0.01 {
        return color
    }
    return .systemYellow
}

func annotationIsHighlightLike(_ annotation: PDFAnnotation) -> Bool {
    if annotationIsTextNote(annotation) { return false }
    let type = annotationTypeName(annotation)
    if pdfHighlightSubtypeNames.contains(type) {
        return true
    }
    if !annotationQuadPoints(for: annotation).isEmpty { return true }
    return false
}

func annotationIsTextNote(_ annotation: PDFAnnotation) -> Bool {
    annotationTypeName(annotation) == "text"
}

func rectIsFinite(_ rect: CGRect) -> Bool {
    rect.origin.x.isFinite
        && rect.origin.y.isFinite
        && rect.size.width.isFinite
        && rect.size.height.isFinite
}

func rectIsUsable(_ rect: CGRect) -> Bool {
    rectIsFinite(rect) && rect.width > 0 && rect.height > 0
}

func safePageBounds(_ page: PDFPage, displayBox: PDFDisplayBox = .cropBox) -> CGRect? {
    let bounds = page.bounds(for: displayBox)
    guard rectIsFinite(bounds), bounds.width > 0, bounds.height > 0 else { return nil }
    return bounds
}

func clampedRect(_ rect: CGRect, within bounds: CGRect?, minSize: CGSize) -> CGRect {
    let minWidth = max(1, minSize.width.isFinite ? minSize.width : 1)
    let minHeight = max(1, minSize.height.isFinite ? minSize.height : 1)
    guard let bounds, rectIsFinite(bounds), bounds.width > 0, bounds.height > 0 else {
        let width = max(minWidth, rect.width.isFinite ? rect.width : minWidth)
        let height = max(minHeight, rect.height.isFinite ? rect.height : minHeight)
        let originX = rect.origin.x.isFinite ? rect.origin.x : 0
        let originY = rect.origin.y.isFinite ? rect.origin.y : 0
        return CGRect(x: originX, y: originY, width: width, height: height)
    }

    let widthCandidate = (rect.width.isFinite && rect.width > 0) ? rect.width : minWidth
    let heightCandidate = (rect.height.isFinite && rect.height > 0) ? rect.height : minHeight
    let width = min(max(widthCandidate, minWidth), bounds.width)
    let height = min(max(heightCandidate, minHeight), bounds.height)
    var x = rect.origin.x.isFinite ? rect.origin.x : bounds.minX
    var y = rect.origin.y.isFinite ? rect.origin.y : bounds.minY
    x = min(max(bounds.minX, x), bounds.maxX - width)
    y = min(max(bounds.minY, y), bounds.maxY - height)
    return CGRect(x: x, y: y, width: width, height: height)
}

func defaultAnchorRect(on page: PDFPage,
                               displayBox: PDFDisplayBox = .cropBox,
                               size: CGSize) -> CGRect {
    let targetWidth = max(1, size.width.isFinite ? size.width : 1)
    let targetHeight = max(1, size.height.isFinite ? size.height : 1)
    guard let bounds = safePageBounds(page, displayBox: displayBox) else {
        return CGRect(x: 0, y: 0, width: targetWidth, height: targetHeight)
    }
    let width = min(targetWidth, bounds.width)
    let height = min(targetHeight, bounds.height)
    let insetX = min(max(12, width * 0.8), max(12, bounds.width * 0.2))
    let insetY = min(max(12, height * 0.8), max(12, bounds.height * 0.2))
    let originX = bounds.minX + insetX
    let originY = bounds.maxY - insetY - height
    return CGRect(x: originX, y: originY, width: width, height: height)
}

func sanitizedAnchorRect(_ rect: CGRect,
                                 page: PDFPage,
                                 displayBox: PDFDisplayBox = .cropBox,
                                 minSize: CGSize) -> CGRect {
    let fallback = defaultAnchorRect(on: page, displayBox: displayBox, size: minSize)
    let candidate = rectIsUsable(rect) ? rect : fallback
    return clampedRect(candidate, within: safePageBounds(page, displayBox: displayBox), minSize: minSize)
}

func quadPointsFromNumberList(_ numbers: [NSNumber]) -> [NSValue] {
    guard numbers.count >= 2 else { return [] }
    var points: [NSValue] = []
    points.reserveCapacity(numbers.count / 2)
    var idx = 0
    while idx + 1 < numbers.count {
        let x = CGFloat(truncating: numbers[idx])
        let y = CGFloat(truncating: numbers[idx + 1])
        points.append(NSValue(point: CGPoint(x: x, y: y)))
        idx += 2
    }
    return points
}

func storedQuadPointsFromValue(_ value: Any?) -> [NSValue]? {
    if let points = value as? [NSValue], !points.isEmpty { return points }
    if let numbers = value as? [NSNumber], !numbers.isEmpty {
        let points = quadPointsFromNumberList(numbers)
        return points.isEmpty ? nil : points
    }
    if let any = value as? [Any], !any.isEmpty {
        let points = any.compactMap { $0 as? NSValue }
        if !points.isEmpty { return points }
        let numbers = any.compactMap { $0 as? NSNumber }
        let converted = quadPointsFromNumberList(numbers)
        return converted.isEmpty ? nil : converted
    }
    return nil
}

// Root cause (Failure Mode 3): PDFKit can yield quad points in annotation-local coordinates.
// Using them as page coords caused overlay/hit regions to render a second "ghost" mark.
// Normalize to page coordinates before rendering/caching to guarantee one-annotation-one-render.
func normalizeQuadPoints(_ points: [NSValue], for annotation: PDFAnnotation) -> [NSValue] {
    guard !points.isEmpty else { return points }
    let bounds = annotation.bounds
    guard rectIsFinite(bounds), bounds.width > 0, bounds.height > 0 else { return points }
    let xs = points.map { $0.pointValue.x }
    let ys = points.map { $0.pointValue.y }
    let minX = xs.min() ?? 0
    let maxX = xs.max() ?? 0
    let minY = ys.min() ?? 0
    let maxY = ys.max() ?? 0
    let epsilon: CGFloat = 1.0
    let unionRect = CGRect(x: minX, y: minY, width: max(0, maxX - minX), height: max(0, maxY - minY))
    if !rectIsFinite(unionRect) || unionRect.width <= 0 || unionRect.height <= 0 {
        return points
    }
    let shiftedRect = unionRect.offsetBy(dx: bounds.minX, dy: bounds.minY)
    let pageBounds = annotation.page?.bounds(for: .cropBox)

    func rectDistanceToBounds(_ rect: CGRect) -> CGFloat {
        abs(rect.minX - bounds.minX)
        + abs(rect.minY - bounds.minY)
        + abs(rect.width - bounds.width)
        + abs(rect.height - bounds.height)
    }

    let unionMatchesBounds = rectDistanceToBounds(unionRect) <= (epsilon * 2)
    let shiftedMatchesBounds = rectDistanceToBounds(shiftedRect) <= (epsilon * 2)
    if unionMatchesBounds && !shiftedMatchesBounds { return points }
    if shiftedMatchesBounds && !unionMatchesBounds {
        let dx = bounds.minX
        let dy = bounds.minY
        return points.map { value in
            let pt = value.pointValue
            return NSValue(point: CGPoint(x: pt.x + dx, y: pt.y + dy))
        }
    }

    let unionInPage = pageBounds.map { $0.intersects(unionRect) } ?? true
    let shiftedInPage = pageBounds.map { $0.intersects(shiftedRect) } ?? true
    if unionInPage && !shiftedInPage { return points }
    if shiftedInPage && !unionInPage {
        let dx = bounds.minX
        let dy = bounds.minY
        return points.map { value in
            let pt = value.pointValue
            return NSValue(point: CGPoint(x: pt.x + dx, y: pt.y + dy))
        }
    }

    let unionScore = rectDistanceToBounds(unionRect)
    let shiftedScore = rectDistanceToBounds(shiftedRect)
    guard shiftedScore + epsilon < unionScore else { return points }
    let dx = bounds.minX
    let dy = bounds.minY
    let normalized = points.map { value in
        let pt = value.pointValue
        return NSValue(point: CGPoint(x: pt.x + dx, y: pt.y + dy))
    }
    if annotationDebugEnabled {
        let id = Unmanaged.passUnretained(annotation).toOpaque()
        let debugID = String(format: "0x%016llx", UInt64(UInt(bitPattern: id)))
        annotationLog("[ANN_QUAD_NORMALIZE] id=\(debugID) bounds=\(NSStringFromRect(bounds)) dx=\(String(format: "%.2f", dx)) dy=\(String(format: "%.2f", dy)) count=\(points.count)")
    }
    return normalized
}

func localQuadPoints(from pagePoints: [NSValue], for annotation: PDFAnnotation) -> [NSValue] {
    guard !pagePoints.isEmpty else { return [] }
    let bounds = annotation.bounds
    guard rectIsFinite(bounds), bounds.width > 0, bounds.height > 0 else { return [] }
    let epsilon: CGFloat = 1.0
    let localPoints = pagePoints.map { value in
        let pt = value.pointValue
        return NSValue(point: CGPoint(x: pt.x - bounds.minX, y: pt.y - bounds.minY))
    }
    let xs = localPoints.map { $0.pointValue.x }
    let ys = localPoints.map { $0.pointValue.y }
    let minX = xs.min() ?? 0
    let maxX = xs.max() ?? 0
    let minY = ys.min() ?? 0
    let maxY = ys.max() ?? 0
    let fitsBounds = minX >= -epsilon
        && minY >= -epsilon
        && maxX <= bounds.width + epsilon
        && maxY <= bounds.height + epsilon
    guard fitsBounds else { return [] }
    return localPoints
}

func annotationQuadPoints(for annotation: PDFAnnotation) -> [NSValue] {
    if let storedValue = annotation.value(forAnnotationKey: annotationStoredQuadPointsKey),
       let stored = storedQuadPointsFromValue(storedValue),
       !stored.isEmpty {
        return normalizeQuadPoints(stored, for: annotation)
    }
    if let quadPoints = annotation.quadrilateralPoints, !quadPoints.isEmpty {
        return normalizeQuadPoints(quadPoints, for: annotation)
    }
    return []
}

func storeQuadPoints(_ points: [NSValue], on annotation: PDFAnnotation) {
    let normalized = normalizeQuadPoints(points, for: annotation)
    if !normalized.isEmpty {
        let local = localQuadPoints(from: normalized, for: annotation)
        annotation.quadrilateralPoints = local.isEmpty ? normalized : local
    }
    // Store in a PDF-safe format (flat number array) to avoid invalid value errors on write.
    let numbers: [NSNumber] = normalized.flatMap { value in
        let pt = value.pointValue
        return [NSNumber(value: Double(pt.x)), NSNumber(value: Double(pt.y))]
    }
    if !numbers.isEmpty {
        annotation.setValue(numbers, forAnnotationKey: annotationStoredQuadPointsKey)
    }
}

func storeGroupQuadPoints(_ points: [NSValue], on annotation: PDFAnnotation) {
    // Store page-coordinate quad points without touching the annotation's geometry.
    guard !points.isEmpty else { return }
    let numbers: [NSNumber] = points.flatMap { value in
        let pt = value.pointValue
        return [NSNumber(value: Double(pt.x)), NSNumber(value: Double(pt.y))]
    }
    guard !numbers.isEmpty else { return }
    annotation.setValue(numbers, forAnnotationKey: annotationGroupQuadPointsKey)
}

func restoreStoredQuadPoints(_ value: Any?, on annotation: PDFAnnotation) {
    guard let value, let points = storedQuadPointsFromValue(value), !points.isEmpty else { return }
    storeQuadPoints(points, on: annotation)
}

func annotationQuadRects(for annotation: PDFAnnotation) -> [CGRect] {
    func rectsFromPoints(_ points: [NSValue]) -> [CGRect] {
        guard points.count >= 4 else { return [] }
        var rects: [CGRect] = []
        var idx = 0
        while idx + 3 < points.count {
            let pts = [
                points[idx].pointValue,
                points[idx + 1].pointValue,
                points[idx + 2].pointValue,
                points[idx + 3].pointValue
            ]
            let xs = pts.map { $0.x }
            let ys = pts.map { $0.y }
            let minX = xs.min() ?? 0
            let maxX = xs.max() ?? 0
            let minY = ys.min() ?? 0
            let maxY = ys.max() ?? 0
            let rect = CGRect(x: minX, y: minY, width: max(0, maxX - minX), height: max(0, maxY - minY))
            if rect.width > 0 && rect.height > 0 && rectIsFinite(rect) {
                rects.append(rect)
            }
            idx += 4
        }
        return rects
    }

    let points = annotationQuadPoints(for: annotation)
    if points.count >= 4 {
        let rects = rectsFromPoints(points)
        if !rects.isEmpty { return rects }
    }

    let bounds = annotation.bounds
    if bounds.width > 0 && bounds.height > 0 && rectIsFinite(bounds) {
        return [bounds]
    }
    return []
}

func normalizedAnnotationText(_ text: String) -> String {
    let parts = text.split { $0.isWhitespace || $0.isNewline }
    return parts.joined(separator: " ")
}

func truncatedAnnotationText(_ text: String, maxLength: Int) -> String {
    guard text.count > maxLength else { return text }
    let end = text.index(text.startIndex, offsetBy: maxLength)
    return String(text[..<end]) + "..."
}

func selectionTextForMatch(_ selection: PDFSelection) -> String {
    normalizedAnnotationText(selection.string ?? "").lowercased()
}

func annotationTextForMatch(_ annotation: PDFAnnotation, page: PDFPage) -> String {
    if let contents = annotation.contents?.trimmingCharacters(in: .whitespacesAndNewlines),
       !contents.isEmpty {
        return normalizedAnnotationText(contents).lowercased()
    }
    return normalizedAnnotationText(annotationPreviewText(for: annotation, page: page)).lowercased()
}

func selectionMatchesAnnotationText(_ selectionText: String,
                                            annotation: PDFAnnotation,
                                            page: PDFPage) -> Bool {
    guard !selectionText.isEmpty else { return false }
    let annText = annotationTextForMatch(annotation, page: page)
    guard !annText.isEmpty else { return false }
    return annText.contains(selectionText) || selectionText.contains(annText)
}

func annotationRichTextPayload(for annotation: PDFAnnotation) -> String? {
    if let payload = annotation.value(forAnnotationKey: annotationRichTextKey) as? String {
        let trimmed = payload.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty { return nil }
        // Treat payloads that are effectively plain text as nil so click-to-open
        // does not trigger a spurious "dirty" submit that can mutate highlights.
        if let decoded = decodeAnnotationRichTextPayload(trimmed) {
            let fallbackFont = PDFAnnotationRowMetrics.commentFont
            let baseFont: NSFont = {
                if let name = decoded.baseFontName,
                   let size = decoded.baseFontSize,
                   let font = NSFont(name: name, size: CGFloat(size)) {
                    return font
                }
                return fallbackFont
            }()
            let baseColor: NSColor = {
                if let hex = decoded.baseColorHex,
                   let color = colorFromHex(hex) {
                    return color
                }
                // Default text should inherit the shared semantic foreground token.
                return annotationDefaultForegroundColor()
            }()
            if !attributedStringHasFormatting(decoded.attributed,
                                              baseFont: baseFont,
                                              baseColor: baseColor) {
                return nil
            }
        }
        return trimmed
    }
    return nil
}

func annotationCommentPlainText(for annotation: PDFAnnotation) -> String {
    if let contents = annotation.contents?.trimmingCharacters(in: .whitespacesAndNewlines),
       !contents.isEmpty {
        return contents
    }
    if let popup = annotation.popup,
       let popupContents = popup.contents?.trimmingCharacters(in: .whitespacesAndNewlines),
       !popupContents.isEmpty {
        return popupContents
    }
    if let textLabel = annotation.value(forAnnotationKey: PDFAnnotationKey.textLabel) as? String {
        let trimmed = textLabel.trimmingCharacters(in: .whitespacesAndNewlines)
        if !trimmed.isEmpty { return trimmed }
    }
    return ""
}

func annotationCommentText(for annotation: PDFAnnotation) -> String {
    let plain = annotationCommentPlainText(for: annotation)
    if !plain.isEmpty { return plain }
    if let rich = annotationRichTextPayload(for: annotation),
       let decoded = decodeAnnotationRichTextPayload(rich) {
        let fallback = decoded.attributed.string.trimmingCharacters(in: .whitespacesAndNewlines)
        if !fallback.isEmpty { return fallback }
    }
    return ""
}

func annotationCommentPayload(for annotation: PDFAnnotation) -> AnnotationCommentContent {
    AnnotationCommentContent(plainText: annotationCommentText(for: annotation),
                             richTextPayload: annotationRichTextPayload(for: annotation))
}

func applyAnnotationContent(_ content: AnnotationCommentContent, to annotation: PDFAnnotation) {
    let normalized = content.normalizedForStorage()
    annotation.contents = normalized.plainText
    applyAnnotationRichText(content: normalized, to: annotation)
}

func applyAnnotationRichText(content: AnnotationCommentContent, to annotation: PDFAnnotation) {
    if let payload = content.richTextPayload,
       !payload.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
        annotation.setValue(payload, forAnnotationKey: annotationRichTextKey)
    } else {
        annotation.removeValue(forAnnotationKey: annotationRichTextKey)
    }
}

func annotationPageLabelOverride(for annotations: [PDFAnnotation]) -> String? {
    for annotation in annotations {
        if let raw = annotation.value(forAnnotationKey: annotationPageLabelOverrideKey) as? String {
            let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty { return trimmed }
        }
    }
    return nil
}

func annotationPreviewText(for annotation: PDFAnnotation, page: PDFPage) -> String {
    let previewStart = annotationTimingEnabled ? CACurrentMediaTime() : 0
    let rects = annotationQuadRects(for: annotation).sorted { a, b in
        let dy = a.maxY - b.maxY
        if abs(dy) > 1 { return dy > 0 }
        return a.minX < b.minX
    }
    defer {
        if annotationTimingEnabled {
            let ms = (CACurrentMediaTime() - previewStart) * 1000.0
            annotationTimingLog("preview_text ms=\(String(format: "%.2f", ms)) rects=\(rects.count)")
        }
    }
    let paddedRects = rects.isEmpty
        ? [annotation.bounds]
        : rects.map { $0.insetBy(dx: -1.5, dy: -1.5) }
    var parts: [String] = []
    for rect in paddedRects {
        guard rect.width > 0, rect.height > 0, rectIsFinite(rect) else { continue }
        if let sel = page.selection(for: rect),
           let raw = sel.string?.trimmingCharacters(in: .whitespacesAndNewlines),
           !raw.isEmpty {
            parts.append(raw)
        }
    }
    if parts.isEmpty, let first = paddedRects.first {
        guard first.width > 0, first.height > 0, rectIsFinite(first) else {
            return annotation.contents.map { normalizedAnnotationText($0) } ?? ""
        }
        let union = paddedRects.dropFirst().reduce(first) { $0.union($1) }
        if union.width > 0, union.height > 0, rectIsFinite(union),
           let sel = page.selection(for: union),
           let raw = sel.string?.trimmingCharacters(in: .whitespacesAndNewlines),
           !raw.isEmpty {
            parts.append(raw)
        }
    }
    if parts.isEmpty, let contents = annotation.contents {
        parts.append(contents)
    }
    return normalizedAnnotationText(parts.joined(separator: " "))
}

func annotationTopOffset(for annotation: PDFAnnotation, page: PDFPage, displayBox: PDFDisplayBox) -> CGFloat {
    let pageBounds = page.bounds(for: displayBox)
    let rects = annotationQuadRects(for: annotation)
    let fallbackMaxY = rectIsFinite(annotation.bounds) ? annotation.bounds.maxY : pageBounds.maxY
    let maxY = rects.map { $0.maxY }.max() ?? fallbackMaxY
    guard maxY.isFinite else { return 0 }
    let clampedMaxY = min(pageBounds.maxY, maxY)
    let offset = pageBounds.maxY - clampedMaxY
    return max(0, offset)
}

func annotationAnchorRect(for annotation: PDFAnnotation) -> CGRect {
    let rects = annotationQuadRects(for: annotation)
    guard let first = rects.first else {
        return rectIsFinite(annotation.bounds) ? annotation.bounds : .zero
    }
    return rects.dropFirst().reduce(first) { $0.union($1) }
}

func annotationRectDistance(_ a: CGRect, _ b: CGRect) -> CGFloat {
    guard rectIsFinite(a), rectIsFinite(b) else { return CGFloat.greatestFiniteMagnitude }
    let dx = max(0, max(a.minX - b.maxX, b.minX - a.maxX))
    let dy = max(0, max(a.minY - b.maxY, b.minY - a.maxY))
    return sqrt(dx * dx + dy * dy)
}

func annotationMatchThreshold(for page: PDFPage, displayBox: PDFDisplayBox) -> CGFloat {
    let bounds = page.bounds(for: displayBox)
    let minDim = min(bounds.width, bounds.height)
    return max(24, minDim * 0.05)
}

final class PDFAnnotationListViewModel {
    private(set) var items: [PDFAnnotationListItem] = []
    var onItemsChanged: (([PDFAnnotationListItem]) -> Void)?

    @discardableResult
    func applyInlineUpdate(groupID: String,
                           pageIndex: Int?,
                           commentText: String? = nil,
                           commentPayload: String? = nil,
                           color: NSColor? = nil,
                           pageLabel: String? = nil) -> Bool {
        guard !items.isEmpty else { return false }
        guard let idx = items.firstIndex(where: { item in
            if item.stableID != groupID { return false }
            if let pageIndex { return item.pageIndex == pageIndex }
            return true
        }) else { return false }

        let current = items[idx]
        let updated = PDFAnnotationListItem(
            stableID: current.stableID,
            pageIndex: current.pageIndex,
            pageLabel: pageLabel ?? current.pageLabel,
            sortTopOffset: current.sortTopOffset,
            sortTimestamp: current.sortTimestamp,
            createdAt: current.createdAt,
            color: color ?? current.color,
            highlightText: current.highlightText,
            commentText: commentText ?? current.commentText,
            commentRichTextPayload: commentPayload ?? current.commentRichTextPayload,
            page: current.page,
            anchorBounds: current.anchorBounds,
            highlightAnnotations: current.highlightAnnotations,
            noteAnnotations: current.noteAnnotations
        )
        items[idx] = updated
        onItemsChanged?(items)
        return true
    }

    func reload(document: PDFDocument?, displayBox: PDFDisplayBox) {
        let timingStart = annotationTimingEnabled ? CACurrentMediaTime() : 0
        guard let document else {
            items = []
            onItemsChanged?(items)
            if annotationTimingEnabled {
                annotationTimingLog("annotations_reload ms=0.00 reason=no_document")
            }
            return
        }

        var mergeCount = 0
        var previousByKey: [PDFAnnotationGroupKey: PDFAnnotationListItem] = [:]
        if !items.isEmpty {
            previousByKey = Dictionary(
                uniqueKeysWithValues: items.map { (PDFAnnotationGroupKey(id: $0.stableID, pageIndex: $0.pageIndex), $0) }
            )
        }

        var groups: [PDFAnnotationGroupKey: PDFAnnotationGroup] = [:]
        for pageIndex in 0..<document.pageCount {
            guard let page = document.page(at: pageIndex) else { continue }
            var ungroupedHighlights: [PDFAnnotation] = []
            var ungroupedNotes: [PDFAnnotation] = []
            var pageGroupKeys: [PDFAnnotationGroupKey] = []

            func addToGroup(_ annotation: PDFAnnotation, groupID: String) {
                let key = PDFAnnotationGroupKey(id: groupID, pageIndex: pageIndex)
                var group = groups[key] ?? PDFAnnotationGroup(key: key, page: page)
                if groups[key] == nil {
                    pageGroupKeys.append(key)
                }
                if annotationIsHighlightLike(annotation) {
                    group.highlights.append(annotation)
                } else {
                    group.notes.append(annotation)
                }
                groups[key] = group
            }

            for annotation in page.annotations {
                let isPreview = (annotation.value(forAnnotationKey: annotationPreviewFlagKey) as? Bool) == true
                    || (annotation.contents?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "") == "preview"
                if isPreview,
                   pdfHighlightSubtypeNames.contains(annotationTypeName(annotation)) {
                    continue
                }
                let isHighlight = annotationIsHighlightLike(annotation)
                let isNote = annotationIsTextNote(annotation)
                if !isHighlight && !isNote { continue }
                if !annotationIsArxivOwned(annotation) { continue }
                if let groupID = annotationGroupID(for: annotation) {
                    addToGroup(annotation, groupID: groupID)
                } else if isHighlight {
                    ungroupedHighlights.append(annotation)
                } else {
                    ungroupedNotes.append(annotation)
                }
            }

            let matchThreshold = annotationMatchThreshold(for: page, displayBox: displayBox)

            func noteGroupCandidates() -> [(key: PDFAnnotationGroupKey, rect: CGRect)] {
                pageGroupKeys.compactMap { key in
                    guard let group = groups[key], let note = group.notes.first else { return nil }
                    guard rectIsUsable(note.bounds) else { return nil }
                    return (key: key, rect: note.bounds)
                }
            }

            func highlightGroupCandidates() -> [(key: PDFAnnotationGroupKey, rect: CGRect)] {
                pageGroupKeys.compactMap { key in
                    guard let group = groups[key], let first = group.highlights.first else { return nil }
                    let rect = annotationAnchorRect(for: first)
                    guard rectIsUsable(rect) else { return nil }
                    return (key: key, rect: rect)
                }
            }

            var remainingHighlights: [PDFAnnotation] = []
            for highlight in ungroupedHighlights {
                let highlightRect = annotationAnchorRect(for: highlight)
                let candidates = noteGroupCandidates()
                if let match = candidates.min(by: { annotationRectDistance(highlightRect, $0.rect) < annotationRectDistance(highlightRect, $1.rect) }),
                   annotationRectDistance(highlightRect, match.rect) <= matchThreshold {
                    var group = groups[match.key] ?? PDFAnnotationGroup(key: match.key, page: page)
                    group.highlights.append(highlight)
                    groups[match.key] = group
                } else {
                    remainingHighlights.append(highlight)
                }
            }
            ungroupedHighlights = remainingHighlights

            var remainingNotes: [PDFAnnotation] = []
            for note in ungroupedNotes {
                let noteRect = note.bounds
                let candidates = highlightGroupCandidates()
                if let match = candidates.min(by: { annotationRectDistance(noteRect, $0.rect) < annotationRectDistance(noteRect, $1.rect) }),
                   annotationRectDistance(noteRect, match.rect) <= matchThreshold {
                    var group = groups[match.key] ?? PDFAnnotationGroup(key: match.key, page: page)
                    group.notes.append(note)
                    groups[match.key] = group
                } else {
                    remainingNotes.append(note)
                }
            }
            ungroupedNotes = remainingNotes

            if !ungroupedHighlights.isEmpty && !ungroupedNotes.isEmpty {
                var unmatchedHighlights: [PDFAnnotation] = []
                var usedNoteIndices: Set<Int> = []
                for highlight in ungroupedHighlights {
                    let highlightRect = annotationAnchorRect(for: highlight)
                    var bestIndex: Int?
                    var bestDistance = CGFloat.greatestFiniteMagnitude
                    for (idx, note) in ungroupedNotes.enumerated() {
                        guard !usedNoteIndices.contains(idx) else { continue }
                        let distance = annotationRectDistance(highlightRect, note.bounds)
                        if distance < bestDistance {
                            bestDistance = distance
                            bestIndex = idx
                        }
                    }
                    if let idx = bestIndex, bestDistance <= matchThreshold {
                        let note = ungroupedNotes[idx]
                        let pairID = "paired|\(annotationStableKey(highlight, pageIndex: pageIndex))|\(annotationStableKey(note, pageIndex: pageIndex))"
                        addToGroup(highlight, groupID: pairID)
                        addToGroup(note, groupID: pairID)
                        usedNoteIndices.insert(idx)
                        mergeCount += 1
                    } else {
                        unmatchedHighlights.append(highlight)
                    }
                }
                ungroupedHighlights = unmatchedHighlights
                ungroupedNotes = ungroupedNotes.enumerated()
                    .filter { !usedNoteIndices.contains($0.offset) }
                    .map { $0.element }
            }

            for highlight in ungroupedHighlights {
                let syntheticID = "synthetic-h|\(annotationStableKey(highlight, pageIndex: pageIndex))"
                addToGroup(highlight, groupID: syntheticID)
            }
            for note in ungroupedNotes {
                let syntheticID = "synthetic-n|\(annotationStableKey(note, pageIndex: pageIndex))"
                addToGroup(note, groupID: syntheticID)
            }
        }

        var nextItems: [PDFAnnotationListItem] = []
        nextItems.reserveCapacity(groups.count)

        for group in groups.values {
            let page = group.page
            let overrideLabel = annotationPageLabelOverride(for: group.notes)
                ?? annotationPageLabelOverride(for: group.highlights)
            let rawLabel = (overrideLabel ?? page.label?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "")
            let pageLabel = rawLabel.isEmpty ? String(group.key.pageIndex + 1) : rawLabel
            let highlightsSorted = group.highlights.sorted { a, b in
                let ay = annotationTopOffset(for: a, page: page, displayBox: displayBox)
                let by = annotationTopOffset(for: b, page: page, displayBox: displayBox)
                if ay != by { return ay < by }
                return annotationStableKey(a, pageIndex: group.key.pageIndex) < annotationStableKey(b, pageIndex: group.key.pageIndex)
            }
            let highlightTextRaw = highlightsSorted
                .map { annotationPreviewText(for: $0, page: page) }
                .joined(separator: " ")
            let highlightText = truncatedAnnotationText(
                normalizedAnnotationText(highlightTextRaw),
                maxLength: annotationPreviewMaxLength
            )

            let notePayloads: [(note: PDFAnnotation, payload: AnnotationCommentContent)] = group.notes.map {
                (note: $0, payload: annotationCommentPayload(for: $0))
            }
            let noteWithComment = notePayloads.first(where: {
                !$0.payload.trimmedPlainText.isEmpty || $0.payload.richTextPayload != nil
            })
            let noteAnnotation = noteWithComment?.note ?? notePayloads.first?.note
            let commentPayload = noteWithComment?.payload
                ?? notePayloads.first?.payload
                ?? AnnotationCommentContent(plainText: "", richTextPayload: nil)
            let commentText = commentPayload.trimmedPlainText
            let commentRichPayload = commentPayload.richTextPayload

            let createdCandidates = (group.notes + group.highlights).compactMap { annotationCreationDateValue(for: $0) }
            let createdAt = createdCandidates.sorted().first

            let anchor = noteAnnotation ?? highlightsSorted.first ?? group.notes.first
            let rawAnchorBounds = anchor?.bounds ?? .zero
            var anchorBounds = sanitizedAnchorRect(rawAnchorBounds,
                                                  page: page,
                                                  displayBox: displayBox,
                                                  minSize: CGSize(width: 1, height: 1))

            let color = (highlightsSorted.first?.color ?? noteAnnotation?.color ?? NSColor.systemYellow)
            let anchorForSort = highlightsSorted.first ?? noteAnnotation ?? group.notes.first
            var sortTop = anchorForSort.map {
                annotationTopOffset(for: $0, page: page, displayBox: displayBox)
            } ?? 0
            let sortTimestamp = (noteAnnotation ?? highlightsSorted.first).map(annotationSortTimestamp) ?? 0
            var highlightTextValue = highlightText

            if let previous = previousByKey[group.key] {
                if !previous.highlightText.isEmpty,
                   highlightTextValue.isEmpty,
                   !highlightsSorted.isEmpty,
                   !previous.highlightAnnotations.isEmpty {
                    highlightTextValue = previous.highlightText
                }
                let priorBounds = previous.anchorBounds
                let hasPriorBounds = rectIsUsable(priorBounds)
                let hasCurrentBounds = rectIsUsable(anchorBounds)
                let anchorDelta = (hasPriorBounds && hasCurrentBounds)
                    ? annotationRectDistance(anchorBounds, priorBounds)
                    : CGFloat.greatestFiniteMagnitude
                if anchorDelta < annotationListAnchorStabilityEpsilon,
                   !previous.highlightText.isEmpty {
                    highlightTextValue = previous.highlightText
                }
                if abs(sortTop - previous.sortTopOffset) < annotationListSortStabilityEpsilon
                    || anchorDelta < annotationListAnchorStabilityEpsilon {
                    sortTop = previous.sortTopOffset
                    if hasPriorBounds {
                        anchorBounds = priorBounds
                    }
                }
            }

            let item = PDFAnnotationListItem(
                stableID: group.key.id,
                pageIndex: group.key.pageIndex,
                pageLabel: "Page \(pageLabel)",
                sortTopOffset: sortTop,
                sortTimestamp: sortTimestamp,
                createdAt: createdAt,
                color: color,
                highlightText: highlightTextValue,
                commentText: commentText,
                commentRichTextPayload: commentRichPayload,
                page: page,
                anchorBounds: anchorBounds,
                highlightAnnotations: highlightsSorted,
                noteAnnotations: group.notes
            )
            nextItems.append(item)
        }

        nextItems.sort { lhs, rhs in
            if lhs.pageIndex != rhs.pageIndex { return lhs.pageIndex < rhs.pageIndex }
            if lhs.sortTopOffset != rhs.sortTopOffset { return lhs.sortTopOffset < rhs.sortTopOffset }
            let lx = lhs.anchorBounds.minX
            let rx = rhs.anchorBounds.minX
            if lx != rx { return lx < rx }
            return lhs.stableID < rhs.stableID
        }

        items = nextItems
        onItemsChanged?(items)
        if annotationDebugEnabled {
            annotationLog("[ANN_LIST_REPLACE] items=\(nextItems.count) groups=\(groups.count) merges=\(mergeCount)")
        }
        if annotationTimingEnabled {
            let ms = (CACurrentMediaTime() - timingStart) * 1000.0
            annotationTimingLog("annotations_reload ms=\(String(format: "%.2f", ms)) groups=\(nextItems.count) pages=\(document.pageCount)")
        }
    }
}

struct PDFAnnotationRowMetrics {
    static let rowInsetX: CGFloat = 6
    static let rowInsetY: CGFloat = 4
    static let cardContractInsetX: CGFloat = 8
    static let cardInsetX: CGFloat = 10
    static let cardInsetY: CGFloat = 8
    static let barWidth: CGFloat = 3
    static let barGap: CGFloat = 8
    static let labelGap: CGFloat = 6
    static let previewGap: CGFloat = 6
    static let previewMaxLines: Int = 3
    static let cornerRadius: CGFloat = 6
    static let menuButtonSize: CGFloat = 16
    static let menuButtonInsetX: CGFloat = 8
    static let menuButtonInsetY: CGFloat = 6
    static let menuButtonGap: CGFloat = 6
    static let metaHorizontalGap: CGFloat = 6
    static let textMeasureWidthFudge: CGFloat = 6
    static let textMeasureHeightFudge: CGFloat = 2
    static let commentHeightFudge: CGFloat = 2
    static var pageFont: NSFont {
        let base = resolvedUIFontFromSettings(defaultSize: 11, weight: .semibold)
        return fontByApplyingTrait(base, trait: .boldFontMask)
    }
    static var previewFont: NSFont {
        let base = resolvedUIFontFromSettings(defaultSize: 11.5, weight: .regular)
        return fontByApplyingTrait(base, trait: .italicFontMask)
    }
    static var commentFont: NSFont {
        resolvedUIFontFromSettings(defaultSize: 12.5, weight: .regular)
    }
    static var placeholderFont: NSFont {
        let base = resolvedUIFontFromSettings(defaultSize: 12.5, weight: .regular)
        return fontByApplyingTrait(base, trait: .italicFontMask)
    }
    static var metaFont: NSFont {
        NSFont.systemFont(ofSize: 11, weight: .regular)
    }
    static let metaGap: CGFloat = 4
    static var topMetaHeight: CGFloat {
        let pageHeight = fontLineHeight(pageFont)
        let metaHeight = fontLineHeight(metaFont)
        return max(pageHeight, metaHeight, menuButtonSize)
    }
    static var bottomMetaHeight: CGFloat {
        fontLineHeight(metaFont)
    }
}

func annotationListCardBaseColor() -> NSColor {
    let base = resolvedSystemColor(.textBackgroundColor).usingColorSpace(.deviceRGB)
        ?? resolvedSystemColor(.textBackgroundColor)
    let settings = AppSettingsStore.shared.current.appearance
    guard settings.annotationListGlassEnabled else { return base }
    let strength = max(0.0, min(1.0, CGFloat(settings.annotationListTintStrength)))
    guard strength > 0.0001 else { return base }
    let trimmed = settings.annotationListTintHex.trimmingCharacters(in: .whitespacesAndNewlines)
    let tint: NSColor
    if !trimmed.isEmpty, let color = colorFromHex(trimmed) {
        tint = color.usingColorSpace(.deviceRGB) ?? color
    } else {
        tint = base
    }
    let pair = glassBackgroundPair(base: base, tint: tint.withAlphaComponent(1.0), intensity: strength)
    return pair.alt ?? pair.primary
}

func annotationComposerTintColorSetting() -> NSColor {
    let settings = AppSettingsStore.shared.current.appearance
    let strength = max(0.0, min(1.0, CGFloat(settings.annotationComposerTintStrength)))
    let trimmed = settings.annotationComposerTintHex.trimmingCharacters(in: .whitespacesAndNewlines)
    let base: NSColor
    if !trimmed.isEmpty, let color = colorFromHex(trimmed) {
        base = color.usingColorSpace(.deviceRGB) ?? color
    } else {
        let accent = resolvedAppAccentDisplayColor()
        base = accent.usingColorSpace(.deviceRGB) ?? accent
    }
    let raw = CGFloat(settings.liquidGlassTintStrength)
    let strengthScale = max(0.0, min(2.0, raw.isFinite ? raw : 1.0))
    let accentAlpha = max(0.06, min(0.35, PANEL_CLEAR_GLASS_TINT_ALPHA * max(0.6, strengthScale)))
    let baseAlpha: CGFloat = trimmed.isEmpty ? accentAlpha : PANEL_CLEAR_GLASS_TINT_ALPHA
    let alpha = max(0.0, min(1.0, baseAlpha * strength))
    return NSColor(srgbRed: base.redComponent, green: base.greenComponent, blue: base.blueComponent, alpha: alpha)
}

func annotationComposerEffectiveBackgroundColor() -> NSColor {
    let base = windowBackgroundSolidColor()
    let tint = annotationComposerTintColorSetting()
    let tintRGB = (tint.usingColorSpace(.deviceRGB) ?? tint)
    let alpha = max(0.0, min(1.0, tintRGB.alphaComponent))
    let bias = max(0.3, min(0.85, alpha * 1.4))
    let biasedBase = blend(base, tintRGB.withAlphaComponent(1.0), t: bias)
    let pair = glassBackgroundPair(base: biasedBase, tint: tintRGB, intensity: 1.0)
    return pair.alt ?? pair.primary
}

func annotationComposerPrimaryTextColor() -> NSColor {
    annotationDefaultForegroundColor()
}

func fontLineHeight(_ font: NSFont) -> CGFloat {
    ceil(font.ascender - font.descender + font.leading)
}

struct TextFieldInsets {
    let horizontal: CGFloat
    let vertical: CGFloat
}

struct TextFieldInsetsCache {
    static var cache: [String: TextFieldInsets] = [:]
}

func textFieldInsets(for font: NSFont,
                             lineBreakMode: NSLineBreakMode = .byWordWrapping) -> TextFieldInsets {
    let key = "\(font.fontName)-\(font.pointSize)-\(lineBreakMode.rawValue)"
    if let cached = TextFieldInsetsCache.cache[key] { return cached }

    let cell = NSTextFieldCell(textCell: "M")
    cell.font = font
    cell.lineBreakMode = lineBreakMode
    cell.usesSingleLineMode = false
    cell.wraps = true
    cell.isScrollable = false

    let refHeight = max(ceil(fontLineHeight(font)), 1)
    let bounds = NSRect(x: 0, y: 0, width: 200, height: refHeight)
    let titleRect = cell.titleRect(forBounds: bounds)
    let horizontal = max(0, bounds.width - titleRect.width)
    let vertical = max(0, bounds.height - titleRect.height)
    let insets = TextFieldInsets(horizontal: horizontal, vertical: vertical)
    TextFieldInsetsCache.cache[key] = insets
    return insets
}

func measuredTextHeight(_ text: String,
                                font: NSFont,
                                width: CGFloat,
                                lineBreakMode: NSLineBreakMode = .byWordWrapping) -> CGFloat {
    guard width > 1 else { return fontLineHeight(font) }
    let insets = textFieldInsets(for: font, lineBreakMode: lineBreakMode)
    let adjustedWidth = max(1, width - insets.horizontal - PDFAnnotationRowMetrics.textMeasureWidthFudge)
    let storage = NSTextStorage(string: text)
    let style = NSMutableParagraphStyle()
    style.lineBreakMode = lineBreakMode
    storage.addAttributes([.font: font, .paragraphStyle: style],
                          range: NSRange(location: 0, length: storage.length))

    let container = NSTextContainer(containerSize: NSSize(width: adjustedWidth, height: CGFloat.greatestFiniteMagnitude))
    container.lineFragmentPadding = 0
    container.lineBreakMode = lineBreakMode
    container.maximumNumberOfLines = 0

    let layout = NSLayoutManager()
    layout.addTextContainer(container)
    storage.addLayoutManager(layout)
    layout.glyphRange(for: container)

    let used = layout.usedRect(for: container)
    let minHeight = fontLineHeight(font) + insets.vertical + PDFAnnotationRowMetrics.textMeasureHeightFudge
    let usedHeight = used.height
    if !usedHeight.isFinite { return minHeight }
    let paddedHeight = usedHeight + insets.vertical + PDFAnnotationRowMetrics.textMeasureHeightFudge
    if !paddedHeight.isFinite { return minHeight }
    return max(ceil(paddedHeight), minHeight)
}

func truncatedTextToFit(_ text: String,
                                font: NSFont,
                                width: CGFloat,
                                maxLines: Int) -> String {
    let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !trimmed.isEmpty else { return "" }
    guard width > 1, maxLines > 0 else { return trimmed }

    let insets = textFieldInsets(for: font, lineBreakMode: .byWordWrapping)
    let maxHeight = fontLineHeight(font) * CGFloat(maxLines)
        + insets.vertical
        + PDFAnnotationRowMetrics.textMeasureHeightFudge
    func height(for value: String) -> CGFloat {
        measuredTextHeight(value, font: font, width: width)
    }

    if height(for: trimmed) <= maxHeight + 0.5 {
        return trimmed
    }

    let ellipsis = "..."
    var low = 0
    var high = trimmed.count
    var best = ""
    while low <= high {
        let mid = (low + high) / 2
        let idx = trimmed.index(trimmed.startIndex, offsetBy: mid)
        var candidate = String(trimmed[..<idx])
        candidate = candidate.trimmingCharacters(in: .whitespacesAndNewlines)
        if candidate.isEmpty {
            high = mid - 1
            continue
        }
        let test = candidate + ellipsis
        if height(for: test) <= maxHeight + 0.5 {
            best = test
            low = mid + 1
        } else {
            high = mid - 1
        }
    }
    return best.isEmpty ? ellipsis : best
}

func quotedPreviewTextToFit(_ text: String,
                                    font: NSFont,
                                    width: CGFloat,
                                    maxLines: Int) -> String {
    let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !trimmed.isEmpty else { return "" }
    let quotedFull = "\"\(trimmed)\""
    guard width > 1, maxLines > 0 else { return quotedFull }

    let insets = textFieldInsets(for: font, lineBreakMode: .byWordWrapping)
    let maxHeight = fontLineHeight(font) * CGFloat(maxLines)
        + insets.vertical
        + PDFAnnotationRowMetrics.textMeasureHeightFudge
    func height(for value: String) -> CGFloat {
        measuredTextHeight(value, font: font, width: width)
    }

    if height(for: quotedFull) <= maxHeight + 0.5 {
        return quotedFull
    }

    let ellipsis = "…"
    var low = 0
    var high = trimmed.count
    var best = "\"\(ellipsis)\""
    while low <= high {
        let mid = (low + high) / 2
        let idx = trimmed.index(trimmed.startIndex, offsetBy: mid)
        var candidate = String(trimmed[..<idx])
        candidate = candidate.trimmingCharacters(in: .whitespacesAndNewlines)
        if candidate.isEmpty {
            high = mid - 1
            continue
        }
        let test = "\"\(candidate)\(ellipsis)\""
        if height(for: test) <= maxHeight + 0.5 {
            best = test
            low = mid + 1
        } else {
            high = mid - 1
        }
    }
    return best
}

final class PDFAnnotationRowView: NSTableCellView, NSTextViewDelegate {
    private let cardView = NSView(frame: .zero)
    private let topMetaContainer = NSView(frame: .zero)
    private let bottomMetaContainer = NSView(frame: .zero)
    private let contentContainer = NSView(frame: .zero)
    private let colorBar = NSView(frame: .zero)
    private let pageLabel = NSTextField(labelWithString: "")
    private let noteLabel = NSTextField(labelWithString: "")
    private let previewLabel = NSTextField(labelWithString: "")
    private let textStack = NSStackView()
    private let commentContainer = NSView(frame: .zero)
    private let commentDisplay = AnnotationTextView()
    private let createdDateLabel = NSTextField(labelWithString: "")
    private let createdTimeLabel = NSTextField(labelWithString: "")
    private let menuButton = NSButton(frame: .zero)
    private let commentEditorScroll = NSScrollView(frame: .zero)
    private let commentEditor = AnnotationTextView()

    private var isSelectedRow: Bool = false
    private var isActive: Bool = true
    private var item: PDFAnnotationListItem?
    private var commentTextRaw: String = ""
    private var commentRichTextPayload: String?
    private var isEditingComment = false
    private var commentEditDidFinish = false
    private var commentDisplayIsPlaceholder = false
    private var resolvedCardBackground: NSColor = resolvedSystemColor(.textBackgroundColor)
    private var needsCommentTextRefresh = false
    private var previewHeightConstraint: NSLayoutConstraint?
    private var commentHeightConstraint: NSLayoutConstraint?
    private var topMetaHeightConstraint: NSLayoutConstraint?
    private var bottomMetaHeightConstraint: NSLayoutConstraint?
    var suppressHeightUpdates = false
    var allowsDynamicHeightUpdates = true
    var usesAlignmentReference = true
    weak var horizontalAlignmentReferenceView: NSView?
    var onMenuTapped: ((PDFAnnotationListItem, NSView) -> Void)?
    var onCommitCommentEdit: ((PDFAnnotationListItem, AnnotationCommentContent) -> Void)?
    var onNeedsHeightUpdate: ((PDFAnnotationRowView) -> Void)?

    override init(frame frameRect: NSRect) {
        super.init(frame: frameRect)
        wantsLayer = false

        cardView.wantsLayer = true
        cardView.layer?.cornerRadius = PDFAnnotationRowMetrics.cornerRadius
        cardView.layer?.borderWidth = 1
        cardView.layer?.masksToBounds = true
        addSubview(cardView)

        topMetaContainer.translatesAutoresizingMaskIntoConstraints = false
        bottomMetaContainer.translatesAutoresizingMaskIntoConstraints = false
        contentContainer.translatesAutoresizingMaskIntoConstraints = false
        cardView.addSubview(topMetaContainer)
        cardView.addSubview(bottomMetaContainer)
        cardView.addSubview(contentContainer)

        pageLabel.font = PDFAnnotationRowMetrics.metaFont
        pageLabel.textColor = annotationDefaultForegroundColor()
        pageLabel.lineBreakMode = .byTruncatingTail
        pageLabel.translatesAutoresizingMaskIntoConstraints = false

        noteLabel.font = PDFAnnotationRowMetrics.metaFont
        noteLabel.textColor = annotationDefaultForegroundColor()
        noteLabel.alignment = .right
        noteLabel.lineBreakMode = .byTruncatingTail
        noteLabel.usesSingleLineMode = true
        noteLabel.translatesAutoresizingMaskIntoConstraints = false

        let menuConfig = NSImage.SymbolConfiguration(pointSize: 11, weight: .regular)
        menuButton.image = NSImage(systemSymbolName: "ellipsis", accessibilityDescription: "More")?.withSymbolConfiguration(menuConfig)
        menuButton.imagePosition = .imageOnly
        menuButton.isBordered = false
        menuButton.bezelStyle = .regularSquare
        menuButton.contentTintColor = annotationDefaultForegroundColor()
        menuButton.target = self
        menuButton.action = #selector(menuButtonClicked)
        menuButton.focusRingType = .none
        menuButton.translatesAutoresizingMaskIntoConstraints = false

        let topRightStack = NSStackView(views: [menuButton, noteLabel])
        topRightStack.translatesAutoresizingMaskIntoConstraints = false
        topRightStack.orientation = .horizontal
        topRightStack.alignment = .centerY
        topRightStack.distribution = .fill
        topRightStack.spacing = PDFAnnotationRowMetrics.menuButtonGap
        topMetaContainer.addSubview(pageLabel)
        topMetaContainer.addSubview(topRightStack)

        createdDateLabel.font = PDFAnnotationRowMetrics.metaFont
        createdDateLabel.textColor = annotationDefaultForegroundColor()
        createdDateLabel.alignment = .left
        createdDateLabel.lineBreakMode = .byTruncatingTail
        createdDateLabel.usesSingleLineMode = true
        createdDateLabel.translatesAutoresizingMaskIntoConstraints = false

        createdTimeLabel.font = PDFAnnotationRowMetrics.metaFont
        createdTimeLabel.textColor = annotationDefaultForegroundColor()
        createdTimeLabel.alignment = .right
        createdTimeLabel.lineBreakMode = .byTruncatingTail
        createdTimeLabel.usesSingleLineMode = true
        createdTimeLabel.translatesAutoresizingMaskIntoConstraints = false

        bottomMetaContainer.addSubview(createdDateLabel)
        bottomMetaContainer.addSubview(createdTimeLabel)

        colorBar.wantsLayer = true
        colorBar.translatesAutoresizingMaskIntoConstraints = false
        contentContainer.addSubview(colorBar)

        previewLabel.font = PDFAnnotationRowMetrics.previewFont
        previewLabel.textColor = annotationDefaultForegroundColor()
        previewLabel.lineBreakMode = .byWordWrapping
        previewLabel.usesSingleLineMode = false
        previewLabel.cell?.wraps = true
        previewLabel.maximumNumberOfLines = 0
        previewLabel.translatesAutoresizingMaskIntoConstraints = false

        let commentPrimary = annotationComposerPrimaryTextColor()
        commentDisplay.isEditable = false
        commentDisplay.isSelectable = false
        commentDisplay.isRichText = true
        commentDisplay.font = PDFAnnotationRowMetrics.commentFont
        commentDisplay.textColor = commentPrimary
        commentDisplay.backgroundColor = .clear
        commentDisplay.drawsBackground = false
        commentDisplay.maxSize = NSSize(width: CGFloat.greatestFiniteMagnitude, height: CGFloat.greatestFiniteMagnitude)
        commentDisplay.isVerticallyResizable = true
        commentDisplay.isHorizontallyResizable = false
        commentDisplay.textContainerInset = NSSize(width: 0, height: 0)
        commentDisplay.textContainer?.widthTracksTextView = true
        commentDisplay.textContainer?.heightTracksTextView = true
        commentDisplay.textContainer?.lineFragmentPadding = 0
        commentDisplay.textContainer?.lineBreakMode = .byWordWrapping
        commentDisplay.onTextDidChange = { [weak self] in
            self?.handleCommentDisplayDidChange()
        }
        commentDisplay.translatesAutoresizingMaskIntoConstraints = false

        commentEditorScroll.borderType = .noBorder
        commentEditorScroll.drawsBackground = false
        commentEditorScroll.hasVerticalScroller = false
        commentEditorScroll.hasHorizontalScroller = false
        commentEditorScroll.autohidesScrollers = true
        commentEditorScroll.isHidden = true
        commentEditorScroll.translatesAutoresizingMaskIntoConstraints = false

        commentEditor.translatesAutoresizingMaskIntoConstraints = false
        commentEditorScroll.documentView = commentEditor

        commentContainer.translatesAutoresizingMaskIntoConstraints = false
        commentContainer.addSubview(commentDisplay)
        commentContainer.addSubview(commentEditorScroll)

        textStack.translatesAutoresizingMaskIntoConstraints = false
        textStack.orientation = .vertical
        textStack.alignment = .width
        textStack.distribution = .fill
        textStack.spacing = PDFAnnotationRowMetrics.previewGap
        textStack.addArrangedSubview(previewLabel)
        textStack.addArrangedSubview(commentContainer)
        contentContainer.addSubview(textStack)

        let topMetaHeight = PDFAnnotationRowMetrics.topMetaHeight
        let bottomMetaHeight = PDFAnnotationRowMetrics.bottomMetaHeight
        topMetaHeightConstraint = topMetaContainer.heightAnchor.constraint(equalToConstant: topMetaHeight)
        bottomMetaHeightConstraint = bottomMetaContainer.heightAnchor.constraint(equalToConstant: bottomMetaHeight)
        previewHeightConstraint = previewLabel.heightAnchor.constraint(equalToConstant: 0)
        commentHeightConstraint = commentContainer.heightAnchor.constraint(equalToConstant: 0)

        NSLayoutConstraint.activate([
            topMetaContainer.topAnchor.constraint(equalTo: cardView.topAnchor, constant: PDFAnnotationRowMetrics.cardInsetY),
            topMetaContainer.leadingAnchor.constraint(equalTo: cardView.leadingAnchor, constant: PDFAnnotationRowMetrics.cardInsetX),
            topMetaContainer.trailingAnchor.constraint(equalTo: cardView.trailingAnchor, constant: -PDFAnnotationRowMetrics.cardInsetX),
            topMetaHeightConstraint!,

            bottomMetaContainer.bottomAnchor.constraint(equalTo: cardView.bottomAnchor, constant: -PDFAnnotationRowMetrics.cardInsetY),
            bottomMetaContainer.leadingAnchor.constraint(equalTo: cardView.leadingAnchor, constant: PDFAnnotationRowMetrics.cardInsetX),
            bottomMetaContainer.trailingAnchor.constraint(equalTo: cardView.trailingAnchor, constant: -PDFAnnotationRowMetrics.cardInsetX),
            bottomMetaHeightConstraint!,

            contentContainer.topAnchor.constraint(equalTo: topMetaContainer.bottomAnchor, constant: PDFAnnotationRowMetrics.labelGap),
            contentContainer.bottomAnchor.constraint(equalTo: bottomMetaContainer.topAnchor, constant: -PDFAnnotationRowMetrics.metaGap),
            contentContainer.leadingAnchor.constraint(equalTo: cardView.leadingAnchor, constant: PDFAnnotationRowMetrics.cardInsetX),
            contentContainer.trailingAnchor.constraint(equalTo: cardView.trailingAnchor, constant: -PDFAnnotationRowMetrics.cardInsetX),

            pageLabel.leadingAnchor.constraint(equalTo: topMetaContainer.leadingAnchor),
            pageLabel.centerYAnchor.constraint(equalTo: topMetaContainer.centerYAnchor),
            topRightStack.trailingAnchor.constraint(equalTo: topMetaContainer.trailingAnchor),
            topRightStack.centerYAnchor.constraint(equalTo: topMetaContainer.centerYAnchor),
            pageLabel.trailingAnchor.constraint(lessThanOrEqualTo: topRightStack.leadingAnchor,
                                               constant: -PDFAnnotationRowMetrics.metaHorizontalGap),

            menuButton.widthAnchor.constraint(equalToConstant: PDFAnnotationRowMetrics.menuButtonSize),
            menuButton.heightAnchor.constraint(equalToConstant: PDFAnnotationRowMetrics.menuButtonSize),

            createdDateLabel.leadingAnchor.constraint(equalTo: bottomMetaContainer.leadingAnchor),
            createdDateLabel.centerYAnchor.constraint(equalTo: bottomMetaContainer.centerYAnchor),
            createdTimeLabel.trailingAnchor.constraint(equalTo: bottomMetaContainer.trailingAnchor),
            createdTimeLabel.centerYAnchor.constraint(equalTo: bottomMetaContainer.centerYAnchor),
            createdDateLabel.trailingAnchor.constraint(lessThanOrEqualTo: createdTimeLabel.leadingAnchor,
                                                       constant: -PDFAnnotationRowMetrics.metaHorizontalGap),

            colorBar.leadingAnchor.constraint(equalTo: contentContainer.leadingAnchor),
            colorBar.topAnchor.constraint(equalTo: contentContainer.topAnchor),
            colorBar.bottomAnchor.constraint(equalTo: contentContainer.bottomAnchor),
            colorBar.widthAnchor.constraint(equalToConstant: PDFAnnotationRowMetrics.barWidth),

            textStack.leadingAnchor.constraint(equalTo: colorBar.trailingAnchor, constant: PDFAnnotationRowMetrics.barGap),
            textStack.trailingAnchor.constraint(equalTo: contentContainer.trailingAnchor),
            textStack.topAnchor.constraint(equalTo: contentContainer.topAnchor),
            textStack.bottomAnchor.constraint(equalTo: contentContainer.bottomAnchor),

            previewHeightConstraint!,
            previewLabel.widthAnchor.constraint(equalTo: textStack.widthAnchor),
            commentHeightConstraint!,
            commentContainer.widthAnchor.constraint(equalTo: textStack.widthAnchor),

            commentDisplay.leadingAnchor.constraint(equalTo: commentContainer.leadingAnchor),
            commentDisplay.trailingAnchor.constraint(equalTo: commentContainer.trailingAnchor),
            commentDisplay.topAnchor.constraint(equalTo: commentContainer.topAnchor),
            commentDisplay.bottomAnchor.constraint(equalTo: commentContainer.bottomAnchor),

            commentEditorScroll.leadingAnchor.constraint(equalTo: commentContainer.leadingAnchor),
            commentEditorScroll.trailingAnchor.constraint(equalTo: commentContainer.trailingAnchor),
            commentEditorScroll.topAnchor.constraint(equalTo: commentContainer.topAnchor),
            commentEditorScroll.bottomAnchor.constraint(equalTo: commentContainer.bottomAnchor)
        ])

        if let clipView = commentEditorScroll.contentView as? NSView {
            NSLayoutConstraint.activate([
                commentEditor.leadingAnchor.constraint(equalTo: clipView.leadingAnchor),
                commentEditor.trailingAnchor.constraint(equalTo: clipView.trailingAnchor),
                commentEditor.topAnchor.constraint(equalTo: clipView.topAnchor),
                commentEditor.bottomAnchor.constraint(equalTo: clipView.bottomAnchor),
                commentEditor.widthAnchor.constraint(equalTo: clipView.widthAnchor)
            ])
        }

        pageLabel.setContentCompressionResistancePriority(.defaultLow, for: .horizontal)
        noteLabel.setContentCompressionResistancePriority(.defaultHigh, for: .horizontal)
        noteLabel.setContentHuggingPriority(.required, for: .horizontal)

        commentEditor.isEditable = true
        commentEditor.isRichText = true
        // List editor: Return commits immediately (Shift+Return still inserts newline).
        commentEditor.submitOnReturn = true
        commentEditor.font = PDFAnnotationRowMetrics.commentFont
        commentEditor.textColor = commentPrimary
        commentEditor.backgroundColor = .clear
        commentEditor.drawsBackground = false
        commentEditor.importsGraphics = false
        commentEditor.allowsUndo = true
        commentEditor.maxSize = NSSize(width: CGFloat.greatestFiniteMagnitude, height: CGFloat.greatestFiniteMagnitude)
        commentEditor.isVerticallyResizable = true
        commentEditor.isHorizontallyResizable = false
        commentEditor.textContainerInset = NSSize(width: 0, height: 0)
        commentEditor.textContainer?.widthTracksTextView = true
        commentEditor.textContainer?.heightTracksTextView = false
        commentEditor.textContainer?.containerSize = NSSize(width: 0, height: CGFloat.greatestFiniteMagnitude)
        commentEditor.textContainer?.lineFragmentPadding = 0
        commentEditor.textContainer?.lineBreakMode = .byWordWrapping
        commentEditor.autoresizingMask = [.width]
        commentEditor.autoScrollCaret = true
        commentEditor.delegate = self
        commentEditor.onSubmit = { [weak self] in self?.commitCommentEdit() }
        commentEditor.onCancel = { [weak self] in self?.cancelCommentEdit() }
        commentEditor.onTextDidChange = { [weak self] in self?.handleCommentTextDidChange() }
    }

    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }

    override func setFrameSize(_ newSize: NSSize) {
        let oldWidth = frame.size.width
        super.setFrameSize(newSize)
        if abs(newSize.width - oldWidth) > 0.25 {
            needsLayout = true
        }
    }

    func configure(with item: PDFAnnotationListItem, selected: Bool, active: Bool, position: (index: Int, total: Int)) {
        self.item = item
        isSelectedRow = selected
        isActive = active

        if pageLabel.stringValue != item.pageLabel {
            pageLabel.stringValue = item.pageLabel
        }
        let noteText = "Note \(position.index)/\(position.total)"
        if noteLabel.stringValue != noteText {
            noteLabel.stringValue = noteText
        }

        if let createdAt = item.createdAt {
            createdDateLabel.stringValue = annotationCreationDateString(createdAt)
            createdTimeLabel.stringValue = annotationCreationTimeString(createdAt)
            createdDateLabel.isHidden = false
            createdTimeLabel.isHidden = false
        } else {
            createdDateLabel.stringValue = ""
            createdTimeLabel.stringValue = ""
            createdDateLabel.isHidden = true
            createdTimeLabel.isHidden = true
        }

        let previewWidth = max(1, currentContentWidth())
        let preview = quotedPreviewTextToFit(item.highlightText,
                                             font: PDFAnnotationRowMetrics.previewFont,
                                             width: previewWidth,
                                             maxLines: PDFAnnotationRowMetrics.previewMaxLines)
        if previewLabel.stringValue != preview {
            previewLabel.stringValue = preview
        }
        if previewLabel.isHidden != preview.isEmpty {
            previewLabel.isHidden = preview.isEmpty
        }

        let previousComment = commentTextRaw
        let previousPayload = commentRichTextPayload
        commentTextRaw = item.commentText
        commentRichTextPayload = item.commentRichTextPayload
        if previousComment != commentTextRaw || previousPayload != commentRichTextPayload {
            needsCommentTextRefresh = true
        }

        let color = (item.color.usingColorSpace(.deviceRGB) ?? item.color).withAlphaComponent(1.0)
        colorBar.layer?.backgroundColor = color.cgColor

        updateAppearance()
        updateContentSizing()
        needsLayout = true
    }

    override func prepareForReuse() {
        super.prepareForReuse()
        item = nil
        isEditingComment = false
        commentEditDidFinish = false
        commentRichTextPayload = nil
        commentEditor.closeInlineMathPopup(commit: true)
        commentEditor.cleanupFormattingPanels()
        commentEditorScroll.isHidden = true
        commentDisplay.isHidden = false
    }

    @objc private func menuButtonClicked() {
        guard let item else { return }
        onMenuTapped?(item, menuButton)
    }

    func beginCommentEditing() {
        guard !isEditingComment else { return }
        isEditingComment = true
        commentEditDidFinish = false
        let baseFont = commentEditor.font ?? PDFAnnotationRowMetrics.commentFont
        let baseColor = commentEditor.textColor ?? annotationDefaultForegroundColor()
        commentEditor.setPayloadBase(font: baseFont, color: baseColor)
        if let payload = commentRichTextPayload,
           let attributed = annotationRichTextAttributedString(from: payload,
                                                               baseFont: baseFont,
                                                               textColor: baseColor) {
            commentEditor.setRichText(attributed)
        } else {
            commentEditor.setRawText(commentTextRaw)
        }
        commentEditorScroll.isHidden = false
        commentDisplay.isHidden = true
        commentEditor.selectAll(nil)
        window?.makeFirstResponder(commentEditor)
        updateContentSizing()
        notifyHeightUpdate()
    }

    private func commitCommentEdit() {
        finishCommentEdit(save: true)
        window?.makeFirstResponder(nil)
    }

    private func cancelCommentEdit() {
        finishCommentEdit(save: false)
        window?.makeFirstResponder(nil)
    }

    private func finishCommentEdit(save: Bool) {
        guard isEditingComment else { return }
        isEditingComment = false
        commentEditDidFinish = true
        commentEditor.closeInlineMathPopup(commit: true)
        commentEditor.cleanupFormattingPanels()

        let newText = commentEditor.rawText()
        let payload = commentEditor.richTextPayload()
        let content = AnnotationCommentContent(plainText: newText, richTextPayload: payload).normalizedForStorage()
        if save {
            commentTextRaw = content.plainText
            commentRichTextPayload = content.richTextPayload
            applyCommentText(content)
            if let item {
                onCommitCommentEdit?(item, content)
            }
        } else if let item {
            commentTextRaw = item.commentText
            commentRichTextPayload = item.commentRichTextPayload
            applyCommentText(AnnotationCommentContent(plainText: commentTextRaw,
                                                     richTextPayload: commentRichTextPayload))
        }

        commentEditorScroll.isHidden = true
        commentDisplay.isHidden = false
        needsLayout = true
        notifyHeightUpdate()
    }

    private func applyCommentText(_ content: AnnotationCommentContent) {
        let primary = annotationComposerPrimaryTextColor()
        let tertiary = primary
        if content.isEmpty {
            commentDisplayIsPlaceholder = true
            let placeholder = "(No comment)"
            let attrs = inlineMathBaseAttributes(font: PDFAnnotationRowMetrics.placeholderFont,
                                                 color: tertiary)
            commentDisplay.textStorage?.setAttributedString(NSAttributedString(string: placeholder, attributes: attrs))
            commentDisplay.didChangeText()
        } else {
            commentDisplayIsPlaceholder = false
            if let payload = content.richTextPayload,
               let attributed = annotationRichTextAttributedString(from: payload,
                                                                   baseFont: PDFAnnotationRowMetrics.commentFont,
                                                                   textColor: primary) {
                commentDisplay.setRichText(attributed)
            } else {
                commentDisplay.setRawText(content.plainText)
            }
        }
        commentDisplay.typingAttributes = inlineMathBaseAttributes(font: PDFAnnotationRowMetrics.commentFont,
                                                                   color: primary)
        updateContentSizing()
        needsLayout = true
    }

    func textDidEndEditing(_ notification: Notification) {
        guard isEditingComment, !commentEditDidFinish else { return }
        finishCommentEdit(save: true)
    }

    private func handleCommentTextDidChange() {
        guard isEditingComment else { return }
        updateContentSizing()
        needsLayout = true
        notifyHeightUpdate()
    }

    private func currentContentWidth() -> CGFloat {
        let cardWidth = cardView.bounds.width > 0 ? cardView.bounds.width : resolvedCardFrame(in: bounds).width
        let contentWidth = cardWidth
            - (PDFAnnotationRowMetrics.cardInsetX * 2)
            - PDFAnnotationRowMetrics.barWidth
            - PDFAnnotationRowMetrics.barGap
        return max(1, contentWidth)
    }

    private func handleCommentDisplayDidChange() {
        guard !isEditingComment else { return }
        updateContentSizing()
        needsLayout = true
        notifyHeightUpdate()
    }

    private func notifyHeightUpdate() {
        guard !suppressHeightUpdates, allowsDynamicHeightUpdates else { return }
        onNeedsHeightUpdate?(self)
    }

    func measuredHeight(cardWidth: CGFloat) -> CGFloat {
        let contentWidth = max(0, cardWidth
                                   - (PDFAnnotationRowMetrics.cardInsetX * 2)
                                   - PDFAnnotationRowMetrics.barWidth
                                   - PDFAnnotationRowMetrics.barGap)
        let topMetaHeight = PDFAnnotationRowMetrics.topMetaHeight
        let bottomMetaHeight = PDFAnnotationRowMetrics.bottomMetaHeight

        var total = PDFAnnotationRowMetrics.rowInsetY * 2
        total += PDFAnnotationRowMetrics.cardInsetY * 2
        total += topMetaHeight
        total += PDFAnnotationRowMetrics.labelGap

        let previewText: String = {
            if let item {
                return quotedPreviewTextToFit(item.highlightText,
                                              font: PDFAnnotationRowMetrics.previewFont,
                                              width: contentWidth,
                                              maxLines: PDFAnnotationRowMetrics.previewMaxLines)
            }
            return previewLabel.stringValue
        }()
        if !previewText.isEmpty {
            let previewHeight = measuredTextHeight(previewText,
                                                   font: PDFAnnotationRowMetrics.previewFont,
                                                   width: contentWidth)
            total += previewHeight
            total += PDFAnnotationRowMetrics.previewGap
        }

        let commentAttributed: NSAttributedString = {
            if isEditingComment, let storage = commentEditor.textStorage {
                return NSAttributedString(attributedString: storage)
            }
            if let storage = commentDisplay.textStorage {
                return NSAttributedString(attributedString: storage)
            }
            return NSAttributedString(string: "")
        }()
        let activeFont: NSFont = {
            if isEditingComment {
                return commentEditor.font ?? PDFAnnotationRowMetrics.commentFont
            }
            return commentDisplayIsPlaceholder
                ? PDFAnnotationRowMetrics.placeholderFont
                : PDFAnnotationRowMetrics.commentFont
        }()
        let commentHeight = measuredCommentHeight(commentAttributed,
                                                  width: contentWidth,
                                                  minLineHeight: fontLineHeight(activeFont))
        total += commentHeight
        total += PDFAnnotationRowMetrics.metaGap
        total += bottomMetaHeight
        return max(total, 44)
    }

    override func layout() {
        super.layout()
        let cardFrame = resolvedCardFrame(in: bounds)
        if cardView.frame != cardFrame {
            if cardView.layer != nil {
                CATransaction.begin()
                CATransaction.setDisableActions(true)
                cardView.frame = cardFrame
                CATransaction.commit()
            } else {
                cardView.frame = cardFrame
            }
        }
        updateMetaHeightConstraintsIfNeeded()
        updateContentSizing()
    }

    private func updateMetaHeightConstraintsIfNeeded() {
        let topHeight = PDFAnnotationRowMetrics.topMetaHeight
        if let constraint = topMetaHeightConstraint,
           abs(constraint.constant - topHeight) > 0.5 {
            constraint.constant = topHeight
        }
        let bottomHeight = PDFAnnotationRowMetrics.bottomMetaHeight
        if let constraint = bottomMetaHeightConstraint,
           abs(constraint.constant - bottomHeight) > 0.5 {
            constraint.constant = bottomHeight
        }
    }

    private func updateContentSizing() {
        guard let previewHeightConstraint,
              let commentHeightConstraint else { return }
        let contentWidth = currentContentWidth()
        guard contentWidth > 0 else { return }

        let previewText: String = {
            if let item {
                return quotedPreviewTextToFit(item.highlightText,
                                              font: PDFAnnotationRowMetrics.previewFont,
                                              width: contentWidth,
                                              maxLines: PDFAnnotationRowMetrics.previewMaxLines)
            }
            return previewLabel.stringValue
        }()
        if previewLabel.stringValue != previewText {
            previewLabel.stringValue = previewText
        }
        let previewHidden = previewText.isEmpty
        if previewLabel.isHidden != previewHidden {
            previewLabel.isHidden = previewHidden
        }
        let previewHeight = previewHidden
            ? 0
            : measuredTextHeight(previewText,
                                 font: PDFAnnotationRowMetrics.previewFont,
                                 width: contentWidth)
        if abs(previewHeightConstraint.constant - previewHeight) > 0.5 {
            previewHeightConstraint.constant = previewHeight
        }

        let commentAttributed: NSAttributedString = {
            if isEditingComment, let storage = commentEditor.textStorage {
                return NSAttributedString(attributedString: storage)
            }
            if let storage = commentDisplay.textStorage {
                return NSAttributedString(attributedString: storage)
            }
            return NSAttributedString(string: "")
        }()
        let activeFont: NSFont = {
            if isEditingComment {
                return commentEditor.font ?? PDFAnnotationRowMetrics.commentFont
            }
            return commentDisplayIsPlaceholder
                ? PDFAnnotationRowMetrics.placeholderFont
                : PDFAnnotationRowMetrics.commentFont
        }()
        let commentHeight = measuredCommentHeight(commentAttributed,
                                                  width: contentWidth,
                                                  minLineHeight: fontLineHeight(activeFont))
        if abs(commentHeightConstraint.constant - commentHeight) > 0.5 {
            commentHeightConstraint.constant = commentHeight
        }
    }

    override func viewDidChangeEffectiveAppearance() {
        super.viewDidChangeEffectiveAppearance()
        updateAppearance()
    }

    private func updateAppearance() {
        let baseBackground = annotationListCardBaseColor()
        let border = resolvedSystemColor(.separatorColor).withAlphaComponent(0.5)
        let cardBackground = baseBackground.withAlphaComponent(0.9)
        cardView.layer?.backgroundColor = cardBackground.cgColor
        cardView.layer?.borderColor = border.cgColor
        resolvedCardBackground = cardBackground
        let listPrimary = annotationDefaultForegroundColor()
        let listSecondary = annotationDefaultForegroundColor()
        let listIcon = annotationDefaultForegroundColor()
        let listTertiary = annotationDefaultForegroundColor()
        let commentPrimary = annotationDefaultForegroundColor()
        let previousCommentPrimary = commentDisplay.textColor ?? commentPrimary

        pageLabel.font = PDFAnnotationRowMetrics.metaFont
        noteLabel.font = PDFAnnotationRowMetrics.metaFont
        previewLabel.font = PDFAnnotationRowMetrics.previewFont
        createdDateLabel.font = PDFAnnotationRowMetrics.metaFont
        createdTimeLabel.font = PDFAnnotationRowMetrics.metaFont
        commentDisplay.font = PDFAnnotationRowMetrics.commentFont
        commentEditor.font = PDFAnnotationRowMetrics.commentFont

        menuButton.contentTintColor = listIcon
        pageLabel.textColor = listPrimary
        noteLabel.textColor = listTertiary
        previewLabel.textColor = listSecondary
        commentDisplay.textColor = commentPrimary
        commentEditor.textColor = commentPrimary
        commentDisplay.setPayloadBase(font: PDFAnnotationRowMetrics.commentFont, color: commentPrimary)
        commentEditor.setPayloadBase(font: PDFAnnotationRowMetrics.commentFont, color: commentPrimary)
        createdDateLabel.textColor = listTertiary
        createdTimeLabel.textColor = listTertiary
        commentEditor.updateTypingAttributes(font: commentEditor.font ?? PDFAnnotationRowMetrics.commentFont,
                                             color: commentPrimary)
        if isEditingComment {
            if let storage = commentEditor.textStorage,
               storage.length > 0 {
                let full = NSRange(location: 0, length: storage.length)
                storage.beginEditing()
                storage.enumerateAttribute(.foregroundColor, in: full, options: []) { value, range, _ in
                    if let color = value as? NSColor, colorsMatch(color, previousCommentPrimary) {
                        storage.addAttribute(.foregroundColor, value: commentPrimary, range: range)
                    }
                }
                storage.endEditing()
                commentEditor.refreshInlineMathAttachmentStyles(in: full)
            }
        } else {
            let needsRefresh = needsCommentTextRefresh
            if needsRefresh {
                applyCommentText(AnnotationCommentContent(plainText: commentTextRaw,
                                                         richTextPayload: commentRichTextPayload))
            } else if !colorsMatch(previousCommentPrimary, commentPrimary),
                      let storage = commentDisplay.textStorage,
                      storage.length > 0 {
                let full = NSRange(location: 0, length: storage.length)
                storage.beginEditing()
                storage.enumerateAttribute(.foregroundColor, in: full, options: []) { value, range, _ in
                    if let color = value as? NSColor, colorsMatch(color, previousCommentPrimary) {
                        storage.addAttribute(.foregroundColor, value: commentPrimary, range: range)
                    }
                }
                storage.endEditing()
                commentDisplay.refreshInlineMathAttachmentStyles(in: full)
            }
        }
        needsCommentTextRefresh = false
    }

    private func resolvedCardFrame(in bounds: NSRect) -> NSRect {
        let rowInsetY = PDFAnnotationRowMetrics.rowInsetY
        let contractX = PDFAnnotationRowMetrics.cardContractInsetX
        let height = max(1, bounds.height - (2 * rowInsetY))
        let scale = backingScale()

        guard usesAlignmentReference,
              let ref = horizontalAlignmentReferenceView,
              let rowWindow = window,
              ref.window === rowWindow else {
            let inset = bounds.insetBy(dx: contractX, dy: rowInsetY)
            return alignRectToDevicePixels(inset, scale: scale)
        }

        let refInWindow = ref.convert(ref.bounds, to: nil)
        let rowInWindow = convert(bounds, to: nil)
        var minX = refInWindow.minX - rowInWindow.minX + contractX
        var maxX = refInWindow.maxX - rowInWindow.minX - contractX
        minX = max(0, min(bounds.width, minX))
        maxX = max(minX + 1, min(bounds.width, maxX))
        minX = ceilToDevicePixels(minX, scale: scale)
        maxX = floorToDevicePixels(maxX, scale: scale)
        if maxX <= minX {
            maxX = min(bounds.width, minX + 1)
        }
        let width = max(1, maxX - minX)
        let y = roundToDevicePixels(rowInsetY, scale: scale)
        let h = roundToDevicePixels(height, scale: scale)
        return NSRect(x: minX, y: y, width: width, height: h)
    }

    private func backingScale() -> CGFloat {
        if let scale = window?.backingScaleFactor, scale.isFinite, scale > 0 { return scale }
        if let scale = window?.screen?.backingScaleFactor, scale.isFinite, scale > 0 { return scale }
        if let scale = NSScreen.main?.backingScaleFactor, scale.isFinite, scale > 0 { return scale }
        return 2.0
    }

    private func roundToDevicePixels(_ value: CGFloat, scale: CGFloat) -> CGFloat {
        guard value.isFinite, scale.isFinite, scale > 0 else { return value }
        return (value * scale).rounded(.toNearestOrAwayFromZero) / scale
    }

    private func floorToDevicePixels(_ value: CGFloat, scale: CGFloat) -> CGFloat {
        guard value.isFinite, scale.isFinite, scale > 0 else { return value }
        return floor(value * scale) / scale
    }

    private func ceilToDevicePixels(_ value: CGFloat, scale: CGFloat) -> CGFloat {
        guard value.isFinite, scale.isFinite, scale > 0 else { return value }
        return ceil(value * scale) / scale
    }

    private func alignRectToDevicePixels(_ rect: NSRect, scale: CGFloat) -> NSRect {
        let minX = ceilToDevicePixels(rect.minX, scale: scale)
        let minY = ceilToDevicePixels(rect.minY, scale: scale)
        let maxX = floorToDevicePixels(rect.maxX, scale: scale)
        let maxY = floorToDevicePixels(rect.maxY, scale: scale)
        return NSRect(x: minX, y: minY, width: max(1, maxX - minX), height: max(1, maxY - minY))
    }

    private func textHeight(_ text: String, font: NSFont, width: CGFloat) -> CGFloat {
        measuredTextHeight(text, font: font, width: width)
    }

    private func measuredCommentHeight(_ attributed: NSAttributedString,
                                        width: CGFloat,
                                        minLineHeight: CGFloat) -> CGFloat {
        let base = measuredAttributedTextHeight(attributed,
                                                width: width,
                                                minLineHeight: minLineHeight)
        return base + PDFAnnotationRowMetrics.commentHeightFudge
    }

    static func height(for item: PDFAnnotationListItem, cardWidth: CGFloat) -> CGFloat {
        let contentWidth = max(0, cardWidth
                                   - (PDFAnnotationRowMetrics.cardInsetX * 2)
                                   - PDFAnnotationRowMetrics.barWidth
                                   - PDFAnnotationRowMetrics.barGap)
        let topMetaHeight = PDFAnnotationRowMetrics.topMetaHeight
        let bottomMetaHeight = PDFAnnotationRowMetrics.bottomMetaHeight

        var total = PDFAnnotationRowMetrics.rowInsetY * 2
        total += PDFAnnotationRowMetrics.cardInsetY * 2
        total += topMetaHeight
        total += PDFAnnotationRowMetrics.labelGap

        let previewText = quotedPreviewTextToFit(item.highlightText,
                                                 font: PDFAnnotationRowMetrics.previewFont,
                                                 width: contentWidth,
                                                 maxLines: PDFAnnotationRowMetrics.previewMaxLines)
        if !previewText.isEmpty {
            let previewHeight = measuredTextHeight(previewText,
                                                   font: PDFAnnotationRowMetrics.previewFont,
                                                   width: contentWidth)
            total += previewHeight
            total += PDFAnnotationRowMetrics.previewGap
        }

        let trimmedComment = item.commentText.trimmingCharacters(in: .whitespacesAndNewlines)
        let hasRichPayload = !(item.commentRichTextPayload?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true)
        let isEmptyComment = trimmedComment.isEmpty && !hasRichPayload
        let commentFont = isEmptyComment
            ? PDFAnnotationRowMetrics.placeholderFont
            : PDFAnnotationRowMetrics.commentFont
        let commentAttributed: NSAttributedString = {
            if isEmptyComment {
                let attrs = inlineMathBaseAttributes(font: PDFAnnotationRowMetrics.placeholderFont,
                                                     color: annotationDefaultForegroundColor())
                return NSAttributedString(string: "(No comment)", attributes: attrs)
            }
            return annotationCommentAttributedString(plainText: item.commentText,
                                                     payload: item.commentRichTextPayload,
                                                     baseFont: PDFAnnotationRowMetrics.commentFont,
                                                     textColor: annotationDefaultForegroundColor())
        }()
        let commentHeight = measuredAttributedTextHeight(commentAttributed,
                                                         width: contentWidth,
                                                         minLineHeight: fontLineHeight(commentFont))
            + PDFAnnotationRowMetrics.commentHeightFudge
        total += commentHeight
        total += PDFAnnotationRowMetrics.metaGap
        total += bottomMetaHeight
        return max(total, 44)
    }
}

final class PDFAnnotationsPanelController: NSObject, NSTableViewDataSource, NSTableViewDelegate {
    private let scrollView = NSScrollView(frame: .zero)
    private let tableView = AnnotationListTableView(frame: .zero)
    private let emptyLabel = NSTextField(labelWithString: "No annotations yet.")
    private var emptyLabelColor: NSColor = annotationDefaultForegroundColor()
    private var items: [PDFAnnotationListItem] = []
    private var selectedID: String?
    private var horizontalLock: HorizontalScrollLock?
    private var scrollObserver: NSObjectProtocol?
    private var rowHeightOverrides: [String: CGFloat] = [:]
    private var lastCardWidth: CGFloat = 0
    private var lastLayoutWidth: CGFloat = 0
    private let usesDynamicRowHeights = true
    enum LayoutMode {
        case full
        case interactive
    }
    weak var alignmentReferenceView: NSView?
    private var pendingHeightRefresh = false
    private var suppressRowHeightUpdates = false
    private var scrollActivityObservers: [NSObjectProtocol] = []
    private var scrollActivityObserversInstalled = false
    private var isLiveScrolling = false
    private var lastScrollActivityTimestamp: CFTimeInterval = 0
    private var pendingScrollRowUpdates = IndexSet()
    private var pendingScrollHeightRefresh = false
    private var scrollIdleWorkItem: DispatchWorkItem?
    private let scrollIdleDelay: CFTimeInterval = 0.18
    private var resizeObservers: [NSObjectProtocol] = []
    private var resizeObserversInstalled = false
    private var isLiveResizing = false
    private var pendingWidthReset = false
    private var pendingInteractiveLayoutRefresh = false
    private var lastResizingState = false
    private var pendingDeferredItems: [PDFAnnotationListItem]?
    private var pendingDeferredApplyWorkItem: DispatchWorkItem?
    var isResizingProvider: (() -> Bool)?
    private var resizeStickyUntil: CFTimeInterval = 0

    var onSelectItem: ((PDFAnnotationListItem) -> Void)?
    var onRequestMenu: ((PDFAnnotationListItem, NSView) -> Void)?
    var onCommitCommentEdit: ((PDFAnnotationListItem, AnnotationCommentContent) -> Void)?
    var onDeleteItem: ((PDFAnnotationListItem) -> Void)?

    override init() {
        super.init()

        let column = NSTableColumn(identifier: NSUserInterfaceItemIdentifier("annotation"))
        column.title = ""
        column.resizingMask = []
        tableView.addTableColumn(column)
        tableView.headerView = nil
        tableView.dataSource = self
        tableView.delegate = self
        tableView.target = self
        tableView.doubleAction = #selector(annotationDoubleClick)
        tableView.usesAutomaticRowHeights = false
        tableView.intercellSpacing = NSSize(width: 0, height: 6)
        tableView.backgroundColor = .clear
        tableView.selectionHighlightStyle = .none
        tableView.allowsEmptySelection = true
        tableView.allowsMultipleSelection = false
        tableView.focusRingType = .none
        tableView.columnAutoresizingStyle = .noColumnAutoresizing
        tableView.translatesAutoresizingMaskIntoConstraints = true
        tableView.autoresizingMask = [.width]
        tableView.onDeletePressed = { [weak self] in
            self?.deleteSelectedItem()
        }
        tableView.onUserScroll = { [weak self] in
            self?.markScrollActivity()
        }

        scrollView.drawsBackground = false
        scrollView.backgroundColor = .clear
        scrollView.hasVerticalScroller = true
        scrollView.hasHorizontalScroller = false
        scrollView.autohidesScrollers = true
        scrollView.scrollerStyle = .overlay
        scrollView.verticalScrollElasticity = .none
        scrollView.documentView = tableView
        scrollView.contentInsets = NSEdgeInsets(top: 4, left: 0, bottom: 8, right: 0)
        horizontalLock = HorizontalScrollLock(scrollView: scrollView,
                                              lockedX: 0,
                                              clampVertical: true,
                                              usesPredominantAxisScrolling: true)
        installScrollObserverIfNeeded()

        emptyLabel.font = NSFont.systemFont(ofSize: 12.5, weight: .regular)
        emptyLabel.textColor = emptyLabelColor
        emptyLabel.alignment = .center
        emptyLabel.lineBreakMode = .byWordWrapping

        let warmFont = PDFAnnotationRowMetrics.commentFont
        let warmColor = annotationDefaultForegroundColor()
        KaTeXRenderer.shared.prewarm(fontSize: warmFont.pointSize,
                                     textColor: warmColor,
                                     fontFamily: inlineMathCSSFontFamily(warmFont))
    }

    deinit {
        if let scrollObserver {
            NotificationCenter.default.removeObserver(scrollObserver)
        }
        if !scrollActivityObservers.isEmpty {
            for token in scrollActivityObservers {
                NotificationCenter.default.removeObserver(token)
            }
            scrollActivityObservers.removeAll()
        }
        scrollIdleWorkItem?.cancel()
        pendingDeferredApplyWorkItem?.cancel()
        if !resizeObservers.isEmpty {
            for token in resizeObservers {
                NotificationCenter.default.removeObserver(token)
            }
            resizeObservers.removeAll()
        }
    }

    func install(in parent: NSView) {
        scrollView.translatesAutoresizingMaskIntoConstraints = true
        parent.addSubview(scrollView)
        parent.addSubview(emptyLabel)
    }

    func setEmptyMessage(_ message: String) {
        emptyLabel.stringValue = message
    }

    func setEmptyMessageColor(_ color: NSColor) {
        emptyLabelColor = color
        emptyLabel.textColor = color
    }

    func updateAppearance() {
        emptyLabel.textColor = emptyLabelColor
        tableView.needsDisplay = true
    }

    func setRowHeightUpdatesSuppressed(_ suppressed: Bool) {
        suppressRowHeightUpdates = suppressed
    }

    private func markScrollActivity() {
        lastScrollActivityTimestamp = CACurrentMediaTime()
        scheduleScrollIdleFlush()
    }

    private func isActivelyScrolling() -> Bool {
        if isLiveScrolling { return true }
        return CACurrentMediaTime() - lastScrollActivityTimestamp < scrollIdleDelay
    }

    private func scheduleScrollIdleFlush() {
        scrollIdleWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            self?.flushDeferredRowHeightUpdatesIfIdle()
        }
        scrollIdleWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + scrollIdleDelay, execute: work)
    }

    private func deferRowHeightUpdates(_ indexSet: IndexSet) {
        guard !indexSet.isEmpty else { return }
        pendingScrollRowUpdates.formUnion(indexSet)
        scheduleScrollIdleFlush()
    }

    // Avoid row-height mutations during live scroll; defer until idle to prevent jitter/flicker.
    private func noteHeightOfRowsSafely(_ indexSet: IndexSet) {
        guard !indexSet.isEmpty else { return }
        guard !suppressRowHeightUpdates else {
            deferRowHeightUpdates(indexSet)
            return
        }
        if isActivelyScrolling() {
            deferRowHeightUpdates(indexSet)
            return
        }
        tableView.noteHeightOfRows(withIndexesChanged: indexSet)
        scrollView.needsLayout = true
    }

    private func flushDeferredRowHeightUpdatesIfIdle() {
        guard !suppressRowHeightUpdates else { return }
        guard !isActivelyScrolling() else {
            scheduleScrollIdleFlush()
            return
        }
        if pendingScrollHeightRefresh {
            pendingScrollHeightRefresh = false
            refreshVisibleRowHeights()
        }
        if !pendingScrollRowUpdates.isEmpty {
            let pending = pendingScrollRowUpdates
            pendingScrollRowUpdates.removeAll()
            tableView.noteHeightOfRows(withIndexesChanged: pending)
            scrollView.needsLayout = true
        }
    }

    func forceRowHeightRefresh() {
        guard !items.isEmpty else { return }
        let indexSet = IndexSet(integersIn: 0..<items.count)
        noteHeightOfRowsSafely(indexSet)
        tableView.layoutSubtreeIfNeeded()
        layoutVisibleRowViews(resizing: isResizingNow(), forceLayout: true)
    }

    func applyItems(_ items: [PDFAnnotationListItem]) {
        if AnimationGuard.shouldDeferHeavyWork {
            pendingDeferredItems = items
            if pendingDeferredApplyWorkItem == nil {
                let work = DispatchWorkItem { [weak self] in
                    guard let self else { return }
                    let next = self.pendingDeferredItems
                    self.pendingDeferredItems = nil
                    self.pendingDeferredApplyWorkItem = nil
                    if let next {
                        self.applyItemsNow(next)
                    }
                }
                pendingDeferredApplyWorkItem = work
                AnimationGuard.deferWork(label: "annotations.apply_items.deferred") {
                    work.perform()
                }
            }
            return
        }
        if pendingDeferredApplyWorkItem != nil {
            pendingDeferredApplyWorkItem?.cancel()
            pendingDeferredApplyWorkItem = nil
            pendingDeferredItems = nil
        }
        applyItemsNow(items)
    }

    private func applyItemsNow(_ items: [PDFAnnotationListItem]) {
        let guardMeasure = AnimationGuard.beginMeasurement("annotations.apply_items")
        defer { AnimationGuard.endMeasurement(guardMeasure, details: "count=\(items.count)") }
        PerfLogger.begin("annotations.panel.apply_items")
        defer { PerfLogger.end("annotations.panel.apply_items") }
        let previousSelection = selectedID
        let previousItems = self.items
        let previousCount = previousItems.count
        pendingScrollRowUpdates.removeAll()
        pendingScrollHeightRefresh = false
        AnnotationScrollDebugState.shared.noteItemsUpdate(previousCount: previousCount,
                                                          newCount: items.count,
                                                          selectedID: previousSelection,
                                                          source: "annotations.applyItems")
        let sameOrder: Bool = {
            guard previousItems.count == items.count else { return false }
            for (a, b) in zip(previousItems, items) {
                if a.stableID != b.stableID || a.pageIndex != b.pageIndex { return false }
            }
            return true
        }()
        let changedTextRows: IndexSet = {
            guard sameOrder else { return IndexSet() }
            var changed = IndexSet()
            for idx in 0..<items.count {
                let prev = previousItems[idx]
                let next = items[idx]
                if prev.highlightText != next.highlightText
                    || prev.commentText != next.commentText
                    || prev.commentRichTextPayload != next.commentRichTextPayload
                    || prev.pageLabel != next.pageLabel {
                    changed.insert(idx)
                }
            }
            return changed
        }()
        let canUpdateInPlace = sameOrder

        self.items = items
        let idSet = Set(items.map { $0.stableID })
        if usesDynamicRowHeights {
            rowHeightOverrides = rowHeightOverrides.filter { idSet.contains($0.key) }
        } else {
            rowHeightOverrides.removeAll()
        }

        if canUpdateInPlace {
            emptyLabel.isHidden = !items.isEmpty
            if let previousSelection,
               let index = items.firstIndex(where: { $0.stableID == previousSelection }) {
                if tableView.selectedRow != index {
                    tableView.selectRowIndexes(IndexSet(integer: index), byExtendingSelection: false)
                }
            }
            let visible = tableView.rows(in: tableView.visibleRect)
            if visible.length > 0 {
                let end = min(items.count, visible.location + visible.length)
                if visible.location < end {
                    let active = scrollView.window?.isKeyWindow ?? true
                    for row in visible.location..<end {
                        guard let cell = tableView.view(atColumn: 0, row: row, makeIfNecessary: false) as? PDFAnnotationRowView else { continue }
                        cell.suppressHeightUpdates = true
                        cell.configure(with: items[row],
                                       selected: tableView.selectedRowIndexes.contains(row),
                                       active: active,
                                       position: notePosition(for: row))
                        cell.suppressHeightUpdates = false
                    }
                }
            }
            tableView.needsDisplay = true
            if !changedTextRows.isEmpty {
                for row in changedTextRows {
                    guard row >= 0, row < items.count else { continue }
                    let id = items[row].stableID
                    if usesDynamicRowHeights {
                        rowHeightOverrides.removeValue(forKey: id)
                    }
                }
                noteHeightOfRowsSafely(changedTextRows)
            }
        } else {
            tableView.reloadData()
        }
        if items.isEmpty {
            selectedID = nil
        }
        if !canUpdateInPlace,
           let previousSelection,
           let index = items.firstIndex(where: { $0.stableID == previousSelection }) {
            tableView.selectRowIndexes(IndexSet(integer: index), byExtendingSelection: false)
        }
        emptyLabel.isHidden = !items.isEmpty
        if usesDynamicRowHeights,
           (!canUpdateInPlace || !changedTextRows.isEmpty),
           !isResizingNow() {
            scheduleVisibleRowHeightRefresh()
        }
    }

    func layout(in frame: NSRect, mode: LayoutMode = .full) {
        let guardMeasure = AnimationGuard.beginMeasurement("annotations.panel.layout")
        defer { AnimationGuard.endMeasurement(guardMeasure, details: "mode=\(mode)") }
        PerfLogger.begin("annotations.panel.layout")
        defer { PerfLogger.end("annotations.panel.layout") }
        scrollView.frame = frame
        // Keep clip-view sizing in lockstep during live resize so card widths don't lag.
        scrollView.tile()
        let contentWidth = max(1, floorToDevicePixels(scrollView.contentView.bounds.width))
        let resizing = isResizingNow()
        AnnotationScrollDebugState.shared.noteLayout(bounds: frame, source: "annotations.panel.layout")
        if let column = tableView.tableColumns.first {
            column.width = contentWidth
        }
        tableView.frame = NSRect(origin: NSPoint(x: 0, y: 0),
                                 size: CGSize(width: contentWidth, height: tableView.frame.height))
        emptyLabel.frame = NSRect(x: frame.minX + 12, y: frame.midY - 10, width: max(0, frame.width - 24), height: 20)

        installResizeObserversIfNeeded()
        installScrollActivityObserversIfNeeded()

        let cardWidth = resolvedCardWidthForHeight()
        let widthChanged = abs(contentWidth - lastLayoutWidth) > 0.25
        let cardWidthChanged = abs(cardWidth - lastCardWidth) > 0.5

        if widthChanged || cardWidthChanged || resizing || mode == .interactive {
            markResizeActivity()
        }
        if mode == .interactive {
            // Lightweight resize path: keep geometry in sync but defer heavy row/layout work.
            if widthChanged || cardWidthChanged {
                pendingInteractiveLayoutRefresh = true
                tableView.needsLayout = true
                PerfLogger.measure("autolayout.annotations.tableView.interactive") {
                    AnimationGuard.measure("autolayout.annotations.tableView.interactive") {
                        tableView.layoutSubtreeIfNeeded()
                    }
                }
                if !items.isEmpty {
                    let visible = tableView.rows(in: tableView.visibleRect)
                    if visible.length > 0 {
                        let end = min(items.count, visible.location + visible.length)
                        let indexSet = IndexSet(integersIn: visible.location..<end)
                        if !resizing {
                            noteHeightOfRowsSafely(indexSet)
                        }
                    }
                    layoutVisibleRowViews(resizing: resizing, forceLayout: true)
                }
            }
            lastResizingState = resizing
            return
        }

        var effectiveWidthChanged = widthChanged
        var effectiveCardWidthChanged = cardWidthChanged
        if pendingInteractiveLayoutRefresh {
            pendingInteractiveLayoutRefresh = false
            effectiveWidthChanged = true
            effectiveCardWidthChanged = true
        }

        if effectiveWidthChanged {
            lastLayoutWidth = contentWidth
            tableView.needsLayout = true
            // Force immediate row-width updates during resize to avoid lagging cards.
            PerfLogger.measure("autolayout.annotations.tableView") {
                AnimationGuard.measure("autolayout.annotations.tableView") {
                    tableView.layoutSubtreeIfNeeded()
                }
            }
            PerfLogger.measure("annotations.layout.visible_rows") {
                layoutVisibleRowViews(resizing: resizing, forceLayout: true)
            }
            if resizing {
                pendingWidthReset = true
            }
        }
        if resizing != lastResizingState {
            lastResizingState = resizing
            PerfLogger.measure("annotations.layout.visible_rows_state") {
                layoutVisibleRowViews(resizing: resizing, forceLayout: true)
            }
            if resizing {
                pendingWidthReset = true
            } else {
                rowHeightOverrides.removeAll()
                if !items.isEmpty, !suppressRowHeightUpdates {
                    let indexSet = IndexSet(integersIn: 0..<items.count)
                    noteHeightOfRowsSafely(indexSet)
                    if usesDynamicRowHeights {
                        scheduleVisibleRowHeightRefresh()
                    }
                }
            }
        }
        if effectiveCardWidthChanged {
            lastCardWidth = cardWidth
            if resizing {
                pendingWidthReset = true
            } else {
                rowHeightOverrides.removeAll()
            }
        }
        if !items.isEmpty, !resizing, !suppressRowHeightUpdates, (effectiveWidthChanged || effectiveCardWidthChanged) {
            let indexSet = IndexSet(integersIn: 0..<items.count)
            noteHeightOfRowsSafely(indexSet)
            if usesDynamicRowHeights {
                scheduleVisibleRowHeightRefresh()
            }
        }
        if !items.isEmpty, !resizing, !suppressRowHeightUpdates {
            layoutVisibleRowViews(resizing: false, forceLayout: true)
            if usesDynamicRowHeights {
                scheduleVisibleRowHeightRefresh()
            }
        }
    }

    func numberOfRows(in tableView: NSTableView) -> Int {
        items.count
    }

    func tableView(_ tableView: NSTableView, shouldSelectRow row: Int) -> Bool {
        row >= 0 && row < items.count
    }

    private func notePosition(for row: Int) -> (index: Int, total: Int) {
        let total = max(1, items.count)
        let index = max(1, min(total, row + 1))
        return (index: index, total: total)
    }

    func tableView(_ tableView: NSTableView, heightOfRow row: Int) -> CGFloat {
        guard row >= 0, row < items.count else { return 44 }
        let cardWidth = resolvedCardWidthForHeight()
        let item = items[row]
        let baseline = PDFAnnotationRowView.height(for: item, cardWidth: cardWidth)
        if usesDynamicRowHeights {
            let id = items[row].stableID
            if let override = rowHeightOverrides[id] {
                return max(44, max(override, baseline))
            }
        }
        return baseline
    }

    func tableView(_ tableView: NSTableView, viewFor tableColumn: NSTableColumn?, row: Int) -> NSView? {
        guard row >= 0, row < items.count else { return nil }
        let cellId = NSUserInterfaceItemIdentifier("annotationRow")
        let cell = (tableView.makeView(withIdentifier: cellId, owner: self) as? PDFAnnotationRowView)
            ?? PDFAnnotationRowView(frame: .zero)
        cell.identifier = cellId
        cell.horizontalAlignmentReferenceView = alignmentReferenceView
        cell.usesAlignmentReference = !isResizingNow()
        cell.allowsDynamicHeightUpdates = usesDynamicRowHeights
        cell.onMenuTapped = { [weak self] item, anchor in
            self?.onRequestMenu?(item, anchor)
        }
        cell.onCommitCommentEdit = { [weak self] item, content in
            self?.onCommitCommentEdit?(item, content)
        }
        cell.onNeedsHeightUpdate = { [weak self, weak tableView] cell in
            guard let self, self.usesDynamicRowHeights else { return }
            guard let tableView else { return }
            let row = tableView.row(for: cell)
            guard row >= 0, row < self.items.count else { return }
            let cardWidth = self.resolvedCardWidthForHeight()
            let measured = cell.measuredHeight(cardWidth: cardWidth)
            let id = self.items[row].stableID
            let previous = self.rowHeightOverrides[id]
            if previous == nil || abs(previous! - measured) > 0.5 {
                self.rowHeightOverrides[id] = measured
            }
            if !self.isResizingNow() {
                self.noteHeightOfRowsSafely(IndexSet(integer: row))
            } else {
                self.pendingHeightRefresh = true
            }
        }
        cell.configure(with: items[row],
                       selected: tableView.selectedRowIndexes.contains(row),
                       active: true,
                       position: notePosition(for: row))
        if usesDynamicRowHeights, !isResizingNow() {
            scheduleRowHeightUpdate(for: cell, row: row)
        }
        return cell
    }

    func tableViewSelectionDidChange(_ notification: Notification) {
        let row = tableView.selectedRow
        if row >= 0, row < items.count {
            let item = items[row]
            selectedID = item.stableID
            let selectionContext = (tableView as? AnnotationListTableView)?.consumeUserInitiatedSelectionContext()
                ?? (userInitiated: true, keyboard: false)
            if selectionContext.userInitiated {
                let clickedRow = tableView.clickedRow
                let shouldOpen = selectionContext.keyboard || clickedRow == row
                if !shouldOpen { return }
                onSelectItem?(item)
            }
        }
        refreshSelection()
    }

    func selectAdjacentItem(delta: Int) -> PDFAnnotationListItem? {
        guard !items.isEmpty else { return nil }
        let currentIndex = selectedID.flatMap { id in
            items.firstIndex(where: { $0.stableID == id })
        }
        let targetIndex: Int
        if let currentIndex {
            let nextIndex = currentIndex + delta
            let clamped = max(0, min(items.count - 1, nextIndex))
            if clamped == currentIndex {
                return nil
            }
            targetIndex = clamped
        } else {
            targetIndex = delta >= 0 ? 0 : (items.count - 1)
        }
        tableView.selectRowIndexes(IndexSet(integer: targetIndex), byExtendingSelection: false)
        tableView.scrollRowToVisible(targetIndex)
        return items[targetIndex]
    }

    func beginEditingComment(for item: PDFAnnotationListItem) {
        guard let row = items.firstIndex(where: { $0.stableID == item.stableID }) else { return }
        tableView.selectRowIndexes(IndexSet(integer: row), byExtendingSelection: false)
        tableView.scrollRowToVisible(row)
        if let cell = tableView.view(atColumn: 0, row: row, makeIfNecessary: false) as? PDFAnnotationRowView {
            cell.beginCommentEditing()
        }
    }

    @objc private func annotationDoubleClick() {
        let row = tableView.clickedRow
        guard row >= 0, row < items.count else { return }
        tableView.selectRowIndexes(IndexSet(integer: row), byExtendingSelection: false)
        if let cell = tableView.view(atColumn: 0, row: row, makeIfNecessary: false) as? PDFAnnotationRowView {
            cell.beginCommentEditing()
        }
    }

    private func refreshSelection() {
        let active = scrollView.window?.isKeyWindow ?? true
        let visible = tableView.rows(in: tableView.visibleRect)
        guard visible.length > 0 else { return }
        for row in visible.location..<(visible.location + visible.length) {
            guard let cell = tableView.view(atColumn: 0, row: row, makeIfNecessary: false) as? PDFAnnotationRowView,
                  row < items.count else { continue }
            cell.configure(with: items[row],
                           selected: tableView.selectedRowIndexes.contains(row),
                           active: active,
                           position: notePosition(for: row))
        }
    }

    private func isResizingNow() -> Bool {
        if isLiveResizing { return true }
        if CACurrentMediaTime() < resizeStickyUntil { return true }
        return isResizingProvider?() ?? false
    }

    private func markResizeActivity() {
        resizeStickyUntil = CACurrentMediaTime() + 0.12
    }

    private func backingScale() -> CGFloat {
        let scale = scrollView.window?.backingScaleFactor
            ?? scrollView.window?.screen?.backingScaleFactor
            ?? NSScreen.main?.backingScaleFactor
            ?? 2.0
        return (scale.isFinite && scale > 0) ? scale : 2.0
    }

    private func floorToDevicePixels(_ value: CGFloat) -> CGFloat {
        let scale = backingScale()
        guard value.isFinite else { return value }
        return floor(value * scale) / scale
    }

    private func ceilToDevicePixels(_ value: CGFloat) -> CGFloat {
        let scale = backingScale()
        guard value.isFinite else { return value }
        return ceil(value * scale) / scale
    }

    private func resolvedCardWidthForHeight() -> CGFloat {
        let rowWidth = max(1, tableView.bounds.width)
        let contractX = PDFAnnotationRowMetrics.cardContractInsetX
        guard !isResizingNow(),
              let ref = alignmentReferenceView,
              let rowWindow = tableView.window,
              ref.window === rowWindow else {
            var minX = contractX
            var maxX = rowWidth - contractX
            minX = max(0, min(rowWidth, minX))
            maxX = max(minX + 1, min(rowWidth, maxX))
            minX = ceilToDevicePixels(minX)
            maxX = floorToDevicePixels(maxX)
            if maxX <= minX {
                maxX = min(rowWidth, minX + 1)
            }
            return max(1, maxX - minX)
        }

        let refInWindow = ref.convert(ref.bounds, to: nil)
        let rowInWindow = tableView.convert(tableView.bounds, to: nil)
        var minX = refInWindow.minX - rowInWindow.minX + contractX
        var maxX = refInWindow.maxX - rowInWindow.minX - contractX
        minX = max(0, min(rowWidth, minX))
        maxX = max(minX + 1, min(rowWidth, maxX))
        minX = ceilToDevicePixels(minX)
        maxX = floorToDevicePixels(maxX)
        if maxX <= minX {
            maxX = min(rowWidth, minX + 1)
        }
        return max(1, maxX - minX)
    }

    private func deleteSelectedItem() {
        let row = tableView.selectedRow
        guard row >= 0, row < items.count else { return }
        onDeleteItem?(items[row])
    }

    private func scheduleRowHeightUpdate(for cell: PDFAnnotationRowView, row: Int) {
        guard usesDynamicRowHeights else { return }
        guard row >= 0, row < items.count else { return }
        DispatchQueue.main.async { [weak self, weak tableView, weak cell] in
            guard let self, let tableView, let cell else { return }
            guard !self.isResizingNow() else { return }
            let cardWidth = self.resolvedCardWidthForHeight()
            let measured = cell.measuredHeight(cardWidth: cardWidth)
            // Row indices can shift after reloads; re-resolve to avoid stale indexes.
            let currentRow = tableView.row(for: cell)
            guard currentRow >= 0, currentRow < self.items.count else { return }
            let id = self.items[currentRow].stableID
            let previous = self.rowHeightOverrides[id]
            if previous == nil || abs(previous! - measured) > 0.5 {
                self.rowHeightOverrides[id] = measured
                self.noteHeightOfRowsSafely(IndexSet(integer: currentRow))
            }
        }
    }

    private func scheduleVisibleRowHeightRefresh() {
        guard usesDynamicRowHeights else { return }
        guard !pendingHeightRefresh else { return }
        if isActivelyScrolling() {
            pendingScrollHeightRefresh = true
            scheduleScrollIdleFlush()
            return
        }
        pendingHeightRefresh = true
        DispatchQueue.main.async { [weak self] in
            guard let self else { return }
            self.pendingHeightRefresh = false
            self.refreshVisibleRowHeights()
        }
    }

    private func refreshVisibleRowHeights() {
        guard usesDynamicRowHeights else { return }
        if isActivelyScrolling() {
            pendingScrollHeightRefresh = true
            scheduleScrollIdleFlush()
            return
        }
        let visible = tableView.rows(in: tableView.visibleRect)
        guard visible.length > 0 else { return }
        let cardWidth = resolvedCardWidthForHeight()
        var changed = IndexSet()
        let end = min(items.count, visible.location + visible.length)
        guard visible.location < end else { return }
        for row in visible.location..<end {
            guard let cell = tableView.view(atColumn: 0, row: row, makeIfNecessary: false) as? PDFAnnotationRowView else { continue }
            let measured = cell.measuredHeight(cardWidth: cardWidth)
            let id = items[row].stableID
            let previous = rowHeightOverrides[id]
            if previous == nil || abs(previous! - measured) > 0.5 {
                rowHeightOverrides[id] = measured
                changed.insert(row)
            }
        }
        if !changed.isEmpty {
            noteHeightOfRowsSafely(changed)
        }
    }

    private func layoutVisibleRowViews(resizing: Bool, forceLayout: Bool = false) {
        let visible = tableView.rows(in: tableView.visibleRect)
        guard visible.length > 0 else { return }
        let end = min(items.count, visible.location + visible.length)
        guard visible.location < end else { return }
        for row in visible.location..<end {
            guard let cell = tableView.view(atColumn: 0, row: row, makeIfNecessary: false) as? PDFAnnotationRowView else { continue }
            cell.usesAlignmentReference = !resizing
            cell.needsLayout = true
            if forceLayout || !resizing {
                cell.layoutSubtreeIfNeeded()
            }
        }
    }

    private func installResizeObserversIfNeeded() {
        guard !resizeObserversInstalled, let window = scrollView.window else { return }
        resizeObserversInstalled = true
        let nc = NotificationCenter.default
        let beginToken = nc.addObserver(forName: NSWindow.willStartLiveResizeNotification,
                                        object: window,
                                        queue: .main) { [weak self] _ in
            guard let self else { return }
            self.isLiveResizing = true
        }
        let endToken = nc.addObserver(forName: NSWindow.didEndLiveResizeNotification,
                                      object: window,
                                      queue: .main) { [weak self] _ in
            guard let self else { return }
            self.isLiveResizing = false
            if self.pendingWidthReset {
                self.pendingWidthReset = false
                self.rowHeightOverrides.removeAll()
            }
            self.scheduleVisibleRowHeightRefresh()
            if !self.items.isEmpty {
                let indexSet = IndexSet(integersIn: 0..<self.items.count)
                self.noteHeightOfRowsSafely(indexSet)
            }
        }
        resizeObservers.append(beginToken)
        resizeObservers.append(endToken)
    }

    private func installScrollActivityObserversIfNeeded() {
        guard !scrollActivityObserversInstalled else { return }
        scrollActivityObserversInstalled = true
        let nc = NotificationCenter.default
        scrollActivityObservers.append(nc.addObserver(forName: NSScrollView.willStartLiveScrollNotification,
                                                     object: scrollView,
                                                     queue: .main) { [weak self] _ in
            guard let self else { return }
            self.isLiveScrolling = true
            self.markScrollActivity()
        })
        scrollActivityObservers.append(nc.addObserver(forName: NSScrollView.didLiveScrollNotification,
                                                     object: scrollView,
                                                     queue: .main) { [weak self] _ in
            self?.markScrollActivity()
        })
        scrollActivityObservers.append(nc.addObserver(forName: NSScrollView.didEndLiveScrollNotification,
                                                     object: scrollView,
                                                     queue: .main) { [weak self] _ in
            guard let self else { return }
            self.isLiveScrolling = false
            self.markScrollActivity()
        })
    }

    private func installScrollObserverIfNeeded() {
        guard AnnotationScrollDebugState.shared.enabled else { return }
        let clip = scrollView.contentView
        clip.postsBoundsChangedNotifications = true
        scrollObserver = NotificationCenter.default.addObserver(
            forName: NSView.boundsDidChangeNotification,
            object: clip,
            queue: .main
        ) { [weak self] _ in
            guard let self else { return }
            let clip = self.scrollView.contentView
            let origin = clip.bounds.origin
            let docSize = self.scrollView.documentView?.bounds.size
            AnnotationScrollDebugState.shared.noteBounds(origin: origin,
                                                         clipSize: clip.bounds.size,
                                                         docSize: docSize,
                                                         source: "annotations.scrollView")
        }
    }
}

final class HorizontalScrollLock {
    private weak var scrollView: NSScrollView?
    private var observer: NSObjectProtocol?
    private weak var observedContentView: NSView?
    private var isAdjusting: Bool = false
    private var lockedX: CGFloat
    private var clampVertical: Bool
    private var swapClipView: Bool
    private var usesPredominantAxisScrolling: Bool

            init(scrollView: NSScrollView,
                 lockedX: CGFloat,
                 clampVertical: Bool = false,
                 swapClipView: Bool = true,
                 usesPredominantAxisScrolling: Bool = false) {
		        self.scrollView = scrollView
		        self.lockedX = lockedX
		        self.clampVertical = clampVertical
                self.swapClipView = swapClipView
                self.usesPredominantAxisScrolling = usesPredominantAxisScrolling

                applyScrollViewPolicy(scrollView)
                if swapClipView {
                    installLockingClipViewIfPossible(on: scrollView)
                }
		        ensureObserver(on: scrollView.contentView)

	        clampIfNeeded()
	    }

	    deinit {
	        if let observer { NotificationCenter.default.removeObserver(observer) }
	    }

        func updateLockedX(_ x: CGFloat, clamp: Bool = true) {
            lockedX = x
            if let clip = scrollView?.contentView as? HorizontalLockingClipView {
                clip.lockedX = x
            }
            if clamp { clampIfNeeded() }
        }

        func setLocksHorizontal(_ enabled: Bool) {
            if let clip = scrollView?.contentView as? HorizontalLockingClipView {
                clip.locksHorizontal = enabled
            }
        }

            private func installLockingClipViewIfPossible(on scrollView: NSScrollView) {
                let oldClip = scrollView.contentView
                if let existing = oldClip as? HorizontalLockingClipView {
                    existing.lockedX = lockedX
                    existing.clampsVertical = clampVertical
                    return
                }

                let doc = scrollView.documentView

        // Root cause: WebKit/PDFKit often use custom clip-view subclasses; locking must live on the
        // clip surface itself to prevent horizontal panning during gestures (no visible snapping).
        // Preserve the original flipped coordinate system when swapping clip views.
                let newClip: NSClipView & HorizontalLockingClipView
                newClip = HorizontalLockClipView(frame: oldClip.frame, flipped: oldClip.isFlipped)
                newClip.lockedX = lockedX
                newClip.clampsVertical = clampVertical
                newClip.postsBoundsChangedNotifications = true
                newClip.drawsBackground = oldClip.drawsBackground
                newClip.backgroundColor = oldClip.backgroundColor

            scrollView.contentView = newClip
            if let doc { scrollView.documentView = doc }
            scrollView.reflectScrolledClipView(newClip)
        }

		    private func applyScrollViewPolicy(_ scrollView: NSScrollView) {
		        scrollView.hasHorizontalScroller = false
		        scrollView.horizontalScrollElasticity = .none
                // When X is hard-locked via the clip view, predominant-axis scrolling can ignore
                // diagonal jitter (good for vertical-only lists) but may drop horizontal-only
                // gestures entirely. Keep it configurable per scroll surface.
                scrollView.usesPredominantAxisScrolling = usesPredominantAxisScrolling
		    }

	    private func ensureObserver(on contentView: NSClipView) {
	        guard observedContentView !== contentView else { return }
	        if let observer { NotificationCenter.default.removeObserver(observer) }
	        observedContentView = contentView
	        contentView.postsBoundsChangedNotifications = true
	        observer = NotificationCenter.default.addObserver(
	            forName: NSView.boundsDidChangeNotification,
	            object: contentView,
	            queue: .main
	        ) { [weak self] _ in
	            self?.clampIfNeeded()
	        }
	    }

        // Scroll clamp notes:
        // Root cause: we were calling constrainBoundsRect() on every bounds change even when
        // clampVertical == false. PDFKit already clamps vertical bounds during momentum, so
        // double-clamping caused a feedback loop and visible top-of-scroll jitter.
        // Change: only correct X unless vertical clamping is explicitly requested.
        // Why this prevents oscillation: the native scroll view remains the single source of
        // truth for vertical bounds, so momentum can settle without competing corrections.
        //
        // Regression test plan:
        // - fast trackpad upward fling to top (repeat)
        // - slow scroll to top
        // - zoomed PDF scroll to top
        // - resize panels while at top
        // - switch PDFs and repeat
		    func clampIfNeeded() {
		        guard let scrollView else { return }
		        guard isAdjusting == false else { return }
		        applyScrollViewPolicy(scrollView)
                if swapClipView {
                    installLockingClipViewIfPossible(on: scrollView)
                }
		        ensureObserver(on: scrollView.contentView)

                let clip = scrollView.contentView
                let origin = clip.bounds.origin
                var target = origin
                    if let lockClip = clip as? HorizontalLockingClipView {
                        if lockClip.locksHorizontal {
                            target.x = lockedX
                        }
                    } else {
                        target.x = lockedX
                    }
                if clampVertical {
                    let constrained = clip.constrainBoundsRect(NSRect(origin: origin, size: clip.bounds.size)).origin
                    target.y = constrained.y
                }
		        guard abs(target.x - origin.x) > 0.01 || abs(target.y - origin.y) > 0.01 else { return }

		        isAdjusting = true
		        clip.setBoundsOrigin(target)
		        scrollView.reflectScrolledClipView(clip)
		        isAdjusting = false
                PDFScrollDebugState.shared.noteClamp(scrollView: scrollView, origin: origin, target: target)
	    }
}

final class AnnotationScrollDebugState {
    static let shared = AnnotationScrollDebugState()
    let enabled: Bool
    private let activityWindow: CFTimeInterval = 0.25

    private var lastWheelTimestamp: CFTimeInterval = 0
    private var lastScrollTimestamp: CFTimeInterval = 0
    private var lastClampTimestamp: CFTimeInterval = 0

    private init() {
        enabled = ProcessInfo.processInfo.environment["ARXIV_ANNOTATION_SCROLL_DEBUG"] == "1"
    }

    var isScrolling: Bool {
        guard enabled else { return false }
        let now = CACurrentMediaTime()
        let last = max(lastWheelTimestamp, max(lastScrollTimestamp, lastClampTimestamp))
        return now - last < activityWindow
    }

    func noteWheel(_ event: NSEvent, source: String) {
        guard enabled else { return }
        lastWheelTimestamp = CACurrentMediaTime()
        log(String(
            format: "%@ wheel dx=%.2f dy=%.2f precise=%@ phase=%@ momentum=%@",
            source,
            Double(event.scrollingDeltaX),
            Double(event.scrollingDeltaY),
            event.hasPreciseScrollingDeltas ? "true" : "false",
            phaseLabel(event.phase),
            phaseLabel(event.momentumPhase)
        ))
    }

    func noteBounds(origin: NSPoint, clipSize: NSSize, docSize: NSSize?, source: String) {
        guard enabled else { return }
        lastScrollTimestamp = CACurrentMediaTime()
        let doc = docSize ?? .zero
        log(String(
            format: "%@ bounds origin=(%.2f,%.2f) clip=(%.1f,%.1f) doc=(%.1f,%.1f)",
            source,
            Double(origin.x),
            Double(origin.y),
            Double(clipSize.width),
            Double(clipSize.height),
            Double(doc.width),
            Double(doc.height)
        ))
    }

    func noteClamp(origin: NSPoint, target: NSPoint, source: String) {
        guard enabled else { return }
        lastClampTimestamp = CACurrentMediaTime()
        log(String(
            format: "%@ clamp origin=(%.2f,%.2f) target=(%.2f,%.2f)",
            source,
            Double(origin.x),
            Double(origin.y),
            Double(target.x),
            Double(target.y)
        ))
    }

    func noteLayout(bounds: NSRect, source: String) {
        guard enabled else { return }
        guard isScrolling else { return }
        log(String(
            format: "%@ layout bounds=(%.1f,%.1f,%.1f,%.1f)",
            source,
            Double(bounds.origin.x),
            Double(bounds.origin.y),
            Double(bounds.size.width),
            Double(bounds.size.height)
        ))
    }

    func noteRowsInvalidated(count: Int, source: String) {
        guard enabled else { return }
        guard isScrolling else { return }
        log("\(source) rowsInvalidated count=\(count)")
    }

    func noteItemsUpdate(previousCount: Int, newCount: Int, selectedID: String?, source: String) {
        guard enabled else { return }
        let scrolling = isScrolling ? "true" : "false"
        let selection = selectedID ?? "-"
        log("\(source) itemsUpdate prev=\(previousCount) new=\(newCount) selected=\(selection) scrolling=\(scrolling)")
    }

    private func log(_ msg: String) {
        print("[ANNOTATION_SCROLL] \(msg)")
    }

    private func phaseLabel(_ phase: NSEvent.Phase) -> String {
        if phase.isEmpty { return "none" }
        var parts: [String] = []
        if phase.contains(.began) { parts.append("began") }
        if phase.contains(.changed) { parts.append("changed") }
        if phase.contains(.ended) { parts.append("ended") }
        if phase.contains(.cancelled) { parts.append("cancelled") }
        if phase.contains(.mayBegin) { parts.append("mayBegin") }
        if phase.contains(.stationary) { parts.append("stationary") }
        return parts.joined(separator: "|")
    }
}

final class PDFScrollDebugState {
    static let shared = PDFScrollDebugState()
    let enabled: Bool
    let logEnabled: Bool
    weak var targetScrollView: NSScrollView?

    var lastWheelDeltaY: CGFloat = 0
    var lastWheelPrecise: Bool = false
    var lastWheelPhase: NSEvent.Phase = []
    var lastMomentumPhase: NSEvent.Phase = []
    var lastWheelTimestamp: CFTimeInterval = 0
    var lastScrollTimestamp: CFTimeInterval = 0
    var lastClampTimestamp: CFTimeInterval = 0
    var lastClampOrigin: NSPoint = .zero
    var lastClampTarget: NSPoint = .zero
    var clampCount: Int = 0

    private var eventCounter: Int = 0
    private let maxEvents = 10
    private(set) var eventLog: [String] = []

    private init() {
        let env = ProcessInfo.processInfo.environment
        enabled = env["ARXIV_PDF_SCROLL_DEBUG"] == "1"
        logEnabled = env["ARXIV_PDF_SCROLL_DEBUG_LOG"] == "1"
    }

    func bind(scrollView: NSScrollView) {
        targetScrollView = scrollView
    }

    func noteWheel(_ event: NSEvent) {
        guard enabled else { return }
        lastWheelDeltaY = event.scrollingDeltaY
        lastWheelPrecise = event.hasPreciseScrollingDeltas
        lastWheelPhase = event.phase
        lastMomentumPhase = event.momentumPhase
        lastWheelTimestamp = CACurrentMediaTime()
        noteEvent("wheel")
        if logEnabled {
            NSLog("[PDFScrollDebug] wheel deltaY=%.2f precise=%@ phase=%@ momentum=%@",
                  lastWheelDeltaY,
                  lastWheelPrecise ? "true" : "false",
                  phaseLabel(lastWheelPhase),
                  phaseLabel(lastMomentumPhase))
        }
    }

    func noteScroll() {
        guard enabled else { return }
        lastScrollTimestamp = CACurrentMediaTime()
        noteEvent("scroll")
    }

    func noteClamp(scrollView: NSScrollView, origin: NSPoint, target: NSPoint) {
        guard enabled else { return }
        guard scrollView === targetScrollView else { return }
        lastClampTimestamp = CACurrentMediaTime()
        lastClampOrigin = origin
        lastClampTarget = target
        clampCount += 1
        noteEvent("clamp")
        if logEnabled {
            NSLog("[PDFScrollDebug] clamp origin=(%.2f,%.2f) target=(%.2f,%.2f)",
                  origin.x, origin.y, target.x, target.y)
        }
    }

    func noteFrame() {
        guard enabled else { return }
        noteEvent("frame")
    }

    private func noteEvent(_ label: String) {
        eventCounter += 1
        eventLog.append("\(eventCounter):\(label)")
        if eventLog.count > maxEvents {
            eventLog.removeFirst(eventLog.count - maxEvents)
        }
    }

    private func phaseLabel(_ phase: NSEvent.Phase) -> String {
        if phase.isEmpty { return "none" }
        var parts: [String] = []
        if phase.contains(.began) { parts.append("began") }
        if phase.contains(.changed) { parts.append("changed") }
        if phase.contains(.ended) { parts.append("ended") }
        if phase.contains(.cancelled) { parts.append("cancelled") }
        if phase.contains(.mayBegin) { parts.append("mayBegin") }
        if phase.contains(.stationary) { parts.append("stationary") }
        return parts.joined(separator: "|")
    }
}

final class PDFScrollDebugOverlay {
    private let state = PDFScrollDebugState.shared
    private weak var scrollView: NSScrollView?
    private weak var hostView: NSView?
    private let container = PassthroughView(frame: .zero)
    private let label = NSTextField(labelWithString: "")
    private var timer: Timer?
    private var wheelMonitor: Any?
    private var scrollObserver: NSObjectProtocol?
    private var lastClampCount: Int = 0

    init(hostView: NSView, scrollView: NSScrollView) {
        self.hostView = hostView
        self.scrollView = scrollView
        state.bind(scrollView: scrollView)

        container.wantsLayer = true
        container.layer?.masksToBounds = true

        label.font = NSFont.monospacedSystemFont(ofSize: 11, weight: .regular)
        label.textColor = .white
        label.backgroundColor = NSColor.black.withAlphaComponent(0.65)
        label.isEditable = false
        label.isSelectable = false
        label.isBezeled = false
        label.drawsBackground = true
        label.usesSingleLineMode = false
        label.lineBreakMode = .byWordWrapping
        label.maximumNumberOfLines = 0
        label.alignment = .left
        label.wantsLayer = true
        label.layer?.cornerRadius = 6
        label.layer?.masksToBounds = true

        container.addSubview(label)
        hostView.addSubview(container)
        installMonitors()
    }

    deinit {
        if let wheelMonitor { NSEvent.removeMonitor(wheelMonitor) }
        if let scrollObserver { NotificationCenter.default.removeObserver(scrollObserver) }
        timer?.invalidate()
    }

    func matches(scrollView: NSScrollView) -> Bool {
        return self.scrollView === scrollView
    }

    func setHidden(_ hidden: Bool) {
        container.isHidden = hidden
    }

    func layout(in bounds: NSRect) {
        let width: CGFloat = 340
        let height: CGFloat = 120
        let x: CGFloat = 12
        let y: CGFloat = max(12, bounds.height - height - 12)
        container.frame = NSRect(x: x, y: y, width: width, height: height)
        label.frame = container.bounds
    }

    private func installMonitors() {
        guard state.enabled else { return }
        if let clip = scrollView?.contentView {
            scrollObserver = NotificationCenter.default.addObserver(
                forName: NSView.boundsDidChangeNotification,
                object: clip,
                queue: .main
            ) { [weak self] _ in
                self?.state.noteScroll()
            }
        }

        wheelMonitor = NSEvent.addLocalMonitorForEvents(matching: .scrollWheel) { [weak self] event in
            guard let self,
                  let hostView = self.hostView,
                  event.window == hostView.window else {
                return event
            }
            let point = hostView.convert(event.locationInWindow, from: nil)
            if hostView.bounds.contains(point) {
                self.state.noteWheel(event)
            }
            return event
        }

        timer = Timer.scheduledTimer(withTimeInterval: displayRefreshInterval(for: hostView?.window),
                                      repeats: true) { [weak self] _ in
            self?.tick()
        }
        timer?.tolerance = 0.01
    }

    private func tick() {
        guard state.enabled, let scrollView else { return }
        let clip = scrollView.contentView
        let doc = scrollView.documentView
        let origin = clip.bounds.origin
        let minY = doc?.bounds.minY ?? 0
        let scrollY = origin.y - minY
        let docHeight = doc?.bounds.height ?? 0
        let clipHeight = clip.bounds.height
        let maxScroll = max(0, docHeight - clipHeight)

        let now = CACurrentMediaTime()
        let lastActivity = max(state.lastWheelTimestamp,
                               max(state.lastScrollTimestamp, state.lastClampTimestamp))
        if now - lastActivity < 0.25 {
            state.noteFrame()
        }

        let clampHappened = state.clampCount != lastClampCount
        lastClampCount = state.clampCount
        let clampDeltaY = state.lastClampTarget.y - state.lastClampOrigin.y

        let deltaMode = state.lastWheelPrecise ? "px" : "line"
        let phase = phaseLabel(state.lastWheelPhase)
        let momentum = phaseLabel(state.lastMomentumPhase)
        let clampFlag = clampHappened ? "1" : "0"
        let events = state.eventLog.joined(separator: " ")

        label.stringValue = String(
            format: "scrollY=%.1f max=%.1f docH=%.1f clipH=%.1f\n" +
                    "deltaY=%.1f mode=%@ phase=%@ momentum=%@ clamp=%@\n" +
                    "clampY=%.2f originY=%.2f targetY=%.2f\n" +
                    "events: %@",
            scrollY, maxScroll, docHeight, clipHeight,
            state.lastWheelDeltaY, deltaMode, phase, momentum, clampFlag,
            clampDeltaY, state.lastClampOrigin.y, state.lastClampTarget.y,
            events
        )
    }

    private func phaseLabel(_ phase: NSEvent.Phase) -> String {
        if phase.isEmpty { return "none" }
        var parts: [String] = []
        if phase.contains(.began) { parts.append("began") }
        if phase.contains(.changed) { parts.append("changed") }
        if phase.contains(.ended) { parts.append("ended") }
        if phase.contains(.cancelled) { parts.append("cancelled") }
        if phase.contains(.mayBegin) { parts.append("mayBegin") }
        if phase.contains(.stationary) { parts.append("stationary") }
        return parts.joined(separator: "|")
    }
}

// Pass-through effect view so background glass never intercepts events.
@available(macOS 26.0, *)
final class PassthroughGlassEffectView: NSGlassEffectView {
    override func hitTest(_ point: NSPoint) -> NSView? { nil }
}

final class StaticBackgroundImageView: NSView {
    private let fillImageView = NSImageView(frame: .zero)
    private let fitImageView = NSImageView(frame: .zero)
    private let overlayCropThreshold: CGFloat = 0.18
    private let fillAlphaWhenOverlay: CGFloat = 0.35
    private let snapshotColorSpace = CGColorSpaceCreateDeviceRGB()

    var baseColor: NSColor = .black {
        didSet {
            layer?.backgroundColor = baseColor.cgColor
            needsDisplay = true
        }
    }

    var image: NSImage? {
        didSet {
            fillImageView.image = image
            fitImageView.image = image
            needsLayout = true
        }
    }

    override init(frame frameRect: NSRect) {
        super.init(frame: frameRect)
        wantsLayer = true
        layer?.backgroundColor = baseColor.cgColor
        layer?.masksToBounds = true
        fillImageView.animates = true
        fillImageView.imageScaling = .scaleNone
        fillImageView.imageAlignment = .alignCenter
        fillImageView.wantsLayer = true
        addSubview(fillImageView)

        fitImageView.animates = true
        fitImageView.imageScaling = .scaleNone
        fitImageView.imageAlignment = .alignCenter
        fitImageView.wantsLayer = true
        addSubview(fitImageView)
    }

    required init?(coder: NSCoder) { fatalError() }

    func updateBackingScale(_ scale: CGFloat) {
        layer?.contentsScale = scale
        fillImageView.layer?.contentsScale = scale
        fitImageView.layer?.contentsScale = scale
        needsLayout = true
    }

    override func hitTest(_ point: NSPoint) -> NSView? { nil }

    override func layout() {
        super.layout()
        updateImageFrame()
    }

    private func updateImageFrame() {
        guard let image = fillImageView.image else {
            fillImageView.frame = bounds
            fitImageView.frame = bounds
            return
        }

        let imageSize = image.size
        let viewSize = bounds.size
        guard imageSize.width > 0,
              imageSize.height > 0,
              viewSize.width > 0,
              viewSize.height > 0 else {
            fillImageView.frame = bounds
            fitImageView.frame = bounds
            return
        }

        let fillScale = max(viewSize.width / imageSize.width, viewSize.height / imageSize.height)
        let fillSize = NSSize(width: imageSize.width * fillScale, height: imageSize.height * fillScale)
        let fillX = bounds.midX - (fillSize.width / 2)
        let fillY = bounds.midY - (fillSize.height / 2)
        fillImageView.frame = NSRect(x: fillX, y: fillY, width: fillSize.width, height: fillSize.height)

        let fitScale = min(viewSize.width / imageSize.width, viewSize.height / imageSize.height)
        let fitSize = NSSize(width: imageSize.width * fitScale, height: imageSize.height * fitScale)
        let fitX = bounds.midX - (fitSize.width / 2)
        let fitY = bounds.midY - (fitSize.height / 2)
        fitImageView.frame = NSRect(x: fitX, y: fitY, width: fitSize.width, height: fitSize.height)

        let viewArea = max(viewSize.width * viewSize.height, CGFloat(1))
        let fillArea = max(fillSize.width * fillSize.height, CGFloat(1))
        let cropRatio = max(CGFloat(0), min(CGFloat(1), CGFloat(1.0) - (viewArea / fillArea)))
        let showOverlay = cropRatio >= overlayCropThreshold

        fitImageView.isHidden = !showOverlay
        if showOverlay {
            fillImageView.alphaValue = fillAlphaWhenOverlay
            fitImageView.alphaValue = 1.0
        } else {
            fillImageView.alphaValue = 1.0
            fitImageView.alphaValue = 1.0
        }
    }

    func snapshotCGImage(in rectInSelf: CGRect, scale: CGFloat) -> CGImage? {
        // Safe region snapshot without AppKit `cacheDisplay` (which can throw exceptions early in startup).
        // We reproduce the current composite of fill+fit image views into a bitmap.
        let rect = rectInSelf.intersection(bounds)
        guard rect.width > 2, rect.height > 2 else { return nil }

        let s = max(1.0, scale)
        let pxW = max(2, Int(round(rect.width * s)))
        let pxH = max(2, Int(round(rect.height * s)))

        let bitmapInfo = CGImageAlphaInfo.premultipliedLast.rawValue
        guard let ctx = CGContext(data: nil,
                                  width: pxW,
                                  height: pxH,
                                  bitsPerComponent: 8,
                                  bytesPerRow: pxW * 4,
                                  space: snapshotColorSpace,
                                  bitmapInfo: bitmapInfo) else {
            return nil
        }
        ctx.interpolationQuality = .high

        // Map view points -> pixel space.
        ctx.scaleBy(x: s, y: s)
        ctx.translateBy(x: -rect.minX, y: -rect.minY)

        func drawImageView(_ iv: NSImageView) {
            guard let img = iv.image,
                  let cg = img.cgImage(forProposedRect: nil, context: nil, hints: nil) else { return }
            let a = max(0.0, min(1.0, iv.alphaValue))
            if a <= 0.001 { return }
            ctx.saveGState()
            ctx.setAlpha(a)
            ctx.draw(cg, in: iv.frame)
            ctx.restoreGState()
        }

        // Base fill (matches the view’s configured base background).
        let bc = (baseColor.usingColorSpace(.deviceRGB) ?? baseColor)
        ctx.setFillColor(red: bc.redComponent, green: bc.greenComponent, blue: bc.blueComponent, alpha: 1)
        ctx.fill(bounds)

        drawImageView(fillImageView)
        if !fitImageView.isHidden {
            drawImageView(fitImageView)
        }

        return ctx.makeImage()
    }
}

final class CardEdgeGlowView: NSView {
    private let glowLayer = CAShapeLayer()
    var cornerRadius: CGFloat = PANEL_CORNER_RADIUS { didSet { needsLayout = true } }
    var glowColor: NSColor = NSColor.white { didSet { updateGlowStyle() } }
    var strokeAlpha: CGFloat = 0.32 { didSet { updateGlowStyle() } }
    var glowOpacity: Float = 0.5 { didSet { updateGlowStyle() } }
    var glowRadius: CGFloat = 18 { didSet { updateGlowStyle() } }
    var glowOffset: CGSize = .zero { didSet { updateGlowStyle() } }

    override init(frame frameRect: NSRect) {
        super.init(frame: frameRect)
        wantsLayer = true
        layer?.masksToBounds = false
        layer?.backgroundColor = NSColor.clear.cgColor
        glowLayer.fillColor = NSColor.clear.cgColor
        glowLayer.lineWidth = 1
        glowLayer.lineJoin = .round
        glowLayer.contentsScale = NSScreen.main?.backingScaleFactor ?? 2.0
        layer?.addSublayer(glowLayer)
        updateGlowStyle()
    }

    required init?(coder: NSCoder) { fatalError() }

    override func hitTest(_ point: NSPoint) -> NSView? { nil }

    override func layout() {
        super.layout()
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        glowLayer.frame = bounds
        let inset = max(0.5, glowLayer.lineWidth / 2)
        let rect = bounds.insetBy(dx: inset, dy: inset)
        let path = CGPath(roundedRect: rect, cornerWidth: cornerRadius, cornerHeight: cornerRadius, transform: nil)
        glowLayer.path = path
        glowLayer.shadowPath = path
        CATransaction.commit()
    }

    private func updateGlowStyle() {
        let stroke = glowColor.withAlphaComponent(strokeAlpha)
        glowLayer.strokeColor = stroke.cgColor
        glowLayer.shadowColor = glowColor.cgColor
        glowLayer.shadowOpacity = glowOpacity
        glowLayer.shadowRadius = glowRadius
        glowLayer.shadowOffset = glowOffset
    }
}

final class CenteredSearchFieldCell: NSSearchFieldCell {
    override func searchTextRect(forBounds rect: NSRect) -> NSRect {
        var textRect = super.searchTextRect(forBounds: rect)
        let font = self.font ?? NSFont.systemFont(ofSize: NSFont.systemFontSize)
        let lineHeight = font.ascender - font.descender + font.leading
        let centeredY = rect.minY + (rect.height - lineHeight) / 2
        textRect.origin.y = centeredY
        textRect.size.height = lineHeight
        return textRect
    }

    override func titleRect(forBounds rect: NSRect) -> NSRect {
        searchTextRect(forBounds: rect)
    }

    override func drawingRect(forBounds rect: NSRect) -> NSRect {
        searchTextRect(forBounds: rect)
    }

    override func edit(withFrame rect: NSRect,
                       in controlView: NSView,
                       editor: NSText,
                       delegate: Any?,
                       event: NSEvent?) {
        let textRect = searchTextRect(forBounds: rect)
        super.edit(withFrame: textRect, in: controlView, editor: editor, delegate: delegate, event: event)
    }

    override func select(withFrame rect: NSRect,
                         in controlView: NSView,
                         editor: NSText,
                         delegate: Any?,
                         start: Int,
                         length: Int) {
        let textRect = searchTextRect(forBounds: rect)
        super.select(withFrame: textRect, in: controlView, editor: editor, delegate: delegate, start: start, length: length)
    }

    override func searchButtonRect(forBounds rect: NSRect) -> NSRect {
        var buttonRect = super.searchButtonRect(forBounds: rect)
        buttonRect.origin.y = rect.minY + (rect.height - buttonRect.height) / 2
        return buttonRect
    }

    override func cancelButtonRect(forBounds rect: NSRect) -> NSRect {
        var buttonRect = super.cancelButtonRect(forBounds: rect)
        buttonRect.origin.y = rect.minY + (rect.height - buttonRect.height) / 2
        return buttonRect
    }
}

final class GlassSeparatorView: NSView {
