class GlassToolbarButton: NSButton {
    private var tracking: NSTrackingArea?
    private let hoverLayer = CALayer()
    private let haloLayer = CAShapeLayer()
    private var isHovering = false
    private var glassBackground: GlassCardView?
    var restingGlowColor: NSColor? { didSet { updateHoverState(animated: false) } }
    var restingTintColor: NSColor? { didSet { updateTint() } }
    var disabledTintColor: NSColor? { didSet { updateTint() } }
    var contrastBackgroundColor: NSColor? { didSet { updateTint() } }
    var debugIdentifier: String?
    var showsHaloRing: Bool = true { didSet { updateHoverState(animated: false) } }
    var showsRestingGlow: Bool = true { didSet { updateHoverState(animated: false) } }
    var restingGlowOpacity: Float = 0.28 { didSet { updateHoverState(animated: false) } }
    var idleHoverOpacity: Float = 0.05 { didSet { updateHoverState(animated: false) } }
    var hoverFillOpacity: Float = 0.12 { didSet { updateHoverState(animated: false) } }
    var pressedFillOpacity: Float = 0.22 { didSet { updateHoverState(animated: false) } }
    var hoverShadowOpacity: Float = 0.22 { didSet { updateHoverState(animated: false) } }
    var pressedShadowOpacity: Float = 0.32 { didSet { updateHoverState(animated: false) } }
    var restingShadowRadius: CGFloat = 4 { didSet { updateHoverState(animated: false) } }
    var hoverShadowRadius: CGFloat = 6 { didSet { updateHoverState(animated: false) } }
    var pressedShadowRadius: CGFloat = 6 { didSet { updateHoverState(animated: false) } }
    var restingShadowOffset: CGSize = CGSize(width: 0, height: -0.4) { didSet { updateHoverState(animated: false) } }
    var hoverShadowOffset: CGSize = CGSize(width: 0, height: -1.0) { didSet { updateHoverState(animated: false) } }
    var pressedShadowOffset: CGSize = CGSize(width: 0, height: -1.0) { didSet { updateHoverState(animated: false) } }
    var hoverScale: CGFloat = 1.085 { didSet { updateHoverState(animated: false) } }
    var activeScale: CGFloat = 1.03 { didSet { updateHoverState(animated: false) } }
    var hoverLift: CGFloat = -1.6 { didSet { updateHoverState(animated: false) } }
    var activeLift: CGFloat = -0.8 { didSet { updateHoverState(animated: false) } }
    var usesGlyphOnlyFeedback: Bool = false { didSet { updateTint(); updateHoverState(animated: false) } }
    var glyphHoverAlpha: CGFloat = 0.86 { didSet { updateTint() } }
    var glyphPressedAlpha: CGFloat = 0.7 { didSet { updateTint() } }

    override init(frame frameRect: NSRect) {
        super.init(frame: frameRect)
        wantsLayer = true
        layer?.masksToBounds = false
        layer?.backgroundColor = NSColor.clear.cgColor

        haloLayer.fillColor = NSColor.clear.cgColor
        haloLayer.strokeColor = NSColor.white.withAlphaComponent(0.30).cgColor
        haloLayer.lineWidth = 1.2
        haloLayer.opacity = 0
        haloLayer.shadowOffset = .zero
        haloLayer.shadowRadius = 14
        haloLayer.shadowOpacity = 0
        layer?.addSublayer(haloLayer)

        hoverLayer.backgroundColor = NSColor.clear.cgColor
        hoverLayer.opacity = 0
        layer?.addSublayer(hoverLayer)
        isBordered = false
        imagePosition = .imageOnly
        focusRingType = .none
        updateTint()
        updateHoverState(animated: false)
    }

    required init?(coder: NSCoder) { fatalError() }

    override func viewDidChangeEffectiveAppearance() {
        super.viewDidChangeEffectiveAppearance()
        updateTint()
        updateHoverState(animated: false)
    }

    override func layout() {
        super.layout()
        CATransaction.begin()
        CATransaction.setDisableActions(true)

        haloLayer.frame = bounds
        let haloRadius = (layer?.cornerRadius ?? 0)
        let inset: CGFloat = 0.6
        let haloRect = haloLayer.bounds.insetBy(dx: inset, dy: inset)
        let haloCorner = max(0, haloRadius - inset)
        let haloPath = CGPath(roundedRect: haloRect,
                              cornerWidth: haloCorner,
                              cornerHeight: haloCorner,
                              transform: nil)
        haloLayer.path = haloPath
        haloLayer.shadowPath = haloPath

        hoverLayer.frame = bounds
        hoverLayer.cornerRadius = layer?.cornerRadius ?? 0
        if let radius = layer?.cornerRadius {
            layer?.shadowPath = CGPath(roundedRect: bounds,
                                       cornerWidth: radius,
                                       cornerHeight: radius,
                                       transform: nil)
        }
        if let glass = glassBackground,
           let superview = superview,
           glass.superview === superview {
            let targetFrame = frame
            let needsInvalidate = glass.frame != targetFrame
            if needsInvalidate {
                glass.frame = targetFrame
            }
            if let radius = layer?.cornerRadius, glass.cornerRadius != radius {
                glass.cornerRadius = radius
            }
            if needsInvalidate {
                glass.invalidateGlass(reason: "button_frame")
            }
	        }
	        CATransaction.commit()
    }

    override func updateTrackingAreas() {
        super.updateTrackingAreas()
        if let tracking { removeTrackingArea(tracking) }
        let opts: NSTrackingArea.Options = [.mouseEnteredAndExited, .activeAlways, .inVisibleRect]
        let area = NSTrackingArea(rect: bounds, options: opts, owner: self, userInfo: nil)
        addTrackingArea(area)
        tracking = area
    }

    override func mouseEntered(with event: NSEvent) {
        isHovering = true
        updateHoverState(animated: true)
    }

    override func mouseExited(with event: NSEvent) {
        isHovering = false
        updateHoverState(animated: true)
    }

    override var isHighlighted: Bool {
        didSet { updateHoverState(animated: true) }
    }

    override var isEnabled: Bool {
        didSet {
            updateTint()
            updateHoverState(animated: false)
        }
    }

    override var alphaValue: CGFloat {
        didSet { glassBackground?.alphaValue = alphaValue }
    }

    override var isHidden: Bool {
        didSet { glassBackground?.isHidden = isHidden }
    }

    override var focusRingMaskBounds: NSRect {
        usesGlyphOnlyFeedback ? .zero : super.focusRingMaskBounds
    }

    override func drawFocusRingMask() {
        guard !usesGlyphOnlyFeedback else { return }
        super.drawFocusRingMask()
    }

    func updateTint() {
        let palette = ToolbarForegroundTheme.shared.palette
        let baseTint = restingTintColor ?? palette.primary
        let tint: NSColor
        if isEnabled {
            tint = baseTint
        } else {
            tint = disabledTintColor ?? palette.disabled
        }
        let background = contrastBackgroundColor ?? palette.background
        let applied = glyphAdjustedTint(tint, background: background)
        contentTintColor = applied
        if ContrastDebug.enabled {
            let context = debugIdentifier ?? "GlassToolbarButton"
            ContrastDebug.logApplied(context: context,
                                     role: .icon,
                                     background: background,
                                     foreground: applied,
                                     note: isEnabled ? "enabled" : "disabled")
            let ok = ContrastDebug.assertForegroundMatchesSearch(foreground: applied,
                                                                background: background,
                                                                role: .icon,
                                                                context: context)
            if !ok {
                let fallback = ThemeContrast.bestContrastingMonochrome(on: background,
                                                                       minimumContrast: ThemeContrast.iconMinimumContrast)
                contentTintColor = glyphAdjustedTint(fallback, background: background)
            }
        }
    }

    func attachLiquidGlassBackground(_ background: GlassCardView) {
        glassBackground = background
        background.alphaValue = alphaValue
        background.isHidden = isHidden
        updateGlassState()
        needsLayout = true
    }

    func invalidateLiquidGlass(reason: String = "button_state") {
        glassBackground?.invalidateGlass(reason: reason)
    }

    func setCornerRadius(_ radius: CGFloat, maskedCorners: CACornerMask? = nil) {
        layer?.cornerRadius = radius
        if let maskedCorners {
            layer?.maskedCorners = maskedCorners
        }
        glassBackground?.cornerRadius = radius
    }

    private func updateHoverState(animated: Bool) {
        let reduceMotion = NSWorkspace.shared.accessibilityDisplayShouldReduceMotion || !animated
        let isActive = isEnabled && (isHovering || isHighlighted)
        let hoverTarget: Float = isHighlighted
            ? pressedFillOpacity
            : ((isHovering && isEnabled) ? hoverFillOpacity : idleHoverOpacity)
        let dark = effectiveAppearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua
        let defaultGlow = dark ? NSColor.white : NSColor.black
        let glowColor = (restingGlowColor ?? defaultGlow).usingColorSpace(.deviceRGB) ?? defaultGlow
        let hoverFillColor = (dark ? NSColor.white : NSColor.black).withAlphaComponent(dark ? 0.12 : 0.08)

        let haloTargetOpacity: Float = showsHaloRing ? 1.0 : 0.0
        let haloTargetShadowOpacity: Float = (showsHaloRing && isHovering && isEnabled && !isHighlighted) ? (dark ? 0.55 : 0.30) : 0.0
        let haloTargetShadowRadius: CGFloat = (showsHaloRing && isHovering && isEnabled && !isHighlighted) ? (dark ? 18 : 14) : (dark ? 14 : 12)

        let baseGlowOpacity: Float = (restingGlowColor == nil || !isEnabled || !showsRestingGlow) ? 0.0 : restingGlowOpacity
        let baseShadowRadius: CGFloat = baseGlowOpacity > 0 ? restingShadowRadius : 0
        let baseShadowOffset: CGSize = baseGlowOpacity > 0 ? restingShadowOffset : .zero
        let targetShadowOpacity: Float = {
            guard isActive else { return baseGlowOpacity }
            return isHighlighted ? pressedShadowOpacity : hoverShadowOpacity
        }()
        let targetShadowRadius: CGFloat = {
            guard isActive else { return baseShadowRadius }
            return isHighlighted ? pressedShadowRadius : hoverShadowRadius
        }()
        let targetShadowOffset: CGSize = {
            guard isActive else { return baseShadowOffset }
            return isHighlighted ? pressedShadowOffset : hoverShadowOffset
        }()
        let hoverOnly = (isHovering && isEnabled && !isHighlighted)
        let scale: CGFloat = hoverOnly ? hoverScale : (isActive ? activeScale : 1.0)
        let lift: CGFloat = hoverOnly ? hoverLift : (isActive ? activeLift : 0.0)
        var transform = CATransform3DIdentity
        transform = CATransform3DTranslate(transform, 0, lift, 0)
        transform = CATransform3DScale(transform, scale, scale, 1.0)

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        layer?.shadowColor = glowColor.cgColor
        haloLayer.shadowColor = glowColor.cgColor
        let haloStrokeAlpha: CGFloat = dark ? 0.35 : 0.22
        haloLayer.strokeColor = glowColor.withAlphaComponent(haloStrokeAlpha).cgColor
        hoverLayer.backgroundColor = hoverFillColor.cgColor
        CATransaction.commit()

        if reduceMotion {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            hoverLayer.opacity = hoverTarget
            layer?.transform = transform
            layer?.shadowOpacity = targetShadowOpacity
            layer?.shadowRadius = targetShadowRadius
            layer?.shadowOffset = targetShadowOffset
            haloLayer.opacity = haloTargetOpacity
            haloLayer.shadowOpacity = haloTargetShadowOpacity
            haloLayer.shadowRadius = haloTargetShadowRadius
            CATransaction.commit()
        } else {
            let preset: SpringPreset = hoverOnly ? .hoverBounce : .microBounce
            animateLayer(hoverLayer, keyPath: "opacity", to: hoverTarget, preset: preset, reduceMotion: false, basicDuration: 0.12)
            animateLayer(layer, keyPath: "transform", to: transform, preset: preset, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowOpacity", to: targetShadowOpacity, preset: preset, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowRadius", to: targetShadowRadius, preset: preset, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowOffset", to: targetShadowOffset, preset: preset, reduceMotion: false, basicDuration: 0.14)

            animateLayer(haloLayer, keyPath: "opacity", to: haloTargetOpacity, preset: preset, reduceMotion: false, basicDuration: 0.14)
            animateLayer(haloLayer, keyPath: "shadowOpacity", to: haloTargetShadowOpacity, preset: preset, reduceMotion: false, basicDuration: 0.14)
            animateLayer(haloLayer, keyPath: "shadowRadius", to: haloTargetShadowRadius, preset: preset, reduceMotion: false, basicDuration: 0.14)
        }

        if usesGlyphOnlyFeedback {
            updateTint()
        }
        updateGlassState()
    }

    private func glyphAdjustedTint(_ tint: NSColor, background: NSColor?) -> NSColor {
        guard usesGlyphOnlyFeedback, isEnabled else { return tint }
        let base = tint.usingColorSpace(.deviceRGB) ?? tint
        let multiplier: CGFloat
        if isHighlighted {
            multiplier = glyphPressedAlpha
        } else if isHovering {
            multiplier = glyphHoverAlpha
        } else {
            multiplier = 1.0
        }
        let clamped = max(0.0, min(1.0, multiplier))
        let alpha = max(0.0, min(1.0, base.alphaComponent * clamped))
        let candidate = base.withAlphaComponent(alpha)
        guard let background else { return candidate }
        return ThemeContrast.ensureContrast(candidate,
                                            on: background,
                                            minimumContrast: ThemeContrast.iconMinimumContrast,
                                            context: "glyph_button")
    }

    private func updateGlassState() {
        guard let glass = glassBackground else { return }
        let state: GlassCardKit.State
        if !isEnabled {
            state = .disabled
        } else if isHighlighted {
            state = .pressed
        } else if isHovering {
            state = .hover
        } else {
            state = .normal
        }
        glass.updateState(state)
    }
}

final class TagButtonView: NSView {
    private var tracking: NSTrackingArea?
    private let backgroundLayer = CALayer()
    private let labelField = AnnotationToolbarTextField(labelWithString: "")
    private let imageView = NSImageView()
    private var isHovering = false
    private var isPressed = false
    private var didFireClick = false
    var fillColor: NSColor { didSet { updateAppearance() } }
    var foregroundColor: NSColor = annotationDefaultForegroundColor() { didSet { updateContentColors() } }
    var underlineColorOverride: NSColor? { didSet { updateLabel() } }
    var isSelected = false { didSet { updateAppearance() } }
    var isEmphasized = false { didSet { updateLabel() } }
    var isUnderlined = false { didSet { updateLabel() } }
    var onClick: (() -> Void)?
    var debugName: String?

    private var textValue: String = "Aa" { didSet { updateLabel() } }
    private var iconImage: NSImage? { didSet { updateContentMode() } }
    private var debugLabel: String { debugName ?? textValue }

    init(fillColor: NSColor) {
        self.fillColor = fillColor
        super.init(frame: .zero)
        wantsLayer = true
        layer?.masksToBounds = false
        layer?.backgroundColor = NSColor.clear.cgColor

        backgroundLayer.backgroundColor = fillColor.cgColor
        backgroundLayer.opacity = 1.0
        layer?.addSublayer(backgroundLayer)

        labelField.translatesAutoresizingMaskIntoConstraints = false
        labelField.isEditable = false
        labelField.isSelectable = false
        labelField.isBordered = false
        labelField.drawsBackground = false
        labelField.alignment = .center
        labelField.usesSingleLineMode = true
        labelField.lineBreakMode = .byTruncatingTail
        labelField.setContentCompressionResistancePriority(.required, for: .horizontal)
        labelField.setContentHuggingPriority(.required, for: .horizontal)

        imageView.translatesAutoresizingMaskIntoConstraints = false
        imageView.imageScaling = .scaleNone
        imageView.isHidden = true

        addSubview(labelField)
        addSubview(imageView)

        labelField.centerXAnchor.constraint(equalTo: centerXAnchor).isActive = true
        labelField.centerYAnchor.constraint(equalTo: centerYAnchor).isActive = true
        labelField.leadingAnchor.constraint(greaterThanOrEqualTo: leadingAnchor, constant: 2).isActive = true
        labelField.trailingAnchor.constraint(lessThanOrEqualTo: trailingAnchor, constant: -2).isActive = true

        imageView.centerXAnchor.constraint(equalTo: centerXAnchor).isActive = true
        imageView.centerYAnchor.constraint(equalTo: centerYAnchor).isActive = true

        updateContentMode()
        updateAppearance()
    }

    required init?(coder: NSCoder) { fatalError() }

    func setText(_ text: String) {
        textValue = text
        iconImage = nil
        updateContentMode()
    }

    func setIcon(_ image: NSImage?) {
        iconImage = image
        updateContentMode()
    }

    override func layout() {
        super.layout()
        CATransaction.begin()
        CATransaction.setDisableActions(true)

        backgroundLayer.frame = bounds
        backgroundLayer.cornerRadius = bounds.height / 2
        layer?.cornerRadius = bounds.height / 2
        layer?.shadowPath = CGPath(roundedRect: bounds,
                                   cornerWidth: bounds.height / 2,
                                   cornerHeight: bounds.height / 2,
                                   transform: nil)
        CATransaction.commit()
    }

    override func updateTrackingAreas() {
        super.updateTrackingAreas()
        if let tracking { removeTrackingArea(tracking) }
        let opts: NSTrackingArea.Options = [.mouseEnteredAndExited, .activeAlways, .inVisibleRect]
        let area = NSTrackingArea(rect: bounds, options: opts, owner: self, userInfo: nil)
        addTrackingArea(area)
        tracking = area
    }

    override func mouseEntered(with event: NSEvent) {
        isHovering = true
        updateAppearance()
        if tagDebugEnabled { annotationLog("TagButtonView mouseEntered \(debugLabel) frame=\(NSStringFromRect(frame))") }
    }

    override func mouseExited(with event: NSEvent) {
        isHovering = false
        updateAppearance()
        if tagDebugEnabled { annotationLog("TagButtonView mouseExited \(debugLabel)") }
    }

    override func mouseDown(with event: NSEvent) {
        isPressed = true
        didFireClick = true
        updateAppearance()
        if tagDebugEnabled {
            let window = event.window.map { "\($0)" } ?? "nil"
            annotationLog("TagButtonView mouseDown \(debugLabel) window=\(window)")
        }
        onClick?()
    }

    override func mouseUp(with event: NSEvent) {
        if isPressed && !didFireClick {
            let point = convert(event.locationInWindow, from: nil)
            if tagDebugEnabled {
                annotationLog("TagButtonView mouseUp click \(debugLabel) point=\(NSStringFromPoint(point))")
            }
            onClick?()
        }
        didFireClick = false
        isPressed = false
        updateAppearance()
    }

    override func acceptsFirstMouse(for event: NSEvent?) -> Bool {
        true
    }

    override func hitTest(_ point: NSPoint) -> NSView? {
        let hit = bounds.contains(point) ? self : nil
        if tagDebugEnabled, hit != nil {
            annotationLog("TagButtonView hitTest \(debugLabel) point=\(NSStringFromPoint(point))")
        }
        return hit
    }

    private func updateContentMode() {
        let hasIcon = iconImage != nil
        imageView.isHidden = !hasIcon
        labelField.isHidden = hasIcon
        if hasIcon {
            imageView.image = iconImage
        }
        updateContentColors()
        updateLabel()
    }

    private func updateContentColors() {
        labelField.textColor = foregroundColor
        imageView.contentTintColor = foregroundColor
        updateLabel()
    }

    private func updateLabel() {
        guard !labelField.isHidden else { return }
        let fontWeight: NSFont.Weight = isEmphasized ? .semibold : .medium
        let font = NSFont.systemFont(ofSize: 11, weight: fontWeight)
        let baselineOffset = opticalBaselineOffset(for: font, text: textValue)
        var attributes: [NSAttributedString.Key: Any] = [
            .font: font,
            .foregroundColor: foregroundColor
        ]
        if baselineOffset != 0 {
            attributes[.baselineOffset] = baselineOffset
        }
        if isUnderlined {
            attributes[.underlineStyle] = NSUnderlineStyle.single.rawValue
            if let override = underlineColorOverride {
                attributes[.underlineColor] = override
            }
        }
        labelField.attributedStringValue = NSAttributedString(string: textValue, attributes: attributes)
    }

    private func opticalBaselineOffset(for font: NSFont, text: String) -> CGFloat {
        guard !text.isEmpty else { return 0 }
        let attr = NSAttributedString(string: text, attributes: [.font: font])
        let line = CTLineCreateWithAttributedString(attr)
        let bounds = CTLineGetBoundsWithOptions(line, [.useOpticalBounds])
        let lineMidY = (font.ascender + font.descender) * 0.5
        let glyphMidY = bounds.midY
        let offset = lineMidY - glyphMidY
        if !offset.isFinite { return 0 }
        return max(-2, min(2, offset))
    }

    private func updateAppearance() {
        let reduceMotion = NSWorkspace.shared.accessibilityDisplayShouldReduceMotion

        let isActive = isHovering || isPressed || isSelected
        let targetOpacity: Float = isActive ? 0.9 : 1.0
        let targetShadowOpacity: Float = isSelected ? 0.32 : (isActive ? 0.22 : 0.12)
        let targetShadowRadius: CGFloat = isSelected ? 5 : (isActive ? 4 : 3)
        let targetShadowOffset = CGSize(width: 0, height: isActive ? -1 : 0)
        // Keep tag hit-testing stable by avoiding view transforms that shift under the cursor.
        let transform = CATransform3DIdentity

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        layer?.shadowColor = fillColor.withAlphaComponent(0.7).cgColor
        layer?.shadowOpacity = targetShadowOpacity
        layer?.shadowRadius = targetShadowRadius
        layer?.shadowOffset = targetShadowOffset
        backgroundLayer.backgroundColor = fillColor.cgColor
        CATransaction.commit()

        if reduceMotion {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            backgroundLayer.opacity = targetOpacity
            layer?.transform = transform
            CATransaction.commit()
        } else {
            let preset: SpringPreset = isPressed ? .microBounce : .hoverBounce
            animateLayer(backgroundLayer, keyPath: "opacity", to: targetOpacity, preset: preset, reduceMotion: false, basicDuration: 0.12)
            animateLayer(layer, keyPath: "transform", to: transform, preset: preset, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowOpacity", to: targetShadowOpacity, preset: preset, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowRadius", to: targetShadowRadius, preset: preset, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowOffset", to: targetShadowOffset, preset: preset, reduceMotion: false, basicDuration: 0.14)
        }
    }
}

final class ColorButtonView: NSView {
    private var tracking: NSTrackingArea?
    private let backgroundLayer = CALayer()
    private var isHovering = false
    private var isPressed = false
    var color: NSColor { didSet { updateAppearance() } }
    var isSelected = false { didSet { updateAppearance() } }
    var onClick: (() -> Void)?

    init(color: NSColor) {
        self.color = color
        super.init(frame: .zero)
        wantsLayer = true
        layer?.masksToBounds = false
        layer?.backgroundColor = NSColor.clear.cgColor

        backgroundLayer.backgroundColor = color.cgColor
        backgroundLayer.opacity = 1.0
        layer?.addSublayer(backgroundLayer)

        updateAppearance()
    }

    required init?(coder: NSCoder) { fatalError() }

    override func layout() {
        super.layout()
        CATransaction.begin()
        CATransaction.setDisableActions(true)

        backgroundLayer.frame = bounds
        backgroundLayer.cornerRadius = bounds.height / 2
        layer?.cornerRadius = bounds.height / 2
        layer?.shadowPath = CGPath(roundedRect: bounds,
                                   cornerWidth: bounds.height / 2,
                                   cornerHeight: bounds.height / 2,
                                   transform: nil)
        CATransaction.commit()
    }

    override func updateTrackingAreas() {
        super.updateTrackingAreas()
        if let tracking { removeTrackingArea(tracking) }
        let opts: NSTrackingArea.Options = [.mouseEnteredAndExited, .activeAlways, .inVisibleRect]
        let area = NSTrackingArea(rect: bounds, options: opts, owner: self, userInfo: nil)
        addTrackingArea(area)
        tracking = area
    }

    override func mouseEntered(with event: NSEvent) {
        isHovering = true
        updateAppearance()
    }

    override func mouseExited(with event: NSEvent) {
        isHovering = false
        updateAppearance()
    }

    override func mouseDown(with event: NSEvent) {
        isPressed = true
        updateAppearance()
    }

    override func mouseUp(with event: NSEvent) {
        if isPressed && bounds.contains(convert(event.locationInWindow, from: nil)) {
            onClick?()
        }
        isPressed = false
        updateAppearance()
    }

    override func acceptsFirstMouse(for event: NSEvent?) -> Bool {
        true
    }

    private func updateAppearance() {
        let reduceMotion = NSWorkspace.shared.accessibilityDisplayShouldReduceMotion

        let isActive = isHovering || isPressed || isSelected
        let targetOpacity: Float = isActive ? 0.9 : 1.0
        let targetShadowOpacity: Float = isSelected ? 0.32 : (isActive ? 0.22 : 0.12)
        let targetShadowRadius: CGFloat = isSelected ? 5 : (isActive ? 4 : 3)
        let targetShadowOffset = CGSize(width: 0, height: isActive ? -1 : 0)
        let scale: CGFloat = isPressed ? 0.95 : (isHovering ? 1.05 : 1.0)
        let lift: CGFloat = isPressed ? 0.5 : (isHovering ? -0.8 : 0.0)

        var transform = CATransform3DIdentity
        transform = CATransform3DTranslate(transform, 0, lift, 0)
        transform = CATransform3DScale(transform, scale, scale, 1.0)

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        layer?.shadowColor = color.withAlphaComponent(0.7).cgColor
        layer?.shadowOpacity = targetShadowOpacity
        layer?.shadowRadius = targetShadowRadius
        layer?.shadowOffset = targetShadowOffset
        backgroundLayer.backgroundColor = color.cgColor
        CATransaction.commit()

        if reduceMotion {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            backgroundLayer.opacity = targetOpacity
            layer?.transform = transform
            CATransaction.commit()
        } else {
            let preset: SpringPreset = isPressed ? .microBounce : .hoverBounce
            animateLayer(backgroundLayer, keyPath: "opacity", to: targetOpacity, preset: preset, reduceMotion: false, basicDuration: 0.12)
            animateLayer(layer, keyPath: "transform", to: transform, preset: preset, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowOpacity", to: targetShadowOpacity, preset: preset, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowRadius", to: targetShadowRadius, preset: preset, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowOffset", to: targetShadowOffset, preset: preset, reduceMotion: false, basicDuration: 0.14)
        }
    }
}

final class ColorSwatchView: NSView {
    var color: NSColor { didSet { updateColor() } }

    init(color: NSColor) {
        self.color = color
        super.init(frame: .zero)
        wantsLayer = true
        layer?.backgroundColor = color.cgColor
        layer?.borderWidth = 1.0
        updateBorderColor()
    }

    required init?(coder: NSCoder) { fatalError() }

    override func layout() {
        super.layout()
        layer?.cornerRadius = bounds.height / 2
    }

    override func viewDidChangeEffectiveAppearance() {
        super.viewDidChangeEffectiveAppearance()
        updateBorderColor()
    }

    private func updateColor() {
        layer?.backgroundColor = color.cgColor
    }

    private func updateBorderColor() {
        let isDark = AppearanceManager.shared.isDark()
        let base = resolvedSystemColor(.separatorColor)
        let color = (isDark ? NSColor.white : base).withAlphaComponent(isDark ? 0.18 : 0.35)
        layer?.borderColor = color.cgColor
    }
}

final class PaletteSwatchStripView: NSStackView {
    private var swatches: [ColorSwatchView] = []
    private let swatchSize = NSSize(width: 18, height: 12)

    var colors: [NSColor] = [] {
        didSet { syncColors() }
    }

    init(colors: [NSColor]) {
        super.init(frame: .zero)
        orientation = .horizontal
        alignment = .centerY
        distribution = .fillProportionally
        spacing = 6
        self.colors = colors
        rebuildSwatches()
    }

    required init?(coder: NSCoder) { fatalError() }

    private func rebuildSwatches() {
        for view in arrangedSubviews {
            removeArrangedSubview(view)
            view.removeFromSuperview()
        }
        swatches = colors.map { ColorSwatchView(color: $0) }
        for swatch in swatches {
            swatch.translatesAutoresizingMaskIntoConstraints = false
            swatch.widthAnchor.constraint(equalToConstant: swatchSize.width).isActive = true
            swatch.heightAnchor.constraint(equalToConstant: swatchSize.height).isActive = true
            swatch.setContentHuggingPriority(.required, for: .horizontal)
            addArrangedSubview(swatch)
        }
    }

    private func syncColors() {
        if swatches.count != colors.count {
            rebuildSwatches()
            return
        }
        for (idx, swatch) in swatches.enumerated() {
            swatch.color = colors[idx]
        }
    }
}

// Reusable “Share button” glass border ornament stack:
// - highlight gradient
// - falloff gradient
// - inner + outer strokes
// The host decides geometry (mask/outer/inner paths) and any animation.
final class ShareStyleOrnamentStack {
    let maskLayer = CAShapeLayer()
    let outlineLayer = CAShapeLayer()
    let innerOutlineLayer = CAShapeLayer()
    let highlightLayer = CAGradientLayer()
    let falloffLayer = CAGradientLayer()

    init() {
        maskLayer.fillColor = NSColor.black.cgColor

        outlineLayer.fillColor = NSColor.clear.cgColor
        innerOutlineLayer.fillColor = NSColor.clear.cgColor
        outlineLayer.lineJoin = .round
        outlineLayer.lineCap = .round
        innerOutlineLayer.lineJoin = .round
        innerOutlineLayer.lineCap = .round

        highlightLayer.startPoint = CGPoint(x: 0.5, y: 1.0)
        highlightLayer.endPoint = CGPoint(x: 0.5, y: 0.0)
        falloffLayer.startPoint = CGPoint(x: 0.5, y: 1.0)
        falloffLayer.endPoint = CGPoint(x: 0.5, y: 0.0)
    }

    func attach(to hostLayer: CALayer) {
        hostLayer.mask = maskLayer
        hostLayer.addSublayer(highlightLayer)
        hostLayer.addSublayer(falloffLayer)
        hostLayer.addSublayer(innerOutlineLayer)
        hostLayer.addSublayer(outlineLayer)
    }

    func setContentsScale(_ scale: CGFloat) {
        maskLayer.contentsScale = scale
        outlineLayer.contentsScale = scale
        innerOutlineLayer.contentsScale = scale
        highlightLayer.contentsScale = scale
        falloffLayer.contentsScale = scale
    }

    func setFrames(bounds: CGRect) {
        maskLayer.frame = bounds
        outlineLayer.frame = bounds
        innerOutlineLayer.frame = bounds
        highlightLayer.frame = bounds
        falloffLayer.frame = bounds
    }

    func applyShareStyle(enabled: Bool) {
        let borderAlpha: CGFloat = enabled ? 0.78 : 0.28
        let innerBorderAlpha: CGFloat = enabled ? 0.34 : 0.14
        let highlightTopAlpha: CGFloat = enabled ? 0.18 : 0.08
        let highlightMidAlpha: CGFloat = enabled ? 0.06 : 0.03
        let falloffAlpha: CGFloat = enabled ? 0.18 : 0.06

        outlineLayer.lineWidth = 1
        innerOutlineLayer.lineWidth = 1
        outlineLayer.strokeColor = NSColor.black.withAlphaComponent(borderAlpha).cgColor
        innerOutlineLayer.strokeColor = NSColor.black.withAlphaComponent(innerBorderAlpha).cgColor
        highlightLayer.colors = [
            NSColor.white.withAlphaComponent(highlightTopAlpha).cgColor,
            NSColor.white.withAlphaComponent(highlightMidAlpha).cgColor,
            NSColor.clear.cgColor
        ]
        falloffLayer.colors = [
            NSColor.clear.cgColor,
            NSColor.black.withAlphaComponent(falloffAlpha).cgColor
        ]
    }

    func applyEdgeStyle(outline: NSColor,
                        innerOutline: NSColor,
                        highlightTop: NSColor,
                        highlightMid: NSColor,
                        falloff: NSColor) {
        outlineLayer.lineWidth = 1
        innerOutlineLayer.lineWidth = 1
        outlineLayer.strokeColor = outline.cgColor
        innerOutlineLayer.strokeColor = innerOutline.cgColor
        highlightLayer.colors = [
            highlightTop.cgColor,
            highlightMid.cgColor,
            NSColor.clear.cgColor
        ]
        highlightLayer.locations = [0.0, 0.55, 1.0]
        falloffLayer.colors = [
            NSColor.clear.cgColor,
            falloff.cgColor
        ]
        falloffLayer.locations = [0.0, 1.0]
    }
}

// Material edge stack: two subtle rim bands (outer attenuation + inner lift).
// Uses even-odd filled rings so the edge reads as part of the fill, not as a stroke.
final class MaterialEdgeStack {
    let maskLayer = CAShapeLayer()
    let outerBandLayer = CAShapeLayer()
    let innerBandLayer = CAShapeLayer()

    init() {
        maskLayer.fillColor = NSColor.black.cgColor

        outerBandLayer.fillRule = .evenOdd
        innerBandLayer.fillRule = .evenOdd
        outerBandLayer.fillColor = NSColor.black.withAlphaComponent(0.06).cgColor
        innerBandLayer.fillColor = NSColor.white.withAlphaComponent(0.03).cgColor
        outerBandLayer.strokeColor = nil
        innerBandLayer.strokeColor = nil
        outerBandLayer.lineWidth = 0
        innerBandLayer.lineWidth = 0
    }

    func attach(to hostLayer: CALayer) {
        hostLayer.mask = maskLayer
        hostLayer.addSublayer(outerBandLayer)
        hostLayer.addSublayer(innerBandLayer)
    }

    func setContentsScale(_ scale: CGFloat) {
        maskLayer.contentsScale = scale
        outerBandLayer.contentsScale = scale
        innerBandLayer.contentsScale = scale
    }

    func setFrames(bounds: CGRect) {
        maskLayer.frame = bounds
        outerBandLayer.frame = bounds
        innerBandLayer.frame = bounds
    }

    func applyEdgeStyle(outerBand: NSColor, innerRim: NSColor) {
        outerBandLayer.fillColor = outerBand.cgColor
        innerBandLayer.fillColor = innerRim.cgColor
    }

    static func ringPath(outer: CGPath, inner: CGPath) -> CGPath {
        let path = CGMutablePath()
        path.addPath(outer)
        path.addPath(inner)
        return path
    }
}

struct ToolbarOutlineEdgeBands {
    let outer: NSColor
    let inner: NSColor
}

enum ToolbarOutlineTokens {
    static func edgeBands(for state: GlassCardKit.State) -> ToolbarOutlineEdgeBands {
        let baseOuter: CGFloat = 0.06
        let baseInner: CGFloat = 0.03
        var outer = baseOuter
        var inner = baseInner

        switch state {
        case .hover:
            inner = min(0.04, baseInner + 0.01)
        case .pressed:
            inner = 0.0
            outer = min(0.08, baseOuter + 0.02)
        case .selected:
            inner = min(0.04, baseInner + 0.01)
        case .disabled:
            outer = baseOuter * 0.6
            inner = baseInner * 0.5
        case .normal:
            break
        }

        return ToolbarOutlineEdgeBands(
            outer: NSColor.black.withAlphaComponent(outer),
            inner: NSColor.white.withAlphaComponent(inner)
        )
    }
}

final class ShareStyleCapsuleOrnamentOverlayView: NSView {
    private let ornaments = ShareStyleOrnamentStack()

    override init(frame frameRect: NSRect) {
        super.init(frame: frameRect)
        wantsLayer = true
        layer?.masksToBounds = false
        if let host = layer {
            ornaments.attach(to: host)
        }
    }

    required init?(coder: NSCoder) { fatalError() }

    override func hitTest(_ point: NSPoint) -> NSView? { nil }

    override func viewDidChangeEffectiveAppearance() {
        super.viewDidChangeEffectiveAppearance()
        needsLayout = true
    }

    override func layout() {
        super.layout()
        updateOrnaments()
    }

    private func updateOrnaments() {
        let b = bounds
        guard b.width > 4, b.height > 4 else { return }

        let scale = max(1.0, window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)
        let radius = b.height / 2

        let maskRect = b
        let outerRect = b.insetBy(dx: 0.5, dy: 0.5)
        let innerRect = b.insetBy(dx: 1.5, dy: 1.5)

        let maskPath = CGPath(roundedRect: maskRect,
                              cornerWidth: radius,
                              cornerHeight: radius,
                              transform: nil)
        let outerPath = CGPath(roundedRect: outerRect,
                               cornerWidth: max(0, radius - 0.5),
                               cornerHeight: max(0, radius - 0.5),
                               transform: nil)
        let innerPath = CGPath(roundedRect: innerRect,
                               cornerWidth: max(0, radius - 1.5),
                               cornerHeight: max(0, radius - 1.5),
                               transform: nil)

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        ornaments.setContentsScale(scale)
        ornaments.setFrames(bounds: b)
        ornaments.applyShareStyle(enabled: true)
        ornaments.maskLayer.path = maskPath
        ornaments.outlineLayer.path = outerPath
        ornaments.innerOutlineLayer.path = innerPath
        CATransaction.commit()
    }
}

final class ShareStyleRoundedRectOrnamentOverlayView: NSView {
    private let ornaments = ShareStyleOrnamentStack()
    var cornerRadius: CGFloat { didSet { needsLayout = true } }

    init(frame frameRect: NSRect, cornerRadius: CGFloat) {
        self.cornerRadius = cornerRadius
        super.init(frame: frameRect)
        wantsLayer = true
        layer?.masksToBounds = false
        if let host = layer {
            ornaments.attach(to: host)
        }
    }

    convenience init(cornerRadius: CGFloat) {
        self.init(frame: .zero, cornerRadius: cornerRadius)
    }

    required init?(coder: NSCoder) { fatalError() }

    override func hitTest(_ point: NSPoint) -> NSView? { nil }

    override func viewDidChangeEffectiveAppearance() {
        super.viewDidChangeEffectiveAppearance()
        needsLayout = true
    }

    override func layout() {
        super.layout()
        updateOrnaments()
    }

    private func updateOrnaments() {
        let b = bounds
        guard b.width > 4, b.height > 4 else { return }

        let scale = max(1.0, window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)
        let clampedRadius = max(0, min(cornerRadius, min(b.width, b.height) / 2))

        let maskRect = b
        let outerRect = b.insetBy(dx: 0.5, dy: 0.5)
        let innerRect = b.insetBy(dx: 1.5, dy: 1.5)

        let maskPath = CGPath(roundedRect: maskRect,
                              cornerWidth: clampedRadius,
                              cornerHeight: clampedRadius,
                              transform: nil)
        let outerPath = CGPath(roundedRect: outerRect,
                               cornerWidth: max(0, clampedRadius - 0.5),
                               cornerHeight: max(0, clampedRadius - 0.5),
                               transform: nil)
        let innerPath = CGPath(roundedRect: innerRect,
                               cornerWidth: max(0, clampedRadius - 1.5),
                               cornerHeight: max(0, clampedRadius - 1.5),
                               transform: nil)

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        ornaments.setContentsScale(scale)
        ornaments.setFrames(bounds: b)
        ornaments.applyShareStyle(enabled: true)
        ornaments.maskLayer.path = maskPath
        ornaments.outlineLayer.path = outerPath
        ornaments.innerOutlineLayer.path = innerPath
        CATransaction.commit()
    }
}

final class ShareToolbarButton: GlassToolbarButton {
    // Secondary action is discoverable via right-click context menu.
    var shareMenuProvider: (() -> NSMenu?)?
    var showsCircularOutline: Bool = true { didSet { updateCircularGlassyOutline() } }

    private let outlineLayer = CAShapeLayer()
    private let innerOutlineLayer = CAShapeLayer()
    private let highlightLayer = CAGradientLayer()
    private let falloffLayer = CAGradientLayer()

    override init(frame frameRect: NSRect) {
        super.init(frame: frameRect)

        // Clip our glass highlight/falloff to the circular shape.
        layer?.masksToBounds = true

        outlineLayer.fillColor = NSColor.clear.cgColor
        innerOutlineLayer.fillColor = NSColor.clear.cgColor
        outlineLayer.lineJoin = .round
        outlineLayer.lineCap = .round
        innerOutlineLayer.lineJoin = .round
        innerOutlineLayer.lineCap = .round

        outlineLayer.lineWidth = 1
        innerOutlineLayer.lineWidth = 1

        highlightLayer.startPoint = CGPoint(x: 0.5, y: 1.0)
        highlightLayer.endPoint = CGPoint(x: 0.5, y: 0.0)
        falloffLayer.startPoint = CGPoint(x: 0.5, y: 1.0)
        falloffLayer.endPoint = CGPoint(x: 0.5, y: 0.0)

        let scale = max(1.0, window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)
        outlineLayer.contentsScale = scale
        innerOutlineLayer.contentsScale = scale
        highlightLayer.contentsScale = scale
        falloffLayer.contentsScale = scale

        // Keep border on top of the hover sheen.
        layer?.addSublayer(highlightLayer)
        layer?.addSublayer(falloffLayer)
        layer?.addSublayer(innerOutlineLayer)
        layer?.addSublayer(outlineLayer)
    }

    required init?(coder: NSCoder) { fatalError() }

    override func viewDidChangeEffectiveAppearance() {
        super.viewDidChangeEffectiveAppearance()
        needsLayout = true
    }

    override func updateTint() {
        super.updateTint()
        updateCircularGlassyOutline()
    }

    override func layout() {
        // Establish the circular corner radius *before* the superclass computes
        // hover/halo/shadow geometry from `layer.cornerRadius`.
        let side = min(bounds.width, bounds.height)
        if side > 0 {
            setCornerRadius(side / 2)
        }
        super.layout()
        updateCircularGlassyOutline()
    }

    private func updateCircularGlassyOutline() {
        let bounds = self.bounds
        let side = min(bounds.width, bounds.height)
        guard side > 0 else { return }

        // Ensure circular shape even if layout ever drifts from a perfect square.
        let radius = side / 2
        setCornerRadius(radius)
        if !showsCircularOutline {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            outlineLayer.opacity = 0
            innerOutlineLayer.opacity = 0
            highlightLayer.opacity = 0
            falloffLayer.opacity = 0
            CATransaction.commit()
            return
        }

        let circleBounds = NSRect(
            x: bounds.midX - side / 2,
            y: bounds.midY - side / 2,
            width: side,
            height: side
        )

        // Keep the outer rim decisively black while preserving a subtle glass highlight.
        let borderAlpha: CGFloat = isEnabled ? 0.78 : 0.28
        let innerBorderAlpha: CGFloat = isEnabled ? 0.34 : 0.14
        let highlightTopAlpha: CGFloat = isEnabled ? 0.18 : 0.08
        let highlightMidAlpha: CGFloat = isEnabled ? 0.06 : 0.03
        let falloffAlpha: CGFloat = isEnabled ? 0.18 : 0.06
        let palette = ToolbarForegroundTheme.shared.palette
        let borderBase = palette.primary

        let outerRect = circleBounds.insetBy(dx: 0.5, dy: 0.5)
        let innerRect = circleBounds.insetBy(dx: 1.5, dy: 1.5)
        let outerPath = CGPath(ellipseIn: outerRect, transform: nil)
        let innerPath = CGPath(ellipseIn: innerRect, transform: nil)

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        outlineLayer.frame = bounds
        innerOutlineLayer.frame = bounds
        highlightLayer.frame = circleBounds
        falloffLayer.frame = circleBounds

        outlineLayer.path = outerPath
        innerOutlineLayer.path = innerPath

        outlineLayer.opacity = 1
        innerOutlineLayer.opacity = 1
        highlightLayer.opacity = 1
        falloffLayer.opacity = 1

        outlineLayer.strokeColor = borderBase.withAlphaComponent(borderAlpha).cgColor
        innerOutlineLayer.strokeColor = borderBase.withAlphaComponent(innerBorderAlpha).cgColor
        highlightLayer.colors = [
            NSColor.white.withAlphaComponent(highlightTopAlpha).cgColor,
            NSColor.white.withAlphaComponent(highlightMidAlpha).cgColor,
            NSColor.clear.cgColor
        ]
        falloffLayer.colors = [
            NSColor.clear.cgColor,
            NSColor.black.withAlphaComponent(falloffAlpha).cgColor
        ]
        CATransaction.commit()
    }

    override func rightMouseDown(with event: NSEvent) {
        if let menu = shareMenuProvider?() {
            NSMenu.popUpContextMenu(menu, with: event, for: self)
            return
        }
        super.rightMouseDown(with: event)
    }
}

final class GlassToolbarMenuButton: NSButton {
    private var tracking: NSTrackingArea?
    private let hoverLayer = CALayer()
    private var isHovering = false
    var restingGlowColor: NSColor? { didSet { updateHoverState(animated: false) } }
    var restingTintColor: NSColor? { didSet { updateTint() } }
    var disabledTintColor: NSColor? { didSet { updateTint() } }
    var contrastBackgroundColor: NSColor? { didSet { updateTint() } }
    var debugIdentifier: String?

    override init(frame frameRect: NSRect) {
        super.init(frame: frameRect)
        wantsLayer = true
        layer?.masksToBounds = false
        layer?.backgroundColor = NSColor.clear.cgColor
        hoverLayer.backgroundColor = NSColor.clear.cgColor
        hoverLayer.opacity = 0
        layer?.addSublayer(hoverLayer)
        isBordered = false
        focusRingType = .none
        imagePosition = .imageTrailing
        alignment = .center
        updateTint()
        updateHoverState(animated: false)
    }

    required init?(coder: NSCoder) { fatalError() }

    override func viewDidChangeEffectiveAppearance() {
        super.viewDidChangeEffectiveAppearance()
        updateTint()
        updateHoverState(animated: false)
    }

    override func layout() {
        super.layout()
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        hoverLayer.frame = bounds
        hoverLayer.cornerRadius = layer?.cornerRadius ?? 0
        if let radius = layer?.cornerRadius {
            layer?.shadowPath = CGPath(roundedRect: bounds,
                                       cornerWidth: radius,
                                       cornerHeight: radius,
                                       transform: nil)
	        }
	        CATransaction.commit()
    }

    override func updateTrackingAreas() {
        super.updateTrackingAreas()
        if let tracking { removeTrackingArea(tracking) }
        let opts: NSTrackingArea.Options = [.mouseEnteredAndExited, .activeAlways, .inVisibleRect]
        let area = NSTrackingArea(rect: bounds, options: opts, owner: self, userInfo: nil)
        addTrackingArea(area)
        tracking = area
    }

    override func mouseEntered(with event: NSEvent) {
        isHovering = true
        updateHoverState(animated: true)
    }

    override func mouseExited(with event: NSEvent) {
        isHovering = false
        updateHoverState(animated: true)
    }

    override var isHighlighted: Bool {
        didSet { updateHoverState(animated: true) }
    }

    override var isEnabled: Bool {
        didSet {
            updateTint()
            updateHoverState(animated: false)
        }
    }

    func updateTint() {
        let palette = ToolbarForegroundTheme.shared.palette
        let baseTint = restingTintColor ?? toolbarForegroundColor()
        let tint: NSColor
        if isEnabled {
            tint = baseTint
        } else {
            tint = disabledTintColor ?? toolbarForegroundColor()
        }
        let applied = tint
        contentTintColor = tint
        if ContrastDebug.enabled {
            let context = debugIdentifier ?? "GlassToolbarMenuButton"
            ContrastDebug.logApplied(context: context,
                                     role: .icon,
                                     background: palette.background,
                                     foreground: tint,
                                     note: isEnabled ? "enabled" : "disabled")
            _ = ContrastDebug.assertForegroundMatchesSearch(foreground: tint,
                                                                background: palette.background,
                                                                role: .icon,
                                                                context: context)
        }
        let attr = NSMutableAttributedString(attributedString: attributedTitle)
        attr.addAttributes([.foregroundColor: tint], range: NSRange(location: 0, length: attr.length))
        attributedTitle = attr
    }

    func setCornerRadius(_ radius: CGFloat, maskedCorners: CACornerMask? = nil) {
        layer?.cornerRadius = radius
        if let maskedCorners {
            layer?.maskedCorners = maskedCorners
        }
    }

    private func updateHoverState(animated: Bool) {
        let reduceMotion = NSWorkspace.shared.accessibilityDisplayShouldReduceMotion || !animated
        let isActive = isEnabled && (isHovering || isHighlighted)
        let hoverTarget: Float = isHighlighted ? 0.22 : ((isHovering && isEnabled) ? 0.12 : 0.0)
        let dark = effectiveAppearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua
        let defaultGlow = dark ? NSColor.white : NSColor.black
        let glowColor = (restingGlowColor ?? defaultGlow).usingColorSpace(.deviceRGB) ?? defaultGlow
        let hoverFillColor = (dark ? NSColor.white : NSColor.black).withAlphaComponent(dark ? 0.12 : 0.08)

        let baseGlowOpacity: Float = (restingGlowColor == nil || !isEnabled) ? 0.0 : 0.24
        let targetShadowOpacity: Float = isActive ? (isHighlighted ? 0.30 : 0.20) : baseGlowOpacity
        let targetShadowRadius: CGFloat = isActive ? 6 : (restingGlowColor == nil ? 0 : 4)
        let targetShadowOffset = CGSize(width: 0, height: isActive ? -1.0 : (restingGlowColor == nil ? 0 : -0.4))
        let scale: CGFloat = isActive ? 1.02 : 1.0
        let lift: CGFloat = isActive ? -0.7 : 0.0
        var transform = CATransform3DIdentity
        transform = CATransform3DTranslate(transform, 0, lift, 0)
        transform = CATransform3DScale(transform, scale, scale, 1.0)

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        layer?.shadowColor = glowColor.cgColor
        hoverLayer.backgroundColor = hoverFillColor.cgColor
        CATransaction.commit()

        if reduceMotion {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            hoverLayer.opacity = hoverTarget
            layer?.transform = transform
            layer?.shadowOpacity = targetShadowOpacity
            layer?.shadowRadius = targetShadowRadius
            layer?.shadowOffset = targetShadowOffset
            CATransaction.commit()
        } else {
            animateLayer(hoverLayer, keyPath: "opacity", to: hoverTarget, preset: .microBounce, reduceMotion: false, basicDuration: 0.12)
            animateLayer(layer, keyPath: "transform", to: transform, preset: .microBounce, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowOpacity", to: targetShadowOpacity, preset: .microBounce, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowRadius", to: targetShadowRadius, preset: .microBounce, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowOffset", to: targetShadowOffset, preset: .microBounce, reduceMotion: false, basicDuration: 0.14)
        }
    }
}

final class MorphingGlassPillControl: NSView {
    private final class PillCircleButton: GlassToolbarButton {
        private let ornamentLayer = CALayer()
        private let ornaments = MaterialEdgeStack()
        private let ambientGlowLayer = CAShapeLayer()
        private let ambientGlowMaskLayer = CAShapeLayer()
        private let ambientGlowColor = NSColor.white
        private let ambientGlowOpacityDark: Float = 0.38
        private let ambientGlowOpacityLight: Float = 0.22
        private let ambientGlowRadiusPxDark: CGFloat = 12.0
        private let ambientGlowRadiusPxLight: CGFloat = 9.0
        var edgeThicknessScale: CGFloat = 1.0 {
            didSet {
                if abs(edgeThicknessScale - oldValue) < 0.01 { return }
                updateOrnaments()
            }
        }
        var hoverChanged: ((Bool) -> Void)?
        private var isHoveringLocal = false
        private var isPressedLocal = false
        private var expandedGlowIntensity: CGFloat = 0

        override init(frame frameRect: NSRect) {
            super.init(frame: frameRect)
            ornamentLayer.masksToBounds = false
            ornaments.attach(to: ornamentLayer)

            ambientGlowLayer.fillColor = NSColor.clear.cgColor
            ambientGlowLayer.strokeColor = nil
            ambientGlowLayer.lineWidth = 0
            ambientGlowLayer.shadowOffset = .zero
            ambientGlowLayer.shadowOpacity = ambientGlowOpacityDark
            ambientGlowLayer.shadowColor = ambientGlowColor.cgColor
            ambientGlowLayer.mask = ambientGlowMaskLayer

            ambientGlowMaskLayer.fillRule = .evenOdd
            ambientGlowMaskLayer.fillColor = NSColor.black.cgColor

            if let root = layer {
                root.insertSublayer(ambientGlowLayer, at: 0)
                root.insertSublayer(ornamentLayer, above: ambientGlowLayer)
            }
        }

        required init?(coder: NSCoder) { fatalError() }

        override func acceptsFirstMouse(for event: NSEvent?) -> Bool { true }

        override func mouseEntered(with event: NSEvent) {
            super.mouseEntered(with: event)
            isHoveringLocal = true
            updateOrnaments()
            hoverChanged?(true)
        }

        override func mouseExited(with event: NSEvent) {
            super.mouseExited(with: event)
            isHoveringLocal = false
            updateOrnaments()
            hoverChanged?(false)
        }

        override func hitTest(_ point: NSPoint) -> NSView? {
            guard isPointInsideCircle(point) else { return nil }
            return super.hitTest(point)
        }

        override func layout() {
            super.layout()
            recenterLayerAnchorIfNeeded()
            updateOrnaments()
        }

        override func viewDidChangeEffectiveAppearance() {
            super.viewDidChangeEffectiveAppearance()
            updateOrnaments()
            needsLayout = true
        }

        override func mouseDown(with event: NSEvent) {
            isPressedLocal = true
            updateOrnaments()
            hoverChanged?(false)
            super.mouseDown(with: event)
            isPressedLocal = false
            updateOrnaments()
        }

        private func isPointInsideCircle(_ point: NSPoint) -> Bool {
            let r = min(bounds.width, bounds.height) / 2
            guard r > 1 else { return false }
            let dx = point.x - bounds.midX
            let dy = point.y - bounds.midY
            return (dx * dx + dy * dy) <= (r * r)
        }

        private func recenterLayerAnchorIfNeeded() {
            guard let layer = layer else { return }
            let anchor = CGPoint(x: 0.5, y: 0.5)
            let position = CGPoint(x: frame.midX, y: frame.midY)
            guard layer.anchorPoint != anchor || layer.position != position else { return }
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            layer.anchorPoint = anchor
            layer.position = position
            CATransaction.commit()
        }

        private func updateOrnaments() {
            let bounds = self.bounds
            let side = min(bounds.width, bounds.height)
            guard side > 2 else { return }

            let radius = side / 2
            let circleBounds = NSRect(
                x: bounds.midX - (side / 2),
                y: bounds.midY - (side / 2),
                width: side,
                height: side
            )

            let scale = max(1.0, window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)
            let isDark = effectiveAppearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua
            let ambientRadiusPx = isDark ? ambientGlowRadiusPxDark : ambientGlowRadiusPxLight
            let baseAmbientOpacity = isDark ? ambientGlowOpacityDark : ambientGlowOpacityLight
            let ambientOpacity = min(1.0, baseAmbientOpacity * Float(expandedGlowIntensity))
            let glowPadding = max(6.0, (ambientRadiusPx / scale) * 2.4)
            let glowBounds = bounds.insetBy(dx: -glowPadding, dy: -glowPadding)

            let maskPath = CGPath(ellipseIn: circleBounds, transform: nil)
            let edgePx = (1.0 / scale) * max(1.0, edgeThicknessScale)
            let maxInset = max(0.0, radius - 0.5)
            let innerInset = min(edgePx, maxInset)
            let innerInset2 = min(edgePx * 2.0, maxInset)
            let outerRect = circleBounds
            let outerInnerRect = circleBounds.insetBy(dx: innerInset, dy: innerInset)
            let innerOuterRect = outerInnerRect
            let innerInnerRect = circleBounds.insetBy(dx: innerInset2, dy: innerInset2)
            let outerPath = CGPath(ellipseIn: outerRect, transform: nil)
            let outerInnerPath = CGPath(ellipseIn: outerInnerRect, transform: nil)
            let innerOuterPath = CGPath(ellipseIn: innerOuterRect, transform: nil)
            let innerInnerPath = CGPath(ellipseIn: innerInnerRect, transform: nil)
            let outerBandPath = MaterialEdgeStack.ringPath(outer: outerPath, inner: outerInnerPath)
            let innerBandPath = MaterialEdgeStack.ringPath(outer: innerOuterPath, inner: innerInnerPath)
            let bands = ToolbarOutlineTokens.edgeBands(for: currentEdgeState())
            let glowCircleBounds = circleBounds.offsetBy(dx: glowPadding, dy: glowPadding)
            let glowCirclePath = CGPath(ellipseIn: glowCircleBounds, transform: nil)
            let glowMaskPath: CGMutablePath = {
                let path = CGMutablePath()
                path.addRect(CGRect(origin: .zero, size: glowBounds.size))
                path.addPath(glowCirclePath)
                return path
            }()

            CATransaction.begin()
            CATransaction.setDisableActions(true)
            ambientGlowLayer.frame = glowBounds
            ambientGlowLayer.contentsScale = scale
            ambientGlowLayer.path = glowCirclePath
            ambientGlowLayer.shadowPath = glowCirclePath
            ambientGlowLayer.shadowRadius = max(0.5, ambientRadiusPx / scale)
            ambientGlowLayer.shadowOpacity = ambientOpacity
            ambientGlowLayer.shadowColor = ambientGlowColor.cgColor
            ambientGlowLayer.isHidden = ambientOpacity < 0.01
            ambientGlowMaskLayer.frame = ambientGlowLayer.bounds
            ambientGlowMaskLayer.contentsScale = scale
            ambientGlowMaskLayer.path = glowMaskPath
            ornamentLayer.frame = bounds
            ornaments.setContentsScale(scale)
            ornaments.setFrames(bounds: ornamentLayer.bounds)
            ornaments.maskLayer.path = maskPath
            ornaments.applyEdgeStyle(outerBand: bands.outer, innerRim: bands.inner)
            ornaments.outerBandLayer.path = outerBandPath
            ornaments.innerBandLayer.path = innerBandPath
            CATransaction.commit()

            setCornerRadius(radius)
        }

        private func currentEdgeState() -> GlassCardKit.State {
            if !isEnabled { return .disabled }
            if isPressedLocal { return .pressed }
            if isHoveringLocal { return .hover }
            return .normal
        }

        func setOrnamentOpacity(_ opacity: CGFloat) {
            let clamped = max(0.0, min(1.0, opacity))
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            ornamentLayer.opacity = Float(clamped)
            ornamentLayer.isHidden = clamped < 0.01
            CATransaction.commit()
        }

        func setExpandedGlow(intensity: CGFloat) {
            let clamped = max(0.0, min(1.0, intensity))
            if abs(clamped - expandedGlowIntensity) < 0.01 { return }
            expandedGlowIntensity = clamped
            updateOrnaments()
        }
    }

    private final class OrnamentOverlayView: NSView {
        override func hitTest(_ point: NSPoint) -> NSView? { nil }
    }

    private let backgroundView: NSView
    var stylingBackgroundView: NSView { backgroundView }
    private let ornamentOverlayView = OrnamentOverlayView(frame: .zero)
    private let edgeOrnaments = MaterialEdgeStack()
    private let pillFillLayer = CAGradientLayer()
    private let pillSheenLayer = CAGradientLayer()

    private let shapeMaskLayer = CAShapeLayer()
    private let hoverLayer = CAShapeLayer()
    private let strokeGroupLayer = CALayer()
    private let seamSmudgeMaskLayer = CAGradientLayer()
    private let rimDarkLayer = CAShapeLayer()
    private let rimLightLayer = CAShapeLayer()
    private let strokeLayer = CAShapeLayer()
    private let innerStrokeLayer = CAShapeLayer()
    private let dispersionLayer = CAGradientLayer()
    private let dispersionMask = CAShapeLayer()
    private var tracking: NSTrackingArea?

    // Robust hover detection: AppKit can miss `mouseEntered` on fast passes or during layout churn.
    // We poll mouse position in screen coordinates and detect segment-rect crossings.
    private var hoverPollTimer: Timer?
    private var hoverReconcileWorkItem: DispatchWorkItem?
    private var lastMouseScreenPoint: NSPoint?
    private var lastCrossingTriggerTime: TimeInterval = 0

    private var isHovering = false
    private var isPressed = false
    private var isExpanded = false
    private var lastOutlineState: GlassCardKit.State = .normal
    private var morphProgress: CGFloat = 0
    private var morphVelocity: CGFloat = 0
    private var morphTarget: CGFloat = 0
    private var morphTickTimer: Timer?
    private var morphLastTick: CFTimeInterval = 0

    // Content (collapsed state): single compositional unit (icon+text inline).
    private let pillLabel = NSTextField(labelWithString: "")
    private let pillLeadingIconView = NSImageView(frame: .zero)
    private let pillTrailingIconView = NSImageView(frame: .zero)
    private let pillIconSpacing: CGFloat = 4
    private var pillIconPointSize: CGFloat = 14

    // Expanded state hit targets + icons.
    private var circleButtons: [NSButton] = []
    private var circleIconViews: [NSImageView] = []
    private var circleIconPointSizeCurrent: CGFloat = 13
    private var circleButtonLabels: [String] = []

    var mirroredHorizontally = false {
        didSet {
            updateStyle()
            updatePaths(animated: false)
            layoutContent(animated: false)
        }
    }
    var pathAnimationPreset: SpringPreset = .soft
    var pathAnimationDuration: CFTimeInterval = 0.28

    var reduceMotionProvider: (() -> Bool)?
    var backgroundProvider: ((CGRect, CGFloat) -> CGImage?)? {
        didSet {
            if let card = backgroundView as? GlassCardView {
                card.backgroundProvider = backgroundProvider
            }
        }
    }

    // Allows the host to theme the pill background using the same pipeline as the embedded search bar.
    // Must not mutate geometry/animation; only appearance (tint/material).
    var backgroundThemeApplier: ((NSView) -> Void)? {
        didSet {
            backgroundThemeApplier?(backgroundView)
        }
    }
    // Foreground resolver shared with the search bar/toolbar pipeline.
    var foregroundColorResolver: ((ForegroundRole) -> NSColor)?
    var effectiveBackgroundProvider: (() -> NSColor)?
    var onActivate: (() -> Void)?
    // Expanded state: index-aware callback (0 == left-most in visual order).
    var onCirclePressed: ((Int) -> Void)?
    var onExpansionStateChanged: ((Bool) -> Void)?
    var outlineStateChanged: ((GlassCardKit.State) -> Void)?
    var circleHoverChanged: ((NSButton, Bool) -> Void)?
    var toolbarOutlineState: GlassCardKit.State { currentState() }
    private var symmetryDebugEnabled: Bool {
        ProcessInfo.processInfo.environment["ARXIV_PILL_SYMMETRY_DEBUG"] == "1"
    }
    private let expandedCircleCount: Int = 6
    private var collapsedCapsuleHeightScale: CGFloat = 1.0
    private var edgeThicknessScale: CGFloat = 1.0
    private let collapsedCapsuleSideExtensionRatio: CGFloat = 0.10
    private let expandedCircleSpacingRatio: CGFloat = 0.28
    // Extra horizontal inset for expanded circles to avoid overlap in narrow layouts.
    private var expandedCircleInsetLeft: CGFloat = 0
    private var expandedCircleInsetRight: CGFloat = 0
    private let expandedCircleInsetEpsilon: CGFloat = 0.25
    // Keep the expanded pill stable while the cursor hovers near the buttons.
    private let expandedHoverPaddingX: CGFloat = 18
    private let expandedHoverPaddingY: CGFloat = 14

    private var baseConfig = GlassCardKit.GlassCardConfig()
    private let rimStyle = GlassCardKit.BorderStyle.clearRim
    private static let suppressedBorderStyle = GlassCardKit.BorderStyle(rimWidth: 0,
                                                                        outerWidth: 0,
                                                                        innerWidth: 0,
                                                                        rimLightAlpha: 0,
                                                                        rimDarkAlpha: 0,
                                                                        outerAlpha: 0,
                                                                        innerAlpha: 0,
                                                                        dispersionAlpha: 0)

    override init(frame frameRect: NSRect) {
        var config = GlassCardKit.GlassCardConfig()
        baseConfig = config
        config.borderStyle = Self.suppressedBorderStyle

        // Match the search bar's rendering pipeline: use an effect view background.
        // The pill's animations are driven by masks/strokes on this view's layer, so only the
        // underlying background implementation changes.
        if #available(macOS 26.0, *) {
            let v = PassthroughGlassEffectView(frame: .zero)
            v.style = .regular
            v.translatesAutoresizingMaskIntoConstraints = true
            backgroundView = v
        } else {
            let v = PassthroughVisualEffectView(frame: .zero)
            v.material = .hudWindow
            v.blendingMode = .withinWindow
            v.state = .active
            v.isEmphasized = true
            v.translatesAutoresizingMaskIntoConstraints = true
            v.wantsLayer = true
            v.layer?.masksToBounds = true
            if #available(macOS 10.13, *) {
                v.layer?.cornerCurve = .continuous
            }
            backgroundView = v
        }
        super.init(frame: frameRect)

        wantsLayer = true
        layer?.masksToBounds = false

        backgroundView.translatesAutoresizingMaskIntoConstraints = true
        backgroundView.wantsLayer = true
        addSubview(backgroundView)

        ornamentOverlayView.translatesAutoresizingMaskIntoConstraints = true
        ornamentOverlayView.wantsLayer = true
        ornamentOverlayView.layer?.masksToBounds = false
        addSubview(ornamentOverlayView)

        pillLabel.translatesAutoresizingMaskIntoConstraints = true
        pillLabel.wantsLayer = true
        pillLabel.isEditable = false
        pillLabel.isSelectable = false
        pillLabel.isBezeled = false
        pillLabel.isBordered = false
        pillLabel.drawsBackground = false
        pillLabel.lineBreakMode = .byTruncatingTail
        addSubview(pillLabel)

        pillLeadingIconView.translatesAutoresizingMaskIntoConstraints = true
        pillLeadingIconView.wantsLayer = true
        pillLeadingIconView.imageAlignment = .alignCenter
        pillLeadingIconView.imageScaling = .scaleProportionallyDown
        addSubview(pillLeadingIconView)

        pillTrailingIconView.translatesAutoresizingMaskIntoConstraints = true
        pillTrailingIconView.wantsLayer = true
        pillTrailingIconView.imageAlignment = .alignCenter
        pillTrailingIconView.imageScaling = .scaleProportionallyDown
        addSubview(pillTrailingIconView)

        shapeMaskLayer.fillColor = NSColor.black.cgColor

        hoverLayer.fillColor = NSColor.white.withAlphaComponent(0.12).cgColor
        hoverLayer.opacity = 0

        // Material edge bands: outer attenuation + inner rim lift.
        if let ornamentLayer = ornamentOverlayView.layer {
            edgeOrnaments.attach(to: ornamentLayer)
        }

        pillFillLayer.startPoint = CGPoint(x: 0.5, y: 1.0)
        pillFillLayer.endPoint = CGPoint(x: 0.5, y: 0.0)
        pillFillLayer.locations = [0.0, 1.0]
        pillFillLayer.opacity = 1.0

        pillSheenLayer.startPoint = CGPoint(x: 0.5, y: 1.0)
        pillSheenLayer.endPoint = CGPoint(x: 0.5, y: 0.0)
        pillSheenLayer.locations = [0.0, 0.55, 1.0]
        pillSheenLayer.opacity = 1.0

        // Smudge/erase the stitched-midline seam on stroked layers without changing geometry.
        // Implemented as a narrow, soft transparent band at x=0.5 in mask coordinates.
        seamSmudgeMaskLayer.startPoint = CGPoint(x: 0.0, y: 0.5)
        seamSmudgeMaskLayer.endPoint = CGPoint(x: 1.0, y: 0.5)
        seamSmudgeMaskLayer.colors = [
            NSColor.white.cgColor,
            NSColor.white.cgColor,
            NSColor.clear.cgColor,
            NSColor.white.cgColor,
            NSColor.white.cgColor,
        ]
        seamSmudgeMaskLayer.locations = [0.0, 0.48, 0.5, 0.52, 1.0]
        seamSmudgeMaskLayer.opacity = 1.0
        strokeGroupLayer.mask = seamSmudgeMaskLayer

        rimDarkLayer.fillColor = NSColor.clear.cgColor
        rimDarkLayer.lineJoin = .round
        rimDarkLayer.lineCap = .round

        rimLightLayer.fillColor = NSColor.clear.cgColor
        rimLightLayer.lineJoin = .round
        rimLightLayer.lineCap = .round

        strokeLayer.fillColor = NSColor.clear.cgColor
        strokeLayer.lineJoin = .round
        strokeLayer.lineCap = .round

        innerStrokeLayer.fillColor = NSColor.clear.cgColor
        innerStrokeLayer.lineJoin = .round
        innerStrokeLayer.lineCap = .round

        dispersionLayer.startPoint = CGPoint(x: 0.0, y: 0.5)
        dispersionLayer.endPoint = CGPoint(x: 1.0, y: 0.5)
        dispersionLayer.mask = dispersionMask

        if let glassLayer = backgroundView.layer {
            glassLayer.mask = shapeMaskLayer

            glassLayer.addSublayer(pillFillLayer)
            glassLayer.addSublayer(pillSheenLayer)

            glassLayer.addSublayer(strokeGroupLayer)
            strokeGroupLayer.addSublayer(rimDarkLayer)
            strokeGroupLayer.addSublayer(rimLightLayer)
            glassLayer.addSublayer(dispersionLayer)
            strokeGroupLayer.addSublayer(strokeLayer)
            strokeGroupLayer.addSublayer(innerStrokeLayer)
            glassLayer.addSublayer(hoverLayer)
        }

        updateStyle()
        updateForEffectiveAppearance()
        updatePaths(animated: false)
        layoutContent(animated: false)
        updateContentVisibility(animated: false)
        updateInteraction(animated: false)
    }

    private func pixelAlignedRect(_ rect: NSRect) -> NSRect {
        let scale = max(1.0, window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)
        let minX = round(rect.minX * scale) / scale
        let minY = round(rect.minY * scale) / scale
        let maxX = round(rect.maxX * scale) / scale
        let maxY = round(rect.maxY * scale) / scale
        return NSRect(x: minX, y: minY, width: max(0, maxX - minX), height: max(0, maxY - minY))
    }

    required init?(coder: NSCoder) { fatalError() }

    deinit {
        stopRobustHoverDetection()
        stopMorphTicker()
    }

    func applyConfig(_ config: GlassCardKit.GlassCardConfig) {
        baseConfig = config
        applyConfigForState()
        updateForEffectiveAppearance()
    }

    func updateTint(_ tint: NSColor?) {
        baseConfig.tint = tint
        applyConfigForState()
        updateForEffectiveAppearance()
    }

    private func currentState() -> GlassCardKit.State {
        if isPressed { return .pressed }
        if isHovering { return .hover }
        return .normal
    }

    private func applyConfigForState() {
        var config = baseConfig
        config.cornerRadius = max(6, bounds.height / 2)
        let state = currentState()
        config.state = state
        if state != lastOutlineState {
            lastOutlineState = state
            outlineStateChanged?(state)
        }
        config.borderStyle = Self.suppressedBorderStyle
        if let card = backgroundView as? GlassCardView {
            card.updateConfig(config)
        } else {
            // The effect view background is themed by the host (embedded search bar theme).
            backgroundThemeApplier?(backgroundView)
        }
        updateStyle()
    }

    override func layout() {
        super.layout()
        backgroundView.frame = bounds
        ornamentOverlayView.frame = bounds
        shapeMaskLayer.frame = bounds
        updatePaths(animated: false)
        layoutContent(animated: false)
        applyConfigForState()
    }

    override func viewDidMoveToWindow() {
        super.viewDidMoveToWindow()
        // Ensure subview-backed layers have their correct initial visibility once attached.
        updateContentVisibility(animated: false)

        if window == nil {
            stopRobustHoverDetection()
            stopMorphTicker()
            lastMouseScreenPoint = nil
        } else {
            // Full-screen transitions can reparent views; reapply appearance-dependent styling.
            applyConfigForState()
            updateForEffectiveAppearance()
            startRobustHoverDetectionIfNeeded()
            syncHoverFromCurrentMouseLocation(animated: false)
        }
    }

    private func startRobustHoverDetectionIfNeeded() {
        guard hoverPollTimer == nil else { return }
        // 60Hz is enough for responsiveness while keeping CPU reasonable.
        let timer = Timer(timeInterval: 1.0 / 60.0, repeats: true) { [weak self] _ in
            self?.pollMouseAndDetectCrossing()
        }
        timer.tolerance = 0.01
        hoverPollTimer = timer
        RunLoop.main.add(timer, forMode: .common)

        // Prime last point immediately to avoid a giant first segment after pauses.
        lastMouseScreenPoint = NSEvent.mouseLocation
    }

    private func stopRobustHoverDetection() {
        hoverReconcileWorkItem?.cancel()
        hoverReconcileWorkItem = nil
        hoverPollTimer?.invalidate()
        hoverPollTimer = nil
    }

    private func pollMouseAndDetectCrossing() {
        guard window != nil else { return }
        let p = NSEvent.mouseLocation
        detectCrossing(usingScreenPoint: p)
        lastMouseScreenPoint = p
    }

    private func pillScreenRect() -> NSRect? {
        guard let w = window, !isHidden, alphaValue > 0.01 else { return nil }
        // Bounds -> window coords -> screen coords.
        let rectInWindow = convert(bounds, to: nil)
        return w.convertToScreen(rectInWindow)
    }

    private func detectCrossing(usingScreenPoint point: NSPoint) {
        guard let rect = pillScreenRect() else { return }

        // If we are already hovering/pressed/expanded, tracking areas should keep us correct.
        // Still record the last point to keep segment math stable.
        let now = ProcessInfo.processInfo.systemUptime
        let last = lastMouseScreenPoint

        // Direct hit.
        if rect.contains(point) {
            triggerHoverFromCrossing(animated: true, now: now)
            return
        }

        // Segment crossing hit (fast pass between samples).
        if let last, segmentIntersectsRect(a: last, b: point, rect: rect) {
            triggerHoverFromCrossing(animated: true, now: now)
        }
    }

    private func triggerHoverFromCrossing(animated: Bool, now: TimeInterval) {
        // Throttle: avoid retriggering continuously while the cursor jitter-crosses the boundary.
        if now - lastCrossingTriggerTime < 0.10 {
            return
        }
        lastCrossingTriggerTime = now

        // Always trigger the expand animation on a crossing event, even if the cursor is no longer inside.
        if !isHovering {
            isHovering = true
            setExpanded(true, animated: animated)
            updateInteraction(animated: animated)
        } else if !isExpanded {
            setExpanded(true, animated: animated)
            updateInteraction(animated: animated)
        }

        // After a short hold (enough for the animation to be visible), reconcile to the true hover state.
        hoverReconcileWorkItem?.cancel()
        let hold = max(0.12, min(0.35, pathAnimationDuration))
        let work = DispatchWorkItem { [weak self] in
            self?.syncHoverFromCurrentMouseLocation(animated: true)
        }
        hoverReconcileWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + hold, execute: work)
    }

    private func segmentIntersectsRect(a: NSPoint, b: NSPoint, rect: NSRect) -> Bool {
        if rect.contains(a) || rect.contains(b) { return true }

        // Fast reject using bounding boxes.
        let minX = min(a.x, b.x)
        let maxX = max(a.x, b.x)
        let minY = min(a.y, b.y)
        let maxY = max(a.y, b.y)
        if maxX < rect.minX || minX > rect.maxX || maxY < rect.minY || minY > rect.maxY {
            return false
        }

        let r1 = NSPoint(x: rect.minX, y: rect.minY)
        let r2 = NSPoint(x: rect.maxX, y: rect.minY)
        let r3 = NSPoint(x: rect.maxX, y: rect.maxY)
        let r4 = NSPoint(x: rect.minX, y: rect.maxY)

        return segmentsIntersect(a1: a, a2: b, b1: r1, b2: r2)
            || segmentsIntersect(a1: a, a2: b, b1: r2, b2: r3)
            || segmentsIntersect(a1: a, a2: b, b1: r3, b2: r4)
            || segmentsIntersect(a1: a, a2: b, b1: r4, b2: r1)
    }

    private func segmentsIntersect(a1: NSPoint, a2: NSPoint, b1: NSPoint, b2: NSPoint) -> Bool {
        func orientation(_ p: NSPoint, _ q: NSPoint, _ r: NSPoint) -> Int {
            let val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y)
            if abs(val) < 1e-9 { return 0 }
            return (val > 0) ? 1 : 2
        }
        func onSegment(_ p: NSPoint, _ q: NSPoint, _ r: NSPoint) -> Bool {
            q.x <= max(p.x, r.x) + 1e-9 && q.x + 1e-9 >= min(p.x, r.x)
                && q.y <= max(p.y, r.y) + 1e-9 && q.y + 1e-9 >= min(p.y, r.y)
        }

        let o1 = orientation(a1, a2, b1)
        let o2 = orientation(a1, a2, b2)
        let o3 = orientation(b1, b2, a1)
        let o4 = orientation(b1, b2, a2)

        if o1 != o2 && o3 != o4 { return true }
        if o1 == 0 && onSegment(a1, b1, a2) { return true }
        if o2 == 0 && onSegment(a1, b2, a2) { return true }
        if o3 == 0 && onSegment(b1, a1, b2) { return true }
        if o4 == 0 && onSegment(b1, a2, b2) { return true }
        return false
    }

    func syncHoverFromCurrentMouseLocation(animated: Bool) {
        guard let w = window else { return }
        let locInWindow = w.mouseLocationOutsideOfEventStream
        let p = convert(locInWindow, from: nil)
        let inside = pointIsInsideHoverRegion(p)

        if inside {
            if !isHovering {
                isHovering = true
                setExpanded(true, animated: animated)
                updateInteraction(animated: animated)
            }
        } else {
            if isHovering || isPressed {
                isHovering = false
                isPressed = false
                setExpanded(false, animated: animated)
                updateInteraction(animated: animated)
            }
        }
    }

    private func pointIsInsideVisibleShape(_ point: NSPoint) -> Bool {
        guard !isHidden, alphaValue > 0.01 else { return false }
        guard bounds.contains(point) else { return false }
        guard let path = shapeMaskLayer.presentation()?.path ?? shapeMaskLayer.path else {
            return bounds.contains(point)
        }
        return path.contains(point)
    }

    private func pointIsInsideHoverRegion(_ point: NSPoint) -> Bool {
        guard !isHidden, alphaValue > 0.01 else { return false }
        if isExpanded || morphProgress > 0.5 {
            let hoverRect = bounds.insetBy(dx: -expandedHoverPaddingX, dy: -expandedHoverPaddingY)
            if hoverRect.contains(point) { return true }
        }
        return pointIsInsideVisibleShape(point)
    }

    override func viewDidChangeEffectiveAppearance() {
        super.viewDidChangeEffectiveAppearance()
        applyConfigForState()
        updateForEffectiveAppearance()
    }

    override func hitTest(_ point: NSPoint) -> NSView? {
        // Expanded state: prioritize the explicit circular button hit targets.
        // This avoids missed clicks during transient mask/path animation states.
        if morphProgress >= 0.78 {
            for b in circleButtons {
                let local = b.convert(point, from: self)
                if b.hitTest(local) != nil { return b }
            }
        }

        // Collapsed (or non-button area): don't intercept clicks in the rectangular bounds when
        // the visible shape is smaller (capsule corners).
        guard pointIsInsideVisibleShape(point) else { return nil }
        return self
    }

    override func updateTrackingAreas() {
        super.updateTrackingAreas()
        if let tracking { removeTrackingArea(tracking) }
        let opts: NSTrackingArea.Options = [.mouseEnteredAndExited, .activeAlways, .inVisibleRect]
        let area = NSTrackingArea(rect: bounds, options: opts, owner: self, userInfo: nil)
        addTrackingArea(area)
        tracking = area
    }

    override func mouseEntered(with event: NSEvent) {
        let p = convert(event.locationInWindow, from: nil)
        guard pointIsInsideHoverRegion(p) else { return }
        isHovering = true
        setExpanded(true, animated: true)
        updateInteraction(animated: true)
    }

    override func mouseExited(with event: NSEvent) {
        let p = convert(event.locationInWindow, from: nil)
        if pointIsInsideHoverRegion(p) { return }
        isHovering = false
        isPressed = false
        setExpanded(false, animated: true)
        updateInteraction(animated: true)
    }

    override func mouseDown(with event: NSEvent) {
        let p = convert(event.locationInWindow, from: nil)
        guard pointIsInsideVisibleShape(p) else { return }
        isPressed = true
        updateInteraction(animated: true)
    }

    override func mouseUp(with event: NSEvent) {
        let wasPressed = isPressed
        isPressed = false
        updateInteraction(animated: true)
        guard wasPressed else { return }
        let point = convert(event.locationInWindow, from: nil)
        if pointIsInsideVisibleShape(point) {
            // Collapsed pill acts as a single control.
            if !isExpanded {
                onActivate?()
            }
        }
    }

    func setExpanded(_ expanded: Bool, animated: Bool) {
        guard expanded != isExpanded else { return }
        isExpanded = expanded
        setMorphTarget(expanded ? 1.0 : 0.0, animated: animated)
        updateContentVisibility(animated: animated)
        // Ensure layout stays in sync with the geometry end state.
        layoutContent(animated: false)

        // Host layout can depend on the pill's visual state (e.g. after animations).
        // Re-center deterministically on every expand/collapse to avoid accumulating drift.
        onExpansionStateChanged?(expanded)
    }

    private func setMorphTarget(_ target: CGFloat, animated: Bool) {
        let reduceMotion = (reduceMotionProvider?() ?? false)
            || NSWorkspace.shared.accessibilityDisplayShouldReduceMotion
            || !animated

        morphTarget = target

        if reduceMotion {
            morphProgress = target
            morphVelocity = 0
            stopMorphTicker()
            updatePaths(animated: false)
            updateContentVisibility(animated: false)
            return
        }

        let spec = springSpec(for: pathAnimationPreset)
        let dir: CGFloat = (morphTarget >= morphProgress) ? 1.0 : -1.0
        morphVelocity += spec.initialVelocity * dir
        morphVelocity = clamp(morphVelocity, -4.0, 4.0)
        startMorphTickerIfNeeded()
    }

    private func startMorphTickerIfNeeded() {
        guard morphTickTimer == nil else { return }
        morphLastTick = monotonicNow()
        let timer = Timer(timeInterval: 1.0 / 120.0, repeats: true) { [weak self] _ in
            self?.tickMorph()
        }
        timer.tolerance = 0.002
        morphTickTimer = timer
        RunLoop.main.add(timer, forMode: .common)
    }

    private func stopMorphTicker() {
        morphTickTimer?.invalidate()
        morphTickTimer = nil
        morphLastTick = 0
    }

    private func tickMorph() {
        let now = monotonicNow()
        let dt = CGFloat(max(1.0 / 240.0, min(1.0 / 30.0, now - (morphLastTick > 0 ? morphLastTick : now))))
        morphLastTick = now

        let spec = springSpec(for: pathAnimationPreset)
        let x = morphProgress
        let v = morphVelocity
        let a = (-spec.damping / spec.mass) * v - (spec.stiffness / spec.mass) * (x - morphTarget)
        let vNext = v + a * dt
        let xNext = x + vNext * dt
        morphVelocity = vNext
        morphProgress = clamp(xNext, -0.2, 1.2)

        updatePaths(animated: false)
        updateContentVisibility(animated: false)

        let posTol: CGFloat = 0.0015
        let velTol: CGFloat = 0.003
        if abs(morphProgress - morphTarget) <= posTol && abs(morphVelocity) <= velTol {
            morphProgress = morphTarget
            morphVelocity = 0
            updatePaths(animated: false)
            updateContentVisibility(animated: false)
            stopMorphTicker()
        }
    }

    private func updateInteraction(animated: Bool) {
        applyConfigForState()
        let reduceMotion = (reduceMotionProvider?() ?? false)
            || NSWorkspace.shared.accessibilityDisplayShouldReduceMotion
            || !animated
        let hoverTarget: Float = 0.0
        let targetShadowOpacity: Float = 0.0
        let targetShadowRadius: CGFloat = 0.0
        let targetShadowOffset = CGSize(width: 0, height: 0)
        let transform = CATransform3DIdentity

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        layer?.shadowColor = NSColor.clear.cgColor
        CATransaction.commit()

        if reduceMotion {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            hoverLayer.opacity = hoverTarget
            layer?.transform = transform
            layer?.shadowOpacity = targetShadowOpacity
            layer?.shadowRadius = targetShadowRadius
            layer?.shadowOffset = targetShadowOffset
            CATransaction.commit()
        } else {
            animateLayer(hoverLayer, keyPath: "opacity", to: hoverTarget, preset: .hoverBounce, reduceMotion: false, basicDuration: 0.12)
            animateLayer(layer, keyPath: "transform", to: transform, preset: .hoverBounce, reduceMotion: false, basicDuration: 0.16)
            animateLayer(layer, keyPath: "shadowOpacity", to: targetShadowOpacity, preset: .hoverBounce, reduceMotion: false, basicDuration: 0.16)
            animateLayer(layer, keyPath: "shadowRadius", to: targetShadowRadius, preset: .hoverBounce, reduceMotion: false, basicDuration: 0.16)
            animateLayer(layer, keyPath: "shadowOffset", to: targetShadowOffset, preset: .hoverBounce, reduceMotion: false, basicDuration: 0.16)
        }
    }

    // Match the shared toolbar/search pipeline: resolve against base + tint, not a pill-local accent.
    private func pillEffectiveBackgroundColor() -> NSColor {
        if let provider = effectiveBackgroundProvider { return provider() }
        return ToolbarForegroundTheme.shared.palette.background
    }

    private func pillForegroundColor() -> NSColor {
        if let resolver = foregroundColorResolver {
            return resolver(.primaryText)
        }
        return toolbarForegroundColor()
    }

    private func updateForEffectiveAppearance() {
        // Collapsed label: SF system typography + dynamic label color.
        let pointSize: CGFloat = 13.5
        let font = resolvedUIFontFromSettings(defaultSize: pointSize, weight: .regular)
        let foreground = pillForegroundColor()

        let iconPoint: CGFloat = 14
        let iconConfig = NSImage.SymbolConfiguration(pointSize: iconPoint, weight: .regular)
        let iconName = "sparkles" // Apple Intelligence-style visual language in SF Symbols.
        let baseIcon = NSImage(systemSymbolName: iconName, accessibilityDescription: nil) ?? NSImage()
        let icon = baseIcon.withSymbolConfiguration(iconConfig) ?? baseIcon
        icon.isTemplate = true
        let mirroredIcon = horizontallyMirroredImage(icon)
        pillLabel.font = font
        pillLabel.textColor = foreground
        pillLabel.stringValue = "Ask Apple Intelligence"
        pillIconPointSize = iconPoint
        pillLeadingIconView.image = icon
        pillTrailingIconView.image = mirroredIcon
        pillLeadingIconView.contentTintColor = foreground
        pillTrailingIconView.contentTintColor = foreground

        if let l = pillLabel.layer {
            l.contentsScale = window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0
        }
        if let l = pillLeadingIconView.layer {
            l.contentsScale = window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0
        }
        if let l = pillTrailingIconView.layer {
            l.contentsScale = window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0
        }

        updateCircleButtonIcons(color: foreground)
        if !circleButtons.isEmpty {
            for button in circleButtons {
                if let pill = button as? PillCircleButton {
                    pill.restingTintColor = nil
                    pill.disabledTintColor = nil
                    pill.contrastBackgroundColor = nil
                    pill.updateTint()
                }
            }
        }
    }

    func refreshForegroundColors() {
        updateForEffectiveAppearance()
    }

    func refreshMaterialTheme() {
        applyConfigForState()
        updateForEffectiveAppearance()
    }

    private func ensureCircleButtonsIfNeeded() {
        guard circleButtons.isEmpty else { return }
        for index in 0..<expandedCircleCount {
            let b = PillCircleButton(frame: .zero)
            b.title = ""
            b.isBordered = false
            b.bezelStyle = .regularSquare
            b.wantsLayer = true
            b.layer?.backgroundColor = NSColor.clear.cgColor
            b.layer?.cornerRadius = 0
            b.edgeThicknessScale = edgeThicknessScale
            b.idleHoverOpacity = 0.0
            b.hoverFillOpacity = 0.0
            b.pressedFillOpacity = 0.0
            b.restingGlowOpacity = 0.0
            b.hoverShadowOpacity = 0.0
            b.pressedShadowOpacity = 0.0
            b.restingShadowRadius = 0.0
            b.hoverShadowRadius = 0.0
            b.pressedShadowRadius = 0.0
            b.restingShadowOffset = .zero
            b.hoverShadowOffset = .zero
            b.pressedShadowOffset = .zero
            b.hoverScale = 1.12
            b.activeScale = 1.04
            b.hoverLift = 0.0
            b.activeLift = 0.0
            b.showsHaloRing = false
            b.showsRestingGlow = false
            b.target = self
            b.action = #selector(circleButtonPressed(_:))
            b.tag = index
            b.setAccessibilityIdentifier("pill.circle.\(index)")
            b.hoverChanged = { [weak self, weak b] hovering in
                guard let self, let button = b else { return }
                self.circleHoverChanged?(button, hovering)
            }

            let iv = NSImageView(frame: .zero)
            iv.imageAlignment = .alignCenter
            iv.imageScaling = .scaleProportionallyDown
            iv.wantsLayer = true
            iv.layer?.anchorPoint = CGPoint(x: 0.5, y: 0.5)
            iv.layer?.contentsScale = window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0

            // Fix launch flash: ensure icon layers start hidden when collapsed.
            if let il = iv.layer {
                CATransaction.begin()
                CATransaction.setDisableActions(true)
                il.opacity = 0.0
                il.transform = CATransform3DTranslate(CATransform3DIdentity, 0, 2.0, 0)
                CATransaction.commit()
            }
            b.addSubview(iv)

            addSubview(b)
            circleButtons.append(b)
            circleIconViews.append(iv)
        }
        for b in circleButtons { b.isEnabled = false }
        updateForEffectiveAppearance()
        updateCircleButtonChrome()
    }

    @objc private func circleButtonPressed(_ sender: Any?) {
        if let b = sender as? NSButton {
            if let onCirclePressed {
                onCirclePressed(b.tag)
                return
            }
        }
        onActivate?()
    }

    func circleButton(at index: Int) -> NSButton? {
        ensureCircleButtonsIfNeeded()
        guard index >= 0, index < circleButtons.count else { return nil }
        return circleButtons[index]
    }

    func updateCircleButtonTooltips(_ labels: [String]) {
        ensureCircleButtonsIfNeeded()
        let normalized = labels.map { raw -> String in
            let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
            return trimmed.isEmpty ? "Ask Apple Intelligence" : trimmed
        }
        let count = min(circleButtons.count, normalized.count)
        circleButtonLabels = normalized
        for i in 0..<count {
            let tooltip = normalized[i]
            circleButtons[i].toolTip = nil
            circleButtons[i].setAccessibilityLabel(tooltip)
        }
        updateCircleButtonIcons(color: pillForegroundColor())
    }

    func circleButtonLabel(for button: NSButton) -> String? {
        guard let idx = circleButtons.firstIndex(where: { $0 === button }) else { return nil }
        guard idx >= 0 && idx < circleButtonLabels.count else { return nil }
        let label = circleButtonLabels[idx].trimmingCharacters(in: .whitespacesAndNewlines)
        return label.isEmpty ? nil : label
    }

    private func updateCircleIconPointSizeIfNeeded(target: CGFloat) {
        let clamped = max(11, min(28, target))
        if abs(clamped - circleIconPointSizeCurrent) < 0.25 { return }
        circleIconPointSizeCurrent = clamped
        updateCircleButtonIcons(color: pillForegroundColor())
    }

    private func updateCircleButtonIcons(color: NSColor) {
        let symbolConfig = NSImage.SymbolConfiguration(pointSize: circleIconPointSizeCurrent, weight: .regular)
        let fallbackSymbols = [
            "doc.text.magnifyingglass",
            "gearshape.2",
            "function",
            "speedometer",
            "checkmark.seal",
            "books.vertical"
        ]
        for (index, iv) in circleIconViews.enumerated() {
            let label = (index < circleButtonLabels.count) ? circleButtonLabels[index] : ""
            let symbolName = symbolNameForCircleLabel(label, fallback: fallbackSymbols[index % fallbackSymbols.count])
            let base = NSImage(systemSymbolName: symbolName, accessibilityDescription: nil)
                ?? NSImage(systemSymbolName: fallbackSymbols[index % fallbackSymbols.count], accessibilityDescription: nil)
                ?? NSImage(systemSymbolName: "circle", accessibilityDescription: nil)
                ?? NSImage()
            let configured = base.withSymbolConfiguration(symbolConfig) ?? base
            configured.isTemplate = true
            iv.image = configured
            iv.contentTintColor = color
        }
    }

    private func symbolNameForCircleLabel(_ label: String, fallback: String) -> String {
        let value = label.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        if value.isEmpty { return fallback }
        if value.contains("summary") || value.contains("contribution") {
            return "doc.text.magnifyingglass"
        }
        if value.contains("method") || value.contains("methodology") || value.contains("assumption")
            || value.contains("approx") || value.contains("bias") {
            return "gearshape.2"
        }
        if value.contains("equation") || value.contains("equations") || value.contains("formula")
            || value.contains("variable") || value.contains("physical") || value.contains("regime") {
            return "function"
        }
        if value.contains("constraint") || value.contains("limit") || value.contains("resolution")
            || value.contains("snr") || value.contains("signal") || value.contains("noise") {
            return "slider.horizontal.3"
        }
        if value.contains("strongest") || value.contains("weakest") || value.contains("follow-up")
            || value.contains("experiment") || value.contains("test") {
            return "star.circle"
        }
        if value.contains("literature") || value.contains("related") || value.contains("read")
            || value.contains("reference") || value.contains("citations") || value.contains("papers") {
            return "books.vertical"
        }
        return fallback
    }

    private func updatePaths(animated _: Bool) {
        let b = bounds
        guard b.width > 4, b.height > 4 else { return }

        updateStyle()
        ensureCircleButtonsIfNeeded()

        let progress = morphProgressForPath()

        // Keep the seam-smudge band roughly constant in physical pixels.
        let scale = max(1.0, window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)
        let halfWidthPx: CGFloat = 1.25 * scale
        let halfWidth = max(0.5, halfWidthPx / max(1.0, b.width))
        let leftStop = max(0.0, 0.5 - halfWidth)
        let rightStop = min(1.0, 0.5 + halfWidth)
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        seamSmudgeMaskLayer.locations = [0.0, NSNumber(value: Double(leftStop)), 0.5, NSNumber(value: Double(rightStop)), 1.0]
        CATransaction.commit()

        let outerInset = max(0.5, rimLightLayer.lineWidth / 2)
        let innerInset = max(0.5, innerStrokeLayer.lineWidth / 2) + 1.0
        // Match Share: let the glass fill reach the visible edge; border ornaments are inset.
        let maskInset: CGFloat = 0.0

        let outerPath = morphPath(in: b, inset: outerInset, progress: progress)
        let innerPath = morphPath(in: b, inset: innerInset, progress: progress)
        let maskPath = morphPath(in: b, inset: maskInset, progress: progress)

        // Material edge bands: 1px outer attenuation + 1px inner rim lift.
        let ornamentMaskPath = morphPath(in: b, inset: 0.0, progress: progress)
        let edgePx = (1.0 / scale) * max(1.0, edgeThicknessScale)
        let maxInset = max(0.0, (min(b.width, b.height) / 2.0) - 0.5)
        let edgeInset = min(edgePx, maxInset)
        let edgeInnerInset = min(edgePx * 2.0, maxInset)
        let outerBandOuterPath = ornamentMaskPath
        let outerBandInnerPath = morphPath(in: b, inset: edgeInset, progress: progress)
        let innerBandOuterPath = outerBandInnerPath
        let innerBandInnerPath = morphPath(in: b, inset: edgeInnerInset, progress: progress)
        let outerBandPath = MaterialEdgeStack.ringPath(outer: outerBandOuterPath, inner: outerBandInnerPath)
        let innerBandPath = MaterialEdgeStack.ringPath(outer: innerBandOuterPath, inner: innerBandInnerPath)

        if let glassLayer = backgroundView.layer {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            pillFillLayer.frame = glassLayer.bounds
            pillSheenLayer.frame = glassLayer.bounds
            shapeMaskLayer.frame = glassLayer.bounds
            hoverLayer.frame = glassLayer.bounds
            strokeGroupLayer.frame = glassLayer.bounds
            seamSmudgeMaskLayer.frame = glassLayer.bounds
            rimDarkLayer.frame = glassLayer.bounds
            rimLightLayer.frame = glassLayer.bounds
            dispersionLayer.frame = glassLayer.bounds
            dispersionMask.frame = glassLayer.bounds
            strokeLayer.frame = glassLayer.bounds
            innerStrokeLayer.frame = glassLayer.bounds
            CATransaction.commit()
        }

        if let ornamentLayer = ornamentOverlayView.layer {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            edgeOrnaments.setFrames(bounds: ornamentLayer.bounds)
            CATransaction.commit()
        }

        applyPath(shapeMaskLayer, path: maskPath)
        applyPath(hoverLayer, path: maskPath)
        applyPath(rimDarkLayer, path: outerPath)
        applyPath(rimLightLayer, path: outerPath)
        applyPath(strokeLayer, path: outerPath)
        applyPath(innerStrokeLayer, path: innerPath)
        applyPath(dispersionMask, path: outerPath)

        applyPath(edgeOrnaments.maskLayer, path: ornamentMaskPath)
        applyPath(edgeOrnaments.outerBandLayer, path: outerBandPath)
        applyPath(edgeOrnaments.innerBandLayer, path: innerBandPath)

        // Fade the seam-smudge mask out as the pill splits.
        let smudgeFade = 1.0 - smoothstep(0.35, 0.9, clamp(progress, 0.0, 1.0))
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        seamSmudgeMaskLayer.opacity = Float(smudgeFade)
        CATransaction.commit()

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        layer?.shadowPath = ornamentMaskPath
        CATransaction.commit()

        if symmetryDebugEnabled {
            let debugRect = b.insetBy(dx: outerInset, dy: outerInset)
            let layout = expandedCircleLayout(in: debugRect, circleCount: expandedCircleCount)
            logSymmetryPairs(leftCenters: layout.left, rightCenters: layout.right, centerX: debugRect.midX)
        }
    }

    private func applyPath(_ layer: CAShapeLayer, path: CGPath) {
        layer.removeAnimation(forKey: "basic_path")
        layer.removeAnimation(forKey: "spring_path")

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        layer.path = path
        CATransaction.commit()
    }

    private func layoutContent(animated: Bool) {
        let b = bounds
        guard b.width > 4, b.height > 4 else { return }
        ensureCircleButtonsIfNeeded()

        // Label centered within the *collapsed* capsule, not the full bounds.
        // This keeps the capsule visually tight around the text without affecting the expanded geometry.
        let contentInset = max(0.5, strokeLayer.lineWidth / 2)
        let capsuleRect = collapsedCapsuleRect(in: b, inset: contentInset)
        let labelSize = pillLabel.fittingSize
        let iconSize = pillIconPointSize
        let totalWidth = iconSize + pillIconSpacing + labelSize.width + pillIconSpacing + iconSize
        let startX = capsuleRect.midX - (totalWidth / 2)
        let iconY = capsuleRect.midY - (iconSize / 2)
        let labelX = startX + iconSize + pillIconSpacing
        let labelY = capsuleRect.midY - (labelSize.height / 2)
        pillLeadingIconView.frame = pixelAlignedRect(NSRect(x: startX, y: iconY, width: iconSize, height: iconSize))
        pillLabel.frame = pixelAlignedRect(NSRect(x: labelX, y: labelY, width: labelSize.width, height: labelSize.height))
        pillTrailingIconView.frame = pixelAlignedRect(NSRect(x: pillLabel.frame.maxX + pillIconSpacing,
                                                             y: iconY,
                                                             width: iconSize,
                                                             height: iconSize))

        // Button frames always reflect the expanded geometry; enablement follows morph progress.
        let outerInset = max(0.5, rimLightLayer.lineWidth / 2)
        let layoutRect = b.insetBy(dx: outerInset, dy: outerInset)
        let layout = expandedCircleLayout(in: layoutRect, circleCount: expandedCircleCount)
        let centers: [CGFloat] = {
            let merged = layout.left + (layout.center.map { [$0] } ?? []) + layout.right
            return merged.sorted()
        }()
        updateCircleIconPointSizeIfNeeded(target: layout.diameter * 0.31)

        for i in 0..<min(circleButtons.count, centers.count) {
            let cx = centers[i]
            let frame = NSRect(x: cx - (layout.diameter / 2), y: layout.y, width: layout.diameter, height: layout.diameter)
            circleButtons[i].frame = pixelAlignedRect(frame)
            circleButtons[i].layer?.cornerRadius = circleButtons[i].bounds.height / 2
            circleIconViews[i].frame = circleButtons[i].bounds.insetBy(dx: max(2, circleButtons[i].bounds.width * 0.22),
                                                                       dy: max(2, circleButtons[i].bounds.height * 0.22))
        }

        if circleButtons.count > centers.count {
            for j in centers.count..<circleButtons.count {
                circleButtons[j].frame = .zero
                circleIconViews[j].frame = .zero
            }
        }

    }

    private func updateContentVisibility(animated _: Bool) {
        ensureCircleButtonsIfNeeded()
        let t = clamp(morphProgress, 0.0, 1.0)
        let labelFade = 1.0 - smoothstep(0.08, 0.38, t)
        let iconFade = smoothstep(0.25, 0.78, t)
        let glowFade = smoothstep(0.55, 1.0, iconFade)
        let labelSlide: CGFloat = -2.4 * (1.0 - labelFade)
        let iconSlide: CGFloat = 2.4 * (1.0 - iconFade)
        let buttonsEnabled = t >= 0.78
        let haloVisible = iconFade > 0.05

        CATransaction.begin()
        CATransaction.setDisableActions(true)

        if let l = pillLabel.layer {
            l.opacity = Float(labelFade)
            l.transform = CATransform3DTranslate(CATransform3DIdentity, 0, labelSlide, 0)
        }
        if let l = pillLeadingIconView.layer {
            l.opacity = Float(labelFade)
            l.transform = CATransform3DTranslate(CATransform3DIdentity, 0, labelSlide, 0)
        }
        if let l = pillTrailingIconView.layer {
            l.opacity = Float(labelFade)
            l.transform = CATransform3DTranslate(CATransform3DIdentity, 0, labelSlide, 0)
        }

        for i in 0..<min(circleButtons.count, circleIconViews.count) {
            circleButtons[i].isEnabled = haloVisible
            circleButtons[i].alphaValue = 1.0
            if let button = circleButtons[i] as? PillCircleButton {
                button.setOrnamentOpacity(iconFade)
                button.setExpandedGlow(intensity: glowFade)
            }
            guard let il = circleIconViews[i].layer else { continue }
            il.opacity = Float(iconFade)
            il.transform = CATransform3DTranslate(CATransform3DIdentity, 0, iconSlide, 0)
        }

        CATransaction.commit()
    }

    func setExpandedCircleInsets(left: CGFloat, right: CGFloat) {
        let clampedLeft = max(0, left)
        let clampedRight = max(0, right)
        if abs(clampedLeft - expandedCircleInsetLeft) < expandedCircleInsetEpsilon,
           abs(clampedRight - expandedCircleInsetRight) < expandedCircleInsetEpsilon {
            return
        }
        expandedCircleInsetLeft = clampedLeft
        expandedCircleInsetRight = clampedRight
        layoutContent(animated: false)
        updatePaths(animated: false)
    }

    func currentExpandedCircleInsets() -> (left: CGFloat, right: CGFloat) {
        (expandedCircleInsetLeft, expandedCircleInsetRight)
    }

    func expandedMaskBounds(forLeftInset left: CGFloat, rightInset right: CGFloat) -> CGRect {
        let rect = bounds
        let layout = expandedCircleLayout(in: rect,
                                          circleCount: expandedCircleCount,
                                          insetLeft: left,
                                          insetRight: right)
        let centers: [CGFloat] = {
            let merged = layout.left + (layout.center.map { [$0] } ?? []) + layout.right
            return merged.sorted()
        }()
        guard let minCenter = centers.first, let maxCenter = centers.last, layout.diameter > 0 else {
            return CGRect(x: rect.midX, y: rect.midY, width: 0, height: 0)
        }
        let minX = minCenter - (layout.diameter / 2)
        let maxX = maxCenter + (layout.diameter / 2)
        return CGRect(x: minX, y: layout.y, width: maxX - minX, height: layout.diameter)
    }

    func maxSymmetricInset(forMinimumCircleDiameter minDiameter: CGFloat) -> CGFloat {
        let rect = bounds
        guard rect.width > 1, rect.height > 1, expandedCircleCount > 0 else { return 0 }
        let diameter = max(2, min(minDiameter, rect.height))
        let count = CGFloat(expandedCircleCount)
        let neededWidth = diameter * (count + ((count - 1) * expandedCircleSpacingRatio))
        let maxInset = max(0, (rect.width - neededWidth) / 2)
        let insetClamp = max(0, (rect.width / 2) - 1)
        if !maxInset.isFinite || !insetClamp.isFinite { return 0 }
        return min(maxInset, insetClamp)
    }

    private func mirroredCompositePath(fromRightHalf right: CGPath, centerX: CGFloat) -> CGPath {
        var t = CGAffineTransform(a: -1, b: 0, c: 0, d: 1, tx: 2 * centerX, ty: 0)
        let left = right.copy(using: &t) ?? right
        let out = CGMutablePath()
        out.addPath(left)
        out.addPath(right)
        return out
    }

    // Morph geometry is driven by a single spring progress value.

    private func clamp(_ value: CGFloat, _ minValue: CGFloat, _ maxValue: CGFloat) -> CGFloat {
        max(minValue, min(maxValue, value))
    }

    private func smoothstep(_ edge0: CGFloat, _ edge1: CGFloat, _ x: CGFloat) -> CGFloat {
        let t = clamp((x - edge0) / max(0.0001, edge1 - edge0), 0.0, 1.0)
        return t * t * (3.0 - 2.0 * t)
    }

    private func easeOutCubic(_ t: CGFloat) -> CGFloat {
        let clamped = clamp(t, 0.0, 1.0)
        let inv = 1.0 - clamped
        return 1.0 - (inv * inv * inv)
    }

    private func morphProgressForPath() -> CGFloat {
        clamp(morphProgress, -0.12, 1.12)
    }

    private func symmetryDebugScale() -> CGFloat {
        max(1.0, window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)
    }

    private func symmetryDebugEpsilon() -> CGFloat {
        0.5 / symmetryDebugScale()
    }

    private func logSymmetryPairs(leftCenters: [CGFloat], rightCenters: [CGFloat], centerX: CGFloat) {
        guard symmetryDebugEnabled, !leftCenters.isEmpty, leftCenters.count == rightCenters.count else { return }
        let epsilon = symmetryDebugEpsilon()
        for pairIndex in 0..<leftCenters.count {
            let leftX = leftCenters[pairIndex]
            let rightX = rightCenters[pairIndex]
            let dxLeft = leftX - centerX
            let dxRight = rightX - centerX
            let sum = dxLeft + dxRight
            let message = String(format: "pair=%d dx_left=%.3f dx_right=%.3f sum=%.3f eps=%.3f",
                                 pairIndex, dxLeft, dxRight, sum, epsilon)
            NSLog("[PillSymmetry] \(message)")
            assert(abs(sum) < epsilon, "Pill symmetry failed: \(message)")
        }
    }

    private func mirroredCenterPairs(centerX: CGFloat,
                                     count: Int,
                                     step: CGFloat) -> (center: CGFloat?, left: [CGFloat], right: [CGFloat]) {
        guard count > 0 else { return (nil, [], []) }
        let hasCenter = (count % 2) == 1
        let pairCount = count / 2
        let offsetBase: CGFloat = hasCenter ? 1.0 : 0.5

        // Source of truth: compute RIGHT side first.
        var rightCenters: [CGFloat] = []
        rightCenters.reserveCapacity(pairCount)
        for pairIndex in 0..<pairCount {
            let dx = (CGFloat(pairIndex) + offsetBase) * step
            rightCenters.append(centerX + dx)
        }

        // Strict geometric mirror across the vertical bisector.
        // x_left = centerX - (x_right - centerX) == 2*centerX - x_right
        let leftCenters = rightCenters.map { xRight in centerX - (xRight - centerX) }
        return (hasCenter ? centerX : nil, leftCenters, rightCenters)
    }

    private func expandedCircleLayout(in rect: CGRect,
                                      circleCount: Int,
                                      insetLeft: CGFloat,
                                      insetRight: CGFloat) -> (center: CGFloat?, left: [CGFloat], right: [CGFloat], diameter: CGFloat, y: CGFloat) {
        guard circleCount > 0 else { return (nil, [], [], 0, rect.midY) }
        let maxInset = max(0, (rect.width / 2) - 1)
        let insetLeft = min(max(0, insetLeft), maxInset)
        let insetRight = min(max(0, insetRight), maxInset)
        let layoutRect = CGRect(x: rect.minX + insetLeft,
                                y: rect.minY,
                                width: rect.width - insetLeft - insetRight,
                                height: rect.height)
        guard layoutRect.width > 1, layoutRect.height > 1 else { return (nil, [], [], 0, rect.midY) }
        let count = CGFloat(circleCount)
        let diameterFromWidth = layoutRect.width / (count + ((count - 1) * expandedCircleSpacingRatio))
        let diameter = max(2, min(layoutRect.height, diameterFromWidth))
        let spacing = max(0, (layoutRect.width - (count * diameter)) / max(1, (count - 1)))
        let step = diameter + spacing
        let pairs = mirroredCenterPairs(centerX: layoutRect.midX, count: circleCount, step: step)
        let y = layoutRect.midY - (diameter / 2)
        return (pairs.center, pairs.left, pairs.right, diameter, y)
    }

    private func expandedCircleLayout(in rect: CGRect,
                                      circleCount: Int) -> (center: CGFloat?, left: [CGFloat], right: [CGFloat], diameter: CGFloat, y: CGFloat) {
        expandedCircleLayout(in: rect,
                             circleCount: circleCount,
                             insetLeft: expandedCircleInsetLeft,
                             insetRight: expandedCircleInsetRight)
    }

    private func morphPath(in bounds: CGRect, inset: CGFloat, progress: CGFloat) -> CGPath {
        let rect = bounds.insetBy(dx: inset, dy: inset)
        guard rect.width > 1, rect.height > 1 else { return CGPath(rect: rect, transform: nil) }

        let t = clamp(progress, -0.15, 1.15)
        let tClamped = clamp(t, 0.0, 1.0)
        let tEase = easeOutCubic(tClamped)
        let overshoot = max(0.0, t - 1.0)
        var spread = tEase + (overshoot * 0.18)
        if expandedCircleInsetLeft > 0.01 || expandedCircleInsetRight > 0.01 {
            spread = min(spread, 1.0)
        }
        let sizeBump = 1.0 + (overshoot * 0.08)
        let circleAppear = smoothstep(0.12, 0.6, tClamped)

        let layout = expandedCircleLayout(in: rect, circleCount: expandedCircleCount)
        let centers: [CGFloat] = {
            let merged = layout.left + (layout.center.map { [$0] } ?? []) + layout.right
            return merged.sorted()
        }()

        let out = CGMutablePath()
        let capsule = collapsedCapsuleRect(in: bounds, inset: inset)
        let capsuleFade = 1.0 - smoothstep(0.35, 0.9, tClamped)
        let capsuleWidth = max(0.0, capsule.width * capsuleFade)
        if capsuleWidth > 1.0 {
            let capsuleRect = CGRect(x: rect.midX - (capsuleWidth / 2),
                                     y: capsule.minY,
                                     width: capsuleWidth,
                                     height: capsule.height)
            out.addRoundedRect(in: capsuleRect,
                               cornerWidth: capsuleRect.height / 2,
                               cornerHeight: capsuleRect.height / 2)
        }

        if circleAppear > 0.001 {
            let diameter = max(0.0, layout.diameter * circleAppear * (0.9 + (0.1 * tEase)) * sizeBump)
            let circleY = rect.midY - (diameter / 2)
            if diameter > 0.5 {
                for cx in centers {
                    let centerX = rect.midX + (cx - rect.midX) * spread
                    let x = centerX - (diameter / 2)
                    out.addEllipse(in: CGRect(x: x, y: circleY, width: diameter, height: diameter))
                }
            }
        }
        return out
    }

    private func collapsedCapsuleRect(in bounds: CGRect, inset: CGFloat) -> CGRect {
        let rect = bounds.insetBy(dx: inset, dy: inset)
        guard rect.width > 1, rect.height > 1 else { return rect }

        let capsuleHeight = max(2.0, rect.height * collapsedCapsuleHeightScale)
        let capsuleY = rect.midY - (capsuleHeight / 2)
        let capsuleRect = CGRect(x: rect.minX, y: capsuleY, width: rect.width, height: capsuleHeight)

        // Apple-like end padding: tight, but not cramped.
        // Keep padding stable across minor font rendering differences.
        let labelWidth = max(0, pillLabel.fittingSize.width)
        let minEndPadding: CGFloat = max(14, capsuleHeight * 0.55)
        let desiredWidth = labelWidth + (2 * minEndPadding)

        // Clamp to available space and to a reasonable minimum so the pill never looks “pinched”.
        let minWidth = max(capsuleHeight * 2.6, 140)
        let baseWidth = min(capsuleRect.width, max(minWidth, desiredWidth))
        let extendedWidth = min(capsuleRect.width,
                                baseWidth * (1.0 + (2.0 * collapsedCapsuleSideExtensionRatio)))
        let x = capsuleRect.midX - (extendedWidth / 2)
        return CGRect(x: x, y: capsuleRect.minY, width: extendedWidth, height: capsuleRect.height)
    }

    func setCollapsedCapsuleHeightScale(_ scale: CGFloat) {
        let clamped = max(0.45, min(1.0, scale))
        if abs(clamped - collapsedCapsuleHeightScale) < 0.001 { return }
        collapsedCapsuleHeightScale = clamped
        updatePaths(animated: false)
        layoutContent(animated: false)
    }

    func setEdgeThicknessScale(_ scale: CGFloat) {
        let clamped = max(1.0, min(2.5, scale))
        if abs(clamped - edgeThicknessScale) < 0.01 { return }
        edgeThicknessScale = clamped
        for case let button as PillCircleButton in circleButtons {
            button.edgeThicknessScale = clamped
        }
        updatePaths(animated: false)
    }

    // MARK: - Test hooks
    func _test_isExpanded() -> Bool { isExpanded }
    func isExpandedForInteraction() -> Bool {
        isExpanded && morphProgress >= 0.78
    }
    func _test_labelOpacity() -> Float { pillLabel.layer?.opacity ?? -1 }
    func _test_circleButtons() -> [NSButton] { circleButtons }
    func _test_hasMorphAnimation() -> Bool {
        if morphTickTimer != nil { return true }
        if abs(morphProgress - morphTarget) > 0.001 { return true }
        if shapeMaskLayer.animation(forKey: "basic_path") != nil { return true }
        if shapeMaskLayer.animation(forKey: "spring_path") != nil { return true }
        if let keys = shapeMaskLayer.animationKeys(), !keys.isEmpty { return true }
        return false
    }


    // Reuse the same base+tint blend as the rest of the toolbar/search system.
    private func pillFillColor(for state: GlassCardKit.State) -> NSColor {
        let base = pillEffectiveBackgroundColor()
        switch state {
        case .hover:
            return blend(base, NSColor.white, t: 0.02)
        case .pressed:
            return blend(base, NSColor.black, t: 0.02)
        case .disabled:
            return blend(base, NSColor.black, t: 0.04)
        default:
            return base
        }
    }

    private func updateStyle() {
        let state = currentState()
        let fill = pillFillColor(for: state)
        let edgeBands = ToolbarOutlineTokens.edgeBands(for: state)

        // Material edge: subtle attenuation + inner rim; no glow or directional highlight.
        let scale = max(1.0, window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)

        CATransaction.begin()
        CATransaction.setDisableActions(true)

        pillFillLayer.contentsScale = scale
        pillSheenLayer.contentsScale = scale

        hoverLayer.fillColor = NSColor.clear.cgColor
        // Keep the pill glass driven by the shared toolbar/search pipeline.
        // The fill layer stays transparent to avoid overriding the glass tint.
        pillFillLayer.colors = [fill.cgColor, fill.cgColor]
        pillSheenLayer.colors = [NSColor.clear.cgColor, NSColor.clear.cgColor, NSColor.clear.cgColor]
        pillFillLayer.opacity = 0
        pillSheenLayer.opacity = 0

        rimDarkLayer.opacity = 0
        rimLightLayer.opacity = 0
        strokeLayer.opacity = 0
        innerStrokeLayer.opacity = 0
        dispersionLayer.opacity = 0

        rimDarkLayer.lineWidth = 0
        rimLightLayer.lineWidth = 0
        strokeLayer.lineWidth = 0
        innerStrokeLayer.lineWidth = 0

        // Edge treatment: match the reference rim profile using accent-derived colors.
        edgeOrnaments.setContentsScale(scale)
        edgeOrnaments.applyEdgeStyle(outerBand: edgeBands.outer, innerRim: edgeBands.inner)

        CATransaction.commit()

        updateCircleButtonChrome()
    }

    private func updateCircleButtonChrome() {
        updateCircleButtonChromeInternal()
    }

    private func updateCircleButtonChromeInternal() {
        guard !circleButtons.isEmpty else { return }

        for case let button as PillCircleButton in circleButtons {
            button.restingGlowColor = nil
            button.showsRestingGlow = false
            button.showsHaloRing = false
            button.restingGlowOpacity = 0.0
            button.hoverShadowOpacity = 0.0
            button.pressedShadowOpacity = 0.0
            button.restingShadowRadius = 0.0
            button.hoverShadowRadius = 0.0
            button.pressedShadowRadius = 0.0
            button.restingShadowOffset = .zero
            button.hoverShadowOffset = .zero
            button.pressedShadowOffset = .zero
        }
    }
}

// MARK: - Pill Animation Stability Tests

#if canImport(XCTest)
final class PillAnimationStabilityTests: XCTestCase {
    private func makeHostWindow() -> NSWindow {
        let w = NSWindow(contentRect: NSRect(x: 0, y: 0, width: 800, height: 600),
                         styleMask: [.borderless],
                         backing: .buffered,
                         defer: false)
        w.isReleasedWhenClosed = false
        w.contentView = NSView(frame: w.contentRect(forFrameRect: w.frame))
        return w
    }

    private func makeControl(in window: NSWindow) -> MorphingGlassPillControl {
        let c = MorphingGlassPillControl(frame: NSRect(x: 100, y: 100, width: 320, height: 34))
        window.contentView?.addSubview(c)
        c.layoutSubtreeIfNeeded()
        return c
    }

    func testStateIntegrityCollapsedAndExpanded() {
        let _ = NSApplication.shared
        let w = makeHostWindow()
        let c = makeControl(in: w)

        c.setExpanded(false, animated: false)
        c.layoutSubtreeIfNeeded()
        XCTAssertEqual(c._test_isExpanded(), false)
        XCTAssertEqual(c._test_labelOpacity(), 1.0, accuracy: 1e-6)

        c.setExpanded(true, animated: false)
        c.layoutSubtreeIfNeeded()
        XCTAssertEqual(c._test_isExpanded(), true)
        XCTAssertEqual(c._test_labelOpacity(), 0.0, accuracy: 1e-6)
    }

    func testRapidToggleStressNoCrashAndFinalState() {
        let _ = NSApplication.shared
        let w = makeHostWindow()
        let c = makeControl(in: w)
        for i in 0..<10 {
            c.setExpanded((i % 2 == 0), animated: true)
        }
        c.setExpanded(true, animated: false)
        XCTAssertEqual(c._test_isExpanded(), true)
    }

    func testRepeatabilityNoLayoutDriftOver50Cycles() {
        let _ = NSApplication.shared
        let w = makeHostWindow()
        let c = makeControl(in: w)
        c.setExpanded(true, animated: false)
        c.layoutSubtreeIfNeeded()
        let baselineFrames = c.subviews.filter { $0 is NSButton }.map { $0.frame }

        for _ in 0..<50 {
            c.setExpanded(false, animated: false)
            c.setExpanded(true, animated: false)
            c.layoutSubtreeIfNeeded()
        }

        let afterFrames = c.subviews.filter { $0 is NSButton }.map { $0.frame }
        XCTAssertEqual(baselineFrames.count, afterFrames.count)
        for i in 0..<min(baselineFrames.count, afterFrames.count) {
            XCTAssertEqual(baselineFrames[i].origin.x, afterFrames[i].origin.x, accuracy: 1e-6)
            XCTAssertEqual(baselineFrames[i].origin.y, afterFrames[i].origin.y, accuracy: 1e-6)
            XCTAssertEqual(baselineFrames[i].size.width, afterFrames[i].size.width, accuracy: 1e-6)
            XCTAssertEqual(baselineFrames[i].size.height, afterFrames[i].size.height, accuracy: 1e-6)
        }
    }
}

final class ToolbarGapClampMathTests: XCTestCase {
    func testMinRightCardWidthSatisfiesGapAtBoundary() {
        // Use the app's current sizing relationships.
        let minGap: CGFloat = 6
        let baseHeight: CGFloat = 32 * 1.3
        let buttonWidth: CGFloat = max(24, 30 * 1.3)
        let edgeInset: CGFloat = 6
        let leftClusterMaxX: CGFloat = (2 * buttonWidth) + (2 * edgeInset)
        let pillOffset: CGFloat = 0

        let minW = PickerWindowController.ToolbarGapClampMath.minRightCardWidthForGap(
            minGap: minGap,
            baseHeight: baseHeight,
            buttonWidth: buttonWidth,
            edgeInset: edgeInset,
            leftClusterMaxXFromCardMinX: leftClusterMaxX,
            pillCenterOffsetFromCardMidX: pillOffset
        )
        XCTAssertGreaterThan(minW, 0)

        let gapAt = PickerWindowController.ToolbarGapClampMath.pillToRightClusterGap(
            forRightCardWidth: minW,
            baseHeight: baseHeight,
            buttonWidth: buttonWidth,
            edgeInset: edgeInset,
            pillCenterOffsetFromCardMidX: pillOffset
        )
        XCTAssertGreaterThanOrEqual(gapAt, minGap - 0.25)

        let smallerW = max(1, minW - 20)
        let gapSmaller = PickerWindowController.ToolbarGapClampMath.pillToRightClusterGap(
            forRightCardWidth: smallerW,
            baseHeight: baseHeight,
            buttonWidth: buttonWidth,
            edgeInset: edgeInset,
            pillCenterOffsetFromCardMidX: pillOffset
        )
        XCTAssertLessThan(gapSmaller, minGap + 0.25)
    }

    func testRightShiftedPillRequiresMoreWidth() {
        let minGap: CGFloat = 6
        let baseHeight: CGFloat = 32 * 1.3
        let buttonWidth: CGFloat = max(24, 30 * 1.3)
        let edgeInset: CGFloat = 6
        let leftClusterMaxX: CGFloat = (2 * buttonWidth) + (2 * edgeInset)

        let w0 = PickerWindowController.ToolbarGapClampMath.minRightCardWidthForGap(
            minGap: minGap,
            baseHeight: baseHeight,
            buttonWidth: buttonWidth,
            edgeInset: edgeInset,
            leftClusterMaxXFromCardMinX: leftClusterMaxX,
            pillCenterOffsetFromCardMidX: 0
        )
        let wShifted = PickerWindowController.ToolbarGapClampMath.minRightCardWidthForGap(
            minGap: minGap,
            baseHeight: baseHeight,
            buttonWidth: buttonWidth,
            edgeInset: edgeInset,
            leftClusterMaxXFromCardMinX: leftClusterMaxX,
            pillCenterOffsetFromCardMidX: 14
        )
        XCTAssertGreaterThanOrEqual(wShifted, w0)
    }
}

final class SettingsNonRegressionTests: XCTestCase {
    private func spinRunLoop(seconds: TimeInterval) {
        let deadline = Date().addingTimeInterval(seconds)
        while Date() < deadline {
            RunLoop.main.run(mode: .default, before: deadline)
        }
    }

    private func snapshotPNGHash(of view: NSView) -> String {
        view.layoutSubtreeIfNeeded()
        let bounds = view.bounds
        guard let rep = view.bitmapImageRepForCachingDisplay(in: bounds) else { return "" }
        view.cacheDisplay(in: bounds, to: rep)
        guard let data = rep.representation(using: .png, properties: [:]) else { return "" }
        let digest = SHA256.hash(data: data)
        return digest.map { String(format: "%02x", $0) }.joined()
    }

    private func clearKnownDefaults() {
        let defaults = UserDefaults.standard
        defaults.removeObject(forKey: "astroStack.settings.v1")
        clearLayoutDefaults()
    }

    override func setUp() {
        super.setUp()
        clearKnownDefaults()
    }

    func testDefaultSettingsRoundTrip() throws {
        let s = AppSettings()
        let encoder = JSONEncoder()
        encoder.outputFormatting = [.sortedKeys]
        let data = try encoder.encode(s)
        let decoded = try JSONDecoder().decode(AppSettings.self, from: data)
        XCTAssertEqual(s, decoded)
        XCTAssertEqual(decoded.schemaVersion, AppSettings.currentSchemaVersion)
    }

    func testOpenCloseSettingsDoesNotChangeMainWindowSnapshot() {
        let _ = NSApplication.shared

        let controller = PickerWindowController()
        controller.showWindow(nil)
        controller.window?.makeKeyAndOrderFront(nil)
        NSApp.activate(ignoringOtherApps: true)
        spinRunLoop(seconds: 0.35)

        guard let mainWindow = controller.window, let root = mainWindow.contentView else {
            XCTFail("missing_main_window")
            return
        }

        // Establish baseline while the main window is key.
        mainWindow.makeKeyAndOrderFront(nil)
        spinRunLoop(seconds: 0.15)
        let baselineHash = snapshotPNGHash(of: root)
        XCTAssertFalse(baselineHash.isEmpty)

        // Open settings, then close; main window should restore focus and render identically.
        SettingsWindowController.shared.openSettings(nil)
        spinRunLoop(seconds: 0.20)
        SettingsWindowController.shared.window?.performClose(nil)
        spinRunLoop(seconds: 0.25)

        mainWindow.makeKeyAndOrderFront(nil)
        NSApp.activate(ignoringOtherApps: true)
        spinRunLoop(seconds: 0.20)
        let afterHash = snapshotPNGHash(of: root)

        XCTAssertEqual(baselineHash, afterHash)
    }
}

final class AppleIntelligencePillButtonUITests: XCTestCase {
    private var priorPresent: AppleIntelligenceHooks.PresentHandler?
    private var priorContextOverride: (() -> String?)?

    override func setUp() {
        super.setUp()
        priorPresent = AppleIntelligenceHooks.present
        priorContextOverride = AppleIntelligenceHooks.contextOverride
    }

    override func tearDown() {
        AppleIntelligenceHooks.present = priorPresent
        AppleIntelligenceHooks.contextOverride = priorContextOverride
        AppSettingsStore.shared.update { s in
            s.appleIntelligence.buttons = AppSettings.AppleIntelligence.defaultButtons
        }
        super.tearDown()
    }

    func testLeftMostCircleUsesAppleIntelligencePrompt() {
        AppSettingsStore.shared.update { s in
            s.appleIntelligence.buttons = AppSettings.AppleIntelligence.defaultButtons
            s.appleIntelligence.buttons[0].label = "Contribution"
            s.appleIntelligence.buttons[0].prompt = "Explain the core contribution."
        }

        AppleIntelligenceHooks.contextOverride = { "Test document context." }

        var captured: AppleIntelligenceRequest?
        AppleIntelligenceHooks.present = { req in
            captured = req
            return true
        }

        let _ = NSApplication.shared
        let controller = PickerWindowController()
        controller.showWindow(nil)
        controller.window?.makeKeyAndOrderFront(nil)
        NSApp.activate(ignoringOtherApps: true)
        RunLoop.main.run(mode: .default, before: Date().addingTimeInterval(0.2))

        let pill = controller.window?.contentView?.subviews.compactMap { $0 as? MorphingGlassPillControl }.first
            ?? controller.window?.contentViewController?.view.subviews.compactMap { $0 as? MorphingGlassPillControl }.first
        XCTAssertNotNil(pill)

        pill?.setExpanded(true, animated: false)
        pill?.layoutSubtreeIfNeeded()
        guard let leftMost = pill?._test_circleButtons().first else {
            XCTFail("missing_circle_buttons")
            return
        }
        leftMost.performClick(nil)
        RunLoop.main.run(mode: .default, before: Date().addingTimeInterval(0.2))

        XCTAssertEqual(captured?.label, "Contribution")
        XCTAssertEqual(captured?.prompt, "Explain the core contribution.")
        XCTAssertEqual(captured?.documentText, "Test document context.")
    }
}

final class ShortcutRunnerURLTests: XCTestCase {
    func testRunURLNameOnly() throws {
        let runner = ShortcutRunner(config: .init(useXCallback: false))
        let url = try runner.makeRunURL(name: "My Shortcut")
        XCTAssertEqual(url.absoluteString, "shortcuts://run-shortcut?name=My%20Shortcut")
    }

    func testRunURLWithInputText() throws {
        let runner = ShortcutRunner(config: .init(useXCallback: false))
        let url = try runner.makeRunURL(name: "S", inputText: "https://example.com/a b")
        XCTAssertEqual(url.absoluteString, "shortcuts://run-shortcut?name=S&input=text&text=https://example.com/a%20b")
    }

    func testXCallbackURL() throws {
        let runner = ShortcutRunner(config: .init(useXCallback: true))
        let url = try runner.makeXCallbackURL(
            name: "My Shortcut",
            xSuccess: URL(string: "shortcuts://")!,
            xError: URL(string: "shortcuts://")!,
            xCancel: URL(string: "shortcuts://")!,
            inputText: nil
        )
        XCTAssertEqual(url.absoluteString, "shortcuts://x-callback-url/run-shortcut?name=My%20Shortcut&x-success=shortcuts://&x-error=shortcuts://&x-cancel=shortcuts://")
    }
}

#else

struct PillAnimationDeterministicTests {
    private struct TestRunner {
        private(set) var failures: Int = 0
        mutating func assertTrue(_ condition: Bool, _ message: String) {
            if !condition {
                failures += 1
                NSLog("[PILL_TESTS] FAIL: \(message)")
            }
        }
        mutating func assertApprox(_ a: Double, _ b: Double, eps: Double = 1e-6, _ message: String) {
            if abs(a - b) > eps {
                failures += 1
                NSLog("[PILL_TESTS] FAIL: \(message) (\(a) vs \(b))")
            }
        }
    }

    private static func makeHostWindow() -> NSWindow {
        let w = NSWindow(contentRect: NSRect(x: 0, y: 0, width: 800, height: 600),
                         styleMask: [.borderless],
                         backing: .buffered,
                         defer: false)
        w.isReleasedWhenClosed = false
        w.contentView = NSView(frame: w.contentRect(forFrameRect: w.frame))
        return w
    }

    private static func makeControl(in window: NSWindow) -> MorphingGlassPillControl {
        let c = MorphingGlassPillControl(frame: NSRect(x: 100, y: 100, width: 320, height: 34))
        window.contentView?.addSubview(c)
        c.layoutSubtreeIfNeeded()
        return c
    }

    static func run() -> Int {
        let _ = NSApplication.shared
        var t = TestRunner()

        do {
            let c = MorphingGlassPillControl(frame: NSRect(x: 0, y: 0, width: 320, height: 34))
            c.setExpanded(false, animated: false)
            t.assertTrue(c._test_isExpanded() == false, "collapsed_state")
            t.assertApprox(Double(c._test_labelOpacity()), 1.0, "collapsed_label_opacity")

            c.setExpanded(true, animated: false)
            t.assertTrue(c._test_isExpanded() == true, "expanded_state")
            t.assertApprox(Double(c._test_labelOpacity()), 0.0, "expanded_label_opacity")
        }

        do {
            let c = MorphingGlassPillControl(frame: NSRect(x: 0, y: 0, width: 320, height: 34))
            for i in 0..<10 {
                c.setExpanded((i % 2 == 0), animated: true)
            }
            c.setExpanded(true, animated: false)
            t.assertTrue(c._test_isExpanded() == true, "rapid_toggle_final_state")
        }

        do {
            let c = MorphingGlassPillControl(frame: NSRect(x: 0, y: 0, width: 360, height: 34))
            c.setExpanded(true, animated: false)
            c.layoutSubtreeIfNeeded()
            let baseline = c.subviews.compactMap { $0 as? NSButton }.map { $0.frame }

            for _ in 0..<50 {
                c.setExpanded(false, animated: false)
                c.setExpanded(true, animated: false)
                c.layoutSubtreeIfNeeded()
            }

            let after = c.subviews.compactMap { $0 as? NSButton }.map { $0.frame }
            t.assertTrue(baseline.count == after.count, "repeatability_button_count")
            for i in 0..<min(baseline.count, after.count) {
                t.assertApprox(Double(baseline[i].origin.x), Double(after[i].origin.x), "repeatability_x_\(i)")
                t.assertApprox(Double(baseline[i].origin.y), Double(after[i].origin.y), "repeatability_y_\(i)")
                t.assertApprox(Double(baseline[i].size.width), Double(after[i].size.width), "repeatability_w_\(i)")
                t.assertApprox(Double(baseline[i].size.height), Double(after[i].size.height), "repeatability_h_\(i)")
            }
        }

        // Basic animation presence check: path should animate when requested.
        do {
            let w = makeHostWindow()
            let c = makeControl(in: w)
            c.setExpanded(true, animated: true)
            CATransaction.flush()
            let reduceMotion = NSWorkspace.shared.accessibilityDisplayShouldReduceMotion
            t.assertTrue(reduceMotion || c._test_hasMorphAnimation(), "morph_path_animates")
        }

        if t.failures == 0 {
            NSLog("[PILL_TESTS] OK")
        }
        return t.failures
    }
}

struct ToolbarGapClampDeterministicTests {
    private struct TestRunner {
        private(set) var failures: Int = 0
        mutating func assertTrue(_ condition: Bool, _ message: String) {
            if !condition {
                failures += 1
                NSLog("[TOOLBAR_GAP_TESTS] FAIL: \(message)")
            }
        }
        mutating func assertGE(_ a: Double, _ b: Double, eps: Double = 0.25, _ message: String) {
            if a + eps < b {
                failures += 1
                NSLog("[TOOLBAR_GAP_TESTS] FAIL: \(message) (\(a) < \(b))")
            }
        }
        mutating func assertLE(_ a: Double, _ b: Double, eps: Double = 0.25, _ message: String) {
            if a > b + eps {
                failures += 1
                NSLog("[TOOLBAR_GAP_TESTS] FAIL: \(message) (\(a) > \(b))")
            }
        }
    }

    static func run() -> Int {
        var t = TestRunner()

        let minGap: CGFloat = 6
        let baseHeight: CGFloat = 32 * 1.3
        let buttonWidth: CGFloat = max(24, 30 * 1.3)
        let edgeInset: CGFloat = 6
        let leftClusterMaxX: CGFloat = (2 * buttonWidth) + (2 * edgeInset)

        let w0 = PickerWindowController.ToolbarGapClampMath.minRightCardWidthForGap(
            minGap: minGap,
            baseHeight: baseHeight,
            buttonWidth: buttonWidth,
            edgeInset: edgeInset,
            leftClusterMaxXFromCardMinX: leftClusterMaxX,
            pillCenterOffsetFromCardMidX: 0
        )
        t.assertTrue(w0.isFinite && w0 > 0, "min_width_finite")

        let gapAt = PickerWindowController.ToolbarGapClampMath.pillToRightClusterGap(
            forRightCardWidth: w0,
            baseHeight: baseHeight,
            buttonWidth: buttonWidth,
            edgeInset: edgeInset,
            pillCenterOffsetFromCardMidX: 0
        )
        t.assertGE(Double(gapAt), Double(minGap), "gap_at_boundary")

        let smaller = max(1, w0 - 20)
        let gapSmaller = PickerWindowController.ToolbarGapClampMath.pillToRightClusterGap(
            forRightCardWidth: smaller,
            baseHeight: baseHeight,
            buttonWidth: buttonWidth,
            edgeInset: edgeInset,
            pillCenterOffsetFromCardMidX: 0
        )
        t.assertLE(Double(gapSmaller), Double(minGap), "gap_below_boundary")

        let wShifted = PickerWindowController.ToolbarGapClampMath.minRightCardWidthForGap(
            minGap: minGap,
            baseHeight: baseHeight,
            buttonWidth: buttonWidth,
            edgeInset: edgeInset,
            leftClusterMaxXFromCardMinX: leftClusterMaxX,
            pillCenterOffsetFromCardMidX: 14
        )
        t.assertTrue(wShifted + 0.5 >= w0, "shifted_requires_more_width")

        if t.failures == 0 {
            NSLog("[TOOLBAR_GAP_TESTS] OK")
        }
        return t.failures
    }
}

struct SettingsNonRegressionDeterministicTests {
    private struct TestRunner {
        private(set) var failures: Int = 0
        mutating func assertTrue(_ condition: Bool, _ message: String) {
            if !condition {
                failures += 1
                NSLog("[SETTINGS_TESTS] FAIL: \(message)")
            }
        }
        mutating func assertEqual(_ a: String, _ b: String, _ message: String) {
            if a != b {
                failures += 1
                NSLog("[SETTINGS_TESTS] FAIL: \(message) (\(a.prefix(12))… vs \(b.prefix(12))…)")
            }
        }
    }

    private static func spinRunLoop(seconds: TimeInterval) {
        let deadline = Date().addingTimeInterval(seconds)
        while Date() < deadline {
            RunLoop.main.run(mode: .default, before: deadline)
        }
    }

    private static func snapshotPNGHash(of view: NSView) -> String {
        view.layoutSubtreeIfNeeded()
        let bounds = view.bounds
        guard let rep = view.bitmapImageRepForCachingDisplay(in: bounds) else { return "" }
        view.cacheDisplay(in: bounds, to: rep)
        guard let data = rep.representation(using: .png, properties: [:]) else { return "" }
        let digest = SHA256.hash(data: data)
        return digest.map { String(format: "%02x", $0) }.joined()
    }

    private static func clearKnownDefaults() {
        let defaults = UserDefaults.standard
        defaults.removeObject(forKey: "astroStack.settings.v1")
        clearLayoutDefaults()
    }

    static func run() -> Int {
        let _ = NSApplication.shared
        clearKnownDefaults()
        var t = TestRunner()

        // Codable round-trip stability.
        do {
            let s = AppSettings()
            let encoder = JSONEncoder()
            if #available(macOS 10.13, *) {
                encoder.outputFormatting = [.sortedKeys]
            }
            let data = (try? encoder.encode(s)) ?? Data()
            let decoded = (try? JSONDecoder().decode(AppSettings.self, from: data))
            t.assertTrue(decoded == s, "default_round_trip")
            t.assertTrue(decoded?.schemaVersion == AppSettings.currentSchemaVersion, "schema_version")
        }

        // Open/close settings must not alter main window render once focus is restored.
        let controller = PickerWindowController()
        controller.showWindow(nil)
        controller.window?.makeKeyAndOrderFront(nil)
        NSApp.activate(ignoringOtherApps: true)
        spinRunLoop(seconds: 0.35)

        guard let mainWindow = controller.window, let root = mainWindow.contentView else {
            t.assertTrue(false, "missing_main_window")
            return t.failures
        }

        mainWindow.makeKeyAndOrderFront(nil)
        spinRunLoop(seconds: 0.15)
        let baselineHash = snapshotPNGHash(of: root)
        t.assertTrue(!baselineHash.isEmpty, "baseline_hash")

        SettingsWindowController.shared.openSettings(nil)
        spinRunLoop(seconds: 0.20)
        SettingsWindowController.shared.window?.performClose(nil)
        spinRunLoop(seconds: 0.25)

        mainWindow.makeKeyAndOrderFront(nil)
        NSApp.activate(ignoringOtherApps: true)
        spinRunLoop(seconds: 0.20)
        let afterHash = snapshotPNGHash(of: root)
        t.assertEqual(baselineHash, afterHash, "main_window_snapshot_unchanged")

        if t.failures == 0 {
            NSLog("[SETTINGS_TESTS] OK")
        }
        return t.failures
    }
}

